// Abre o modal de Parâmetros Legais. restaurar=true preenche com os defaults 2026.
function openParametrosLegais(restaurar){
  const pl = restaurar ? { ...PARAMS_LEGAIS_DEFAULTS } : _pl();
  const map = {
    'pl-ano':'ano','pl-salario-minimo':'salarioMinimo','pl-inss-teto':'inssTeto',
    'pl-inss1-lim':'inss1Lim','pl-inss1-aliq':'inss1Aliq',
    'pl-inss2-lim':'inss2Lim','pl-inss2-aliq':'inss2Aliq',
    'pl-inss3-lim':'inss3Lim','pl-inss3-aliq':'inss3Aliq',
    'pl-inss4-lim':'inss4Lim','pl-inss4-aliq':'inss4Aliq',
    'pl-irrf-dep':'irrfDedDependente',
    'pl-irrf1-lim':'irrf1Lim',
    'pl-irrf2-lim':'irrf2Lim','pl-irrf2-aliq':'irrf2Aliq','pl-irrf2-ded':'irrf2Ded',
    'pl-irrf3-lim':'irrf3Lim','pl-irrf3-aliq':'irrf3Aliq','pl-irrf3-ded':'irrf3Ded',
    'pl-irrf4-lim':'irrf4Lim','pl-irrf4-aliq':'irrf4Aliq','pl-irrf4-ded':'irrf4Ded',
    'pl-irrf5-aliq':'irrf5Aliq','pl-irrf5-ded':'irrf5Ded',
    'pl-fgts-aliq':'fgtsAliq','pl-fgts-multa40':'fgtsMulta40','pl-fgts-multa20':'fgtsMulta20',
    'pl-aviso-base':'avisoBase','pl-aviso-ano':'avisoPorAno','pl-aviso-max':'avisoMax'
  };
  for(const id in map) setVal(id, pl[map[id]]);
  document.getElementById('modal-parametros-legais').classList.remove('hidden');
  if(restaurar) toast('Valores de 2026 restaurados no formulário — clique em Salvar para confirmar.','warning');
}

async function saveParametrosLegais(){
  const dados = {
    ano: parseInt(val('pl-ano'))||PARAMS_LEGAIS_DEFAULTS.ano,
    salarioMinimo: numVal('pl-salario-minimo')||PARAMS_LEGAIS_DEFAULTS.salarioMinimo,
    inssTeto: numVal('pl-inss-teto')||PARAMS_LEGAIS_DEFAULTS.inssTeto,
    inss1Lim:numVal('pl-inss1-lim'), inss1Aliq:numVal('pl-inss1-aliq'),
    inss2Lim:numVal('pl-inss2-lim'), inss2Aliq:numVal('pl-inss2-aliq'),
    inss3Lim:numVal('pl-inss3-lim'), inss3Aliq:numVal('pl-inss3-aliq'),
    inss4Lim:numVal('pl-inss4-lim'), inss4Aliq:numVal('pl-inss4-aliq'),
    irrfDedDependente:numVal('pl-irrf-dep'),
    irrf1Lim:numVal('pl-irrf1-lim'),
    irrf2Lim:numVal('pl-irrf2-lim'), irrf2Aliq:numVal('pl-irrf2-aliq'), irrf2Ded:numVal('pl-irrf2-ded'),
    irrf3Lim:numVal('pl-irrf3-lim'), irrf3Aliq:numVal('pl-irrf3-aliq'), irrf3Ded:numVal('pl-irrf3-ded'),
    irrf4Lim:numVal('pl-irrf4-lim'), irrf4Aliq:numVal('pl-irrf4-aliq'), irrf4Ded:numVal('pl-irrf4-ded'),
    irrf5Aliq:numVal('pl-irrf5-aliq'), irrf5Ded:numVal('pl-irrf5-ded'),
    fgtsAliq:numVal('pl-fgts-aliq'), fgtsMulta40:numVal('pl-fgts-multa40'), fgtsMulta20:numVal('pl-fgts-multa20'),
    avisoBase:parseInt(val('pl-aviso-base'))||30,
    avisoPorAno:parseInt(val('pl-aviso-ano'))||3,
    avisoMax:parseInt(val('pl-aviso-max'))||90,
    updatedAt:new Date().toISOString()
  };
  const btn=document.querySelector('#modal-parametros-legais .btn-primary');
  setBtnLoading(btn,true,'');
  try {
    await DB.saveDoc('configuracoes','parametrosLegais',dados,true);
    State.parametrosLegais = { ...PARAMS_LEGAIS_DEFAULTS, ...dados };
    Auth.log('PARAMS_LEGAIS_UPDATED', null, `Parâmetros legais ${dados.ano}`);
    closeModal('modal-parametros-legais');
    toast('Parâmetros legais salvos! Os cálculos do sistema já usam os novos valores.');
  } catch(e){
    toast('Erro ao salvar parâmetros: '+(e?.message||e),'error');
  } finally {
    setBtnLoading(btn,false,'<i class="fa-solid fa-floppy-disk"></i> Salvar Parâmetros');
  }
}

function applyEmpresaConfig(){
  const e = State.empresa;
  const nome    = e.nomeEmpresa || EMPRESA_DEFAULTS.nomeEmpresa;
  const logo    = e.logoUrl     || 'logo.png';
  const subdesc = e.subdesc     || EMPRESA_DEFAULTS.subdesc;

  // título da aba
  document.title = nome + ' — Sistema de Gestão';

  // logos
  ['empresa-logo-loading','empresa-logo-setup','empresa-logo-login',
   'empresa-logo-sidebar','empresa-logo-cont','empresa-logo-report'].forEach(id=>{
    const el=document.getElementById(id);
    if(el){ el.src=logo; el.alt=nome; }
  });

  // textos de nome
  ['empresa-nome-login','empresa-nome-cont','empresa-nome-report'].forEach(id=>{
    const el=document.getElementById(id);
    if(el) el.textContent=nome;
  });

  // sidebar brand (tem estrutura especial)
  const sideNome=document.getElementById('empresa-nome-sidebar');
  if(sideNome) sideNome.textContent=nome;

  // subtítulo login e sidebar
  const descLogin=document.getElementById('empresa-desc-login');
  if(descLogin) descLogin.textContent=subdesc;
  const descSide=document.getElementById('empresa-desc-sidebar');
  if(descSide) descSide.textContent=subdesc;

  // dashboard welcome
  const dWelcome=document.getElementById('dashboard-welcome-empresa');
  if(dWelcome) dWelcome.textContent='Bem-vindo ao sistema de gestão de colaboradores ' + nome;

  // footer relatório
  const repFoot=document.getElementById('empresa-footer-report');
  if(repFoot) repFoot.textContent=nome + ' — Sistema de Gestão de Colaboradores';

  // licença lock
  const supNome=document.getElementById('empresa-suporte-nome');
  if(supNome) supNome.textContent=nome;
  const licFoot=document.getElementById('empresa-footer-licenca');
  if(licFoot) licFoot.textContent=nome + ' — Sistema de Gestão';

  // formulário de configurações (se estiver visível)
  if(document.getElementById('cfg-nome-empresa')){
    setVal('cfg-nome-empresa',       e.nomeEmpresa||'');
    setVal('cfg-razao-social',       e.razaoSocial||'');
    setVal('cfg-cnpj',               e.cnpj||'');
    setVal('cfg-descricao',          e.descricao||'');
    setVal('cfg-logo-url',           e.logoUrl||'');
    setVal('cfg-subdesc',            e.subdesc||'');
    setVal('cfg-modo-contabilidade', e.modoContabilidade||'ambas');
    setVal('cfg-dia-limite-adiantamento', e.diaLimiteAdiantamento||15);
  }

  // Banners de modo de contabilidade nas seções
  _applyModoBanners(e.modoContabilidade||'ambas');
}

function _applyModoBanners(modo){
  const banners = {
    'pag-modo-banner':  document.getElementById('pag-modo-banner'),
    'cont-modo-banner': document.getElementById('cont-modo-banner'),
  };
  const modoLabels = {
    interna: { label:'Contabilidade Interna', cor:'#1B5E20', bg:'#E8F5E9', icon:'fa-house' },
    externa: { label:'Contabilidade Externa',  cor:'#1565C0', bg:'#E3F2FD', icon:'fa-building' },
    ambas:   { label:'Interna + Externa',      cor:'#4A148C', bg:'#F3E5F5', icon:'fa-code-branch' },
  };
  const m = modoLabels[modo] || modoLabels.ambas;

  const pagBanner = document.getElementById('pag-modo-banner');
  if(pagBanner){
    const hidden = modo === 'externa';
    pagBanner.style.display = hidden ? 'none' : '';
    if(!hidden) pagBanner.innerHTML =
      modo === 'interna'
        ? `<i class="fa-solid fa-circle-check" style="color:${m.cor}"></i> <strong>Modo Contabilidade Interna</strong> — Você gerencia a folha de pagamento internamente. Use esta seção para acompanhar encargos, INSS, IRRF e FGTS de cada colaborador.`
        : `<i class="fa-solid fa-code-branch" style="color:${m.cor}"></i> <strong>Modo Ambas</strong> — Pagamentos para gestão interna. Use Contabilidade para exportar dados à contabilidade externa.`;
  }

  const contBanner = document.getElementById('cont-modo-banner');
  if(contBanner){
    const hidden = modo === 'interna';
    contBanner.style.display = hidden ? 'none' : '';
    if(!hidden) contBanner.innerHTML =
      modo === 'externa'
        ? `<i class="fa-solid fa-circle-check" style="color:${m.cor}"></i> <strong>Modo Contabilidade Externa</strong> — Exporte a planilha mensal e envie ao seu contador. Ele é responsável pelo cálculo de INSS, FGTS e IRRF.`
        : `<i class="fa-solid fa-code-branch" style="color:${m.cor}"></i> <strong>Modo Ambas</strong> — Contabilidade para exportação ao contador externo. Use Pagamentos para gestão interna de encargos.`;
  }
}

async function saveEmpresaConfig(){
  if(Auth.currentUser?.role!=='master'){ toast('Apenas o master pode alterar as configurações','error'); return; }
  const dados = {
    nomeEmpresa:       val('cfg-nome-empresa').trim() || EMPRESA_DEFAULTS.nomeEmpresa,
    razaoSocial:       val('cfg-razao-social').trim(),
    cnpj:              val('cfg-cnpj').trim(),
    descricao:         val('cfg-descricao').trim(),
    logoUrl:           val('cfg-logo-url').trim(),
    subdesc:           val('cfg-subdesc').trim(),
    modoContabilidade: val('cfg-modo-contabilidade') || 'ambas',
    diaLimiteAdiantamento: Math.min(28, Math.max(1, parseInt(val('cfg-dia-limite-adiantamento'))||15)),
    cnae:              val('cfg-cnae').trim(),
    endereco:          val('cfg-endereco').trim(),
    numero:            val('cfg-numero').trim(),
    complemento:       val('cfg-complemento').trim(),
    bairro:            val('cfg-bairro').trim(),
    cidade:            val('cfg-cidade').trim(),
    uf:                val('cfg-uf').trim().toUpperCase(),
    cep:               val('cfg-cep').trim(),
    telefone:          val('cfg-telefone').trim(),
    email:             val('cfg-email').trim(),
    updatedAt:         new Date().toISOString()
  };
  try {
    await DB.saveDoc('configuracoes','empresa',dados,true);
    // preserva campos gravados fora deste form (contCodigos/contNoturnoReduzida da planilha contábil etc.). #planilha-contador
    State.empresa = { ...EMPRESA_DEFAULTS, ...(State.empresa||{}), ...dados };
    applyEmpresaConfig();
    _applyModoBanners(dados.modoContabilidade||'ambas');
    toast('Configurações salvas com sucesso!','success');
  } catch(e){
    toast('Erro ao salvar configurações: ' + e.message,'error');
  }
}

function renderConfiguracoes(){
  const e = State.empresa;
  setVal('cfg-nome-empresa',       e.nomeEmpresa||'');
  setVal('cfg-razao-social',       e.razaoSocial||'');
  setVal('cfg-cnpj',               e.cnpj||'');
  setVal('cfg-descricao',          e.descricao||'');
  setVal('cfg-logo-url',           e.logoUrl||'');
  setVal('cfg-subdesc',            e.subdesc||'');
  setVal('cfg-modo-contabilidade', e.modoContabilidade||'ambas');
  setVal('cfg-cnae',               e.cnae||'');
  setVal('cfg-endereco',           e.endereco||'');
  setVal('cfg-numero',             e.numero||'');
  setVal('cfg-complemento',        e.complemento||'');
  setVal('cfg-bairro',             e.bairro||'');
  setVal('cfg-cidade',             e.cidade||'');
  setVal('cfg-uf',                 e.uf||'');
  setVal('cfg-cep',                e.cep||'');
  setVal('cfg-telefone',           e.telefone||'');
  setVal('cfg-email',              e.email||'');
  renderFeriadosConfig();
  renderPainelRecursos();
  renderLinksAcesso();
  renderPlanosPrecos();
  renderParametrosLegais();
  // Regra de adiantamento — prazo mínimo de casa (default 20). #adiant-prazo-admissao
  { const _v=State.empresa?.adiantamentoMinDiasAdmissao; setVal('cfg-adiant-min-dias', (_v==null?20:_v)); }
}
// Salva a regra "prazo mínimo de casa p/ adiantamento" em configuracoes/empresa. Vale para
// novos lançamentos a partir daqui (não mexe no que já foi lançado/pago). #adiant-prazo-admissao
async function salvarRegrasAdiantamento(){
  let dias=parseInt(val('cfg-adiant-min-dias'));
  if(isNaN(dias)||dias<0) dias=0;
  State.empresa = State.empresa||{};
  State.empresa.adiantamentoMinDiasAdmissao = dias;
  try{
    await DB.saveDoc('configuracoes','empresa',{adiantamentoMinDiasAdmissao:dias},true);
    try{ Auth.log('REGRA_ADIANT_SAVE', null, `Prazo mínimo de casa p/ adiantamento: ${dias} dia(s)`); }catch(_){}
    try{ if(State.currentSection==='adiantamentos') renderAdiantamentos(); }catch(_){}
    toast(dias>0?`Regra salva: mínimo de ${dias} dia(s) de casa para receber adiantamento.`:'Regra salva: sem prazo mínimo para adiantamento.','success');
  }catch(e){ toast('Erro ao salvar a regra: '+(e.message||e),'error'); }
}

// ===== Parâmetros Legais (Configurações) — preenche os campos com os valores atuais
// (empresa.parametrosLegais ou o default legal). #param-legal =====
function renderParametrosLegais(){
  ['tolDiaMin','tolBatidaMin','monitorFaltasMin','adNoturnoPerc','vtCoPartPerc','acumuloPerc','refNaoRendidaPerc','oj394Corte'].forEach(k=>{
    const el=document.getElementById('pl-'+k); if(el) el.value=_paramLegal(k);
  });
  const cb1=document.getElementById('pl-dsrHeBaseSabado'); if(cb1) cb1.checked=_paramLegal('dsrHeBaseSabado')!==false;
  const cb2=document.getElementById('pl-dsrHe12x36');      if(cb2) cb2.checked=_paramLegal('dsrHe12x36')===true;
  const cbAP=document.getElementById('pl-avisoAtrasoPush');  if(cbAP) cbAP.checked=_paramLegal('avisoAtrasoPush')!==false;   // #regra-ponto-he-atraso
  const cbAE=document.getElementById('pl-avisoAtrasoEmail'); if(cbAE) cbAE.checked=_paramLegal('avisoAtrasoEmail')===true;
}
async function salvarParametrosLegais(){
  const num=(id,def)=>{ const v=parseFloat(val('pl-'+id)); return isNaN(v)?def:v; };
  const pl={
    tolDiaMin:        num('tolDiaMin',        PARAM_LEGAL_DEFAULTS.tolDiaMin),
    tolBatidaMin:     num('tolBatidaMin',     PARAM_LEGAL_DEFAULTS.tolBatidaMin),
    monitorFaltasMin: num('monitorFaltasMin', PARAM_LEGAL_DEFAULTS.monitorFaltasMin),
    adNoturnoPerc:    num('adNoturnoPerc',    PARAM_LEGAL_DEFAULTS.adNoturnoPerc),
    vtCoPartPerc:     num('vtCoPartPerc',     PARAM_LEGAL_DEFAULTS.vtCoPartPerc),
    acumuloPerc:      num('acumuloPerc',      PARAM_LEGAL_DEFAULTS.acumuloPerc),
    refNaoRendidaPerc:num('refNaoRendidaPerc',PARAM_LEGAL_DEFAULTS.refNaoRendidaPerc),
    dsrHeBaseSabado:  !!document.getElementById('pl-dsrHeBaseSabado')?.checked,
    dsrHe12x36:       !!document.getElementById('pl-dsrHe12x36')?.checked,
    avisoAtrasoPush:  !!document.getElementById('pl-avisoAtrasoPush')?.checked,
    avisoAtrasoEmail: !!document.getElementById('pl-avisoAtrasoEmail')?.checked,
    oj394Corte:       val('pl-oj394Corte')||PARAM_LEGAL_DEFAULTS.oj394Corte,
  };
  State.empresa = State.empresa||{};
  State.empresa.parametrosLegais = pl;
  try{
    await DB.saveDoc('configuracoes','empresa',{parametrosLegais:pl},true);
    // Espelha a escolha push/e-mail num doc que o worker drg-monitor lê no aviso de atraso. #regra-ponto-he-atraso
    try{ await DB.saveDoc('configuracoes','avisoAtrasoCfg',{push:pl.avisoAtrasoPush, email:pl.avisoAtrasoEmail, updatedAt:new Date().toISOString()},true); }catch(_){}
    aplicarParametrosLegais();
    try{ if(val('payroll-employee')) recalculate(); }catch(_){}
    try{ Auth.log('PARAM_LEGAL_SAVE', null, JSON.stringify(pl)); }catch(_){}
    toast('Parâmetros legais salvos. Os cálculos passam a usar estes valores.','success');
  }catch(e){ toast('Erro ao salvar parâmetros: '+(e.message||e),'error'); }
}
function restaurarParametrosLegais(){
  if(!confirm('Restaurar TODOS os parâmetros legais para o padrão da lei vigente?\n\nOs campos voltam ao default — clique em "Salvar parâmetros" para gravar.')) return;
  if(State.empresa) State.empresa.parametrosLegais = {...PARAM_LEGAL_DEFAULTS};
  renderParametrosLegais();
  toast('Padrão legal restaurado nos campos. Clique em "Salvar parâmetros" para gravar.','info');
}

// ===== Links de Acesso (Configurações) — endereço de cada app/perfil, derivado do
// próprio host (funciona em qualquer hospedagem). Botões copiar/abrir. #links-acesso =====
function renderLinksAcesso(){
  const el = document.getElementById('links-acesso-body');
  if(!el) return;
  // Base = diretório atual (tira query/hash e o nome do arquivo). Ex.: .../drg-sistema/
  const base = location.href.replace(/[?#].*$/,'').replace(/[^/]*$/,'');
  const links = [
    {icon:'fa-user-plus',     cor:'#2E7D32', nome:'Criar conta (cadastro gratuito)', desc:'Link para novas empresas criarem a própria conta. Compartilhe com quem vai se cadastrar.', arq:'cadastro.html'},
    {icon:'fa-table-columns', cor:'#1565C0', nome:'Portal (todos os acessos)', desc:'Página inicial com os apps — boa para deixar salva.', arq:'portal.html'},
    {icon:'fa-user-shield',   cor:'#7B1FA2', nome:'Master',      desc:'App principal — acesso total. Entra com o login master.', arq:'index.html'},
    {icon:'fa-user-gear',     cor:'#5C6BC0', nome:'Gestor',      desc:'Mesmo app principal — acesso conforme o perfil. Entra com o próprio login.', arq:'index.html'},
    {icon:'fa-headset',       cor:'#C62828', nome:'Operador',    desc:'Painel do Operador (login próprio).', arq:'operator.html'},
    {icon:'fa-user-check',    cor:'#1B5E20', nome:'Supervisor',  desc:'Aprova/recusa as batidas de ponto fora do horário.', arq:'supervisor.html'},
    {icon:'fa-clock',         cor:'#00897B', nome:'Colaborador', desc:'App de ponto eletrônico (instala no celular).', arq:'ponto.html'},
  ];
  el.innerHTML = links.map(l=>{
    const url = base + l.arq;
    return `<div style="display:flex;align-items:center;gap:10px;padding:9px 0;border-bottom:1px solid #eef1f4">
      <div style="width:34px;height:34px;flex-shrink:0;border-radius:8px;display:flex;align-items:center;justify-content:center;background:${l.cor}1A;color:${l.cor}"><i class="fa-solid ${l.icon}"></i></div>
      <div style="flex:1;min-width:0">
        <div style="font-weight:700;font-size:13px;color:var(--text)">${l.nome}</div>
        <div style="font-size:11px;color:#778;margin-bottom:2px">${l.desc}</div>
        <div style="font-size:11px;color:#1565C0;font-family:monospace;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="${url}">${url}</div>
      </div>
      <button class="btn btn-sm btn-outline" style="flex-shrink:0;font-size:11px;padding:5px 9px" onclick="_copiarLink('${url}')" title="Copiar link"><i class="fa-solid fa-copy"></i></button>
      <a class="btn btn-sm btn-outline" style="flex-shrink:0;font-size:11px;padding:5px 9px" href="${url}" target="_blank" rel="noopener" title="Abrir em nova aba"><i class="fa-solid fa-arrow-up-right-from-square"></i></a>
    </div>`;
  }).join('');
}
function _copiarLink(url){
  if(navigator.clipboard && navigator.clipboard.writeText){
    navigator.clipboard.writeText(url).then(()=>toast('Link copiado!','success')).catch(()=>toast('Não consegui copiar — copie manualmente: '+url,'warning'));
  } else { toast('Copie manualmente: '+url,'info'); }
}

// ===== Planos & Preços (Configurações) — tabela comercial editável pelo master.
// Salva em configuracoes/planos (raiz). O Worker de cadastro lê 'trialDias' daqui,
// então o período grátis vale de verdade sem mexer no código. #planos-precos
function _planosDefault(){
  return {
    trialDias: 180,
    toleranciaInadimplenciaDias: 5,
    faixas: [
      {nome:'Start',        min:0,   max:10,   mensal:39,  anual:390},
      {nome:'Essencial',    min:11,  max:25,   mensal:79,  anual:790},
      {nome:'Profissional', min:26,  max:50,   mensal:149, anual:1490},
      {nome:'Empresarial',  min:51,  max:100,  mensal:249, anual:2490},
      {nome:'Acima de 100', min:101, max:null, mensal:0,   anual:0},
    ],
  };
}
// Teto de funcionários ATIVOS do plano do tenant. Prioridade:
//  1) maxFuncionarios explícito no metadata (setado pelo operador ou pelo Asaas na contratação)
//  2) em trial sem teto explícito → teto da 1ª faixa dos planos (Start, ex.: 10)
//  3) sem tenant (dono/raiz) ou plano pago sem teto → ilimitado (não bloqueia). #planos-trava
function _planoMaxFuncionarios(){
  if(!DB.tenantId) return Infinity;
  const t = State.tenantMeta || {};
  const m = Number(t.maxFuncionarios);
  if(m > 0) return m;
  const status = t.status || t.plano;
  if(status === 'trial'){
    const faixas = (State.planos && Array.isArray(State.planos.faixas) && State.planos.faixas.length)
      ? State.planos.faixas : _planosDefault().faixas;
    const fm = Number(faixas[0] && faixas[0].max);
    return fm > 0 ? fm : 10;
  }
  return Infinity;
}
async function renderPlanosPrecos(){
  const el = document.getElementById('planos-precos-body');
  if(!el) return;
  // Cliente (tenant) assina; só o dono/raiz edita a tabela de preços. #planos-precos
  if(DB.tenantId) return renderAssinaturaCliente(el);
  if(!State.planos){
    try{ State.planos = await DB.getDoc('configuracoes','planos'); }catch(_){ State.planos=null; }
    if(!State.planos || !Array.isArray(State.planos.faixas) || !State.planos.faixas.length) State.planos = _planosDefault();
  }
  _planosPintar();
}
function _planosPintar(){
  const el = document.getElementById('planos-precos-body');
  if(!el) return;
  const p = State.planos || _planosDefault();
  const meses = (p.trialDias||0)/30;
  const rows = (p.faixas||[]).map((f,i)=>`
    <tr>
      <td style="padding:4px"><input type="text" value="${esc(f.nome||'')}" data-pl="nome" data-i="${i}" style="min-width:120px;width:100%;padding:6px;border:1px solid var(--border);border-radius:5px"></td>
      <td style="padding:4px"><input type="number" value="${f.min==null?0:f.min}" data-pl="min" data-i="${i}" min="0" style="width:66px;padding:6px;border:1px solid var(--border);border-radius:5px"></td>
      <td style="padding:4px"><input type="number" value="${f.max==null?'':f.max}" data-pl="max" data-i="${i}" min="0" placeholder="∞" style="width:66px;padding:6px;border:1px solid var(--border);border-radius:5px"></td>
      <td style="padding:4px"><input type="number" value="${f.mensal==null?0:f.mensal}" data-pl="mensal" data-i="${i}" min="0" step="0.01" style="width:88px;padding:6px;border:1px solid var(--border);border-radius:5px"></td>
      <td style="padding:4px"><input type="number" value="${f.anual==null?0:f.anual}" data-pl="anual" data-i="${i}" min="0" step="0.01" style="width:88px;padding:6px;border:1px solid var(--border);border-radius:5px"></td>
      <td style="padding:4px;text-align:center"><button class="btn btn-sm btn-outline" onclick="_planosRemover(${i})" title="Remover faixa" style="color:#c62828;border-color:#ef9a9a;padding:5px 9px"><i class="fa-solid fa-trash"></i></button></td>
    </tr>`).join('');
  el.innerHTML = `
    <p style="font-size:12px;color:#666;margin-bottom:12px"><i class="fa-solid fa-circle-info"></i> Sua tabela comercial — edite valores, faixas e o período grátis como quiser. O cadastro de novos clientes usa o <strong>período grátis</strong> abaixo. (A cobrança automática por Asaas ainda não está ligada; por ora a tabela é referência de venda.)</p>
    <div style="display:flex;align-items:center;gap:10px;margin-bottom:14px;flex-wrap:wrap">
      <label style="font-size:13px;font-weight:600;color:#444">Período grátis (dias):</label>
      <input type="number" id="pl-trial-dias" value="${p.trialDias==null?180:p.trialDias}" min="0" style="width:90px;padding:8px;border:1px solid var(--border);border-radius:6px">
      <span style="font-size:12px;color:#94a3b8">≈ ${meses ? meses.toFixed(meses%1?1:0) : 0} mes(es) — 180 = 6 meses</span>
    </div>
    <div style="display:flex;align-items:center;gap:10px;margin-bottom:14px;flex-wrap:wrap">
      <label style="font-size:13px;font-weight:600;color:#444">Tolerância de inadimplência (dias):</label>
      <input type="number" id="pl-tolerancia-dias" value="${p.toleranciaInadimplenciaDias==null?5:p.toleranciaInadimplenciaDias}" min="0" style="width:90px;padding:8px;border:1px solid var(--border);border-radius:6px">
      <span style="font-size:12px;color:#94a3b8">dias de folga após o vencimento antes de bloquear o acesso</span>
    </div>
    <div style="overflow-x:auto">
    <table style="width:100%;border-collapse:collapse;font-size:13px">
      <thead><tr style="text-align:left;color:#64748b;border-bottom:2px solid var(--border)">
        <th style="padding:6px 4px">Plano</th><th style="padding:6px 4px">De (func.)</th><th style="padding:6px 4px">Até (func.)</th>
        <th style="padding:6px 4px">Mensal (R$)</th><th style="padding:6px 4px">Anual (R$)</th><th></th>
      </tr></thead>
      <tbody>${rows}</tbody>
    </table>
    </div>
    <div style="display:flex;gap:8px;margin-top:14px;flex-wrap:wrap">
      <button class="btn btn-outline btn-sm" onclick="_planosAdicionar()"><i class="fa-solid fa-plus"></i> Adicionar faixa</button>
      <button class="btn btn-primary btn-sm" onclick="salvarPlanosPrecos()"><i class="fa-solid fa-floppy-disk"></i> Salvar planos</button>
    </div>
    <p style="font-size:11px;color:#94a3b8;margin-top:8px">Dica: deixe o campo "Até" vazio na última faixa para "sem limite". Anual sugerido = 10× o mensal (2 meses grátis).</p>`;
}
// Lê os inputs de volta pro State (evita perder edições ao adicionar/remover faixa)
function _planosColeta(){
  const p = State.planos || _planosDefault();
  const td = document.getElementById('pl-trial-dias');
  if(td) p.trialDias = Math.max(0, parseInt(td.value)||0);
  const tol = document.getElementById('pl-tolerancia-dias');
  if(tol) p.toleranciaInadimplenciaDias = Math.max(0, parseInt(tol.value)||0);
  document.querySelectorAll('#planos-precos-body [data-pl]').forEach(inp=>{
    const i = +inp.dataset.i, campo = inp.dataset.pl;
    if(!p.faixas[i]) return;
    if(campo==='nome')      p.faixas[i].nome = inp.value.trim();
    else if(campo==='max')  p.faixas[i].max  = (inp.value==='' ? null : Math.max(0, parseInt(inp.value)||0));
    else                    p.faixas[i][campo] = Math.max(0, parseFloat(inp.value)||0);
  });
  State.planos = p;
  return p;
}
function _planosAdicionar(){
  _planosColeta();
  State.planos.faixas.push({nome:'Nova faixa', min:0, max:null, mensal:0, anual:0});
  _planosPintar();
}
function _planosRemover(i){
  _planosColeta();
  State.planos.faixas.splice(i,1);
  _planosPintar();
}
async function salvarPlanosPrecos(){
  if(Auth.currentUser?.role!=='master'){ toast('Apenas o master pode alterar os planos','error'); return; }
  const p = _planosColeta();
  p.updatedAt = new Date().toISOString();
  try{
    await DB.saveDoc('configuracoes','planos',p,true);
    toast('Planos & preços salvos!','success');
  }catch(e){ toast('Erro ao salvar planos: '+e.message,'error'); }
}

// ===== Assinatura do CLIENTE (tenant) — escolhe faixa, gera cobrança recorrente Asaas
// via Worker /assinar-plano e abre o link de pagamento. Preços vêm de /planos-publicos. #planos-precos
function _plNumApp(n){ n = Number(n)||0; return n%1 ? n.toFixed(2).replace('.',',') : String(n); }
async function renderAssinaturaCliente(el){
  const t = State.tenantMeta || {};
  const hoje = new Date().toISOString().split('T')[0];
  let statusHtml;
  if(t.status==='ativo'){
    statusHtml = `<div style="padding:10px 14px;border-radius:10px;background:#E8F5E9;border:1px solid #A5D6A7;color:#2E7D32;font-size:13px;font-weight:600">
      <i class="fa-solid fa-circle-check"></i> Plano ativo${t.planoFaixa?': '+esc(t.planoFaixa):''}${t.validade?' — próxima renovação em '+formatDateBr(t.validade):''}.${t.inadimplente?' <span style="color:#c62828">(pagamento em atraso)</span>':''}</div>`;
  } else if(t.validade && t.validade>=hoje){
    const dias = Math.max(0, Math.floor((new Date(t.validade)-new Date())/86400000));
    statusHtml = `<div style="padding:10px 14px;border-radius:10px;background:#FFF8E1;border:1px solid #FFE082;color:#8D6E00;font-size:13px;font-weight:600">
      <i class="fa-solid fa-gift"></i> Período grátis — ${dias} dia(s) restante(s) (até ${formatDateBr(t.validade)}). Assine para não perder o acesso.</div>`;
  } else {
    statusHtml = `<div style="padding:10px 14px;border-radius:10px;background:#FDECEA;border:1px solid #F5B5AE;color:#c62828;font-size:13px;font-weight:600">
      <i class="fa-solid fa-triangle-exclamation"></i> Período grátis encerrado. Assine um plano para continuar usando o sistema.</div>`;
  }
  el.innerHTML = statusHtml +
    `<p style="font-size:12px;color:#666;margin:12px 0 8px"><i class="fa-solid fa-circle-info"></i> Escolha o plano pelo seu nº de funcionários. O pagamento (PIX, boleto ou cartão) abre em outra aba e o acesso é liberado automaticamente após a confirmação.</p>
     <label style="font-size:13px;display:inline-flex;align-items:center;gap:6px;margin-bottom:10px"><input type="checkbox" id="pl-ciclo-anual"> Cobrança anual <span style="color:#2E7D32;font-weight:600">(2 meses grátis)</span></label>
     <div id="pl-assinar-lista"><div style="color:#94A3B8;font-size:13px">Carregando planos...</div></div>`;
  let dados=null;
  try{
    const r = await fetch(APROVACAO_WORKER+'/planos-publicos',{method:'POST',headers:{'Content-Type':'application/json'},body:'{}'});
    dados = await r.json().catch(()=>null);
  }catch(_){}
  State._faixasAssinatura = (dados && Array.isArray(dados.faixas) && dados.faixas.length) ? dados.faixas : null;
  _renderAssinarLista();
  const chk=document.getElementById('pl-ciclo-anual'); if(chk) chk.onchange=_renderAssinarLista;
}
function _renderAssinarLista(){
  const box=document.getElementById('pl-assinar-lista'); if(!box) return;
  const faixas=State._faixasAssinatura;
  if(!faixas){ box.innerHTML='<div style="color:#c62828;font-size:13px">Não consegui carregar os planos agora. Recarregue a página e tente de novo.</div>'; return; }
  const anual=!!(document.getElementById('pl-ciclo-anual')||{}).checked;
  box.innerHTML = faixas.map((f,i)=>{
    const valor = anual ? Number(f.anual) : Number(f.mensal);
    const label = (f.max==null||f.max==='') ? `acima de ${Math.max(0,(Number(f.min)||0)-1)} func.`
                : (Number(f.min)<=1 ? `até ${f.max} func.` : `${f.min}–${f.max} func.`);
    const pode = valor>0;
    const preco = pode ? `R$ ${_plNumApp(valor)}<span style="font-size:11px;color:#778;font-weight:400">/${anual?'ano':'mês'}</span>` : `<span style="color:#778;font-size:13px">Sob consulta</span>`;
    return `<div style="display:flex;align-items:center;justify-content:space-between;gap:10px;padding:10px 12px;border:1px solid var(--border);border-radius:10px;margin-bottom:8px">
      <div><div style="font-weight:700;font-size:14px">${esc(f.nome||'')}</div><div style="font-size:11px;color:#778">${label}</div></div>
      <div style="text-align:right"><div style="font-weight:700;font-size:15px">${preco}</div>
      ${pode?`<button class="btn btn-primary btn-sm" style="margin-top:4px" onclick="assinarPlano(${i})"><i class="fa-solid fa-credit-card"></i> Assinar</button>`:''}</div>
    </div>`;
  }).join('');
}
async function assinarPlano(i){
  const anual=!!(document.getElementById('pl-ciclo-anual')||{}).checked;
  const cycle = anual ? 'YEARLY' : 'MONTHLY';
  if(!confirm('Vamos gerar sua assinatura e abrir a página de pagamento em outra aba. Continuar?')) return;
  toast('Gerando assinatura...','info');
  try{
    const r = await _aprovacaoReq('/assinar-plano',{ faixaIndex:i, cycle });
    if(r && r.ok && r.invoiceUrl){
      window.open(r.invoiceUrl,'_blank','noopener');
      toast('Assinatura criada! A página de pagamento abriu em outra aba.','success');
    } else {
      toast((r&&r.erro)||'Não foi possível criar a assinatura.','error');
    }
  }catch(e){ toast('Erro ao assinar: '+(e.message||e),'error'); }
}

// ===== Feriados — UI de configuração (folga/trabalha + extras). #feriados =====
function renderFeriadosConfig(){
  const sel=document.getElementById('feriados-ano');
  const body=document.getElementById('feriados-config-body');
  if(!sel || !body) return;
  const anoAtual = (typeof currentAno==='function') ? currentAno() : new Date().getFullYear();
  if(!sel.options.length){
    let opts='';
    for(let a=anoAtual-1; a<=anoAtual+2; a++) opts+=`<option value="${a}"${a===anoAtual?' selected':''}>${a}</option>`;
    sel.innerHTML=opts;
  }
  const ano=parseInt(sel.value)||anoAtual;
  // Popula os selects de UF (estadual/municipal) uma vez. #feriados-escopo
  ['feriado-est-uf','feriado-mun-uf'].forEach(id=>{ const s=document.getElementById(id); if(s && !s.options.length) s.innerHTML=_ufOptionsHTML(); });
  const lista=_feriadosDoAno(ano);
  const diaSemNome=['dom','seg','ter','qua','qui','sex','sáb'];
  body.innerHTML = lista.map(f=>{
    const [yy,mm,dd]=f.ymd.split('-');
    const ds=diaSemNome[new Date(+yy,+mm-1,+dd).getDay()];
    const folga=f.folga;
    const escTag = f.oficial ? ''
      : f.escopo==='estadual'  ? ` <span style="font-size:10px;color:#1565C0;font-weight:600">(estadual ${esc(f.uf||'?')})</span>`
      : f.escopo==='municipal' ? ` <span style="font-size:10px;color:#6A1B9A;font-weight:600">(municipal ${esc(f.cidade||'?')}${f.uf?'/'+esc(f.uf):''})</span>`
      : ` <span style="font-size:10px;color:#6A1B9A">(extra)</span>`;
    return `<div style="display:flex;align-items:center;gap:10px;padding:6px 4px;border-bottom:1px solid #f0f0f0;font-size:13px">
      <span style="min-width:96px;font-weight:600">${dd}/${mm} <span style="color:#999;font-weight:400">${ds}</span></span>
      <span style="flex:1">${esc(f.nome)}${escTag}</span>
      <button class="btn btn-sm" onclick="toggleFeriadoFolga('${f.ymd}')" style="font-size:11px;padding:3px 10px;background:${folga?'#E8F5E9':'#FFF3E0'};color:${folga?'#2E7D32':'#E65100'};border:1px solid ${folga?'#A5D6A7':'#FFCC80'}">${folga?'🏖️ Folga':'💼 Trabalha'}</button>
      ${f.oficial?'':`<button class="btn btn-sm btn-outline" onclick="removerFeriadoExtra('${f._id||f.ymd}')" title="Remover" style="font-size:11px;padding:3px 8px;color:#c62828;border-color:#ef9a9a"><i class="fa-solid fa-trash"></i></button>`}
    </div>`;
  }).join('') || '<div style="color:#999;font-size:13px;padding:8px">Nenhum feriado neste ano.</div>';
}
async function _salvarFeriadosConfig(){
  State.feriadosConfig = State.feriadosConfig || {trabalha:[],extras:[]};
  try{ await DB.saveDoc('configuracoes','feriados',State.feriadosConfig,true); }
  catch(e){ toast('Erro ao salvar feriados: '+(e.message||e),'error'); }
}
function toggleFeriadoFolga(ymd){
  const cfg=State.feriadosConfig=State.feriadosConfig||{trabalha:[],extras:[]};
  cfg.trabalha=cfg.trabalha||[];
  const i=cfg.trabalha.indexOf(ymd);
  if(i>=0) cfg.trabalha.splice(i,1); else cfg.trabalha.push(ymd);
  _salvarFeriadosConfig(); renderFeriadosConfig();
  toast(i>=0?'Feriado: equipe FOLGA (sem VT/VR p/ 5x2 e 6x1).':'Feriado: equipe TRABALHA (VT/VR normal).','success');
}
const _UFS_BR=['AC','AL','AP','AM','BA','CE','DF','ES','GO','MA','MT','MS','MG','PA','PB','PR','PE','PI','RJ','RN','RS','RO','RR','SC','SP','SE','TO'];
function _ufOptionsHTML(){ return '<option value="">UF</option>'+_UFS_BR.map(u=>`<option value="${u}">${u}</option>`).join(''); }
// Feriado ESTADUAL: vale só p/ postos cujo estado (UF) bate. #feriados-escopo
function adicionarFeriadoEstadual(){
  const data=val('feriado-est-data'), nome=(val('feriado-est-nome')||'').trim(), uf=(val('feriado-est-uf')||'').toUpperCase();
  if(!data){ toast('Escolha a data do feriado estadual.','warning'); return; }
  if(!nome){ toast('Informe o nome do feriado.','warning'); return; }
  if(!uf){ toast('Escolha o estado (UF).','warning'); return; }
  const cfg=State.feriadosConfig=State.feriadosConfig||{trabalha:[],extras:[]};
  cfg.extras=cfg.extras||[];
  if(cfg.extras.some(e=>e.ymd===data && e.escopo==='estadual' && (e.uf||'').toUpperCase()===uf)){ toast(`Já existe um feriado estadual (${uf}) nessa data.`,'warning'); return; }
  cfg.extras.push({ id:genId(), ymd:data, nome, escopo:'estadual', uf });
  setVal('feriado-est-data',''); setVal('feriado-est-nome',''); setVal('feriado-est-uf','');
  const sel=document.getElementById('feriados-ano'); if(sel && data.slice(0,4)!==sel.value){ sel.value=data.slice(0,4); }
  _salvarFeriadosConfig(); renderFeriadosConfig();
  toast(`Feriado estadual (${uf}) adicionado.`,'success');
}
// Feriado MUNICIPAL: vale só p/ postos cuja cidade (+UF) bate. #feriados-escopo
function adicionarFeriadoMunicipal(){
  const data=val('feriado-mun-data'), nome=(val('feriado-mun-nome')||'').trim(), cidade=(val('feriado-mun-cidade')||'').trim(), uf=(val('feriado-mun-uf')||'').toUpperCase();
  if(!data){ toast('Escolha a data do feriado municipal.','warning'); return; }
  if(!nome){ toast('Informe o nome do feriado.','warning'); return; }
  if(!cidade){ toast('Informe a cidade.','warning'); return; }
  if(!uf){ toast('Escolha o estado (UF) da cidade.','warning'); return; }
  const cfg=State.feriadosConfig=State.feriadosConfig||{trabalha:[],extras:[]};
  cfg.extras=cfg.extras||[];
  if(cfg.extras.some(e=>e.ymd===data && e.escopo==='municipal' && _normCidade(e.cidade)===_normCidade(cidade) && (e.uf||'').toUpperCase()===uf)){ toast(`Já existe um feriado municipal (${cidade}/${uf}) nessa data.`,'warning'); return; }
  cfg.extras.push({ id:genId(), ymd:data, nome, escopo:'municipal', uf, cidade });
  setVal('feriado-mun-data',''); setVal('feriado-mun-nome',''); setVal('feriado-mun-cidade',''); setVal('feriado-mun-uf','');
  const sel=document.getElementById('feriados-ano'); if(sel && data.slice(0,4)!==sel.value){ sel.value=data.slice(0,4); }
  _salvarFeriadosConfig(); renderFeriadosConfig();
  toast(`Feriado municipal (${cidade}/${uf}) adicionado.`,'success');
}
// Remove por id (extras novos) ou por ymd (legado sem id).
function removerFeriadoExtra(key){
  const cfg=State.feriadosConfig=State.feriadosConfig||{trabalha:[],extras:[]};
  cfg.extras=(cfg.extras||[]).filter(e=> e.id ? e.id!==key : e.ymd!==key);
  cfg.trabalha=(cfg.trabalha||[]).filter(d=>d!==key);   // legado: key pode ser o ymd
  _salvarFeriadosConfig(); renderFeriadosConfig();
  toast('Feriado removido.','success');
}

// Estimativa de preço do Gemini 2.5 Flash (US$ por 1 milhão de tokens) e
