let _navigatingBack=false;

function goBack(){
  if(State.sectionHistory.length===0) return;
  _navigatingBack=true;
  const prev=State.sectionHistory.pop();
  showSection(prev);
  _navigatingBack=false;
}

function _updateBackBtn(){
  const btn=document.getElementById('btn-voltar');
  if(btn) btn.classList.toggle('hidden', State.sectionHistory.length===0);
}

// ============================================
// MENU LATERAL — grupos colapsáveis
// ============================================
const NAV_GROUPS = {
  pessoas:     ['employees','documentos','docsempresa','comunicacao'],
  ponto:       ['payroll','escalas','autorizacoes'],
  pagamentos:  ['pagamentos','adiantamentos','aprovacoes','recibos'],
  clt:         ['decimoterceiro','ferias','rescisao'],
  operacao:    ['postos','contratos','contabilidade'],
  sistema:     ['banco','users','configuracoes']
};

function _navGrpStateKey(){
  const u = Auth.currentUser?.username || 'guest';
  return 'drg_nav_groups_' + u;
}

function _loadNavGrpState(){
  try { return JSON.parse(localStorage.getItem(_navGrpStateKey())||'{}'); } catch(_){ return {}; }
}
function _saveNavGrpState(state){
  try { localStorage.setItem(_navGrpStateKey(), JSON.stringify(state)); } catch(_){ }
}

function toggleNavGroup(groupId){
  const el = document.getElementById('nav-grp-'+groupId);
  if(!el) return;
  el.classList.toggle('collapsed');
  const state = _loadNavGrpState();
  state[groupId] = el.classList.contains('collapsed') ? 'closed' : 'open';
  _saveNavGrpState(state);
}

// Aplica o estado salvo + esconde grupos que não têm nenhum filho visível.
// Também marca o grupo que contém a seção ativa.
function applyNavGroupsState(activeName){
  const state = _loadNavGrpState();
  Object.keys(NAV_GROUPS).forEach(gid => {
    const grp = document.getElementById('nav-grp-'+gid);
    if(!grp) return;
    const filhos = NAV_GROUPS[gid];
    // Conta filhos visíveis (li não-hidden)
    let visiveis = 0;
    filhos.forEach(secId => {
      const li = document.getElementById('nav-'+secId+'-li');
      // Itens sem -li (ex.: payroll é só <li> sem id-li) sempre contam como visíveis
      if(!li || !li.classList.contains('hidden')) visiveis++;
    });
    if(visiveis === 0){
      grp.classList.add('hidden');
      return;
    }
    grp.classList.remove('hidden');
    // Estado open/closed — primeira visita fica aberto (mostra tudo); depois respeita o salvo
    const saved = state[gid];
    const containsActive = filhos.includes(activeName);
    if(containsActive){
      grp.classList.remove('collapsed');
      grp.classList.add('has-active');
    } else {
      grp.classList.remove('has-active');
      if(saved === 'closed') grp.classList.add('collapsed');
      else grp.classList.remove('collapsed');
    }
  });
}

function showSection(name){
  if(!Auth.currentUser) return;
  const mods=getUserModules(Auth.currentUser);
  if(name==='users'          && !mods.users && !mods.log) return;
  if(name==='employees'      && !mods.employees)    return;
  if(name==='payroll'        && !mods.payroll)      return;
  if(name==='escalas'        && !mods.escalas)      return;
  if(name==='pagamentos'     && !mods.pagamentos)      return;
  if(name==='recibos'        && !mods.pagamentos)      return;
  if(name==='adiantamentos'  && !mods.pagamentos)      return;
  if(name==='aprovacoes'     && !mods.pagamentosLancar && !mods.pagamentosAprovar) return;
  if(name==='decimoterceiro' && !mods.decimoterceiro)  return;
  if(name==='ferias'         && !mods.ferias)          return;
  if(name==='rescisao'       && !mods.rescisao)        return;
  if(name==='contabilidade'  && !mods.contabilidade)   return;
  if(name==='banco'          && Auth.currentUser?.role!=='master') return;
  if(name==='postos'         && !mods.postos)       return;
  if(name==='rubricas'       && !mods.pagamentos && Auth.currentUser?.role!=='master') return;
  if(name==='contratos'      && !mods.contratos)    return;
  if(name==='comunicacao'    && !mods.comunicacao)  return;
  if(name==='autorizacoes'   && !mods.autorizarPonto) return;
  if(name==='monitorfaltas'  && !mods.monitorarFaltas) return;
  if(name==='estoque'        && !mods.estoque) return;
  if(name==='documentos'     && !mods.employees) return;
  if(name==='docsempresa'    && !mods.documentosEmpresa && Auth.currentUser?.role!=='master') return;
  if(name==='importaholerite'&& !mods.folhaEnviar && Auth.currentUser?.role!=='master') return;
  if(name==='configuracoes'  && !mods.configuracoes && Auth.currentUser?.role!=='master') return;
  if(name==='lgpd'           && !mods.lgpd && Auth.currentUser?.role!=='master') return;
  // Empilha seção atual antes de trocar (exceto se estiver voltando ou já está na mesma seção)
  if(!_navigatingBack && State.currentSection && State.currentSection!==name){
    State.sectionHistory.push(State.currentSection);
    if(State.sectionHistory.length>30) State.sectionHistory.shift(); // cap
  }
  _updateBackBtn();
  // Limpa qualquer modal flutuante que possa bloquear cliques
  const floatingModal=document.getElementById('modal-stat-detail');
  if(floatingModal) floatingModal.remove();
  document.querySelectorAll('.section').forEach(s=>s.classList.remove('active'));
  document.querySelectorAll('.nav-link').forEach(n=>n.classList.remove('active'));
  const section=document.getElementById('section-'+name);
  const navBtn=document.getElementById('nav-'+name);
  if(section) section.classList.add('active');
  if(navBtn)  navBtn.classList.add('active');
  applyNavGroupsState(name);
  const titles={dashboard:'Dashboard',employees:'Colaboradores',payroll:'Folha de Ponto',escalas:'Escalas',
                pagamentos:'Pagamentos',beneficios:'Benefícios',recibos:'Recibos Enviados',adiantamentos:'Adiantamentos',aprovacoes:'Aprovações de Pagamentos',decimoterceiro:'13º Salário',ferias:'Férias',rescisao:'Rescisões',
                contabilidade:'Contabilidade',banco:'Banco de Dados',users:'Usuários & Acessos',postos:'Postos de Trabalho',rubricas:'Rubricas',contratos:'Contratos',comunicacao:'Comunicação',autorizacoes:'Autorizações de Ponto',monitorfaltas:'Monitor de Faltas',estoque:'Estoque / EPIs',documentos:'Documentos do Colaborador',docsempresa:'Documentos da Empresa',configuracoes:'Configurações',lgpd:'Conformidade LGPD'};
  document.getElementById('topbar-title').textContent=titles[name]||name;
  State.currentSection=name;
  if(name==='employees') setEmployeeFilter('ativo');   // abre sempre em ATIVOS (atalhos do dashboard sobrescrevem depois)
  if(name==='payroll')   { initPayrollSection(); renderPayrollStats(); }
  if(name==='escalas')   renderEscalas();
  if(name==='lgpd')      renderLGPD();
  if(name==='dashboard') renderDashboard();
  if(name==='pagamentos')      {
    _applyModoBanners(State.empresa?.modoContabilidade||'ambas');
    // Se voltando de uma revisão (clique numa linha), restaura a MESMA competência
    // e rola até a linha. Senão, default = mês de calendário atual.
    if(State._pagReturn){ setVal('pag-mes',State._pagReturn.mes); setVal('pag-ano',State._pagReturn.ano); }
    else { setVal('pag-mes',currentMes()); setVal('pag-ano',currentAno()); }
    renderPagamentos();
    if(State._pagReturn){ const _emp=State._pagReturn.empId; State._pagReturn=null; setTimeout(()=>_pagScrollToEmp(_emp),60); }
  }
  if(name==='beneficios')      switchBeneficioTab(_beneficioTabAtual||'hoje');
  if(name==='recibos')         renderRecibosEnviados();
  if(name==='aprovacoes')      renderAprovacoes();
  if(name==='adiantamentos')   renderAdiantamentos();
  if(name==='decimoterceiro')  renderDecimoTerceiro();
  if(name==='ferias')          renderFeriasModulo();
  if(name==='rescisao')        renderRescisoes();
  if(name==='contabilidade')   { _applyModoBanners(State.empresa?.modoContabilidade||'ambas');
    // Volta à MESMA competência de onde saiu (clicou num nome do aviso → aplicou folha →
    // voltou); senão abre na vigente. #contab-retorno-competencia
    if(State._contReturn){ setVal('cont-mes',State._contReturn.mes); setVal('cont-ano',State._contReturn.ano); State._contReturn=null; }
    else { const _vc=competenciaVigente(); setVal('cont-mes',_vc.mes); setVal('cont-ano',_vc.ano); }
    renderContabilidade(); }
  if(name==='banco')           renderBancoDados();
  if(name==='comunicacao')     renderComunicacaoSection();
  if(name==='autorizacoes')    renderAutorizacoesSection();
  if(name==='monitorfaltas')   renderMonitorFaltas();
  if(name==='estoque')         renderEstoque();
  if(name==='documentos')      renderDocumentosPendentes();
  if(name==='docsempresa')     renderDocsEmpresa();
  if(name==='importaholerite') renderImportaHolerite();
  if(name==='configuracoes')  renderConfiguracoes();
  if(name==='postos')    renderPostosTable();
  if(name==='rubricas')  renderRubricas();
  if(name==='contratos') {
    // Garante aba Tenants ativa e carrega dados
    switchAdminTab('tenants');
    loadAdminTenants();
    populateContratoPostoSelect();
  }
  if(name==='users'){
    renderUsersTable(); renderPerfisTable(); renderLogTable();
    // Lista de usuários vem do Worker (a coleção users é só-servidor).
    if(Auth.currentUser?.role==='master'){
      loadUsersFromWorker().then(()=>{ if(State.currentSection==='users') renderUsersTable(); });
    }
    // Se usuário só tem acesso ao log (não a gestão de usuários), ocultar cards de usuários e perfis
    const userCard=document.querySelector('#section-users .card:first-child');
    const perfilCard=document.querySelector('#section-users .card:nth-child(2)');
    const pageHeader=document.querySelector('#section-users .page-header');
    const logOnly=!mods.users && mods.log;
    const isMaster=Auth.currentUser?.role==='master';
    if(userCard)   userCard.style.display   = (logOnly||!isMaster)?'none':'';
    if(perfilCard) perfilCard.style.display  = logOnly?'none':'';
    if(pageHeader) pageHeader.style.display  = logOnly?'none':'';
  }
  _applyViewLock(name);
  // Toda troca de seção começa do TOPO — não herda o scroll da tela anterior (a
  // rolagem fica no container .page-content). Os drill-downs que rolam até uma linha
  // (ex.: retorno de Pagamentos via _pagScrollToEmp, foco em Autorizações) usam
  // setTimeout e rodam DEPOIS deste reset, então continuam funcionando. #scroll-topo
  const _pc=document.querySelector('.page-content');
  if(_pc) _pc.scrollTop=0;
  if(window.scrollTo) window.scrollTo(0,0);
  // Fechar menu automaticamente no celular ao navegar
  if(window.innerWidth<=768) closeSidebarMobile();
}

// Modais de cada seção que devem ser travados quando o perfil é "somente visualizar".
const SECTION_MODALS={
  employees:['modal-employee'],
  payroll:['modal-ponto-manual','modal-banco-horas','modal-he-review'],
  escalas:['modal-corrido-perc','modal-bulk-refeicao'],
  decimoterceiro:['modal-decimo-terceiro'],
  ferias:['modal-ferias-modulo'],
  rescisao:['modal-rescisao'],
  postos:['modal-posto'],
  contratos:['modal-contrato','modal-adm-tenant','modal-adm-cobranca']
};
// Trava campos e o botão Salvar de um modal (mantém imprimir/exportar/fechar).
function _lockModalView(modalId){
  const m=document.getElementById(modalId); if(!m) return;
  m.querySelectorAll('input,select,textarea').forEach(el=>{ el.disabled=true; });
  m.querySelectorAll('.modal-footer button, button.btn-primary').forEach(b=>{
    const txt=(b.textContent||'').trim();
    if(/cancelar|fechar|voltar|imprimir|exportar|pr[ée]via|pdf|csv|excel/i.test(txt)) return;
    b.disabled=true;
  });
}

// ── Modo "somente visualizar": trava a UI de uma seção conforme o nível do perfil ──
// Mostra um aviso e desabilita os botões de ação. A segurança real é o guarda do DB;
// isto é a camada visual. Re-executado a cada navegação (idempotente).
function _applyViewLock(sectionName){
  const section=document.getElementById('section-'+sectionName);
  if(!section) return;
  const viewOnly=CRUD_MODULES.includes(sectionName) && !canEditModule(sectionName);
  section.classList.toggle('view-locked', viewOnly);
  let banner=section.querySelector('.view-only-banner');
  if(viewOnly && !banner){
    banner=document.createElement('div');
    banner.className='view-only-banner';
    banner.innerHTML='<i class="fa-solid fa-eye"></i> <strong>Modo somente leitura.</strong> Seu perfil permite consultar e imprimir neste módulo, mas não alterar dados.';
    section.insertBefore(banner, section.firstChild);
  } else if(!viewOnly && banner){
    banner.remove();
  }
  if(!viewOnly) return;
  // Desabilita botões de ação (criar/editar/excluir/salvar) — best-effort por texto/ícone.
  const EDIT_RE=/salvar|adicionar|cadastrar|excluir|remover|\bnov[oa]\b|lançar|aprovar|importar|reabrir|fechar/i;
  section.querySelectorAll('button').forEach(btn=>{
    const txt=(btn.textContent||'').replace(/\s+/g,' ').trim();
    const ic=btn.querySelector('i');
    const isTrash=ic && /fa-trash/.test(ic.className||'');
    if(isTrash || (txt && EDIT_RE.test(txt))) btn.disabled=true;
  });
  (SECTION_MODALS[sectionName]||[]).forEach(_lockModalView);
}

function toggleSidebar(){
  const sidebar=document.getElementById('sidebar');
  const overlay=document.getElementById('sidebar-overlay');
  if(window.innerWidth<=768){
    // Mobile: abre/fecha como drawer lateral
    const isOpen=sidebar.classList.toggle('mobile-open');
    if(overlay) overlay.classList.toggle('active', isOpen);
    document.body.style.overflow=isOpen?'hidden':'';
  } else {
    // Desktop: colapsa/expande normalmente
    sidebar.classList.toggle('collapsed');
  }
}
function closeSidebarMobile(){
  const sidebar=document.getElementById('sidebar');
  const overlay=document.getElementById('sidebar-overlay');
  sidebar.classList.remove('mobile-open');
  if(overlay) overlay.classList.remove('active');
  document.body.style.overflow='';
}

// ============================================
// LOGIN / LOGOUT
// ============================================
// Login 100% verificado no servidor (Worker). A senha nunca é conferida no
// cliente — o Worker valida e devolve um Firebase Custom Token (sessão real).
// ID único e persistente desta máquina/navegador (trava de dispositivo, LGPD).
// Gerado 1x e guardado no localStorage. Enviado no /login pro Worker conferir.
function _genDeviceId(){
  return (window.crypto && crypto.randomUUID) ? crypto.randomUUID()
       : 'dev-' + Date.now().toString(36) + '-' + Math.random().toString(36).slice(2,12);
}
// ID do dispositivo RESILIENTE: localStorage → cookie → memória. Nunca devolve vazio
// (vazio fazia o login travar com "dispositivo não identificado" em navegador que
// bloqueia localStorage — modo anônimo, cookies/site-data bloqueados). #fix-deviceid
function _getDeviceId(){
  // 1) localStorage (preferido)
  try{
    let id = localStorage.getItem('drg_device_id');
    if(!id){ id = _genDeviceId(); localStorage.setItem('drg_device_id', id); }
    if(id){ try{ document.cookie = 'drg_device_id='+id+';path=/;max-age=31536000;SameSite=Lax'; }catch(_){ } return id; }
  }catch(e){ /* localStorage bloqueado → tenta cookie */ }
  // 2) cookie (quando o localStorage está bloqueado mas cookies não)
  try{
    const m = document.cookie.match(/(?:^|;\s*)drg_device_id=([^;]+)/);
    if(m && m[1]) return decodeURIComponent(m[1]);
    const id = _genDeviceId();
    document.cookie = 'drg_device_id='+id+';path=/;max-age=31536000;SameSite=Lax';
    if(/(?:^|;\s*)drg_device_id=/.test(document.cookie)) return id;
  }catch(e){ /* cookie também bloqueado → memória */ }
  // 3) memória (último recurso — não persiste entre recargas, mas o login funciona)
  if(!window.__drgDevMem) window.__drgDevMem = _genDeviceId();
  return window.__drgDevMem;
}

// MT-2: o tenant ATIVO passa a vir do CLAIM do token (autoritativo), não da URL
// ?tenant= (que o cliente controla). Lido após o login/restauração de sessão e ANTES
// de carregar dados, pra namespacear no tenant certo. Sem claim = modo raiz/legado.
// A URL só serve de "pista" pré-login pra rotear o /login; depois o token manda. #multitenant
async function _aplicarTenantDoToken(){
  try{
    const u = firebase.auth().currentUser;
    if(!u) return;
    const res = await u.getIdTokenResult();
    const claimTenant = (res && res.claims && res.claims.tenantId) ? String(res.claims.tenantId) : null;
    DB.tenantId = claimTenant || null;
    if(claimTenant) localStorage.setItem('drg_tenant', claimTenant);
    else localStorage.removeItem('drg_tenant');   // raiz: limpa ?tenant= acidental da URL
    console.info(`[DRG] Tenant (token): ${DB.tenantId||'raiz/legado'}`);
  }catch(e){ console.warn('Falha ao ler tenant do token:', (e&&e.message)||e); }
}

async function doLogin(event){
  event.preventDefault();
  const username=val('login-username'), password=val('login-password');
  const errorEl=document.getElementById('login-error');
  const errorMsg=document.getElementById('login-error-msg');
  errorEl.classList.add('hidden');

  const btn=document.getElementById('login-btn');
  btn.disabled=true;
  btn.innerHTML='<i class="fa-solid fa-spinner fa-spin"></i> Verificando...';

  try {
    if(!username||!password){
      errorMsg.textContent='Preencha usuário e senha.';
      errorEl.classList.remove('hidden'); return;
    }

    let r;
    try {
      r=await _workerReqPublic('/login',{username,password,deviceId:_getDeviceId(),tenantId:DB.tenantId||''});  // MT-1: tenant da URL → token carimba tenantId. #multitenant
    } catch(e){
      console.warn('Worker /login indisponível:', (e&&e.message)||e);
      errorMsg.textContent='Servidor de login indisponível no momento. Verifique a conexão e tente de novo.';
      errorEl.classList.remove('hidden'); return;
    }
    if(!r || r.ok!==true || !r.user || !r.customToken){
      Auth.log('LOGIN_FAILED',username,(r&&r.erro)||'recusado pelo servidor');
      const _erro=(r&&r.erro)||'';
      let msg;
      if(r && r.deviceBlocked) msg='Este usuário só pode acessar do dispositivo autorizado. Procure o administrador para liberar esta máquina.';
      else if(/senha/i.test(_erro)) msg='Senha incorreta.';
      // Mostra o MOTIVO REAL do servidor (ex.: "Muitas tentativas erradas. Aguarde 15 min",
      // "usuário inativo") — antes qualquer erro virava "Usuário inválido ou sem acesso",
      // o que confundia (ex.: lockout de rate-limit aparecia como conta inexistente). #login-msg-real
      else if(_erro) msg = _erro.charAt(0).toUpperCase()+_erro.slice(1);
      else msg='Usuário inválido ou sem acesso.';
      errorMsg.textContent = msg;
      errorEl.classList.remove('hidden'); return;
    }

    await firebase.auth().signInWithCustomToken(r.customToken);
    await _aplicarTenantDoToken();   // MT-2: tenant autoritativo do token, antes de carregar dados. #multitenant
    const user=r.user;
    // Trava de HORÁRIO DE ACESSO — bloqueia o login fora da janela permitida (Master nunca). #acesso-horario
    if(user.role!=='master'){
      let _reg=null;
      try{ const _acc=(await DB.getDoc('configuracoes','acessoUsuarios'))||{}; _reg=_acc[user.username]||null; }catch(_){}
      if(_reg && !_acessoPermitidoAgora(_reg)){
        try{ Auth.log('LOGIN_BLOQUEADO_HORARIO', username, _acessoRegraLabel(_reg)); }catch(_){}
        await firebase.auth().signOut().catch(()=>{});
        errorMsg.textContent='Acesso permitido apenas '+_acessoRegraLabel(_reg)+'. Fora desse horário o sistema fica bloqueado.';
        errorEl.classList.remove('hidden'); return;
      }
    }
    Auth.currentUser=user;
    Auth.saveSession(user);
    Auth.log('LOGIN_SUCCESS',username,`Perfil: ${roleLabel(user.role)} · servidor`);
    // Carrega os dados AGORA — depois do login, com sessão real.
    // Antes da S3-A, isso rodava no init() com sessão anônima.
    const ok=await _carregarDadosPosLogin();
    if(!ok){
      // Licença bloqueou ou erro de conexão — `_carregarDadosPosLogin` já
      // mostrou a mensagem; mantém a tela de login visível pra retry.
      return;
    }
    document.getElementById('login-screen').classList.add('hidden');
    setVal('login-username',''); setVal('login-password','');
    errorEl.classList.add('hidden');
    applyUserSession(user);
    AutoBackup.tryRestore();
    if(user.forceChange) setTimeout(()=>openChangePasswordModal(true),600);
  } finally {
    btn.disabled=false;
    btn.innerHTML='<i class="fa-solid fa-right-to-bracket"></i> Entrar';
  }
}

function doLogout(){
  Auth.log('LOGOUT', Auth.currentUser?Auth.currentUser.username:'');
  Auth.clearSession();
  firebase.auth().signOut().catch(()=>{});
  AutoBackup.stop();
  // Recarrega a página pra garantir estado limpo — sem listeners DB
  // acumulados nem State contaminado caso o usuário logue de novo.
  // (Os listeners do Firestore SDK não têm `unsubscribe` exposto pelo nosso
  // DB.listen — refresh é a forma mais simples e segura.)
  setTimeout(() => window.location.reload(), 100);
}

// Logout com confirmação — usado pelo botão "Sair" da barra superior.
function confirmLogout(){
  if(confirm('Deseja sair do sistema?')) doLogout();
}

// ============================================
// MINHA CONTA — 2FA (Google Authenticator)
// ============================================
// Chamada autenticada ao Worker de segurança: envia o ID token do Firebase.
async function _aprovacaoReq(path, body){
  if(typeof firebase==='undefined' || !firebase.auth) throw new Error('Firebase indisponível.');
  const fu = firebase.auth().currentUser;
  if(!fu || fu.isAnonymous) throw new Error('Sessão segura indisponível — saia e entre de novo.');
  const idToken = await fu.getIdToken();
  const r = await fetch(APROVACAO_WORKER + path, {
    method:'POST', headers:{'Content-Type':'application/json'},
    body: JSON.stringify({ idToken, ...(body||{}) })
  });
  const data = await r.json().catch(()=>({}));
  if(!r.ok) throw new Error(data.error || ('HTTP '+r.status));
  return data;
}

// ============================================
// FOTO DO USUÁRIO (avatar do perfil)
// ============================================
function _userFotoKey(){
  const u=Auth.currentUser||{};
  return (u.id||u.username||'x').toString().replace(/[^a-zA-Z0-9_-]/g,'_');
}

// Aplica a foto (data URL) no topo e na prévia do modal Minha Conta. '' = sem foto.
function _aplicarFotoUsuario(dataUrl){
  const tImg=document.getElementById('topbar-user-foto');
  const tIco=document.getElementById('topbar-user-icon');
  if(tImg && tIco){
    if(dataUrl){ tImg.src=dataUrl; tImg.style.display=''; tIco.style.display='none'; }
    else { tImg.removeAttribute('src'); tImg.style.display='none'; tIco.style.display=''; }
  }
  const pImg=document.getElementById('minha-conta-foto-preview');
  const pVaz=document.getElementById('minha-conta-foto-vazio');
  const pRem=document.getElementById('minha-conta-foto-remover');
  if(pImg && pVaz){
    if(dataUrl){ pImg.src=dataUrl; pImg.style.display=''; pVaz.style.display='none'; }
    else { pImg.removeAttribute('src'); pImg.style.display='none'; pVaz.style.display=''; }
    if(pRem) pRem.style.display=dataUrl?'':'none';
  }
}

// Carrega a foto do usuário logado do Firestore.
async function loadUserFoto(){
  try{
    const d=await DB.getDoc('configuracoes','userfoto_'+_userFotoKey());
    _aplicarFotoUsuario((d&&d.foto)||'');
  }catch(e){ /* sem foto — segue com o ícone padrão */ }
}

// Upload: reduz a imagem escolhida a um avatar pequeno (160px) e salva.
function onMinhaContaFoto(ev){
  const file=ev.target.files&&ev.target.files[0];
  ev.target.value='';
  if(!file) return;
  if(!/^image\//.test(file.type||'')){ toast('Selecione um arquivo de imagem.','error'); return; }
  const reader=new FileReader();
  reader.onload=()=>{
    const img=new Image();
    img.onload=()=>{
      const S=160, cv=document.createElement('canvas');
      cv.width=S; cv.height=S;
      const ctx=cv.getContext('2d');
      const m=Math.min(img.width,img.height);
      ctx.drawImage(img,(img.width-m)/2,(img.height-m)/2,m,m,0,0,S,S);
      _salvarFotoUsuario(cv.toDataURL('image/jpeg',0.82));
    };
    img.onerror=()=>toast('Não foi possível ler essa imagem.','error');
    img.src=reader.result;
  };
  reader.onerror=()=>toast('Não foi possível ler o arquivo.','error');
  reader.readAsDataURL(file);
}

async function _salvarFotoUsuario(dataUrl){
  try{
    await DB.saveDoc('configuracoes','userfoto_'+_userFotoKey(),{foto:dataUrl,updatedAt:new Date().toISOString()},true);
    _aplicarFotoUsuario(dataUrl);
    toast('Foto do perfil atualizada!','success');
  }catch(e){ toast('Erro ao salvar a foto: '+(e.message||e),'error'); }
}

async function removerFotoUsuario(){
  try{
    await DB.saveDoc('configuracoes','userfoto_'+_userFotoKey(),{foto:'',updatedAt:new Date().toISOString()},true);
    _aplicarFotoUsuario('');
    toast('Foto removida.','success');
  }catch(e){ toast('Erro ao remover a foto: '+(e.message||e),'error'); }
}

async function openMinhaConta(){
  const u = Auth.currentUser;
  if(!u) return;
  const infoEl   = document.getElementById('minha-conta-info');
  const statusEl = document.getElementById('mfa-status-box');
  document.getElementById('mfa-enroll-box').style.display = 'none';
  document.getElementById('modal-minha-conta').classList.remove('hidden');
  loadUserFoto();
  infoEl.innerHTML = `<strong>${u.username}</strong> — ${u.email||'(sem e-mail cadastrado)'} &middot; Perfil: ${roleLabel(u.role)}`;
  const fu = (typeof firebase!=='undefined' && firebase.auth) ? firebase.auth().currentUser : null;
  if(!fu || fu.isAnonymous){
    statusEl.innerHTML = '<div style="color:#C62828"><i class="fa-solid fa-triangle-exclamation"></i> Para usar o 2FA, sua conta precisa estar no login seguro (Firebase Auth). Confira se o seu <strong>e-mail está preenchido</strong> no cadastro, depois <strong>saia e entre de novo</strong>.</div>';
    return;
  }
  statusEl.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> Verificando 2FA...';
  try {
    const r = await _aprovacaoReq('/mfa/status', {});
    if(r.ativo){
      statusEl.innerHTML = '<div style="color:#1B5E20;font-weight:600"><i class="fa-solid fa-circle-check"></i> Verificação em 2 etapas ATIVADA nesta conta.</div>'
        + '<button class="btn btn-outline" style="margin-top:8px;font-size:12px;padding:5px 12px" onclick="mfaIniciarAtivacao()"><i class="fa-solid fa-rotate"></i> Reconfigurar (troquei de celular)</button>';
    } else {
      statusEl.innerHTML = '<div style="color:#E65100"><i class="fa-solid fa-shield-halved"></i> Verificação em 2 etapas ainda <strong>não ativada</strong>.</div>'
        + '<button class="btn btn-primary" style="margin-top:8px" onclick="mfaIniciarAtivacao()"><i class="fa-solid fa-mobile-screen-button"></i> Ativar 2FA</button>';
    }
  } catch(e){
    statusEl.innerHTML = `<div style="color:#C62828"><i class="fa-solid fa-triangle-exclamation"></i> Erro ao consultar o 2FA: ${e.message}</div>`;
  }
}

async function mfaIniciarAtivacao(){
  const box  = document.getElementById('mfa-enroll-box');
  const qrEl = document.getElementById('mfa-qr');
  try {
    const r = await _aprovacaoReq('/mfa/enroll', {});
    qrEl.innerHTML = '';
    if(typeof QRCode!=='undefined'){
      new QRCode(qrEl, { text:r.uri, width:160, height:160, correctLevel:QRCode.CorrectLevel.M });
    } else {
      qrEl.textContent = '(QR indisponível — use a chave manual ao lado)';
    }
    document.getElementById('mfa-secret').textContent = r.secret;
    setVal('mfa-code','');
    box.style.display = '';
  } catch(e){
    toast('Erro ao iniciar o 2FA: '+e.message, 'error');
  }
}

async function mfaConfirm(){
  const code = (val('mfa-code')||'').replace(/\D/g,'');
  if(code.length!==6){ toast('Digite o código de 6 dígitos do app.','error'); return; }
  try {
    const r = await _aprovacaoReq('/mfa/confirm', { code });
    if(r && r.ok){
      toast('2FA ativado com sucesso!','success');
      openMinhaConta();
    } else {
      toast('Código incorreto. Confira no Google Authenticator e tente de novo.','error');
    }
  } catch(e){
    toast('Erro ao confirmar: '+e.message,'error');
  }
}

// ============================================
// RECUPERAÇÃO DE ACESSO
// ============================================
// O código de recuperação NÃO fica mais no cliente — é um Secret no Worker
// (RECOVERY_CODE). doRecovery() chama a rota pública /recuperar-acesso.

function openRecoveryModal(){
  const modal=document.getElementById('modal-recovery');
  if(!modal) return;
  modal.classList.remove('hidden');
  setVal('recovery-code','');
  document.getElementById('recovery-error').classList.add('hidden');
  document.getElementById('recovery-success').classList.add('hidden');
  const btn=document.getElementById('recovery-btn');
  if(btn){ btn.style.display=''; btn.disabled=false; btn.innerHTML='<i class="fa-solid fa-unlock"></i> Restaurar Acesso'; }
}

// Chamada ao Worker SEM exigir login — para rotas públicas (recuperação).
async function _workerReqPublic(path, body){
  const r = await fetch(APROVACAO_WORKER + path, {
    method:'POST', headers:{'Content-Type':'application/json'},
    body: JSON.stringify(body||{})
  });
  const data = await r.json().catch(()=>({}));
  if(!r.ok) throw new Error(data.error || ('HTTP '+r.status));
  return data;
}

async function doRecovery(){
  const code=val('recovery-code');
  const errEl=document.getElementById('recovery-error');
  const errMsg=document.getElementById('recovery-error-msg');
  const successEl=document.getElementById('recovery-success');
  errEl.classList.add('hidden');
  successEl.classList.add('hidden');
  if(!code){ errMsg.textContent='Digite o código de recuperação.'; errEl.classList.remove('hidden'); return; }
  const btn=document.getElementById('recovery-btn');
  if(btn){ btn.disabled=true; btn.innerHTML='<i class="fa-solid fa-circle-notch fa-spin"></i> Restaurando...'; }
  try {
    // A verificação do código e o reset acontecem no Worker (servidor).
    const r=await _workerReqPublic('/recuperar-acesso',{code});
    if(!r.ok) throw new Error(r.erro||'Não foi possível restaurar o acesso.');
    document.getElementById('recovery-new-user').textContent=r.username||'admin';
    document.getElementById('recovery-new-pass').textContent=r.senha||'';
    successEl.classList.remove('hidden');
    if(btn){ btn.style.display='none'; }
  } catch(e){
    errMsg.textContent=(e&&e.message)||'Erro ao restaurar acesso. Verifique a conexão.';
    errEl.classList.remove('hidden');
    if(btn){ btn.disabled=false; btn.innerHTML='<i class="fa-solid fa-unlock"></i> Restaurar Acesso'; }
  }
}

function roleLabel(role){
  if(role==='master')  return 'Master';
  if(role==='operador') return 'Operador';
  if(role && role.startsWith('p_')){
    const perfilId=role.replace('p_','');
    const perfil=(State.perfis||[]).find(p=>p.id===perfilId);
    return perfil?perfil.nome:'Perfil Custom.';
  }
  return 'Operador';
}

function applyUserSession(user){
  const _tbName=document.getElementById('topbar-user-name');
  if(_tbName) _tbName.textContent=user.username||'';
  // Trava de HORÁRIO DE ACESSO: fixa a regra da sessão e, se já estiver FORA da janela
  // (ex.: reload da página fora do horário), encerra a sessão. Master nunca é bloqueado.
  // Vale p/ login novo E restauração de sessão (ambos passam por aqui). #acesso-horario
  const _ar = (user.role==='master') ? null : _acessoNormalize((State.acessoUsuarios||{})[user.username]);
  _acessoRegraSessao = (_ar && _ar.ativa) ? _ar : null;
  if(_acessoRegraSessao && !_acessoPermitidoAgora(_acessoRegraSessao)){
    try{ Auth.log('ACESSO_BLOQUEADO_HORARIO', user.username, _acessoRegraLabel(_acessoRegraSessao)); }catch(_){}
    alert('Acesso permitido apenas '+_acessoRegraLabel(_acessoRegraSessao)+'. Fora desse horário o sistema fica bloqueado.');
    doLogout(); return;
  }
  _iniciarTimerAcesso();
  loadUserFoto();
  try{ _renderSomBtn(); }catch(_){}   // reflete o estado salvo do som de avisos. #som-avisos
  const mods=getUserModules(user);
  // Usuários & Acessos: master ou quem tem acesso ao log
  const usersLi=document.getElementById('nav-users-li');
  if(usersLi) usersLi.classList.toggle('hidden', !mods.users && !mods.log);
  // Colaboradores: quem tem acesso ao módulo employees
  const empLi=document.getElementById('nav-employees-li');
  if(empLi) empLi.classList.toggle('hidden', !mods.employees);
  // Documentos do colaborador (envio pelo app): mesma permissão de employees
  const docLi=document.getElementById('nav-documentos-li');
  if(docLi) docLi.classList.toggle('hidden', !mods.employees);
  // Documentos da Empresa (globais): permissão dedicada outorgável. Master sempre. #docs-empresa
  const docEmpLi=document.getElementById('nav-docsempresa-li');
  if(docEmpLi) docEmpLi.classList.toggle('hidden', !mods.documentosEmpresa && user.role!=='master');
  // Importar Holerites: quem pode enviar holerite (folhaEnviar) ou Master. #importar-holerite
  const impHolLi=document.getElementById('nav-importaholerite-li');
  if(impHolLi) impHolLi.classList.toggle('hidden', !mods.folhaEnviar && user.role!=='master');
  // Comunicação: módulo dedicado (delegável). Master sempre tem.
  const commLi=document.getElementById('nav-comunicacao-li');
  if(commLi) commLi.classList.toggle('hidden', !mods.comunicacao);
  // Link "Supervisor" na topbar — abre supervisor.html em nova aba.
  // So' aparece pra quem tem a permissao autorizarPonto.
  const linkSup=document.getElementById('topbar-link-supervisor');
  if(linkSup) linkSup.classList.toggle('hidden', !mods.autorizarPonto);
  // Autorizacoes (historico): mesma permissao do app de supervisor.
  const autzLi=document.getElementById('nav-autorizacoes-li');
  if(autzLi) autzLi.classList.toggle('hidden', !mods.autorizarPonto);
  if(mods.autorizarPonto) _initAutzBadge();   // contador de pendentes ao vivo no nav. #autz-badge
  // Monitor de Faltas: permissao dedicada (eu escolho quem). #monitor-faltas
  const mfLi=document.getElementById('nav-monitorfaltas-li');
  if(mfLi) mfLi.classList.toggle('hidden', !mods.monitorarFaltas);
  if(mods.monitorarFaltas) _initMonitorFaltasBadge();
  // Postos de Trabalho: master ou gestor
  const postosLi=document.getElementById('nav-postos-li');
  if(postosLi) postosLi.classList.toggle('hidden', !mods.postos);
  const escLi=document.getElementById('nav-escalas-li');
  if(escLi) escLi.classList.toggle('hidden', !mods.escalas);
  // Botão Revisar HE no card Horas Extras
  const btnHE=document.getElementById('btn-revisar-he');
  if(btnHE) btnHE.classList.toggle('hidden', !(mods.aprovaHE || user.role==='master'));
  const pagLi=document.getElementById('nav-pagamentos-li');
  if(pagLi) pagLi.classList.toggle('hidden', !mods.pagamentos);
  const benLi=document.getElementById('nav-beneficios-li');
  if(benLi) benLi.classList.toggle('hidden', !mods.pagamentos);
  const recLi=document.getElementById('nav-recibos-li');
  if(recLi) recLi.classList.toggle('hidden', !mods.pagamentos);
  const adiLi=document.getElementById('nav-adiantamentos-li');
  if(adiLi) adiLi.classList.toggle('hidden', !mods.pagamentos);
  const aprLi=document.getElementById('nav-aprovacoes-li');
  if(aprLi) aprLi.classList.toggle('hidden', !mods.pagamentosLancar && !mods.pagamentosAprovar);
  const decLi=document.getElementById('nav-decimoterceiro-li');
  if(decLi) decLi.classList.toggle('hidden', !mods.decimoterceiro);
  const ferLi=document.getElementById('nav-ferias-li');
  if(ferLi) ferLi.classList.toggle('hidden', !mods.ferias);
  const rescLi=document.getElementById('nav-rescisao-li');
  if(rescLi) rescLi.classList.toggle('hidden', !mods.rescisao);
  const contLi=document.getElementById('nav-contabilidade-li');
  if(contLi) contLi.classList.toggle('hidden', !mods.contabilidade);
  const contratosLi=document.getElementById('nav-contratos-li');
  if(contratosLi) contratosLi.classList.toggle('hidden', !mods.contratos);
  const estoqueLi=document.getElementById('nav-estoque-li');
  if(estoqueLi) estoqueLi.classList.toggle('hidden', !mods.estoque);
  const cfgLi=document.getElementById('nav-configuracoes-li');
  if(cfgLi) cfgLi.classList.toggle('hidden', !mods.configuracoes && user.role!=='master');
  const lgpdLi=document.getElementById('nav-lgpd-li');
  if(lgpdLi) lgpdLi.classList.toggle('hidden', !mods.lgpd && user.role!=='master');   // #lgpd
  showSection('dashboard');
  updateDbInfo();
}

// ============================================
// ALTERAR SENHA
// ============================================
function openChangePasswordModal(forced=false){
  document.getElementById('modal-change-pass').classList.remove('hidden');
  document.getElementById('change-pass-warn').style.display=forced?'':'none';
  document.getElementById('change-pass-close').style.display=forced?'none':'';
  document.getElementById('change-pass-cancel-btn').style.display=forced?'none':'';
  ['cp-current','cp-new','cp-confirm'].forEach(id=>setVal(id,''));
}

async function changePassword(){
  const user=Auth.currentUser; if(!user) return;
  const current=val('cp-current'), newPass=val('cp-new'), confirmPass=val('cp-confirm');
  if(!current){ toast('Informe a senha atual.','error'); return; }
  if(newPass.length<6){ toast('Mínimo 6 caracteres.','error'); return; }
  if(newPass!==confirmPass){ toast('Senhas não coincidem.','error'); return; }
  try {
    // Verificação e troca acontecem no Worker (a coleção users é só-servidor).
    const r=await _aprovacaoReq('/usuarios/trocar-senha',{currentPassword:current,newPassword:newPass});
    if(!r || r.ok!==true){ toast((r&&r.erro)||'Não foi possível alterar a senha.','error'); return; }
    user.forceChange=false;
    Auth.log('PASSWORD_CHANGED',user.username);
    closeModal('modal-change-pass');
    toast('Senha alterada com sucesso!');
  } catch(e){
    toast((e&&e.message)||'Erro ao alterar a senha.','error');
  }
}

// ============================================
// GERENCIAMENTO DE USUÁRIOS
// ============================================
// === Permissões POR USUÁRIO (substituem os perfis; perfis viram opcional/oculto). #perm-por-usuario ===
function _renderUsrPermissoes(modules, perm){
  modules=modules||{}; perm=perm||{};
  const box=document.getElementById('usr-permissoes'); if(!box) return;
  box.innerHTML = Object.keys(MODULOS_LABELS).map(mod=>{
    const checked = modules[mod] ? 'checked' : '';
    if(CRUD_MODULES.includes(mod)){
      const edChecked = (modules[mod] && perm[mod]!=='view') ? 'checked' : '';
      return `<div class="checkbox-label perm-card"><label class="perm-mod"><input type="checkbox" name="usrmod" value="${mod}" ${checked}> <span>${MODULOS_LABELS[mod]}</span></label><label class="perm-edit"><input type="checkbox" data-usredit="${mod}" ${edChecked}> Editar</label></div>`;
    }
    return `<label class="checkbox-label"><input type="checkbox" name="usrmod" value="${mod}" ${checked}> <span>${MODULOS_LABELS[mod]}</span></label>`;
  }).join('');
}
function _collectUsrPermissoes(){
  const modules={dashboard:true}, modulesPerm={};
  Object.keys(MODULOS_LABELS).forEach(mod=>{
    const chk=document.querySelector(`#usr-permissoes input[name="usrmod"][value="${mod}"]`);
    modules[mod]=chk?chk.checked:false;
    const ed=document.querySelector(`#usr-permissoes input[data-usredit="${mod}"]`);
    if(ed && modules[mod]) modulesPerm[mod]= ed.checked ? 'edit' : 'view';
  });
  return {modules, modulesPerm};
}
function _fillUsrCopiarSelect(excludeId){
  const sel=document.getElementById('usr-copiar-perms'); if(!sel) return;
  const opts=['<option value="">— começar do zero / não copiar —</option>'];
  (Auth.users||[]).filter(u=>u && u.id!==excludeId && u.role!=='master')
    .sort((a,b)=>(a.username||'').localeCompare(b.username||''))
    .forEach(u=>opts.push(`<option value="${u.id}">${u.username}</option>`));
  sel.innerHTML=opts.join(''); sel.value='';
}
function _usrCopiarPermissoes(userId){
  if(!userId) return;
  const u=(Auth.users||[]).find(x=>x.id===userId); if(!u) return;
  _renderUsrPermissoes(getUserModules(u), getUserPerms(u));
}
// Migração 1-clique: copia a permissão EFETIVA atual (via perfil) p/ dentro de cada usuário.
async function migrarPerfisParaUsuarios(){
  if(Auth.currentUser?.role!=='master') return;
  if(!confirm('Copiar as permissões atuais de cada usuário (vindas dos perfis) para DENTRO de cada usuário?\n\nNinguém perde nem ganha acesso — só passa a ser controlado por usuário. Quem já tem lista própria não é alterado.')) return;
  try{
    const map=(await DB.getDoc('configuracoes','permissoesUsuarios'))||{};
    let n=0;
    (Auth.users||[]).forEach(u=>{
      if(!u || u.role==='master' || map[u.username]) return;
      map[u.username]={ modules:getUserModules(u), modulesPerm:getUserPerms(u) };
      n++;
    });
    await DB.saveDoc('configuracoes','permissoesUsuarios',map,false);
    State.permissoesUsuarios=map;
    toast(`${n} usuário(s) migrado(s) para permissões próprias.`);
    if(State.currentSection==='users') renderUsersTable();
  }catch(e){ toast('Erro na migração.','error'); }
}

function openUserModal(id=null){
  if(Auth.currentUser?.role!=='master') return;
  // Atualizar opções de perfil com perfis customizados
  const roleSelect=document.getElementById('usr-role');
  roleSelect.innerHTML=`
    <option value="operador">Operador — só Folha de Ponto e Relatórios</option>
    <option value="master">Master — Acesso Total</option>`;
  (State.perfis||[]).forEach(p=>{
    const opt=document.createElement('option');
    opt.value='p_'+p.id; opt.textContent='Perfil: '+p.nome;
    roleSelect.appendChild(opt);
  });
  // Listener — toggla a visibilidade do bloco "Postos" e dos dispositivos conforme o perfil
  roleSelect.onchange=()=>{ _toggleUsrPostosGroup(); _refreshUsrDeviceRow(); };
  // Popular checkboxes de postos
  _renderUsrPostosCheckboxes([]);
  document.getElementById('modal-user').classList.remove('hidden');
  const editNote=document.getElementById('usr-edit-note');
  const titleEl=document.getElementById('modal-user-title');
  if(id){
    const u=Auth.users.find(u=>u.id===id); if(!u) return;
    titleEl.innerHTML='<i class="fa-solid fa-user-pen"></i> Editar Usuário';
    setVal('usr-id',u.id); setVal('usr-username',u.username);
    setVal('usr-email',u.email||'');
    setVal('usr-role', u.role==='master'?'master':'operador'); setVal('usr-active',String(u.active));
    setVal('usr-password',''); setVal('usr-password-confirm','');
    _renderUsrPostosCheckboxes(Array.isArray(u.postosResponsavel)?u.postosResponsavel:[]);
    _renderUsrPermissoes(getUserModules(u), getUserPerms(u)); _fillUsrCopiarSelect(u.id);   // #perm-por-usuario
    setVal('usr-max-dispositivos', String(u.maxDispositivos||1));
    _renderJanelaGrid(u.janelaNotif);
    _renderAcessoGrid((State.acessoUsuarios||{})[u.username]);   // trava de horário de acesso. #acesso-horario
    editNote.style.display='';
    _refreshUsrDeviceRow();
  } else {
    titleEl.innerHTML='<i class="fa-solid fa-user-plus"></i> Novo Usuário';
    ['usr-id','usr-username','usr-email','usr-password','usr-password-confirm'].forEach(i=>setVal(i,''));
    setVal('usr-role','operador'); setVal('usr-active','true');
    _renderUsrPermissoes({}, {}); _fillUsrCopiarSelect(null);   // #perm-por-usuario
    setVal('usr-max-dispositivos','1');
    _renderJanelaGrid(null);
    _renderAcessoGrid(null);   // trava de horário de acesso. #acesso-horario
    editNote.style.display='none';
    _refreshUsrDeviceRow();
  }
  _toggleUsrPostosGroup();
}

// Bloco de dispositivos autorizados no modal de usuário (trava de N máquinas).
// Master é livre → esconde. Mostra o limite (editável) + quantos já registraram.
// Lê o estado de Auth.users (com deviceIds/maxDispositivos vindos do Worker).
function _refreshUsrDeviceRow(){
  const row=document.getElementById('usr-device-row');
  if(!row) return;
  if(val('usr-role')==='master'){ row.style.display='none'; return; }
  row.style.display='';
  const id=val('usr-id');
  const u=id?Auth.users.find(x=>x.id===id):null;
  const n=u ? (Array.isArray(u.deviceIds)?u.deviceIds.length:(u.deviceId?1:0)) : 0;
  const max=Math.max(1, parseInt(val('usr-max-dispositivos'))||1);
  const status=document.getElementById('usr-device-status');
  if(status){
    status.innerHTML = id
      ? `<i class="fa-solid fa-laptop"></i> <strong style="color:${(n>0&&n>=max)?'#E65100':'#1B5E20'}">${n}</strong> de <strong>${max}</strong> dispositivo(s) registrado(s)${(n>0&&n>=max)?' — limite atingido':''}.`
      : 'As máquinas são registradas no 1º login de cada uma, até o limite.';
  }
  const resetBtn=document.getElementById('usr-device-reset-btn');
  if(resetBtn) resetBtn.style.display=(id&&n>0)?'':'none';
}

// Master libera um novo dispositivo pro usuário (zera o deviceId). No próximo
// login, a máquina que ele usar vira a nova autorizada. #trava-dispositivo
async function resetarDispositivoUsuario(id){
  if(Auth.currentUser?.role!=='master') return;
  const u=Auth.users.find(x=>x.id===id); if(!u){ toast('Usuário não encontrado.','error'); return; }
  if(!confirm(`Zerar os dispositivos de "${u.username}"?\n\nTodas as máquinas registradas deixam de valer. Nos próximos logins, as máquinas que ele usar viram as novas autorizadas (até o limite).`)) return;
  try{
    const r=await _aprovacaoReq('/usuarios/salvar',{
      user:{ id:u.id, username:u.username, email:u.email, role:u.role, active:u.active!==false,
             postosResponsavel:Array.isArray(u.postosResponsavel)?u.postosResponsavel:[],
             maxDispositivos:u.maxDispositivos||1 },
      resetDevice:true,
    });
    if(!r||r.ok!==true){ toast((r&&r.erro)||'Não foi possível resetar os dispositivos.','error'); return; }
    Auth.log('USER_DEVICE_RESET',Auth.currentUser.username,`Dispositivos zerados: ${u.username}`);
    toast(`Dispositivos de "${u.username}" zerados. Ele registra as novas máquinas nos próximos logins.`);
    await loadUsersFromWorker();
    if(State.currentSection==='users') renderUsersTable();
    if(val('usr-id')===id) _refreshUsrDeviceRow();
  }catch(e){ toast((e&&e.message)||'Erro ao resetar os dispositivos.','error'); }
}

// Mostra o bloco de "Postos sob responsabilidade" só quando o perfil não é Master.
function _toggleUsrPostosGroup(){
  const role=val('usr-role');
  const isMaster = role==='master';
  const grp=document.getElementById('usr-postos-group');
  if(grp) grp.style.display = isMaster ? 'none' : '';
  // Master NUNCA tem trava de horário de acesso (p/ não se trancar de fora). #acesso-horario
  const acc=document.getElementById('usr-acesso-group');
  if(acc) acc.style.display = isMaster ? 'none' : '';
  // Master = acesso total → some a lista de permissões por usuário. #perm-por-usuario
  const perm=document.getElementById('usr-permissoes-group');
  if(perm) perm.style.display = isMaster ? 'none' : '';
}

// Popula a grade de checkboxes de postos. `selecionados` é um array de razaoSocial.
function _renderUsrPostosCheckboxes(selecionados){
  const box=document.getElementById('usr-postos-list');
  if(!box) return;
  const postos=(State.postos||[]).slice().sort((a,b)=>(a.razaoSocial||'').localeCompare(b.razaoSocial||''));
  if(postos.length===0){
    box.innerHTML='<div style="color:var(--text-muted);font-size:12px;grid-column:1/-1;padding:4px">Nenhum posto cadastrado. Cadastre os postos primeiro em "Postos de Trabalho".</div>';
    return;
  }
  const sel=new Set(selecionados||[]);
  box.innerHTML=postos.map(p=>{
    const rs=(p.razaoSocial||'').replace(/"/g,'&quot;');
    const checked=sel.has(p.razaoSocial)?'checked':'';
    return `<label class="checkbox-label" style="font-size:13px;display:flex;align-items:center;gap:6px;padding:4px 6px;cursor:pointer">
      <input type="checkbox" name="usr-posto" value="${rs}" ${checked}>
      <span>${rs||'(sem nome)'}</span>
    </label>`;
  }).join('');
}

// ── Janela de notificações (por usuário) ──────────────────────────────── #janela-notif
// Define os dias/horários em que o usuário (supervisor/gestor) recebe avisos dos
// colaboradores via push. Fora da janela fica silencioso, exceto as exceções marcadas.
const _JANELA_DIAS_LABEL = ['Dom','Seg','Ter','Qua','Qui','Sex','Sáb'];
function _janelaDefault(){
  return { ativa:false,
    dias: Array.from({length:7}, ()=>({ on:false, ini:'06:00', fim:'22:00' })),
    excecoes: { folga:false, foraJanela:false, falta:false } };
}
// Coage um valor salvo (possivelmente incompleto/antigo) p/ o formato seguro.
function _janelaNormalize(j){
  const d=_janelaDefault();
  if(!j || typeof j!=='object') return d;
  const hm=(s,def)=>{ const m=/^(\d{1,2}):(\d{2})$/.exec(String(s||'')); if(!m) return def;
    let h=Math.min(23,+m[1]), mi=Math.min(59,+m[2]); return String(h).padStart(2,'0')+':'+String(mi).padStart(2,'0'); };
  const dias=[]; for(let i=0;i<7;i++){ const s=(Array.isArray(j.dias)&&j.dias[i])||{}; dias.push({ on:!!s.on, ini:hm(s.ini,'06:00'), fim:hm(s.fim,'22:00') }); }
  const ex=j.excecoes||{};
  return { ativa:!!j.ativa, dias, excecoes:{ folga:!!ex.folga, foraJanela:!!ex.foraJanela, falta:!!ex.falta } };
}
// Renderiza a grade dos 7 dias dentro do modal de usuário.
// ============================================================
// TRAVA DE HORÁRIO DE ACESSO ao sistema (por usuário; Master NUNCA é bloqueado)
// ============================================================
// MESMO PADRÃO da Janela de notificações (decisão do dono 2026-06-27): grade por dia,
// cada dia com seu próprio horário (on/ini/fim) — { ativa, dias:[{on,ini,fim}×7] }.
// Reusa _inJanela (avalia a janela do dia + virada de meia-noite). Guardada no Firestore
// em configuracoes/acessoUsuarios (FORA do Worker), chaveada por username. Avaliada no
// LOGIN (doLogin), na restauração de sessão (applyUserSession) e por um timer de 60s que
// DESLOGA quem sai da janela. Lado cliente (relógio LOCAL) — app sem back-end. #acesso-horario
let _acessoRegraSessao=null, _acessoTimer=null;
function _acessoDefault(){
  return { ativa:false, feriadoLibera:false, dias: Array.from({length:7}, ()=>({ on:false, ini:'08:00', fim:'18:00' })) };
}
// Coage qualquer formato salvo p/ {ativa, dias:[{on,ini,fim}]}. Converte também o formato
// ANTIGO de janela única ({restrito, dias:[0..6], inicio, fim}) p/ a grade por dia. #acesso-horario
function _acessoNormalize(j){
  const def=_acessoDefault();
  if(!j || typeof j!=='object') return def;
  const hm=(s,d)=>{ const m=/^(\d{1,2}):(\d{2})$/.exec(String(s||'')); if(!m) return d; return String(Math.min(23,+m[1])).padStart(2,'0')+':'+String(Math.min(59,+m[2])).padStart(2,'0'); };
  // Formato antigo (janela única): dias é lista de números + tem inicio/fim/restrito.
  if(Array.isArray(j.dias) && (j.dias.length===0 || typeof j.dias[0]==='number')){
    const set=new Set(j.dias), ini=hm(j.inicio,'08:00'), fim=hm(j.fim,'18:00');
    return { ativa:!!j.restrito, feriadoLibera:!!j.feriadoLibera, dias: Array.from({length:7},(_,i)=>({ on:set.has(i), ini, fim })) };
  }
  const dias=[]; for(let i=0;i<7;i++){ const s=(Array.isArray(j.dias)&&j.dias[i])||{}; dias.push({ on:!!s.on, ini:hm(s.ini,'08:00'), fim:hm(s.fim,'18:00') }); }
  return { ativa:!!j.ativa, feriadoLibera:!!j.feriadoLibera, dias };
}
function _acessoPermitidoAgora(regra, d){
  const j=_acessoNormalize(regra);
  if(!j.ativa) return true;                  // sem restrição = acessa sempre
  const dt=d||new Date();
  // Feriado é "contabilizado": por padrão BLOQUEIA o acesso o dia todo; o checkbox
  // "Liberar acesso em feriados" libera (ex.: escalado p/ HE no feriado). #acesso-feriado
  if(_ehFeriado(dt.getFullYear(), dt.getMonth()+1, dt.getDate())) return !!j.feriadoLibera;
  return _inJanela(j, dt);                    // MESMA avaliação por dia da janela de notificações
}
function _acessoRegraLabel(regra){
  const j=_acessoNormalize(regra);
  if(!j.ativa) return 'sem restrição';
  const parts=j.dias.map((x,i)=> x.on ? `${_JANELA_DIAS_LABEL[i]} ${x.ini}-${x.fim}` : null).filter(Boolean);
  return parts.length ? parts.join(' · ') : '(nenhum dia liberado)';
}
function _renderAcessoGrid(regra){
  const j=_acessoNormalize(regra);
  const chk=document.getElementById('usr-acesso-restrito'); if(chk) chk.checked=j.ativa;
  const chkFer=document.getElementById('usr-acesso-feriado-libera'); if(chkFer) chkFer.checked=j.feriadoLibera;
  const box=document.getElementById('usr-acesso-dias');
  if(box){
    const dim=on=>on?'':'opacity:.4';
    box.innerHTML = j.dias.map((d,i)=>`
      <div class="usr-acesso-row" style="display:flex;align-items:center;gap:8px;padding:3px 0">
        <label style="display:flex;align-items:center;gap:6px;min-width:78px;cursor:pointer;font-size:13px">
          <input type="checkbox" class="usr-acesso-dia-on" data-dia="${i}" onchange="_acessoDiaToggle(this)" ${d.on?'checked':''}> <span>${_JANELA_DIAS_LABEL[i]}</span>
        </label>
        <input type="time" class="usr-acesso-dia-ini" data-dia="${i}" value="${d.ini}" ${d.on?'':'disabled'} style="padding:4px 6px;border:1px solid var(--border);border-radius:6px;font-size:13px;${dim(d.on)}">
        <span class="usr-acesso-arrow" style="color:var(--text-muted);${dim(d.on)}">→</span>
        <input type="time" class="usr-acesso-dia-fim" data-dia="${i}" value="${d.fim}" ${d.on?'':'disabled'} style="padding:4px 6px;border:1px solid var(--border);border-radius:6px;font-size:13px;${dim(d.on)}">
        <span class="usr-acesso-naoacessa" style="font-size:11px;color:#c62828;font-weight:600;${d.on?'display:none':''}">não acessa</span>
      </div>`).join('');
  }
  _toggleAcessoConfig();
}
function _acessoDiaToggle(cb){
  const on=cb.checked, row=cb.closest('.usr-acesso-row'); if(!row) return;
  row.querySelectorAll('input[type=time]').forEach(inp=>{ inp.disabled=!on; inp.style.opacity=on?'':'.4'; });
  const arrow=row.querySelector('.usr-acesso-arrow'); if(arrow) arrow.style.opacity=on?'':'.4';
  const nr=row.querySelector('.usr-acesso-naoacessa'); if(nr) nr.style.display=on?'none':'';
}
function _toggleAcessoConfig(){
  const on=!!document.getElementById('usr-acesso-restrito')?.checked;
  const box=document.getElementById('usr-acesso-config'); if(box) box.style.display=on?'':'none';
}
function _collectAcessoRegra(){
  const j=_acessoDefault();
  j.ativa=!!document.getElementById('usr-acesso-restrito')?.checked;
  j.feriadoLibera=!!document.getElementById('usr-acesso-feriado-libera')?.checked;
  document.querySelectorAll('.usr-acesso-dia-on').forEach(c=>{ const i=+c.dataset.dia; if(j.dias[i]) j.dias[i].on=c.checked; });
  document.querySelectorAll('.usr-acesso-dia-ini').forEach(c=>{ const i=+c.dataset.dia; if(j.dias[i]&&c.value) j.dias[i].ini=c.value; });
  document.querySelectorAll('.usr-acesso-dia-fim').forEach(c=>{ const i=+c.dataset.dia; if(j.dias[i]&&c.value) j.dias[i].fim=c.value; });
  return _acessoNormalize(j);
}
// Timer de sessão: desloga quem está logado quando a janela de acesso termina. Master ileso.
function _iniciarTimerAcesso(){
  if(_acessoTimer) return;
  _acessoTimer=setInterval(()=>{
    const u=Auth.currentUser;
    if(!u || u.role==='master' || !_acessoRegraSessao) return;
    if(!_acessoPermitidoAgora(_acessoRegraSessao)){
      clearInterval(_acessoTimer); _acessoTimer=null;
      try{ Auth.log('LOGOUT_FORA_HORARIO', u.username, _acessoRegraLabel(_acessoRegraSessao)); }catch(_){}
      alert('Seu horário de acesso ao sistema terminou ('+_acessoRegraLabel(_acessoRegraSessao)+'). O sistema será encerrado.');
      doLogout();
    }
  }, 60*1000);
}

