// Lê a UI do modal → objeto janelaNotif.
function _collectJanelaNotif(){
  const j=_janelaDefault();
  j.ativa = !!document.getElementById('usr-janela-ativa')?.checked;
  document.querySelectorAll('.usr-janela-dia-on').forEach(c=>{ const i=+c.dataset.dia; if(j.dias[i]) j.dias[i].on=c.checked; });
  document.querySelectorAll('.usr-janela-dia-ini').forEach(c=>{ const i=+c.dataset.dia; if(j.dias[i]&&c.value) j.dias[i].ini=c.value; });
  document.querySelectorAll('.usr-janela-dia-fim').forEach(c=>{ const i=+c.dataset.dia; if(j.dias[i]&&c.value) j.dias[i].fim=c.value; });
  j.excecoes.folga      = !!document.getElementById('usr-exc-folga')?.checked;
  j.excecoes.foraJanela = !!document.getElementById('usr-exc-forajanela')?.checked;
  j.excecoes.falta      = !!document.getElementById('usr-exc-falta')?.checked;
  return _janelaNormalize(j);
}
// ── Avaliação da janela (lógica compartilhada com o worker) ──────────────
// `now` está NA janela? Trata virada de meia-noite (fim<=ini) e o rabo do dia anterior.
function _inJanela(janela, d){
  const wd=d.getDay(), now=d.getHours()*60+d.getMinutes();
  const hm=s=>{ const p=String(s||'').split(':'); return (+p[0]||0)*60+(+p[1]||0); };
  const dias=(janela&&janela.dias)||[];
  const hoje=dias[wd];
  if(hoje && hoje.on){
    const ini=hm(hoje.ini), fim=hm(hoje.fim);
    if(fim>ini){ if(now>=ini && now<fim) return true; }
    else       { if(now>=ini) return true; }            // vira meia-noite: ini→24:00 é hoje
  }
  const prev=dias[(wd+6)%7];                              // rabo do dia anterior (00:00→fim)
  if(prev && prev.on){ const ini=hm(prev.ini), fim=hm(prev.fim); if(fim<=ini && now<fim) return true; }
  return false;
}
// Decide se um aviso do tipo `tipo` ('foraJanela'|'folga'|'falta') pode notificar AGORA.
function _janelaPermiteAgora(janela, tipo, d){
  d=d||new Date();
  if(!janela || !janela.ativa) return true;              // sem restrição = recebe sempre
  if(_inJanela(janela, d)) return true;
  const e=janela.excecoes||{};
  if(tipo==='folga'      && e.folga)      return true;
  if(tipo==='foraJanela' && e.foraJanela) return true;
  if(tipo==='falta'      && e.falta)      return true;
  return false;                                          // fora da janela e sem exceção → segura
}

// Carrega a lista de usuários do Worker (a coleção users é só-servidor).
async function loadUsersFromWorker(){
  try {
    const r=await _aprovacaoReq('/usuarios/listar',{});
    if(r && r.ok && Array.isArray(r.usuarios)){ Auth.users=r.usuarios; return true; }
  } catch(e){ console.warn('Listar usuários:', (e&&e.message)||e); }
  return false;
}

// Descreve, em texto claro, O QUE mudou ao salvar um usuário — p/ o Log de Acessos
// ficar específico (auditoria/LGPD). Recebe o snapshot ANTES das gravações. #log-detalhado
function _descreverEdicaoUsuario(oldUser, oldMods, oldAcessoAtiva, novo){
  if(!oldUser){
    const n = novo.modules ? Object.keys(novo.modules).filter(k=>novo.modules[k] && k!=='dashboard').length : 0;
    return `Criado: ${novo.username} — ${novo.role==='master'?'tipo Master (acesso total)':`tipo Usuário, ${n} permissão(ões)`}${novo.active?'':', INATIVO'}`;
  }
  const p=[];
  if((oldUser.active!==false)!==!!novo.active) p.push(`status ${oldUser.active!==false?'Ativo':'Inativo'}→${novo.active?'Ativo':'Inativo'}`);
  const om=oldUser.role==='master', nm=novo.role==='master';
  if(om!==nm) p.push(`tipo ${om?'Master':'Usuário'}→${nm?'Master':'Usuário'}`);
  const oP=Array.isArray(oldUser.postosResponsavel)?oldUser.postosResponsavel.length:0;
  const nP=Array.isArray(novo.postosResponsavel)?novo.postosResponsavel.length:0;
  if(oP!==nP) p.push(`postos sob responsabilidade ${oP}→${nP}`);
  if((oldUser.maxDispositivos||1)!==(novo.maxDispositivos||1)) p.push(`máx. dispositivos ${oldUser.maxDispositivos||1}→${novo.maxDispositivos||1}`);
  if(!nm && novo.modules){
    const lib=[], rev=[];
    Object.keys(MODULOS_LABELS).forEach(k=>{ const a=!!(oldMods||{})[k], b=!!novo.modules[k]; if(b&&!a) lib.push(MODULOS_LABELS[k]); if(a&&!b) rev.push(MODULOS_LABELS[k]); });
    if(lib.length) p.push(`liberou permissões: ${lib.join(', ')}`);
    if(rev.length) p.push(`revogou permissões: ${rev.join(', ')}`);
  }
  if(!!oldAcessoAtiva!==!!novo.acessoAtiva) p.push(`trava de horário de acesso ${novo.acessoAtiva?'ATIVADA':'desativada'}`);
  if(novo.senhaTrocada) p.push('senha redefinida');
  return `Editado: ${novo.username}${p.length?' — '+p.join('; '):' (sem mudanças relevantes)'}`;
}

async function saveUser(){
  if(Auth.currentUser?.role!=='master') return;
  const id=val('usr-id'), username=val('usr-username').toLowerCase().replace(/\s+/g,'.'),
        role=val('usr-role'), active=val('usr-active')==='true',
        password=val('usr-password'), confirmPw=val('usr-password-confirm'),
        email=(val('usr-email')||'').trim().toLowerCase();
  if(!username){ toast('Usuário obrigatório.','error'); return; }
  if(!email || !/^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(email)){ toast('Informe um e-mail válido — necessário para o login seguro.','error'); return; }
  if(password){
    if(password.length<6){ toast('Mínimo 6 caracteres.','error'); return; }
    if(password!==confirmPw){ toast('Senhas não coincidem.','error'); return; }
  } else if(!id){
    toast('Informe uma senha.','error'); return;
  }
  // Coleta os postos selecionados (vazio = sem restrição). Master ignora.
  const postosResponsavel = role==='master'
    ? []
    : Array.from(document.querySelectorAll('#usr-postos-list input[name="usr-posto"]:checked')).map(c=>c.value);
  const maxDispositivos = role==='master' ? 1 : Math.max(1, parseInt(val('usr-max-dispositivos'))||1);
  const janelaNotif = _collectJanelaNotif();
  const btn=document.querySelector('#modal-user .btn-primary');
  setBtnLoading(btn,true,'');
  // Snapshot ANTES das gravações, p/ descrever o que mudou no Log. #log-detalhado
  const _oldUser = id ? Auth.users.find(u=>u.id===id) : null;
  const _oldMods = _oldUser ? getUserModules(_oldUser) : {};
  const _oldAcessoAtiva = _oldUser ? !!_acessoNormalize((State.acessoUsuarios||{})[_oldUser.username]).ativa : false;
  const _novoPerm = role==='master' ? null : _collectUsrPermissoes();
  try {
    const r=await _aprovacaoReq('/usuarios/salvar',{
      user:{ id:id||undefined, username, email, role, active, postosResponsavel, maxDispositivos, janelaNotif },
      novaSenha: password||undefined,
    });
    if(!r || r.ok!==true){ toast((r&&r.erro)||'Não foi possível salvar o usuário.','error'); return; }
    // Trava de HORÁRIO DE ACESSO — guardada no Firestore (fora do Worker), chaveada por
    // username. Master nunca tem regra (removida se existir). Read-modify-write p/ não
    // sobrescrever as regras dos outros usuários. #acesso-horario
    try{
      const _acc=(await DB.getDoc('configuracoes','acessoUsuarios'))||{};
      const _reg=_collectAcessoRegra();
      if(role==='master' || !_reg.ativa) delete _acc[username];
      else _acc[username]=_reg;
      State.acessoUsuarios=_acc;
      await DB.saveDoc('configuracoes','acessoUsuarios',_acc,false);
    }catch(e){ console.warn('salvar trava de horário de acesso', e); }
    // PERMISSÕES POR USUÁRIO — Firestore (fora do Worker), por username; read-modify-write
    // p/ não sobrescrever os outros. Master = acesso total (remove a lista). #perm-por-usuario
    try{
      const _pm=(await DB.getDoc('configuracoes','permissoesUsuarios'))||{};
      if(role==='master') delete _pm[username];
      else _pm[username]=_novoPerm;
      State.permissoesUsuarios=_pm;
      await DB.saveDoc('configuracoes','permissoesUsuarios',_pm,false);
    }catch(e){ console.warn('salvar permissões do usuário', e); }
    const _detLog=_descreverEdicaoUsuario(_oldUser, _oldMods, _oldAcessoAtiva, {
      username, role, active, postosResponsavel, maxDispositivos,
      modules:_novoPerm?_novoPerm.modules:null,
      acessoAtiva: role!=='master' && !!_collectAcessoRegra().ativa,
      senhaTrocada: !!password
    });
    Auth.log(id?'USER_UPDATED':'USER_CREATED',Auth.currentUser.username,_detLog);
    toast(`Usuário "${username}" ${id?'atualizado':'criado'}.`);
    closeModal('modal-user');
    await loadUsersFromWorker();
    if(State.currentSection==='users') renderUsersTable();
  } catch(e){
    toast((e&&e.message)||'Erro ao salvar usuário.','error');
  } finally {
    setBtnLoading(btn,false,'<i class="fa-solid fa-floppy-disk"></i> Salvar');
  }
}

// ================= MONITOR DE LGPD (#lgpd) — ferramenta TÉCNICA de apoio; NÃO é parecer jurídico =================
function _lgpdDiasDesde(ts){ if(!ts) return Infinity; try{ return Math.floor((Date.now()-new Date(ts).getTime())/86400000); }catch(_){ return Infinity; } }
function _lgpdChecks(){
  const out=[];
  const users=(Auth.users||[]).filter(Boolean);
  const emps=(State.employees||[]).filter(Boolean);
  const acesso=State.acessoUsuarios||{};
  const log=(Auth.accessLog||[]);
  const sensiveis=['employees','contabilidade','pagamentos'];
  const ociosos=users.filter(u=>u.active!==false && u.role!=='master' && _lgpdDiasDesde(u.lastLogin)>90);
  out.push(ociosos.length? {nivel:'risco',titulo:'Contas ativas sem acesso há +90 dias',detalhe:`${ociosos.length} conta(s): ${ociosos.map(u=>u.username).join(', ')}. Conta ociosa = porta aberta para dado pessoal.`,corrigir:'Inative ou remova quem não usa mais (Usuários & Acessos).',nav:'users'} : {nivel:'ok',titulo:'Sem contas ativas ociosas',detalhe:'Todas as contas ativas tiveram acesso nos últimos 90 dias.',nav:'users'});
  const masters=users.filter(u=>u.role==='master'&&u.active!==false);
  out.push(masters.length>2? {nivel:'aviso',titulo:'Muitos administradores Master',detalhe:`${masters.length} contas Master (acesso TOTAL a todos os dados): ${masters.map(u=>u.username).join(', ')}. A LGPD pede minimizar quem vê tudo.`,corrigir:'Dê permissões específicas por usuário em vez de Master.',nav:'users'} : {nivel:'ok',titulo:'Quantidade de Master adequada',detalhe:`${masters.length} administrador(es) Master.`,nav:'users'});
  const semTrava=users.filter(u=>{ if(u.role==='master'||u.active===false) return false; const m=getUserModules(u); return sensiveis.some(k=>m[k]) && !_acessoNormalize(acesso[u.username]).ativa; });
  out.push(semTrava.length? {nivel:'aviso',titulo:'Acesso a dados sensíveis sem trava de horário',detalhe:`${semTrava.length} usuário(s) veem cadastro/salário sem restrição de horário: ${semTrava.map(u=>u.username).join(', ')}.`,corrigir:'Ative a trava de horário de acesso no cadastro desses usuários.',nav:'users'} : {nivel:'ok',titulo:'Dados sensíveis com controle de horário',detalhe:'Quem vê dado sensível tem trava de horário (ou é Master).',nav:'users'});
  const demAntigos=emps.filter(e=>(e.status==='demitido'||e.status==='inativo') && e.dataDemissao && _lgpdDiasDesde(e.dataDemissao+'T00:00:00')>365*5);
  out.push(demAntigos.length? {nivel:'aviso',titulo:'Ex-colaboradores retidos há +5 anos',detalhe:`${demAntigos.length} demitido(s) há mais de 5 anos com cadastro completo. Reveja a retenção (atenção: obrigações trabalhistas/fiscais podem exigir a guarda — confirme com o contador).`,corrigir:'Anonimize/elimine o que não tem mais finalidade ou base legal.',nav:'employees'} : {nivel:'ok',titulo:'Retenção de ex-colaboradores ok',detalhe:'Nenhum demitido com +5 anos pendente de revisão.',nav:'employees'});
  const veSaude=users.filter(u=>u.active!==false && (u.role==='master'||getUserModules(u).employees));
  out.push({nivel:'info',titulo:'Acesso a dados de saúde (atestados)',detalhe:`${veSaude.length} usuário(s) podem ver atestados médicos (dado sensível especial): ${veSaude.map(u=>u.username).join(', ')}. Garanta que só quem precisa tenha esse acesso.`,corrigir:'Os atestados ficam no cadastro do Colaborador; reveja também as permissões de quem acessa.',nav:'employees'});
  const semEmail=users.filter(u=>u.active!==false && u.role!=='master' && !u.email);
  out.push(semEmail.length? {nivel:'risco',titulo:'Usuários sem e-mail de login seguro',detalhe:`${semEmail.length}: ${semEmail.map(u=>u.username).join(', ')}.`,corrigir:'Cadastre e-mail (login seguro) para todos.',nav:'users'} : {nivel:'ok',titulo:'Login seguro configurado',detalhe:'Todos os usuários têm e-mail de login.',nav:'users'});
  const logRec=log.filter(e=>_lgpdDiasDesde(e.timestamp)<=30).length;
  out.push(logRec>0? {nivel:'ok',titulo:'Trilha de auditoria ativa',detalhe:`${logRec} evento(s) registrados nos últimos 30 dias — quem fez o quê está preservado.`,nav:'users'} : {nivel:'aviso',titulo:'Pouca atividade no log',detalhe:'Sem registros recentes — confirme que a trilha de auditoria está sendo preservada.',nav:'users'});
  return out;
}
function _lgpdEventosSensiveis(dias){
  dias=dias||186;
  const classifica=(t,det)=>{
    t=String(t||''); det=String(det||'');
    if(/EMPLOYEE|COLABORAD/i.test(t)) return {cat:/DELET|EXCLU|REMOV/i.test(t)?'Exclusão / anulação de dados':'Alteração de dado de colaborador',cor:'#c62828',ic:'fa-user-pen',nav:'employees'};
    if(/DELET|EXCLU|LIMP|REMOV|ANULAD|DESFEITO/i.test(t)) return {cat:'Exclusão / anulação de dados',cor:'#c62828',ic:'fa-trash',nav:'users'};
    if(/EXPORT|CSV|BACKUP/i.test(t)) return {cat:'Exportação de dados',cor:'#E65100',ic:'fa-file-export',nav:'users'};
    if(/USER_CREATED|USER_UPDATED|PERFIL|LGPD/i.test(t) || /permiss|trava de hor/i.test(det)) return {cat:'Mudança de acesso / permissão',cor:'#6A1B9A',ic:'fa-user-shield',nav:'users'};
    if(/RECIBO_ENVIADO|HOLERITE|FOLHA.*ENVI|ENVIAD/i.test(t)) return {cat:'Envio de dado pessoal',cor:'#1565C0',ic:'fa-paper-plane',nav:'recibos'};
    if(/BLOQUEAD|FORA_HORARIO|NEGAD/i.test(t)) return {cat:'Acesso bloqueado / negado',cor:'#00838F',ic:'fa-ban',nav:'users'};
    return null;
  };
  return (Auth.accessLog||[]).filter(e=>_lgpdDiasDesde(e.timestamp)<=dias)
    .map(e=>{ const c=classifica(e.type,e.details); return c?{...e,...c}:null; }).filter(Boolean);
}
function _lgpdAttr(s){ return String(s||'').replace(/&/g,'&amp;').replace(/"/g,'&quot;').replace(/</g,'&lt;'); }
async function salvarLgpdConfig(){
  if(!getUserModules(Auth.currentUser).lgpd && Auth.currentUser?.role!=='master') return;
  const cfg={ nome:val('lgpd-dpo-nome').trim(), oab:val('lgpd-dpo-oab').trim(), email:(val('lgpd-dpo-email')||'').trim(), telefone:val('lgpd-dpo-tel').trim() };
  try{ await DB.saveDoc('configuracoes','lgpdConfig',cfg,false); State.lgpdConfig=cfg; Auth.log('LGPD_DPO_SALVO',Auth.currentUser.username,`Encarregado: ${cfg.nome||'—'}${cfg.oab?' ('+cfg.oab+')':''}`); toast('Encarregado (DPO) salvo.'); }
  catch(e){ toast('Erro ao salvar o responsável.','error'); }
}
// Política de Privacidade e Proteção de Dados (LGPD) — template preenchido com a empresa
// e o Encarregado/DPO. Conteúdo jurídico-base; revisar com advogado. #lgpd
function _lgpdPoliticaHtml(){
  const emp=_e('nomeEmpresa')||'a Empresa';
  const cfg=State.lgpdConfig||{};
  const dpo=(cfg.nome||cfg.email||cfg.telefone||cfg.oab)
    ? `${cfg.nome||'—'}${cfg.oab?` (OAB ${cfg.oab})`:''}${cfg.email?` · ${cfg.email}`:''}${cfg.telefone?` · ${cfg.telefone}`:''}`
    : '<em>(defina o Encarregado/DPO no campo acima)</em>';
  const S=(t,c)=>`<h4 style="margin:14px 0 4px;color:#1a3a6b;font-size:14px">${t}</h4><div style="font-size:13px;line-height:1.6;color:#333">${c}</div>`;
  return `
  <p style="font-size:13px;line-height:1.6;color:#333"><strong>${emp}</strong>, na qualidade de <strong>Controladora</strong> de dados, está comprometida com a proteção da privacidade e dos dados pessoais que trata, em conformidade com a <strong>Lei nº 13.709/2018 (LGPD)</strong>. Esta Política explica quais dados coletamos, por que, como os protegemos e quais são os direitos dos titulares.</p>
  ${S('1. Encarregado pelo Tratamento de Dados (DPO)',`Contato para assuntos de proteção de dados: <strong>${dpo}</strong>.`)}
  ${S('2. Dados pessoais que tratamos',`<ul style="margin:4px 0 0 18px"><li><strong>De colaboradores:</strong> nome, CPF, RG, CTPS, PIS, data de nascimento, endereço, telefone, e-mail, dados bancários/PIX, foto, cargo, jornada, registros de ponto, salário e verbas, dependentes e <strong>dados de saúde</strong> (atestados/afastamentos — dado pessoal sensível).</li><li><strong>Imagens e áudio (CFTV):</strong> nas <strong>portarias e áreas comuns</strong> dos condomínios em que atuamos, captamos <strong>imagem e, quando sinalizado, áudio</strong> por câmeras de segurança, que podem registrar colaboradores, moradores, visitantes e prestadores.</li></ul>`)}
  ${S('3. Finalidades e bases legais',`<ul style="margin:4px 0 0 18px"><li><strong>Gestão de pessoal e folha</strong> (admissão, ponto, pagamento, benefícios, obrigações acessórias): execução do contrato de trabalho e <strong>cumprimento de obrigação legal/regulatória</strong> (CLT, eSocial, fiscais).</li><li><strong>Dados de saúde (atestados):</strong> cumprimento de obrigação legal trabalhista e proteção da vida.</li><li><strong>Imagem e áudio (CFTV):</strong> <strong>segurança patrimonial e das pessoas</strong> e <strong>apuração de faltas disciplinares</strong> cometidas durante o expediente, com base no <strong>legítimo interesse</strong> e no <strong>exercício regular de direitos</strong>, com aviso/sinalização nos locais monitorados.</li></ul>`)}
  ${S('4. Câmeras e áudio em portarias e áreas comuns',`O monitoramento por CFTV tem <strong>finalidade de segurança</strong> das pessoas e do patrimônio. Os ambientes monitorados são <strong>sinalizados</strong>. As imagens e áudios podem ser utilizados para <strong>apuração de incidentes de segurança</strong>, para <strong>apuração de faltas disciplinares cometidas durante o expediente</strong> e para o cumprimento de exigência legal. <strong>Não</strong> são utilizados para o monitoramento contínuo de produtividade. Áreas de expectativa de privacidade (banheiros, vestiários) <strong>não</strong> são monitoradas. As gravações são guardadas por período limitado e necessário (em regra, até <strong>15 dias</strong>, salvo necessidade de apuração) e o acesso é restrito a pessoas autorizadas.`)}
  ${S('5. Compartilhamento',`Compartilhamos dados apenas quando necessário: com o <strong>contador/contabilidade</strong>, <strong>órgãos públicos</strong> (eSocial, Receita, Justiça do Trabalho, INSS), <strong>instituições financeiras</strong> (pagamento) e <strong>condomínios contratantes</strong> no limite da prestação do serviço. Não vendemos dados pessoais.`)}
  ${S('6. Retenção e eliminação',`Mantemos os dados pelo tempo necessário às finalidades e às obrigações legais (ex.: documentos trabalhistas/previdenciários pelos prazos legais). Os <strong>registros de acesso ao sistema</strong> são mantidos por <strong>6 meses</strong>. As <strong>imagens de CFTV</strong>, em regra, por até <strong>15 dias</strong>. Findo o prazo e a finalidade, os dados são eliminados ou anonimizados.`)}
  ${S('7. Direitos do titular',`Nos termos do art. 18 da LGPD, o titular pode solicitar: confirmação e acesso aos dados; correção; anonimização, bloqueio ou eliminação; portabilidade; informação sobre compartilhamentos; e revogação de consentimento. Os pedidos devem ser dirigidos ao Encarregado (item 1).`)}
  ${S('8. Segurança',`Adotamos medidas técnicas e administrativas: <strong>controle de acesso por usuário</strong> (cada pessoa só acessa o necessário), restrição de horário de acesso, <strong>trilha de auditoria</strong> de operações sensíveis, autenticação e segregação de dados por organização.`)}
  ${S('9. Atualizações',`Esta Política pode ser atualizada. A versão vigente fica disponível no sistema. Última geração: ${new Date().toLocaleDateString('pt-BR')}.`)}
  <p style="font-size:11px;color:#888;margin-top:14px;border-top:1px solid #eee;padding-top:8px">Documento-base gerado pelo DRG-Kronos como apoio à conformidade. Recomenda-se a revisão por advogado/DPO antes da publicação.</p>`;
}
