function baixarOtsTermo(id){
  const t=(State.termosLgpd||[]).find(x=>x.id===id); if(!t||!t.carimboOts){ toast('Carimbo ainda não gerado (o robô carimba após a assinatura).','warning'); return; }
  try{
    const bin=atob(t.carimboOts); const arr=new Uint8Array(bin.length); for(let i=0;i<bin.length;i++) arr[i]=bin.charCodeAt(i);
    const blob=new Blob([arr],{type:'application/octet-stream'}); const a=document.createElement('a');
    a.href=URL.createObjectURL(blob); a.download=`carimbo_${(t.employeeNome||'termo').replace(/[^\w]+/g,'_')}.ots`; a.click(); URL.revokeObjectURL(a.href);
    toast('Arquivo .ots baixado — verificável em opentimestamps.org');
  }catch(e){ toast('Erro ao baixar o .ots.','error'); }
}
// Baixa o ARQUIVO EXATO cujo SHA-256 foi carimbado no blockchain (.ots), p/ conferência em
// opentimestamps.org. Conteúdo = a MESMA string que o app assinou (conteudo|pinHash|ip|ua|
// fingerprint|ts) — sem cabeçalho/BOM, senão o hash não bate. Recalcula e confere o hash
// localmente antes de baixar. #lgpd-termo #carimbo-tempo
async function baixarTermoConferencia(id){
  const t=(State.termosLgpd||[]).find(x=>x.id===id);
  if(!t || t.status!=='assinado' || !t.assinatura){ toast('Termo ainda não assinado — não há hash para conferir.','warning'); return; }
  const a=t.assinatura;
  const conteudo = (a.conteudoJson!=null) ? a.conteudoJson : (t.conteudoHtml||'');
  const ts = a.assinadoEm || t.assinadoEm || '';
  const hashInput = `${conteudo}|${a.pinHash||''}|${a.ip||''}|${a.userAgent||''}|${a.deviceFingerprint||''}|${ts}`;
  // Confere se o hash recomputado bate com o que foi assinado/carimbado (garante o arquivo certo).
  let okHash=null;
  try{
    const buf=await crypto.subtle.digest('SHA-256', new TextEncoder().encode(hashInput));
    const hex=Array.from(new Uint8Array(buf)).map(b=>b.toString(16).padStart(2,'0')).join('');
    okHash=(hex===(a.hash||''));
  }catch(_){ okHash=null; }
  if(okHash===false){
    if(!confirm('Atenção: o hash recalculado NÃO bateu com o hash assinado (termo de formato antigo?). O arquivo pode não validar no blockchain. Baixar mesmo assim?')) return;
  }
  try{
    const nome=(t.employeeNome||'termo').replace(/[^\w]+/g,'_');
    const blob=new Blob([hashInput],{type:'application/octet-stream'});   // UTF-8, sem BOM — bytes idênticos ao que gerou o hash
    const el=document.createElement('a'); el.href=URL.createObjectURL(blob);
    el.download=`termo_lgpd_${nome}_${(a.hash||'').slice(0,8)}.txt`; el.click(); URL.revokeObjectURL(el.href);
    toast(okHash===false
      ? 'Arquivo baixado (atenção: o hash não confere localmente).'
      : 'Arquivo de conferência baixado. Em opentimestamps.org (Verify), suba ESTE arquivo + o .ots para validar a data na rede Bitcoin.','success');
  }catch(e){ toast('Erro ao baixar o arquivo de conferência.','error'); }
}

// ══════════ VERIFICAÇÃO DO CARIMBO DO TEMPO — DENTRO DO APP (sem site externo) #carimbo-verificar ══════════
// Motor ÚNICO reusado em TODAS as instâncias com carimbo (termo LGPD, férias, folha, holerite,
// recibo de benefício, EPI). Pragmático: (1) a prova .ots corresponde ao documento (o digest
// embutido no .ots == hash assinado); (2) integridade do conteúdo (best-effort); (3) status que
// o robô já gravou (registrado/confirmado). Não depende de site/serviço externo.
const CARIMBO_TIPOS = {
  termolgpd: { find:id=>(State.termosLgpd||[]).find(x=>x.id===id),       assin:d=>d.assinatura,         pref:'carimbo',    label:'Termo LGPD',          nome:d=>d.employeeNome||'' },
  ferias:    { find:id=>(State.termosFerias||[]).find(x=>x.id===id),     assin:d=>d.assinatura,         pref:'carimbo',    label:'Termo de Férias',     nome:d=>d.employeeNome||'' },
  folha:     { find:id=>(State.payrolls||[]).find(x=>x.id===id),         assin:d=>d.assinatura,         pref:'carimboFol', label:'Folha assinada',      nome:d=>_carimboNomeEmp(d.employeeId) },
  holerite:  { find:id=>(State.payrolls||[]).find(x=>x.id===id),         assin:d=>d.holeriteAssinatura, pref:'carimboHol', label:'Holerite',            nome:d=>_carimboNomeEmp(d.employeeId) },
  beneficio: { find:id=>(State.beneficioRecibos||[]).find(x=>x.id===id), assin:d=>d.assinatura,         pref:'carimbo',    label:'Recibo de Benefício', nome:d=>d.employeeNome||_carimboNomeEmp(d.employeeId) },
  epi:       { find:id=>(State.estoqueMov||[]).find(x=>x.id===id),       assin:d=>d.assinatura,         pref:'carimbo',    label:'Recibo de EPI',       nome:d=>_carimboNomeEmp(d.colaboradorId) },
};
function _carimboNomeEmp(empId){ const e=(State.employees||[]).find(x=>x.id===empId); return e?e.nome:''; }
function _carimboCampos(d, pref){ return { ots:d[pref+'Ots']||'', status:d[pref+'Status']||'', criadoEm:d[pref+'CriadoEm']||'', confirmadoEm:d[pref+'ConfirmadoEm']||'' }; }
// Reconstrói a string EXATA que foi assinada (integridade + arquivo de conferência). Conteúdo:
// conteudoJson (termo/férias/EPI) → reciboHtml (benefício) → conteudoHtml (doc) → holerite; ts em assinadoEm/em.
function _carimboHashInput(d, a){
  if(!a) return null;
  const conteudo = (a.conteudoJson!=null) ? a.conteudoJson
    : (d.reciboHtml!=null ? d.reciboHtml
    : (d.conteudoHtml!=null ? d.conteudoHtml
    : ((d.holeriteConferencia&&d.holeriteConferencia.reciboHtml!=null) ? d.holeriteConferencia.reciboHtml : null)));
  if(conteudo==null) return null;
  const ts = a.assinadoEm || a.em || d.assinadoEm || '';
  return `${conteudo}|${a.pinHash||''}|${a.ip||''}|${a.userAgent||''}|${a.deviceFingerprint||''}|${ts}`;
}
// Digest (32 bytes → hex) embutido no .ots do worker: header 31(magic)+1(versão)+1(op sha256) → bytes [33..65).
function _otsDigestHex(otsBase64){
  try{ const bin=atob(otsBase64); if(bin.length<65) return '';
    let hex=''; for(let i=33;i<65;i++) hex+=(bin.charCodeAt(i)&0xff).toString(16).padStart(2,'0'); return hex;
  }catch(_){ return ''; }
}
async function _carimboVerificar(tipo, id){
  const cfg=CARIMBO_TIPOS[tipo]; if(!cfg) return null;
  const d=cfg.find(id); if(!d) return null;
  const a=cfg.assin(d)||null; const c=_carimboCampos(d, cfg.pref);
  const hash=(a&&a.hash)||'';
  const res={ label:cfg.label, nome:cfg.nome(d), hash, assinado:!!a, temOts:!!c.ots, status:c.status, criadoEm:c.criadoEm, confirmadoEm:c.confirmadoEm, provaOk:null, integridadeOk:null };
  if(c.ots){ const dg=_otsDigestHex(c.ots); res.provaOk = !!(dg && hash && dg.toLowerCase()===String(hash).toLowerCase()); }
  const hi=_carimboHashInput(d, a);
  if(hi!=null && hash){ try{ const buf=await crypto.subtle.digest('SHA-256', new TextEncoder().encode(hi));
    res.integridadeOk=(Array.from(new Uint8Array(buf)).map(x=>x.toString(16).padStart(2,'0')).join('')===hash);
  }catch(_){ res.integridadeOk=null; } }
  return res;
}
async function verificarCarimbo(tipo, id){
  const r=await _carimboVerificar(tipo, id);
  if(!r){ toast('Documento não encontrado.','error'); return; }
  _carimboVerificarModal(tipo, id, r);
}
function _carimboLinha(ok, okTxt, falhaTxt, nuloTxt){
  if(ok===true)  return `<div style="color:#1B5E20"><i class="fa-solid fa-circle-check"></i> ${okTxt}</div>`;
  if(ok===false) return `<div style="color:#c62828"><i class="fa-solid fa-circle-xmark"></i> ${falhaTxt}</div>`;
  return `<div style="color:#94a3b8"><i class="fa-solid fa-circle-minus"></i> ${nuloTxt}</div>`;
}
function _carimboVerificarModal(tipo, id, r){
  document.getElementById('modal-carimbo-verificar')?.remove();
  let statusHtml;
  if(!r.assinado){ statusHtml=`<div style="color:#E65100"><i class="fa-solid fa-clock"></i> Documento ainda não assinado.</div>`; }
  else if(!r.temOts){ statusHtml=`<div style="color:#5E35B1"><i class="fa-solid fa-hourglass-half"></i> <strong>Carimbo pendente</strong> — o robô carimba após a assinatura (pode levar alguns minutos). Ainda não há prova para validar.</div>`; }
  else {
    const bloco = r.status==='confirmado'
      ? `<div style="color:#1B5E20;font-weight:700;margin-top:2px"><i class="fa-solid fa-link"></i> Confirmado no blockchain (Bitcoin)${r.confirmadoEm?' em '+new Date(r.confirmadoEm).toLocaleString('pt-BR'):''}.</div>`
      : `<div style="color:#5E35B1;font-weight:700;margin-top:2px"><i class="fa-solid fa-link"></i> Carimbo registrado${r.criadoEm?' em '+new Date(r.criadoEm).toLocaleString('pt-BR'):''} — aguardando confirmação do Bitcoin (algumas horas).</div>`;
    statusHtml = `${_carimboLinha(r.provaOk,'A prova (.ots) corresponde a este documento.','A prova (.ots) NÃO corresponde a este documento.','Prova .ots não pôde ser lida.')}
      ${_carimboLinha(r.integridadeOk,'Conteúdo íntegro (confere com o que foi assinado).','Conteúdo NÃO confere com o assinado.','Integridade não verificável neste formato.')}
      ${bloco}`;
  }
  const acoes = r.temOts ? `<button class="btn btn-outline" onclick="baixarComprovanteCarimbo('${tipo}','${id}')" style="font-size:12px"><i class="fa-solid fa-download"></i> Baixar comprovante p/ auditoria</button>` : '';
  const html=`<div id="modal-carimbo-verificar" class="modal-overlay" onclick="if(event.target===this)this.remove()">
    <div class="modal-dialog" style="max-width:470px">
      <div class="modal-header"><h3><i class="fa-solid fa-shield-halved" style="color:#00695C"></i> Verificação do carimbo</h3>
        <button class="modal-close" onclick="document.getElementById('modal-carimbo-verificar').remove()"><i class="fa-solid fa-xmark"></i></button></div>
      <div class="modal-body" style="font-size:13px;line-height:1.7">
        <div style="font-size:12px;color:#64748b;margin-bottom:8px">${r.label}${r.nome?' — '+esc(r.nome):''}</div>
        ${statusHtml}
        ${r.temOts?`<div style="font-size:11px;color:#64748b;margin-top:12px">Precisa comprovar para um auditor ou processo? Baixe o comprovante — traz a prova e o passo a passo.</div>`:''}
      </div>
      <div class="modal-footer" style="flex-wrap:wrap;gap:8px">${acoes}
        <button class="btn btn-primary" onclick="document.getElementById('modal-carimbo-verificar').remove()">Fechar</button></div>
    </div></div>`;
  document.body.insertAdjacentHTML('beforeend', html);
}
// UM ÚNICO download p/ auditoria: .zip com a prova (.ots) + o documento de conferência + LEIA-ME.
// Acaba a confusão de "qual arquivo baixar" — é só entregar o .zip ao auditor/advogado. #carimbo-verificar
async function baixarComprovanteCarimbo(tipo, id){
  const cfg=CARIMBO_TIPOS[tipo]; if(!cfg) return; const d=cfg.find(id); if(!d) return;
  const c=_carimboCampos(d, cfg.pref); const a=cfg.assin(d);
  if(!c.ots){ toast('Ainda não há carimbo para gerar o comprovante.','warning'); return; }
  if(typeof JSZip==='undefined'){ toast('JSZip não carregado. Verifique a conexão.','error'); return; }
  try{
    const zip=new JSZip();
    const bin=atob(c.ots); const arr=new Uint8Array(bin.length); for(let i=0;i<bin.length;i++) arr[i]=bin.charCodeAt(i);
    zip.file('carimbo.ots', arr);
    const hi=_carimboHashInput(d, a);
    if(hi!=null) zip.file('documento_para_conferencia.txt', hi);
    zip.file('LEIA-ME.txt',
`Como validar este carimbo do tempo (blockchain / OpenTimestamps)

1) Acesse https://opentimestamps.org
2) Clique na aba "Verify"
3) Envie os DOIS arquivos desta pasta:
   - documento_para_conferencia.txt
   - carimbo.ots
4) O site confirma a data e a hora em que o documento foi assinado, gravadas na rede Bitcoin.

Observacao: a validacao so aparece DEPOIS que o carimbo e "confirmado" no Bitcoin
(algumas horas apos a assinatura). Antes disso o status fica "registrado/pendente".

Hash SHA-256 do documento: ${(a&&a.hash)||'-'}
`);
    const nome=(cfg.nome(d)||'documento').replace(/[^\w]+/g,'_');
    const content=await zip.generateAsync({type:'blob'});
    const el=document.createElement('a'); el.href=URL.createObjectURL(content); el.download=`comprovante_${tipo}_${nome}.zip`; el.click(); URL.revokeObjectURL(el.href);
    toast('Comprovante (.zip) baixado — contém a prova, o documento e o passo a passo.','success');
  }catch(e){ console.error('comprovante carimbo',e); toast('Erro ao gerar o comprovante.','error'); }
}
// Botões padronizados p/ as listas: "Verificar" (se assinado) + selo "carimbo pendente" enquanto
// o robô não carimbou. Substitui os botões avulsos de .ots/Conferência (o Verificar já os oferece). #carimbo-verificar
function _carimboAcoesHtml(tipo, id, stop){
  const cfg=CARIMBO_TIPOS[tipo]; if(!cfg) return ''; const d=cfg.find(id); if(!d) return '';
  const a=cfg.assin(d); if(!a) return '';   // só documento assinado
  const c=_carimboCampos(d, cfg.pref);
  const sp = stop?'event.stopPropagation();':'';
  const verif=`<button class="btn btn-sm btn-outline" onclick="${sp}verificarCarimbo('${tipo}','${id}')" style="font-size:11px" title="Verificar o carimbo do tempo dentro do sistema"><i class="fa-solid fa-shield-halved"></i> Verificar carimbo</button>`;
  if(!c.ots) return `${verif} <span style="font-size:11px;color:#5E35B1" title="O robô ainda vai carimbar este documento"><i class="fa-solid fa-hourglass-half"></i> carimbo pendente</span>`;
  return verif;
}

// Aba "Termos LGPD" no cadastro do colaborador — arquivo dos termos dele. #lgpd-termo
function renderTermosLgpdColab(){
  const c = document.getElementById('termos-lgpd-colab-list'); if(!c) return;
  try{ _renderTermosLgpdColab(c); }
  catch(e){ c.innerHTML='<div style="font-size:12px;color:#c62828;padding:8px 2px">Erro ao carregar os termos: '+((e&&e.message)||e)+'. Recarregue a página (Ctrl+F5).</div>'; console.error('renderTermosLgpdColab', e); }
}
function _renderTermosLgpdColab(c){
  const empId = State.editingEmployeeId || val('emp-id');
  if(!empId){ c.innerHTML='<div style="font-size:12px;color:#94a3b8;padding:8px 2px">Salve o colaborador primeiro.</div>'; return; }
  const lista=(State.termosLgpd||[]).filter(t=>t.employeeId===empId && t.status!=='anulado').sort((a,b)=>(b.enviadoEm||'').localeCompare(a.enviadoEm||''));
  if(!lista.length){ c.innerHTML=`<div class="empty-state small"><i class="fa-solid fa-file-shield" style="font-size:32px;color:#cbd5e0"></i><p style="font-size:13px;margin-top:8px">Nenhum termo enviado a este colaborador.</p></div>`; return; }
  c.innerHTML=lista.map(t=>{
    const ass=t.status==='assinado', cor=ass?'#2E7D32':'#E65100', bg=ass?'#E8F5E9':'#FFF3E0';
    const quando=ass&&t.assinadoEm?'assinado '+new Date(t.assinadoEm).toLocaleString('pt-BR'):(t.enviadoEm?'enviado '+new Date(t.enviadoEm).toLocaleString('pt-BR'):'—');
    const hash=t.assinatura&&t.assinatura.hash?`${t.assinatura.hash.substring(0,16)}…`:'';
    return `<div style="border:1px solid #e0e0e0;border-radius:8px;padding:12px 14px;margin-bottom:10px;background:#fafafa">
      <div style="display:flex;justify-content:space-between;align-items:center;gap:10px;flex-wrap:wrap">
        <div><div style="font-weight:700;color:#1a1a2e;font-size:14px">${t.titulo||'Termo LGPD'}</div>
          <div style="font-size:11px;color:#888;margin-top:2px">${quando}${hash?' · hash '+hash:''}</div></div>
        <div style="display:flex;align-items:center;gap:8px">
          <span style="background:${bg};color:${cor};padding:3px 10px;border-radius:8px;font-size:11px;font-weight:700">${ass?'Assinado':'Pendente'}</span>${_carimboBadge(t)}
          <button class="btn btn-sm btn-outline" onclick="verTermoLgpd('${t.id}')" style="font-size:11px"><i class="fa-solid fa-eye"></i> Ver termo${ass?' + hash':''}</button>
          ${_carimboAcoesHtml('termolgpd', t.id)}
        </div>
      </div>
    </div>`;
  }).join('');
}
let _lgpdTermoFiltro='todos';
function _lgpdFiltrarTermo(f){ _lgpdTermoFiltro=(_lgpdTermoFiltro===f)?'todos':f; renderLGPD(); }
function _lgpdNovoEnvio(empId){   // pré-seleciona o colaborador no envio (não assinou → novo envio). #lgpd
  const sel=document.getElementById('lgpd-termo-emp');
  if(sel){ sel.value=empId; try{ sel.scrollIntoView({behavior:'smooth',block:'center'}); }catch(_){} sel.style.outline='2px solid #6A1B9A'; setTimeout(()=>{ if(sel) sel.style.outline=''; }, 1800); }
  toast('Colaborador selecionado — clique em "Gerar e enviar termo".');
}
function _lgpdTermosTabela(){
  const todos=(State.termosLgpd||[]).filter(t=>t.status!=='anulado');
  // Demitido/inativo SOME dos PENDENTES (demitido antes de assinar não fica "pendente" na tela).
  // O ASSINADO permanece (é histórico/prova). #demissao-some-lgpd
  const _empAtivoT = t => { const e=(State.employees||[]).find(x=>x.id===t.employeeId); return !e || (e.status||'ativo')==='ativo'; };
  const nAss=todos.filter(t=>t.status==='assinado').length;
  const nPend=todos.filter(t=>t.status!=='assinado' && _empAtivoT(t)).length;
  const ativos=(State.employees||[]).filter(e=>(e.status||'ativo')==='ativo');
  const comTermo=new Set(todos.map(t=>t.employeeId));
  const semTermoEmps=ativos.filter(e=>!comTermo.has(e.id)).sort((a,b)=>(a.nome||'').localeCompare(b.nome||''));
  const f=_lgpdTermoFiltro;
  const chip=(key,cor,bg,ic,n,lbl)=>`<div onclick="_lgpdFiltrarTermo('${key}')" style="flex:1;min-width:120px;background:${bg};border:${f===key?'2px':'1px'} solid ${f===key?cor:cor+'33'};border-radius:8px;padding:10px 12px;cursor:pointer" title="Clique para filtrar a lista"><div style="font-size:22px;font-weight:800;color:${cor};line-height:1"><i class="fa-solid ${ic}" style="font-size:14px"></i> ${n}</div><div style="font-size:11px;color:${cor};font-weight:600;margin-top:2px">${lbl}</div></div>`;
  const resumo=`<div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:10px">
    ${chip('pendente','#E65100','#FFF3E0','fa-clock',nPend,'Pendentes (não assinaram)')}
    ${chip('assinado','#2E7D32','#E8F5E9','fa-circle-check',nAss,'Assinados')}
    ${chip('semtermo','#9E9E9E','#F5F5F5','fa-user-slash',semTermoEmps.length,'Ativos sem termo enviado')}
  </div>${f!=='todos'?`<div style="font-size:12px;margin-bottom:8px"><a href="javascript:void(0)" onclick="_lgpdFiltrarTermo('todos')" style="color:var(--primary);font-weight:600"><i class="fa-solid fa-arrow-left"></i> ver todos</a> · mostrando <strong>${f==='semtermo'?'ativos sem termo':(f==='assinado'?'assinados':'pendentes')}</strong></div>`:''}`;
  const thead=`<thead><tr style="background:#F5F7FB">
    <th style="padding:6px 8px;border:1px solid var(--border);text-align:left;font-size:11px">Colaborador</th>
    <th style="padding:6px 8px;border:1px solid var(--border);font-size:11px">Status</th>
    <th style="padding:6px 8px;border:1px solid var(--border);text-align:left;font-size:11px">Quando</th>
    <th style="padding:6px 8px;border:1px solid var(--border);font-size:11px">Ações</th>
  </tr></thead>`;
  const wrap=rows=>resumo+`<div style="overflow:auto;max-height:42vh"><table style="width:100%;border-collapse:collapse">${thead}<tbody>${rows}</tbody></table></div>`;
  if(f==='semtermo'){
    if(!semTermoEmps.length) return resumo+'<div class="empty-state small"><i class="fa-solid fa-circle-check"></i><p>Todos os colaboradores ativos já têm termo.</p></div>';
    const rows=semTermoEmps.map(e=>`<tr onclick="_lgpdNovoEnvio('${e.id}')" style="cursor:pointer" title="Selecionar para enviar o termo">
      <td style="padding:6px 8px;border:1px solid var(--border);font-size:12px">${e.nome||'—'}<div style="font-size:10px;color:var(--text-muted)">CPF ${e.cpf||'—'}</div></td>
      <td style="padding:6px 8px;border:1px solid var(--border);text-align:center"><span style="background:#F5F5F5;color:#9E9E9E;padding:2px 8px;border-radius:8px;font-size:11px;font-weight:700">sem termo</span></td>
      <td style="padding:6px 8px;border:1px solid var(--border);font-size:11px">—</td>
      <td style="padding:6px 8px;border:1px solid var(--border);text-align:center"><button class="btn-icon btn-outline" onclick="event.stopPropagation();_lgpdNovoEnvio('${e.id}')" title="Enviar termo a este colaborador"><i class="fa-solid fa-paper-plane"></i></button></td>
    </tr>`).join('');
    return wrap(rows);
  }
  let lista=todos.slice().sort((a,b)=>(b.enviadoEm||'').localeCompare(a.enviadoEm||''));
  if(f==='assinado') lista=lista.filter(t=>t.status==='assinado');
  else if(f==='pendente') lista=lista.filter(t=>t.status!=='assinado' && _empAtivoT(t));
  else lista=lista.filter(t=>t.status==='assinado' || _empAtivoT(t)); // 'todos': esconde pendentes de demitidos
  if(!lista.length) return resumo+'<div class="empty-state small"><i class="fa-solid fa-file-signature"></i><p>Nenhum termo nesta categoria.</p></div>';
  const badge=s=> s==='assinado'?'<span style="background:#E8F5E9;color:#2E7D32;padding:2px 8px;border-radius:8px;font-size:11px;font-weight:700">Assinado</span>':'<span style="background:#FFF3E0;color:#E65100;padding:2px 8px;border-radius:8px;font-size:11px;font-weight:700">Pendente</span>';
  const rows=lista.map(t=>{ const ass=t.status==='assinado'; const nav=ass?`_alertaAbrirEmp('${t.employeeId}','tab-termos-lgpd')`:`_lgpdNovoEnvio('${t.employeeId}')`;
    return `<tr onclick="${nav}" style="cursor:pointer" title="${ass?'Abrir o cadastro do colaborador':'Reenviar — vai para o novo envio'}">
    <td style="padding:6px 8px;border:1px solid var(--border);font-size:12px">${t.employeeNome||'—'}<div style="font-size:10px;color:var(--text-muted)">CPF ${t.cpf||'—'}</div></td>
    <td style="padding:6px 8px;border:1px solid var(--border);text-align:center;white-space:nowrap">${badge(t.status)}${_carimboBadge(t)}</td>
    <td style="padding:6px 8px;border:1px solid var(--border);font-size:11px;white-space:nowrap">${t.status==='assinado'&&t.assinadoEm?new Date(t.assinadoEm).toLocaleString('pt-BR'):(t.enviadoEm?'env. '+new Date(t.enviadoEm).toLocaleDateString('pt-BR'):'—')}</td>
    <td style="padding:6px 8px;border:1px solid var(--border);text-align:center;white-space:nowrap">
      <button class="btn-icon btn-outline" onclick="event.stopPropagation();verTermoLgpd('${t.id}')" title="Ver termo + hash"><i class="fa-solid fa-eye"></i></button>
      ${_carimboAcoesHtml('termolgpd', t.id, true)}
      <button class="btn-icon btn-danger-icon" onclick="event.stopPropagation();anularTermoLgpd('${t.id}')" title="Anular"><i class="fa-solid fa-ban"></i></button>
    </td>
  </tr>`; }).join('');
  return wrap(rows);
}
// "Atualizar" do monitor: RECARREGA os dados do banco (não só re-renderiza). #lgpd
async function atualizarLGPD(){
  toast('Atualizando…');
  const cutoff=new Date(Date.now()-186*86400000).toISOString();
  const tasks=[
    DB.getAll('termosLgpd').then(d=>{State.termosLgpd=d;}).catch(()=>{}),
    DB.getAll('pedidosTitular').then(d=>{State.pedidosTitular=d;}).catch(()=>{}),
    DB.getAll('employees').then(d=>{State.employees=d;}).catch(()=>{}),
    DB.getDoc('configuracoes','permissoesUsuarios').then(d=>{State.permissoesUsuarios=d||{};}).catch(()=>{}),
    DB.getDoc('configuracoes','acessoUsuarios').then(d=>{State.acessoUsuarios=d||{};}).catch(()=>{}),
    DB.getDoc('configuracoes','lgpdConfig').then(d=>{State.lgpdConfig=d||{};}).catch(()=>{}),
    DB.col('accessLog').where('timestamp','>=',cutoff).orderBy('timestamp','desc').limit(5000).get()
      .then(s=>{Auth.accessLog=s.docs.map(d=>d.data());})
      .catch(()=>DB.col('accessLog').orderBy('timestamp','desc').limit(2000).get().then(s=>{Auth.accessLog=s.docs.map(d=>d.data());}).catch(()=>{}))
  ];
  if(typeof loadUsersFromWorker==='function') tasks.push(loadUsersFromWorker().catch(()=>{}));
  try{ await Promise.all(tasks); renderLGPD(); toast('Atualizado.'); }
  catch(e){ renderLGPD(); toast('Atualizado (parcial).','warning'); }
}
// ===== Direitos do Titular (LGPD art. 18) — registro e acompanhamento. #lgpd-titular =====
const PEDIDO_TITULAR_TIPOS=['Confirmação / Acesso aos dados','Correção de dados','Eliminação / Exclusão','Anonimização / Bloqueio','Portabilidade','Informação sobre compartilhamentos','Revogação de consentimento','Oposição ao tratamento'];
function _pedidoStatusCfg(s){ return s==='concluido'?{t:'Concluído',c:'#2E7D32',b:'#E8F5E9'}:s==='andamento'?{t:'Em andamento',c:'#1565C0',b:'#E3F2FD'}:{t:'Aberto',c:'#E65100',b:'#FFF3E0'}; }
function abrirPedidoTitular(id){
  const p=id?(State.pedidosTitular||[]).find(x=>x.id===id):null;
  document.getElementById('modal-pedido-titular')?.remove();
  const opts=PEDIDO_TITULAR_TIPOS.map(t=>`<option ${p&&p.tipo===t?'selected':''}>${t}</option>`).join('');
  const html=`<div id="modal-pedido-titular" class="modal" style="display:flex;align-items:center;justify-content:center;position:fixed;inset:0;background:rgba(0,0,0,.5);z-index:9999">
    <div style="background:#fff;max-width:560px;width:94%;border-radius:10px;max-height:92vh;overflow:auto">
      <div style="background:#1a3a6b;color:#fff;padding:12px 16px;display:flex;justify-content:space-between;align-items:center"><h3 style="margin:0;font-size:16px"><i class="fa-solid fa-user-lock"></i> ${id?'Editar':'Novo'} pedido do titular</h3><button onclick="document.getElementById('modal-pedido-titular').remove()" style="background:none;border:none;color:#fff;font-size:22px;cursor:pointer;line-height:1">&times;</button></div>
      <div style="padding:16px">
        <input type="hidden" id="pt-id" value="${p?p.id:''}">
        <div class="form-row"><div class="form-group"><label>Titular (nome) <span class="required">*</span></label><input id="pt-nome" value="${p?_lgpdAttr(p.nome):''}"></div><div class="form-group"><label>CPF / identificador</label><input id="pt-cpf" value="${p?_lgpdAttr(p.cpf):''}"></div></div>
        <div class="form-group"><label>Contato (e-mail / telefone)</label><input id="pt-contato" value="${p?_lgpdAttr(p.contato):''}"></div>
        <div class="form-row"><div class="form-group"><label>Tipo de pedido</label><select id="pt-tipo">${opts}</select></div><div class="form-group"><label>Status</label><select id="pt-status"><option value="aberto" ${!p||p.status==='aberto'?'selected':''}>Aberto</option><option value="andamento" ${p&&p.status==='andamento'?'selected':''}>Em andamento</option><option value="concluido" ${p&&p.status==='concluido'?'selected':''}>Concluído</option></select></div></div>
        <div class="form-group"><label>Descrição do pedido</label><textarea id="pt-desc" rows="3" style="width:100%">${p?_lgpdAttr(p.descricao):''}</textarea></div>
        <div class="form-group"><label>Resposta / providências adotadas</label><textarea id="pt-resp" rows="3" style="width:100%">${p?_lgpdAttr(p.resposta):''}</textarea></div>
        <button class="btn btn-primary" onclick="salvarPedidoTitular()"><i class="fa-solid fa-floppy-disk"></i> Salvar pedido</button>
      </div>
    </div></div>`;
  document.body.insertAdjacentHTML('beforeend', html);
}
async function salvarPedidoTitular(){
  const id=val('pt-id')||genId();
  const exist=(State.pedidosTitular||[]).find(x=>x.id===id);
  const nome=val('pt-nome').trim(); if(!nome){ toast('Informe o nome do titular.','warning'); return; }
  const status=val('pt-status');
  const reg={ id, nome, cpf:val('pt-cpf').trim(), contato:val('pt-contato').trim(), tipo:val('pt-tipo'), descricao:val('pt-desc').trim(), resposta:val('pt-resp').trim(), status,
    origem: exist?(exist.origem||'manual'):'manual', employeeId: exist?(exist.employeeId||null):null,
    criadoEm: exist?exist.criadoEm:new Date().toISOString(), concluidoEm: status==='concluido'?((exist&&exist.concluidoEm)||new Date().toISOString()):null,
    atualizadoEm:new Date().toISOString(), registradoPor: exist?(exist.registradoPor||(Auth.currentUser&&Auth.currentUser.username)):(Auth.currentUser&&Auth.currentUser.username)||'—' };
  try{ await DB.save('pedidosTitular', reg); State.pedidosTitular=[...(State.pedidosTitular||[]).filter(x=>x.id!==id), reg];
    Auth.log(exist?'LGPD_PEDIDO_ATUALIZADO':'LGPD_PEDIDO_CRIADO', Auth.currentUser.username, `${reg.tipo} — ${reg.nome} (${_pedidoStatusCfg(status).t})`);
    document.getElementById('modal-pedido-titular')?.remove(); toast('Pedido do titular salvo.'); renderLGPD(); }
  catch(e){ toast('Erro ao salvar o pedido.','error'); }
}
function imprimirPedidoTitular(id){
  const p=(State.pedidosTitular||[]).find(x=>x.id===id); if(!p) return;
  const prazo=p.criadoEm?new Date(new Date(p.criadoEm).getTime()+15*86400000).toLocaleDateString('pt-BR'):'—';
  const html=`<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Pedido do titular</title><style>body{font-family:Arial,sans-serif;padding:24px;max-width:760px;margin:0 auto;color:#212529;font-size:13px;line-height:1.6}h1{color:#1a3a6b;font-size:18px}b{color:#1a3a6b}</style></head><body>
  <h1>${_e('nomeEmpresa')||'Empresa'} — Pedido de Direito do Titular (LGPD art. 18)</h1>
  <p><b>Titular:</b> ${p.nome||'—'} ${p.cpf?'· CPF '+p.cpf:''}<br><b>Contato:</b> ${p.contato||'—'}</p>
  <p><b>Tipo:</b> ${p.tipo||'—'}<br><b>Status:</b> ${_pedidoStatusCfg(p.status).t}</p>
  <p><b>Recebido em:</b> ${p.criadoEm?new Date(p.criadoEm).toLocaleString('pt-BR'):'—'} · <b>Prazo de resposta (15 dias):</b> ${prazo}${p.concluidoEm?' · <b>Concluído em:</b> '+new Date(p.concluidoEm).toLocaleString('pt-BR'):''}</p>
  <p><b>Descrição:</b><br>${(p.descricao||'—').replace(/</g,'&lt;')}</p>
  <p><b>Resposta / providências:</b><br>${(p.resposta||'—').replace(/</g,'&lt;')}</p>
  <p style="margin-top:18px;font-size:10px;color:#888">Encarregado/DPO: ${(State.lgpdConfig&&State.lgpdConfig.nome)||'—'}. Gerado em ${new Date().toLocaleString('pt-BR')}.</p></body></html>`;
  const w=window.open('','_blank','width=860,height=700'); if(!w){ toast('Permita pop-ups','error'); return; } w.document.write(html); w.document.close();
}
async function excluirPedidoTitular(id){
  if(!confirm('Excluir este registro de pedido do titular?')) return;
  try{ await DB.remove('pedidosTitular', id); State.pedidosTitular=(State.pedidosTitular||[]).filter(x=>x.id!==id); toast('Pedido excluído.'); renderLGPD(); }
  catch(e){ toast('Erro ao excluir.','error'); }
}
function _lgpdPedidosTitular(){
  const ps=(State.pedidosTitular||[]).slice().sort((a,b)=>(b.criadoEm||'').localeCompare(a.criadoEm||''));
  const abertos=ps.filter(p=>p.status!=='concluido').length;
  const vencidos=ps.filter(p=>p.status!=='concluido' && p.criadoEm && (Date.now()-new Date(p.criadoEm).getTime())>15*86400000).length;
  const head=`<div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px;margin-bottom:8px">
    <div style="font-size:12px;color:var(--text-muted)"><strong style="color:#E65100">${abertos}</strong> em aberto${vencidos?` · <strong style="color:#c62828">${vencidos}</strong> fora do prazo (15 dias)`:''}</div>
    <button class="btn btn-primary btn-sm" onclick="abrirPedidoTitular()"><i class="fa-solid fa-plus"></i> Registrar pedido</button>
  </div>`;
  if(!ps.length) return head+'<div class="empty-state small"><i class="fa-solid fa-user-lock"></i><p>Nenhum pedido de titular registrado.</p></div>';
  const rows=ps.map(p=>{ const sc=_pedidoStatusCfg(p.status); const venc=p.status!=='concluido'&&p.criadoEm&&(Date.now()-new Date(p.criadoEm).getTime())>15*86400000;
    return `<tr>
    <td style="padding:6px 8px;border:1px solid var(--border);font-size:12px">${p.nome||'—'}<div style="font-size:10px;color:var(--text-muted)">${p.cpf||''}</div></td>
    <td style="padding:6px 8px;border:1px solid var(--border);font-size:11px">${p.tipo||'—'}${p.origem==='app'?' <span style="background:#EDE7F6;color:#5E35B1;padding:1px 6px;border-radius:6px;font-size:10px;font-weight:700">via app</span>':''}</td>
    <td style="padding:6px 8px;border:1px solid var(--border);text-align:center"><span style="background:${sc.b};color:${sc.c};padding:2px 8px;border-radius:8px;font-size:11px;font-weight:700">${sc.t}</span></td>
    <td style="padding:6px 8px;border:1px solid var(--border);font-size:11px;white-space:nowrap;${venc?'color:#c62828;font-weight:700':''}">${p.criadoEm?new Date(p.criadoEm).toLocaleDateString('pt-BR'):'—'}${venc?' ⚠':''}</td>
    <td style="padding:6px 8px;border:1px solid var(--border);text-align:center;white-space:nowrap">
      <button class="btn-icon btn-outline" onclick="abrirPedidoTitular('${p.id}')" title="Abrir/editar"><i class="fa-solid fa-pen"></i></button>
      <button class="btn-icon btn-outline" onclick="imprimirPedidoTitular('${p.id}')" title="Imprimir"><i class="fa-solid fa-print"></i></button>
      <button class="btn-icon btn-danger-icon" onclick="excluirPedidoTitular('${p.id}')" title="Excluir"><i class="fa-solid fa-trash"></i></button>
    </td>
  </tr>`; }).join('');
  return head+`<div style="overflow:auto;max-height:40vh"><table style="width:100%;border-collapse:collapse"><thead><tr style="background:#F5F7FB">
    <th style="padding:6px 8px;border:1px solid var(--border);text-align:left;font-size:11px">Titular</th>
    <th style="padding:6px 8px;border:1px solid var(--border);text-align:left;font-size:11px">Tipo</th>
    <th style="padding:6px 8px;border:1px solid var(--border);font-size:11px">Status</th>
    <th style="padding:6px 8px;border:1px solid var(--border);text-align:left;font-size:11px">Recebido</th>
    <th style="padding:6px 8px;border:1px solid var(--border);font-size:11px">Ações</th>
  </tr></thead><tbody>${rows}</tbody></table></div>`;
}
function renderLGPD(){
  const el=document.getElementById('lgpd-content'); if(!el) return;
  const _cfg=State.lgpdConfig||{};
  const _empOpts=(State.employees||[]).filter(e=>(e.status||'ativo')==='ativo').sort((a,b)=>(a.nome||'').localeCompare(b.nome||'')).map(e=>`<option value="${e.id}">${e.nome}</option>`).join('');
  const checks=_lgpdChecks();
  const nRisco=checks.filter(c=>c.nivel==='risco').length;
  const nAviso=checks.filter(c=>c.nivel==='aviso').length;
  const corNivel={ok:'#2E7D32',aviso:'#E65100',risco:'#c62828',info:'#1565C0'};
  const icNivel={ok:'fa-circle-check',aviso:'fa-triangle-exclamation',risco:'fa-circle-exclamation',info:'fa-circle-info'};
  const sg = nRisco? {txt:`${nRisco} risco(s)${nAviso?` e ${nAviso} aviso(s)`:''} a tratar`,cor:'#c62828',ic:'fa-circle-exclamation'} : nAviso? {txt:`${nAviso} aviso(s) a revisar`,cor:'#E65100',ic:'fa-triangle-exclamation'} : {txt:'Nenhum risco encontrado nas verificações',cor:'#2E7D32',ic:'fa-circle-check'};
  const cardCheck=c=>`<div ${c.nav?`onclick="showSection('${c.nav}')" style="cursor:pointer;`:'style="'}border:1px solid var(--border);border-left:4px solid ${corNivel[c.nivel]};border-radius:8px;padding:12px 14px;margin-bottom:8px;background:#fff" title="${c.nav?'Clique para abrir a tela e revisar/corrigir':''}">
    <div style="display:flex;align-items:center;gap:8px;font-weight:700;color:${corNivel[c.nivel]};font-size:14px"><i class="fa-solid ${icNivel[c.nivel]}"></i> ${c.titulo}${c.nav?' <i class="fa-solid fa-arrow-right" style="font-size:11px;color:var(--text-muted);margin-left:auto"></i>':''}</div>
    <div style="font-size:13px;color:#444;margin-top:4px;line-height:1.5">${c.detalhe}</div>
    ${c.corrigir?`<div style="font-size:12px;color:var(--text-muted);margin-top:5px"><i class="fa-solid fa-screwdriver-wrench"></i> <strong>Como corrigir:</strong> ${c.corrigir}</div>`:''}
  </div>`;
  const eventos=_lgpdEventosSensiveis(186);
  const evtRows=eventos.slice(0,150).map(e=>`<tr ${e.nav?`onclick="showSection('${e.nav}')" style="cursor:pointer"`:''} title="${e.nav?'Clique para abrir a tela de origem':''}">
    <td style="padding:6px 8px;border:1px solid var(--border);white-space:nowrap;font-size:11px">${fmtDateTime(e.timestamp)}</td>
    <td style="padding:6px 8px;border:1px solid var(--border);font-size:11px;color:${e.cor};font-weight:600;white-space:nowrap"><i class="fa-solid ${e.ic}"></i> ${e.cat}${e.nav?' <i class="fa-solid fa-arrow-right" style="font-size:9px;opacity:.6"></i>':''}</td>
    <td style="padding:6px 8px;border:1px solid var(--border);font-size:11px">${e.username||'—'}</td>
    <td style="padding:6px 8px;border:1px solid var(--border);font-size:11px">${e.details||'—'}</td>
  </tr>`).join('');
  el.innerHTML=`
  <div class="card"><div class="card-header" style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px">
    <h3><i class="fa-solid fa-user-shield"></i> Conformidade LGPD</h3>
    <div style="display:flex;gap:6px;flex-wrap:wrap">
      <button class="btn btn-primary" onclick="gerarRelatorioLGPD()"><i class="fa-solid fa-file-lines"></i> Gerar relatório</button>
      <button class="btn btn-outline" style="border-color:#2E7D32;color:#2E7D32" onclick="atualizarLGPD()"><i class="fa-solid fa-rotate"></i> Atualizar</button>
    </div>
  </div>
  <div class="card-body">
    <div style="background:#FFF8E1;border:1px solid #FFE082;border-radius:8px;padding:10px 14px;font-size:12px;color:#795548;margin-bottom:14px">
      <i class="fa-solid fa-circle-info"></i> Ferramenta de apoio que aponta possíveis riscos de proteção de dados. <strong>Não substitui a orientação de um advogado/DPO.</strong>
    </div>
    <div style="border:1px solid var(--border);border-radius:8px;padding:12px 14px;margin-bottom:16px;background:#F8FAFF">
      <div style="font-weight:700;font-size:14px;margin-bottom:8px"><i class="fa-solid fa-user-tie" style="color:var(--primary)"></i> Encarregado pelo Tratamento de Dados (DPO) / Advogado responsável</div>
      <div class="form-row">
        <div class="form-group"><label>Nome</label><input id="lgpd-dpo-nome" value="${_lgpdAttr(_cfg.nome)}" placeholder="Nome completo"></div>
        <div class="form-group"><label>OAB</label><input id="lgpd-dpo-oab" value="${_lgpdAttr(_cfg.oab)}" placeholder="OAB/UF nº"></div>
      </div>
      <div class="form-row">
        <div class="form-group"><label>E-mail</label><input id="lgpd-dpo-email" value="${_lgpdAttr(_cfg.email)}" placeholder="email@..."></div>
        <div class="form-group"><label>Telefone</label><input id="lgpd-dpo-tel" value="${_lgpdAttr(_cfg.telefone)}" placeholder="(00) 00000-0000"></div>
      </div>
      <button class="btn btn-primary" onclick="salvarLgpdConfig()"><i class="fa-solid fa-floppy-disk"></i> Salvar responsável</button>
    </div>
    <div style="border:1px solid var(--border);border-radius:8px;margin-bottom:16px;overflow:hidden">
      <div onclick="_lgpdTogglePolitica()" style="cursor:pointer;display:flex;justify-content:space-between;align-items:center;gap:8px;padding:12px 14px;background:#F8FAFF" title="Clique para revelar a Política de Privacidade">
        <div style="font-weight:700;font-size:14px;color:var(--primary)"><i class="fa-solid fa-file-shield"></i> Política de Privacidade e Proteção de Dados</div>
        <div style="display:flex;align-items:center;gap:10px"><button class="btn btn-outline" onclick="event.stopPropagation();_lgpdImprimirPolitica()" title="Imprimir / salvar PDF"><i class="fa-solid fa-print"></i> Imprimir</button><i id="lgpd-pol-chevron" class="fa-solid fa-chevron-down" style="color:var(--text-muted)"></i></div>
      </div>
      <div id="lgpd-politica" style="display:none;padding:14px 16px;border-top:1px solid var(--border)">${_lgpdPoliticaHtml()}</div>
    </div>
    <div style="border:1px solid var(--border);border-radius:8px;padding:12px 14px;margin-bottom:16px">
      <div style="font-weight:700;font-size:14px;margin-bottom:8px"><i class="fa-solid fa-file-signature" style="color:var(--primary)"></i> Termo de Ciência e Consentimento (LGPD)</div>
      <div style="font-size:12px;color:var(--text-muted);margin-bottom:8px">Envia o termo ao <strong>app de ponto</strong> do colaborador para ele <strong>assinar com o PIN</strong> (gera hash e arquiva no histórico).</div>
      <div style="display:flex;gap:8px;flex-wrap:wrap;align-items:flex-end;margin-bottom:12px">
        <div class="form-group" style="margin:0;flex:1;min-width:220px"><label style="font-size:12px">Colaborador</label><select id="lgpd-termo-emp"><option value="">Selecione…</option>${_empOpts}</select></div>
        <button class="btn btn-primary" onclick="enviarTermoLgpd()"><i class="fa-solid fa-paper-plane"></i> Gerar e enviar termo</button>
        <button class="btn btn-outline" onclick="enviarTermoTodosLgpd()" title="Enviar a todos os colaboradores ativos que ainda não têm termo"><i class="fa-solid fa-users"></i> Enviar para todos</button>
      </div>
      ${_lgpdTermosTabela()}
    </div>
    <div style="border:1px solid var(--border);border-radius:8px;padding:12px 14px;margin-bottom:16px">
      <div style="font-weight:700;font-size:14px;margin-bottom:6px"><i class="fa-solid fa-user-lock" style="color:var(--primary)"></i> Pedidos do Titular (direitos LGPD — art. 18)</div>
      <div style="font-size:12px;color:var(--text-muted);margin-bottom:10px">Registre e acompanhe pedidos de titulares (acesso, correção, eliminação, etc.). Prazo de resposta: <strong>15 dias</strong>.</div>
      ${_lgpdPedidosTitular()}
    </div>
    <div style="display:flex;align-items:center;gap:12px;background:#fff;border:1px solid var(--border);border-left:5px solid ${sg.cor};border-radius:8px;padding:12px 16px;margin-bottom:16px">
      <i class="fa-solid ${sg.ic}" style="font-size:26px;color:${sg.cor}"></i>
      <div><div style="font-weight:700;color:${sg.cor};font-size:15px">${sg.txt}</div><div style="font-size:12px;color:var(--text-muted)">${checks.length} verificações automáticas nos seus próprios dados.</div></div>
    </div>
    <h4 style="margin:0 0 8px;font-size:14px"><i class="fa-solid fa-list-check"></i> Verificações</h4>
    ${checks.map(cardCheck).join('')}
    <h4 style="margin:18px 0 6px;font-size:14px"><i class="fa-solid fa-shield-halved"></i> Vigia de eventos sensíveis — últimos 6 meses (${eventos.length})</h4>
    <div style="font-size:12px;color:var(--text-muted);margin-bottom:8px">Operações que tocam dado pessoal: exclusões, exportações, mudanças de acesso, envios e acessos bloqueados.</div>
    ${eventos.length? `<div style="overflow:auto;max-height:50vh"><table style="width:100%;border-collapse:collapse;min-width:640px"><thead><tr style="background:#F5F7FB">
      <th style="padding:6px 8px;border:1px solid var(--border);text-align:left;font-size:11px">Data/Hora</th>
      <th style="padding:6px 8px;border:1px solid var(--border);text-align:left;font-size:11px">Categoria</th>
      <th style="padding:6px 8px;border:1px solid var(--border);text-align:left;font-size:11px">Usuário</th>
      <th style="padding:6px 8px;border:1px solid var(--border);text-align:left;font-size:11px">Detalhe</th>
    </tr></thead><tbody>${evtRows}</tbody></table></div>` : '<div class="empty-state small"><i class="fa-solid fa-circle-check"></i><p>Nenhum evento sensível nos últimos 6 meses.</p></div>'}
  </div></div>`;
}

function gerarRelatorioLGPD(){
  const checks=_lgpdChecks();
  const eventos=_lgpdEventosSensiveis(186);
  const cfg=State.lgpdConfig||{};
  const nRisco=checks.filter(c=>c.nivel==='risco').length, nAviso=checks.filter(c=>c.nivel==='aviso').length, nOk=checks.filter(c=>c.nivel==='ok').length;
  const nivelLabel={ok:'OK',aviso:'ATENÇÃO',risco:'RISCO',info:'INFO'};
  const nivelCor={ok:'#2E7D32',aviso:'#E65100',risco:'#c62828',info:'#1565C0'};
  const esc=s=>String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
  const checkRows=checks.map(c=>`<tr><td style="white-space:nowrap;color:${nivelCor[c.nivel]};font-weight:bold">${nivelLabel[c.nivel]}</td><td><strong>${esc(c.titulo)}</strong><br><span style="font-size:10px;color:#555">${esc(c.detalhe)}</span>${c.corrigir?`<br><span style="font-size:10px;color:#777">Corrigir: ${esc(c.corrigir)}</span>`:''}</td></tr>`).join('');
  const evtRows=eventos.slice(0,400).map(e=>`<tr><td style="white-space:nowrap">${fmtDateTime(e.timestamp)}</td><td>${esc(e.cat)}</td><td>${esc(e.username||'—')}</td><td style="font-size:10px">${esc(e.details||'—')}</td></tr>`).join('');
  const dpo=(cfg.nome||cfg.oab||cfg.email||cfg.telefone)
    ? `<p style="margin:2px 0"><strong>${esc(cfg.nome||'—')}</strong>${cfg.oab?` — OAB ${esc(cfg.oab)}`:''}</p><p style="margin:2px 0;font-size:11px;color:#555">${esc(cfg.email||'')}${cfg.email&&cfg.telefone?' · ':''}${esc(cfg.telefone||'')}</p>`
    : '<p style="color:#c62828;margin:2px 0">Encarregado (DPO) não informado.</p>';
  const html=`<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Relatório LGPD</title>
<style>body{font-family:Arial,sans-serif;padding:20px;color:#212529;font-size:12px}h1{color:#1a3a6b;font-size:18px;margin:0 0 4px}h2{color:#1a3a6b;font-size:14px;border-bottom:2px solid #1a3a6b;padding-bottom:3px;margin:18px 0 8px}table{width:100%;border-collapse:collapse;font-size:11px}th,td{border:1px solid #ccc;padding:5px 7px;text-align:left;vertical-align:top}th{background:#1a3a6b;color:#fff}.box{border:1px solid #ccc;border-radius:6px;padding:10px 12px;margin:8px 0}@media print{body{padding:6px}}</style>
</head><body>
<h1>${esc(_e('nomeEmpresa')||'Empresa')} — Relatório de Conformidade LGPD</h1>
<p style="color:#666;font-size:11px">Gerado em ${new Date().toLocaleString('pt-BR')} por ${esc(Auth.currentUser?.username||'—')}</p>
<div class="box"><strong>Encarregado pelo Tratamento de Dados (DPO) / Advogado responsável</strong>${dpo}</div>
<div class="box"><strong>Resumo:</strong> ${checks.length} verificações — <span style="color:#2E7D32">${nOk} OK</span>, <span style="color:#E65100">${nAviso} atenção</span>, <span style="color:#c62828">${nRisco} risco</span>. Eventos sensíveis (90 dias): ${eventos.length}.</div>
<h2>Verificações de conformidade</h2>
<table><thead><tr><th style="width:80px">Nível</th><th>Item</th></tr></thead><tbody>${checkRows}</tbody></table>
<h2>Eventos sensíveis — últimos 6 meses (${eventos.length})</h2>
${eventos.length?`<table><thead><tr><th style="width:120px">Data/Hora</th><th>Categoria</th><th>Usuário</th><th>Detalhe</th></tr></thead><tbody>${evtRows}</tbody></table>`:'<p>Nenhum evento sensível no período.</p>'}
<p style="margin-top:18px;font-size:10px;color:#888">Documento gerado pelo DRG-Kronos como ferramenta de apoio à conformidade. Não constitui parecer jurídico; recomenda-se a validação pelo Encarregado/DPO.</p>
</body></html>`;
  const win=window.open('','_blank','width=900,height=700');
  if(!win){ toast('Permita pop-ups para gerar o relatório','error'); return; }
  win.document.write(html + '<scr'+'ipt>window.onload=function(){window.print();}<\/scr'+'ipt>');
  win.document.close();
  try{ Auth.log('LGPD_RELATORIO',Auth.currentUser.username,`${checks.length} verificações · ${eventos.length} eventos`); }catch(_){}
}

function renderUsersTable(){
  const tbody=document.getElementById('users-tbody'); if(!tbody) return;
  tbody.innerHTML=Auth.users.map(u=>{
    const _temPerm=!!(State.permissoesUsuarios||{})[u.username];
    const roleCls=u.role==='master'?'badge-master':(_temPerm||u.role&&u.role.startsWith('p_'))?'badge-gestor':'badge-operador';
    const acessoLbl=u.role==='master'?'Master':(_temPerm?'Personalizado':roleLabel(u.role));
    const isMaster=Auth.currentUser?.role==='master';
    const logToggle=u.role!=='master'&&isMaster?`<button class="btn-icon ${u.showLog?'btn-primary-icon':'btn-outline'}" onclick="toggleShowLog('${u.id}')" title="${u.showLog?'Revogar acesso ao log':'Dar acesso ao log'}"><i class="fa-solid fa-list-check"></i></button>`:'';
    return `<tr>
      <td><div style="display:flex;align-items:center;gap:8px">
        <div class="recent-avatar" style="width:30px;height:30px;font-size:11px">${initials(u.username)}</div>
        <strong>${u.username}</strong>
        ${u.id==='master-default'?'<span class="badge badge-muted" style="font-size:10px">padrão</span>':''}
      </div></td>
      <td><span class="badge ${roleCls}">${acessoLbl}</span></td>
      <td>${fmtDateTime(u.lastLogin)}</td>
      <td><span class="badge ${u.active?'badge-success':'badge-danger'}">${u.active?'Ativo':'Inativo'}</span></td>
      <td><div class="actions-cell">
        ${logToggle}
        <button class="btn-icon btn-warning-icon" onclick="openUserModal('${u.id}')" title="Editar"><i class="fa-solid fa-pencil"></i></button>
        ${u.id!==Auth.currentUser?.id?`<button class="btn-icon btn-danger-icon" onclick="confirmDeleteUser('${u.id}')" title="Excluir"><i class="fa-solid fa-trash"></i></button>`:''}
      </div></td>
    </tr>`;
  }).join('');
}

function confirmDeleteUser(id){
  const u=Auth.users.find(u=>u.id===id); if(!u) return;
  if(u.id==='master-default'){ toast('O usuário padrão não pode ser removido.','warning'); return; }
  document.getElementById('confirm-message').textContent=`Excluir o usuário "${u.username}"?`;
  const btn=document.getElementById('confirm-ok-btn');
  btn.innerHTML='<i class="fa-solid fa-trash"></i> Excluir';
  btn.onclick=async()=>{
    try {
      const r=await _aprovacaoReq('/usuarios/excluir',{id});
      if(!r || r.ok!==true){ toast((r&&r.erro)||'Não foi possível excluir.','error'); return; }
      Auth.log('USER_DELETED',Auth.currentUser.username,`Removido: ${u.username}`);
      toast(`Usuário "${u.username}" excluído.`,'warning');
      await loadUsersFromWorker();
      if(State.currentSection==='users') renderUsersTable();
    } catch(e){
      toast((e&&e.message)||'Erro ao excluir usuário.','error');
    }
    closeModal('modal-confirm');
  };
  document.getElementById('modal-confirm').classList.remove('hidden');
}

