  BANCO_HORAS_DEBITO:  {label:'Baixa no banco de horas', cls:'ev-payroll', icon:'fa-piggy-bank'},
  ATESTADO_LANCADO:    {label:'Atestado lançado',     cls:'ev-payroll',    icon:'fa-notes-medical'},
