// EXPORTAR / IMPORTAR MANUAL
// ============================================
async function exportDatabase(){
  const backup=buildBackupObject();
  const json=JSON.stringify(backup,null,2);
  const blob=new Blob([json],{type:'application/json'});
  const url=URL.createObjectURL(blob);
  const date=new Date().toLocaleDateString('pt-BR').replace(/\//g,'-');
  const a=document.createElement('a');
  a.href=url; a.download=`DRGlobal_backup_${date}.json`;
  document.body.appendChild(a); a.click(); document.body.removeChild(a); URL.revokeObjectURL(url);
  Auth.log('BACKUP_MANUAL',null,`DRGlobal_backup_${date}.json`);
  toast('Backup exportado com sucesso!');
}

function importDatabase(event){
  const file=event.target.files[0]; if(!file) return;
  const reader=new FileReader();
  reader.onload=async function(e){
    try {
      const backup=JSON.parse(e.target.result);
      if(!backup.employees||!backup.payrolls){ toast('Arquivo inválido.','error'); return; }
      const empCount=backup.employees.length, payCount=backup.payrolls.length,
            usrCount=(backup.users||[]).length;
      document.getElementById('confirm-message').textContent=
        `Importar backup de ${fmtDate(backup.exportedAt)}? `+
        `${empCount} colaboradores, ${payCount} lançamentos, ${usrCount} usuários. `+
        `Os dados atuais serão substituídos.`;
      const btn=document.getElementById('confirm-ok-btn');
      btn.innerHTML='<i class="fa-solid fa-file-import"></i> Importar';
      btn.onclick=async()=>{
        setBtnLoading(btn,true,'');
        try {
          // `users` NÃO é restaurado por backup — é coleção só-servidor,
          // gerida pelo Worker (criação/edição via /usuarios/*).
          const tasks=[
            ...backup.employees.map(r=>DB.save('employees',r)),
            ...backup.payrolls.map(r=>DB.save('payrolls',r)),
            ...(backup.accessLog||[]).slice(0,200).map(r=>DB.save('accessLog',r))
          ];
          await Promise.all(tasks);
          closeModal('modal-confirm');
          Auth.log('BACKUP_IMPORT',null,file.name);
          toast(`Importado: ${empCount} colaboradores, ${payCount} lançamentos.`);
        } finally {
          setBtnLoading(btn,false,'<i class="fa-solid fa-trash"></i> Excluir');
        }
      };
      document.getElementById('modal-confirm').classList.remove('hidden');
    } catch{ toast('Erro ao ler o arquivo.','error'); }
    event.target.value='';
  };
  reader.readAsText(file);
}

async function setupAutoBackup(){
  if(AutoBackup.fileHandle){ await AutoBackup.stop(); toast('Auto-backup desativado.','warning'); }
  else { AutoBackup.setup(); }
}

// ============================================
// DASHBOARD
// ============================================
// Gera um card padronizado do Dashboard: rótulo no topo (esquerda),
// ícone no canto superior direito, valor/informação abaixo.
function _statCard(o){
  const accent=o.accent||'var(--primary)';
  const vStyle=[];
  if(o.valueColor) vStyle.push('color:'+o.valueColor);
  if(o.smallValue) vStyle.push('font-size:13px;font-weight:600');
  const valueStyle=vStyle.length?` style="${vStyle.join(';')}"`:'';
  const sub=o.sub?`<div class="stat-sub"${o.subColor?` style="color:${o.subColor}"`:''}>${o.sub}</div>`:'';
  const cursor=o.onclick?'cursor:pointer;':'';
  return `<div class="stat-card" style="${cursor}border-color:${accent}"${o.onclick?` onclick="${o.onclick}"`:''}${o.title?` title="${o.title}"`:''}>
    <div class="stat-icon" style="background:${o.iconBg||'var(--primary-light)'};color:${o.iconColor||'var(--primary)'}"><i class="fa-solid ${o.icon}"></i></div>
    <div>
      <div class="stat-value"${valueStyle}>${o.value}</div>
      <div class="stat-label">${o.label}</div>
      ${sub}
    </div>
  </div>`;
}

// --- Personalização do Dashboard (por usuário) ---
let _dashConfig = { ordem:[], ocultos:[] };
let _dashConfigLoadedFor = null;
let _dashEditMode = false;
let _dashOrderedKeys = [];

async function saveDashConfig(){
  const uid=Auth.currentUser?.id; if(!uid) return;
  try {
    await DB.saveDoc('configuracoes','dashboard_'+uid,
      { ordem:_dashConfig.ordem||[], ocultos:_dashConfig.ocultos||[], updatedAt:new Date().toISOString() }, true);
  } catch(e){ console.error('Erro ao salvar layout do dashboard:',e); }
}

function toggleDashEdit(){
  _dashEditMode=!_dashEditMode;
  const btn=document.getElementById('btn-dash-edit');
  const hint=document.getElementById('dash-edit-hint');
  if(btn) btn.innerHTML=_dashEditMode
    ? '<i class="fa-solid fa-check"></i> Concluir'
    : '<i class="fa-solid fa-sliders"></i> Personalizar cards';
  if(hint) hint.style.display=_dashEditMode?'':'none';
  renderDashboard();
}

function _dashMove(key,dir){
  const keys=[..._dashOrderedKeys];
  const i=keys.indexOf(key); if(i<0) return;
  const j=i+dir; if(j<0||j>=keys.length) return;
  [keys[i],keys[j]]=[keys[j],keys[i]];
  _dashConfig.ordem=keys;
  saveDashConfig();
  renderDashboard();
}

function _dashToggle(key){
  const oc=_dashConfig.ocultos;
  const i=oc.indexOf(key);
  if(i>=0) oc.splice(i,1); else oc.push(key);
  saveDashConfig();
  renderDashboard();
}

// Renderiza os cards aplicando ordem e ocultos do usuário
function _renderDashCards(catalogo){
  const stats=document.getElementById('dashboard-stats'); if(!stats) return;
  const cfg=_dashConfig;
  const ordered=[...catalogo].sort((a,b)=>{
    let ia=cfg.ordem.indexOf(a.key), ib=cfg.ordem.indexOf(b.key);
    if(ia<0) ia=999; if(ib<0) ib=999;
    return ia-ib;
  });
  _dashOrderedKeys=ordered.map(c=>c.key);
  if(_dashEditMode){
    stats.innerHTML=ordered.map((c,i)=>{
      const oculto=cfg.ocultos.includes(c.key);
      return `<div class="dash-edit-wrap${oculto?' dash-oculto':''}">
        ${c.html}
        <div class="dash-edit-bar">
          <button onclick="_dashMove('${c.key}',-1)" ${i===0?'disabled':''} title="Mover para cima"><i class="fa-solid fa-arrow-up"></i></button>
          <button onclick="_dashMove('${c.key}',1)" ${i===ordered.length-1?'disabled':''} title="Mover para baixo"><i class="fa-solid fa-arrow-down"></i></button>
          <button class="dash-edit-toggle" onclick="_dashToggle('${c.key}')">${oculto?'<i class="fa-solid fa-eye"></i> Mostrar':'<i class="fa-solid fa-eye-slash"></i> Ocultar'}</button>
        </div>
      </div>`;
    }).join('');
  } else {
    stats.innerHTML=ordered.filter(c=>!cfg.ocultos.includes(c.key)).map(c=>c.html).join('');
  }
}

function renderDashboard(){
  // Carrega a personalização do dashboard do usuário (uma vez por usuário)
  const _uid=Auth.currentUser?.id;
  if(_uid && _dashConfigLoadedFor!==_uid){
    _dashConfigLoadedFor=_uid;
    DB.getDoc('configuracoes','dashboard_'+_uid).then(d=>{
      _dashConfig = d ? { ordem:d.ordem||[], ocultos:d.ocultos||[] } : { ordem:[], ocultos:[] };
      if(State.currentSection==='dashboard') renderDashboard();
    }).catch(()=>{});
  }
  const mes=currentMes(), ano=currentAno();
  const payThisMonth=State.payrolls.filter(p=>p.mes==mes&&p.ano==ano);
  const totalEsp     =payThisMonth.reduce((s,p)=>s+(p.remuneracao||0),0);
  const totalLiqFinal=payThisMonth.reduce((s,p)=>s+(p.totalLiquidoFinal||p.remuneracao||0),0);
  const totalINSS    =payThisMonth.reduce((s,p)=>s+(p.inss||0),0);
  const totalFGTS    =payThisMonth.reduce((s,p)=>s+(p.fgts||0),0);
  const ativos=State.employees.filter(e=>(e.status||'ativo')==='ativo').length;
  const inativos=State.employees.filter(e=>(e.status||'ativo')==='inativo').length;
  const afastados=State.employees.filter(e=>(e.status||'ativo')==='afastado').length;
  const licMaternidade=State.employees.filter(e=>(e.status||'ativo')==='licenca-maternidade').length;
  const totalPostos=(State.postos||[]).length;
  const escalasMes=(State.escalas||[]).filter(es=>es.mes==mes&&es.ano==ano).length;
  // Isentos de ponto não precisam de escala — não entram na contagem de pendência
  const ativosComPonto=State.employees.filter(e=>(e.status||'ativo')==='ativo' && !e.isentoPonto).length;
  const escalasPend=Math.max(0, ativosComPonto-escalasMes);
  // Benefícios a pagar — hoje e esta semana
  const hojeISO = new Date().toISOString().substring(0,10);
  const semana  = _semanaDe(hojeISO);
  const colabsHoje   = _colabsTrabalhandoEm(hojeISO);
  const colabsSemana = (State.employees||[]).filter(e => (e.status||'ativo')==='ativo' &&
    _diasTrabalhadosNoIntervalo(e, semana.inicio, semana.fim) > 0);
  let totalBenHoje = 0, totalBenSemana = 0;
  colabsHoje.forEach(e => {
    const b = _calcBeneficiosColab(e, hojeISO, hojeISO, 'dia');
    totalBenHoje += b.total;
  });
  colabsSemana.forEach(e => {
    const b = _calcBeneficiosColab(e, semana.inicio, semana.fim, 'semana');
    totalBenSemana += b.total;
  });
  // HE Pendente de revisão: percorre payrolls do mês e conta dias com divergência > tolerância e status pendente
  let heRevisaoEmps = 0, heRevisaoDias = 0, heRevisaoRef = 0;
  payThisMonth.forEach(p => {
    const emp = State.employees.find(e=>e.id===p.employeeId);
    if(!emp || emp.isentoPonto || !p.pontoManualDias) return;  // isento não tem HE
    let hasPendente = false;
    p.pontoManualDias.forEach(d => {
      // Pedido de refeição não rendida aguardando o supervisor. #ref-nao-rendida-solicitada
      if(d.refExtra && d.refExtra.status==='pendente'){ heRevisaoRef++; hasPendente = true; }
      if(!d.entrada || !d.saida) return;
      const exp = _getExpectedDayComp(emp, p.mes, p.ano, d.dia);
      // NÃO pula folga: _detectHEDivergencia é a fonte única (folga trabalhada =
      // HE pendente). O '!exp.entrada' descartava folga e dessincronizava do
      // badge do card. #he-folga-consistencia
      if(!exp) return;
      // Almoço suprimido detectado pela batida, sem decisão → pendência a autorizar. #ref-detectada
      if(!(d.refExtra&&d.refExtra.status) && _almocoSuprimidoDetectadoMin(d, exp, emp)>0){ heRevisaoRef++; hasPendente = true; }
      const detec = _detectHEDivergencia(d, exp);
      if(detec.precisaRevisao && (d.heReview?.status||'pendente')==='pendente'){
        heRevisaoDias++;
        hasPendente = true;
      }
    });
    if(hasPendente) heRevisaoEmps++;
  });
  const stats=document.getElementById('dashboard-stats'); if(!stats) return;
  const catalogo=[];
  catalogo.push({key:'ativos', html:_statCard({label:'Colaboradores ativos', value:ativos, icon:'fa-user-check',
    accent:'var(--primary)', iconBg:'var(--primary-light)', iconColor:'var(--primary)',
    onclick:"showSection('employees');setEmployeeFilter('ativo')", title:'Ver colaboradores ativos'})});
  catalogo.push({key:'afastados', html:_statCard({label:'Afastados INSS', value:afastados, icon:'fa-user-clock',
    accent:'#00838F', iconBg:'#E0F7FA', iconColor:'#00838F',
    onclick:"showSection('employees');setEmployeeFilter('afastado')", title:'Ver afastados INSS'})});
  if(licMaternidade>0) catalogo.push({key:'licMaternidade', html:_statCard({label:'Licença Maternidade', value:licMaternidade, icon:'fa-baby',
    accent:'#E91E63', iconBg:'#FCE4EC', iconColor:'#E91E63', valueColor:'#E91E63',
    onclick:"showSection('employees');setEmployeeFilter('licenca-maternidade')", title:'Ver licenças maternidade'})});
  catalogo.push({key:'inativos', html:_statCard({label:'Colaboradores inativos', value:inativos, icon:'fa-user-slash',
    accent:'#9E9E9E', iconBg:'#F5F5F5', iconColor:'#757575',
    onclick:"showSection('employees');setEmployeeFilter('inativo')", title:'Ver colaboradores inativos'})});
  catalogo.push({key:'postos', html:_statCard({label:'Postos de trabalho', value:totalPostos, icon:'fa-building',
    accent:'#1565C0', iconBg:'#E3F2FD', iconColor:'#1565C0', valueColor:'#1565C0',
    onclick:"showSection('postos')", title:'Ver postos de trabalho'})});
  if(heRevisaoEmps>0) catalogo.push({key:'heRevisao', html:_statCard({label:'Pendentes de revisar HE', value:heRevisaoEmps, icon:'fa-magnifying-glass',
    accent:'#E65100', iconBg:'#FFF3E0', iconColor:'#E65100', valueColor:'#E65100',
    sub:`<i class="fa-solid fa-triangle-exclamation"></i> ${heRevisaoDias} dia(s) de HE${heRevisaoRef?` + <span style="color:#6A1B9A">${heRevisaoRef} refeição</span>`:''} — clique pra revisar`, subColor:'#E65100',
    onclick:"_dashGotoHEReview()", title:'Colaboradores com HE acima da tolerância CLT e/ou refeição não rendida aguardando revisão'})});
  // Faltas registradas no mês — colaboradores com falta injustificada. Clique → lista de nomes → folha. #card-faltas
  {
    const _faltasL = _getFaltasList(mes, ano);
    if(_faltasL.length>0){
      const _totFaltaDias = _faltasL.reduce((s,x)=>s+x.qtd,0);
      catalogo.push({key:'faltas', html:_statCard({label:'Faltas registradas', value:_faltasL.length, icon:'fa-user-xmark',
        accent:'#c62828', iconBg:'#FFEBEE', iconColor:'#c62828', valueColor:'#c62828',
        sub:`${_totFaltaDias} dia(s) de falta em ${MESES[mes]} — clique p/ ver os nomes`, subColor:'#c62828',
        onclick:"openFaltasList()", title:'Colaboradores com faltas injustificadas no mês — clique para ver os nomes e abrir a folha de cada um'})});
    }
  }
  // Férias — PAGAMENTO a vencer (CLT Art. 145: até 2 dias antes do início). #ferias-pagamento
  {
    const _ferPag=_getFeriasPagamentoPend();
    if(_ferPag.length>0){
      const _venc=_ferPag.filter(x=>x.vencido).length;
      catalogo.push({key:'feriasPagar', html:_statCard({label:'Férias a pagar', value:_ferPag.length, icon:'fa-umbrella-beach',
        accent:'#00695C', iconBg:'#E0F2F1', iconColor:'#00695C', valueColor:_venc>0?'#c62828':'#00695C',
        sub:_venc>0
          ? `<i class="fa-solid fa-triangle-exclamation"></i> ${_venc} com prazo VENCIDO — pague já (atraso = em dobro)`
          : 'pagar até 2 dias antes do início — clique p/ ver',
        subColor:_venc>0?'#c62828':'#00695C',
        onclick:"openFeriasPagamentoList()", title:'Férias com pagamento a vencer — remuneração + 1/3 deve ser paga até 2 dias antes do início (CLT Art. 145)'})});
    }
  }
  {
    const pendAprov=(State.solicitacoes||[]).filter(s=>s.status==='pendente');
    const md=getUserModules(Auth.currentUser);
    if(pendAprov.length>0 && (md.pagamentosLancar||md.pagamentosAprovar)){
      const totalP=pendAprov.reduce((s,x)=>s+(x.valor||0),0);
      catalogo.push({key:'aprovacoesPend', html:_statCard({label:'Pagamentos aguardando aprovação', value:pendAprov.length, icon:'fa-hourglass-half',
        accent:'#E65100', iconBg:'#FFF3E0', iconColor:'#E65100', valueColor:'#E65100',
        sub:`${fmtMoney(totalP)} — clique para revisar`, subColor:'#E65100',
        onclick:"showSection('aprovacoes')", title:'Solicitações de pagamento pendentes de aprovação'})});
    }

    // Pedidos de autorização do operador aguardando o MASTER decidir (inclusão + pagamento). #autorizacao-master
    const pedAutoriz=pendAprov.filter(s=>s.autorizacaoSolicitada);
    const _ehAprovador = md.pagamentosAprovar || Auth.currentUser?.role==='master';
    if(pedAutoriz.length>0 && _ehAprovador){
      const totalA=pedAutoriz.reduce((s,x)=>s+(x.valor||0),0);
      catalogo.push({key:'autorizacaoPend', html:_statCard({label:'Pedidos de autorização (você decide)', value:pedAutoriz.length, icon:'fa-user-shield',
        accent:'#C2185B', iconBg:'#FCE4EC', iconColor:'#C2185B', valueColor:'#C2185B',
        sub:`${fmtMoney(totalA)} — um operador pediu sua autorização. Clique para decidir.`, subColor:'#C2185B',
        onclick:"showSection('aprovacoes')", title:'Pagamentos lançados por operador aguardando sua autorização (inclusão + pagamento)'})});
    }

    // Documentos enviados pelo colaborador via app, aguardando aprovação
    const pendDocs=(State.documentos||[]).filter(d=>d.status==='pendente');
    if(pendDocs.length>0 && md.employees){
      catalogo.push({key:'docsPend', html:_statCard({label:'Documentos aguardando aprovação', value:pendDocs.length, icon:'fa-folder-tree',
        accent:'#6A1B9A', iconBg:'#F3E5F5', iconColor:'#6A1B9A', valueColor:'#6A1B9A',
        sub:'Enviados pelos colaboradores pelo app — clique para revisar', subColor:'#6A1B9A',
        onclick:"showSection('documentos')", title:'Documentos enviados pelo app aguardando aprovação'})});
    }

    // Adiantamentos vencidos no mês corrente — passou do dia limite e o
    // pagamento ainda não foi feito (nem via sistema, nem registrado como pago fora).
    {
      const _agora=new Date();
      const _mesA=_agora.getMonth()+1, _anoA=_agora.getFullYear(), _diaA=_agora.getDate();
      const _diaLim=Math.min(28,Math.max(1,parseInt(State.empresa?.diaLimiteAdiantamento)||15));
      if(_diaA>_diaLim){
        const _compA=String(_mesA).padStart(2,'0')+'/'+_anoA;
        const _venc=(State.payrolls||[]).filter(p=>
          p.mes==_mesA && p.ano==_anoA &&
          p.adiantamentoAtivo && (p.adiantamentoValor||0)>0 &&
          !p.adiantamentoPagoExterno &&
          !(State.solicitacoes||[]).some(s=>s.origem==='adiantamento' && s.employeeId===p.employeeId &&
            s.competencia===_compA && (s.status==='pendente'||s.status==='pago'))
        );
        if(_venc.length>0){
          const _totV=_venc.reduce((s,p)=>s+(p.adiantamentoValor||0),0);
          catalogo.push({key:'adiantVencidos', html:_statCard({
            label:'Adiantamentos vencidos', value:_venc.length, icon:'fa-triangle-exclamation',
            accent:'#c62828', iconBg:'#FFEBEE', iconColor:'#c62828', valueColor:'#c62828',
            sub:`${fmtMoney(_totV)} — passou do dia ${_diaLim}; pague ou marque como pago fora`, subColor:'#c62828',
            onclick:"showSection('adiantamentos')", title:'Adiantamentos vencidos do mês corrente'
          })});
        }
      }
    }

    // Adiantamentos quinzenais — TOTAL do mês corrente (todos com adiantamentoAtivo
    // e valor > 0, vencidos ou não). Clique abre a lista por colaborador.
    {
      const _agoraQ=new Date();
      const _mesQ=_agoraQ.getMonth()+1, _anoQ=_agoraQ.getFullYear();
      const _listaQ=(State.payrolls||[]).filter(p =>
        p.mes==_mesQ && p.ano==_anoQ &&
        p.adiantamentoAtivo && (p.adiantamentoValor||0)>0
      );
      if(_listaQ.length>0){
        const _totQ=_listaQ.reduce((s,p)=>s+(p.adiantamentoValor||0),0);
        catalogo.push({key:'adiantQuinzenais', html:_statCard({
          label:'Adiantamentos quinzenais', value:_listaQ.length, icon:'fa-money-bill-trend-up',
          accent:'#00897B', iconBg:'#E0F2F1', iconColor:'#00695C', valueColor:'#00695C',
          sub:`${fmtMoney(_totQ)} — ${MESES[_mesQ]}/${_anoQ} · clique p/ ver a lista`, subColor:'#00695C',
          onclick:"showSection('adiantamentos')", title:'Total dos adiantamentos quinzenais do mês corrente'
        })});
      }
    }
  }
  if(colabsHoje.length>0||colabsSemana.length>0) catalogo.push({key:'beneficios', html:_statCard({label:'Benefícios a pagar hoje', value:colabsHoje.length, icon:'fa-money-check-dollar',
    accent:'#0288D1', iconBg:'#E1F5FE', iconColor:'#0288D1', valueColor:'#0288D1',
    sub:`${fmtMoney(totalBenHoje)} hoje &middot; Semana: ${colabsSemana.length} colab. ${fmtMoney(totalBenSemana)}`, subColor:'#01579B',
    onclick:"openBeneficiosPagar()", title:'Ver benefícios a pagar hoje e nesta semana'})});
  catalogo.push({key:'escalas', html:_statCard({label:`Escalas — ${MESES[mes]}/${ano}`, value:escalasMes, icon:'fa-calendar-days',
    accent:'#6A1B9A', iconBg:'#F3E5F5', iconColor:'#6A1B9A', valueColor:'#6A1B9A',
    sub: escalasPend>0?`<i class="fa-solid fa-triangle-exclamation"></i> ${escalasPend} pendente(s) de revisão`:'<i class="fa-solid fa-check-circle"></i> Todas projetadas',
    subColor: escalasPend>0?'#E65100':'#1B5E20',
    onclick:"showSection('escalas')", title:'Ver escalas do mês'})});
  {
    const modo=State.empresa?.modoContabilidade||'ambas';
    const usaInterna=modo==='interna'||modo==='ambas';
    const usaExterna=modo==='externa'||modo==='ambas';
    const encargosCalc=totalINSS>0;
    if(usaInterna) catalogo.push({key:'folha', html:_statCard({label:`Folha de ${MESES[mes]}<span style="display:block;font-weight:400;font-size:11px;color:var(--text-muted);margin-top:2px">${payThisMonth.length} Holerite${payThisMonth.length!==1?'s':''}</span>`,
      value:fmtMoney(usaExterna&&!encargosCalc?totalEsp:totalLiqFinal), icon:'fa-money-bill-wave',
      accent:'#1B5E20', iconBg:'#E8F5E9', iconColor:'#1B5E20', valueColor:'#1B5E20',
      onclick:"showSection('pagamentos')", title:'Ver pagamentos do mês'})});
    if(usaExterna&&!usaInterna) catalogo.push({key:'contabilidade', html:_statCard({label:`Remunerações ${MESES[mes]} — ${payThisMonth.length} folha(s)`,
      value:fmtMoney(totalEsp), icon:'fa-calculator',
      accent:'#F57F17', iconBg:'#FFF3E0', iconColor:'#F57F17',
      sub:'Exportar para contador externo', subColor:'#777',
      onclick:"showSection('contabilidade')", title:'Ver planilha de contabilidade'})});
  }
  catalogo.push({key:'folhasLancadas', html:_statCard({label:`Folhas lançadas em ${MESES[mes]}`, value:payThisMonth.length, icon:'fa-file-circle-check',
    accent:'var(--success)', iconBg:'var(--success-light)', iconColor:'var(--success)', valueColor:'var(--success)',
    onclick:"showSection('payroll')", title:'Ver folha de ponto'})});
  catalogo.push({key:'contratos', html:_statCard({label:'Contratos ativos', value:(State.contratos||[]).filter(c=>!c.status||c.status!=='inativo').length, icon:'fa-file-signature',
    accent:'#2E7D32', iconBg:'#F1F8E9', iconColor:'#2E7D32', valueColor:'#2E7D32',
    onclick:"showSection('contratos')", title:'Ver contratos'})});
  if(State.cct) catalogo.push({key:'cct', html:_statCard({label:'CCT vigente', value:`desde ${formatDateBr(State.cct.vigencia)}`, icon:'fa-file-contract',
    accent:'#7B1FA2', iconBg:'#F3E5F5', iconColor:'#7B1FA2', valueColor:'#7B1FA2', smallValue:true,
    onclick:"openCctModal()", title:'Abrir a CCT vigente'})});
  _renderDashCards(catalogo);
  renderBirthdays();
  renderAlerts();
  renderExperiencias();
  const recEl=document.getElementById('recent-payrolls'); if(!recEl) return;
  const recent=[...State.payrolls].sort((a,b)=>new Date(b.createdAt)-new Date(a.createdAt)).slice(0,6);
  if(recent.length===0){
    recEl.innerHTML=`<div class="empty-state small"><i class="fa-solid fa-file-circle-xmark"></i><p>Nenhum lançamento recente</p></div>`;
  } else {
    recEl.innerHTML=recent.map(p=>{
      const emp=State.employees.find(e=>e.id===p.employeeId); if(!emp) return '';
      const totalFaltas='faltasJustificadas' in p?(p.faltasJustificadas||0)+(p.faltasInjustificadas||0):(p.faltas||0);
      return `<div class="recent-item">
        <div class="recent-avatar">${initials(emp.nome)}</div>
        <div><div class="recent-name">${emp.nome}</div>
             <div class="recent-period">${MESES[p.mes]}/${p.ano} — ${p.diasTrabalhados}d / ${totalFaltas} falta(s)</div></div>
        <div class="recent-value">${fmtMoney(p.remuneracao)}</div>
      </div>`;
    }).join('');
  }
}

function formatDateBr(iso){
  if(!iso) return '—';
  // Para datas no formato YYYY-MM-DD sem hora
  if(iso.length===10) { const [y,m,d]=iso.split('-'); return `${d}/${m}/${y}`; }
  return new Date(iso).toLocaleDateString('pt-BR');
}

// ============================================
// STATS DA FOLHA DE PONTO
// ============================================
function renderPayrollStats(){
  const grid=document.getElementById('payroll-stats-grid'); if(!grid) return;
  const mes=currentMes(), ano=currentAno();
  const payThisMonth=State.payrolls.filter(p=>p.mes==mes&&p.ano==ano);
  const tR=payThisMonth.reduce((s,p)=>s+(p.remuneracao||0),0);
  const tVT=payThisMonth.reduce((s,p)=>s+(p.valeTransporte||0),0);
  const tVR=payThisMonth.reduce((s,p)=>s+(p.valeRefeicao||0),0);
  const tVA=payThisMonth.reduce((s,p)=>s+(p.valeAlimentacaoLiquido||0),0);
  const tHE=payThisMonth.reduce((s,p)=>s+(p.horasExtrasValor||0),0);
  const tB=payThisMonth.reduce((s,p)=>s+(p.bonificacao||0),0);
  const tAN=payThisMonth.reduce((s,p)=>s+(p.adNoturno||0),0);
  const tAdiant=payThisMonth.reduce((s,p)=>s+(p.adiantamentoValor||p.adiantamento||0),0);
  const tTotal=tR+tVT+tVR+tVA+tHE+tB+tAN;
  const sc='cursor:pointer;transition:box-shadow .15s' , sh='onmouseover="this.style.boxShadow=\'0 4px 16px #0002\'" onmouseout="this.style.boxShadow=\'\'"';
  grid.innerHTML=`
    <div class="stat-card green" style="${sc}" onclick="showPayrollStatDetail('_all','Folhas Lançadas','#2E7D32')" ${sh}>
      <div class="stat-icon"><i class="fa-solid fa-file-circle-check"></i></div>
      <div><div class="stat-value">${payThisMonth.length}</div><div class="stat-label">Folhas lançadas — ${MESES[mes]}</div></div></div>
    <div class="stat-card amber" style="${sc}" onclick="showPayrollStatDetail('remuneracao','Total Remunerações','#F9A825')" ${sh}>
      <div class="stat-icon"><i class="fa-solid fa-money-bill-wave"></i></div>
      <div><div class="stat-value">${fmtMoney(tR)}</div><div class="stat-label">Total Remunerações</div></div></div>
    <div class="stat-card" style="border-color:#0288D1;border-left-width:4px;${sc}" onclick="showPayrollStatDetail('valeTransporte','Vale Transporte','#0288D1')" ${sh}>
      <div class="stat-icon" style="background:#E1F5FE;color:#0288D1"><i class="fa-solid fa-bus"></i></div>
      <div><div class="stat-value" style="font-size:15px">${fmtMoney(tVT)}</div><div class="stat-label">Vale Transporte</div></div></div>
    <div class="stat-card" style="border-color:#E65100;border-left-width:4px;${sc}" onclick="showPayrollStatDetail('valeRefeicao','Vale Refeição','#E65100')" ${sh}>
      <div class="stat-icon" style="background:#FBE9E7;color:#E65100"><i class="fa-solid fa-utensils"></i></div>
      <div><div class="stat-value" style="font-size:15px">${fmtMoney(tVR)}</div><div class="stat-label">Vale Refeição</div></div></div>
    <div class="stat-card" style="border-color:#2E7D32;border-left-width:4px;${sc}" onclick="showPayrollStatDetail('valeAlimentacaoLiquido','Vale Alimentação','#2E7D32')" ${sh}>
      <div class="stat-icon" style="background:#E8F5E9;color:#2E7D32"><i class="fa-solid fa-basket-shopping"></i></div>
      <div><div class="stat-value" style="font-size:15px">${fmtMoney(tVA)}</div><div class="stat-label">Vale Alimentação</div></div></div>
    <div class="stat-card" style="border-color:#5C6BC0;border-left-width:4px;${sc}" onclick="showPayrollStatDetail('horasExtrasValor','Horas Extras','#5C6BC0')" ${sh}>
      <div class="stat-icon" style="background:#E8EAF6;color:#5C6BC0"><i class="fa-solid fa-clock-rotate-left"></i></div>
      <div><div class="stat-value" style="font-size:15px">${fmtMoney(tHE)}</div><div class="stat-label">Horas Extras</div></div></div>
    <div class="stat-card" style="border-color:#F57C00;border-left-width:4px;${sc}" onclick="showPayrollStatDetail('bonificacao','Bonificação','#F57C00')" ${sh}>
      <div class="stat-icon" style="background:#FFF3E0;color:#F57C00"><i class="fa-solid fa-star"></i></div>
      <div><div class="stat-value" style="font-size:15px">${fmtMoney(tB)}</div><div class="stat-label">Bonificação</div></div></div>
    <div class="stat-card" style="border-color:#00796B;border-left-width:4px;${sc}" onclick="showPayrollStatDetail('adiantamento','Adiantamentos','#00796B')" ${sh}>
      <div class="stat-icon" style="background:#E0F2F1;color:#00796B"><i class="fa-solid fa-hand-holding-dollar"></i></div>
      <div><div class="stat-value" style="font-size:15px">${fmtMoney(tAdiant)}</div><div class="stat-label">Adiantamentos</div></div></div>
    <div class="stat-card blue" style="${sc}" onclick="showPayrollStatDetail('_total','Total Geral do Mês','#1565C0')" ${sh}>
      <div class="stat-icon"><i class="fa-solid fa-calculator"></i></div>
      <div><div class="stat-value">${fmtMoney(tTotal)}</div><div class="stat-label">Total Geral do Mês</div></div></div>
  `;
}

function showPayrollStatDetail(fieldKey, label, color, mesArg, anoArg){
  const mes=(mesArg!=null)?mesArg:currentMes(), ano=(anoArg!=null)?anoArg:currentAno();
  const payThisMonth=State.payrolls.filter(p=>p.mes==mes&&p.ano==ano);
  let items=[];
  if(fieldKey==='_semfolha'){
    // Colaboradores ATIVOS sem folha lançada no mês — respeita o escopo do usuário.
    const have=new Set(payThisMonth.map(p=>p.employeeId));
    items=_filtrarEmpsPorEscopo(State.employees)
      .filter(e=>(e.status||'ativo')==='ativo' && !have.has(e.id))
      .map(e=>({empId:e.id,nome:e.nome,setor:e.posto||e.setor||'—',value:0,valueLabel:'Sem folha'}))
      .sort((a,b)=>(a.nome||'').localeCompare(b.nome||''));
  } else if(fieldKey==='_all'){
    items=payThisMonth.map(p=>{
      const emp=State.employees.find(e=>e.id===p.employeeId); if(!emp) return null;
      return {empId:p.employeeId,nome:emp.nome,setor:emp.setor||'—',value:p.remuneracao||0,valueLabel:fmtMoney(p.remuneracao||0)};
    }).filter(Boolean);
  } else if(fieldKey==='_total'){
    items=payThisMonth.map(p=>{
      const emp=State.employees.find(e=>e.id===p.employeeId); if(!emp) return null;
      const t=(p.remuneracao||0)+(p.valeTransporte||0)+(p.valeRefeicao||0)+(p.valeAlimentacaoLiquido||0)+(p.horasExtrasValor||0)+(p.bonificacao||0)+(p.adNoturno||0);
      return {empId:p.employeeId,nome:emp.nome,setor:emp.setor||'—',value:t,valueLabel:fmtMoney(t)};
    }).filter(i=>i&&i.value>0);
  } else {
    items=payThisMonth.map(p=>{
      const emp=State.employees.find(e=>e.id===p.employeeId); if(!emp) return null;
      const v=p[fieldKey]||0; if(v<=0) return null;
      return {empId:p.employeeId,nome:emp.nome,setor:emp.setor||'—',value:v,valueLabel:fmtMoney(v)};
    }).filter(Boolean);
  }
  items.sort((a,b)=>b.value-a.value);
  const _closeStatDetail=()=>{ const m=document.getElementById('modal-stat-detail'); if(m) m.remove(); };
  _closeStatDetail();
  const modal=document.createElement('div');
  modal.id='modal-stat-detail';
  modal.style.cssText='position:fixed;inset:0;background:rgba(10,20,40,.55);display:flex;align-items:center;justify-content:center;z-index:9999;padding:20px;animation:fadeIn .15s ease';
  modal.addEventListener('click',e=>{ if(e.target===modal) _closeStatDetail(); });
  const bodyRows = items.length===0
    ? `<div style="text-align:center;padding:40px;color:#aaa"><i class="fa-solid fa-inbox" style="font-size:36px;margin-bottom:12px;display:block"></i><div style="font-size:14px">Nenhum registro neste mês</div></div>`
    : items.map(it=>`
      <div data-emp-row="${it.empId}" data-emp-nome="${(it.nome||'').replace(/"/g,'&quot;')}"
           style="display:flex;align-items:center;gap:14px;padding:14px 20px;cursor:pointer;border-bottom:1px solid #f0f0f0;transition:background .12s;-webkit-tap-highlight-color:${color}25"
           onmouseover="this.style.background='${color}10'" onmouseout="this.style.background=''"
           onmousedown="this.style.background='${color}22'" onmouseup="this.style.background='${color}10'"
           ontouchstart="this.style.background='${color}22'" ontouchend="this.style.background=''">
        <div style="width:40px;height:40px;border-radius:50%;background:${color}22;color:${color};display:flex;align-items:center;justify-content:center;font-weight:800;font-size:14px;flex-shrink:0;letter-spacing:-.5px">${initials(it.nome)}</div>
        <div style="flex:1;min-width:0">
          <div style="font-weight:600;color:#1a1a2e;font-size:14px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${it.nome}</div>
          <div style="font-size:12px;color:#9e9e9e;margin-top:1px">${it.setor}</div>
        </div>
        <div style="font-weight:700;color:${color};font-size:15px;white-space:nowrap;margin-right:4px">${it.valueLabel}</div>
        <i class="fa-solid fa-arrow-right" style="color:${color};font-size:13px"></i>
      </div>`).join('');
  modal.innerHTML=`
    <div style="background:#fff;border-radius:16px;width:100%;max-width:480px;max-height:85vh;display:flex;flex-direction:column;box-shadow:0 24px 60px rgba(0,0,0,.25);overflow:hidden">
      <div style="display:flex;align-items:center;justify-content:space-between;padding:18px 20px 14px;border-bottom:2px solid ${color}30;background:${color}08">
        <div>
          <div style="font-size:17px;font-weight:700;color:#1a1a2e">${label}</div>
          <div data-stat-count style="font-size:12px;color:#888;margin-top:2px">${MESES[mes]}/${ano} · ${items.length} colaborador${items.length!==1?'es':''}</div>
        </div>
        <button onclick="document.getElementById('modal-stat-detail').remove()" style="border:none;background:${color}15;color:${color};width:34px;height:34px;border-radius:50%;cursor:pointer;font-size:16px;display:flex;align-items:center;justify-content:center">✕</button>
      </div>
      ${items.length > 0 ? `
      <div style="padding:10px 16px;border-bottom:1px solid #f0f0f0;background:#fafafa">
        <div style="position:relative">
          <i class="fa-solid fa-magnifying-glass" style="position:absolute;left:12px;top:50%;transform:translateY(-50%);color:#9e9e9e;font-size:13px;pointer-events:none"></i>
          <input data-stat-search type="text" placeholder="Buscar por nome..."
            style="width:100%;padding:9px 12px 9px 34px;border:1px solid #e0e0e0;border-radius:8px;font-size:14px;outline:none;transition:border-color .15s"
            onfocus="this.style.borderColor='${color}'" onblur="this.style.borderColor='#e0e0e0'">
        </div>
        <div data-stat-empty style="display:none;text-align:center;padding:20px;color:#aaa;font-size:13px"><i class="fa-solid fa-magnifying-glass" style="font-size:24px;margin-bottom:8px;display:block;opacity:.5"></i>Nenhum nome encontrado</div>
      </div>` : ''}
      <div data-stat-rows style="overflow-y:auto;flex:1">${bodyRows}</div>
    </div>`;
  document.body.appendChild(modal);
  // Listeners via JS — mais robusto que inline onclick. Cada linha leva
  // o usuario para a Folha de Ponto do colaborador no mes correspondente,
  // com scroll + destaque visual no campo do indicador clicado.
  modal.querySelectorAll('[data-emp-row]').forEach(row => {
    row.addEventListener('click', (ev) => {
      ev.stopPropagation();
      const empId = row.dataset.empRow;
      const empNome = row.dataset.empNome || '';
      _closeStatDetail();
      toast(`Abrindo folha de ${empNome}...`, 'success');
      openPayrollForEmployee(empId, { mes, ano, fieldKey, label, color });
    });
  });
  // Lupa de busca por nome — filtra em tempo real
  const searchInput = modal.querySelector('[data-stat-search]');
  if (searchInput) {
    const rows       = modal.querySelectorAll('[data-emp-row]');
    const countEl    = modal.querySelector('[data-stat-count]');
    const emptyEl    = modal.querySelector('[data-stat-empty]');
    const rowsCont   = modal.querySelector('[data-stat-rows]');
    const monthLabel = `${MESES[mes]}/${ano}`;
    // Helper pra "normalizar" — remove acentos e baixa caso, casa busca "joao" com "João"
    const norm = s => (s || '').toLowerCase()
      .normalize('NFD').replace(/[̀-ͯ]/g, '');
    searchInput.addEventListener('input', () => {
      const q = norm(searchInput.value.trim());
      let visible = 0;
      rows.forEach(r => {
        const match = !q || norm(r.dataset.empNome || '').includes(q);
        r.style.display = match ? '' : 'none';
        if (match) visible++;
      });
      if (countEl) countEl.textContent = `${monthLabel} · ${visible} colaborador${visible !== 1 ? 'es' : ''}`;
      if (emptyEl) emptyEl.style.display = visible === 0 ? 'block' : 'none';
      if (rowsCont) rowsCont.style.display = visible === 0 ? 'none' : '';
    });
    // Foca o input automaticamente (desktop). Em mobile o teclado virtual
    // pode subir junto — aceitavel, o caso de uso e' "abriu pra buscar".
    setTimeout(() => searchInput.focus(), 50);
  }
}

// Helpers globais para o openPayrollForEmployee com destaque
// (definidos no escopo do app — usados depois que showSection renderiza)
function _highlightPayrollField(fieldKey, color){
  // Mapeia o campo do payroll para o id do input/elemento na tela da folha.
  // IDs conferidos no index.html (linha de cada input).
  const map = {
    horasExtrasValor:        'payroll-he-valor',
    remuneracao:             'payroll-remuneracao',
    valeTransporte:          'payroll-vt-total',
    valeRefeicao:            'payroll-vr-total',
    valeAlimentacaoLiquido:  'payroll-va-total',
    adNoturno:               'payroll-noturno',
    bonificacao:             'payroll-bonus',
    atraso:                  'atrasos-card',                 // drill-down da planilha contábil → card de Atrasos. #planilha-contador
    falta:                   'payroll-faltas-injustificadas',
  };
  const targetId = map[fieldKey];
  if(!targetId) return;
  const el = document.getElementById(targetId);
  if(!el) return;
  // Procura o container/card pai para o scroll/destaque ficar melhor visualmente
  const card = el.closest('.benefit-card') || el.closest('.form-group') || el;
  try{ card.scrollIntoView({behavior:'smooth', block:'center'}); }catch(_){ card.scrollIntoView(); }
  // Destaque pulsante por 3.5s: aplica via classe CSS injetada uma vez.
  if(!document.getElementById('_hl-pulse-style')){
    const st = document.createElement('style');
    st.id = '_hl-pulse-style';
    st.textContent = `
      @keyframes hlPulse { 0%,100%{box-shadow:0 0 0 0 var(--hl-color)} 50%{box-shadow:0 0 0 8px var(--hl-shadow)} }
      ._hl-active { animation: hlPulse 1s ease-in-out 3; outline:3px solid var(--hl-color) !important; outline-offset:3px; border-radius:6px; }
    `;
    document.head.appendChild(st);
  }
  card.style.setProperty('--hl-color', color);
  card.style.setProperty('--hl-shadow', color + '40');
  card.classList.add('_hl-active');
  setTimeout(() => card.classList.remove('_hl-active'), 3500);
}

// ============================================
// CONTABILIDADE
// ============================================
// ============================================================
// MÓDULO PAGAMENTOS
// ============================================================
function renderPagamentos(){
  const mes=parseInt(val('pag-mes')||currentMes());
  const ano=parseInt(val('pag-ano')||currentAno());
  const statusFilt=val('pag-status-filter')||'ativo';

  let emps=_filtrarEmpsPorEscopo(State.employees).slice();
  if(statusFilt!=='all') emps=emps.filter(e=>(e.status||'ativo')===statusFilt);
  emps.sort((a,b)=>a.nome.localeCompare(b.nome));
  if(emps.length===0){ toast('Nenhum colaborador encontrado.','warning'); return; }

  const mesLabel=MESES[mes]||'';
  const folhasMes=State.payrolls.filter(p=>p.mes===mes&&p.ano===ano);
  const folhaMap=_buildFolhaMap(folhasMes);

  // Totais
  let tBruto=0,tINSS=0,tIRRF=0,tFGTS=0,tAdiant=0,tLiquido=0,comFolha=0,semFolhaCount=0;
  emps.forEach(e=>{
    const p=folhaMap[e.id];
    if(p){
      comFolha++;
      tBruto  +=(p.totalBruto||0);
      tINSS   +=(p.inss||0);
      tIRRF   +=(p.irrf||0);
      tFGTS   +=(p.fgts||0);
      tAdiant +=(p.adiantamentoValor||p.adiantamento||0);
      tLiquido+=_reciboOficialLinhas(e,p).liquido; // mesma conta do holerite → cruzamentos batem
    } else { semFolhaCount++; }
  });

  // Stats grid
  const statsEl=document.getElementById('pag-stats');
  if(statsEl){
    const scrollToTable=`document.getElementById('pag-table-card').scrollIntoView({behavior:'smooth',block:'start'})`;
    statsEl.innerHTML=`
      <div class="stat-card" style="cursor:pointer" onclick="${scrollToTable}">
        <div class="stat-icon" style="background:rgba(27,94,32,0.1)"><i class="fa-solid fa-sack-dollar" style="color:var(--success)"></i></div>
        <div class="stat-info"><div class="stat-label">Total da Folha</div><div class="stat-value" style="color:var(--success)">${fmtMoney(tLiquido)}</div></div>
      </div>
      <div class="stat-card" style="cursor:pointer" onclick="showPayrollStatDetail('inss','Total INSS','#c0392b',${mes},${ano})">
        <div class="stat-icon" style="background:rgba(192,57,43,0.1)"><i class="fa-solid fa-building-columns" style="color:#c0392b"></i></div>
        <div class="stat-info"><div class="stat-label">Total INSS</div><div class="stat-value" style="color:#c0392b">${fmtMoney(tINSS)}</div></div>
      </div>
      <div class="stat-card" style="cursor:pointer" onclick="showPayrollStatDetail('irrf','Total IRRF','#c0392b',${mes},${ano})">
        <div class="stat-icon" style="background:rgba(192,57,43,0.1)"><i class="fa-solid fa-file-invoice" style="color:#c0392b"></i></div>
        <div class="stat-info"><div class="stat-label">Total IRRF</div><div class="stat-value" style="color:#c0392b">${fmtMoney(tIRRF)}</div></div>
      </div>
      <div class="stat-card" style="cursor:pointer" onclick="showPayrollStatDetail('fgts','FGTS Empregador','#1565C0',${mes},${ano})">
        <div class="stat-icon" style="background:rgba(21,101,192,0.1)"><i class="fa-solid fa-piggy-bank" style="color:#1565C0"></i></div>
        <div class="stat-info"><div class="stat-label">FGTS Empregador</div><div class="stat-value" style="color:#1565C0">${fmtMoney(tFGTS)}</div></div>
      </div>
      <div class="stat-card" style="cursor:pointer" onclick="${scrollToTable}">
        <div class="stat-icon" style="background:rgba(27,94,32,0.1)"><i class="fa-solid fa-circle-check" style="color:var(--success)"></i></div>
        <div class="stat-info"><div class="stat-label">Com Holerite</div><div class="stat-value" style="color:var(--success)">${comFolha}</div></div>
      </div>
      <div class="stat-card" style="cursor:pointer" onclick="showPayrollStatDetail('_semfolha','Sem Holerite','#c0392b',${mes},${ano})">
        <div class="stat-icon" style="background:rgba(239,83,80,0.1)"><i class="fa-solid fa-circle-xmark" style="color:var(--danger)"></i></div>
        <div class="stat-info"><div class="stat-label">Sem Holerite</div><div class="stat-value" style="color:${semFolhaCount>0?'var(--danger)':'#999'}">${semFolhaCount}</div></div>
      </div>
    `;
  }

  // Tabela
  const card=document.getElementById('pag-table-card');
  const tbody=document.getElementById('pag-tbody');
  const tfoot=document.getElementById('pag-tfoot');
  const title=document.getElementById('pag-table-title');
  if(!tbody) return;
  if(title) title.innerHTML=`<i class="fa-solid fa-money-check-dollar"></i> Holerites — ${mesLabel} / ${ano} <small style="font-size:12px;font-weight:400;color:#666">(${emps.length} colaborador(es))</small>`;

  const rows=emps.map((e,i)=>{
    const p=folhaMap[e.id];
    const bruto   =p?(p.totalBruto||0):0;
    const inss    =p?(p.inss||0):0;
    const irrf    =p?(p.irrf||0):0;
    const adiant  =p?(p.adiantamentoValor||p.adiantamento||0):0;
    const fgts    =p?(p.fgts||0):0;
    const liq     =p?_reciboOficialLinhas(e,p).liquido:0; // mesma conta do holerite → cruzamentos batem
    const statusStr=p?p.status:'sem folha';
    const badge=statusStr==='fechada'
      ?`<span class="badge" style="background:#E8F5E9;color:#1B5E20;border:1px solid #A5D6A7;padding:2px 8px;border-radius:12px;font-size:11px">✓ Fechada</span>`
      :statusStr==='aberta'
        ?`<span class="badge" style="background:#FFF3E0;color:#E65100;border:1px solid #FFCC80;padding:2px 8px;border-radius:12px;font-size:11px">⏳ Aberta</span>`
        :`<span class="badge" style="background:#FFEBEE;color:#c0392b;border:1px solid #FFCDD2;padding:2px 8px;border-radius:12px;font-size:11px">— Sem folha</span>`;
    const rowBg=i%2===0?'#ffffff':'#EEF2FF';
    const border=!p?'border-left:3px solid #EF9A9A':'';
    return `<tr style="background:${rowBg};${border};cursor:pointer" data-nome="${(e.nome||'').toLowerCase()}" data-reg="${e.registro?String(e.registro).padStart(4,'0'):''}" onclick="_pagRowClick(event,'${e.id}')" title="Clique na linha para revisar/editar a folha de ${(e.nome||'').replace(/"/g,'')}">
      <td style="text-align:center"><input type="checkbox" class="pag-row-check" data-emp-id="${e.id}" onclick="event.stopPropagation();updatePagSelCount()"></td>
      <td>${i+1}</td>
      <td style="font-size:11px">${e.registro?String(e.registro).padStart(4,'0'):'—'}</td>
      <td><strong>${e.nome}</strong></td>
      <td style="font-size:11px">${e.cargo||e.setor||'—'}</td>
      <td>${e.salarioBase?fmtMoney(e.salarioBase):'—'}</td>
      <td style="font-weight:600">${bruto?fmtMoney(bruto):'<span style="color:#ccc">—</span>'}</td>
      <td style="color:#c0392b">${inss?'('+fmtMoney(inss)+')':'—'}</td>
      <td style="color:#c0392b">${irrf?'('+fmtMoney(irrf)+')':'—'}</td>
      <td style="color:#c0392b">${adiant?'('+fmtMoney(adiant)+')':'—'}</td>
      <td style="color:#1565C0">${fgts?fmtMoney(fgts):'—'}</td>
      <td style="font-weight:700;color:#1B5E20">${liq?fmtMoney(liq):'<span style="color:#ccc">—</span>'}</td>
      <td>${badge}${p?`<div style="margin-top:4px"><label style="font-size:10px;color:#555;cursor:pointer;display:inline-flex;align-items:center;gap:3px" onclick="event.stopPropagation()"><input type="checkbox" class="pag-revisada" ${p.revisada?'checked':''} onclick="event.stopPropagation();_pagToggleRevisada('${p.id}',this.checked)"> ${p.revisada?'<span style="color:#1B5E20;font-weight:600">Revisada</span>':'Revisada'}</label></div>`:''}</td>
      <td style="white-space:nowrap">
        ${(() => {
          const env = p ? _reciboEnvioVigente(e.id, mes, ano) : null;
          let badge = '';
          let enviarTitle = 'Enviar recibo pro colaborador (gera link com protocolo)';
          let enviarColor = '#1565C0';
          if(env){
            if(env.visualizadoEm){
              badge = `<span title="Visualizado em ${new Date(env.visualizadoEm).toLocaleString('pt-BR')}" style="display:inline-block;background:#E8F5E9;color:#1B5E20;border:1px solid #A5D6A7;border-radius:10px;padding:0 6px;font-size:10px;margin-right:4px"><i class="fa-solid fa-circle-check"></i> Visualizado</span>`;
              enviarTitle = `Visualizado em ${new Date(env.visualizadoEm).toLocaleString('pt-BR')}`;
              enviarColor = '#1B5E20';
            } else {
              badge = `<span title="Enviado em ${new Date(env.geradoEm).toLocaleString('pt-BR')}; aguardando abertura" style="display:inline-block;background:#FFF3E0;color:#E65100;border:1px solid #FFCC80;border-radius:10px;padding:0 6px;font-size:10px;margin-right:4px"><i class="fa-solid fa-paper-plane"></i> Enviado</span>`;
              enviarTitle = `Enviado em ${new Date(env.geradoEm).toLocaleString('pt-BR')} — aguardando abertura`;
              enviarColor = '#E65100';
            }
          }
          return `${badge}
            <button class="btn-icon" onclick="imprimirReciboOficial('${e.id}')" title="Recibo Oficial CLT (Portaria 671)" ${p?'':'disabled style="opacity:.4;cursor:not-allowed"'}><i class="fa-solid fa-file-invoice-dollar" style="color:#1B5E20"></i></button>
            <button class="btn-icon" onclick="enviarReciboOficial('${e.id}')" title="${enviarTitle}" ${p?'':'disabled style="opacity:.4;cursor:not-allowed"'}><i class="fa-solid fa-paper-plane" style="color:${enviarColor}"></i></button>
            <button class="btn-icon" onclick="event.stopPropagation();openPayrollForEmployee('${e.id}')" title="Abrir folha de ponto"><i class="fa-solid fa-arrow-up-right-from-square"></i></button>
            ${p && p.status==='aberta' ? `<button class="btn-icon" onclick="event.stopPropagation();fecharFolhaPorId('${p.id}')" title="Fechar folha"><i class="fa-solid fa-lock" style="color:#5C6BC0"></i></button>` : ''}
            ${p && p.status==='fechada' ? `<button class="btn-icon" onclick="event.stopPropagation();reabrirFolhaPorId('${p.id}')" title="Reabrir folha"><i class="fa-solid fa-lock-open" style="color:#EF6C00"></i></button>` : ''}`;
        })()}
      </td>
    </tr>`;
  }).join('');
  tbody.innerHTML=rows;

  // Rodapé com totais
  tfoot.innerHTML=`<tr style="background:#EEF4FF;font-weight:700;font-size:12px">
    <td colspan="6" style="padding:8px 10px">TOTAIS — ${comFolha} de ${emps.length} com holerite</td>
    <td>${fmtMoney(tBruto)}</td>
    <td style="color:#c0392b">(${fmtMoney(tINSS)})</td>
    <td style="color:#c0392b">(${fmtMoney(tIRRF)})</td>
    <td style="color:#c0392b">${tAdiant>0?'('+fmtMoney(tAdiant)+')':'—'}</td>
    <td style="color:#1565C0">${fmtMoney(tFGTS)}</td>
    <td style="color:var(--success)">${fmtMoney(tLiquido)}</td>
    <td colspan="2"></td>
  </tr>`;

  if(card) card.style.display='';
}

// ============================================================================
// REVISÃO PELA TELA PAGAMENTOS — clicar na linha abre a folha pra revisar/editar;
// o botão Voltar global retorna pra esta lista na MESMA competência (rolando até
// a linha). Fechar/reabrir e marcar "Revisada" direto daqui. #pagamentos-revisao
// ============================================================================
// Clique na linha — ignora cliques em controles (checkbox, botões, labels).
function _pagRowClick(ev, empId){
  if(ev && ev.target && ev.target.closest('button,input,a,label')) return;
  _pagAbrirRevisao(empId);
}

// Abre a folha do colaborador pra revisão, NA MESMA competência exibida em
// Pagamentos, e guarda o contexto pra o Voltar global retornar exatamente aqui.
function _pagAbrirRevisao(empId){
  const mes=parseInt(val('pag-mes')||currentMes());
  const ano=parseInt(val('pag-ano')||currentAno());
  State._pagReturn={ mes, ano, empId };
  showSection('payroll'); // empilha 'pagamentos' no histórico → botão Voltar retorna aqui
  // Se o período não é o vigente, destrava a navegação (coerência visual do painel).
  const vig=competenciaVigente();
  const chk=document.getElementById('chk-consultar-passadas');
  if(chk && (mes!==vig.mes||ano!==vig.ano) && !chk.checked){ chk.checked=true; _togglePeriodoNavegacao(true); }
  setVal('payroll-mes', String(mes));
  setVal('payroll-ano', String(ano));
  try{ _ensurePayrollEmployeeOption(empId); }catch(e){ console.warn('_pagAbrirRevisao', e); }
  setVal('payroll-employee', empId);
  onPayrollPeriodoChange(); // atualiza painel de fechamento + recarrega a folha
}

// Rola até a linha do colaborador na lista de Pagamentos e dá um flash amarelo.
function _pagScrollToEmp(empId){
  const cb=document.querySelector(`#pag-tbody .pag-row-check[data-emp-id="${empId}"]`);
  const tr=cb?cb.closest('tr'):null;
  if(!tr) return;
  tr.scrollIntoView({behavior:'smooth', block:'center'});
  const old=tr.style.background;
  tr.style.transition='background-color .5s';
  tr.style.background='#FFF59D';
  setTimeout(()=>{ tr.style.background=old; }, 1300);
}

// Marca/desmarca a folha como REVISADA (salva quem revisou + quando). Revisada é
// pré-requisito pra enviar a folha/holerite pra conferência no app. #revisada-gate
async function _pagToggleRevisada(payrollId, checked){
  const p=State.payrolls.find(r=>r.id===payrollId);
  if(!p){ toast('Folha não encontrada.','error'); return; }
  const u=Auth.currentUser||{};
  const upd = checked
    ? { revisada:true, revisadoPor:(u.username||u.id||''), revisadoEm:new Date().toISOString() }
    : { revisada:false, revisadoPor:null, revisadoEm:null };
  try{
    await DB.merge('payrolls', p.id, upd);
    const s=State.payrolls.find(r=>r.id===p.id); if(s) Object.assign(s, upd);
    Auth.log('PAYROLL_REVISADA', null, `${p.employeeId} — ${MESES[p.mes]}/${p.ano} — ${checked?'revisada':'desmarcada'}`);
    if(State.currentSection==='pagamentos') renderPagamentos();
  }catch(e){ console.error(e); toast('Erro ao salvar a revisão.','error'); }
}

function exportPagamentosCsv(){
  const mes=parseInt(val('pag-mes')||currentMes());
  const ano=parseInt(val('pag-ano')||currentAno());
  const statusFilt=val('pag-status-filter')||'ativo';
  const mesLabel=MESES[mes]||'';
  let emps=_filtrarEmpsPorEscopo(State.employees).slice();
  if(statusFilt!=='all') emps=emps.filter(e=>(e.status||'ativo')===statusFilt);
  emps.sort((a,b)=>a.nome.localeCompare(b.nome));
  const folhaMap=_buildFolhaMap(State.payrolls.filter(p=>p.mes===mes&&p.ano===ano));
  const header=['#','Registro','Nome','Cargo','Salario Base','Total Bruto','INSS','IRRF','FGTS','Liquido Final','Status'];
  const rows=emps.map((e,i)=>{
    const p=folhaMap[e.id];
    const fmt=v=>v?(v.toFixed(2).replace('.',',')):'-';
    return [i+1, e.registro||'', e.nome, e.cargo||e.setor||'', fmt(e.salarioBase),
      fmt(p?.totalBruto), fmt(p?.inss), fmt(p?.irrf), fmt(p?.fgts),
      fmt(p?.totalLiquidoFinal||p?.remuneracao), p?p.status:'sem folha'].join(';');
  });
  const csv='﻿'+[header.join(';'),...rows].join('\n');
  const a=document.createElement('a');
  a.href='data:text/csv;charset=utf-8,'+encodeURIComponent(csv);
  a.download=`pagamentos_${mes.toString().padStart(2,'0')}_${ano}.csv`;
  a.click();
}

function printPagamentos(){
  const mes=parseInt(val('pag-mes')||currentMes());
  const ano=parseInt(val('pag-ano')||currentAno());
  const mesLabel=MESES[mes]||'';
  const table=document.getElementById('pag-table');
  if(!table){ toast('Carregue os dados primeiro.','warning'); return; }
  // Clona a tabela e tira a coluna de checkbox da impressão (1ª coluna).
  const clone = table.cloneNode(true);
  clone.querySelectorAll('tr').forEach(tr=>{
    const first = tr.firstElementChild;
    if(first && first.querySelector('input[type="checkbox"]')) first.remove();
  });
  const w=window.open('','_blank');
  w.document.write(`<!DOCTYPE html><html lang="pt-BR"><head><meta charset="UTF-8">
    <title>Pagamentos ${mesLabel}/${ano}</title>
    <style>body{font-family:Arial,sans-serif;font-size:10px}
    table{width:100%;border-collapse:collapse}th,td{border:1px solid #ccc;padding:4px 6px}
    th{background:#1a3a6b;color:#fff}tr:nth-child(even){background:#f5f5f5}
    h2{color:#1a3a6b}</style></head><body>
    <h2>${_e('nomeEmpresa')} — Pagamentos ${mesLabel} / ${ano}</h2>
    ${clone.outerHTML}</body></html>`);
  w.document.close();
  w.print();
}

// Filtro de busca (nome ou matrícula) — esconde linhas que não casam.
function filterPagamentos(){
  const q = (val('pag-search')||'').toLowerCase().trim();
  document.querySelectorAll('#pag-tbody tr').forEach(tr=>{
    if(!q){ tr.style.display=''; return; }
    const nome = (tr.dataset.nome||'').toLowerCase();
    const reg  = (tr.dataset.reg||'').toLowerCase();
    tr.style.display = (nome.includes(q) || reg.includes(q)) ? '' : 'none';
  });
  // Desmarca o "selecionar todos" quando a busca muda.
  const all = document.getElementById('pag-check-all');
  if(all) all.checked = false;
  updatePagSelCount();
}

// Marca/desmarca todas as linhas VISÍVEIS (respeita o filtro).
function toggleAllPagamentos(master){
  document.querySelectorAll('#pag-tbody tr').forEach(tr=>{
    if(tr.style.display === 'none') return;
    const cb = tr.querySelector('.pag-row-check');
    if(cb) cb.checked = !!master.checked;
  });
  updatePagSelCount();
}

// Atualiza o contador + estado do botão "Imprimir Selecionados".
function updatePagSelCount(){
  const n = document.querySelectorAll('#pag-tbody .pag-row-check:checked').length;
  const btn = document.getElementById('btn-imprimir-selecionados-pag');
  const badge = document.getElementById('pag-sel-count');
  if(btn) btn.disabled = (n === 0);
  if(badge){
    badge.textContent = n;
    badge.style.display = n > 0 ? '' : 'none';
  }
}

// ============================================
// RECIBO DE PAGAMENTO DE SALÁRIO (CLT / Portaria 671)
// Layout oficial com códigos MTE/SEFIP, bases (INSS/IRRF/FGTS), FGTS depositado,
// linha de assinatura e rodapé com protocolo (placeholder — Fase B2 ativa o envio
// pro app do colaborador e atualiza esse protocolo com data/hora de visualização).
// ============================================

// Rubricas FIXAS (fixaTodos) — aplicadas automaticamente a TODOS os colaboradores
// ativos (ex.: Seguro de Vida 224). Reaproveita o catálogo de Rubricas (seção própria).
// Exceção por colaborador via emp.rubricasOptOut (lista de id/código a pular) — espaço
// pra parametrização futura. Retorna [{codigo,descricao,tipo:'P'|'D',valor,incideINSS,incideFGTS,incideIRRF}]. #rubricas-fixas
function _rubricasFixasColab(emp){
  if(!emp) return [];
  const optOut  = emp.rubricasOptOut || [];
  const salBase = parseFloat(emp.salarioBase||0) || 0;
  return (State.rubricas||[])
    .filter(r=>r.fixaTodos && r.ativa!==false && !optOut.includes(r.id) && !optOut.includes(r.codigo))
    .map(r=>{
      let valor = parseFloat(r.valorPadrao||0) || 0;
      if(r.calculo==='percentual') valor = +(salBase*valor/100).toFixed(2);  // 'quantidade' não faz sentido p/ todos → trata como fixo
      return { codigo:r.codigo||'', descricao:r.descricao||'Rubrica', tipo:(r.tipo==='P'?'P':'D'),
               valor:valor, incideINSS:!!r.incideINSS, incideFGTS:!!r.incideFGTS, incideIRRF:!!r.incideIRRF };
    })
    .filter(f=>f.valor>0);
}
// Soma as fixas por categoria: provento tributável (entra na base INSS/IRRF/FGTS),
// provento não-tributável (só no líquido) e desconto.
function _rubricasFixasTotais(fixas){
  let provTrib=0, provNtrib=0, desc=0;
  (fixas||[]).forEach(f=>{ if(f.tipo==='P'){ if(f.incideINSS) provTrib+=f.valor; else provNtrib+=f.valor; } else desc+=f.valor; });
  return { provTrib, provNtrib, desc };
}

// Monta as linhas de proventos/descontos a partir do payroll record.
// Retorna { linhas:[{cod,nome,ref,pr,de}], totalPr, totalDe, liquido, baseINSS, baseFGTS, baseIRRF, fgtsDepositado }.
function _reciboOficialLinhas(emp, p){
  const salBase     = parseFloat(emp.salarioBase||0);
  const remuneracao = +p.remuneracao||0;
  const an          = +p.adNoturno||0;
  const heVal       = +p.horasExtrasValor||0;
  const heHoras     = +p.horasExtrasTotal||0;
  const hePerc      = parseInt(p.horasExtrasPerc||50);
  const heCorrido   = +p.heCorridoValor||0;          // HE "hora corrida" — campo separado do motor (9613)
  const heCorridoMin= +p.heCorridoMin||0;
  const ins         = +p.insalubridade||0;
  const acu         = +p.acumuloFuncao||0;
  const outProv     = +p.outrosProventosTotal||0;    // prêmios / ajudas lançados no cadastro (9617)
  const inss        = +p.inss||0;
  const irrf        = +p.irrf||0;
  const fgts        = +p.fgts||0;
  const adiant      = +(p.adiantamentoValor||p.adiantamento||0);
  const vt          = +p.valeTransporte||0;
  const descAtraso  = +p.descontoAtraso||0;          // desconto de atraso (9595) — o motor o subtrai no líquido
  const descSaida   = +p.descontoSaida||0;           // desconto de saída no expediente (9626)
  const plano       = +p.planoSaudeDesc||0;          // plano de saúde (9622)
  const pensao      = +p.pensaoAlimenticiaDesc||0;   // pensão alimentícia (9623)
  const outDesc     = +p.outrosDescontosTotal||0;    // outros descontos lançados (9618)
  const emprest     = +p.emprestimo||0;              // empréstimo/consignado (0218) — desconto pós-tributação. #planilha-contador
  const faltasNum   = +(p.faltas||0);
  const descFaltas  = Math.max(0, salBase - remuneracao);
  const grauInsal   = parseFloat(emp.insalubridade||0) || 20;
  const linhas = [];

  // Proventos
  linhas.push({cod:'0001', nome:'Salário Mensal', ref:'30,00', pr:salBase, de:0});
  if(heVal>0){
    const code = hePerc>=100 ? '0081' : '0080';
    const nome = hePerc>=100 ? 'Horas Extras 100%' : 'Horas Extras 50%';
    linhas.push({cod:code, nome:nome, ref:heHoras.toFixed(2).replace('.',',')+' h', pr:heVal, de:0});
  }
  if(heCorrido>0) linhas.push({cod:'0082', nome:'Horas Extras (Hora Corrida)', ref:heCorridoMin?heCorridoMin+' min':'—', pr:heCorrido, de:0});
  if((+p.dsrSobreHE||0)>0) linhas.push({cod:'0083', nome:'DSR sobre Horas Extras', ref:'—', pr:+p.dsrSobreHE, de:0});   // Súmula 172. #dsr-he
  if(an>0) linhas.push({cod:'0066', nome:'Adicional Noturno 20%',  ref:'—',                                  pr:an,  de:0});
  if(ins>0) linhas.push({cod:'0099', nome:'Adicional Insalubridade '+grauInsal+'%', ref:grauInsal+'%',       pr:ins, de:0});
  if(acu>0) linhas.push({cod:'0103', nome:'Acúmulo de Função',     ref:'—',                                  pr:acu, de:0});
  if(outProv>0) linhas.push({cod:'0150', nome:'Outros Proventos',  ref:'—',                                  pr:outProv, de:0});
  // Refeição não rendida (intervalo intrajornada suprimido, hora cheia + 50%) — INDENIZATÓRIA (CLT 71 §4),
  // não-tributável: soma em totalPr/líquido mas NÃO entra na base INSS/IRRF/FGTS. #ref-nao-rendida
  const _refNR = p.refNaoRendidaValor||0;
  if(_refNR>0) linhas.push({cod:'0085', nome:'Refeição não rendida (hora + 50%)', ref:(p.refNaoRendidaMin?minutesToStr(p.refNaoRendidaMin):'—'), pr:_refNR, de:0});

  // Descontos
  if(descFaltas>0){
    // faltasNum>0 → faltas reais; faltasNum==0 com desconto → salário proporcional (admissão/desligamento no meio do mês)
    if(faltasNum>0) linhas.push({cod:'0950', nome:'Faltas',                  ref:faltasNum.toFixed(2).replace('.',',')+' d', pr:0, de:descFaltas});
    else            linhas.push({cod:'0951', nome:'Salário Proporcional (dias não trabalhados)', ref:'—',  pr:0, de:descFaltas});
  }
  if(descAtraso>0) linhas.push({cod:'0952', nome:'Atrasos',                  ref:'—',                                              pr:0, de:descAtraso});
  if(descSaida>0)  linhas.push({cod:'0953', nome:'Saídas no Expediente',     ref:'—',                                              pr:0, de:descSaida});
  if(adiant>0)     linhas.push({cod:'0905', nome:'Adiantamento Salarial',    ref:'40%',                                            pr:0, de:adiant});
  if(inss>0)       linhas.push({cod:'0900', nome:'INSS',                     ref:'—',                                              pr:0, de:inss});
  if(irrf>0)       linhas.push({cod:'0901', nome:'IRRF',                     ref:'—',                                              pr:0, de:irrf});
  if(plano>0)      linhas.push({cod:'0920', nome:'Plano de Saúde',           ref:'—',                                              pr:0, de:plano});
  if(pensao>0)     linhas.push({cod:'0930', nome:'Pensão Alimentícia',       ref:'—',                                              pr:0, de:pensao});
  if(outDesc>0)    linhas.push({cod:'0960', nome:'Outros Descontos',         ref:'—',                                              pr:0, de:outDesc});
  if(emprest>0)    linhas.push({cod:'0961', nome:'Empréstimo / Consignado',  ref:'—',                                              pr:0, de:emprest});
  if(vt>0){
    // Co-participação CLT (Lei 7.418/85): desconta o MENOR entre 6% do salário-base
    // e o custo do VT. Antes descontava o VT cheio (passava do teto e anulava o
    // benefício, que é pago à parte no cartão). #vt-coparticipacao
    const vtCoPart = Math.min(+(salBase*(_paramLegal('vtCoPartPerc')/100)).toFixed(2), vt);
    if(vtCoPart>0) linhas.push({cod:'0910', nome:'Vale Transporte (co-part. 6%)', ref:'até 6%', pr:0, de:vtCoPart});
  }

  // Rubricas fixas p/ todos (Seguro de Vida etc.) — usa SÓ o snapshot salvo na folha.
  // Folhas antigas (sem snapshot) ficam intactas e batem com o totalLiquidoFinal salvo;
  // o seguro passa a aparecer/descontar nas folhas recalculadas pós-implantação. Cada uma vira sua linha. #rubricas-fixas
  const _fixas = Array.isArray(p.rubricasFixas) ? p.rubricasFixas : [];
  _fixas.forEach(f=>{
    if(f.tipo==='P') linhas.push({cod:f.codigo||'0150', nome:f.descricao||'Outros Proventos', ref:'fixa', pr:f.valor||0, de:0});
    else             linhas.push({cod:f.codigo||'0960', nome:f.descricao||'Outros Descontos', ref:'fixa', pr:0, de:f.valor||0});
  });

  const totalPr   = linhas.reduce((s,l)=>s+(l.pr||0), 0);
  const totalDe   = linhas.reduce((s,l)=>s+(l.de||0), 0);
  const liquido   = totalPr - totalDe;
  // Proventos fixos NÃO-tributáveis (ex.: reembolso) não entram na base INSS, mesmo somando em totalPr.
  const _fixProvNtrib = _fixas.filter(f=>f.tipo==='P' && !f.incideINSS).reduce((s,f)=>s+(f.valor||0),0);
  const baseINSS  = Math.max(0, totalPr - descFaltas - _fixProvNtrib - _refNR);  // proventos tributáveis (faltas/proporcional já descontados; ref. não rendida é indenizatória → fora da base)
  const baseFGTS  = baseINSS;
  // Base IRRF espelha calcIRRF: bruto - INSS - (dependentes × dedução) - pensão - plano de saúde (Lei 9.250/95). #fix-plano-irrf
  const dedDep    = (parseInt(emp.dependentesIRRF||0)||0) * (_pl().irrfDedDependente||0);
  const baseIRRF  = Math.max(0, baseINSS - inss - dedDep - pensao - plano);
  return { linhas, totalPr, totalDe, liquido, baseINSS, baseFGTS, baseIRRF, fgtsDepositado: fgts };
}

// Gera o hash do protocolo (não-críptográfico, só pra identificação visual).
function _reciboGerarProtocolo(empId, mes, ano, liquido){
  const seed = String(empId)+'|'+mes+'|'+ano+'|'+(liquido||0).toFixed(2)+'|'+new Date().toISOString();
  let h = 0, i = 0, len = seed.length;
  while(i<len){ h = ((h<<5)-h) + seed.charCodeAt(i++); h |= 0; }
  return ('00000000' + (h>>>0).toString(16)).slice(-8) + ('00000000' + (Math.floor(Math.random()*0xffffffff)).toString(16)).slice(-8);
}

// HTML de UM recibo individual.
// opts.protocolo  — usa um protocolo já existente (recibo enviado/persistido).
// opts.visualizadoEm — exibe carimbo de visualização no rodapé.
function _reciboOficialUmHTML(emp, p, mes, ano, opts){
  opts = opts || {};
  const r = _reciboOficialLinhas(emp, p);
  const mesLabel = MESES[mes]||'';
  const competencia = `${MESES[mes]||''} / ${ano}`;
  const protocolo = opts.protocolo || _reciboGerarProtocolo(emp.id, mes, ano, r.liquido);
  const visualizadoStr = opts.visualizadoEm
    ? new Date(opts.visualizadoEm).toLocaleString('pt-BR')
    : '<em>aguardando envio</em>';
  const _esc = s => String(s||'').replace(/[&<>"]/g, c=>({ '&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;' })[c]);
  const _mn  = v => (v>0 ? fmtMoney(v) : '');
  const empNome = _e('nomeEmpresa') || _e('razaoSocial') || '';
  const empCnpj = _e('cnpj') || '—';
  const empEnd  = _empresaEnderecoLinha() || '';
  const empCnae = _e('cnae') || '';
  const empLogo = _logoSrc();  // URL absoluta (custom logoUrl ou logo.png do sistema) — resolve em popups
  const ctpsTxt = [emp.ctpsNumero, emp.ctpsSerie, emp.ctpsUf].filter(Boolean).join(' / ') || '—';
  const rgTxt   = (emp.rg||'—') + (emp.rgOrgao?' '+emp.rgOrgao:'');
  const endCol  = [emp.endereco, emp.numero?'nº '+emp.numero:'', emp.complemento, emp.bairro,
                   [emp.cidade, emp.estado].filter(Boolean).join('/'), emp.cep?'CEP '+emp.cep:''].filter(Boolean).join(' — ') || '—';

  const linhasHtml = r.linhas.map(l=>`
    <tr>
      <td style="padding:3px 6px;text-align:center;font-family:monospace">${l.cod}</td>
      <td style="padding:3px 6px">${_esc(l.nome)}</td>
      <td style="padding:3px 6px;text-align:center">${_esc(l.ref)}</td>
      <td style="padding:3px 6px;text-align:right">${_mn(l.pr)}</td>
      <td style="padding:3px 6px;text-align:right">${_mn(l.de)}</td>
    </tr>`).join('');

  // Linhas vazias para “completar” a tabela (visual de impresso oficial)
  const minRows = 14;
  const fillRows = Math.max(0, minRows - r.linhas.length);
  let preenchimento = '';
  for(let i=0;i<fillRows;i++) preenchimento += `<tr><td style="padding:3px 6px">&nbsp;</td><td></td><td></td><td></td><td></td></tr>`;

  return `
  <div class="recibo">
    <table class="cabecalho" style="width:100%;border:1px solid #000;border-collapse:collapse">
      <tr>
        <td style="width:90px;border-right:1px solid #000;text-align:center;padding:6px">
          ${empLogo?`<div style="background:#fff;padding:3px;display:inline-block"><img src="${_esc(empLogo)}" style="max-height:60px;max-width:80px"></div>`:'<div style="font-size:9px;color:#666">LOGO</div>'}
        </td>
        <td style="padding:6px 10px">
          <div style="font-weight:700;font-size:13px">${_esc(empNome)}</div>
          <div style="font-size:10px;line-height:1.3">CNPJ: ${_esc(empCnpj)}${empCnae?' &nbsp;·&nbsp; CNAE: '+_esc(empCnae):''}</div>
          ${empEnd?`<div style="font-size:9px;color:#444;line-height:1.3">${_esc(empEnd)}</div>`:''}
        </td>
        <td style="width:230px;text-align:right;padding:6px 10px;border-left:1px solid #000">
          <div style="font-weight:700;font-size:12px">RECIBO DE PAGAMENTO DE SALÁRIO</div>
          <div style="font-size:10px">Competência: <strong>${_esc(competencia)}</strong></div>
        </td>
      </tr>
    </table>

    <table class="dados-col" style="width:100%;border:1px solid #000;border-top:none;border-collapse:collapse;font-size:10px">
      <tr>
        <td style="padding:3px 6px;width:55%"><strong>Colaborador:</strong> ${_esc(emp.nome)}</td>
        <td style="padding:3px 6px"><strong>Matrícula:</strong> ${emp.registro?String(emp.registro).padStart(4,'0'):'—'}</td>
      </tr>
      <tr>
        <td style="padding:3px 6px"><strong>CPF:</strong> ${_esc(emp.cpf||'—')} &nbsp;·&nbsp; <strong>RG:</strong> ${_esc(rgTxt)}</td>
        <td style="padding:3px 6px"><strong>PIS/PASEP:</strong> ${_esc(emp.pisNit||'—')}</td>
      </tr>
      <tr>
        <td style="padding:3px 6px"><strong>CTPS:</strong> ${_esc(ctpsTxt)}</td>
        <td style="padding:3px 6px"><strong>Admissão:</strong> ${emp.dataAdmissao?formatDateBr(emp.dataAdmissao):'—'}</td>
      </tr>
      <tr>
        <td style="padding:3px 6px"><strong>Cargo:</strong> ${_esc(emp.cargo||'—')}${emp.cargoCBO?' &nbsp;·&nbsp; <strong>CBO:</strong> '+_esc(emp.cargoCBO):''}</td>
        <td style="padding:3px 6px"><strong>Salário-base:</strong> ${fmtMoney(emp.salarioBase||0)}</td>
      </tr>
      <tr>
        <td style="padding:3px 6px" colspan="2"><strong>Endereço:</strong> ${_esc(endCol)}</td>
      </tr>
    </table>

    <table class="lancamentos" style="width:100%;border:1px solid #000;border-top:none;border-collapse:collapse;font-size:10px">
      <thead>
        <tr style="background:#e8e8e8">
          <th style="padding:4px 6px;border-bottom:1px solid #000;width:50px">Cód.</th>
          <th style="padding:4px 6px;border-bottom:1px solid #000;text-align:left">Descrição</th>
          <th style="padding:4px 6px;border-bottom:1px solid #000;width:90px">Referência</th>
          <th style="padding:4px 6px;border-bottom:1px solid #000;width:100px;text-align:right">Vencimentos</th>
          <th style="padding:4px 6px;border-bottom:1px solid #000;width:100px;text-align:right">Descontos</th>
        </tr>
      </thead>
      <tbody>
        ${linhasHtml}
        ${preenchimento}
      </tbody>
      <tfoot>
        <tr style="background:#f3f3f3;font-weight:700">
          <td colspan="3" style="padding:5px 6px;border-top:1px solid #000;text-align:right">TOTAIS</td>
          <td style="padding:5px 6px;border-top:1px solid #000;text-align:right">${fmtMoney(r.totalPr)}</td>
          <td style="padding:5px 6px;border-top:1px solid #000;text-align:right">${fmtMoney(r.totalDe)}</td>
        </tr>
        <tr style="background:#f9f9f9;font-weight:700">
          <td colspan="4" style="padding:5px 6px;text-align:right">LÍQUIDO A RECEBER</td>
          <td style="padding:5px 6px;text-align:right;font-size:12px">${fmtMoney(r.liquido)}</td>
        </tr>
      </tfoot>
    </table>

    <table class="bases" style="width:100%;border:1px solid #000;border-top:none;border-collapse:collapse;font-size:9px">
      <tr>
        <td style="padding:4px 6px;width:25%"><strong>Salário-base:</strong> ${fmtMoney(emp.salarioBase||0)}</td>
        <td style="padding:4px 6px;width:25%"><strong>Base INSS:</strong> ${fmtMoney(r.baseINSS)}</td>
        <td style="padding:4px 6px;width:25%"><strong>Base FGTS:</strong> ${fmtMoney(r.baseFGTS)}</td>
        <td style="padding:4px 6px;width:25%"><strong>FGTS depositado:</strong> ${fmtMoney(r.fgtsDepositado)}</td>
      </tr>
      <tr>
        <td colspan="2" style="padding:4px 6px"><strong>Base IRRF:</strong> ${fmtMoney(r.baseIRRF)}</td>
        <td colspan="2" style="padding:4px 6px"><strong>Banco / PIX:</strong> ${_esc(emp.chavePix||'—')}</td>
      </tr>
    </table>

    <table class="assinatura" style="width:100%;border:1px solid #000;border-top:none;border-collapse:collapse;font-size:10px">
      <tr>
        <td style="padding:14px 10px;width:65%">
          <div style="margin-bottom:30px">Declaro ter recebido a importância líquida acima discriminada, referente ao período mencionado.</div>
          <div style="border-top:1px solid #000;padding-top:3px;font-size:9px">Assinatura do empregado &nbsp;·&nbsp; Data: ____/____/______</div>
        </td>
        <td style="padding:14px 10px;border-left:1px solid #000;font-size:9px;line-height:1.5">
          <div style="margin-bottom:6px"><strong>Documento eletrônico</strong></div>
          <div>Protocolo: <span style="font-family:monospace">${protocolo}</span></div>
          <div>Gerado em: ${new Date().toLocaleString('pt-BR')}</div>
          <div>Visualização: ${visualizadoStr}</div>
        </td>
      </tr>
    </table>
  </div>`;
}

// Empacota 1+ recibos numa página A4 pronta pra impressão (page-break entre).
function _reciboOficialPaginaHTML(itens, mes, ano){
  const blocos = itens.map((it,i)=>{
    const sep = i>0 ? '<div style="page-break-before:always"></div>' : '';
    return sep + _reciboOficialUmHTML(it.emp, it.p, mes, ano);
  }).join('\n');
  const mesLabel = MESES[mes]||'';
  return `<!DOCTYPE html><html lang="pt-BR"><head><meta charset="UTF-8">
    <title>Recibo de Pagamento — ${mesLabel}/${ano}</title>
    <style>
      @page { size:A4; margin:14mm 12mm }
      body { font-family: 'Times New Roman', Tinos, serif; font-size:10px; color:#000; margin:0 }
      table { border-collapse:collapse }
      .recibo { margin:0 auto }
      @media print { body { -webkit-print-color-adjust:exact; print-color-adjust:exact } }
    </style></head><body>
    ${blocos}
    </body></html>`;
}

// Imprime UM recibo (botão "Recibo" da linha da tabela de Pagamentos).
function imprimirReciboOficial(empId){
  const mes=parseInt(val('pag-mes')||currentMes());
  const ano=parseInt(val('pag-ano')||currentAno());
  const emp = State.employees.find(e=>e.id===empId);
  const p   = State.payrolls.find(x=>x.employeeId===empId && x.mes===mes && x.ano===ano);
  if(!emp){ toast('Colaborador não encontrado.','error'); return; }
  if(!p){ toast('Folha desse colaborador não foi calculada para o período.','warning'); return; }
  const html = _reciboOficialPaginaHTML([{emp,p}], mes, ano);
  const w = window.open('','_blank');
  w.document.write(html); w.document.close(); w.print();
  Auth.log && Auth.log('RECIBO_OFICIAL_GERADO', null, `${emp.nome} | ${String(mes).padStart(2,'0')}/${ano}`);
}

// Imprime os recibos oficiais de TODOS os colaboradores marcados.
// Substitui o antigo "Imprimir Selecionados" (que só clonava a tabela).
function printPagamentosSelecionados(){
  const sel = Array.from(document.querySelectorAll('#pag-tbody .pag-row-check:checked'))
                    .map(cb => cb.dataset.empId);
  if(!sel.length){ toast('Selecione pelo menos um colaborador.','warning'); return; }
  const mes=parseInt(val('pag-mes')||currentMes());
  const ano=parseInt(val('pag-ano')||currentAno());
  const itens=[]; let semFolha=0;
  for(const empId of sel){
    const emp = State.employees.find(e=>e.id===empId);
    const p   = State.payrolls.find(x=>x.employeeId===empId && x.mes===mes && x.ano===ano);
    if(emp && p) itens.push({emp,p}); else if(emp) semFolha++;
  }
  if(!itens.length){ toast('Nenhum dos selecionados tem folha calculada para o período.','warning'); return; }
  const html = _reciboOficialPaginaHTML(itens, mes, ano);
  const w = window.open('','_blank');
  w.document.write(html); w.document.close(); w.print();
  Auth.log && Auth.log('RECIBO_OFICIAL_GERADO_LOTE', null, `${itens.length} recibo(s) | ${String(mes).padStart(2,'0')}/${ano}${semFolha?` (${semFolha} sem folha)`:''}`);
}

// ============================================================================
// FASE 1 — VISUALIZAR RELATÓRIO DE HOLERITES (revisar antes de enviar)
// Abre um preview (recibos empilhados OU planilha consolidada) com a barra de
// ações no rodapé (Imprimir/PDF · Excel · Fechar) via _abrirJanelaExport.
// Respeita a seleção: se houver linhas marcadas na tabela de Pagamentos, mostra
// só as selecionadas; senão, todas as folhas calculadas do período.
// ============================================================================

// Coleta { mes, ano, itens:[{emp,p}], semFolha, useSel } do período exibido.
function _relatHoleritesColeta(){
  const mes=parseInt(val('pag-mes')||currentMes());
  const ano=parseInt(val('pag-ano')||currentAno());
  const statusFilt=val('pag-status-filter')||'ativo';
  const selIds=Array.from(document.querySelectorAll('#pag-tbody .pag-row-check:checked')).map(cb=>cb.dataset.empId);
  const useSel=selIds.length>0;
  const selSet=new Set(selIds);
  let emps=_filtrarEmpsPorEscopo(State.employees).slice();
  if(statusFilt!=='all') emps=emps.filter(e=>(e.status||'ativo')===statusFilt);
  if(useSel) emps=emps.filter(e=>selSet.has(e.id));
  emps.sort((a,b)=>a.nome.localeCompare(b.nome));
  const folhaMap=_buildFolhaMap(State.payrolls.filter(p=>p.mes===mes&&p.ano===ano));
  const itens=[]; let semFolha=0;
  emps.forEach(e=>{ const p=folhaMap[e.id]; if(p) itens.push({emp:e,p}); else semFolha++; });
  return { mes, ano, itens, semFolha, useSel };
}

// Relatório de RECIBOS (holerites individuais empilhados) — preview p/ revisão.
function verRelatorioHolerites(){
  const { mes, ano, itens, semFolha, useSel } = _relatHoleritesColeta();
  if(!itens.length){ toast(useSel?'Nenhum dos selecionados tem folha calculada no período.':'Nenhuma folha calculada no período.','warning'); return; }
  const html = _reciboOficialPaginaHTML(itens, mes, ano);
  _abrirJanelaExport(html, 'pdf', `Recibos_${MESES[mes]}_${ano}${useSel?'_selecionados':''}`);
  if(semFolha) toast(`${itens.length} recibo(s) no relatório · ${semFolha} sem folha (omitido).`,'info');
}

// Relatório de PLANILHA consolidada (1 linha por colaborador) — preview p/ revisão.
function verRelatorioPlanilhaHolerites(){
  const { mes, ano, itens, semFolha, useSel } = _relatHoleritesColeta();
  if(!itens.length){ toast(useSel?'Nenhum dos selecionados tem folha calculada no período.':'Nenhuma folha calculada no período.','warning'); return; }
  const html = _planilhaHoleritesHTML(itens, mes, ano, useSel);
  _abrirJanelaExport(html, 'pdf', `Planilha_Holerites_${MESES[mes]}_${ano}${useSel?'_selecionados':''}`);
  if(semFolha) toast(`${itens.length} colaborador(es) na planilha · ${semFolha} sem folha (omitido).`,'info');
}

// Monta o HTML da planilha consolidada (bruto/INSS/IRRF/Adiant./FGTS/líquido).
function _planilhaHoleritesHTML(itens, mes, ano, useSel){
  const _esc = s => String(s||'').replace(/[&<>"]/g, c=>({ '&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;' })[c]);
  let tBruto=0,tINSS=0,tIRRF=0,tFGTS=0,tAdiant=0,tLiq=0;
  const rows = itens.map((it,i)=>{
    const e=it.emp, p=it.p;
    const bruto=p.totalBruto||0, inss=p.inss||0, irrf=p.irrf||0, fgts=p.fgts||0;
    const adiant=p.adiantamentoValor||p.adiantamento||0;
    const liq=p.totalLiquidoFinal||p.remuneracao||0;
    tBruto+=bruto; tINSS+=inss; tIRRF+=irrf; tFGTS+=fgts; tAdiant+=adiant; tLiq+=liq;
    const stat=p.status==='fechada'?'Fechada':(p.status==='aberta'?'Aberta':'—');
    return `<tr>
      <td>${i+1}</td>
      <td>${e.registro?String(e.registro).padStart(4,'0'):'—'}</td>
      <td style="text-align:left">${_esc(e.nome)}</td>
      <td style="text-align:left">${_esc(e.cargo||e.setor||'—')}</td>
      <td class="r">${fmtMoney(e.salarioBase||0)}</td>
      <td class="r">${fmtMoney(bruto)}</td>
      <td class="r" style="color:#c0392b">${inss?'('+fmtMoney(inss)+')':'—'}</td>
      <td class="r" style="color:#c0392b">${irrf?'('+fmtMoney(irrf)+')':'—'}</td>
      <td class="r" style="color:#c0392b">${adiant?'('+fmtMoney(adiant)+')':'—'}</td>
      <td class="r" style="color:#1565C0">${fgts?fmtMoney(fgts):'—'}</td>
      <td class="r" style="font-weight:700;color:#1B5E20">${fmtMoney(liq)}</td>
      <td>${stat}</td>
    </tr>`;
  }).join('');
  const empNome = _e('nomeEmpresa') || _e('razaoSocial') || '';
  return `<!DOCTYPE html><html lang="pt-BR"><head><meta charset="UTF-8">
    <title>Planilha de Holerites — ${MESES[mes]}/${ano}</title>
    <style>
      @page { size:A4 landscape; margin:10mm }
      body { font-family:Arial,sans-serif; font-size:11px; color:#000; margin:0; padding:14px }
      h2 { color:#1a3a6b; margin:0 0 4px }
      .sub { color:#555; font-size:12px; margin-bottom:12px }
      table { width:100%; border-collapse:collapse }
      th,td { border:1px solid #ccc; padding:4px 6px; text-align:center }
      th { background:#1a3a6b; color:#fff }
      td.r { text-align:right }
      tr:nth-child(even) td { background:#f5f7fb }
      tfoot td { font-weight:700; background:#EEF4FF }
      @media print { body{ -webkit-print-color-adjust:exact; print-color-adjust:exact } }
    </style></head><body>
    <h2>${_esc(empNome)} — Planilha de Holerites</h2>
    <div class="sub">Competência ${MESES[mes]} / ${ano}${useSel?' · (somente selecionados)':''} · ${itens.length} colaborador(es) · Gerado em ${new Date().toLocaleString('pt-BR')}</div>
    <table>
      <thead><tr>
        <th>#</th><th>Matr.</th><th>Colaborador</th><th>Cargo/Setor</th>
        <th>Sal.Base</th><th>Bruto</th><th>INSS</th><th>IRRF</th><th>Adiant.</th><th>FGTS</th><th>Líquido</th><th>Status</th>
      </tr></thead>
      <tbody>${rows}</tbody>
      <tfoot><tr>
        <td colspan="5" style="text-align:right">TOTAIS</td>
        <td class="r">${fmtMoney(tBruto)}</td>
        <td class="r" style="color:#c0392b">(${fmtMoney(tINSS)})</td>
        <td class="r" style="color:#c0392b">(${fmtMoney(tIRRF)})</td>
        <td class="r" style="color:#c0392b">${tAdiant>0?'('+fmtMoney(tAdiant)+')':'—'}</td>
        <td class="r" style="color:#1565C0">${fmtMoney(tFGTS)}</td>
        <td class="r" style="color:#1B5E20">${fmtMoney(tLiq)}</td>
        <td></td>
      </tr></tfoot>
    </table>
    </body></html>`;
}

// ============================================
// B2 — ENVIO DO RECIBO PRO APP DO COLABORADOR
// Como o app de login do colaborador ainda não existe, o "envio" gera um
// link único (#/recibo/TOKEN) que o gestor manda por WhatsApp/e-mail. Quando
// o colaborador abre, o sistema marca `visualizadoEm` (data/hora) e estampa o
// protocolo no recibo — atende à comprovação de entrega da CLT.
// ============================================

// Procura um envio NÃO anulado para esse colaborador/competência.
function _reciboEnvioVigente(empId, mes, ano){
  return (State.holeritesEnviados||[]).find(r =>
    r.employeeId===empId && r.mes===mes && r.ano===ano && !r.anulado);
}

// Gera token URL-safe (32 hex chars) — só "quem tem o link vê" (estilo Drive).
function _reciboGerarToken(){
  if(window.crypto && crypto.getRandomValues){
    const arr = new Uint8Array(16);
    crypto.getRandomValues(arr);
    return Array.from(arr).map(b=>b.toString(16).padStart(2,'0')).join('');
  }
  return (Date.now().toString(36) + Math.random().toString(36).slice(2) + Math.random().toString(36).slice(2)).slice(0,32);
}

// Snapshot dos campos do colaborador usados no recibo. Persistimos junto com
// o registro pra que o link público continue válido mesmo se o cadastro mudar.
function _reciboSnapshotEmp(emp){
  const keys = ['id','nome','registro','cpf','rg','rgOrgao','pisNit','ctpsNumero','ctpsSerie','ctpsUf',
                'dataAdmissao','cargo','cargoCBO','salarioBase','insalubridade',
                'endereco','numero','complemento','bairro','cidade','estado','cep','chavePix'];
  const out = {};
  keys.forEach(k => out[k] = emp[k] || '');
  return out;
}

// Cria (ou recupera) o envio e abre o modal com link copiável + WhatsApp/e-mail.
async function enviarReciboOficial(empId){
  if(!getUserModules(Auth.currentUser).pagamentosLancar){
    toast('Você não tem permissão para enviar recibos.','error'); return;
  }
  const mes = parseInt(val('pag-mes')||currentMes());
  const ano = parseInt(val('pag-ano')||currentAno());
  const emp = State.employees.find(e=>e.id===empId);
  const p   = State.payrolls.find(x=>x.employeeId===empId && x.mes===mes && x.ano===ano);
  if(!emp){ toast('Colaborador não encontrado.','error'); return; }
  if(!p){ toast('Folha desse colaborador não foi calculada para o período.','warning'); return; }

  let reg = _reciboEnvioVigente(empId, mes, ano);
  if(!reg){
    const r = _reciboOficialLinhas(emp, p);
    reg = {
      id: genId(),
      employeeId: empId,
      employeeNome: emp.nome,
      mes, ano,
      protocolo: _reciboGerarProtocolo(empId, mes, ano, r.liquido),
      token:     _reciboGerarToken(),
      geradoEm:  new Date().toISOString(),
      geradoPor: (Auth.currentUser && (Auth.currentUser.username || Auth.currentUser.nome)) || '—',
      enviado:   true,
      visualizadoEm: null,
      anulado:   false,
      liquido:   r.liquido,
      empSnapshot: _reciboSnapshotEmp(emp),
      pSnapshot:   JSON.parse(JSON.stringify(p))
    };
    try {
      await DB.save('holeritesEnviados', reg);
      State.holeritesEnviados = [...(State.holeritesEnviados||[]).filter(x=>x.id!==reg.id), reg];
      Auth.log && Auth.log('RECIBO_ENVIADO', null, `${emp.nome} | ${String(mes).padStart(2,'0')}/${ano} | ${reg.protocolo}`);
    } catch(e){
      console.error(e);
      toast('Erro ao salvar o envio. Tente novamente.','error'); return;
    }
  }
  const link = location.origin + location.pathname + '#/recibo/' + reg.token;
  _abrirModalEnvioRecibo(emp, reg, link);
}

// Manda o MESMO recibo pro app do colaborador assinar (com hash) — reaproveita o
// fluxo do holerite-conferência (_reciboOficialUmHTML). Decisão do usuário 2026-05-31:
// o "Enviar recibo" ganha a opção de app+assinatura, mantendo o link público. #recibo-app-assina
async function _enviarReciboAppAssinar(empId, mes, ano){
  const p = State.payrolls.find(x=>x.employeeId===empId && x.mes==mes && x.ano==ano);
  if(!p){ toast('Folha não encontrada para assinar no app.','error'); return; }
  document.getElementById('modal-envio-recibo')?.remove();
  await enviarHoleriteParaConferencia(p.id);  // valida 'fechada'/permissão e envia c/ hash
}

function _abrirModalEnvioRecibo(emp, reg, link){
  const compLabel = `${MESES[reg.mes]||''}/${reg.ano}`;
  const primeiroNome = (emp.nome||'').split(' ')[0] || emp.nome || '';
  // Mesmo documento do "Enviar Holerite p/ Conferência" → app + assinatura/hash.
  const _pConf = State.payrolls.find(x=>x.employeeId===reg.employeeId && x.mes==reg.mes && x.ano==reg.ano);
  const _confSt = _pConf?.holeriteConferencia?.status || null;
  const _fechada = _pConf?.status==='fechada';
  const _appBox = `
    <div style="background:#F5F3FF;border:1px solid #DDD6FE;border-radius:8px;padding:12px;margin-bottom:14px">
      <div style="font-weight:700;color:#5B21B6;font-size:13px;margin-bottom:5px"><i class="fa-solid fa-mobile-screen-button"></i> Assinar no app do colaborador (hash SHA-256)</div>
      ${_confSt
        ? `<div style="font-size:12px;color:#5B21B6;margin-bottom:8px">Status no app: <strong>${(_statusEnvioLabel(_confSt)||{}).txt||_confSt}</strong>${_pConf.holeriteConferencia.enviadoEm?` · enviado em ${new Date(_pConf.holeriteConferencia.enviadoEm).toLocaleString('pt-BR')}`:''}</div>`
        : `<div style="font-size:12px;color:#7c6aaa;margin-bottom:8px">Manda o recibo pro app do colaborador <strong>conferir e assinar</strong> — igual à folha de ponto, com hash.</div>`}
      ${_fechada
        ? `<button onclick="_enviarReciboAppAssinar('${reg.employeeId}',${reg.mes},${reg.ano})" style="width:100%;background:#6D28D9;color:#fff;border:none;padding:10px;border-radius:6px;cursor:pointer;font-size:13px;font-weight:600"><i class="fa-solid fa-paper-plane"></i> ${_confSt&&_confSt!=='pendente'?'Reenviar pro app p/ assinar':_confSt==='pendente'?'Reenviar pro app':'Enviar pro app p/ assinar'}</button>`
        : `<div style="font-size:12px;color:#E65100;background:#FFF3E0;border-radius:5px;padding:8px 10px"><i class="fa-solid fa-lock"></i> Para assinar no app, <strong>feche a competência</strong> desta folha primeiro.</div>`}
    </div>`;
  const msgWa = `Olá ${primeiroNome}! Seu recibo de pagamento (${compLabel}) está disponível para visualização: ${link}`;
  const waUrl = `https://wa.me/${(emp.celular||'').replace(/\D/g,'')?'55'+emp.celular.replace(/\D/g,''):''}?text=${encodeURIComponent(msgWa)}`;
  const mailto = `mailto:${emp.email||''}?subject=${encodeURIComponent('Recibo de pagamento — '+compLabel)}&body=${encodeURIComponent(msgWa)}`;
  const visualBox = reg.visualizadoEm
    ? `<div style="background:#E8F5E9;border-left:4px solid #1B5E20;padding:10px 12px;margin-bottom:12px;font-size:13px;color:#1B5E20"><i class="fa-solid fa-circle-check"></i> <strong>Visualizado em ${new Date(reg.visualizadoEm).toLocaleString('pt-BR')}</strong></div>`
    : `<div style="background:#FFF3E0;border-left:4px solid #E65100;padding:10px 12px;margin-bottom:12px;font-size:13px;color:#E65100"><i class="fa-solid fa-clock"></i> Aguardando visualização do colaborador</div>`;

  document.getElementById('modal-envio-recibo')?.remove();
  const html = `
    <div id="modal-envio-recibo" class="modal" style="display:flex;align-items:center;justify-content:center;position:fixed;inset:0;background:rgba(0,0,0,.5);z-index:9999">
      <div class="modal-content" style="background:#fff;max-width:560px;width:92%;border-radius:8px;overflow:hidden;box-shadow:0 8px 32px rgba(0,0,0,.3)">
        <div style="background:#1a3a6b;color:#fff;padding:12px 16px;display:flex;justify-content:space-between;align-items:center">
          <h3 style="margin:0;font-size:16px"><i class="fa-solid fa-paper-plane"></i> Enviar recibo — ${(emp.nome||'').split(' ').slice(0,2).join(' ')}</h3>
          <button onclick="document.getElementById('modal-envio-recibo').remove()" style="background:transparent;border:none;color:#fff;font-size:20px;cursor:pointer;line-height:1">&times;</button>
        </div>
        <div style="padding:16px">
          ${visualBox}
          <div style="font-size:12px;color:#555;margin-bottom:12px">
            <div><strong>Competência:</strong> ${compLabel}</div>
            <div><strong>Protocolo:</strong> <span style="font-family:monospace">${reg.protocolo}</span></div>
            <div><strong>Líquido:</strong> ${fmtMoney(reg.liquido||0)}</div>
          </div>
          ${_appBox}
          <label style="font-weight:600;font-size:12px;display:block;margin-bottom:4px">Ou compartilhe por link público <span style="font-weight:400;color:#999">(sem assinatura)</span></label>
          <div style="display:flex;gap:6px">
            <input type="text" id="recibo-link-input" value="${link}" readonly style="flex:1;font-family:monospace;font-size:11px;padding:8px 10px;border:1px solid #ccc;border-radius:4px;background:#f7f7f7">
            <button onclick="_copiarLinkRecibo()" style="background:#1a3a6b;color:#fff;border:none;padding:6px 14px;border-radius:4px;cursor:pointer;font-size:13px"><i class="fa-solid fa-copy"></i> Copiar</button>
          </div>
          <p style="font-size:11px;color:#888;margin:4px 0 0">Qualquer pessoa com o link pode ver o recibo. Compartilhe apenas com ${primeiroNome}.</p>
          <div style="display:flex;gap:8px;margin-top:16px">
            <a href="${waUrl}" target="_blank" style="flex:1;text-align:center;background:#25D366;color:#fff;border:none;padding:10px;border-radius:4px;text-decoration:none;font-size:13px;font-weight:600"><i class="fa-brands fa-whatsapp"></i> WhatsApp${emp.celular?' ('+emp.celular+')':''}</a>
            <a href="${mailto}" style="flex:1;text-align:center;background:#1565C0;color:#fff;border:none;padding:10px;border-radius:4px;text-decoration:none;font-size:13px;font-weight:600"><i class="fa-solid fa-envelope"></i> E-mail${emp.email?' ('+emp.email+')':''}</a>
          </div>
        </div>
        <div style="padding:10px 16px;border-top:1px solid #eee;display:flex;justify-content:space-between;align-items:center;background:#fafafa">
          <button onclick="_anularReciboEnviado('${reg.id}')" style="background:transparent;color:#c0392b;border:1px solid #c0392b;padding:6px 12px;border-radius:4px;cursor:pointer;font-size:12px"><i class="fa-solid fa-ban"></i> Anular este envio</button>
          <button onclick="document.getElementById('modal-envio-recibo').remove()" style="background:#666;color:#fff;border:none;padding:8px 16px;border-radius:4px;cursor:pointer;font-size:13px">Fechar</button>
        </div>
      </div>
    </div>`;
  document.body.insertAdjacentHTML('beforeend', html);
}

function _copiarLinkRecibo(){
  const input = document.getElementById('recibo-link-input');
  if(!input) return;
  input.select(); input.setSelectionRange(0, 999);
  try {
    if(navigator.clipboard && navigator.clipboard.writeText){
      navigator.clipboard.writeText(input.value).then(()=>toast('Link copiado!','success'));
    } else {
      document.execCommand('copy');
      toast('Link copiado!','success');
    }
  } catch(e){ console.error(e); toast('Não foi possível copiar — copie manualmente.','warning'); }
}

async function _anularReciboEnviado(regId){
  if(!confirm('Anular este envio? O link deixará de funcionar imediatamente. Você poderá gerar um novo recibo depois.')) return;
  const reg = (State.holeritesEnviados||[]).find(r=>r.id===regId);
  if(!reg){ toast('Registro não encontrado.','error'); return; }
  const updated = {...reg, anulado:true, anuladoEm:new Date().toISOString(),
                   anuladoPor:(Auth.currentUser&&(Auth.currentUser.username||Auth.currentUser.nome))||'—'};
  try {
    await DB.save('holeritesEnviados', updated);
    const ix = State.holeritesEnviados.findIndex(r=>r.id===regId);
    if(ix>=0) State.holeritesEnviados[ix] = updated;
    Auth.log && Auth.log('RECIBO_ANULADO', null, `${reg.employeeNome} | ${String(reg.mes).padStart(2,'0')}/${reg.ano} | ${reg.protocolo}`);
    toast('Envio anulado.','success');
    document.getElementById('modal-envio-recibo')?.remove();
    if(State.currentSection==='pagamentos') renderPagamentos();
  } catch(e){ console.error(e); toast('Erro ao anular.','error'); }
}

// ============================================
// ROTA PÚBLICA — #/recibo/TOKEN
// Detectada no início de init(). Bypass do login do gestor. Usa
// collectionGroup pra achar o registro pelo token. Marca visualizadoEm na
// 1ª abertura e renderiza o recibo no body.
// ============================================
async function _entrarRotaPublicaSeAplicavel(){
  const hash = location.hash || '';
  const m = hash.match(/^#\/recibo\/([A-Fa-f0-9]{16,64})$/);
  if(!m) return false;
  const token = m[1];

  document.body.innerHTML = `<div style="font-family:Arial;padding:60px;text-align:center;color:#666">
    <div style="font-size:42px;margin-bottom:14px">⏳</div>
    <div>Carregando seu recibo...</div></div>`;

  // SEM sessão anônima: o recibo é servido pelo Worker (rota pública /recibo-publico),
  // que lê por token via conta de serviço e marca a visualização. Frente C, etapa 5. #recibo-publico
  try {
    const r = await _workerReqPublic('/recibo-publico', { token, userAgent: (navigator.userAgent||'').slice(0,200) });
    if(!r || r.ok!==true){
      document.body.innerHTML = _paginaPublicaErroHTML(
        (r && r.anulado) ? 'Recibo indisponível.' : 'Recibo não encontrado.',
        (r && r.anulado) ? 'Este recibo foi anulado pelo emissor.'
                         : 'O link pode ter sido digitado errado ou o envio foi anulado pelo emissor.');
      return true;
    }
    const data = r.recibo || {};
    const emp = data.empSnapshot || {};
    const p   = data.pSnapshot   || {};
    const reciboHtml = _reciboOficialUmHTML(emp, p, data.mes, data.ano,
      { protocolo: data.protocolo, visualizadoEm: data.visualizadoEm });

    document.body.innerHTML = `
      <div style="background:#eef0f4;min-height:100vh;padding:0">
        <div style="background:#1a3a6b;color:#fff;padding:10px 16px;font-family:Arial;font-size:13px;text-align:center">
          Recibo de Pagamento · Documento eletrônico
        </div>
        <div style="max-width:820px;margin:16px auto;background:#fff;box-shadow:0 2px 18px rgba(0,0,0,.12);padding:24px;font-family:'Times New Roman',serif">
          <div style="background:#E8F5E9;border-left:4px solid #1B5E20;padding:10px 12px;margin-bottom:14px;font-size:12px;color:#1B5E20;font-family:Arial">
            <i class="fa-solid fa-circle-check"></i> <strong>Visualização registrada em ${new Date(data.visualizadoEm).toLocaleString('pt-BR')}</strong> · Protocolo <span style="font-family:monospace">${data.protocolo}</span>
          </div>
          <div style="text-align:center;margin:0 0 14px">
            <button onclick="window.print()" style="background:#1B5E20;color:#fff;border:none;padding:8px 16px;border-radius:4px;cursor:pointer;font-family:Arial;font-size:13px">
              🖨 Imprimir / Salvar PDF
            </button>
          </div>
          ${reciboHtml}
        </div>
        <style>
          @media print {
            body { background:#fff !important }
            div[style*="background:#1a3a6b"], div[style*="background:#E8F5E9"], button { display:none !important }
            div[style*="max-width:820px"] { box-shadow:none !important; padding:0 !important; max-width:100% !important; margin:0 !important }
          }
        </style>
      </div>`;
    return true;
  } catch(e){
    console.error('Erro ao carregar recibo público:', e);
    document.body.innerHTML = _paginaPublicaErroHTML('Não foi possível abrir o recibo.', (e&&e.message)||'Erro de conexão. Tente novamente em alguns instantes.');
    return true;
  }
}

function _paginaPublicaErroHTML(titulo, msg){
  return `<div style="font-family:Arial;padding:40px;text-align:center;background:#f4f4f8;min-height:100vh">
    <div style="max-width:480px;margin:0 auto;background:#fff;padding:40px;border-radius:8px;box-shadow:0 2px 12px rgba(0,0,0,.1)">
      <div style="font-size:48px;color:#c0392b;margin-bottom:8px">⚠️</div>
      <h2 style="color:#333;margin:0 0 10px">${titulo}</h2>
      <p style="color:#666;margin:0">${msg}</p>
    </div></div>`;
}

// ============================================
// TELA RECIBOS ENVIADOS — histórico consolidado
// Mostra TODOS os envios já feitos: filtros por mês/ano/status/colaborador,
// cards com totais, tabela com protocolo + link rápido + ações (reabrir
// modal, anular, reimprimir).
// ============================================
// Status EFETIVO do recibo enviado: cruza a coleção holeritesEnviados (envio por
// LINK público — marca visualizadoEm quando o colab abre) com o holeriteConferencia
// do payroll (envio pro APP, onde o colab ASSINA com hash). Sem isso, a tela
// Recibos Enviados ignorava a assinatura feita no app e ficava "Aguardando" mesmo
// já assinada na aba Holerites Assinados. Agora a assinatura reflete nas DUAS
// páginas. #recibo-assinatura-2paginas
function _reciboStatusEfetivo(r){
  if(r.anulado) return { key:'anulado', txt:'Anulado', cor:'#c0392b', bg:'#FFEBEE', bd:'#FFCDD2', icon:'fa-ban', data:null, interagiu:false };
  const p = (State.payrolls||[]).find(x=>x.employeeId===r.employeeId && x.mes==r.mes && x.ano==r.ano);
  const conf = p && p.holeriteConferencia;
  const cs = conf && conf.status;
  if(cs==='assinada')            return { key:'assinado',    txt:'Assinado',          cor:'#1B5E20', bg:'#E8F5E9', bd:'#A5D6A7', icon:'fa-file-signature',   data: conf.assinadoEm,   interagiu:true };
  if(cs==='contestada')          return { key:'contestado',  txt:'Contestado',        cor:'#C62828', bg:'#FFEBEE', bd:'#FFCDD2', icon:'fa-circle-xmark',     data: conf.contestadoEm, interagiu:true };
  if(cs==='aceita_por_silencio') return { key:'silencio',    txt:'Aceito (silêncio)', cor:'#558B2F', bg:'#F1F8E9', bd:'#C5E1A5', icon:'fa-clock-rotate-left',data: conf.silencioEm,   interagiu:true };
  const visData = (cs==='visualizada' && conf.visualizadoEm) || r.visualizadoEm || null;
  if(visData)                    return { key:'visualizado', txt:'Visualizado',       cor:'#1B5E20', bg:'#E8F5E9', bd:'#A5D6A7', icon:'fa-circle-check',     data: visData,           interagiu:true };
  return { key:'aguardando', txt:'Aguardando', cor:'#E65100', bg:'#FFF3E0', bd:'#FFCC80', icon:'fa-clock', data:null, interagiu:false };
}

function _recibosEnviadosFiltrados(){
  const mes = (val('rec-mes')||'').trim();
  const ano = (val('rec-ano')||'').trim();
  const status = (val('rec-status')||'').trim();
  const q = (val('rec-search')||'').toLowerCase().trim();
  let lista = (State.holeritesEnviados||[]).slice();
  if(mes) lista = lista.filter(r=>r.mes==parseInt(mes));
  if(ano) lista = lista.filter(r=>r.ano==parseInt(ano));
  if(status==='visualizado') lista = lista.filter(r=>_reciboStatusEfetivo(r).interagiu);
  if(status==='pendente')    lista = lista.filter(r=>_reciboStatusEfetivo(r).key==='aguardando');
  if(status==='anulado')     lista = lista.filter(r=>!!r.anulado);
  if(q){
    lista = lista.filter(r=>{
      const emp = State.employees.find(e=>e.id===r.employeeId);
      const reg = emp?String(emp.registro||'').padStart(4,'0'):'';
      const nome = (r.employeeNome || emp?.nome || '').toLowerCase();
      return nome.includes(q) || reg.includes(q);
    });
  }
  // Mais recentes primeiro
  lista.sort((a,b)=> new Date(b.geradoEm||0) - new Date(a.geradoEm||0));
  return lista;
}

function renderRecibosEnviados(){
  const tbody = document.getElementById('rec-tbody');
  const statsEl = document.getElementById('rec-stats');
  if(!tbody) return;
  const todos = (State.holeritesEnviados||[]);
  const filtrados = _recibosEnviadosFiltrados();

  // Stats globais (não filtrados — visão geral fica útil). Usam o status EFETIVO,
  // então a assinatura no app conta como interação (sai de "Aguardando").
  const totalEnv  = todos.length;
  const totalVis  = todos.filter(r=>_reciboStatusEfetivo(r).interagiu).length;
  const totalPend = todos.filter(r=>_reciboStatusEfetivo(r).key==='aguardando').length;
  const totalAnu  = todos.filter(r=>!!r.anulado).length;
  const pctVis    = totalEnv>0 ? Math.round(totalVis*100/totalEnv) : 0;
  if(statsEl){
    statsEl.innerHTML = `
      <div class="stat-card">
        <div class="stat-icon" style="background:rgba(26,58,107,0.1)"><i class="fa-solid fa-paper-plane" style="color:#1a3a6b"></i></div>
        <div class="stat-info"><div class="stat-label">Total enviados</div><div class="stat-value" style="color:#1a3a6b">${totalEnv}</div></div>
      </div>
      <div class="stat-card">
        <div class="stat-icon" style="background:rgba(27,94,32,0.1)"><i class="fa-solid fa-circle-check" style="color:#1B5E20"></i></div>
        <div class="stat-info"><div class="stat-label">Visualizados (${pctVis}%)</div><div class="stat-value" style="color:#1B5E20">${totalVis}</div></div>
      </div>
      <div class="stat-card">
        <div class="stat-icon" style="background:rgba(230,81,0,0.1)"><i class="fa-solid fa-clock" style="color:#E65100"></i></div>
        <div class="stat-info"><div class="stat-label">Aguardando abertura</div><div class="stat-value" style="color:#E65100">${totalPend}</div></div>
      </div>
      <div class="stat-card">
        <div class="stat-icon" style="background:rgba(192,57,43,0.1)"><i class="fa-solid fa-ban" style="color:#c0392b"></i></div>
        <div class="stat-info"><div class="stat-label">Anulados</div><div class="stat-value" style="color:#c0392b">${totalAnu}</div></div>
      </div>`;
  }

  if(!filtrados.length){
    tbody.innerHTML = `<tr><td colspan="9" style="padding:30px;text-align:center;color:#888">
      ${totalEnv===0 ? 'Nenhum recibo enviado ainda. Use o botão de envio na tela Pagamentos.' : 'Nenhum recibo bate com os filtros aplicados.'}
    </td></tr>`;
    return;
  }

  tbody.innerHTML = filtrados.map((r,i)=>{
    const emp = State.employees.find(e=>e.id===r.employeeId);
    const nome = r.employeeNome || emp?.nome || '—';
    const reg  = emp ? String(emp.registro||'').padStart(4,'0') : '—';
    const compLabel = `${MESES[r.mes]||'?'}/${r.ano}`;
    const liq = fmtMoney(r.liquido||0);
    const enviado = r.geradoEm ? new Date(r.geradoEm).toLocaleString('pt-BR') : '—';
    const st = _reciboStatusEfetivo(r);
    const visual  = st.data ? new Date(st.data).toLocaleString('pt-BR') : '—';
    const badge = `<span style="background:${st.bg};color:${st.cor};border:1px solid ${st.bd};padding:2px 8px;border-radius:12px;font-size:11px"><i class="fa-solid ${st.icon}"></i> ${st.txt}</span>`;
    const link = location.origin + location.pathname + '#/recibo/' + (r.token||'');
    const linkEscaped = link.replace(/'/g,"\\'");
    const bg = i%2===0 ? '#fff' : '#f7f9fc';
    return `<tr style="background:${bg}">
      <td>${i+1}</td>
      <td><strong>${nome}</strong><br><span style="font-size:10px;color:#888">Reg. ${reg}</span></td>
      <td style="white-space:nowrap">${compLabel}</td>
      <td style="font-weight:600;color:#1B5E20">${liq}</td>
      <td style="font-family:monospace;font-size:10px;color:#555" title="${r.protocolo||''}">${(r.protocolo||'—').slice(0,10)}…</td>
      <td style="font-size:11px">${enviado}</td>
      <td style="font-size:11px">${visual}</td>
      <td>${badge}</td>
      <td style="white-space:nowrap">
        ${r.anulado ? '' : `
          <button class="btn-icon" onclick="_reciboReabrirModal('${r.id}')" title="Abrir modal de envio (copiar link, WhatsApp, e-mail)"><i class="fa-solid fa-paper-plane" style="color:#1565C0"></i></button>
          <button class="btn-icon" onclick="_reciboCopiarLinkRapido('${linkEscaped}')" title="Copiar link"><i class="fa-solid fa-link" style="color:#1a3a6b"></i></button>
          <button class="btn-icon" onclick="_reciboAbrirComoColaborador('${linkEscaped}')" title="Abrir o link em uma nova aba (como o colaborador veria)"><i class="fa-solid fa-up-right-from-square" style="color:#666"></i></button>
        `}
        <button class="btn-icon" onclick="_reciboImprimirDoRegistro('${r.id}')" title="Imprimir recibo"><i class="fa-solid fa-print" style="color:#1B5E20"></i></button>
        ${r.anulado ? '' : `<button class="btn-icon" onclick="_anularReciboEnviado('${r.id}')" title="Anular envio"><i class="fa-solid fa-ban" style="color:#c0392b"></i></button>`}
      </td>
    </tr>`;
  }).join('');
}

// Reabre o modal de envio com os dados do registro existente.
function _reciboReabrirModal(regId){
  const reg = (State.holeritesEnviados||[]).find(r=>r.id===regId);
  if(!reg){ toast('Registro não encontrado.','error'); return; }
  const emp = State.employees.find(e=>e.id===reg.employeeId) || reg.empSnapshot || { nome: reg.employeeNome };
  const link = location.origin + location.pathname + '#/recibo/' + reg.token;
  _abrirModalEnvioRecibo(emp, reg, link);
}

function _reciboCopiarLinkRapido(link){
  try {
    if(navigator.clipboard && navigator.clipboard.writeText){
      navigator.clipboard.writeText(link).then(()=>toast('Link copiado!','success'));
    } else {
      const ta = document.createElement('textarea'); ta.value=link; document.body.appendChild(ta);
      ta.select(); document.execCommand('copy'); ta.remove();
      toast('Link copiado!','success');
    }
  } catch(e){ console.error(e); toast('Não foi possível copiar.','error'); }
}

function _reciboAbrirComoColaborador(link){
  window.open(link, '_blank');
}

// Imprime o recibo direto a partir do snapshot persistido (não precisa ter folha em estado).
function _reciboImprimirDoRegistro(regId){
  const reg = (State.holeritesEnviados||[]).find(r=>r.id===regId);
  if(!reg){ toast('Registro não encontrado.','error'); return; }
  const emp = reg.empSnapshot || State.employees.find(e=>e.id===reg.employeeId);
  const p = reg.pSnapshot;
  if(!emp || !p){ toast('Dados do recibo incompletos.','error'); return; }
  const html = _reciboOficialPaginaHTML([{emp, p}], reg.mes, reg.ano);
  const w = window.open('','_blank');
  w.document.write(html); w.document.close(); w.print();
}

function exportRecibosCsv(){
  const lista = _recibosEnviadosFiltrados();
  if(!lista.length){ toast('Nada para exportar.','warning'); return; }
  const header = ['#','Colaborador','Registro','Competência','Líquido','Protocolo','Token','Enviado em','Visualizado em','Status','Link'];
  const rows = lista.map((r,i)=>{
    const emp = State.employees.find(e=>e.id===r.employeeId);
    const nome = r.employeeNome || emp?.nome || '';
    const reg = emp ? String(emp.registro||'').padStart(4,'0') : '';
    const stEf = _reciboStatusEfetivo(r);
    const status = stEf.txt;
    const link = location.origin + location.pathname + '#/recibo/' + (r.token||'');
    const fmtBr = iso => iso ? new Date(iso).toLocaleString('pt-BR') : '';
    return [i+1, nome, reg, `${MESES[r.mes]||'?'}/${r.ano}`,
      (r.liquido||0).toFixed(2).replace('.',','),
      r.protocolo||'', r.token||'',
      fmtBr(r.geradoEm), fmtBr(stEf.data), status, link
    ].map(v=>String(v).replace(/;/g,',')).join(';');
  });
  const csv = '﻿' + [header.join(';'), ...rows].join('\n');
  const a = document.createElement('a');
  a.href = 'data:text/csv;charset=utf-8,' + encodeURIComponent(csv);
  a.download = `recibos_enviados_${new Date().toISOString().slice(0,10)}.csv`;
  a.click();
}

// ============================================
// MÓDULO 13º SALÁRIO
// ============================================
function renderDecimoTerceiro(){
  const ano=parseInt(val('dec-ano')||currentAno());
  const statusFilt=val('dec-status-filter')||'ativo';
  let emps=_filtrarEmpsPorEscopo(State.employees).slice();
  if(statusFilt!=='all') emps=emps.filter(e=>(e.status||'ativo')===statusFilt);
  emps.sort((a,b)=>a.nome.localeCompare(b.nome));

  const recMap={};
  (State.decimoTerceiro||[]).filter(r=>r.ano===ano).forEach(r=>{ recMap[r.employeeId]=r; });

  const tbody=document.getElementById('dec-tbody');
  if(!tbody) return;
  if(emps.length===0){ tbody.innerHTML='<tr><td colspan="11" style="text-align:center;padding:20px">Nenhum colaborador.</td></tr>'; return; }

  let totalBruto=0,totalINSS=0,totalIRRF=0,totalFGTS=0,totalLiq=0;
  const _refDecL=`${ano}-12-31`;
  const rows=emps.map((emp,i)=>{
    const mesesDir=_avosDecimo(emp,ano);
    const salBase=parseFloat(emp.salarioBase||0);
    const rec=recMap[emp.id]||{};
    // Base = salário + médias variáveis (salvas no registro OU pré-calculadas dos 12 meses),
    // pra o bruto da lista bater com o do modal. #dsr-he-camada2
    const mediaAdic=(rec.mediaAdic!=null)?+rec.mediaAdic:(_mediaAdicionaisRescisao(emp.id,_refDecL)||0);
    const mediaDsr =(rec.mediaDsr!=null) ?+rec.mediaDsr :(_mediaDsrHERescisao(emp.id,_refDecL)||0);
    const baseCalc=salBase+mediaAdic+mediaDsr;
    const bruto=Math.round(baseCalc*mesesDir/12*100)/100;
    const parc1=Math.round(bruto/2*100)/100;
    const inss=calcINSS(bruto);
    const irrf=calcIRRF(bruto,emp.dependentesIRRF||0,emp.pensaoAlimenticia||0,0,inss);  // 13o tributa o BRUTO CHEIO (exclusivo na fonte), nao metade. #fix-irrf13
    const fgts=calcFGTS(bruto);
    const parc2=Math.round((bruto/2-inss-irrf)*100)/100;
    const liq=Math.round((bruto-inss-irrf)*100)/100;
    totalBruto+=bruto; totalINSS+=inss; totalIRRF+=irrf; totalFGTS+=fgts; totalLiq+=liq;
    const status=rec.status||'pendente';
    const badge=status==='pago'?'<span class="badge badge-success">Pago</span>':status==='parcial'?'<span class="badge badge-warning">Parcial</span>':'<span class="badge badge-muted">Pendente</span>';
    return `<tr>
      <td>${i+1}</td><td>${emp.registro||'—'}</td><td>${emp.nome}</td>
      <td style="text-align:center">${mesesDir}/12</td>
      <td>${fmtMoney(bruto)}</td><td>${fmtMoney(parc1)}</td>
      <td style="color:#c0392b">(${fmtMoney(inss)})</td>
      <td style="color:#c0392b">(${fmtMoney(irrf)})</td>
      <td style="color:#1a3a6b">${fmtMoney(fgts)}</td>
      <td>${fmtMoney(parc2)}</td><td>${badge}</td>
      <td><button class="btn btn-sm btn-outline-primary" onclick="openDecimoTerceiro('${emp.id}')"><i class="fa-solid fa-pen-to-square"></i></button></td>
    </tr>`;
  });
  tbody.innerHTML=rows.join('');
  const tfoot=document.getElementById('dec-tfoot');
  if(tfoot) tfoot.innerHTML=`<tr style="font-weight:600;background:#f0f4ff">
    <td colspan="4" style="text-align:right">TOTAIS</td>
    <td>${fmtMoney(totalBruto)}</td><td>—</td>
    <td style="color:#c0392b">(${fmtMoney(totalINSS)})</td>
    <td style="color:#c0392b">(${fmtMoney(totalIRRF)})</td>
    <td style="color:#1a3a6b">${fmtMoney(totalFGTS)}</td>
    <td>${fmtMoney(totalLiq)}</td><td colspan="2"></td>
  </tr>`;
}

function openDecimoTerceiro(empId){
  const emp=State.employees.find(e=>e.id===empId); if(!emp) return;
  const ano=parseInt(val('dec-ano')||currentAno());
  const rec=(State.decimoTerceiro||[]).find(r=>r.employeeId===empId&&r.ano===ano)||{};
  const mesesDir=_avosDecimo(emp,ano);
  setVal('dec-modal-emp-id',empId);
  setVal('dec-modal-ano',ano);
  setVal('dec-modal-nome',emp.nome);
  setVal('dec-modal-cargo',emp.cargo||emp.setor||'—');
  setVal('dec-modal-admissao',emp.dataAdmissao?formatDateBr(emp.dataAdmissao):'—');
  setVal('dec-modal-meses-dir',mesesDir);
  setVal('dec-modal-sal-base',(parseFloat(emp.salarioBase||0)).toFixed(2));
  setVal('dec-modal-status',rec.status||'pendente');
  setVal('dec-modal-obs',rec.obs||'');
  setVal('dec-modal-parc1-data',rec.parc1Data||'');
  setVal('dec-modal-parc2-data',rec.parc2Data||'');
  // Médias variáveis (noturno/HE + reflexo DSR) — salvas no registro ou pré-preenchidas
  // pela média dos 12 meses (ref. 31/dez do ano). Editáveis. #dsr-he-camada2
  const _refDec=`${ano}-12-31`;
  const _mAdic=(rec.mediaAdic!=null)?+rec.mediaAdic:_mediaAdicionaisRescisao(empId,_refDec);
  const _mDsr =(rec.mediaDsr!=null) ?+rec.mediaDsr :_mediaDsrHERescisao(empId,_refDec);
  setVal('dec-modal-media-adic', (+_mAdic>0)?(+_mAdic).toFixed(2):'');
  setVal('dec-modal-media-dsr',  (+_mDsr>0) ?(+_mDsr).toFixed(2) :'');
  _calcDecTercPreview(emp,mesesDir);
  document.getElementById('modal-decimo-terceiro').classList.remove('hidden');
}

function _calcDecTercPreview(emp,mesesDir){
  if(!emp){ const id=val('dec-modal-emp-id'); emp=State.employees.find(e=>e.id===id); if(!emp) return; }
  if(mesesDir===undefined) mesesDir=parseInt(val('dec-modal-meses-dir')||12);
  const salBase=parseFloat(emp.salarioBase||0);
  // Base do 13º = salário + média de adicionais variáveis (noturno/HE, Súmula 45/347) +
  // reflexo do DSR sobre HE (Súmula 172/OJ 394). Campos editáveis, pré-preenchidos. #dsr-he-camada2
  const mediaAdic=parseFloat(val('dec-modal-media-adic')||0);
  const mediaDsr=parseFloat(val('dec-modal-media-dsr')||0);
  const baseCalc=salBase+mediaAdic+mediaDsr;
  const bruto=Math.round(baseCalc*mesesDir/12*100)/100;
  const parc1=Math.round(bruto/2*100)/100;
  const inss=calcINSS(bruto);
  const irrf=calcIRRF(bruto,emp.dependentesIRRF||0,emp.pensaoAlimenticia||0,0,inss);  // 13o tributa o BRUTO CHEIO (exclusivo na fonte), nao metade. #fix-irrf13
  const fgts=calcFGTS(bruto);
  const parc2=Math.round((bruto/2-inss-irrf)*100)/100;
  const liq=Math.round((bruto-inss-irrf)*100)/100;
  setVal('dec-modal-bruto',bruto.toFixed(2));
  setVal('dec-modal-parc1',parc1.toFixed(2));
  setVal('dec-modal-inss',inss.toFixed(2));
  setVal('dec-modal-irrf',irrf.toFixed(2));
  setVal('dec-modal-fgts',fgts.toFixed(2));
  setVal('dec-modal-parc2',parc2.toFixed(2));
  setVal('dec-modal-liquido',liq.toFixed(2));
}

async function saveDecimoTerceiro(){
  const empId=val('dec-modal-emp-id'); if(!empId) return;
  const emp=State.employees.find(e=>e.id===empId); if(!emp) return;
  const ano=parseInt(val('dec-modal-ano')||currentAno());
  const rec={
    id:`${empId}_${ano}`,
    employeeId:empId, nomeEmp:emp.nome, ano,
    status:val('dec-modal-status')||'pendente',
    obs:val('dec-modal-obs')||'',
    parc1Data:val('dec-modal-parc1-data')||'',
    parc2Data:val('dec-modal-parc2-data')||'',
    mediaAdic:parseFloat(val('dec-modal-media-adic')||0),
    mediaDsr:parseFloat(val('dec-modal-media-dsr')||0),
    bruto:parseFloat(val('dec-modal-bruto')||0),
    parc1:parseFloat(val('dec-modal-parc1')||0),
    parc2:parseFloat(val('dec-modal-parc2')||0),
    inss:parseFloat(val('dec-modal-inss')||0),
    irrf:parseFloat(val('dec-modal-irrf')||0),
    fgts:parseFloat(val('dec-modal-fgts')||0),
    liquido:parseFloat(val('dec-modal-liquido')||0),
    updatedAt:new Date().toISOString()
  };
  const btn=document.querySelector('#modal-decimo-terceiro .btn-primary');
  setBtnLoading(btn,true,'');
  try {
    await DB.save('decimoTerceiro',rec);
    closeModal('modal-decimo-terceiro');
    toast('13º Salário salvo!');
    Auth.log('DEC_TERCEIRO_SAVED',Auth.currentUser.username,`${emp.nome} / ${ano}`);
  } catch(e){ toast('Erro ao salvar.','error'); }
  finally{ setBtnLoading(btn,false,'<i class="fa-solid fa-floppy-disk"></i> Salvar'); }
}

