// ============================================
// MÓDULO FÉRIAS
// ============================================
function renderFeriasModulo(){
  const ano=parseInt(val('fer-mod-ano')||currentAno());
  const statusFilt=val('fer-mod-status-filter')||'ativo';
  let emps=_filtrarEmpsPorEscopo(State.employees).slice();
  if(statusFilt!=='all') emps=emps.filter(e=>(e.status||'ativo')===statusFilt);
  emps.sort((a,b)=>a.nome.localeCompare(b.nome));

  const recMap={};
  (State.ferias||[]).filter(r=>r.ano===ano).forEach(r=>{
    if(!recMap[r.employeeId]) recMap[r.employeeId]=[];
    recMap[r.employeeId].push(r);
  });

  const tbody=document.getElementById('fer-mod-tbody');
  if(!tbody) return;
  if(emps.length===0){ tbody.innerHTML='<tr><td colspan="8" style="text-align:center;padding:20px">Nenhum colaborador.</td></tr>'; return; }

  const _badge=status=>status==='gozadas'?'<span class="badge badge-success">Gozadas</span>':status==='agendadas'?'<span class="badge badge-warning">Agendadas</span>':'<span class="badge badge-muted">Pendente</span>';
  const _periodoGozo=r=>(r.inicio&&r.fim)?`<div style="font-size:10px;color:var(--text-muted)">${formatDateBr(r.inicio)}–${formatDateBr(r.fim)}${(r.abonoDias||0)>0?` · +${r.abonoDias}d abono`:''}</div>`:'';
  const rowsArr=[];
  emps.forEach((emp,i)=>{
    // Uma linha POR período de férias (férias fracionadas: 15+10+5). Antes só o
    // último período aparecia — os demais sumiam da tela. #19
    const recs=(recMap[emp.id]||[]).slice().sort((a,b)=>String(a.inicio||'').localeCompare(String(b.inicio||'')));
    const admissao=emp.dataAdmissao||'';
    let periodoAquis='—', direitoAno='—';
    if(admissao){
      const adm=new Date(admissao.substring(0,10)+'T00:00:00');
      const anoAdm=adm.getFullYear(), mesAdm=adm.getMonth(), diaAdm=adm.getDate();
      const periodos=ano-anoAdm;
      if(periodos>=1){
        const ini=new Date(anoAdm+periodos-1,mesAdm,diaAdm);
        const fim=new Date(anoAdm+periodos,mesAdm,diaAdm-1);
        periodoAquis=`${ini.toLocaleDateString('pt-BR')} – ${fim.toLocaleDateString('pt-BR')}`;
        direitoAno=`${anoAdm+periodos}`;
      }
    }
    const baseCols=`<td>${i+1}</td><td>${emp.registro||'—'}</td><td>${emp.nome}</td><td>${emp.cargo||emp.setor||'—'}</td><td style="font-size:11px">${periodoAquis}</td><td style="text-align:center">${direitoAno}</td>`;
    const blankCols='<td></td><td></td><td></td><td></td><td></td><td></td>';
    if(recs.length===0){
      rowsArr.push(`<tr>${baseCols}<td>${_badge('pendente')}</td>
        <td><button class="btn btn-sm btn-outline-primary" onclick="openFeriasModulo('${emp.id}')" title="Lançar férias"><i class="fa-solid fa-pen-to-square"></i></button></td></tr>`);
    } else {
      recs.forEach((r,ri)=>{
        const addBtn=ri===recs.length-1?` <button class="btn btn-sm btn-outline-secondary" onclick="openFeriasModulo('${emp.id}')" title="Adicionar outro período (férias fracionadas)"><i class="fa-solid fa-plus"></i></button>`:'';
        rowsArr.push(`<tr>${ri===0?baseCols:blankCols}
          <td>${_badge(r.status||'pendente')}${_periodoGozo(r)}</td>
          <td><button class="btn btn-sm btn-outline-primary" onclick="openFeriasModulo('${emp.id}','${r.id}')" title="Editar este período"><i class="fa-solid fa-pen-to-square"></i></button>${addBtn}</td></tr>`);
      });
    }
  });
  tbody.innerHTML=rowsArr.join('');
}

function openFeriasModulo(empId, recId){
  const emp=State.employees.find(e=>e.id===empId); if(!emp) return;
  const ano=parseInt(val('fer-mod-ano')||currentAno());
  const recs=(State.ferias||[]).filter(r=>r.employeeId===empId&&r.ano===ano);
  // recId → edita o período específico; sem recId → NOVO período (campos limpos),
  // pra permitir férias fracionadas (2-3 períodos no mesmo ano). #19
  const rec = recId ? (recs.find(r=>String(r.id)===String(recId))||{}) : {};
  setVal('fer-modal-emp-id',empId);
  setVal('fer-modal-ano',ano);
  setVal('fer-modal-nome',emp.nome);
  setVal('fer-modal-cargo',emp.cargo||emp.setor||'—');
  setVal('fer-modal-admissao',emp.dataAdmissao?formatDateBr(emp.dataAdmissao):'—');
  setVal('fer-modal-sal-base',(parseFloat(emp.salarioBase||0)).toFixed(2));
  setVal('fer-modal-inicio',rec.inicio||'');
  setVal('fer-modal-fim',rec.fim||'');
  setVal('fer-modal-abono-dias',rec.abonoDias||0);
  setVal('fer-modal-status',rec.status||'pendente');
  setVal('fer-modal-obs',rec.obs||'');
  // Médias variáveis (noturno/HE + reflexo DSR) — salvas no registro ou pré-preenchidas
  // pela média dos 12 meses (ref. início do gozo, ou fim do ano). Editáveis. #dsr-he-camada2
  const _refFer=rec.inicio||`${ano}-12-31`;
  const _mAdicF=(rec.mediaAdic!=null)?+rec.mediaAdic:_mediaAdicionaisRescisao(empId,_refFer);
  const _mDsrF =(rec.mediaDsr!=null) ?+rec.mediaDsr :_mediaDsrHERescisao(empId,_refFer);
  setVal('fer-modal-media-adic',(+_mAdicF>0)?(+_mAdicF).toFixed(2):'');
  setVal('fer-modal-media-dsr', (+_mDsrF>0) ?(+_mDsrF).toFixed(2) :'');
  calcFeriasModuloPreview();
  document.getElementById('modal-ferias-modulo').classList.remove('hidden');
}

function calcFeriasModuloPreview(){
  const empId=val('fer-modal-emp-id');
  const emp=State.employees.find(e=>e.id===empId); if(!emp) return;
  const salBase=parseFloat(emp.salarioBase||0);
  // Base de férias = salário + média de adicionais variáveis (noturno/HE, Súmula 45/347) +
  // reflexo do DSR sobre HE (Súmula 172/OJ 394). Campos editáveis, pré-preenchidos. #dsr-he-camada2
  const mediaAdic=parseFloat(val('fer-modal-media-adic')||0);
  const mediaDsr=parseFloat(val('fer-modal-media-dsr')||0);
  const baseCalc=salBase+mediaAdic+mediaDsr;
  const abonoDias=Math.min(10,Math.max(0,parseInt(val('fer-modal-abono-dias')||0)));
  const diasGozo=30-abonoDias;
  const abono=Math.round(baseCalc/30*abonoDias*100)/100;
  const salFruicao=Math.round(baseCalc*diasGozo/30*100)/100;
  // 1/3 constitucional incide sobre TODA a remuneração de férias (fruição + abono).
  // Tributação (CLT/jurisprudência): abono pecuniário e o 1/3 sobre ele são ISENTOS
  // de INSS/IRRF; a base é só a fruição + o 1/3 da fruição.
  const tercoGozo=Math.round(salFruicao/3*100)/100;
  const tercoAbono=Math.round(abono/3*100)/100;
  const terco=Math.round((tercoGozo+tercoAbono)*100)/100;
  const totalBruto=Math.round((salFruicao+terco+abono)*100)/100;
  const baseTributavel=salFruicao+tercoGozo;
  const inss=calcINSS(baseTributavel);
  const irrf=calcIRRF(baseTributavel,emp.dependentesIRRF||0,emp.pensaoAlimenticia||0,0,inss);
  const totalLiq=Math.round((totalBruto-inss-irrf)*100)/100;
  const abonoBox=document.getElementById('fer-abono-box');
  if(abonoBox) abonoBox.classList.toggle('hidden',abonoDias===0);
  setVal('fer-modal-dias-gozo',diasGozo);
  setVal('fer-modal-sal-fruicao',salFruicao.toFixed(2));
  setVal('fer-modal-terco',terco.toFixed(2));
  setVal('fer-modal-abono-val',abono.toFixed(2));
  setVal('fer-modal-total-bruto',totalBruto.toFixed(2));
  setVal('fer-modal-inss',inss.toFixed(2));
  setVal('fer-modal-irrf',irrf.toFixed(2));
  setVal('fer-modal-total-liquido',totalLiq.toFixed(2));
}

async function saveFeriasModulo(){
  const empId=val('fer-modal-emp-id'); if(!empId) return;
  const emp=State.employees.find(e=>e.id===empId); if(!emp) return;
  const ano=parseInt(val('fer-modal-ano')||currentAno());
  const inicio=val('fer-modal-inicio'), fim=val('fer-modal-fim');
  if(!inicio||!fim){ toast('Informe as datas de início e fim.','error'); return; }
  const abonoDias=parseInt(val('fer-modal-abono-dias')||0);
  const rec={
    id:`${empId}_${ano}_${inicio.replace(/[\/\-]/g,'')}`,
    employeeId:empId, nomeEmp:emp.nome, ano, inicio, fim, abonoDias,
    status:val('fer-modal-status')||'pendente',
    obs:val('fer-modal-obs')||'',
    mediaAdic:parseFloat(val('fer-modal-media-adic')||0),
    mediaDsr:parseFloat(val('fer-modal-media-dsr')||0),
    salFruicao:parseFloat(val('fer-modal-sal-fruicao')||0),
    terco:parseFloat(val('fer-modal-terco')||0),
    abono:parseFloat(val('fer-modal-abono-val')||0),
    totalBruto:parseFloat(val('fer-modal-total-bruto')||0),
    inss:parseFloat(val('fer-modal-inss')||0),
    irrf:parseFloat(val('fer-modal-irrf')||0),
    totalLiquido:parseFloat(val('fer-modal-total-liquido')||0),
    updatedAt:new Date().toISOString()
  };
  const btn=document.querySelector('#modal-ferias-modulo .btn-primary');
  setBtnLoading(btn,true,'');
  try {
    await DB.save('ferias',rec);
    closeModal('modal-ferias-modulo');
    toast('Férias salvas!');
    Auth.log('FERIAS_SAVED',Auth.currentUser.username,`${emp.nome} / ${inicio}–${fim}`);
  } catch(e){ toast('Erro ao salvar.','error'); }
  finally{ setBtnLoading(btn,false,'<i class="fa-solid fa-floppy-disk"></i> Salvar'); }
}

