function renderBancoDados(){
  try { AutoBackup._renderModalStatus(); } catch(_){}   // relógio do último auto-backup no card Backup. #auto-backup-relogio
  // Card da CCT — mostra valores atuais (ou alerta se a CCT nao carregou)
  const cctInfo = document.getElementById('banco-cct-info');
  if(cctInfo){
    const cct = State.cct;
    if(!cct){
      cctInfo.innerHTML = `<div style="padding:10px;background:#FFEBEE;border:1px solid #EF9A9A;border-radius:4px;color:#B71C1C">
        <i class="fa-solid fa-triangle-exclamation"></i> <strong>CCT não carregada</strong> — o Firestore pode estar com erro de listener (veja "Recarregar dados"). Sem a CCT, a bonificação fica R$0.
      </div>`;
    } else {
      const _bonifLine = cct.bonificacao>0
        ? `<div style="margin-top:6px;padding:6px 8px;background:#E8F5E9;border-radius:4px"><strong>Bonificação Boa Permanência:</strong> ${fmtMoney(cct.bonificacao)}</div>`
        : `<div style="margin-top:6px;padding:6px 8px;background:#FFEBEE;border-radius:4px;color:#B71C1C"><strong>Bonificação:</strong> NÃO CONFIGURADA — bonificações ficam R$0</div>`;
      cctInfo.innerHTML = `
        <div><strong>Vigência:</strong> ${cct.vigencia ? formatDateBr(cct.vigencia) : '—'}</div>
        <div><strong>Salário base:</strong> ${cct.salarioBase ? fmtMoney(cct.salarioBase) : '—'}</div>
        <div><strong>VT/dia:</strong> ${cct.vtDiario ? fmtMoney(cct.vtDiario) : '—'} · <strong>VR/dia:</strong> ${cct.vrDiario ? fmtMoney(cct.vrDiario) : '—'}</div>
        <div><strong>VA mensal:</strong> ${cct.vaMensal ? fmtMoney(cct.vaMensal) : '—'}</div>
        ${_bonifLine}
      `;
    }
  }
  // Card de estatísticas — conta o que está em memória
  const statsEl = document.getElementById('banco-stats');
  if(statsEl){
    const nColab = (State.employees||[]).length;
    const nPay   = (State.payrolls||[]).length;
    const nEsc   = (State.escalas||[]).length;
    const nPostos= (State.postos||[]).length;
    statsEl.innerHTML = `
      <div style="display:flex;justify-content:space-between;padding:5px 0;border-bottom:1px solid #eee"><span>Colaboradores</span><strong>${nColab}</strong></div>
      <div style="display:flex;justify-content:space-between;padding:5px 0;border-bottom:1px solid #eee"><span>Folhas (lançamentos)</span><strong>${nPay}</strong></div>
      <div style="display:flex;justify-content:space-between;padding:5px 0;border-bottom:1px solid #eee"><span>Escalas salvas</span><strong>${nEsc}</strong></div>
      <div style="display:flex;justify-content:space-between;padding:5px 0;border-bottom:1px solid #eee"><span>Postos de trabalho</span><strong>${nPostos}</strong></div>
      <div style="margin-top:8px;padding:6px 8px;background:#E3F2FD;border-radius:4px;color:#0D47A1;font-size:11px"><i class="fa-solid fa-circle-info"></i> Fonte: Firebase Firestore</div>
    `;
  }
}

// Força o reload dos dados do Firestore — útil quando o listener falhou (erro
// 400 / transport errored). Recarrega a página inteira: os listeners do init()
// montam tudo de novo do zero.
function recarregarDadosFirestore(){
  if(!confirm('Recarregar dados do Firebase?\n\nA página vai ser recarregada. Qualquer alteração não salva será perdida.')) return;
  try { window.location.reload(); }
  catch(e){ toast('Erro ao recarregar: '+(e.message||e), 'error'); }
}

// Repara batidas mal-encaixadas numa jornada SEM intervalo contratual (sábado
// curto de 4h do 6x1A/6x1C, plantão 12x36, fds curto etc.). O app de ponto
// (ponto.html) decide a sequência das batidas pela flag GERAL `semRefeicao` do
// colaborador — ele não sabe que AQUELE dia específico não tem almoço. Então a
// 2ª batida de um plantão curto cai no slot "Int. Início" em vez de "Saída",
// deixando a saída vazia. Como a apuração exige entrada E saída, o dia vira "sem
// batida" e fabrica uma FALTA fantasma mesmo com o horário explícito na folha.
// Aqui reordenamos as batidas presentes pela jornada ESPERADA do dia: se o dia
// não prevê intervalo e a saída está vazia mas há batida no slot de intervalo,
// a 1ª batida é a entrada e a ÚLTIMA é a saída. #falta-fantasma
function _repararBatidasDia(pd, exp){
  const entrada=(pd&&pd.entrada)||'', saida=(pd&&pd.saida)||'', intIni=(pd&&pd.intIni)||'', intFim=(pd&&pd.intFim)||'';
  const expTemIntervalo = !!(exp && exp.intIni && exp.intFim);
  // Só reparamos o sinal CLÁSSICO do bug: saída vazia + batida presa no slot de
  // intervalo, num dia cuja jornada esperada NÃO tem intervalo. Mantém intacto
  // qualquer dia bem-formado (com saída) e qualquer jornada que prevê almoço.
  if(!saida && (intIni||intFim) && !expTemIntervalo){
    const marcas=[entrada,intIni,intFim].filter(Boolean);   // ordem de preenchimento = cronológica
    if(marcas.length>=2) return { entrada:marcas[0], saida:marcas[marcas.length-1], intIni:'', intFim:'' };
    if(marcas.length===1) return { entrada:marcas[0], saida:'', intIni:'', intFim:'' };
  }
  return { entrada, saida, intIni, intFim };
}

// Totais de apuração de ponto do período (horas), por colaborador. MESMA LÓGICA
// do espelho da folha (_buildFolhaHtmlFromRecord) — manter em sincronia p/ os
// números da Contabilidade baterem com a folha impressa. #folha-detalhada
function _apuracaoPontoTotais(emp, p){
  const out={trabMin:0,prevMin:0,atrasoMin:0,extraMin:0,faltaMin:0,faltaQtd:0,naoRendMin:0,naoRendAprovadoMin:0,diasAbaixoMeio:0};
  if(!emp || !p) return out;
  if(emp.isentoPonto) return out;
  const mes=p.mes, ano=p.ano;
  const diasPonto=Array.isArray(p.pontoManualDias)?p.pontoManualDias:[];
  // SEM ponto lançado, NÃO se fabrica falta de todo dia previsto (senão a folha
  // sem ponto aparece com TODAS as horas como falta — ex.: 185h pra quem tem 0
  // faltas). Sem ponto, as faltas vêm do nº SALVO (faltasInjustificadas). #fix-falta-sem-ponto
  const temPonto = diasPonto.length>0;
  const is12x36=escalaFamilia(emp.escala||'5x2A')==='12x36';
  const _MCa = _minContratadosEmp(emp);
  let diasPrevistosCnt=0;
  for(const cd of _compDias(mes,ano)){
    const d=cd.dia, dow=cd.diaSem, isWknd=dow===0||dow===6;
    const pd=diasPonto.find(x=>x.dia===d)||{};
    const exp=_getExpectedDay(emp,cd.mes,cd.ano,d);   // mês REAL do dia (fronteira 26-31). #fronteira
    const _bat=_repararBatidasDia(pd, exp);           // sábado curto: 2ª batida no slot errado → falta fantasma. #falta-fantasma
    const entrada=_bat.entrada, saida=_bat.saida, intIni=_bat.intIni, intFim=_bat.intFim;
    let minLiq=0;
    if(entrada&&saida){ let mb=timeToMinutes(saida)-timeToMinutes(entrada); if(mb<=0)mb+=24*60; minLiq=mb-_calcIntervaloMin(intIni,intFim,entrada,saida); }
    const _emFerias=_emFeriasNoDia(emp, `${cd.ano}-${String(cd.mes).padStart(2,'0')}-${String(d).padStart(2,'0')}`);
    const ehFolga=_emFerias||!exp||exp.tipo==='folga'||!exp.entrada;
    let prevMin=0, contratualIntMin=0;
    if(!ehFolga){ let mbE=timeToMinutes(exp.saida)-timeToMinutes(exp.entrada); if(mbE<=0)mbE+=24*60; contratualIntMin=_calcIntervaloMin(exp.intIni,exp.intFim,exp.entrada,exp.saida); if((emp.semRefeicao||is12x36)&&contratualIntMin===0&&mbE>360)contratualIntMin=60; prevMin=Math.max(0,mbE-contratualIntMin); }
    if(!ehFolga) diasPrevistosCnt++;
    const temBatida=!!(entrada&&saida);
    // HE = SÓ a AUTORIZADA — mesma fonte (_heMinDia) que o pagamento usa; HE não
    // aprovada na revisão não entra na apuração. Atraso/ref.não rendida seguem pelo déficit. #he-autorizada-folha
    if(temBatida){ out.extraMin += _heMinDia({...(_bat||{}), heReview: pd.heReview}, exp, _MCa); }
    if(!ehFolga&&temBatida){ const _ir=_calcIntervaloMin(intIni,intFim,entrada,saida); const delta=(is12x36||_usaFdsLivreResolve(emp.escala))?((minLiq+_ir)-(prevMin+contratualIntMin)):(minLiq-prevMin); if(delta<0&&Math.abs(delta)>HE_TOLERANCIA_DIA_MIN){ out.atrasoMin+=-delta; } const _nr=Math.max(0,contratualIntMin-_ir); out.naoRendMin+=(_nr>HE_TOLERANCIA_DIA_MIN?_nr:0); }   /* ref. não rendida só conta acima da tolerância 10min/dia (Súmula 366). #ref-tolerancia */
    else if(!ehFolga&&!temBatida&&temPonto&&_diaEmBrancoEhFalta(emp,cd.mes,cd.ano,d,isWknd,is12x36)){ out.faltaMin+=prevMin; out.faltaQtd++; }
    out.trabMin+=(minLiq>0?minLiq:0); out.prevMin+=prevMin;
    // Dia TRABALHADO (com batida) em que se cumpriu menos de 50% da jornada prevista —
    // base da regra rígida da Boa Permanência (decisão do dono 2026-06-26). #bp-rigida
    if(!ehFolga && temBatida && prevMin>0 && (minLiq>0?minLiq:0) < prevMin*0.5) out.diasAbaixoMeio++;
    // Refeição não rendida APROVADA pelo supervisor (pedido do app OU almoço suprimido
    // detectado pela batida e autorizado na revisão). NÃO paga sozinha — sempre passa pela
    // aprovação. semRefeicao (trabalha sozinho) recebe por naoRendMin (auto). #ref-nao-rendida-solicitada #ref-detectada
    if(pd.refExtra && pd.refExtra.status==='aprovado'){ out.naoRendAprovadoMin += (+pd.refExtra.min||0); }
  }
  // SEM ponto lançado no registro → NÃO conta todo dia previsto como falta (isso fazia
  // a contabilidade mostrar Faltas = Horas Previstas pra quem tem 0 faltas). Usa o nº de
  // faltas injustificadas SALVO (em horas, pela jornada média prevista). #fix-falta-sem-ponto
  if(!temPonto){
    let fInj = +(p.faltasInjustificadas||0);
    // Não pode haver mais faltas do que dias previstos DENTRO do vínculo. Quando o
    // período inteiro cai antes da admissão ou depois da demissão, diasPrevistosCnt=0
    // (o _getExpectedDay já recorta esses dias) → zera o número salvo, evitando falta
    // fantasma de mês já fora do contrato (ex.: demitido em maio com faltas em junho). #pos-demissao
    fInj = diasPrevistosCnt>0 ? Math.min(fInj, diasPrevistosCnt) : 0;
    out.faltaQtd = fInj;
    out.faltaMin = (fInj>0 && diasPrevistosCnt>0) ? Math.round(fInj*(out.prevMin/diasPrevistosCnt)) : 0;
  }
  return out;
}
// Minutos → "H:MM" (suporta > 24h)
function _minToHM(mm){ const x=Math.max(0,Math.round(mm||0)); return Math.floor(x/60)+':'+String(x%60).padStart(2,'0'); }

// Sobreposição (minutos) entre [a,b] e [c,d].
function _overlapMin(a,b,c,d){ return Math.max(0, Math.min(b,d)-Math.max(a,c)); }
// Apuração de horas NOTURNAS (CLT art. 73) a partir das batidas reais: minutos
// trabalhados na janela 22:00–05:00, descontando intervalo. noturnoHeMin = parte
// noturna que cai em HORA EXTRA (antes da entrada prevista ou após a saída prevista).
// Hora noturna REDUZIDA (52'30") aplicada quando empresa.contNoturnoReduzida!==false. #planilha-contador
function _apuracaoNoturnoTotais(emp,p){
  const out={noturnoMin:0, noturnoHeMin:0};
  if(!emp||!p) return out;
  if(emp.isentoPonto) return out;
  const dias=Array.isArray(p.pontoManualDias)?p.pontoManualDias:[];
  const nz=[[0,300],[1320,1740]];   // zonas noturnas: 00:00–05:00 e 22:00–(05:00 do dia seguinte)
  for(const cd of _compDias(p.mes,p.ano)){
    const d=cd.dia;
    const pd=dias.find(x=>x.dia===d)||{};
    const ent=pd.entrada||'', sai=pd.saida||'';
    if(!ent||!sai) continue;
    let ws=timeToMinutes(ent), we=timeToMinutes(sai); if(we<=ws) we+=1440;
    let nightDia=0; nz.forEach(z=>{ nightDia+=_overlapMin(ws,we,z[0],z[1]); });
    const ii=pd.intIni||'', iff=pd.intFim||'';
    if(ii&&iff){ let bs=timeToMinutes(ii), be=timeToMinutes(iff); if(bs<ws)bs+=1440; if(be<bs)be+=1440;
      nz.forEach(z=>{ nightDia-=_overlapMin(bs,be,z[0],z[1]); }); }
    out.noturnoMin+=Math.max(0,nightDia);
    // HE noturna (0237): trecho trabalhado fora da jornada prevista que cai na zona noturna.
    const exp=_getExpectedDay(emp,cd.mes,cd.ano,d);
    if(exp&&exp.entrada&&exp.saida){
      let es=timeToMinutes(exp.entrada), ee=timeToMinutes(exp.saida); if(ee<=es) ee+=1440;
      let heNight=0;
      if(we>ee){ const xs=Math.max(ws,ee); nz.forEach(z=>{ heNight+=_overlapMin(xs,we,z[0],z[1]); }); }
      if(ws<es){ const xe=Math.min(we,es); nz.forEach(z=>{ heNight+=_overlapMin(ws,xe,z[0],z[1]); }); }
      out.noturnoHeMin+=Math.max(0,heNight);
    }
  }
  const reduz=(State.empresa&&State.empresa.contNoturnoReduzida!==false);  // default ON (hora reduzida 52'30")
  if(reduz){ const f=60/52.5; out.noturnoMin=Math.round(out.noturnoMin*f); out.noturnoHeMin=Math.round(out.noturnoHeMin*f); }
  return out;
}
// Minutos → "HH:MM" (horas zero-padded — formato da planilha do contador). #planilha-contador
function _minToHHMM(mm){ const x=Math.max(0,Math.round(mm||0)); return String(Math.floor(x/60)).padStart(2,'0')+':'+String(x%60).padStart(2,'0'); }

// ============================================================
// PLANILHA CONTÁBIL (modelo do contador) — códigos das rubricas.
// Códigos padrão são os do sistema do contador; editáveis em
// Configurações/Contabilidade e persistidos em empresa.contCodigos. #planilha-contador
// ============================================================
const CONT_COD_DEFAULTS = {
  tipoCalculo:'11', adNot:'0219', heAdNot:'0237', he50:'0150', he100:'0200',
  dsrHe:'0083', vt:'0203', vr:'0209', atrasos:'0217', valeAvulso:'0214', emprestimo:'0218',
  faltas:'8792', acumulo:'0999', insalubridade:'0999', outros:'0999'
};
const CONT_COD_KEYS = ['tipoCalculo','adNot','heAdNot','he50','he100','dsrHe','vt','vr','atrasos','valeAvulso','emprestimo','faltas','acumulo','insalubridade','outros'];
function _contCod(k){ const c=(State.empresa&&State.empresa.contCodigos)||{}; return (c[k]!=null&&c[k]!=='')?String(c[k]):CONT_COD_DEFAULTS[k]; }

function _payrollScore(p){
  if(!p) return -1;
  const dias=Array.isArray(p.pontoManualDias)?p.pontoManualDias:[];
  const diasComBatida=dias.filter(d=>d&&(d.entrada||d.saida||d.intIni||d.intFim)).length;
  const valores=['valeTransporte','valeRefeicao','adiantamentoValor','adiantamento','insalubridade','acumuloFuncao','horasExtrasTotal']
    .reduce((s,k)=>s+(+p[k]>0?1:0),0);
  return (p.status==='fechada'?100000:0) + dias.length*1000 + diasComBatida*10 + valores;
}

function _buildFolhaMap(folhasMes){
  const map={};
  (folhasMes||[]).forEach(p=>{
    if(!p||!p.employeeId) return;
    const cur=map[p.employeeId];
    if(!cur || _payrollScore(p)>_payrollScore(cur)) map[p.employeeId]=p;
  });
  return map;
}

// Preenche os inputs do editor de códigos com os valores vigentes.
function _preencherContCodigos(){
  CONT_COD_KEYS.forEach(k=>{ const el=document.getElementById('contcod-'+k); if(el) el.value=_contCod(k); });
  const red=document.getElementById('cont-noturno-reduzida');
  if(red) red.checked=(State.empresa?.contNoturnoReduzida!==false);  // default ON
}
// Salva os códigos editados no doc empresa.
async function salvarContCodigos(){
  if(Auth.currentUser?.role!=='master'){ toast('Apenas o master pode alterar os códigos','error'); return; }
  const obj={};
  CONT_COD_KEYS.forEach(k=>{ const v=(val('contcod-'+k)||'').trim(); if(v) obj[k]=v; });
  const reduz=document.getElementById('cont-noturno-reduzida')?.checked!==false;
  try{
    await DB.saveDoc('configuracoes','empresa',{contCodigos:obj, contNoturnoReduzida:reduz},true);
    State.empresa = State.empresa||{}; State.empresa.contCodigos = obj; State.empresa.contNoturnoReduzida = reduz;
    toast('Códigos da planilha contábil salvos!','success');
    renderContabilidade();
  }catch(e){ toast('Erro ao salvar códigos: '+e.message,'error'); }
}
// Restaura os códigos padrão do contador.
function resetarContCodigos(){
  CONT_COD_KEYS.forEach(k=>{ const el=document.getElementById('contcod-'+k); if(el) el.value=CONT_COD_DEFAULTS[k]; });
  toast('Códigos padrão restaurados. Clique em Salvar para aplicar.','info');
}

// ===================== RESUMO DE ENCARGOS DA EMPRESA (por competência) =====================
// Consolida quanto RECOLHER no mês: INSS/IRRF retidos dos empregados + FGTS e — se o regime
// NÃO for Simples — os encargos PATRONAIS (INSS 20% + RAT×FAP + terceiros) sobre a base
// contributiva (totalBruto das folhas). Simples Nacional: CPP já no DAS → bloco patronal
// desligado. Regime/alíquotas configuráveis POR EMPRESA (multi-tenant). v1 = folha MENSAL
// (não inclui 13º/férias/rescisão — encargos próprios). #encargos
function _encParamsEmpresa(){
  const e=State.empresa||{};
  const num=(v,d)=>{ const n=parseFloat(v); return isFinite(n)?n:d; };
  return {
    regime:   e.regimeTributario || 'simples',
    patrAliq: num(e.encInssPatronalAliq,20),
    ratAliq:  num(e.encRatAliq,1),
    fap:      num(e.encFapFator,1)||1,
    terAliq:  num(e.encTerceirosAliq,5.8),
    esocialModo: e.esocialModo || 'exportar'
  };
}
function _resumoEncargosCompetencia(mes,ano){
  const folhasMes=State.payrolls.filter(p=>p.mes===mes && p.ano===ano);
  const folhaMap=_buildFolhaMap(folhasMes);   // dedup: pega o registro mais completo por colaborador
  const P=_encParamsEmpresa();
  const r={...P, headcount:0, base:0, inssRetido:0, irrfRetido:0, fgts:0, liquido:0,
           inssPatronal:0, rat:0, terceiros:0, gpsTotal:0, custoEmpregador:0, semValores:0, semValoresList:[]};
  Object.keys(folhaMap).forEach(id=>{
    const p=folhaMap[id]; if(!p) return;
    const base=+(p.totalBruto||0), inss=+(p.inss||0), irrf=+(p.irrf||0), fgts=+(p.fgts||0), liq=+(p.totalLiquidoFinal||0);
    r.headcount++;
    r.base+=base; r.inssRetido+=inss; r.irrfRetido+=irrf; r.fgts+=fgts; r.liquido+=liq;
    if(base<=0 && inss<=0 && fgts<=0){ r.semValores++;
      // Guarda quem está sem valores p/ o aviso clicável (abre a folha da pessoa). #alerta-clicavel
      const _e=(State.employees||[]).find(x=>x.id===id);
      r.semValoresList.push({ id, nome:(_e&&_e.nome)||p.employeeNome||'(sem nome)', reg:(_e&&_e.registro)||'' });
    }
  });
  r.semValoresList.sort((a,b)=>(a.nome||'').localeCompare(b.nome||''));
  if(P.regime!=='simples'){
    r.inssPatronal = r.base * P.patrAliq/100;
    r.rat          = r.base * (P.ratAliq*P.fap)/100;
    r.terceiros    = r.base * P.terAliq/100;
  }
  r.gpsTotal        = r.inssRetido + r.inssPatronal + r.rat + r.terceiros;     // INSS a recolher (GPS)
  r.custoEmpregador = r.base + r.inssPatronal + r.rat + r.terceiros + r.fgts;  // custo total ~ bruto + patronais + FGTS
  return r;
}
// Clique num nome do aviso "folhas sem valores": lembra a competência da Contabilidade p/
// voltar NELA depois de aplicar a folha, e abre a folha da pessoa. #contab-retorno-competencia
function _contAbrirFolha(empId, mes, ano){
  State._contReturn = { mes:+mes, ano:+ano };
  openPayrollForEmployee(empId, { mes:+mes, ano:+ano });
}
// Seleção múltipla + aplicar em LOTE as folhas "sem valores" — sem abrir uma por uma. #contab-aplicar-lote
function _contSelAll(on){ document.querySelectorAll('.cont-chk').forEach(c=>{ c.checked=!!on; }); }
function _contAplicarSelecionados(mes,ano){
  const ids=[...document.querySelectorAll('.cont-chk:checked')].map(c=>c.value);
  if(!ids.length){ toast('Marque ao menos um colaborador.','warning'); return; }
  _contAplicarLote(ids, mes, ano);
}
function _contAplicarTodos(mes,ano){
  const ids=[...document.querySelectorAll('.cont-chk')].map(c=>c.value);
  if(!ids.length){ toast('Nenhuma folha para aplicar.','warning'); return; }
  _contAplicarLote(ids, mes, ano);
}
// Reusa o MESMO cálculo da tela (onPayrollEmployeeChange+recalculate, síncronos) p/ cada folha,
// lê os encargos e persiste — igual abrir e clicar "Aplicar na Folha", mas em lote. #contab-aplicar-lote
async function _contAplicarLote(ids, mes, ano){
  mes=parseInt(mes)||parseInt(val('cont-mes'))||currentMes(); ano=parseInt(ano)||parseInt(val('cont-ano'))||currentAno();
  if(!ids||!ids.length) return;
  if(!confirm(`Aplicar a folha de ${ids.length} colaborador(es) em ${MESES[mes]}/${ano}?\n\nCalcula e grava os encargos (INSS/FGTS/bruto) de cada um de uma vez — igual abrir e clicar "Aplicar na Folha".`)) return;
  const _pEmp=val('payroll-employee'), _pMes=val('payroll-mes'), _pAno=val('payroll-ano');   // p/ restaurar o form
  setVal('payroll-mes',mes); setVal('payroll-ano',ano);
  let ok=0, pend=0, err=0;
  for(const empId of ids){
    try{
      if(typeof _ensurePayrollEmployeeOption==='function') _ensurePayrollEmployeeOption(empId);
      setVal('payroll-employee', empId);
      onPayrollEmployeeChange();   // carrega a folha do colaborador + recalcula (síncrono)
      recalculate();              // garante os encargos no DOM
      const bruto=numVal('payroll-total-bruto')||0;
      if(!(bruto>0)){ pend++; continue; }   // cadastro incompleto / sem base → não aplica
      const _enc={ totalBruto:bruto, inss:numVal('payroll-inss')||0, irrf:numVal('payroll-irrf')||0,
        fgts:numVal('payroll-fgts')||0, totalLiquidoFinal:numVal('payroll-total-liquido-final')||0, updatedAt:new Date().toISOString() };
      let _pf=(State.payrolls||[]).find(p=>p.employeeId===empId&&p.mes==mes&&p.ano==ano);
      const _existed=!!_pf; const id=_pf?_pf.id:_payrollId(empId,mes,ano);
      if(_pf) Object.assign(_pf,_enc); else { _pf={id,employeeId:empId,mes,ano,createdAt:new Date().toISOString(),..._enc}; (State.payrolls=State.payrolls||[]).push(_pf); }
      await DB.merge('payrolls', id, _existed?_enc:{employeeId:empId,mes,ano,createdAt:_pf.createdAt,..._enc});
      ok++;
    }catch(e){ console.error('aplicar lote', empId, e); err++; }
  }
  if(_pMes) setVal('payroll-mes',_pMes); if(_pAno) setVal('payroll-ano',_pAno);
  if(_pEmp){ setVal('payroll-employee',_pEmp); try{ onPayrollEmployeeChange(); }catch(_){} }
  try{ Auth.log('CONTAB_APLICAR_LOTE', null, `${MESES[mes]}/${ano} — ${ok} aplicada(s), ${pend} pendente(s), ${err} erro(s)`); }catch(_){}
  toast(`${ok} folha(s) aplicada(s)${pend?` · ${pend} com cadastro incompleto/sem base`:''}${err?` · ${err} erro(s)`:''}.`, ok?'success':'warning');
  renderContabilidade();
}
// HTML do resumo (reusado na tela e na impressão).
function _encargosResumoHtml(r,mes,ano){
  const simples = r.regime==='simples';
  const regimeLbl = simples ? 'Simples Nacional' : 'Lucro Presumido / Real';
  const money=v=>fmtMoney(v||0);
  const row=(lbl,vv,cor,sub)=>`<div style="display:flex;justify-content:space-between;align-items:baseline;padding:7px 0;border-bottom:1px solid #f0f0f0">
    <span style="color:#444">${lbl}${sub?` <small style="color:#999">${sub}</small>`:''}</span>
    <strong style="color:${cor||'#1a3a6b'};font-variant-numeric:tabular-nums">${money(vv)}</strong></div>`;
  const patronalBloco = simples ? `
    <div style="padding:10px 12px;background:#F1F8E9;border:1px solid #C5E1A5;border-radius:6px;font-size:12px;color:#33691E">
      <i class="fa-solid fa-circle-check"></i> <strong>Simples Nacional</strong>: a contribuição previdenciária patronal (CPP) já está embutida no DAS — não há INSS patronal/RAT/terceiros a recolher à parte. FGTS e retidos seguem normais.
    </div>` : `
    ${row(`INSS patronal`, r.inssPatronal, '#6A1B9A', `${r.patrAliq}%`)}
    ${row(`RAT / SAT`, r.rat, '#6A1B9A', `${r.ratAliq}%${r.fap!==1?` × FAP ${r.fap}`:''}`)}
    ${row(`Terceiros (Sistema S etc.)`, r.terceiros, '#6A1B9A', `${r.terAliq}%`)}`;
  return `
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:18px 28px">
      <div>
        <div style="font-weight:700;color:#1a3a6b;margin-bottom:4px;font-size:13px"><i class="fa-solid fa-sack-dollar"></i> Bases e retidos</div>
        ${row('Base de cálculo (folha bruta)', r.base, '#1a3a6b')}
        ${row('INSS retido dos empregados', r.inssRetido, '#B71C1C')}
        ${row('IRRF retido', r.irrfRetido, '#B71C1C')}
        ${row('FGTS a recolher', r.fgts, '#00695C', '8%')}
      </div>
      <div>
        <div style="font-weight:700;color:#6A1B9A;margin-bottom:4px;font-size:13px"><i class="fa-solid fa-building-columns"></i> Encargos patronais</div>
        ${patronalBloco}
      </div>
    </div>
    <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:12px;margin-top:16px">
      <div style="background:#EEF4FF;border:1px solid #C5CAE9;border-radius:8px;padding:12px;text-align:center">
        <div style="font-size:11px;color:#3949AB;text-transform:uppercase;letter-spacing:.5px">GPS — INSS a recolher</div>
        <div style="font-size:18px;font-weight:800;color:#1a3a6b;margin-top:3px">${money(r.gpsTotal)}</div>
        <div style="font-size:10px;color:#888">retido${simples?'':' + patronal + RAT + terceiros'}</div>
      </div>
      <div style="background:#E0F2F1;border:1px solid #80CBC4;border-radius:8px;padding:12px;text-align:center">
        <div style="font-size:11px;color:#00695C;text-transform:uppercase;letter-spacing:.5px">FGTS</div>
        <div style="font-size:18px;font-weight:800;color:#00695C;margin-top:3px">${money(r.fgts)}</div>
        <div style="font-size:10px;color:#888">8% sobre a base</div>
      </div>
      <div style="background:#FFF8E1;border:1px solid #FFE082;border-radius:8px;padding:12px;text-align:center">
        <div style="font-size:11px;color:#E65100;text-transform:uppercase;letter-spacing:.5px">Custo total empregador</div>
        <div style="font-size:18px;font-weight:800;color:#E65100;margin-top:3px">${money(r.custoEmpregador)}</div>
        <div style="font-size:10px;color:#888">bruto + patronais + FGTS</div>
      </div>
    </div>
    ${r.semValores>0?`<div style="margin-top:12px;padding:10px 12px;background:#FFEBEE;border:1px solid #EF9A9A;border-radius:6px;font-size:12px;color:#B71C1C">
      <i class="fa-solid fa-triangle-exclamation"></i> <strong>${r.semValores} folha(s)</strong> sem valores calculados (INSS/FGTS zerados). Marque e aplique em lote, ou clique no nome para abrir uma:
      <div style="display:flex;gap:8px;flex-wrap:wrap;align-items:center;margin:8px 0">
        <label style="display:flex;align-items:center;gap:5px;cursor:pointer;font-weight:600"><input type="checkbox" id="cont-sel-all" onchange="_contSelAll(this.checked)" style="width:auto;margin:0"> Selecionar todos</label>
        <button class="btn btn-sm" onclick="_contAplicarSelecionados(${mes},${ano})" style="background:#C62828;color:#fff;border:none;font-size:11px;padding:5px 12px;font-weight:700"><i class="fa-solid fa-check-double"></i> Aplicar selecionados</button>
        <button class="btn btn-sm" onclick="_contAplicarTodos(${mes},${ano})" style="background:#8E0000;color:#fff;border:none;font-size:11px;padding:5px 12px;font-weight:700"><i class="fa-solid fa-list-check"></i> Aplicar em todas (${r.semValores})</button>
      </div>
      <div style="display:flex;flex-wrap:wrap;gap:6px">
        ${(r.semValoresList||[]).map(c=>`<label style="display:inline-flex;align-items:center;gap:6px;background:#fff;border:1px solid #EF9A9A;border-radius:14px;padding:3px 10px;font-weight:600;white-space:nowrap">
          <input type="checkbox" class="cont-chk" value="${c.id}" style="width:auto;margin:0">
          <a href="javascript:void(0)" onclick="_contAbrirFolha('${c.id}',${mes},${ano})" title="Abrir a folha de ${esc(c.nome)}" style="color:#B71C1C;text-decoration:none">${c.reg?`<span style="opacity:.55">${esc(String(c.reg).padStart(4,'0'))}</span> `:''}${esc(c.nome)}</a>
        </label>`).join('')}
      </div>
    </div>`:''}
    <div style="margin-top:12px;font-size:11px;color:#999;line-height:1.5">
      <i class="fa-solid fa-circle-info"></i> Regime: <strong>${regimeLbl}</strong> · ${r.headcount} folha(s) na competência. Base contributiva = total bruto das folhas mensais; <strong>não inclui</strong> 13º, férias e rescisões (encargos próprios). Confira as alíquotas patronais (RAT/FAP/terceiros) com seu contador — variam por CNAE/FPAS.
    </div>`;
}
function _renderEncargosCard(mes,ano){
  const body=document.getElementById('cont-encargos-body');
  const card=document.getElementById('cont-encargos-card');
  if(!body||!card) return;
  const r=_resumoEncargosCompetencia(mes,ano);
  const titEl=document.getElementById('cont-encargos-titulo');
  if(titEl) titEl.textContent=`Resumo de Encargos — ${MESES[mes]}/${ano}`;
  body.innerHTML=_encargosResumoHtml(r,mes,ano);
  card.style.display = r.headcount>0 ? '' : 'none';
}
// --- Config do regime/alíquotas (por empresa) ---
function _preencherEncargosConfig(){
  const P=_encParamsEmpresa();
  setVal('enc-regime', P.regime);
  setVal('enc-inss-patronal', P.patrAliq);
  setVal('enc-rat', P.ratAliq);
  setVal('enc-fap', P.fap);
  setVal('enc-terceiros', P.terAliq);
  setVal('enc-esocial-modo', P.esocialModo);
  setVal('enc-classtrib', (State.empresa&&State.empresa.esocialClassTrib)||'');
  setVal('enc-contato-nome', (State.empresa&&State.empresa.esocialContatoNome)||'');
  setVal('enc-contato-cpf', (State.empresa&&State.empresa.esocialContatoCpf)||'');
  setVal('enc-cnpj-sindicato', (State.empresa&&State.empresa.cnpjSindicato)||'');
  _toggleEncargosAliq();
}
function _toggleEncargosAliq(){
  const simples=(val('enc-regime')||'simples')==='simples';
  const box=document.getElementById('enc-aliq-box');
  if(box){ box.style.opacity=simples?'0.45':'1'; box.style.pointerEvents=simples?'none':''; }
  const hint=document.getElementById('enc-simples-hint');
  if(hint) hint.style.display=simples?'':'none';
}
async function salvarEncargosConfig(){
  if(Auth.currentUser?.role!=='master'){ toast('Apenas o master pode alterar o regime/encargos','error'); return; }
  const num=(id,d)=>{ const n=parseFloat((val(id)||'').replace(',','.')); return isFinite(n)?n:d; };
  const dados={
    regimeTributario:    val('enc-regime')||'simples',
    encInssPatronalAliq: num('enc-inss-patronal',20),
    encRatAliq:          num('enc-rat',1),
    encFapFator:         num('enc-fap',1)||1,
    encTerceirosAliq:    num('enc-terceiros',5.8),
    esocialModo:         val('enc-esocial-modo')||'exportar',
    esocialClassTrib:    val('enc-classtrib')||'',
    esocialContatoNome:  val('enc-contato-nome')||'',
    esocialContatoCpf:   _soDigitos(val('enc-contato-cpf')),
    cnpjSindicato:       _soDigitos(val('enc-cnpj-sindicato'))
  };
  try{
    await DB.saveDoc('configuracoes','empresa',dados,true);
    State.empresa={ ...EMPRESA_DEFAULTS, ...(State.empresa||{}), ...dados };
    toast('Regime e encargos salvos!','success');
    renderContabilidade();
  }catch(e){ toast('Erro ao salvar encargos: '+e.message,'error'); }
}
function resetarEncargosConfig(){
  setVal('enc-regime', EMPRESA_DEFAULTS.regimeTributario);
  setVal('enc-inss-patronal', EMPRESA_DEFAULTS.encInssPatronalAliq);
  setVal('enc-rat', EMPRESA_DEFAULTS.encRatAliq);
  setVal('enc-fap', EMPRESA_DEFAULTS.encFapFator);
  setVal('enc-terceiros', EMPRESA_DEFAULTS.encTerceirosAliq);
  setVal('enc-esocial-modo', EMPRESA_DEFAULTS.esocialModo);
  setVal('enc-classtrib', EMPRESA_DEFAULTS.esocialClassTrib);
  setVal('enc-contato-nome', EMPRESA_DEFAULTS.esocialContatoNome);
  setVal('enc-contato-cpf', EMPRESA_DEFAULTS.esocialContatoCpf);
  setVal('enc-cnpj-sindicato', EMPRESA_DEFAULTS.cnpjSindicato);
  _toggleEncargosAliq();
  toast('Padrão restaurado. Clique em Salvar para aplicar.','info');
}
