// ===================== DEMONSTRATIVOS POR TRIBUTO (memória de cálculo) — FASE 2 =====================
// A guia OFICIAL com código de barras só sai do governo (DCTFWeb p/ INSS+IRRF, FGTS Digital
// p/ FGTS), alimentada pelo eSocial — não dá pra gerar fora. O que entregamos é o
// DEMONSTRATIVO/memória de cálculo por tributo, com quebra POR COLABORADOR, que o contador
// usa pra conferir e lançar. #encargos #demonstrativos
function _demonstrativoEncargosData(mes,ano){
  const folhasMes=State.payrolls.filter(p=>p.mes===mes && p.ano===ano);
  const folhaMap=_buildFolhaMap(folhasMes);
  const P=_encParamsEmpresa();
  const rows=[];
  Object.keys(folhaMap).forEach(id=>{
    const p=folhaMap[id]; if(!p) return;
    const e=State.employees.find(x=>x.id===id)||{};
    rows.push({
      id, nome:(e.nome||p.employeeName||'—'),
      reg:(e.registro?String(e.registro).padStart(4,'0'):'—'),
      base:+(p.totalBruto||0), inss:+(p.inss||0), irrf:+(p.irrf||0), fgts:+(p.fgts||0)
    });
  });
  rows.sort((a,b)=>a.nome.localeCompare(b.nome));
  const T={base:0,inss:0,irrf:0,fgts:0};
  rows.forEach(r=>{ T.base+=r.base; T.inss+=r.inss; T.irrf+=r.irrf; T.fgts+=r.fgts; });
  const isSimples=P.regime==='simples';
  const patronal  = isSimples?0:T.base*P.patrAliq/100;
  const rat       = isSimples?0:T.base*(P.ratAliq*P.fap)/100;
  const terceiros = isSimples?0:T.base*P.terAliq/100;
  const prevTotal = T.inss + patronal + rat + terceiros;
  return {P,isSimples,rows,T,patronal,rat,terceiros,prevTotal};
}
function _demonstrativoEncargosHtml(mes,ano){
  const d=_demonstrativoEncargosData(mes,ano);
  const e=State.empresa||{};
  const {P,isSimples,rows,T,patronal,rat,terceiros,prevTotal}=d;
  const money=v=>fmtMoney(v||0);
  const th=(t,al)=>`<th style="text-align:${al||'left'};padding:5px 8px;border:1px solid #cfd8e3;background:#eef4ff;font-size:11px">${t}</th>`;
  const td=(t,al,bold)=>`<td style="text-align:${al||'left'};padding:4px 8px;border:1px solid #e3e8ef;font-size:11px${bold?';font-weight:700':''}">${t}</td>`;
  // tabela por colaborador: Colaborador | Cód | Base | <valor>
  const tabela=(valLbl,getVal,onlyNonZero)=>{
    const rr=onlyNonZero?rows.filter(r=>getVal(r)>0):rows;
    if(!rr.length) return '<p style="color:#999;font-size:12px;margin:6px 0">Nenhum valor nesta competência.</p>';
    const body=rr.map(r=>`<tr>${td(esc(r.nome))}${td(r.reg,'center')}${td(money(r.base),'right')}${td(money(getVal(r)),'right')}</tr>`).join('');
    const tBase=rr.reduce((s,r)=>s+r.base,0), tVal=rr.reduce((s,r)=>s+getVal(r),0);
    return `<table style="border-collapse:collapse;width:100%;margin-top:6px">
      <thead><tr>${th('Colaborador')}${th('Cód.','center')}${th('Remuneração base (R$)','right')}${th(valLbl+' (R$)','right')}</tr></thead>
      <tbody>${body}</tbody>
      <tfoot><tr>${td('TOTAL — '+rr.length+' colaborador(es)','left',true)}${td('','center')}${td(money(tBase),'right',true)}${td(money(tVal),'right',true)}</tr></tfoot>
    </table>`;
  };
  const memRow=(lbl,vv,sub,strong)=>`<tr${strong?' style="border-top:2px solid #1a3a6b"':''}><td style="padding:${strong?'5':'3'}px 8px;color:${strong?'#1a3a6b':'#444'};font-weight:${strong?'800':'400'}">${lbl}${sub?` <small style="color:#999;font-weight:400">${sub}</small>`:''}</td><td style="padding:${strong?'5':'3'}px 8px;text-align:right;font-weight:${strong?'800':'600'};color:${strong?'#1a3a6b':'#222'};font-variant-numeric:tabular-nums">${money(vv)}</td></tr>`;
  const secStyle='page-break-inside:avoid;margin-bottom:26px';
  const h2=(t,cor)=>`<h2 style="font-size:15px;color:${cor};border-bottom:2px solid ${cor};padding-bottom:4px;margin:0 0 8px">${t}</h2>`;
  // 1) PREVIDÊNCIA (INSS)
  const prevMem=`<table style="border-collapse:collapse;min-width:360px;margin-bottom:6px">
    ${memRow('INSS segurados (retido dos empregados)',T.inss)}
    ${isSimples?'':memRow('INSS patronal',patronal,P.patrAliq+'%')}
    ${isSimples?'':memRow('RAT / SAT',rat,P.ratAliq+'%'+(P.fap!==1?' × FAP '+P.fap:''))}
    ${isSimples?'':memRow('Terceiros (Sistema S, Sal-Educação…)',terceiros,P.terAliq+'%')}
    ${memRow('Total previdenciário a recolher',prevTotal,'',true)}
  </table>
  ${isSimples?'<div style="font-size:11px;color:#33691E;background:#F1F8E9;border:1px solid #C5E1A5;border-radius:6px;padding:8px 10px;margin-bottom:6px"><b>Simples Nacional:</b> a contribuição patronal (CPP) está no DAS. Recolhe-se à parte apenas o <b>INSS retido dos empregados</b> (via DCTFWeb/DARF).</div>':'<div style="font-size:11px;color:#666;margin-bottom:6px">Recolhimento via <b>DCTFWeb → DARF previdenciário</b> (alimentado pelo eSocial).</div>'}`;
  const secPrev=`<div style="${secStyle}">${h2('1. Previdência (INSS)','#1a3a6b')}${prevMem}${tabela('INSS segurado',r=>r.inss,false)}</div>`;
  // 2) FGTS
  const fgtsMem=`<table style="border-collapse:collapse;min-width:360px;margin-bottom:6px">
    ${memRow('Base FGTS (remuneração)',T.base)}
    ${memRow('FGTS a depositar',T.fgts,'8%',true)}
  </table>
  <div style="font-size:11px;color:#666;margin-bottom:6px">Depósito via <b>FGTS Digital</b> (guia com QR Code/PIX gerada pelo sistema, a partir do eSocial).</div>`;
  const secFgts=`<div style="${secStyle}">${h2('2. FGTS','#00695C')}${fgtsMem}${tabela('FGTS 8%',r=>r.fgts,false)}</div>`;
  // 3) IRRF
  const irrfMem=`<table style="border-collapse:collapse;min-width:360px;margin-bottom:6px">
    ${memRow('IRRF retido na fonte',T.irrf,'DARF 0561',true)}
  </table>
  <div style="font-size:11px;color:#666;margin-bottom:6px">Recolhimento via <b>DCTFWeb → DARF (código 0561)</b>. A base legal do IRRF é a remuneração líquida de INSS, dependentes, pensão e plano de saúde (difere da remuneração bruta).</div>`;
  const secIrrf=`<div style="${secStyle}">${h2('3. IRRF (Imposto de Renda Retido na Fonte)','#B71C1C')}${irrfMem}${tabela('IRRF retido',r=>r.irrf,true)}</div>`;
  return `<!DOCTYPE html><html lang="pt-BR"><head><meta charset="UTF-8"><title>Demonstrativos de Encargos ${MESES[mes]}/${ano}</title>
  <style>body{font-family:Arial,Helvetica,sans-serif;color:#222;padding:24px;max-width:900px;margin:0 auto}h1{font-size:18px;color:#1a3a6b;margin:0 0 2px}small{color:#666}@media print{.noprint{display:none}}</style>
  </head><body>
  <div style="display:flex;align-items:center;gap:14px;border-bottom:2px solid #e8f0fe;padding-bottom:12px;margin-bottom:18px">
    <img src="${_logoSrc()}" style="height:42px;object-fit:contain" onerror="this.style.display='none'">
    <div><h1>${esc(e.nomeEmpresa||'Empresa')}</h1><small>${esc(e.cnpj||'')} · Demonstrativos de Encargos (memória de cálculo) — ${MESES[mes]}/${ano} · Regime: ${isSimples?'Simples Nacional':'Lucro Presumido/Real'}</small></div>
  </div>
  ${secPrev}${secFgts}${secIrrf}
  <div style="margin-top:14px;font-size:10px;color:#999;border-top:1px solid #eee;padding-top:8px">Documento de CONFERÊNCIA (memória de cálculo) — não é guia de arrecadação. As guias oficiais (DARF/FGTS Digital) são emitidas pelos sistemas do governo a partir do eSocial. Base mensal; não inclui 13º, férias e rescisões. Gerado em ${new Date().toLocaleString('pt-BR')} · DRG-Kronos</div>
  </body></html>`;
}
function _imprimirDemonstrativosEncargos(){
  const mes=parseInt(val('cont-mes')||currentMes());
  const ano=parseInt(val('cont-ano')||currentAno());
  const d=_demonstrativoEncargosData(mes,ano);
  if(!d.rows.length){ toast('Sem folhas nesta competência.','warning'); return; }
  const win=window.open('','_blank');
  if(!win){ toast('Permita pop-ups para imprimir.','warning'); return; }
  win.document.write(_demonstrativoEncargosHtml(mes,ano));
  win.document.close();
  setTimeout(()=>{ try{win.print();}catch(_){}} ,500);
}

// ===================== eSOCIAL — DIAGNÓSTICO DE PRONTIDÃO (Fase 3b, passo 1) =====================
// ~90% das rejeições do eSocial são por DADO CADASTRAL faltando/inválido (CPF, PIS, CBO…),
// não por erro de XML. Antes de gerar qualquer evento, este diagnóstico confere empresa +
// colaboradores contra o que o eSocial exige e lista o que falta. 100% seguro (não transmite).
// É a base p/ os eventos (S-1000/S-2200/S-1200) saírem aceitos. #esocial
function _soDigitos(s){ return String(s||'').replace(/\D/g,''); }
function _cpfValido(cpf){
  cpf=_soDigitos(cpf); if(cpf.length!==11 || /^(\d)\1{10}$/.test(cpf)) return false;
  let s=0; for(let i=0;i<9;i++) s+=(+cpf[i])*(10-i); let d=(s*10)%11; if(d===10)d=0; if(d!==+cpf[9]) return false;
  s=0; for(let i=0;i<10;i++) s+=(+cpf[i])*(11-i); d=(s*10)%11; if(d===10)d=0; return d===+cpf[10];
}
function _pisValido(pis){
  pis=_soDigitos(pis); if(pis.length!==11) return false;
  const w=[3,2,9,8,7,6,5,4,3,2]; let s=0; for(let i=0;i<10;i++) s+=(+pis[i])*w[i];
  let d=11-(s%11); if(d>=10)d=0; return d===+pis[10];
}
function _cnpjValido(cnpj){
  cnpj=_soDigitos(cnpj); if(cnpj.length!==14 || /^(\d)\1{13}$/.test(cnpj)) return false;
  const calc=base=>{ const len=base.length; let pos=len-7,sum=0;
    for(let i=len;i>=1;i--){ sum+=(+base[len-i])*(pos--); if(pos<2)pos=9; }
    const r=sum%11; return r<2?0:11-r; };
  if(calc(cnpj.slice(0,12))!==+cnpj[12]) return false;
  return calc(cnpj.slice(0,13))===+cnpj[13];
}
function _esocialParams(){
  const e=State.empresa||{};
  return {
    tpAmb:String(e.esocialTpAmb||'2'),
    classTrib:(e.esocialClassTrib||'').trim(),
    regime:_encParamsEmpresa().regime,
    cnpj:_soDigitos(e.cnpj),
    modo:(e.esocialModo||'exportar'),
    contatoNome:(e.esocialContatoNome||'').trim(),
    contatoCpf:_soDigitos(e.esocialContatoCpf),
    verProc:(e.esocialVerProc||'DRG-Kronos').trim()
  };
}
function _esocialPendenciasEmpresa(){
  const e=State.empresa||{}; const Q=_esocialParams(); const f=[];
  if(Q.cnpj.length!==14) f.push('CNPJ (14 dígitos)');
  if(!Q.classTrib) f.push('Classificação tributária (eSocial)');
  if(!e.cnae) f.push('CNAE');
  if(!e.cep || !e.uf) f.push('Endereço (CEP/UF)');
  if(!Q.contatoNome) f.push('Nome do responsável/contato');
  if(!_cpfValido(Q.contatoCpf)) f.push('CPF do responsável/contato');
  return f;
}
// CNPJ do sindicato da categoria: usa o do colaborador; se vazio, cai no padrão da empresa. #esocial
function _cnpjSindEmp(e){ return _soDigitos((e&&e.cnpjSindicato)||'') || _soDigitos((State.empresa&&State.empresa.cnpjSindicato)||''); }
function _esocialPendenciasColab(e){
  const f=[];
  if(!e.cpf || !_cpfValido(e.cpf)) f.push('CPF inválido/ausente');
  if(!e.pisNit || !_pisValido(e.pisNit)) f.push('PIS/NIT inválido/ausente');
  if(!e.dataNascimento) f.push('Data de nascimento');
  if(!e.dataAdmissao) f.push('Data de admissão');
  if(!(e.salarioBase>0)) f.push('Salário base');
  if(!e.cargoCBO) f.push('CBO');
  if(!(e.cargo||e.setor)) f.push('Cargo');
  if(!e.sexo) f.push('Sexo');
  if(!e.raca) f.push('Raça/cor');
  if(!e.grauInstrucao) f.push('Grau de instrução');
  if(!e.nomeMae) f.push('Nome da mãe');
  if(!e.cep || !e.endereco) f.push('Endereço');
  if(_soDigitos(e.codMunicipio).length!==7) f.push('Cód. IBGE município (reabrir CEP)');
  if(!_cnpjValido(_cnpjSindEmp(e))) f.push('CNPJ do sindicato');
  return f;
}
function _renderEsocialDiagnostico(){
  const card=document.getElementById('esocial-diag-card');
  const body=document.getElementById('esocial-diag-body');
  if(!card || !body) return;
  const empPend=_esocialPendenciasEmpresa();
  const emps=_filtrarEmpsPorEscopo(State.employees).filter(e=>(e.status||'ativo')==='ativo').slice().sort((a,b)=>a.nome.localeCompare(b.nome));
  let prontos=0;
  const linhas=emps.map(e=>{
    const p=_esocialPendenciasColab(e); if(!p.length) prontos++;
    const ok=!p.length;
    return `<tr>
      <td style="padding:5px 8px;border:1px solid #e3e8ef">${esc(e.nome)}</td>
      <td style="padding:5px 8px;border:1px solid #e3e8ef;text-align:center;white-space:nowrap">${ok?'<span style="color:#1B5E20;font-weight:700">✓ Pronto</span>':`<span style="color:#B71C1C;font-weight:700">${p.length} pend.</span>`}</td>
      <td style="padding:5px 8px;border:1px solid #e3e8ef;font-size:11px;color:#B71C1C">${ok?'<span style="color:#bbb">—</span>':esc(p.join(' · '))}</td>
      <td style="padding:5px 8px;border:1px solid #e3e8ef;text-align:center;white-space:nowrap">${ok?`<button class="btn btn-outline btn-sm" style="padding:2px 8px;font-size:11px;border-color:#1a3a6b;color:#1a3a6b" onclick="_gerarEsocialS2200('${e.id}')" title="Gerar o S-2200 (admissão) de ${esc(e.nome)}"><i class="fa-solid fa-download"></i> S-2200</button> <button class="btn btn-outline btn-sm" style="padding:2px 8px;font-size:11px;border-color:#00695C;color:#00695C" onclick="_gerarEsocialS1200('${e.id}')" title="Gerar o S-1200 (remuneração) de ${esc(e.nome)} na competência selecionada"><i class="fa-solid fa-download"></i> S-1200</button>`:'<span style="color:#bbb">—</span>'}</td>
    </tr>`;
  }).join('');
  const empOk=empPend.length===0;
  const tabela=emps.length? `<table style="border-collapse:collapse;width:100%;margin-top:8px">
    <thead><tr>
      <th style="text-align:left;padding:5px 8px;border:1px solid #cfd8e3;background:#eef4ff;font-size:11px">Colaborador</th>
      <th style="text-align:center;padding:5px 8px;border:1px solid #cfd8e3;background:#eef4ff;font-size:11px">Situação</th>
      <th style="text-align:left;padding:5px 8px;border:1px solid #cfd8e3;background:#eef4ff;font-size:11px">O que falta (eSocial)</th>
      <th style="text-align:center;padding:5px 8px;border:1px solid #cfd8e3;background:#eef4ff;font-size:11px">Evento</th>
    </tr></thead><tbody>${linhas}</tbody></table>` : '<p style="color:#999;font-size:12px">Nenhum colaborador ativo.</p>';
  body.innerHTML=`
    <div style="display:flex;gap:12px;flex-wrap:wrap;margin-bottom:10px">
      <div style="flex:1;min-width:200px;background:${empOk?'#E8F5E9':'#FFEBEE'};border:1px solid ${empOk?'#A5D6A7':'#EF9A9A'};border-radius:8px;padding:10px 12px">
        <div style="font-weight:700;color:${empOk?'#1B5E20':'#B71C1C'};font-size:13px"><i class="fa-solid fa-building"></i> Empresa — ${empOk?'pronta':'pendências'}</div>
        <div style="font-size:12px;color:${empOk?'#33691E':'#B71C1C'};margin-top:3px">${empOk?'CNPJ, classTrib, CNAE e endereço OK.':esc(empPend.join(' · '))}</div>
      </div>
      <div style="flex:1;min-width:200px;background:#EEF4FF;border:1px solid #C5CAE9;border-radius:8px;padding:10px 12px">
        <div style="font-weight:700;color:#1a3a6b;font-size:13px"><i class="fa-solid fa-users"></i> Colaboradores ativos</div>
        <div style="font-size:12px;color:#3949AB;margin-top:3px"><strong>${prontos}/${emps.length}</strong> prontos · <strong style="color:#B71C1C">${emps.length-prontos}</strong> com pendência</div>
      </div>
    </div>
    ${tabela}
    <div style="margin-top:12px;padding-top:10px;border-top:1px dashed #e0e0e0">
      <div style="font-weight:700;color:#1a3a6b;font-size:13px;margin-bottom:6px"><i class="fa-solid fa-file-code"></i> Gerar eventos (XML)</div>
      <button class="btn btn-outline btn-sm" ${empOk?'':'disabled'} onclick="_gerarEsocialS1000()" style="${empOk?'border-color:#1a3a6b;color:#1a3a6b':''}" title="${empOk?'Gera o XML do S-1000 (dados do empregador)':'Corrija as pendências da empresa primeiro'}"><i class="fa-solid fa-building"></i> Gerar S-1000 (empregador)</button>
      <button class="btn btn-outline btn-sm" ${empOk?'':'disabled'} onclick="_gerarEsocialS1005()" style="${empOk?'border-color:#1a3a6b;color:#1a3a6b':''}" title="${empOk?'Gera o XML do S-1005 (estabelecimento — CNAE/RAT/FAP)':'Corrija as pendências da empresa primeiro'}"><i class="fa-solid fa-location-dot"></i> Gerar S-1005 (estabelecimento)</button>
      <button class="btn btn-primary btn-sm" ${empOk?'':'disabled'} onclick="_gerarLoteEsocial()" title="${empOk?'Empacota TODOS os eventos da competência (tabelas + admissões + remunerações dos prontos) num lote único':'Corrija as pendências da empresa primeiro'}"><i class="fa-solid fa-box-archive"></i> Gerar lote da competência</button>
      <div style="font-size:11px;color:#999;margin-top:6px">Ambiente: <b>produção restrita</b> (tpAmb=2). Valide os XMLs no eSocial antes da produção. Próximos eventos (S-2200 admissão, S-1200 remuneração) exigem dados extras: código IBGE do município, sindicato e tabela de horários/rubricas.</div>
    </div>
    <div style="margin-top:10px;font-size:11px;color:#999;line-height:1.5"><i class="fa-solid fa-circle-info"></i> Conferência de cadastro p/ o eSocial (CPF/PIS validados com dígito verificador). Corrija as pendências no cadastro de cada colaborador (e em Configurações, a empresa) antes de gerar os eventos.</div>`;
  card.style.display='';
}

// --- Geração de XML do eSocial (helpers + S-1000) — Fase 3b, passo 2 ---
function _xmlEsc(s){ return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&apos;'); }
function _baixarArquivo(nome, conteudo, mime){
  const blob=new Blob([conteudo],{type:(mime||'text/plain')+';charset=utf-8'});
  const url=URL.createObjectURL(blob);
  const a=document.createElement('a'); a.href=url; a.download=nome;
  document.body.appendChild(a); a.click(); document.body.removeChild(a); URL.revokeObjectURL(url);
}
function _esocialTS(){ const d=new Date(); const p=n=>String(n).padStart(2,'0'); return ''+d.getFullYear()+p(d.getMonth()+1)+p(d.getDate())+p(d.getHours())+p(d.getMinutes())+p(d.getSeconds()); }
// Id do evento: ID + tpInsc(1) + nrInsc(14, zero-pad p/ CNPJ) + aaaammddhhmmss + sequencial(5) = 36 chars.
let _esocialSeq=0;
function _esocialId(nrInsc14){ _esocialSeq=(_esocialSeq%99999)+1; return 'ID1'+String(nrInsc14).padStart(14,'0')+_esocialTS()+String(_esocialSeq).padStart(5,'0'); }
// S-1000 (evtInfoEmpregador) — leiaute S-1.3 (namespace v_S_01_03_00). Estrutura mínima de
// INCLUSÃO p/ empresa (tpInsc=1/CNPJ). Gerado em produção RESTRITA (tpAmb=2) — validar no
// eSocial antes de produção. indPertIRRF/dadosIsencao/infoOrgInternacional não incluídos
// (aplicáveis a naturezas/regimes específicos — ajustar com o contador). #esocial
function _esocialEventoS1000(competenciaISO){
  const e=State.empresa||{}; const Q=_esocialParams();
  const cnpj14=Q.cnpj.padStart(14,'0');
  const raiz=cnpj14.slice(0,8);
  const id=_esocialId(cnpj14);
  const iniValid=competenciaISO || (new Date().toISOString().slice(0,7));
  const fone=_soDigitos(e.telefone).slice(0,13);
  const email=(e.email||'').slice(0,60);
  const linhasContato=[
    `        <nmCtt>${_xmlEsc((Q.contatoNome||'').slice(0,70))}</nmCtt>`,
    `        <cpfCtt>${Q.contatoCpf}</cpfCtt>`,
    fone?`        <foneFixo>${fone}</foneFixo>`:'',
    email?`        <email>${_xmlEsc(email)}</email>`:''
  ].filter(Boolean).join('\n');
  return `<?xml version="1.0" encoding="UTF-8"?>
<eSocial xmlns="http://www.esocial.gov.br/schema/evt/evtInfoEmpregador/v_S_01_03_00">
  <evtInfoEmpregador Id="${id}">
    <ideEvento>
      <tpAmb>${Q.tpAmb}</tpAmb>
      <procEmi>1</procEmi>
      <verProc>${_xmlEsc(Q.verProc)}</verProc>
    </ideEvento>
    <ideEmpregador>
      <tpInsc>1</tpInsc>
      <nrInsc>${raiz}</nrInsc>
    </ideEmpregador>
    <infoEmpregador>
      <inclusao>
        <idePeriodo>
          <iniValid>${iniValid}</iniValid>
        </idePeriodo>
        <infoCadastro>
          <classTrib>${_xmlEsc(Q.classTrib)}</classTrib>
          <indCoop>0</indCoop>
          <indConstr>0</indConstr>
          <indDesFolha>0</indDesFolha>
          <indOptRegEletron>1</indOptRegEletron>
          <indEntEd>N</indEntEd>
          <indEtt>N</indEtt>
          <contato>
${linhasContato}
          </contato>
        </infoCadastro>
      </inclusao>
    </infoEmpregador>
  </evtInfoEmpregador>
</eSocial>`;
}
function _gerarEsocialS1000(){
  if(Auth.currentUser?.role!=='master'){ toast('Apenas o master pode gerar eventos do eSocial','error'); return; }
  const pend=_esocialPendenciasEmpresa();
  if(pend.length){ toast('Complete os dados da empresa antes: '+pend.join(' · '),'error'); return; }
  const mes=parseInt(val('cont-mes')||currentMes());
  const ano=parseInt(val('cont-ano')||currentAno());
  const compISO=`${ano}-${String(mes).padStart(2,'0')}`;
  const xml=_esocialEventoS1000(compISO);
  const cnpj=_soDigitos((State.empresa||{}).cnpj);
  _baixarArquivo(`S-1000_${cnpj}_${compISO}.xml`, xml, 'application/xml');
  toast('S-1000 gerado (produção restrita). Valide no eSocial antes de transmitir.','success');
}
// S-1005 (evtTabEstab) — tabela de estabelecimentos. Reaproveita CNAE + RAT/FAP da config
// de encargos. aliqGilrat: aliqRat (1/2/3) × FAP = aliqRatAjust. Leiaute S-1.3, produção
// restrita. Em Simples com GILRAT substituído, ajustar com o contador. #esocial
function _esocialEventoS1005(competenciaISO){
  const e=State.empresa||{}; const Q=_esocialParams(); const P=_encParamsEmpresa();
  const cnpj14=Q.cnpj.padStart(14,'0');
  const raiz=cnpj14.slice(0,8);
  const id=_esocialId(cnpj14);
  const iniValid=competenciaISO || (new Date().toISOString().slice(0,7));
  const cnae7=_soDigitos(e.cnae).slice(0,7);
  const aliqRat=String(Math.round(P.ratAliq)||1);
  const fap=(P.fap||1).toFixed(2);
  const aliqAjust=((Math.round(P.ratAliq)||1)*(P.fap||1)).toFixed(2);
  return `<?xml version="1.0" encoding="UTF-8"?>
<eSocial xmlns="http://www.esocial.gov.br/schema/evt/tabelas/evtTabEstab/v_S_01_03_00">
  <evtTabEstab Id="${id}">
    <ideEvento>
      <tpAmb>${Q.tpAmb}</tpAmb>
      <procEmi>1</procEmi>
      <verProc>${_xmlEsc(Q.verProc)}</verProc>
    </ideEvento>
    <ideEmpregador>
      <tpInsc>1</tpInsc>
      <nrInsc>${raiz}</nrInsc>
    </ideEmpregador>
    <infoEstab>
      <inclusao>
        <ideEstab>
          <tpInsc>1</tpInsc>
          <nrInsc>${cnpj14}</nrInsc>
          <iniValid>${iniValid}</iniValid>
        </ideEstab>
        <dadosEstab>
          <cnaePrep>${cnae7}</cnaePrep>
          <aliqGilrat>
            <aliqRat>${aliqRat}</aliqRat>
            <fap>${fap}</fap>
            <aliqRatAjust>${aliqAjust}</aliqRatAjust>
          </aliqGilrat>
        </dadosEstab>
      </inclusao>
    </infoEstab>
  </evtTabEstab>
</eSocial>`;
}
function _gerarEsocialS1005(){
  if(Auth.currentUser?.role!=='master'){ toast('Apenas o master pode gerar eventos do eSocial','error'); return; }
  const pend=_esocialPendenciasEmpresa();
  if(pend.length){ toast('Complete os dados da empresa antes: '+pend.join(' · '),'error'); return; }
  const e=State.empresa||{};
  if(_soDigitos(e.cnae).length<7){ toast('CNAE incompleto (precisa de 7 dígitos) para o S-1005.','error'); return; }
  const mes=parseInt(val('cont-mes')||currentMes());
  const ano=parseInt(val('cont-ano')||currentAno());
  const compISO=`${ano}-${String(mes).padStart(2,'0')}`;
  const xml=_esocialEventoS1005(compISO);
  const cnpj=_soDigitos(e.cnpj);
  _baixarArquivo(`S-1005_${cnpj}_${compISO}.xml`, xml, 'application/xml');
  toast('S-1005 gerado (produção restrita). Valide no eSocial.','success');
}
// --- S-2200 (evtAdmissao) — converte os campos de TEXTO do cadastro p/ os CÓDIGOS do
// eSocial e monta a admissão. Leiaute S-1.3, produção restrita. Estrutura mínima de
// empregado CLT urbano; horContratual usa 44h/sem padrão + tpJornada pela escala. Ajustar
// jornada/sindicato/categoria especiais com o contador. #esocial
function _esocialSexo(s){ s=(s||'').toLowerCase(); if(s.indexOf('masc')===0)return 'M'; if(s.indexOf('fem')===0)return 'F'; return ''; }
function _esocialRaca(r){ const m={'branca':'1','preta':'2','parda':'3','amarela':'4','indígena':'5','indigena':'5','não declarado':'6','nao declarado':'6'}; return m[(r||'').toLowerCase()]||'6'; }
function _esocialGrauInstr(g){ const m={'analfabeto':'01','fundamental':'05','médio':'07','medio':'07','técnico':'07','tecnico':'07','superior':'09','pós-graduação':'10','pos-graduacao':'10','mestrado':'11','doutorado':'12'}; return m[(g||'').toLowerCase()]||''; }
function _esocialTpJornada(escala){ const fam=escalaFamilia(escala||'5x2A'); if(fam==='12x36')return '2'; if(fam==='6x1')return '3'; return '1'; }
function _addDiasISO(iso, dias){ const d=new Date((iso||'').slice(0,10)+'T00:00:00'); if(isNaN(d.getTime()))return ''; d.setDate(d.getDate()+dias); const p=n=>String(n).padStart(2,'0'); return d.getFullYear()+'-'+p(d.getMonth()+1)+'-'+p(d.getDate()); }
function _esocialEventoS2200(emp){
  const Q=_esocialParams();
  const cnpj14=Q.cnpj.padStart(14,'0'); const raiz=cnpj14.slice(0,8);
  const id=_esocialId(cnpj14);
  const exper=(emp.tipoContrato==='experiencia');
  const dtAdm=(emp.dataAdmissao||'').slice(0,10);
  const dtTerm=exper?_addDiasISO(dtAdm,(parseInt(emp.expPeriodo1)||45)):'';
  const compl=(emp.complemento||'').trim();
  const linhaCompl=compl?`\n            <complemento>${_xmlEsc(compl.slice(0,30))}</complemento>`:'';
  const linhaDtTerm=dtTerm?`\n            <dtTerm>${dtTerm}</dtTerm>`:'';
  return `<?xml version="1.0" encoding="UTF-8"?>
<eSocial xmlns="http://www.esocial.gov.br/schema/evt/admissao/v_S_01_03_00">
  <evtAdmissao Id="${id}">
    <ideEvento>
      <indRetif>1</indRetif>
      <tpAmb>${Q.tpAmb}</tpAmb>
      <procEmi>1</procEmi>
      <verProc>${_xmlEsc(Q.verProc)}</verProc>
    </ideEvento>
    <ideEmpregador>
      <tpInsc>1</tpInsc>
      <nrInsc>${raiz}</nrInsc>
    </ideEmpregador>
    <trabalhador>
      <cpfTrab>${_soDigitos(emp.cpf)}</cpfTrab>
      <nmTrab>${_xmlEsc((emp.nome||'').slice(0,70))}</nmTrab>
      <sexo>${_esocialSexo(emp.sexo)}</sexo>
      <racaCor>${_esocialRaca(emp.raca)}</racaCor>
      <grauInstr>${_esocialGrauInstr(emp.grauInstrucao)}</grauInstr>
      <nascimento>
        <dtNascto>${(emp.dataNascimento||'').slice(0,10)}</dtNascto>
        <paisNascto>105</paisNascto>
        <paisNac>105</paisNac>
      </nascimento>
      <endereco>
        <brasil>
          <dscLograd>${_xmlEsc((emp.endereco||'').slice(0,80))}</dscLograd>
          <nrLograd>${_xmlEsc(String(emp.numero||'S/N').slice(0,10))}</nrLograd>${linhaCompl}
          <bairro>${_xmlEsc((emp.bairro||'').slice(0,90))}</bairro>
          <cep>${_soDigitos(emp.cep)}</cep>
          <codMunic>${_soDigitos(emp.codMunicipio)}</codMunic>
          <uf>${emp.estado||''}</uf>
        </brasil>
      </endereco>
    </trabalhador>
    <vinculo>
      <matricula>${_xmlEsc(emp.registro?String(emp.registro):'')}</matricula>
      <tpRegTrab>1</tpRegTrab>
      <tpRegPrev>1</tpRegPrev>
      <cadIni>N</cadIni>
      <infoRegimeTrab>
        <infoCeletista>
          <dtAdm>${dtAdm}</dtAdm>
          <tpAdmissao>1</tpAdmissao>
          <indAdmissao>1</indAdmissao>
          <tpRegJor>1</tpRegJor>
          <natAtividade>1</natAtividade>
          <cnpjSindCategProf>${_cnpjSindEmp(emp)}</cnpjSindCategProf>
        </infoCeletista>
      </infoRegimeTrab>
      <infoContrato>
        <nmCargo>${_xmlEsc((emp.cargo||emp.setor||'').slice(0,100))}</nmCargo>
        <CBOCargo>${_soDigitos(emp.cargoCBO)}</CBOCargo>
        <codCateg>${emp.categoriaESocial||'101'}</codCateg>
        <remuneracao>
          <vrSalFx>${(+emp.salarioBase||0).toFixed(2)}</vrSalFx>
          <undSalFixo>5</undSalFixo>
        </remuneracao>
        <duracao>
          <tpContr>${exper?'2':'1'}</tpContr>${linhaDtTerm}
        </duracao>
        <localTrabalho>
          <localTrabGeral>
            <tpInsc>1</tpInsc>
            <nrInsc>${cnpj14}</nrInsc>
          </localTrabGeral>
        </localTrabalho>
        <horContratual>
          <qtdHrsSem>44</qtdHrsSem>
          <tpJornada>${_esocialTpJornada(emp.escala)}</tpJornada>
          <tmpParc>0</tmpParc>
        </horContratual>
      </infoContrato>
    </vinculo>
  </evtAdmissao>
</eSocial>`;
}
function _gerarEsocialS2200(empId){
  if(Auth.currentUser?.role!=='master'){ toast('Apenas o master pode gerar eventos do eSocial','error'); return; }
  const emp=State.employees.find(e=>e.id===empId); if(!emp){ toast('Colaborador não encontrado.','error'); return; }
  const ep=_esocialPendenciasEmpresa();
  if(ep.length){ toast('Complete os dados da empresa antes: '+ep.join(' · '),'error'); return; }
  const pend=_esocialPendenciasColab(emp);
  if(pend.length){ toast('Complete o cadastro de '+(emp.nome||'')+': '+pend.join(' · '),'error'); return; }
  const xml=_esocialEventoS2200(emp);
  _baixarArquivo(`S-2200_${_soDigitos(emp.cpf)}.xml`, xml, 'application/xml');
  toast('S-2200 de '+(emp.nome||'')+' gerado (produção restrita). Valide no eSocial.','success');
}

// ===================== S-1010 (tabela de RUBRICAS) — base do S-1200 =====================
// O eSocial classifica cada verba por uma NATUREZA (Tabela 3) + incidências (INSS/IRRF/FGTS).
// Esses códigos dependem do enquadramento → o contador confirma. Aqui o mapa é EDITÁVEL:
// pré-preenchemos descrição/tipo/código; natureza e incidências o usuário completa. #esocial
const ESOCIAL_RUBR_BASE=[
  {key:'salario',  desc:'Salário base',                 tp:'1'},
  {key:'he50',     desc:'Horas extras 50%',             tp:'1'},
  {key:'he100',    desc:'Horas extras 100%',            tp:'1'},
  {key:'adnot',    desc:'Adicional noturno',            tp:'1'},
  {key:'dsrhe',    desc:'DSR sobre horas extras',       tp:'1'},
  {key:'insal',    desc:'Adicional de insalubridade',   tp:'1'},
  {key:'acumulo',  desc:'Acúmulo de função',            tp:'1'},
  {key:'vr',       desc:'Vale refeição/alimentação',    tp:'1'},
  {key:'desinss',  desc:'Desconto INSS',                tp:'2'},
  {key:'desirrf',  desc:'Desconto IRRF',                tp:'2'},
  {key:'desvt',    desc:'Desconto vale-transporte',     tp:'2'},
  {key:'desfalta', desc:'Desconto de faltas/DSR',       tp:'2'},
  {key:'desatraso',desc:'Desconto de atrasos',          tp:'2'}
];
function _esocialRubricasMap(){
  const stored=(State.empresa&&State.empresa.esocialRubricas)||{};
  return ESOCIAL_RUBR_BASE.map((b,i)=>{
    const s=stored[b.key]||{};
    return { key:b.key, desc:b.desc, tp:s.tp||b.tp, cod:s.cod||String(i+1),
             nat:s.nat||'', cp:s.cp||'00', ir:s.ir||'00', fg:s.fg||'00' };
  });
}
