function renderHistoricoSalario(hist){
  const wrap=document.getElementById('historico-salario-wrap');
  const listEl=document.getElementById('historico-salario-list');
  if(!wrap||!listEl) return;
  if(!hist||hist.length===0){ wrap.style.display='none'; return; }
  wrap.style.display='';
  const sorted=[...hist].sort((a,b)=>b.data.localeCompare(a.data)).slice(0,6);
  listEl.innerHTML=sorted.map((h,i)=>`
    <div style="display:flex;justify-content:space-between;padding:4px 0;border-bottom:1px solid var(--border)">
      <span>${formatDateBr(h.data)}</span>
      <span style="font-weight:600;color:var(--success)">${fmtMoney(h.valor)}</span>
      ${i===0?'<span class="badge badge-success" style="font-size:10px">Atual</span>':'<span></span>'}
    </div>
  `).join('');
}

// ============================================
// EXPORTAR RELATÓRIO CSV
// ============================================
function exportReportCsv(){
  if(_currentReportType==='beneficios'){ _exportBeneficiosCsv(); return; }
  const mes=parseInt(val('report-mes')), ano=parseInt(val('report-ano'));
  if(!mes||!ano){ toast('Gere o relatório primeiro.','warning'); return; }
  const records=State.payrolls.filter(p=>p.mes===mes&&p.ano===ano);
  // Filtra por status conforme seleção (padrão: todos)
  const statusFilt = val('report-status-filter') || 'all';
  const todosEmps=[...State.employees]
    .filter(e => statusFilt === 'all' || (e.status||'ativo') === statusFilt)
    .sort((a,b)=>(a.nome||'').localeCompare(b.nome));
  if(todosEmps.length===0){ toast('Nenhum colaborador cadastrado.','warning'); return; }
  const cols=['Nº','Nome','Posto','Escala','Dias Trabalhados','Faltas','Remuneração (R$)',
    'VT (R$)','VR (R$)','VA Líquido (R$)','Adic. Noturno (R$)','Bonificação (R$)','Chave PIX'];
  const rows=[cols.join(';')];
  todosEmps.forEach((emp,i)=>{
    const p=records.find(r=>r.employeeId===emp.id)||{};
    const nome=emp.nome||'—';
    const posto=emp.posto||'—';
    const escala=escalaLabel(emp.escala||'5x2A');
    const pix=emp.chavePix||'—';
    // Força texto no Excel: se PIX for numérico, usa ="valor" para evitar notação científica
    const pixCsv = (pix !== '—' && /^[\d\s().+\-]+$/.test(pix)) ? `="${pix}"` : pix;
    const totalFaltas='faltasJustificadas' in p?(p.faltasJustificadas||0)+(p.faltasInjustificadas||0):(p.faltas||0);
    const num=String(emp.registro||'').padStart(4,'0')||String(i+1);
    rows.push([num,nome,posto,escala,p.diasTrabalhados||0,totalFaltas,
      (p.remuneracao||0).toFixed(2),(p.valeTransporte||0).toFixed(2),
      (p.valeRefeicao||0).toFixed(2),(p.valeAlimentacaoLiquido||0).toFixed(2),
      (p.adNoturno||0).toFixed(2),(p.bonificacao||0).toFixed(2),pixCsv].join(';'));
  });
  const blob=new Blob(['﻿'+rows.join('\n')],{type:'text/csv;charset=utf-8'});
  const url=URL.createObjectURL(blob);
  const a=document.createElement('a');
  a.href=url; a.download=`DRGlobal_relatorio_${MESES[mes]}_${ano}.csv`;
  document.body.appendChild(a); a.click(); document.body.removeChild(a); URL.revokeObjectURL(url);
  toast('Relatório exportado em CSV!');
}

// CSV da Folha de Benefícios (VT, VR, VA, Bonificação)
function _exportBeneficiosCsv(){
  const mes=parseInt(val('report-benef-mes')), ano=parseInt(val('report-benef-ano'));
  if(!mes||!ano){ toast('Gere o relatório primeiro.','warning'); return; }
  const folha=val('report-benef-folha')||'consolidado';
  const statusFilter=val('report-benef-status')||'ativo';
  let emps=_filtrarEmpsPorEscopo(State.employees).slice();
  if(statusFilter!=='all') emps=emps.filter(e=>(e.status||'ativo')===statusFilter);
  emps.sort((a,b)=>(a.nome||'').localeCompare(b.nome||'','pt-BR'));
  const linhas=emps.map(e=>{
    const p=State.payrolls.find(r=>r.employeeId===e.id&&r.mes===mes&&r.ano===ano);
    return {emp:e,temFolha:!!p,
      vt:p?(p.valeTransporte||0):0, vr:p?(p.valeRefeicao||0):0,
      va:p?(p.valeAlimentacaoLiquido||0):0, bon:p?(p.bonificacao||0):0};
  });
  let cols, rowFn;
  if(folha==='consolidado'){
    cols=['Nº','Colaborador','Setor','Posto','Escala','VT (R$)','VR (R$)','VA (R$)','Bonificação (R$)','Total (R$)','Folha Lançada'];
    rowFn=(l,i)=>[i+1,l.emp.nome||'—',l.emp.setor||'—',l.emp.posto||'—',escalaLabel(l.emp.escala||'5x2A'),
      l.vt.toFixed(2),l.vr.toFixed(2),l.va.toFixed(2),l.bon.toFixed(2),(l.vt+l.vr+l.va+l.bon).toFixed(2),l.temFolha?'Sim':'Não'];
  } else if(folha==='vales'){
    cols=['Nº','Colaborador','Setor','Posto','VT (R$)','VR (R$)','VA (R$)','Total Vales (R$)','Folha Lançada'];
    rowFn=(l,i)=>[i+1,l.emp.nome||'—',l.emp.setor||'—',l.emp.posto||'—',
      l.vt.toFixed(2),l.vr.toFixed(2),l.va.toFixed(2),(l.vt+l.vr+l.va).toFixed(2),l.temFolha?'Sim':'Não'];
  } else {
    const cfg={
      vt:{lbl:'Vale-Transporte (R$)',pick:l=>l.vt},
      vr:{lbl:'Vale-Refeição (R$)',pick:l=>l.vr},
      va:{lbl:'Vale-Alimentação (R$)',pick:l=>l.va},
      bonificacao:{lbl:'Bonificação (R$)',pick:l=>l.bon}
    }[folha];
    const quintaLbl=folha==='bonificacao'?'Chave PIX':'Escala';
    cols=['Nº','Colaborador','Setor','Posto',quintaLbl,cfg.lbl,'Folha Lançada'];
    rowFn=(l,i)=>{
      const q=folha==='bonificacao'?(l.emp.chavePix||'—'):escalaLabel(l.emp.escala||'5x2A');
      return [i+1,l.emp.nome||'—',l.emp.setor||'—',l.emp.posto||'—',q,cfg.pick(l).toFixed(2),l.temFolha?'Sim':'Não'];
    };
  }
  const csvCell=v=>{ const s=String(v); return /[;"\n]/.test(s)?`"${s.replace(/"/g,'""')}"`:s; };
  const rows=[cols.join(';')];
  linhas.forEach((l,i)=>rows.push(rowFn(l,i).map(csvCell).join(';')));
  const blob=new Blob(['﻿'+rows.join('\n')],{type:'text/csv;charset=utf-8'});
  const url=URL.createObjectURL(blob);
  const a=document.createElement('a');
  a.href=url; a.download=`DRGlobal_beneficios_${folha}_${MESES[mes]}_${ano}.csv`;
  document.body.appendChild(a); a.click(); document.body.removeChild(a); URL.revokeObjectURL(url);
  toast('Folha de benefícios exportada em CSV!');
}

// ============================================
// COLABORADORES — CRUD
// ============================================
function setEmployeeFilter(filter){
  State.employeeFilter = filter;
  // Limpa a busca ao trocar o filtro de status (evita 0 resultados por conflito)
  const searchEl=document.getElementById('employee-search');
  if(searchEl) searchEl.value='';
  document.querySelectorAll('.status-filter-btn').forEach(btn=>{
    btn.classList.toggle('active', btn.dataset.filter === filter);
  });
  renderEmployeeTable();
}

// ── Filtros avançados de Colaboradores (painel flutuante) ───
function toggleEmpFiltros(){
  const panel=document.getElementById('emp-filtros-panel'); if(!panel) return;
  const abrir = panel.style.display==='none' || !panel.style.display;
  if(abrir){
    _popularEmpFiltros();
    panel.style.display='block';
    setTimeout(()=>document.addEventListener('click',_empFiltrosClickFora),0);
  } else {
    panel.style.display='none';
    document.removeEventListener('click',_empFiltrosClickFora);
  }
}
function _empFiltrosClickFora(e){
  const wrap=document.querySelector('.emp-filtros-wrap');
  if(wrap && !wrap.contains(e.target)){
    const panel=document.getElementById('emp-filtros-panel');
    if(panel) panel.style.display='none';
    document.removeEventListener('click',_empFiltrosClickFora);
  }
}
function _popularEmpFiltros(){
  const f=State.empFilters||{};
  const distintos=(campo)=>[...new Set((State.employees||[])
    .map(e=>(e[campo]||'').toString().trim()).filter(Boolean))]
    .sort((a,b)=>a.localeCompare(b,'pt-BR'));
  const fill=(id,vals,cur,labelFn)=>{
    const sel=document.getElementById(id); if(!sel) return;
    sel.innerHTML='<option value="">Todos</option>'+vals.map(v=>{
      const esc=String(v).replace(/"/g,'&quot;');
      return `<option value="${esc}">${labelFn?labelFn(v):v}</option>`;
    }).join('');
    sel.value=cur||'';
  };
  fill('filtro-posto',  distintos('posto'),  f.posto);
  fill('filtro-setor',  distintos('setor'),  f.setor);
  fill('filtro-escala', distintos('escala'), f.escala, v=>escalaLabel(v));
  const turnoSel=document.getElementById('filtro-turno');
  if(turnoSel) turnoSel.value=f.turno||'';
}
function aplicarEmpFiltros(){
  State.empFilters={
    posto:  val('filtro-posto')||'',
    setor:  val('filtro-setor')||'',
    escala: val('filtro-escala')||'',
    turno:  val('filtro-turno')||'',
  };
  _updateEmpFiltrosBadge();
  renderEmployeeTable();
}
function limparEmpFiltros(){
  State.empFilters={posto:'',setor:'',escala:'',turno:''};
  ['filtro-posto','filtro-setor','filtro-escala','filtro-turno'].forEach(id=>{
    const s=document.getElementById(id); if(s) s.value='';
  });
  _updateEmpFiltrosBadge();
  renderEmployeeTable();
}
function _updateEmpFiltrosBadge(){
  const f=State.empFilters||{};
  const n=['posto','setor','escala','turno'].filter(k=>f[k]).length;
  const badge=document.getElementById('emp-filtros-count');
  if(badge){ badge.textContent=n; badge.style.display=n?'inline-flex':'none'; }
  const btn=document.getElementById('btn-emp-filtros');
  if(btn) btn.classList.toggle('active', n>0);
}

function statusBadge(status){
  const s = status||'ativo';
  if(s==='ativo')               return '<span class="badge badge-status-ativo">Ativo</span>';
  if(s==='inativo')             return '<span class="badge badge-status-inativo">Inativo</span>';
  if(s==='afastado')            return '<span class="badge badge-status-afastado">Afastado INSS</span>';
  if(s==='licenca-maternidade') return '<span class="badge" style="background:#FCE4EC;color:#C2185B;font-weight:700">Lic. Maternidade</span>';
  return `<span class="badge badge-muted">${s}</span>`;
}

function renderEmployeeTable(){
  const query=(document.getElementById('employee-search')?.value||'').toLowerCase();
  // Aplica o escopo de postos do usuário (supervisor responsável por N postos)
  // ANTES de qualquer outro filtro — assim a contagem e os filtros visíveis já
  // refletem só o universo do usuário.
  let list=_filtrarEmpsPorEscopo(State.employees);
  if(query) list=list.filter(e=>
    (e.nome||'').toLowerCase().includes(query)||
    (e.cpf||'').toLowerCase().includes(query)||
    (e.rg||'').toLowerCase().includes(query)||
    (e.posto||'').toLowerCase().includes(query)||
    (e.setor||'').toLowerCase().includes(query)||
    String(e.registro||'').includes(query)
  );
  if(State.employeeFilter!=='all') list=list.filter(e=>(e.status||'ativo')===State.employeeFilter);
  // Filtros avançados (painel "Filtros")
  const ef=State.empFilters||{};
  if(ef.posto)  list=list.filter(e=>(e.posto||'')===ef.posto);
  if(ef.setor)  list=list.filter(e=>(e.setor||'')===ef.setor);
  if(ef.escala) list=list.filter(e=>(e.escala||'')===ef.escala);
  if(ef.turno)  list=list.filter(e=>{ const not=!!e.turnoNoturno; return ef.turno==='noturno'?not:!not; });
  const tbody=document.getElementById('employee-tbody');
  const empty=document.getElementById('employee-empty');
  const countEl=document.getElementById('employee-count');
  // Total visível = total dentro do escopo do usuário (não o State.employees inteiro)
  const totalNoEscopo=_filtrarEmpsPorEscopo(State.employees).length;
  countEl.textContent=`${list.length} de ${totalNoEscopo} colaborador${totalNoEscopo!==1?'es':''}`;
  if(list.length===0){
    tbody.innerHTML=''; document.getElementById('employee-table').style.display='none';
    empty.style.display=''; return;
  }
  document.getElementById('employee-table').style.display=''; empty.style.display='none';
  const isLicenca = State.employeeFilter === 'licenca-maternidade';
  const podeAvulso = !!getUserModules(Auth.currentUser).pagamentosLancar;
  const podeComunicar = !!getUserModules(Auth.currentUser).employees || Auth.currentUser?.role === 'master';
  const podeRevisar = !!getUserModules(Auth.currentUser).revisarContrato; // master ou autorizado
  tbody.innerHTML=list.map((e)=>{
    const celularLimpo=(e.celular||'').replace(/\D/g,'');
    // Selo "contrato revisado" (só conferência — não trava nada). Só quem tem
    // permissão revisarContrato pode marcar/desmarcar. Guarda quem revisou + quando.
    const _rev=e.contratoRevisado;
    let revCell;
    if(_rev && _rev.em){
      const _tt=`Revisado por ${(_rev.porNome||_rev.por||'—')} em ${new Date(_rev.em).toLocaleDateString('pt-BR')}`;
      revCell = podeRevisar
        ? `<span onclick="toggleContratoRevisado('${e.id}')" title="${_tt} · clique para DESMARCAR" style="cursor:pointer;color:#2E7D32;font-size:17px"><i class="fa-solid fa-square-check"></i></span>`
        : `<span title="${_tt}" style="color:#2E7D32;font-size:17px"><i class="fa-solid fa-square-check"></i></span>`;
    } else {
      revCell = podeRevisar
        ? `<span onclick="toggleContratoRevisado('${e.id}')" title="Marcar contrato como REVISADO" style="cursor:pointer;color:#9E9E9E;font-size:17px"><i class="fa-regular fa-square"></i></span>`
        : `<span title="Sem permissão para revisar contratos" style="color:#CFD8DC;font-size:17px"><i class="fa-regular fa-square"></i></span>`;
    }
    const whatsBtn=celularLimpo?`<button class="btn-icon btn-whatsapp-icon" onclick="openWhatsApp('${celularLimpo}','${e.nome.split(' ')[0]}')" title="WhatsApp"><i class="fa-brands fa-whatsapp"></i></button>`:'';
    const nomeSafe=(e.nome||'').replace(/"/g,'&quot;');
    const postoSafe=(e.posto||'').replace(/"/g,'&quot;');
    return `<tr onclick="openEmployeeModal('${e.id}')" style="cursor:pointer" title="Abrir cadastro de ${nomeSafe}">
      <td><span class="badge badge-muted">${e.registro?String(e.registro).padStart(4,'0'):'—'}</span></td>
      <td style="max-width:260px"><div style="display:flex;align-items:center;gap:8px;min-width:0">
        ${e.fotoUrl?`<img src="${e.fotoUrl}" class="emp-table-photo" alt="">`:`<div class="emp-table-initials">${initials(e.nome)}</div>`}
        <span class="td-name" style="overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="${nomeSafe}">${e.nome}</span>
      </div></td>
      <td>${statusBadge(e.status)}</td>
      <td style="max-width:300px"><span style="font-size:12px;color:var(--text-muted);display:block;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="${postoSafe}">${e.posto||'—'}</span></td>
      <td onclick="event.stopPropagation()" style="text-align:center">${revCell}</td>
      <td onclick="event.stopPropagation()"><div class="actions-cell">
        ${whatsBtn}
        <button class="btn-icon btn-primary-icon" onclick="openPayrollForEmployee('${e.id}')" title="Lançar Folha"><i class="fa-solid fa-file-invoice-dollar"></i></button>
        ${podeAvulso?`<button class="btn-icon" style="color:#00695C" onclick="openPagamentoAvulsoModal('${e.id}')" title="Pagamento avulso"><i class="fa-solid fa-money-bill-wave"></i></button>`:''}
        ${podeComunicar?`<button class="btn-icon" style="color:#1976D2" onclick="openComunicarModal('${e.id}')" title="Enviar mensagem"><i class="fa-solid fa-envelope"></i></button>`:''}
        <button class="btn-icon btn-warning-icon" onclick="openEmployeeModal('${e.id}')" title="Editar"><i class="fa-solid fa-pencil"></i></button>
        <button class="btn-icon btn-danger-icon" onclick="confirmDeleteEmployee('${e.id}')" title="Excluir"><i class="fa-solid fa-trash"></i></button>
      </div></td>
    </tr>`;
  }).join('');
}

// Selo "contrato revisado" — só conferência (não trava nada). Marca/desmarca com
// registro de quem revisou e quando. Gated pela permissão revisarContrato. #contrato-revisado
async function toggleContratoRevisado(empId){
  if(!getUserModules(Auth.currentUser).revisarContrato){
    toast('Você não tem permissão para revisar contratos.','error'); return;
  }
  const emp=(State.employees||[]).find(e=>e.id===empId);
  if(!emp){ toast('Colaborador não encontrado.','error'); return; }
  const u=Auth.currentUser||{};
  const jaRev=!!(emp.contratoRevisado && emp.contratoRevisado.em);
  if(jaRev){
    if(!confirm(`Desmarcar a revisão do contrato de ${emp.nome}?\n(revisado por ${emp.contratoRevisado.porNome||emp.contratoRevisado.por||'—'})`)) return;
    emp.contratoRevisado = null;
  } else {
    emp.contratoRevisado = { por: u.username||u.id||'', porNome: u.username||u.nome||'', em: new Date().toISOString() };
  }
  emp.updatedAt=new Date().toISOString();
  try{
    await DB.merge('employees', empId, { contratoRevisado: emp.contratoRevisado, updatedAt: emp.updatedAt });
    try{ Auth.log && Auth.log(jaRev?'CONTRATO_REVISAO_REMOVIDA':'CONTRATO_REVISADO', null, emp.nome); }catch(_){}
    renderEmployeeTable();
    toast(jaRev?'Revisão removida.':`Contrato de ${(emp.nome||'').split(' ')[0]} marcado como revisado.`,'success');
  }catch(e){ console.error('toggleContratoRevisado',e); toast('Erro ao salvar.','error'); }
}

function onDemissaoChange(){
  const demissao=val('emp-data-demissao');
  if(demissao){ setVal('emp-status','inativo'); }
}

function onEscalaChange(userChanged){
  const escala=val('emp-escala');
  const is12=(escalaFamilia(escala)==='12x36');
  const isAlt=(typeof escala==='string' && escala.startsWith('6x1ALT'));
  const row=document.getElementById('turno-noturno-row');
  if(row) row.style.display=is12?'':'none';
  const rowCiclo=document.getElementById('row-ciclo-12x36');
  if(rowCiclo) rowCiclo.style.display=is12?'':'none';
  const rowAlt=document.getElementById('row-alternada-folga');
  if(rowAlt) rowAlt.style.display=isAlt?'':'none';
  // Escala do sistema com horário fixo: já preenche entrada/saída/refeição e o
  // turno noturno conforme a variante.
  // Os horários (entrada/saída/refeição) são do CONTRATO. Na ABERTURA do cadastro NÃO os
  // tocamos — a JORNADA SEGUE O CONTRATO, sem autonomia. O preenchimento pelo padrão da
  // escala só ocorre quando o GESTOR troca a escala no seletor (conveniência) e NUNCA
  // apaga a refeição já definida (12x36 não tem refeição padrão → mantém a do contrato). #jornada-segue-contrato
  if(!userChanged) return;
  const def=ESCALA_HORARIOS_DEFAULT[escala];
  if(def && _escalaFixa(escala)){
    setVal('emp-horario-entrada', def.entrada);
    setVal('emp-horario-saida', def.saida);
    if(def.intIni) setVal('emp-horario-ref-ini', def.intIni);   // só preenche se a escala TEM refeição padrão; não zera o contrato
    if(def.intFim) setVal('emp-horario-ref-fim', def.intFim);
    const nt=document.getElementById('emp-turno-noturno');
    if(nt) nt.checked=_escala12x36Noturna(escala);
  }
}

function onEmpStatusChange(){
  const status=val('emp-status');
  const rowLic=document.getElementById('row-licenca-maternidade');
  if(rowLic) rowLic.style.display=(status==='licenca-maternidade')?'':'none';
}

// Isento de controle de jornada (CLT Art. 62) — mostra a dica e esmaece
// os campos de escala/horário (ficam irrelevantes: não há controle de ponto).
function onIsentoPontoChange(){
  const chk = document.getElementById('emp-isento-ponto');
  if(!chk) return;
  const isento = chk.checked;
  const hint = document.getElementById('emp-isento-ponto-hint');
  if(hint) hint.style.display = isento ? '' : 'none';
  // Esmaece (não desabilita — o gestor ainda pode preencher por referência)
  ['emp-escala','emp-horario-entrada','emp-horario-saida','emp-horario-ref-ini','emp-horario-ref-fim']
    .forEach(id => { const el=document.getElementById(id); if(el){ el.style.opacity = isento ? '.5' : '1'; } });
}

// Habilita/desabilita os inputs de horário de refeição conforme flag "semRefeicao"
function onSemRefeicaoChange(){
  const chk=document.getElementById('emp-sem-refeicao');
  const ini=document.getElementById('emp-horario-ref-ini');
  const fim=document.getElementById('emp-horario-ref-fim');
  if(!chk) return;
  const sem=chk.checked;
  if(ini){ ini.disabled=sem; if(sem) ini.value=''; ini.style.opacity=sem?'.45':'1'; }
  if(fim){ fim.disabled=sem; if(sem) fim.value=''; fim.style.opacity=sem?'.45':'1'; }
}

function _toggleOpcaoLicencaMaternidade(mostrar){
  const opt=document.getElementById('opt-licenca-maternidade');
  if(!opt) return;
  opt.style.display=mostrar?'':'none';
  // Se estiver escondendo e estava selecionada, volta para 'ativo'
  if(!mostrar && val('emp-status')==='licenca-maternidade'){
    setVal('emp-status','ativo');
    onEmpStatusChange();
  }
}

function getNextRegistro(){
  if(State.employees.length===0) return 1;
  const max=State.employees.reduce((m,e)=>Math.max(m,parseInt(e.registro)||0),0);
  return max+1;
}

// ============================================
// ENCARGOS & IRRF — LISTAS DINÂMICAS
// ============================================
// Autocomplete do catálogo de Rubricas no campo de descrição dos "Outros Proventos/Descontos".
// Sugere as rubricas do tipo certo (D→descontos, P→proventos) com o código como dica —
// padroniza os nomes sem travar a digitação livre. #rubricas-bridge
function _rubricasDatalistHtml(tipo){
  const t = tipo==='proventos' ? 'P' : 'D';
  const opts=(State.rubricas||[]).filter(r=>r.ativa!==false && r.tipo===t && !r.fixaTodos)
    .sort((a,b)=>(a.descricao||'').localeCompare(b.descricao||''))
    .map(r=>`<option value="${esc(r.descricao||'')}">${r.codigo?('cód. '+esc(r.codigo)):''}</option>`).join('');
  return `<datalist id="rubricas-dl-${tipo}">${opts}</datalist>`;
}
function renderOutrosItens(items, tipo){
  const container=document.getElementById(`emp-outros-${tipo}`);
  if(!container) return;
  container.innerHTML=_rubricasDatalistHtml(tipo)+(items||[]).map((item,i)=>`
    <div class="outro-item-row" id="${tipo}-row-${i}">
      <input type="text" list="rubricas-dl-${tipo}" placeholder="Descrição (ex: Adiantamento salarial)" value="${(item.descricao||'').replace(/"/g,'&quot;')}" id="${tipo}-desc-${i}">
      <input type="number" placeholder="0,00" value="${item.valor||0}" min="0" step="0.01" id="${tipo}-val-${i}">
      <button type="button" class="btn-icon btn-danger-icon" onclick="removeOutroItem('${tipo}',${i})" title="Remover">
        <i class="fa-solid fa-xmark"></i>
      </button>
    </div>`).join('');
}

function addOutroItem(tipo){
  const container=document.getElementById(`emp-outros-${tipo}`);
  if(!container) return;
  const idx=container.querySelectorAll('.outro-item-row').length;
  const row=document.createElement('div');
  row.className='outro-item-row';
  row.id=`${tipo}-row-${idx}`;
  row.innerHTML=`
    <input type="text" list="rubricas-dl-${tipo}" placeholder="Descrição" id="${tipo}-desc-${idx}">
    <input type="number" placeholder="0,00" min="0" step="0.01" id="${tipo}-val-${idx}">
    <button type="button" class="btn-icon btn-danger-icon" onclick="removeOutroItem('${tipo}',${idx})" title="Remover">
      <i class="fa-solid fa-xmark"></i>
    </button>`;
  container.appendChild(row);
  row.querySelector('input[type="text"]').focus();
}

function removeOutroItem(tipo, idx){
  const row=document.getElementById(`${tipo}-row-${idx}`);
  if(row) row.remove();
}

function collectOutrosItens(tipo){
  const container=document.getElementById(`emp-outros-${tipo}`);
  if(!container) return [];
  return Array.from(container.querySelectorAll('.outro-item-row')).map(row=>{
    const inputs=row.querySelectorAll('input');
    const descricao=(inputs[0]?.value||'').trim();
    const valor=parseFloat(inputs[1]?.value)||0;
    return descricao?{descricao,valor}:null;
  }).filter(Boolean);
}

// ── Empréstimos / Consignados (recorrente) ── #consignado-recorrente
// Cada consignado guarda: tipo (privado/público), origem (banco/órgão), parcela,
// nº total de parcelas e a competência de início. A parcela do mês é CALCULADA
// (não decrementa um contador gravado) → auto-corretiva, nunca perde a referência.
function _consignadoRowHtml(it){
  it=it||{};
  const ini=(it.inicioAno && it.inicioMes)?`${it.inicioAno}-${String(it.inicioMes).padStart(2,'0')}`:'';
  const _v=v=>String(v==null?'':v).replace(/"/g,'&quot;');
  return `<div class="consig-row" style="display:flex;gap:6px;align-items:center;flex-wrap:wrap;border:1px solid var(--border);border-radius:8px;padding:7px 8px">
    <select class="cg-tipo" style="padding:7px;border:1px solid var(--border);border-radius:6px;font-size:12px">
      <option value="privado"${it.tipo!=='publico'?' selected':''}>Privado (banco)</option>
      <option value="publico"${it.tipo==='publico'?' selected':''}>Público / Gov</option>
    </select>
    <input type="text" class="cg-origem" placeholder="Banco / órgão" value="${_v(it.origem)}" style="flex:1;min-width:110px;padding:7px;border:1px solid var(--border);border-radius:6px;font-size:12px">
    <input type="number" class="cg-parcela" placeholder="Parcela R$" min="0" step="0.01" value="${it.parcela||''}" style="width:108px;padding:7px;border:1px solid var(--border);border-radius:6px;font-size:12px" title="Valor da parcela mensal">
    <input type="number" class="cg-num" placeholder="Nº parc." min="1" step="1" value="${it.parcelasTotais||''}" style="width:80px;padding:7px;border:1px solid var(--border);border-radius:6px;font-size:12px" title="Total de parcelas">
    <input type="month" class="cg-inicio" value="${ini}" style="width:140px;padding:6px;border:1px solid var(--border);border-radius:6px;font-size:12px" title="Mês da 1ª parcela">
    <button type="button" class="btn-icon btn-danger-icon" onclick="removeConsignado(this)" title="Remover"><i class="fa-solid fa-xmark"></i></button>
  </div>`;
}
function renderConsignados(items){
  const c=document.getElementById('emp-consignados'); if(!c) return;
  c.innerHTML=(items||[]).map(_consignadoRowHtml).join('');
}
function addConsignado(){
  const c=document.getElementById('emp-consignados'); if(!c) return;
  c.insertAdjacentHTML('beforeend', _consignadoRowHtml({}));
  c.lastElementChild?.querySelector('.cg-origem')?.focus();
}
function removeConsignado(btn){ const r=btn&&btn.closest('.consig-row'); if(r) r.remove(); }
function collectConsignados(){
  const c=document.getElementById('emp-consignados'); if(!c) return [];
  return Array.from(c.querySelectorAll('.consig-row')).map(r=>{
    const tipo=r.querySelector('.cg-tipo')?.value||'privado';
    const origem=(r.querySelector('.cg-origem')?.value||'').trim();
    const parcela=parseFloat(r.querySelector('.cg-parcela')?.value)||0;
    const parcelasTotais=parseInt(r.querySelector('.cg-num')?.value)||0;
    const ini=(r.querySelector('.cg-inicio')?.value||'').split('-');
    const inicioAno=parseInt(ini[0])||0, inicioMes=parseInt(ini[1])||0;
    if(!(parcela>0) || !(parcelasTotais>0) || !inicioMes || !inicioAno) return null;
    return { tipo, origem, parcela:+parcela.toFixed(2), parcelasTotais, inicioMes, inicioAno };
  }).filter(Boolean);
}
// Soma das parcelas ATIVAS na competência (mes/ano). idx = nº da parcela naquele mês.
function _consignadoTotalDoMes(emp, mes, ano){
  const arr=(emp && Array.isArray(emp.consignados))?emp.consignados:[];
  let total=0; const detalhe=[];
  arr.forEach(c=>{
    if(!c || !(+c.parcela>0) || !(+c.parcelasTotais>0) || !c.inicioMes || !c.inicioAno) return;
    const idx=(ano - c.inicioAno)*12 + (mes - c.inicioMes) + 1;   // 1-based
    if(idx>=1 && idx<=c.parcelasTotais){ total+=+c.parcela; detalhe.push({...c, parcelaNum:idx}); }
  });
  return { total:+total.toFixed(2), detalhe };
}

