// Sincroniza as ocorrências de atraso de origem 'ponto' com o que o Ponto
// Manual detectou. Cria/atualiza uma por dia com déficit; remove dias que
// não têm mais atraso. PRESERVA a decisão do operador (justificado/motivo/
// abonado) por dia. Ocorrências manuais (origem!='ponto') não são tocadas.
async function _sincronizarAtrasosDoPonto(empId, mes, ano, detectados){
  State.atrasos = State.atrasos || [];
  const idDe = dia => `atr_p_${empId}_${ano}_${String(mes).padStart(2,'0')}_${String(dia).padStart(2,'0')}`;
  const diasDetectados = new Set(detectados.map(d=>d.dia));
  const tarefas = [];
  // Remove ocorrências do ponto de dias que não têm mais atraso. Reconhece como "do
  // ponto" por origem='ponto' OU pelo PREFIXO do id (atr_p_...) — assim limpa também
  // registros antigos gravados antes de a origem ser marcada. Manual usa genId() (id
  // aleatório, sem esse prefixo), então nunca é tocado por engano. #atraso-fonte-unica
  const _ehDoPonto = a => a.origem==='ponto' || /^atr_p_/.test(String(a.id||''));
  const removerIds = State.atrasos
    .filter(a=>a.employeeId===empId && a.mes==mes && a.ano==ano && _ehDoPonto(a) && !diasDetectados.has(a.dia))
    .map(a=>a.id);
  removerIds.forEach(id=>tarefas.push(DB.remove('atrasos', id)));
  // Cria/atualiza os detectados (preserva a decisão do operador)
  const novos = [];
  for(const det of detectados){
    const id = idDe(det.dia);
    const ex = State.atrasos.find(a=>a.id===id);
    novos.push({
      id, employeeId:empId, mes, ano, dia:det.dia, minutos:det.minutos, origem:'ponto',
      motivo: ex?.motivo||'', justificado:!!ex?.justificado, abonado:!!ex?.abonado,
      createdAt: ex?.createdAt||new Date().toISOString(), updatedAt:new Date().toISOString(),
    });
  }
  novos.forEach(doc=>tarefas.push(DB.save('atrasos', doc)));
  // Atualiza o State em memória (otimista — o listener confirma depois)
  State.atrasos = State.atrasos.filter(a=>!removerIds.includes(a.id) && !novos.some(n=>n.id===a.id));
  State.atrasos.push(...novos);
  await Promise.all(tarefas);
}

// Detecta os atrasos do ponto de UMA folha SEM DOM (lê p.pontoManualDias). MESMA regra
// do applyPontoManual: déficit do dia além da tolerância CLT (10min). 12x36 mede pela
// PRESENÇA (jornada), não pelo líquido — refeição de 60min não é atraso. Base do
// recálculo de atrasos em lote. #plantao-refeicao #atraso-fonte-unica
function _detectAtrasosPonto(emp, p){
  const out=[];
  if(!emp || !p || emp.isentoPonto) return out;
  const dias=Array.isArray(p.pontoManualDias)?p.pontoManualDias:[];
  if(!dias.length) return out;
  const fam=escalaFamilia(emp.escala||'5x2A');
  const is12x36=fam==='12x36';
  let minContratados=480; if(fam==='6x1')minContratados=440; else if(fam==='12x36')minContratados=660;
  const _mod=_escalaModelo(emp.escala); if(_mod)minContratados=_modeloMinContratados(_mod);
  for(const cd of _compDias(p.mes,p.ano)){
    const pd=dias.find(x=>x && x.dia===cd.dia);
    if(!pd) continue;
    const exp=_getExpectedDay(emp,cd.mes,cd.ano,cd.dia);
    const _bat=_repararBatidasDia(pd, exp);
    const entrada=_bat.entrada, saida=_bat.saida, intIni=_bat.intIni, intFim=_bat.intFim;
    if(!entrada || !saida) continue;
    if(!exp || exp.tipo==='folga' || !exp.entrada || !exp.saida) continue;
    const realDay={dia:cd.dia, diaSem:cd.diaSem, entrada, saida, intIni, intFim};
    if(pd.heReview) realDay.heReview=pd.heReview;
    const effLiq=_effectiveMinLiq(realDay, exp, minContratados);
    const faltaDia = (is12x36||_usaFdsLivreResolve(emp.escala)) ? (_presencaMin(exp)-_presencaMin(realDay)) : (_liqMin(exp)-effLiq);
    if(faltaDia>HE_TOLERANCIA_DIA_MIN) out.push({dia:cd.dia, minutos:Math.round(faltaDia)});
  }
  return out;
}

// RECÁLCULO EM LOTE dos atrasos do ponto de uma competência (master). Reaplica a regra
// atual de atraso a TODAS as folhas e re-sincroniza a coleção `atrasos` — apaga os
// automáticos que não existem mais (ex.: atraso falso de 12x36 pré-correção da refeição)
// e PRESERVA justificativas/abonos e atrasos lançados à mão. Conserta o card de Atrasos
// e a Contabilidade de uma vez (ambos lêem a coleção). #plantao-refeicao #atraso-fonte-unica
async function recalcularAtrasosCompetencia(mesArg, anoArg){
  toast('Iniciando recálculo de atrasos...','info');
  if(Auth.currentUser?.role!=='master'){ toast('Apenas o usuário master pode rodar o recálculo.','error'); return; }
  const mes = parseInt(mesArg || val('payroll-mes') || val('cont-mes') || currentMes());
  const ano = parseInt(anoArg || val('payroll-ano') || val('cont-ano') || currentAno());
  const afetadas=(State.payrolls||[]).filter(p=>p.mes==mes&&p.ano==ano);
  if(!afetadas.length){ toast(`Nenhuma folha encontrada em ${MESES[mes]}/${ano}.`,'warning'); return; }
  if(!confirm(`Recalcular os ATRASOS detectados do ponto de ${afetadas.length} folha(s) da competência ${MESES[mes]}/${ano} (${_compLabel(mes,ano)})?\n\n• Reaplica a regra ATUAL (12x36: refeição de 60min dentro da jornada NÃO é atraso).\n• Remove os atrasos automáticos que não existem mais; PRESERVA justificativas/abonos e atrasos lançados à mão.\n• Atualiza o card de Atrasos e a Contabilidade. O desconto no recibo se ajusta ao abrir/salvar cada folha.\n• Roda mesmo em folhas FECHADAS.\n\nContinuar?`)) return;
  let nAlteradas=0, nSemMudanca=0, totalRemovidos=0;
  for(const p of afetadas){
    const emp=State.employees.find(e=>e.id===p.employeeId);
    if(!emp) continue;
    const antes=(State.atrasos||[]).filter(a=>a.employeeId===p.employeeId && a.mes==mes && a.ano==ano && (a.origem==='ponto' || /^atr_p_/.test(String(a.id||'')))).length;
    const detect=_detectAtrasosPonto(emp, p);
    try{
      await _sincronizarAtrasosDoPonto(p.employeeId, mes, ano, detect);
      if(detect.length !== antes){ nAlteradas++; if(detect.length < antes) totalRemovidos += (antes - detect.length); }
      else nSemMudanca++;
    }catch(e){ console.error('recalc atrasos', emp.nome, e); }
  }
  try{ Auth.log('RECALC_ATRASOS', null, `${MESES[mes]}/${ano} — ${nAlteradas} folha(s) alterada(s), ${totalRemovidos} atraso(s) removido(s)`); }catch(_){}
  toast(`Recálculo de atrasos concluído: ${nAlteradas} folha(s) alterada(s) · ${totalRemovidos} atraso(s) falso(s) removido(s) · ${nSemMudanca} sem mudança. Reabra a Contabilidade pra ver o efeito.`, 'success');
  if(val('payroll-employee')) onPayrollEmployeeChange();
}

// Folgas avulsas (override tipo='folga') que caem na competência, com suas flags.
// remunerada=false → desconta o dia (salário/30) sem virar falta; pagaBeneficios=true
// → recebe VT/VR/VA do dia. Ambas NÃO são falta (já garantido pelo override folga). #folga-avulsa
function _folgasAvulsasComp(emp, mes, ano){
  if(!emp || !Array.isArray(emp.overridesHorario)) return [];
  const out=[];
  for(const cd of _compDias(mes, ano)){
    const ymd = `${cd.ano}-${String(cd.mes).padStart(2,'0')}-${String(cd.dia).padStart(2,'0')}`;
    const ov = emp.overridesHorario.find(o => o && o.data===ymd && o.tipo==='folga');
    if(ov){
      // O dia ERA previsto de trabalho na escala? Avalia IGNORANDO este override de
      // folga (clone sem ele) — senão o próprio override mascara o dia como folga.
      // Só dia de trabalho gera desconto da folga não remunerada; folga sobre dia
      // que já era descanso (domingo/folga da escala) NÃO desconta sal/30. #folga-avulsa-guarda
      const _empSemOvr = { ...emp, overridesHorario: emp.overridesHorario.filter(o=>o!==ov) };
      const _exp = _getExpectedDay(_empSemOvr, cd.mes, cd.ano, cd.dia);
      const eraTrabalho = !!(_exp && _exp.tipo!=='folga' && _exp.entrada);
      out.push({ dia:cd.dia, remunerada:!!ov.remunerada, pagaBeneficios:!!ov.pagaBeneficios, eraTrabalho });
    }
  }
  return out;
}

// Conta os dias de TRABALHO previstos no mês para o colaborador, conforme a
// escala (escala salva > âncora 12x36 > contratual). Base do proporcional.
function _diasPrevistosEscala(emp, mes, ano){
  if(!emp) return 0;
  _fdsLivreCtxDias=null; _fdsLivreCtxEmp=null;  // projeção é determinística (não usa folha viva)
  let n = 0;
  for(const d of _compDias(mes, ano)){
    const exp = _getExpectedDay(emp, d.mes, d.ano, d.dia, true); // mês cheio (proporcional)
    if(exp && exp.tipo!=='folga' && exp.entrada) n++;
  }
  return n;
}

// Dias previstos no mês com jornada líquida ACIMA de 6h — base do VR
// (CLT Art. 71). Ex.: 6x1A com sábado curto (4h) — o sábado conta pro VT
// mas NÃO pro VR. Usado pra calcular a proporção de VR na folha.
function _diasPrevistosComVR(emp, mes, ano){
  if(!emp) return 0;
  _fdsLivreCtxDias=null; _fdsLivreCtxEmp=null;  // projeção determinística
  let n = 0;
  for(const d of _compDias(mes, ano)){
    const exp = _getExpectedDay(emp, d.mes, d.ano, d.dia, true); // mês cheio (proporcional)
    if(exp && exp.tipo!=='folga' && exp.entrada && _liqMin(exp) > 360) n++;
  }
  return n;
}

// Lista as DATAS previstas pela escala no mês de USO — pra mostrar ao gestor
// EXATAMENTE quais dias geraram o crédito do benefício (visibilidade pedida
// 2026-05-31). Espelha _diasPrevistosEscala/_diasPrevistosComVR. Para isento
// (Art.62) lista dias úteis (seg–sex), igual ao cálculo. Retorna {dia,mes,ano,vr}.
function _diasPrevistosEscalaLista(emp, mes, ano){
  if(!emp) return [];
  const out=[];
  const isento = !!emp.isentoPonto;
  for(const d of _compDias(mes, ano)){
    if(isento){
      const dow=new Date(d.ano, d.mes-1, d.dia).getDay();
      if(dow>=1 && dow<=5) out.push({ dia:d.dia, mes:d.mes, ano:d.ano, vr:true });
    } else {
      const exp=_getExpectedDay(emp, d.mes, d.ano, d.dia, true);
      if(exp && exp.tipo!=='folga' && exp.entrada) out.push({ dia:d.dia, mes:d.mes, ano:d.ano, vr:_liqMin(exp)>360 });
    }
  }
  return out;
}

// Dias úteis (seg–sex) da COMPETÊNCIA (26→25) — fallback de benefícios pra
// isento sem escala. Conta sobre o período da competência (igual ao não-isento,
// que usa _diasPrevistosEscala/_compDias), não sobre o mês de calendário.
function _diasUteisMes(mes, ano){
  let n = 0;
  for(const cd of _compDias(mes, ano)){
    if(cd.diaSem!==0 && cd.diaSem!==6) n++;
  }
  return n;
}

// Dias ÚTEIS (seg–sáb, exceto feriados) e DESCANSOS (domingos + feriados) da
// competência — base do DSR sobre verba variável (HE), Lei 605/49 + Súmula 172 TST.
// Decisão do dono 2026-06-03: divisor inclui o SÁBADO. Feriado em dia útil conta como
// descanso; domingo já é descanso (sem dupla contagem). #dsr-he
function _diasUteisEDescansos(mes, ano, loc){
  const sabUtil = _paramLegal('dsrHeBaseSabado')!==false;   // sábado entra no divisor? (param legal)
  let uteis = 0, descansos = 0;
  for(const cd of _compDias(mes, ano)){
    const ehDomingo = cd.diaSem===0;
    const ehSabado  = cd.diaSem===6;
    const ehFeriado = !!_ehFeriado(cd.ano, cd.mes, cd.dia, loc);
    if(ehDomingo || ehFeriado || (ehSabado && !sabUtil)) descansos++;
    else uteis++;
  }
  return { uteis, descansos };
}

// Nº de SEMANAS (seg→dom) com pelo menos 1 falta INJUSTIFICADA no mês — base do
// DSR perdido (Lei 605/49: falta injustificada na semana → perde o repouso da
// semana). Detecta os dias de falta pelo ponto (dia que deveria trabalhar, sem
// batida, sem atestado/férias — _diaEmBrancoEhFalta) e agrupa por semana. Vale
// p/ TODAS as escalas (inclusive 12x36, onde o DSR é embutido mas a falta o
// desconta). Fallback: faltas lançadas à mão sem ponto → 1 DSR por falta. #fix-dsr-falta
function _dsrSemanasComFalta(emp, mes, ano, pontoDias, faltasInjustCount){
  if(!emp || !(faltasInjustCount>0)) return 0;
  if(emp.isentoPonto) return 0;
  const is12 = escalaFamilia(emp.escala||'5x2A')==='12x36';
  const semanas = new Set();
  let detectadas = 0;
  for(const cd of _compDias(mes, ano)){
    const pd = (pontoDias||[]).find(x=>x.dia===cd.dia);
    if(pd && (pd.entrada || pd.saida)) continue;   // tem batida → não é falta
    const isWknd = cd.diaSem===0 || cd.diaSem===6;
    if(_diaEmBrancoEhFalta(emp, cd.mes, cd.ano, cd.dia, isWknd, is12)){
      detectadas++;
      const d = new Date(cd.ano, cd.mes-1, cd.dia);
      const seg = new Date(d); seg.setDate(d.getDate() - ((d.getDay()+6)%7));  // segunda da semana
      semanas.add(`${seg.getFullYear()}-${seg.getMonth()}-${seg.getDate()}`);
    }
  }
  if(detectadas===0) return faltasInjustCount;   // faltas manuais sem ponto: estrito = 1 DSR por falta
  return semanas.size;
}

// Flag global: true só durante o ato de FECHAR a folha (fecharFolhaIndividual).
// Libera a apuração da bonificação no `recalculate` no momento do fechamento,
// pra ela ser computada e persistida antes de a folha virar 'fechada'.
let _fechandoFolha = false;

// Comissão de Boa Permanência — REGRA RÍGIDA (decisão do dono 2026-06-26, TRAVADA).
// Recebe APENAS quem cumpre TODAS as condições de assiduidade abaixo:
//   (B) ZERO faltas de qualquer tipo no mês — injustificada, justificada E qualquer dia
//       inteiro coberto por ATESTADO ou ABONO (atestado, INCLUSIVE o próprio, derruba).
//   (C) MÊS COMPLETO — admitido até o início do período e não desligado antes do fim
//       (admissão OU demissão no meio do período = sem mês completo = não recebe).
//   (D) NENHUM dia trabalhado com menos de 50% da jornada diária cumprida.
// A condição (A) "folha FECHADA" é exigida no PAGAMENTO (tela Benefícios / caminho 'mes'),
// NÃO aqui — senão a folha aberta não conseguiria preencher o valor do bônus antes de fechar.
// `totalFaltasLive` = faltas do form (no fechamento ao vivo); se null, lê do registro salvo.
// `bonificacaoSemprePagar` (override do master) e isento são tratados pelos chamadores.
// Retorna {ok, motivo}. #bp-rigida
function _mesCompletoNaCompetencia(emp, mes, ano){
  const dias=_compDias(mes,ano); if(!dias.length) return true;
  const f=dias[0], l=dias[dias.length-1];
  const ini=new Date(f.ano, f.mes-1, f.dia);
  const fim=new Date(l.ano, l.mes-1, l.dia);
  const adm = emp.dataAdmissao ? new Date(((emp.dataAdmissao+'').substring(0,10))+'T00:00:00') : null;
  if(adm && !isNaN(adm.getTime()) && adm > ini) return false;   // admitido DEPOIS do início do período
  const dem = emp.dataDemissao ? new Date(((emp.dataDemissao+'').substring(0,10))+'T00:00:00') : null;
  if(dem && !isNaN(dem.getTime()) && dem < fim) return false;   // desligado ANTES do fim do período
  return true;
}
// Algum dia inteiro de ausência coberto por atestado/abono no mês? (atestado de DIA, próprio
// ou não, e abono — derrubam o BP). Atestado de HORAS não conta aqui; jornada parcial é
// tratada pela regra dos 50% (_apuracaoPontoTotais.diasAbaixoMeio). #bp-rigida
function _temAusenciaDeDiaNoMes(empId, mes, ano){
  const t=_atestadoTotais(empId, mes, ano);
  // COBERTURA por colega NÃO conta como ausência (posto coberto = sem falta) → mantém o BP.
  // (Decisão do dono 2026-06-27, DESTRAVAR/ALTERAR da regra rígida de BP.) #cobertura-colega
  return (((t.dias||0) - (t.diasCobertura||0)) + (t.diasNaoAbonados||0)) > 0;
}

function _boaPermanenciaElegivel(emp, mes, ano, totalFaltasLive){
  if(!emp) return {ok:false, motivo:''};
  // (C) Mês completo — admissão/demissão no meio do período → não recebe. #bp-rigida
  if(!_mesCompletoNaCompetencia(emp, mes, ano))
    return {ok:false, motivo:'sem mês completo (admissão/desligamento no período)'};
  const pay = (State.payrolls||[]).find(p=>p.employeeId===emp.id && p.mes==mes && p.ano==ano);
  // (B) Falta de qualquer tipo (injust. + just.) → perde o prêmio inteiro (tudo-ou-nada).
  let faltas = totalFaltasLive;
  if(faltas == null){
    faltas = ('faltasInjustificadas' in (pay||{}))
      ? ((pay.faltasInjustificadas||0)+(pay.faltasJustificadas||0))
      : ((pay && pay.faltas) || 0);
  }
  if(faltas > 0) return {ok:false, motivo:'faltas no mês — benefício perdido'};
  // (B) Dia inteiro coberto por atestado/abono também derruba — inclusive atestado próprio. #bp-rigida
  if(_temAusenciaDeDiaNoMes(emp.id, mes, ano))
    return {ok:false, motivo:'atestado/abono no mês — benefício perdido'};
  // (D) Algum dia trabalhado com menos de 50% da jornada cumprida → perde. #bp-rigida
  if(pay && ((_apuracaoPontoTotais(emp, pay).diasAbaixoMeio)||0) > 0)
    return {ok:false, motivo:'dia com menos de 50% da jornada — benefício perdido'};
  return {ok:true, motivo:''};
}

function recalculate(){
  const dias=numVal('payroll-dias');
  let faltasJust=numVal('payroll-faltas-justificadas');
  let faltasInjust=numVal('payroll-faltas-injustificadas');
  let totalFaltas=faltasJust+faltasInjust;

  const empId=val('payroll-employee');
  const emp=State.employees.find(e=>e.id===empId);
  const salBase=emp?(emp.salarioBase||0):numVal('payroll-remuneracao');
  // Isento de controle de jornada (CLT Art. 62 — cargo de confiança): salário
  // cheio, sem desconto de falta/atraso, sem HE/adic. noturno, benefícios
  // integrais. Não bate ponto. As travas abaixo respeitam essa flag.
  const isentoPonto = !!(emp && emp.isentoPonto);
  if(isentoPonto){
    faltasJust=0; faltasInjust=0; totalFaltas=0;
    setVal('payroll-faltas-justificadas',0);
    setVal('payroll-faltas-injustificadas',0);
  }
  setVal('payroll-faltas', totalFaltas);

  // --- Descontos CLT ---
  const valorDia   = salBase/30;          // CLT: divisor 30 para faltas
  const valorHora  = salBase/220;         // CLT: divisor 220 para horas
  const valorMinuto= valorHora/60;

  // Atestados médicos aprovados — abatem faltas (dias) e atraso (horas): pagos, sem desconto
  const _atest = _atestadoTotais(val('payroll-employee'), parseInt(val('payroll-mes')), parseInt(val('payroll-ano')));
  // Dias de trabalho previstos no mês (pela escala) — base do proporcional
  const _mesR = parseInt(val('payroll-mes')||currentMes());
  const _anoR = parseInt(val('payroll-ano')||currentAno());
  const diasPrevistos = emp ? _diasPrevistosEscala(emp, _mesR, _anoR) : 0;
  // Dias pagos = trabalhados + dias de atestado (atestado é pago). Limitado
  // aos dias previstos — dias extras viram HE, não inflam a remuneração.
  const diasPagos = Math.min(diasPrevistos || (dias + _atest.dias), dias + _atest.dias);
  // Multiplicador de benefícios por dia. VT conta todos os dias trabalhados.
  // VR só os dias com jornada líquida > 6h (CLT Art. 71) — calculado pela
  // proporção dos dias previstos com >6h sobre o total de dias previstos
  // (ex.: 6x1A com sábado curto recebe VT no sábado mas não VR). Isento
  // recebe ambos integrais.
  // Folgas avulsas: NÃO remunerada desconta o dia (sal/30); pagaBeneficios soma VT/VR/VA. #folga-avulsa
  const _folgasAv        = (emp && !isentoPonto) ? _folgasAvulsasComp(emp, _mesR, _anoR) : [];
  // Só desconta folga não remunerada que caiu em dia de TRABALHO (a trava eraTrabalho
  // evita descontar sal/30 de folga lançada sobre dia que já era descanso). #folga-avulsa-guarda
  const folgasNaoRemDias = _folgasAv.filter(f=>!f.remunerada && f.eraTrabalho).length;
  const folgasBenefDias  = _folgasAv.filter(f=>f.pagaBeneficios).length;
  const diasBeneficio = isentoPonto ? (diasPrevistos || _diasUteisMes(_mesR, _anoR)) : (dias + folgasBenefDias);
  const diasPrevistosVr = emp ? _diasPrevistosComVR(emp, _mesR, _anoR) : 0;
  const diasBeneficioVr = isentoPonto
    ? diasBeneficio
    : ((diasPrevistos > 0 ? Math.round(dias * (diasPrevistosVr / diasPrevistos)) : 0) + folgasBenefDias);

  // Segmentos de lotação no período — base do salário/insalubridade/acúmulo POR
  // PERÍODO (ex.: troca de função/salário no meio do mês). Fast-path: 1 segmento
  // (sem transferência no período) → cálculo idêntico ao de antes, sem regressão.
  const _cardsR=_getPontoManualCards();
  const _regR=State.payrolls.find(p=>p.employeeId===empId&&p.mes==_mesR&&p.ano==_anoR);
  const _pontoDiasR=_cardsR.length?_collectPontoManualDias()
                  :(_regR&&Array.isArray(_regR.pontoManualDias)?_regR.pontoManualDias:[]);
  const _segs=(emp && !isentoPonto && diasPrevistos>0)
    ? _segmentosLotacao(emp,_mesR,_anoR,_pontoDiasR,_atest.dias) : [];
  const _multiSeg=_segs.length>1;

  // --- Refeição não rendida (intervalo intrajornada suprimido) ---
  // Paga a HORA CHEIA + acréscimo de 50% (art. 71 §4: "o período suprimido, com acréscimo
  // de 50%"). Natureza INDENIZATÓRIA → NÃO-tributável: entra só no líquido (igual provNtrib),
  // fora da base de INSS/IRRF/FGTS. A hora suprimida NÃO está no salário (o previsto subtrai
  // 60min p/ todos, inclusive semRefeicao) → não há duplicidade ao pagar a hora cheia. #ref-hora-cheia #ref-nao-rendida #folha-detalhada
  // Dois caminhos de pagamento:
  //  (a) semRefeicao=true → trabalha sozinho SEMPRE → paga TODA refeição não rendida apurada.
  //  (b) demais → paga SÓ os dias APROVADOS pelo supervisor (naoRendAprovadoMin): pedido do
  //      colaborador no app OU almoço suprimido DETECTADO pela batida e autorizado na revisão.
  //      A detecção NÃO paga sozinha (evita batida maliciosa de volta antes dos 60min). Caso típico: zelador que goza o almoço nos dias
  //      úteis (o colega rende) mas trabalha corrido sozinho em feriado/sáb/dom. #ref-nao-rendida-solicitada
  let refNaoRendidaMin=0, refNaoRendidaValor=0;
  if(emp && !isentoPonto && salBase>0){
    const _apNR=_apuracaoPontoTotais(emp,{mes:_mesR,ano:_anoR,pontoManualDias:_pontoDiasR});
    refNaoRendidaMin = emp.semRefeicao ? _apNR.naoRendMin : _apNR.naoRendAprovadoMin;   // não-sozinho: paga SÓ o aprovado pelo supervisor (almoço suprimido detectado vira pendência de autorização — não paga sozinho). #ref-detectada
    refNaoRendidaValor=+((refNaoRendidaMin/60)*valorHora*(1+_paramLegal('refNaoRendidaPerc')/100)).toFixed(2);   // hora CHEIA + acréscimo (art. 71 §4: "o período suprimido, com acréscimo de 50%"). #ref-hora-cheia
  }
  setVal('payroll-ref-nao-rendida-min', refNaoRendidaMin||'');
  setVal('payroll-ref-nao-rendida-valor', refNaoRendidaValor>0?refNaoRendidaValor.toFixed(2):'0.00');

  // Atrasos — lista de ocorrências (coleção `atrasos`). Só as ocorrências
  // NÃO abonadas descontam. O atestado abate horas de atraso. Isento não desconta.
  const _atrasoTot = _atrasoTotais(val('payroll-employee'), _mesR, _anoR);
  const minutosAtraso = _atrasoTot.minutos;
  const minutosAtrasoEf = Math.max(0, _atrasoTot.minutosDesc - _atest.horasMin);
  const descontoAtraso = (!isentoPonto && minutosAtrasoEf>0) ? minutosAtrasoEf*valorMinuto : 0;
  setVal('payroll-atraso-min', minutosAtraso||'');
  setVal('payroll-desconto-atraso', descontoAtraso>0 ? descontoAtraso.toFixed(2) : '0.00');

  // Remuneração PROPORCIONAL: salário × (dias pagos ÷ dias previstos na
  // escala). Cumpriu todos os dias previstos → salário cheio. Trabalhou
  // parte → recebe a fração correspondente. O desconto de atraso NÃO é
  // abatido aqui — ele é subtraído UMA vez no líquido final (atrasoEnc) e
  // nas impressões. Antes era abatido nos dois lugares (desconto dobrado).
  let remuneracaoProp;
  if(isentoPonto) remuneracaoProp = salBase;
  else if(_multiSeg) remuneracaoProp = _segs.reduce((s,x)=> s + (x.lot.salarioBase||0)*(x.diasPagos/diasPrevistos), 0);
  else if(diasPrevistos>0){
    // MODELO ESTRITO de falta injustificada (Lei 605/49, decisão do usuário 2026-06-03):
    // paga os dias EMPREGADOS no mês (admissão/desligamento seguem proporcionais) e
    // desconta cada falta injustificada como DIA (salário÷30) + DSR da semana (salário÷30).
    // remuneração mantém o sentido de "salário líquido já descontado" → recibo/INSS/IRRF/
    // folha continuam corretos sem alteração (descFaltas = salBase − remuneração). #fix-dsr-falta
    // Dias não-abonados (abono c/ abona=false) entram em diasEmpregado e são descontados
    // a salário÷30 (igual falta injustificada), porém SEM DSR — são justificados. #atestado-abona-falta
    const _diasNaoAbon = _atest.diasNaoAbonados||0;
    const diasEmpregado = Math.min(diasPrevistos, diasPagos + faltasInjust + _diasNaoAbon);
    const baseEmpregado = salBase*(diasEmpregado/diasPrevistos);
    const valorDiaDSR   = salBase/30;
    const dsrSemanas    = _dsrSemanasComFalta(emp, _mesR, _anoR, _pontoDiasR, faltasInjust);
    remuneracaoProp = baseEmpregado - faltasInjust*valorDiaDSR - dsrSemanas*valorDiaDSR - _diasNaoAbon*valorDiaDSR;
  } else remuneracaoProp = 0;
  // Folga NÃO remunerada: desconta o dia (salário/30) da remuneração — reduz a base
  // (e por tabela INSS/IRRF, como um dia não trabalhado/não pago). NÃO é falta → sem DSR. #folga-avulsa
  const descFolgaNaoRem = (folgasNaoRemDias>0 && salBase>0) ? folgasNaoRemDias*(salBase/30) : 0;
  const remuneracaoBase = Math.max(0, remuneracaoProp - descFolgaNaoRem);
  if(salBase>0){
    setVal('payroll-remuneracao', remuneracaoBase.toFixed(2));
  }
  const remuneracao = remuneracaoBase; // valor proporcional recém-calculado

  // --- VT e VR (respeita frequência diária ou semanal definida no cadastro) ---
  const vtFreqCalc = emp?.vtFreq || 'diario';
  const vrFreqCalc = emp?.vrFreq || 'diario';
  const semCalc    = _semanasTrabalhadas(dias, emp?.escala);
  const semCalcVr  = _semanasTrabalhadas(diasBeneficioVr, emp?.escala);
  // Feriados trabalhados (5x2/6x1, modo folga): só somam VT/VR se APROVADOS pelo
  // supervisor. `dias` (e o VR proporcional) já incluem o dia batido → tira os NÃO
  // aprovados. Painel de aprovação renderizado abaixo. #feriados
  const _ferTrab   = emp ? _feriadosTrabalhadosNaFolha(emp, _mesR, _anoR, _pontoDiasR) : [];
  const _ferVtExcl = isentoPonto ? 0 : _ferTrab.filter(f=>!f.aprovado).length;
  const _ferVrExcl = isentoPonto ? 0 : _ferTrab.filter(f=>!f.aprovado && f.vr).length;
  _renderFeriadoTrabPanel(_ferTrab, empId, _mesR, _anoR);
  const vtMult = (vtFreqCalc === 'semanal') ? semCalc   : Math.max(0, diasBeneficio   - _ferVtExcl);  // todos os dias − feriados não aprovados
  const vrMult = (vrFreqCalc === 'semanal') ? semCalcVr : Math.max(0, diasBeneficioVr - _ferVrExcl);  // dias > 6h − feriados não aprovados
  setVal('payroll-vt-total',(numVal('payroll-vt-dia')*vtMult).toFixed(2));
  setVal('payroll-vr-total',(numVal('payroll-vr-dia')*vrMult).toFixed(2));

  // --- Comissão de Boa Permanência ---
  // Regra RÍGIDA (decisão do dono 2026-06-26): devida só a quem teve mês SEM qualquer
  // falta (just./injust./atestado/abono), MÊS COMPLETO (sem admissão/demissão no meio)
  // e NENHUM dia trabalhado abaixo de 50% da jornada — ver _boaPermanenciaElegivel/#bp-rigida.
  // (O "folha fechada" é exigido no pagamento, não aqui — o valor é preenchido antes de
  // fechar.) A flag "bonificacaoSemprePagar" no cadastro força o pagamento. #bp-rigida
  const bonusCard=document.getElementById('bonus-card');
  const bonusInput=document.getElementById('payroll-bonus');
  const bonusAlert=document.getElementById('bonus-alert');
  const bonusAlertMsg=document.getElementById('bonus-alert-msg');
  const sempreP=!!(emp&&emp.bonificacaoSemprePagar);
  const _bp = emp ? _boaPermanenciaElegivel(emp,_mesR,_anoR,totalFaltas) : {ok:false,motivo:''};
  if(!_bp.ok && !sempreP){
    // Pendente (folha ainda aberta) OU perdida (faltas no mês) — não preenche
    bonusCard.classList.add('locked'); bonusInput.disabled=true;
    setVal('payroll-bonus',''); bonusAlert.classList.remove('hidden');
    const titulo = _bp.pendente ? 'Comissão de Boa Permanência: PENDENTE' : 'Comissão de Boa Permanência: não cabível';
    if(bonusAlertMsg) bonusAlertMsg.innerHTML=`<strong>${titulo}</strong> — ${_bp.motivo||'pendência'}.`;
  } else {
    bonusCard.classList.remove('locked'); bonusInput.disabled=false;
    if(!_bp.ok && sempreP){
      bonusAlert.classList.remove('hidden');
      if(bonusAlertMsg) bonusAlertMsg.innerHTML='<strong>Comissão liberada por configuração</strong> — colaborador marcado para receber mesmo sem cumprir a regra de boa permanência.';
    } else {
      bonusAlert.classList.add('hidden');
    }
    // Auto-preenche da CCT quando o campo está vazio OU zerado. (Antes só
    // preenchia se vazio — um "0" salvo travava o auto-preenchimento e a
    // bonificação ficava 0,00 mesmo com a comissão liberada por configuração.)
    if((numVal('payroll-bonus')||0)<=0 && State.cct && State.cct.bonificacao>0){
      setVal('payroll-bonus', State.cct.bonificacao.toFixed(2));
    }
  }

  // --- VA: integral até 2 faltas INJUSTIFICADAS; a partir da 3ª, desconta
  //     CADA dia faltado (os 3 + os extras), no valor vaMensal/diasPrevistos por
  //     dia. Decisão do usuário 2026-05-28. Antes: proporcional aos dias pagos e
  //     zerava tudo com >=3 faltas — agora só desconta os dias de falta.
  const vaNote=document.getElementById('va-note');
  if(emp&&(emp.valorMensalVa||0)>0){
    const vaMensal=emp.valorMensalVa||0;
    if(isentoPonto){
      // Isento: VA integral, sem penalidade de faltas
      setVal('payroll-va-total',vaMensal.toFixed(2));
      setVal('payroll-va-liquido',vaMensal.toFixed(2));
      if(vaNote){ vaNote.classList.remove('hidden'); vaNote.innerHTML=`<i class="fa-solid fa-user-tie" style="color:#4F46E5"></i> VA integral — cargo de confiança (isento de controle de jornada).`; }
    } else if(faltasInjust>=3){
      // Desconta os dias faltados (os 3 + os extras), por dia = vaMensal/diasPrevistos
      const vaDia  = diasPrevistos>0 ? vaMensal/diasPrevistos : 0;
      const vaDesc = Math.min(vaMensal, vaDia*faltasInjust);
      const vaFinal= Math.max(0, vaMensal - vaDesc);
      setVal('payroll-va-total',vaFinal.toFixed(2));
      setVal('payroll-va-liquido',vaFinal.toFixed(2));
      if(vaNote){ vaNote.classList.remove('hidden'); vaNote.innerHTML=`<i class="fa-solid fa-circle-minus" style="color:#c0392b"></i> VA com desconto — ${faltasInjust} falta(s) injustificada(s) × ${fmtMoney(vaDia)}/dia (${diasPrevistos} dias previstos) = −${fmtMoney(vaDesc)} · recebe ${fmtMoney(vaFinal)}.`; }
    } else {
      // 0, 1 ou 2 faltas injustificadas → VA integral (desconto só a partir da 3ª)
      setVal('payroll-va-total',vaMensal.toFixed(2));
      setVal('payroll-va-liquido',vaMensal.toFixed(2));
      if(vaNote){ vaNote.classList.remove('hidden'); vaNote.innerHTML=`<i class="fa-solid fa-circle-check" style="color:var(--success)"></i> VA integral ${fmtMoney(vaMensal)} — ${faltasInjust} falta(s) injustificada(s) (desconto só a partir da 3ª).`; }
    }
  } else {
    if(vaNote) vaNote.classList.add('hidden');
  }

  // --- Adicional Noturno (20% sobre hora, hora noturna = 52min30s) ---
  // Isento (cargo de confiança) não recebe adicional noturno (Art. 62 CLT).
  // POR PERÍODO: conta só os dias trabalhados cuja lotação vigente era noturna
  // (ex.: colaboradora noturno→diurno no meio do mês recebe só os dias noturnos).
  if(emp && !isentoPonto){
    const _empIdN=val('payroll-employee');
    const _mesN=parseInt(val('payroll-mes')||currentMes());
    const _anoN=parseInt(val('payroll-ano')||currentAno());
    const _cardsN=_getPontoManualCards();
    const _regN=State.payrolls.find(p=>p.employeeId===_empIdN&&p.mes==_mesN&&p.ano==_anoN);
    const _pontoN=_cardsN.length ? _collectPontoManualDias()
                : (_regN&&Array.isArray(_regN.pontoManualDias) ? _regN.pontoManualDias : []);
    const diasNot=_diasNoturnosTrabalhados(emp, _mesN, _anoN, _pontoN);
    // Card visível se é/foi noturno em algum momento (atual ou no período).
    const ehNoturnoAtual=emp.turnoNoturno&&escalaFamilia(emp.escala||'5x2A')==='12x36';
    const noturnoCard=document.getElementById('noturno-card');
    if(noturnoCard) noturnoCard.classList.toggle('hidden', !(diasNot>0||ehNoturnoAtual));
    if(diasNot>0&&emp.salarioBase){
      // (salário/220) * 20% * 7h noturnas médias * dias noturnos efetivos
      setVal('payroll-noturno',calcAdNoturno(emp.salarioBase,diasNot).toFixed(2));
    } else {
      // Sem dias noturnos: zera (evita adicional fantasma de quando era noturno).
      setVal('payroll-noturno','');
    }
  } else if(isentoPonto){
    // Isento: zera adicional noturno e esconde o card
    const noturnoCard=document.getElementById('noturno-card');
    if(noturnoCard) noturnoCard.classList.add('hidden');
    setVal('payroll-noturno','');
  }

  // Fator de PROPORCIONALIDADE dos adicionais (insalubridade/acúmulo) = mesma
  // proporção da remuneração: dias pagos ÷ dias previstos. Admissão/desligamento no
  // meio do mês (ou faltas) reduzem o adicional na mesma medida do salário — antes
  // saíam CHEIOS e pagavam a maior. Isento = integral. Decisão do usuário 2026-06-03. #fix-adic-proporcional
  const _fatorAdic = isentoPonto ? 1 : (diasPrevistos>0 ? Math.min(1, diasPagos/diasPrevistos) : 0);

  // --- Acúmulo de Função (+20% sobre salário base) — por período ---
  const acumuloCard=document.getElementById('acumulo-card');
  // Valor: por segmento de lotação (só os períodos com acúmulo), proporcional aos
  // dias PAGOS de cada um. Fast-path (1 segmento) = salBase*20% × fator.
  const acumuloVal = _multiSeg
    ? _segs.reduce((s,x)=> s + (x.lot.acumuloFuncao ? (x.lot.salarioBase||0)*(_paramLegal('acumuloPerc')/100)*(x.diasPagos/diasPrevistos) : 0), 0)
    : ((emp&&emp.acumuloFuncao&&salBase>0) ? salBase*(_paramLegal('acumuloPerc')/100)*_fatorAdic : 0);
  if(acumuloVal>0){
    if(acumuloCard) acumuloCard.classList.remove('hidden');
    setVal('payroll-acumulo',acumuloVal.toFixed(2));
  } else {
    if(acumuloCard) acumuloCard.classList.add('hidden');
    setVal('payroll-acumulo','');
  }

  // --- Insalubridade (20% / 40% / 60% sobre salário mínimo nacional) — por período ---
  const insalubCard=document.getElementById('insalubridade-card');
  const insalubGrau=document.getElementById('insalubridade-grau');
  const insalubPerc=emp?(emp.insalubridade||0):0;
  const salMin=(State.cct&&State.cct.salarioMinimo)||1518;
  // Valor: por segmento (cada período usa seu grau), proporcional aos dias PAGOS.
  // Fast-path (1 segmento) = salMin*perc/100 × fator de proporcionalidade.
  const insalubVal = _multiSeg
    ? _segs.reduce((s,x)=> s + salMin*((x.lot.insalubridade||0)/100)*(x.diasPagos/diasPrevistos), 0)
    : (insalubPerc>0 ? salMin*(insalubPerc/100)*_fatorAdic : 0);
  if(insalubVal>0){
    if(insalubCard) insalubCard.classList.remove('hidden');
    setVal('payroll-insalubridade',insalubVal.toFixed(2));
    if(insalubGrau){
      const grauLabel=_multiSeg?'(por período)':(insalubPerc===20?'(Mínimo 20%)':insalubPerc===40?'(Médio 40%)':'(Máximo 60%)');
      insalubGrau.textContent=grauLabel;
    }
  } else {
    if(insalubCard) insalubCard.classList.add('hidden');
    setVal('payroll-insalubridade','');
    if(insalubGrau) insalubGrau.textContent='';
  }

  // --- Jornada & Horas Extras ---
  const tEntrada  = timeToMinutes(val('payroll-entrada'));
  const tSaida    = timeToMinutes(val('payroll-saida'));
  const tIntIni   = timeToMinutes(val('payroll-intervalo-inicio'));
  const tIntFim   = timeToMinutes(val('payroll-intervalo-fim'));

  if(isentoPonto){
    // Cargo de confiança não tem hora extra (CLT Art. 62) — zera tudo.
    setVal('payroll-horas-liquidas','—');
    setVal('payroll-horas-extras-dia','—');
    setVal('payroll-he-total','');
  } else if(tEntrada!==null && tSaida!==null){
    // Jornada bruta (suporta virada de meia-noite)
    let minBrutos = tSaida - tEntrada;
    if(minBrutos <= 0) minBrutos += 24*60;
    // Intervalo intrajornada
    const minIntervalo = (tIntIni!==null && tIntFim!==null)
      ? Math.max(0, tIntFim - tIntIni) : 0;
    // Jornada líquida real
    const minLiquidos = Math.max(0, minBrutos - minIntervalo);

    // Jornada contratada (baseada no cadastro do colaborador)
    let minContratados = 480; // padrão: 8h
    if(emp && emp.horarioEntrada && emp.horarioSaida){
      const tEContr = timeToMinutes(emp.horarioEntrada);
      const tSContr = timeToMinutes(emp.horarioSaida);
      if(tEContr!==null && tSContr!==null){
        let minBrutosContr = tSContr - tEContr;
        if(minBrutosContr <= 0) minBrutosContr += 24*60;
        minContratados = Math.max(0, minBrutosContr - minIntervalo);
      }
    } else if(emp){
      const fam = escalaFamilia(emp.escala||'5x2A');
      if(fam==='6x1')   minContratados=440;  // 7h20min
      else if(fam==='12x36') minContratados=660; // 11h (12h - 1h intervalo)
    }

    const minExtrasDia = Math.max(0, minLiquidos - minContratados);
    const hExtrasDia   = minExtrasDia / 60;
    const hExtrasMes   = hExtrasDia * dias;

    setVal('payroll-horas-liquidas',  minutesToStr(minLiquidos));
    setVal('payroll-horas-extras-dia', minExtrasDia>0 ? minutesToStr(minExtrasDia) : '—');

    // Auto-preencher total de horas extras (editável pelo usuário)
    if(hExtrasMes > 0 || numVal('payroll-he-total')===0){
      setVal('payroll-he-total', hExtrasMes>0 ? hExtrasMes.toFixed(2) : '');
    }
  } else {
    setVal('payroll-horas-liquidas','—');
    setVal('payroll-horas-extras-dia','—');
  }

  // ── HORAS EXTRAS de folha com ponto diário ──────────────────────────
  // Se a folha tem ponto batido dia a dia, o total de HE vem da revisão
  // por dia (_heMinFromDias respeita aprovado/recusado/pendente). Isso
  // SOBREPÕE o cálculo "jornada representativa × dias" acima — sem isso a
  // folha pagaria HE não aprovada / não refletiria as edições do ponto.
  (function(){
    const empId = val('payroll-employee');
    const mesN  = parseInt(val('payroll-mes')||currentMes());
    const anoN  = parseInt(val('payroll-ano')||currentAno());
    const reg   = State.payrolls.find(p=>p.employeeId===empId&&p.mes==mesN&&p.ano==anoN);
    const cards = _getPontoManualCards();
    const diasP = cards.length ? _collectPontoManualDias()
                : (reg && Array.isArray(reg.pontoManualDias) ? reg.pontoManualDias : null);
    if(!emp || !diasP || !diasP.some(d=>d&&d.entrada&&d.saida)) return;
    const heMin = _heMinFromDias(emp, mesN, anoN, diasP);
    setVal('payroll-he-total', heMin>0 ? +(heMin/60).toFixed(2) : '');
  })();

  // Valor das horas extras
  const hETotalInformado = numVal('payroll-he-total')||0;
  const percHE = parseInt(val('payroll-he-perc')||'50');
  const valorHE = hETotalInformado>0 && salBase>0
    ? hETotalInformado * (salBase/220) * (1 + percHE/100) : 0;
  // Destino das horas extras: pagar na folha ou lançar no banco de horas
  const heDestino = val('payroll-he-destino')||'folha';
  const heBancoNote = document.getElementById('he-banco-note');
  if(heDestino==='banco'){
    // Vai para o banco — não entra no valor a pagar (he-valor = 0)
    setVal('payroll-he-valor','0.00');
    if(heBancoNote){
      if(hETotalInformado>0){
        const vmBanco = State.cct?.bancoValidadeMeses || 12;
        heBancoNote.style.display='';
        heBancoNote.innerHTML=`<i class="fa-solid fa-piggy-bank"></i> <strong>${hETotalInformado.toFixed(2).replace('.',',')} h</strong> serão lançadas no banco de horas ao salvar a folha (1 para 1, validade de ${vmBanco} meses). Não entram no valor a pagar.`;
      } else {
        heBancoNote.style.display='none';
      }
    }
  } else {
    setVal('payroll-he-valor', valorHE>0 ? valorHE.toFixed(2) : '0.00');
    if(heBancoNote) heBancoNote.style.display='none';
  }

  // --- HE Corrido (calculado a partir da Escala) ---
  // Para cada dia com tipo='corrido' na escala do colaborador no mês,
  // soma minutos de refeição que viraram extra, multiplica por valor-hora e adicional do dia
  const heCorridoBlock = document.getElementById('he-corrido-block');
  let heCorridoMin = 0, heCorridoValor = 0;
  let heCorridoDetalhe = '';
  if(emp){
    const empMes = parseInt(val('payroll-mes'));
    const empAno = parseInt(val('payroll-ano'));
    const escalaDoMes = (State.escalas||[]).find(e =>
      e.employeeId===emp.id && e.mes==empMes && e.ano==empAno);
    if(escalaDoMes && Array.isArray(escalaDoMes.dias)){
      // Duração da refeição (em min) baseada no cadastro do colaborador
      let refMin = 60;
      if(emp.horarioRefIni && emp.horarioRefFim){
        let dm = timeToMinutes(emp.horarioRefFim) - timeToMinutes(emp.horarioRefIni);
        if(dm < 0) dm += 24*60;
        if(dm > 0 && dm <= 4*60) refMin = dm;
      }
      const buckets = {}; // {perc: minutos}
      escalaDoMes.dias.forEach(d => {
        if(d.tipo === 'corrido'){
          const p = parseInt(d.hePercDia)||50;
          buckets[p] = (buckets[p]||0) + refMin;
        }
      });
      Object.entries(buckets).forEach(([perc, minutos]) => {
        heCorridoMin += minutos;
        if(salBase > 0){
          heCorridoValor += (minutos/60) * (salBase/220) * (1 + parseInt(perc)/100);
        }
      });
      heCorridoDetalhe = Object.entries(buckets)
        .map(([perc, minutos]) => `${minutesToStr(minutos)} a +${perc}%`)
        .join(' · ') || '—';
    }
  }
  setVal('payroll-he-corrido-min',     heCorridoMin > 0 ? heCorridoMin : '');
  setVal('payroll-he-corrido-detalhe', heCorridoDetalhe);
  setVal('payroll-he-corrido-valor',   heCorridoValor > 0 ? heCorridoValor.toFixed(2) : '0.00');
  if(heCorridoBlock){
    heCorridoBlock.style.display = (heCorridoMin > 0) ? '' : 'none';
  }

  // --- Adiantamento quinzenal ---
  // SEMPRE calculado sobre o SALÁRIO BASE do cadastro (não sobre a
  // remuneração apurada do mês). Padrão: adiantamento quinzenal é um %
  // fixo do salário base, pago no meio do mês — independente de quantos
  // dias da folha já foram lançados.
  const ativoAdiant=val('payroll-adiantamento-ativo')==='sim';
  const percAdiant=parseInt(val('payroll-adiantamento-perc')||'40');
  if(ativoAdiant && salBase>0){
    setVal('payroll-adiantamento-valor',((salBase*(percAdiant/100))).toFixed(2));
  } else {
    setVal('payroll-adiantamento-valor','0.00');
  }

  // --- Encargos Legais (INSS / IRRF / FGTS) ---
  const encargosCard=document.getElementById('encargos-legais-card');
  if(emp){
    if(encargosCard) encargosCard.classList.remove('hidden');
    const heValEnc   = numVal('payroll-he-valor')||0;
    const noturnoEnc = numVal('payroll-noturno')||0;
    const acumuloEnc = numVal('payroll-acumulo')||0;
    const insalubEnc = numVal('payroll-insalubridade')||0;
    // Boa Permanência NÃO entra no salário — é benefício pago junto com o VR
    // (não tributada). Fica só no campo `bonificacao` (auditoria) e soma no VR.
    const outProv=(emp.outrosProventos||[]).reduce((s,i)=>s+(parseFloat(i.valor)||0),0);
    const outDesc=(emp.outrosDescontos||[]).reduce((s,i)=>s+(parseFloat(i.valor)||0),0);
    // Rubricas fixas p/ todos (Seguro de Vida etc.). provTrib entra na base de impostos. #rubricas-fixas
    const _rfix=_rubricasFixasColab(emp);
    const _rfT=_rubricasFixasTotais(_rfix);
    // DSR sobre HE (Súmula 172 TST): a HE habitual reflete no descanso semanal remunerado.
    // = (HE paga no mês ÷ dias úteis seg-sáb) × (domingos + feriados). Verba SALARIAL →
    // entra na base de INSS/IRRF/FGTS (soma no totalBruto). 12x36 fica de fora (descanso
    // embutido na escala) — decisão do dono 2026-06-03. HE em BANCO não paga (he-valor=0). #dsr-he
    const _is12x36DSR = escalaFamilia(emp.escala||'5x2A')==='12x36';
    const _dsrIncl12x36 = _paramLegal('dsrHe12x36')===true;   // param legal: 12x36 recebe DSR s/ HE?
    let dsrSobreHE = 0;
    if(!isentoPonto && salBase>0 && (!_is12x36DSR || _dsrIncl12x36)){
      const _heBaseDSR = heValEnc + heCorridoValor;   // HE PAGA no mês (folha)
      if(_heBaseDSR>0){
        const _ud=_diasUteisEDescansos(_mesR, _anoR, _locFeriadoEmp(emp));
        if(_ud.uteis>0 && _ud.descansos>0) dsrSobreHE = +(_heBaseDSR/_ud.uteis*_ud.descansos).toFixed(2);
      }
    }
    setVal('payroll-dsr-he', dsrSobreHE>0 ? dsrSobreHE.toFixed(2) : '0.00');
    const totalBruto=remuneracao+heValEnc+heCorridoValor+dsrSobreHE+noturnoEnc+acumuloEnc+insalubEnc+outProv+_rfT.provTrib;
    const pensaoEnc  =emp.pensaoAlimenticia||0;
    const planoEnc   =emp.planoSaude||0;
    const inss=calcINSS(totalBruto);
    const fgts=calcFGTS(totalBruto);
    const irrf=calcIRRF(totalBruto,emp.dependentesIRRF||0,pensaoEnc,planoEnc,inss);
    const adiantEnc=ativoAdiant?numVal('payroll-adiantamento-valor')||0:0;
    const atrasoEnc=numVal('payroll-desconto-atraso')||0;
    // Desconto de saídas durante o expediente (minutos ausentes não-abonados)
    const _saidaTot=_saidaTotais(val('payroll-employee'),_mesR,_anoR);
    // Isento (CLT Art. 62) não sofre desconto de saída — igual ao atraso (9108). #12
    const descontoSaida=isentoPonto?0:Math.round(_saidaTot.minutosDesc*valorMinuto*100)/100;
    setVal('payroll-saida-min', _saidaTot.minutos||'');
    setVal('payroll-desconto-saida', descontoSaida>0?descontoSaida.toFixed(2):'0.00');
    // VR/VA são benefícios pagos à parte (vale/cartão) — NÃO entram no líquido.
    // O VT entra só como CO-PARTICIPAÇÃO (menor entre 6% do salário e o custo do
    // VT) — mesmo critério do holerite e da folha impressa, pra TODOS os cruzamentos
    // (tela, Pagamentos, folha, holerite) baterem. #vt-coparticipacao
    const _vtTotEnc=numVal('payroll-vt-total')||0;
    const vtCoPartEnc=_vtTotEnc>0?Math.min(+(salBase*(_paramLegal('vtCoPartPerc')/100)).toFixed(2), _vtTotEnc):0;
    const emprestEnc=numVal('payroll-emprestimo')||0;   // empréstimo/consignado — desconta do líquido. #planilha-contador
    const totalLiqFinal=Math.max(0,totalBruto+_rfT.provNtrib+refNaoRendidaValor-inss-irrf-pensaoEnc-planoEnc-outDesc-emprestEnc-_rfT.desc-adiantEnc-atrasoEnc-descontoSaida-vtCoPartEnc);
    setVal('payroll-total-bruto',       totalBruto.toFixed(2));
    setVal('payroll-outros-proventos',  outProv.toFixed(2));
    setVal('payroll-outros-descontos',  outDesc.toFixed(2));
    setVal('payroll-inss',              inss.toFixed(2));
    setVal('payroll-irrf',              irrf.toFixed(2));
    setVal('payroll-fgts',              fgts.toFixed(2));
    setVal('payroll-plano-saude-desc',  planoEnc.toFixed(2));
    setVal('payroll-pensao',            pensaoEnc.toFixed(2));
    setVal('payroll-total-liquido-final',totalLiqFinal.toFixed(2));
  } else {
    if(encargosCard) encargosCard.classList.add('hidden');
  }
  try{ renderColabDashboard(); }catch(_){}   // mini-dashboard do colaborador no mês. #colab-dashboard
}

// Dashboard compacto do colaborador (logo abaixo do nome na Folha): atrasos, horas
// extras (aprovadas/pendentes), atestados, abonos e faltas do mês. #colab-dashboard
function renderColabDashboard(){
  const box=document.getElementById('payroll-colab-dashboard'); if(!box) return;
  const empId=val('payroll-employee');
  const emp=State.employees.find(e=>e.id===empId);
  if(!emp){ box.innerHTML=''; return; }
  const mes=parseInt(val('payroll-mes')||currentMes()), ano=parseInt(val('payroll-ano')||currentAno());
  const p=(State.payrolls||[]).find(x=>x.employeeId===empId && x.mes==mes && x.ano==ano);

  // Atrasos do mês
  const atr=_atrasoTotais(empId,mes,ano);
  // Horas extras: aprovadas (minutos pagos) + nº de dias pendentes de aprovação
  let heAprovMin=0, hePendDias=0;
  if(p && !emp.isentoPonto){
    try{ heAprovMin=_apuracaoPontoTotais(emp,p).extraMin||0; }catch(_){}
    (Array.isArray(p.pontoManualDias)?p.pontoManualDias:[]).forEach(pd=>{
      if(!pd||!pd.dia||!pd.entrada||!pd.saida) return;
      let detec; try{ detec=_detectHEDivergencia({dia:pd.dia,diaSem:pd.diaSem,entrada:pd.entrada,saida:pd.saida,intIni:pd.intIni,intFim:pd.intFim,heReview:pd.heReview}, _getExpectedDay(emp,mes,ano,pd.dia)); }catch(_){ detec=null; }
      if(detec && detec.precisaRevisao){ const st=pd.heReview&&pd.heReview.status; if(st!=='aprovado' && st!=='recusado') hePendDias++; }
    });
  }
  // Atestados / abonos
  const at=_atestadoTotais(empId,mes,ano);
  const _abs=(State.atestados||[]).filter(a=>a.employeeId===empId && a.mes==mes && a.ano==ano && a.status!=='pendente' && a.categoria==='abono');
  const abAbonDias=_abs.filter(a=>a.abona!==false).reduce((s,a)=>s+(parseInt(a.dias)||0),0);
  // Faltas (campos da folha já recalculados)
  const fInj=numVal('payroll-faltas-injustificadas')||0;
  const fJus=numVal('payroll-faltas-justificadas')||0;

  const card=(cor,bg,icon,valor,label,sub,onclick)=>`
    <div onclick="${onclick||''}" style="flex:1;min-width:120px;background:${bg};border:1px solid ${cor}33;border-left:4px solid ${cor};border-radius:10px;padding:9px 12px;${onclick?'cursor:pointer':''}">
      <div style="font-size:11px;color:${cor};font-weight:700;text-transform:uppercase;letter-spacing:.3px"><i class="fa-solid ${icon}"></i> ${label}</div>
      <div style="font-size:18px;font-weight:800;color:#1f2937;line-height:1.1;margin-top:2px">${valor}</div>
      <div style="font-size:11px;color:#64748b;margin-top:1px">${sub||'&nbsp;'}</div>
    </div>`;

  box.innerHTML=`
    <div style="margin:4px 0 14px">
      <div style="font-size:11px;font-weight:700;color:#475569;text-transform:uppercase;letter-spacing:.4px;margin-bottom:6px"><i class="fa-solid fa-chart-simple" style="color:#1565C0"></i> Situação do mês — ${esc(emp.nome||'')}</div>
      <div style="display:flex;gap:8px;flex-wrap:wrap">
        ${card('#C2410C','#FFF7ED','fa-user-clock', (atr.minutos>0?minutesToStr(atr.minutos):'0h'), 'Atrasos', `${atr.count||0} dia(s)${atr.minutosDesc>0?' · desconta':''}`)}
        ${card('#0E7490','#ECFEFF','fa-bolt', (heAprovMin>0?minutesToStr(heAprovMin):'0h'), 'Horas extras', hePendDias>0?`<span style="color:#E65100;font-weight:700">${hePendDias} dia(s) a aprovar</span>`:'todas aprovadas', hePendDias>0?'openHEReview()':'')}
        ${card('#1B5E20','#E8F5E9','fa-notes-medical', `${at.dias||0} dia(s)`, 'Atestados', at.horasMin>0?(minutesToStr(at.horasMin)+' em horas'):'pagos')}
        ${card('#1565C0','#E3F2FD','fa-calendar-check', `${abAbonDias} abon.`, 'Abonos', `${at.diasNaoAbonados||0} não abonado(s)`)}
        ${card('#C62828','#FDECEA','fa-user-xmark', `${fInj} injust.`, 'Faltas', `${fJus} justificada(s)`)}
      </div>
    </div>`;
}

function renderPayrollHistory(empId){
  const histEl=document.getElementById('payroll-history');
  if(!empId){ histEl.innerHTML=`<div class="empty-state small"><i class="fa-solid fa-user-clock"></i><p>Selecione um colaborador</p></div>`; return; }
  const records=State.payrolls.filter(p=>p.employeeId===empId).sort((a,b)=>b.ano-a.ano||b.mes-a.mes);
  if(records.length===0){ histEl.innerHTML=`<div class="empty-state small"><i class="fa-solid fa-folder-open"></i><p>Sem lançamentos anteriores</p></div>`; return; }
  histEl.innerHTML=records.map(p=>{
    const totalFaltas='faltasJustificadas' in p?(p.faltasJustificadas||0)+(p.faltasInjustificadas||0):(p.faltas||0);
    return `<div class="history-item" onclick="loadPayrollRecord('${p.id}')">
      <div class="history-period">${MESES[p.mes].substr(0,3)}/${p.ano}</div>
      <div class="history-info">
        <div class="h-name">${p.diasTrabalhados} dias / ${totalFaltas} falta(s)</div>
        <div class="h-sub">Remun.: ${fmtMoney(p.remuneracao)}</div>
      </div>
      <div class="history-actions">
        <button class="btn-icon btn-danger-icon" onclick="confirmDeletePayroll(event,'${p.id}')" title="Excluir"><i class="fa-solid fa-trash"></i></button>
      </div>
    </div>`;
  }).join('');
}

let _loadingPayroll = false;
function loadPayrollRecord(id){
  const p=State.payrolls.find(r=>r.id===id); if(!p) return;
  // Anti-recursão: loadPayrollRecord chama onPayrollEmployeeChange no fim, que
  // por sua vez chama loadPayrollRecord — sem este guard o par entra em
  // recursão infinita (RangeError) e a folha abre quebrada / sem colaborador.
  if(_loadingPayroll) return;
  _loadingPayroll = true;
  try {
  _ensurePayrollEmployeeOption(p.employeeId); // garante o nome certo no select
  setVal('payroll-employee',p.employeeId); setVal('payroll-mes',p.mes); setVal('payroll-ano',p.ano);
  // Período De/Até — restaura se salvo, caso contrário auto-preenche
  if(p.periodoDe) setVal('payroll-periodo-de',p.periodoDe);
  if(p.periodoAte) setVal('payroll-periodo-ate',p.periodoAte);
  setVal('payroll-observacao-folha', p.observacaoFolha||'');  // #folha-detalhada
  if(!p.periodoDe||!p.periodoAte) _autoFillPeriodoDates(p.mes,p.ano);
  setVal('payroll-dias',p.diasTrabalhados);
  // Suporte a registros antigos (campo faltas único) e novos (divididos)
  setVal('payroll-faltas-justificadas',p.faltasJustificadas||0);
  setVal('payroll-faltas-injustificadas',p.faltasInjustificadas||(p.faltas||0));
  setVal('payroll-remuneracao',p.remuneracao); setVal('payroll-vt-dia',p.vtDia||'');
  setVal('payroll-vt-total',p.valeTransporte); setVal('payroll-vr-dia',p.vrDia||'');
  setVal('payroll-vr-total',p.valeRefeicao); setVal('payroll-va-total',p.valeAlimentacaoTotal||'');
  setVal('payroll-va-liquido',p.valeAlimentacaoLiquido||''); setVal('payroll-bonus',p.bonificacao||'');
  setVal('payroll-noturno',p.adNoturno||'');
  setVal('payroll-acumulo',p.acumuloFuncao||'');
  setVal('payroll-insalubridade',p.insalubridade||'');
  setVal('payroll-emprestimo',p.emprestimo||'');
  // Atrasos: ocorrências vêm da coleção `atrasos`; o recalculate preenche os
  // campos ocultos de total/desconto. Aqui só restaura o total salvo.
  setVal('payroll-atraso-min',p.minutosAtraso||'');
  setVal('payroll-desconto-atraso',p.descontoAtraso||'');
  // Optante (recebeAdiantamento no cadastro) FORÇA o adiantamento ativo —
  // mesmo em folhas salvas antes da marcação OU se o campo não tinha sido gravado.
  // Sem isso, dava prejuízo na empresa: pagava o salário cheio sem descontar o
  // adiantamento já pago no meio do mês.
  const _adEmp = State.employees.find(e=>e.id===p.employeeId);
  // Optante só força "Sim" se cumpre o prazo mínimo de casa (ou é isento). Folha já com
  // adiantamento ATIVO salvo permanece (não é desfeita). #adiant-prazo-admissao
  const _adOptante = !!(_adEmp && _adEmp.recebeAdiantamento) && _adiantElegivelPrazo(_adEmp, p);
  const _adPerc = p.adiantamentoPerc || 40;
  setVal('payroll-adiantamento-ativo', (_adOptante || p.adiantamentoAtivo) ? 'sim' : 'nao');
  setVal('payroll-adiantamento-perc', _adPerc);
  // Garante valor coerente: se é optante e ainda não tem valor salvo (folha
  // antiga), calcula AGORA pelo salário base. Evita exibir/persistir R$0 enquanto
  // o recalculate não roda.
  const _adValor = (_adOptante && !p.adiantamentoValor && (_adEmp?.salarioBase||0)>0)
    ? (_adEmp.salarioBase * (_adPerc/100))
    : (p.adiantamentoValor || 0);
  setVal('payroll-adiantamento-valor', _adValor ? _adValor.toFixed(2) : '');
  // Consignado recorrente: se a folha ainda não tem empréstimo lançado, preenche com a
  // soma das parcelas ativas nesta competência (e mostra a nota). Não sobrescreve um
  // valor já lançado/editado à mão. #consignado-recorrente
  try{
    const _cons=_consignadoTotalDoMes(_adEmp, p.mes, p.ano);
    const _cnote=document.getElementById('payroll-consignado-note');
    if(_cons.total>0){
      if(!p.emprestimo || +p.emprestimo===0) setVal('payroll-emprestimo', _cons.total.toFixed(2));
      if(_cnote) _cnote.innerHTML=`<i class="fa-solid fa-building-columns" style="color:#6A1B9A"></i> Consignado recorrente: `+_cons.detalhe.map(d=>`${d.tipo==='publico'?'Público':'Privado'}${d.origem?' '+esc(d.origem):''} — parcela ${d.parcelaNum}/${d.parcelasTotais} (${fmtMoney(d.parcela)})`).join(' · ');
    } else if(_cnote){ _cnote.innerHTML=''; }
  }catch(_){}
  // Jornada & Horas Extras
  setVal('payroll-entrada',       p.horarioEntrada||'');
  setVal('payroll-saida',         p.horarioSaida||'');
  setVal('payroll-intervalo-inicio', p.intervaloInicio||'');
  setVal('payroll-intervalo-fim',    p.intervaloFim||'');
  setVal('payroll-he-total',  p.horasExtrasTotal||'');
  setVal('payroll-he-perc',   p.horasExtrasPerc||50);
  setVal('payroll-he-valor',  p.horasExtrasValor||'');
  setVal('payroll-he-destino',p.heDestino||'folha');
  setVal('payroll-he-corrido-min',     p.heCorridoMin||'');
  setVal('payroll-he-corrido-detalhe', p.heCorridoDetalhe||'');
  setVal('payroll-he-corrido-valor',   p.heCorridoValor||'');
  setVal('payroll-dsr-he',             p.dsrSobreHE||'');
  const emp=State.employees.find(e=>e.id===p.employeeId);
  if(emp) setVal('payroll-pix',emp.chavePix||'');
  onPayrollEmployeeChange();
  // Atualiza o painel de fechamento + badge de status pra refletir a
  // competência da folha clicada no histórico (antes o painel ficava preso
  // na competência anterior — o badge não trocava).
  _updatePainelFechamento(p.mes, p.ano);
  _autoFillPeriodoDates(p.mes, p.ano);
  } finally { _loadingPayroll = false; }
}

function confirmDeletePayroll(event,id){
  event.stopPropagation();
  const p=State.payrolls.find(r=>r.id===id); if(!p) return;
  document.getElementById('confirm-message').textContent=`Excluir lançamento de ${MESES[p.mes]}/${p.ano}?`;
  const btn=document.getElementById('confirm-ok-btn');
  btn.innerHTML='<i class="fa-solid fa-trash"></i> Excluir';
  btn.onclick=async()=>{
    await DB.remove('payrolls',id);
    // Remove o crédito de banco de horas gerado por esta folha (se houver)
    if((State.bancoHoras||[]).some(b=>b.id==='bh_folha_'+id)){
      await DB.remove('bancoHoras','bh_folha_'+id).catch(()=>{});
    }
    const empNome=(State.employees.find(e=>e.id===p.employeeId)||{}).nome||'—';
    Auth.log('PAYROLL_DELETED', null, `${empNome} — ${MESES[p.mes]}/${p.ano}`);
    closeModal('modal-confirm'); renderPayrollHistory(val('payroll-employee'));
    toast('Lançamento excluído.','warning');
  };
  document.getElementById('modal-confirm').classList.remove('hidden');
}

async function savePayroll(){
  const empId=val('payroll-employee'), mes=val('payroll-mes'), ano=val('payroll-ano');
  if(!empId){ toast('Selecione um colaborador.','error'); return; }
  if(!mes||!ano){ toast('Informe mês e ano.','error'); return; }
  // Bloquear se o cadastro do colaborador estiver incompleto
  const _empSave=State.employees.find(e=>e.id===empId);
  const _pendSave=_cadastroPendencias(_empSave);
  if(_pendSave.length){
    toast(`Complete o cadastro do colaborador antes de salvar a folha. Faltam: ${_pendSave.join(', ')}.`,'error');
    return;
  }
  // Bloquear se a folha estiver fechada
  const existingCheck=State.payrolls.find(p=>p.employeeId===empId&&p.mes==mes&&p.ano==ano);
  if(existingCheck?.status==='fechada'){
    toast('Esta folha está fechada. Clique em "Reabrir esta Folha" para editar.','error'); return;
  }
  const dias=numVal('payroll-dias');
  let faltasJust=numVal('payroll-faltas-justificadas');
  let faltasInjust=numVal('payroll-faltas-injustificadas');
  let totalFaltas=faltasJust+faltasInjust;
  const vtDia=numVal('payroll-vt-dia'), vrDia=numVal('payroll-vr-dia');
  const existing=State.payrolls.find(p=>p.employeeId===empId&&p.mes==mes&&p.ano==ano);
  // Frequência: lê do cadastro do colaborador
  const empSel = State.employees.find(e=>e.id===empId);
  const isentoPontoSave = !!(empSel && empSel.isentoPonto);
  if(isentoPontoSave){
    faltasJust=0; faltasInjust=0; totalFaltas=0;
  }
  const vtFreq = empSel?.vtFreq || 'diario';
  const vrFreq = empSel?.vrFreq || 'diario';
  const semanas = _semanasTrabalhadas(dias, empSel?.escala);
  // VT/VR PERSISTIDOS leem os campos canonicos de recalculate (payroll-vt-total/payroll-vr-total),
  // que ja aplicam a regra >6h (CLT Art.71) e o caso isento — igual ao VA. Antes recomputava
  // vtDia*dias com dias crus e gravava/imprimia A MAIOR (divergente da tela). #fix-vtvr-save
  const valeTransporteTotal = numVal('payroll-vt-total');
  const valeRefeicaoTotal   = numVal('payroll-vr-total');
  // REGRA DURA — prazo mínimo de casa p/ adiantamento (Configurações). Se o operador tentou
  // lançar adiantamento p/ quem não cumpriu o prazo (e não é isento no contrato), força "Não"
  // e avisa — não deixa lançar. #adiant-prazo-admissao
  let _adiantAtivoSave = val('payroll-adiantamento-ativo')==='sim';
  if(_adiantAtivoSave){
    const _empAd=State.employees.find(e=>e.id===empId);
    if(!_adiantElegivelPrazo(_empAd, {mes:parseInt(mes), ano:parseInt(ano)})){
      _adiantAtivoSave=false;
      setVal('payroll-adiantamento-ativo','nao'); setVal('payroll-adiantamento-valor','');
      const _min=parseInt(State.empresa?.adiantamentoMinDiasAdmissao)||0;
      toast(`Adiantamento NÃO lançado: ${_empAd?.nome||'o colaborador'} ainda não tem ${_min} dias de casa (regra em Configurações). Para liberar, marque "Isentar do prazo mínimo de adiantamento" no contrato dele.`,'warning');
    }
  }
  const record={
    id:existing?existing.id:_payrollId(empId,mes,ano), employeeId:empId,
    mes:parseInt(mes), ano:parseInt(ano),
    diasTrabalhados:dias,
    faltas:totalFaltas,
    faltasJustificadas:faltasJust,
    faltasInjustificadas:faltasInjust,
    remuneracao:numVal('payroll-remuneracao'),
    vtDia, vtFreq, semanasTrabalhadas:semanas, valeTransporte:valeTransporteTotal,
    vrDia, vrFreq, valeRefeicao:valeRefeicaoTotal,
    valeAlimentacaoTotal:numVal('payroll-va-total'),
    valeAlimentacaoLiquido:numVal('payroll-va-liquido'),
    // Bonificação: zera só se houver falta E o colaborador NÃO tem flag de "sempre pagar"
    bonificacao:(function(){
      const empRec=State.employees.find(e=>e.id===empId);
      const sempreP=!!(empRec&&empRec.bonificacaoSemprePagar);
      if(totalFaltas>0 && !sempreP) return 0;
      return numVal('payroll-bonus')||0;
    })(),
    adNoturno:isentoPontoSave?0:numVal('payroll-noturno'),
    acumuloFuncao:numVal('payroll-acumulo')||0,
    insalubridade:numVal('payroll-insalubridade')||0,
    emprestimo:numVal('payroll-emprestimo')||0,   // consignado — só informativo na planilha contábil (cód. 0218). #planilha-contador
    // Atrasos — detalhe na coleção `atrasos`; aqui ficam só os totais.
    minutosAtraso:isentoPontoSave?0:(numVal('payroll-atraso-min')||0),
    descontoAtraso:isentoPontoSave?0:(numVal('payroll-desconto-atraso')||0),
    adiantamentoAtivo:_adiantAtivoSave,
    adiantamentoPerc:parseInt(val('payroll-adiantamento-perc')||'40'),
    adiantamentoValor:_adiantAtivoSave?numVal('payroll-adiantamento-valor'):0,
    // Jornada & Horas Extras
    horarioEntrada:val('payroll-entrada')||'',
    horarioSaida:val('payroll-saida')||'',
    intervaloInicio:val('payroll-intervalo-inicio')||'',
    intervaloFim:val('payroll-intervalo-fim')||'',
    horasLiquidasDia:val('payroll-horas-liquidas')||'',
    horasExtrasDia:val('payroll-horas-extras-dia')||'',
    horasExtrasTotal:isentoPontoSave?0:(numVal('payroll-he-total')||0),
    horasExtrasPerc:parseInt(val('payroll-he-perc')||'50'),
    horasExtrasValor:isentoPontoSave?0:(numVal('payroll-he-valor')||0),
    heDestino:val('payroll-he-destino')||'folha',
    // HE Corrido (vinda da Escala — somatório de minutos por % de adicional)
    heCorridoMin:    isentoPontoSave?0:(numVal('payroll-he-corrido-min')||0),
    heCorridoDetalhe:isentoPontoSave?'':(val('payroll-he-corrido-detalhe')||''),
    heCorridoValor:  isentoPontoSave?0:(numVal('payroll-he-corrido-valor')||0),
    dsrSobreHE:      isentoPontoSave?0:(numVal('payroll-dsr-he')||0),   // reflexo DSR s/ HE (Súmula 172). #dsr-he
    pdfName:State.currentPdfFile?State.currentPdfFile.name:(existing?existing.pdfName:''),
    // Encargos Legais
    totalBruto:          numVal('payroll-total-bruto')||0,
    outrosProventosTotal:numVal('payroll-outros-proventos')||0,
    outrosDescontosTotal:numVal('payroll-outros-descontos')||0,
    inss:                numVal('payroll-inss')||0,
    irrf:                numVal('payroll-irrf')||0,
    fgts:                numVal('payroll-fgts')||0,
    planoSaudeDesc:      numVal('payroll-plano-saude-desc')||0,
    pensaoAlimenticiaDesc:numVal('payroll-pensao')||0,
    // Saídas durante o expediente (detalhe na coleção `saidas`)
    minutosSaida:        isentoPontoSave?0:(numVal('payroll-saida-min')||0),
    descontoSaida:       isentoPontoSave?0:(numVal('payroll-desconto-saida')||0),
    totalLiquidoFinal:   numVal('payroll-total-liquido-final')||0,
    // Snapshot das rubricas fixas p/ todos (Seguro de Vida etc.) aplicadas nesta folha —
    // congela o que foi descontado, mesmo que o catálogo mude depois. #rubricas-fixas
    rubricasFixas: _rubricasFixasColab(State.employees.find(e=>e.id===val('payroll-employee'))),
    // Preserva os pontos do app — savePayroll nunca deve apagar pontoManualDias
    // Sanitiza: Firestore rejeita undefined; converte para null ou remove
    pontoManualDias: _sanitizeForFirestore(existing?.pontoManualDias || []),
    // Observação/ajuste manual da folha (impressa no espelho + Contabilidade). #folha-detalhada
    observacaoFolha: val('payroll-observacao-folha')||'',
    // Refeição não rendida (indenizatória, 50%) — snapshot p/ recibo/folha/contab. #ref-nao-rendida
    refNaoRendidaMin:   isentoPontoSave?0:(numVal('payroll-ref-nao-rendida-min')||0),
    refNaoRendidaValor: isentoPontoSave?0:(numVal('payroll-ref-nao-rendida-valor')||0),
    // Período e status
    periodoDe: val('payroll-periodo-de')||'',
    periodoAte: val('payroll-periodo-ate')||'',
    status: existing?.status||'aberta',
    updatedAt:new Date().toISOString(),
    createdAt:existing?existing.createdAt:new Date().toISOString()
  };
  const btn=document.querySelector('#section-payroll .btn-primary');
  setBtnLoading(btn,true,'');
  try {
    // Sanitiza o record inteiro contra `undefined` (Firestore rejeita)
    const cleanRecord = _sanitizeForFirestore(record);
    await DB.save('payrolls', cleanRecord);
    // Atualiza o cache local NA HORA (o listener confirma depois) — assim telas que releem
    // ao voltar (ex.: Contabilidade) já refletem os valores aplicados e o nome sai do aviso
    // de "folhas sem valores". #contab-retorno-competencia
    { const _ix=(State.payrolls||[]).findIndex(p=>p.id===cleanRecord.id); if(_ix>=0) State.payrolls[_ix]=cleanRecord; else (State.payrolls=State.payrolls||[]).push(cleanRecord); }
    // Sincroniza o crédito de banco de horas gerado por esta folha
    await _syncBancoFromPayroll(cleanRecord);
    const empNome=(State.employees.find(e=>e.id===empId)||{}).nome||'—';
    Auth.log(existing?'PAYROLL_UPDATED':'PAYROLL_CREATED', null, `${empNome} — ${MESES[parseInt(mes)]}/${ano}`);
    toast(existing?'Lançamento atualizado!':'Lançamento salvo!');
    clearPdf(null,true);
  } catch(e){
    console.error('savePayroll erro:', e, 'record:', record);
    toast('Erro ao salvar: ' + (e?.message || e), 'error');
  }
  finally { setBtnLoading(btn,false,'<i class="fa-solid fa-floppy-disk"></i> Salvar Lançamento'); }
}

