function openPayrollForEmployee(empId, ctx){
  // ctx (opcional) = { mes, ano, fieldKey, label, color }
  // Quando vem de um drill-down de stat, ajusta o mes/ano da Folha e
  // depois faz scroll + destaca o campo correspondente do indicador clicado.
  showSection('payroll');
  setTimeout(() => {
    if(ctx && ctx.mes) setVal('payroll-mes', String(ctx.mes));
    if(ctx && ctx.ano) setVal('payroll-ano', String(ctx.ano));
    // A seção abre TRAVADA na vigente (#folha-abre-vigente). Se o drill-down aponta uma
    // competência diferente, destrava a navegação p/ exibir/permitir esse período.
    const _vgD=competenciaVigente();
    if(ctx && ((ctx.mes && +ctx.mes!==_vgD.mes) || (ctx.ano && +ctx.ano!==_vgD.ano))){
      const _cP=document.getElementById('chk-consultar-passadas');
      if(_cP && !_cP.checked){ _cP.checked=true; _togglePeriodoNavegacao(true); }
    }
    // REGRA DURA: clicar no nome (Monitor de Faltas, cards, drill-downs) SEMPRE abre a
    // folha DAQUELA pessoa. Garante a opção do colaborador-alvo no select ANTES de
    // selecionar (alinha filtro de posto, inclui demitido/afastado, injeta se faltar).
    // Sem isso, setVal falhava em silêncio quando a pessoa estava fora do dropdown
    // filtrado (ex.: 12x36 de outro posto) e abria a folha de OUTRO colaborador. #monitor-abre-folha-certa
    try { _ensurePayrollEmployeeOption(empId); } catch(e){ console.warn('openPayrollForEmployee', e); }
    setVal('payroll-employee', empId);
    onPayrollEmployeeChange();
    if(ctx && ctx.fieldKey){
      // espera o render da folha terminar para destacar
      setTimeout(() => _highlightPayrollField(ctx.fieldKey, ctx.color || '#5C6BC0'), 250);
    }
  }, 100);
}

// ============================================
// BANCO DE HORAS
// ============================================
// Coleção `bancoHoras`: cada doc é um lançamento (crédito ou débito).
//  - crédito de folha: id fixo `bh_folha_{payrollId}` (idempotente — re-salvar
//    a folha não duplica; trocar para "pagar na folha" remove o crédito)
//  - débito manual:    id via genId()
// Crédito = { tipo:'credito', horas, data, validade, origem:'folha', competencia, payrollId }
// Débito  = { tipo:'debito',  horas, data, origem:'manual', observacao }

function _ultimoDiaMesISO(mes, ano){
  const d=new Date(parseInt(ano), parseInt(mes), 0); // dia 0 do mês seguinte = último dia do mês
  return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
}
function _addMonthsISO(iso, months){
  const [y,m,d]=iso.split('-').map(Number);
  const base=new Date(y, m-1+months, d);
  return `${base.getFullYear()}-${String(base.getMonth()+1).padStart(2,'0')}-${String(base.getDate()).padStart(2,'0')}`;
}
function _fmtHoras(h){
  const n=Math.round((parseFloat(h)||0)*60);
  return n>0 ? minutesToStr(n) : '0h';
}

// Percorre os créditos em FIFO por validade (débitos consomem os mais próximos de
// expirar primeiro) e separa o que ainda é COMPENSÁVEL do que já VENCEU. Horas
// vencidas não podem mais abater jornada — viram HE a pagar (decisão do usuário). #14
function _bancoFifoStatus(empId){
  const movs=(State.bancoHoras||[]).filter(b=>b.employeeId===empId);
  const creditos=movs.filter(m=>m.tipo==='credito'&&(parseFloat(m.horas)||0)>0)
    .map(m=>({horas:parseFloat(m.horas)||0, validade:(m.validade||m.data||'')}))
    .sort((a,b)=>String(a.validade).localeCompare(String(b.validade)));
  let debito=movs.filter(m=>m.tipo==='debito').reduce((s,m)=>s+(parseFloat(m.horas)||0),0);
  const hojeISO=new Date().toISOString().substring(0,10);
  // Débitos (compensação) consomem créditos VÁLIDOS primeiro; créditos VENCIDOS NÃO são
  // abatidos por compensação — viram HE a pagar (regra #14). Antes o FIFO por validade
  // comia os vencidos primeiro, fazendo o colaborador PERDER as horas devidas. #fix-banco-venc
  const _vencido = c => c.validade && c.validade < hojeISO;
  const validos  = creditos.filter(c=>!_vencido(c));   // já ordenados por validade asc
  const vencidos = creditos.filter(_vencido);
  let saldoValido=0, horasVencidas=0;
  for(const c of validos){
    let rem=c.horas;
    if(debito>0){ const use=Math.min(rem,debito); rem-=use; debito-=use; }
    if(rem>0.0001) saldoValido+=rem;
  }
  horasVencidas = vencidos.reduce((s,c)=>s+c.horas,0);
  // Débito remanescente (excede os válidos — raro, barrado pelo gate) abate as vencidas por último.
  if(debito>0.0001) horasVencidas = Math.max(0, horasVencidas - debito);
  const r=x=>Math.round(x*1e6)/1e6;
  return { saldoValido:r(saldoValido), horasVencidas:r(horasVencidas) };
}

// Saldo COMPENSÁVEL (exclui créditos vencidos — esses viram HE a pagar e não
// abatem mais jornada). Antes somava tudo, inclusive horas já expiradas. #14
function bancoSaldo(empId){
  return _bancoFifoStatus(empId).saldoValido;
}

// FIFO: débitos consomem os créditos mais antigos. Retorna o crédito vivo
// mais próximo de expirar { horas, validade } ou null se não há saldo.
function bancoProximaExpiracao(empId){
  const movs=(State.bancoHoras||[]).filter(b=>b.employeeId===empId);
  const creditos=movs.filter(m=>m.tipo==='credito'&&(parseFloat(m.horas)||0)>0)
    .map(m=>({horas:parseFloat(m.horas)||0, validade:m.validade||m.data||''}))
    .sort((a,b)=>a.validade.localeCompare(b.validade));
  let debito=movs.filter(m=>m.tipo==='debito').reduce((s,m)=>s+(parseFloat(m.horas)||0),0);
  for(const c of creditos){
    let rem=c.horas;
    if(debito>0){ const use=Math.min(rem,debito); rem-=use; debito-=use; }
    if(rem>0.0001) return { horas:rem, validade:c.validade };
  }
  return null;
}

// Sincroniza o crédito de banco de horas gerado por uma folha de ponto
async function _syncBancoFromPayroll(record){
  const docId='bh_folha_'+record.id;
  const existing=(State.bancoHoras||[]).find(b=>b.id===docId);
  if(record.heDestino==='banco' && (record.horasExtrasTotal||0)>0){
    const validadeMeses=State.cct?.bancoValidadeMeses||12;
    // Data do lançamento = fim da competência (dia 25), não o último dia do mês.
    const dataLanc=_compPeriodo(record.mes, record.ano).ateISO;
    const doc={
      id:docId, employeeId:record.employeeId, tipo:'credito',
      horas:record.horasExtrasTotal, data:dataLanc,
      validade:_addMonthsISO(dataLanc, validadeMeses),
      origem:'folha',
      competencia:`${String(record.mes).padStart(2,'0')}/${record.ano}`,
      payrollId:record.id, observacao:'',
      createdAt:existing?.createdAt||new Date().toISOString(),
      updatedAt:new Date().toISOString()
    };
    try { await DB.save('bancoHoras', doc); }
    catch(e){ console.error('Erro ao lançar crédito no banco de horas:', e); }
  } else if(existing){
    try { await DB.remove('bancoHoras', docId); }
    catch(e){ console.error('Erro ao remover crédito do banco de horas:', e); }
  }
}

// --- Modal Banco de Horas ---
function openBancoHorasFromPayroll(){
  const empId=val('payroll-employee');
  if(!empId){ toast('Selecione um colaborador na folha primeiro.','error'); return; }
  openBancoHoras(empId);
}
function openBancoHoras(empId){
  const emp=State.employees.find(e=>e.id===empId);
  if(!emp){ toast('Colaborador não encontrado.','error'); return; }
  setVal('bh-emp-id', empId);
  document.getElementById('bh-emp-nome').textContent=emp.nome||'—';
  setVal('bh-deb-data', new Date().toISOString().split('T')[0]);
  setVal('bh-deb-horas','');
  setVal('bh-deb-obs','');
  document.getElementById('modal-banco-horas').classList.remove('hidden');
  renderBancoHoras();
}
function renderBancoHoras(){
  const empId=val('bh-emp-id'); if(!empId) return;
  const movs=(State.bancoHoras||[]).filter(b=>b.employeeId===empId)
    .slice().sort((a,b)=>(b.data||'').localeCompare(a.data||''));
  const saldo=bancoSaldo(empId);
  const exp=bancoProximaExpiracao(empId);
  const _fifo=_bancoFifoStatus(empId);
  const _empBH=State.employees.find(e=>e.id===empId)||{};
  const _bhHePerc=_hePercVencidas(); // % de HE p/ horas vencidas (CCT; padrão 50%). #14-cct
  const _bhVencValor=_fifo.horasVencidas>0 ? Math.round(_fifo.horasVencidas*((parseFloat(_empBH.salarioBase||0))/220)*(1+_bhHePerc/100)*100)/100 : 0;
  const vencCard=_fifo.horasVencidas>0.0001 ? `<div style="flex:1;min-width:200px;background:#FFF8E1;border:1px solid #FFE082;border-left:4px solid #E65100;border-radius:8px;padding:10px 12px">
      <div style="font-size:11px;color:#E65100;text-transform:uppercase;letter-spacing:.5px">Vencidas — pagar como HE (${_bhHePerc}%)</div>
      <div style="font-size:18px;font-weight:700;color:#E65100">${_fmtHoras(_fifo.horasVencidas)} · ${fmtMoney(_bhVencValor)}</div>
      <button class="btn btn-sm" style="margin-top:6px;background:#E65100;color:#fff;border:none" onclick="pagarHorasVencidasHE('${empId}')"><i class="fa-solid fa-money-bill-wave"></i> Lançar pagamento de HE</button>
    </div>` : '';
  const hoje=new Date(); hoje.setHours(0,0,0,0);
  // Card de próxima expiração
  let expCard;
  if(exp&&exp.validade){
    const dv=new Date(exp.validade+'T00:00:00');
    const dias=Math.round((dv-hoje)/(1000*60*60*24));
    const cor=dias<0?'#C62828':dias<=30?'#E65100':'#00695C';
    const txt=dias<0?`Expirou há ${Math.abs(dias)} dia(s)`:dias===0?'Expira hoje':`Expira em ${dias} dia(s)`;
    expCard=`<div style="flex:1;min-width:170px;background:#fff;border:1px solid #B2DFDB;border-left:4px solid ${cor};border-radius:8px;padding:10px 12px">
      <div style="font-size:11px;color:#607D8B;text-transform:uppercase;letter-spacing:.5px">Próxima a expirar</div>
      <div style="font-size:18px;font-weight:700;color:${cor}">${_fmtHoras(exp.horas)}</div>
      <div style="font-size:12px;color:${cor}">${txt} · ${formatDateBr(exp.validade)}</div>
    </div>`;
  } else {
    expCard=`<div style="flex:1;min-width:170px;background:#fff;border:1px solid #E0E0E0;border-radius:8px;padding:10px 12px">
      <div style="font-size:11px;color:#607D8B;text-transform:uppercase;letter-spacing:.5px">Próxima a expirar</div>
      <div style="font-size:14px;color:#9E9E9E;margin-top:8px">Sem horas no banco</div>
    </div>`;
  }
  document.getElementById('bh-resumo').innerHTML=`
    <div style="flex:1;min-width:170px;background:#fff;border:1px solid #B2DFDB;border-left:4px solid #00897B;border-radius:8px;padding:10px 12px">
      <div style="font-size:11px;color:#607D8B;text-transform:uppercase;letter-spacing:.5px">Saldo atual</div>
      <div style="font-size:22px;font-weight:700;color:#00695C">${_fmtHoras(saldo)}</div>
    </div>
    ${expCard}
    ${vencCard}`;
  // Extrato
  if(!movs.length){
    document.getElementById('bh-extrato').innerHTML=`<div class="empty-state small"><i class="fa-solid fa-piggy-bank"></i><p>Nenhum lançamento no banco de horas</p></div>`;
    return;
  }
  const rows=movs.map(m=>{
    const isCred=m.tipo==='credito';
    const cor=isCred?'#2E7D32':'#C62828';
    const sinal=isCred?'+':'−';
    const tipoLabel=isCred?'<span style="color:#2E7D32;font-weight:600">Crédito</span>':'<span style="color:#C62828;font-weight:600">Baixa</span>';
    const desc=isCred
      ? (m.origem==='folha'?`Folha ${m.competencia||''}`:'Crédito manual')
      : (m.observacao||'Compensação');
    const validade=(isCred&&m.validade)?`<span style="font-size:11px;color:#607D8B">val. ${formatDateBr(m.validade)}</span>`:'—';
    const acao=(m.origem==='manual')
      ? `<button class="btn-icon" onclick="removeBancoLancamento('${m.id}')" title="Excluir lançamento"><i class="fa-solid fa-trash" style="color:#C62828"></i></button>`
      : `<span style="font-size:12px;color:#9E9E9E" title="Crédito gerado pela Folha de Ponto — altere lá">🔒</span>`;
    return `<tr>
      <td>${m.data?formatDateBr(m.data):'—'}</td>
      <td>${tipoLabel}</td>
      <td style="font-weight:700;color:${cor}">${sinal} ${_fmtHoras(m.horas)}</td>
      <td>${desc}</td>
      <td>${validade}</td>
      <td style="text-align:center">${acao}</td>
    </tr>`;
  }).join('');
  document.getElementById('bh-extrato').innerHTML=`
    <table class="data-table" style="font-size:13px">
      <thead><tr><th>Data</th><th>Tipo</th><th>Horas</th><th>Descrição</th><th>Validade</th><th></th></tr></thead>
      <tbody>${rows}</tbody>
    </table>`;
}
async function addBancoDebito(){
  const empId=val('bh-emp-id'); if(!empId){ toast('Colaborador não definido.','error'); return; }
  const data=val('bh-deb-data');
  const horas=numVal('bh-deb-horas');
  const obs=val('bh-deb-obs');
  if(!data){ toast('Informe a data da baixa.','error'); return; }
  if(!(horas>0)){ toast('Informe as horas compensadas.','error'); return; }
  const saldo=bancoSaldo(empId);
  if(horas>saldo+0.0001){
    toast(`Baixa (${_fmtHoras(horas)}) maior que o saldo disponível (${_fmtHoras(saldo)}).`,'error');
    return;
  }
  const doc={
    id:genId(), employeeId:empId, tipo:'debito',
    horas, data, origem:'manual', observacao:obs||'',
    createdAt:new Date().toISOString(), updatedAt:new Date().toISOString()
  };
  try {
    await DB.save('bancoHoras', doc);
    const empNome=(State.employees.find(e=>e.id===empId)||{}).nome||'—';
    Auth.log('BANCO_HORAS_DEBITO', null, `${empNome} — baixa de ${_fmtHoras(horas)}`);
    setVal('bh-deb-horas',''); setVal('bh-deb-obs','');
    toast('Baixa lançada no banco de horas.');
    renderBancoHoras();
  } catch(e){ toast('Erro ao lançar baixa: '+(e?.message||e),'error'); }
}

// Paga as horas de banco VENCIDAS como HORA EXTRA. Baixa as horas do banco
// (débito origem 'vencido') e cria uma solicitação de pagamento PENDENTE que vai
// para Aprovações (PIX/2FA) — reusa o fluxo padrão, sem caminho paralelo. #14
async function pagarHorasVencidasHE(empId){
  if(!getUserModules(Auth.currentUser).pagamentosLancar){ toast('Você não tem permissão para lançar pagamentos.','error'); return; }
  const emp=State.employees.find(e=>e.id===empId); if(!emp){ toast('Colaborador não encontrado.','error'); return; }
  const { horasVencidas }=_bancoFifoStatus(empId);
  if(!(horasVencidas>0.0001)){ toast('Não há horas vencidas a pagar.','info'); return; }
  const salBase=parseFloat(emp.salarioBase||0);
  const hePerc=_hePercVencidas(); // % de HE p/ horas vencidas (CCT; padrão 50%). #14-cct
  const valorHora=salBase/220;
  const valor=Math.round(horasVencidas*valorHora*(1+hePerc/100)*100)/100;
  const hojeISO=new Date().toISOString().substring(0,10);
  document.getElementById('confirm-message').innerHTML=`Pagar <strong>${_fmtHoras(horasVencidas)}</strong> de banco de horas VENCIDAS como hora extra (${hePerc}%) para <strong>${esc(emp.nome||'')}</strong>?<br><br>`+
    `Valor: <strong>${fmtMoney(valor)}</strong> &nbsp;<span style="font-size:12px;color:#607D8B">(${_fmtHoras(horasVencidas)} × ${fmtMoney(valorHora)}/h × ${(1+hePerc/100).toFixed(2).replace('.',',')})</span><br><br>`+
    `Isso baixa as horas do banco e cria uma solicitação de pagamento <strong>pendente em Aprovações</strong>.`;
  const btn=document.getElementById('confirm-ok-btn');
  btn.innerHTML='<i class="fa-solid fa-money-bill-wave"></i> Lançar HE';
  btn.onclick=async()=>{
    btn.onclick=null;
    try{
      // 1) Baixa as horas vencidas do banco (FIFO consome justamente os créditos expirados).
      await DB.save('bancoHoras', {
        id:genId(), employeeId:empId, tipo:'debito', horas:horasVencidas, data:hojeISO,
        origem:'vencido', observacao:`Vencidas pagas como HE ${hePerc}% — ${fmtMoney(valor)}`,
        createdAt:new Date().toISOString(), updatedAt:new Date().toISOString()
      });
      // 2) Solicitação de pagamento → Aprovações (PIX/2FA).
      await _criarSolicitacaoPagamento({
        employeeId:empId, employeeNome:emp.nome||'', valor,
        pixKey:emp.chavePix||'', keyType:'CPF',
        descricao:`HE de banco de horas vencidas — ${_fmtHoras(horasVencidas)} × ${hePerc}%`,
        scheduleDate:hojeISO, competencia:`BHVENC_${hojeISO}`, origem:'banco-he-vencida'
      });
      Auth.log('BANCO_HORAS_HE_VENCIDA', null, `${emp.nome} — ${_fmtHoras(horasVencidas)} pagas como HE (${fmtMoney(valor)})`);
      closeModal('modal-confirm');
      renderBancoHoras();
      toast('HE vencida lançada e enviada para Aprovações.','success');
    }catch(e){ toast('Erro ao lançar: '+(e?.message||e),'error'); console.error(e); }
  };
  document.getElementById('modal-confirm').classList.remove('hidden');
}

function removeBancoLancamento(id){
  const m=(State.bancoHoras||[]).find(b=>b.id===id);
  if(!m) return;
  if(m.origem!=='manual'){ toast('Créditos da folha são alterados na Folha de Ponto.','warning'); return; }
  document.getElementById('confirm-message').textContent=`Excluir esta baixa de ${_fmtHoras(m.horas)} do banco de horas?`;
  const btn=document.getElementById('confirm-ok-btn');
  btn.innerHTML='<i class="fa-solid fa-trash"></i> Excluir';
  btn.onclick=async()=>{
    try { await DB.remove('bancoHoras', id); } catch(e){}
    closeModal('modal-confirm');
    renderBancoHoras();
    toast('Lançamento excluído.','warning');
  };
  document.getElementById('modal-confirm').classList.remove('hidden');
}

// ============================================
// FECHAMENTO DE PERÍODO
// ============================================
function _periodoKey(mes,ano){ return `${ano}_${mes}`; }

function _autoFillPeriodoDates(mes,ano){
  mes=parseInt(mes); ano=parseInt(ano);
  if(!mes||!ano) return;
  // Competência fecha no dia 25: período 26/(mês-1) → 25/mês.
  const p=_compPeriodo(mes,ano);
  const de=p.deISO, ate=p.ateISO;
  const deEl=document.getElementById('payroll-periodo-de');
  const ateEl=document.getElementById('payroll-periodo-ate');
  // Sempre força o período correto da competência (campos são informativos/derivados).
  if(deEl) deEl.value=de;
  if(ateEl) ateEl.value=ate;
}

function onPayrollPeriodoChange(){
  const mes=val('payroll-mes')||currentMes();
  const ano=val('payroll-ano')||currentAno();
  _autoFillPeriodoDates(mes,ano);
  _updatePainelFechamento(mes,ano);
  // Mantém o dropdown "Carregar competência" refletindo o período atual.
  const _selComp=document.getElementById('payroll-competencia-rapida');
  if(_selComp){ const k=`${ano}-${String(mes).padStart(2,'0')}`; if([..._selComp.options].some(o=>o.value===k)) _selComp.value=k; }
  // Recarregar folha do colaborador selecionado para o novo período
  const empId=val('payroll-employee');
  if(empId) onPayrollEmployeeChange();
}

async function _updatePainelFechamento(mes,ano){
  mes=parseInt(mes||currentMes()); ano=parseInt(ano||currentAno());
  const key=_periodoKey(mes,ano);
  const label=document.getElementById('fechamento-periodo-label');
  const badge=document.getElementById('fechamento-status-badge');
  const btnFechar=document.getElementById('btn-fechar-periodo');
  const btnReabrir=document.getElementById('btn-reabrir-periodo');
  const infoFechado=document.getElementById('fechamento-periodo-fechado-info');
  const dataInput=document.getElementById('fechamento-data-input');
  if(label) label.textContent=`${MESES[mes]} / ${ano}  ·  ${_compLabel(mes,ano)}`;

  // Carregar config do Firestore
  let conf={};
  try{
    const confDoc=await DB.getDoc('configuracoes',`fechamento_${key}`);
    if(confDoc) conf=confDoc;
  }catch(e){ console.warn('Conf fechamento não carregada:',e); }
  State.confFolha=State.confFolha||{};
  State.confFolha[key]=conf;

  if(dataInput) dataInput.value=conf.dataFechamento||'';
  const hoje=new Date().toISOString().substring(0,10);
  const periodoFechado=!!conf.fechado;

  if(badge){
    badge.innerHTML=periodoFechado
      ? `<span style="background:#E8EAF6;color:#5C6BC0;padding:4px 10px;border-radius:12px;font-size:12px;font-weight:700"><i class="fa-solid fa-lock"></i> Período Fechado</span>`
      : `<span style="background:#E8F5E9;color:#2E7D32;padding:4px 10px;border-radius:12px;font-size:12px;font-weight:700"><i class="fa-solid fa-lock-open"></i> Período Aberto</span>`;
  }
  if(btnFechar) btnFechar.style.display=periodoFechado?'none':'inline-flex';
  if(btnReabrir){
    const temFechada=State.payrolls.some(p=>p.mes==mes&&p.ano==ano&&p.status==='fechada');
    btnReabrir.style.display=(periodoFechado||temFechada)?'inline-flex':'none';
  }
  const btnFolhasFechadas=document.getElementById('btn-folhas-fechadas');
  if(btnFolhasFechadas){
    const temFechada=State.payrolls.some(p=>p.mes==mes&&p.ano==ano&&p.status==='fechada');
    btnFolhasFechadas.style.display=temFechada?'inline-flex':'none';
  }
  // Se a lista estiver aberta, mantém em sincronia ao re-renderizar o painel.
  if(document.getElementById('modal-folhas-fechadas')) renderFolhasFechadasLista();
  if(infoFechado){
    if(periodoFechado && conf.fechadoEm){
      infoFechado.style.display='inline';
      infoFechado.textContent=`Fechado em ${new Date(conf.fechadoEm).toLocaleDateString('pt-BR')}`;
    } else { infoFechado.style.display='none'; }
  }

  // Botão "Enviar p/ Conferência" + sumário de status (visível só p/ master
  // OU usuários com permissão folhaEnviar; só aparece com folhas fechadas).
  const btnEnviar = document.getElementById('btn-enviar-conferencia');
  const envioStatus = document.getElementById('fechamento-envio-status');
  if(btnEnviar){
    const folhasFechadas = State.payrolls.filter(p=>p.mes==mes&&p.ano==ano&&p.status==='fechada');
    const podeEnviar = Auth.currentUser?.role==='master' || getUserModules(Auth.currentUser).folhaEnviar;
    btnEnviar.style.display = (folhasFechadas.length>0 && podeEnviar) ? 'inline-flex' : 'none';
    if(envioStatus){
      if(folhasFechadas.length>0 && podeEnviar){
        const cnt = { pendente:0, visualizada:0, assinada:0, contestada:0, aceita_por_silencio:0, naoEnviada:0 };
        folhasFechadas.forEach(p => {
          const st = _statusEnvioConf(p);
          if(!st) cnt.naoEnviada++;
          else cnt[st] = (cnt[st]||0) + 1;
        });
        const partes = [];
        if(cnt.naoEnviada) partes.push(`<span style="color:#9E9E9E"><i class="fa-solid fa-paper-plane"></i> ${cnt.naoEnviada} não enviada(s)</span>`);
        if(cnt.pendente) partes.push(`<span style="color:#0288D1"><i class="fa-solid fa-paper-plane"></i> ${cnt.pendente} aguardando</span>`);
        if(cnt.visualizada) partes.push(`<span style="color:#F57F17"><i class="fa-solid fa-eye"></i> ${cnt.visualizada} vista(s)</span>`);
        if(cnt.assinada) partes.push(`<span style="color:#2E7D32"><i class="fa-solid fa-circle-check"></i> ${cnt.assinada} assinada(s)</span>`);
        if(cnt.contestada) partes.push(`<span style="color:#C62828"><i class="fa-solid fa-circle-xmark"></i> ${cnt.contestada} contestada(s)</span>`);
        if(cnt.aceita_por_silencio) partes.push(`<span style="color:#558B2F"><i class="fa-solid fa-clock-rotate-left"></i> ${cnt.aceita_por_silencio} silêncio</span>`);
        envioStatus.innerHTML = partes.length ? partes.join(' · ') : '';
      } else {
        envioStatus.innerHTML = '';
      }
    }
  }

  // Atualiza o badge de status do período (vigente / histórico / futuro)
  // sempre que o painel re-renderiza. Garante consistência ao mudar mês/ano.
  _renderBadgeStatusPeriodo(mes, ano);

  // Auto-fechamento: se hoje >= data de fechamento e não foi fechado ainda.
  // Suspenso após reabertura manual (conf.autoFecharSuspenso) — senão "Reabrir
  // Todas" seria desfeito na hora, já que hoje já passou do dia 25.
  if(!periodoFechado && conf.dataFechamento && hoje>=conf.dataFechamento && !conf.autoFecharSuspenso){
    await _executarFechamentoPeriodo(mes,ano,key,conf,true);
  }
}

async function configurarDataFechamento(){
  const mes=parseInt(val('payroll-mes')||currentMes());
  const ano=parseInt(val('payroll-ano')||currentAno());
  const data=document.getElementById('fechamento-data-input')?.value;
  if(!data){ toast('Informe a data de fechamento.','error'); return; }
  const key=_periodoKey(mes,ano);
  const conf=State.confFolha?.[key]||{};
  const novaConf={ ...conf, dataFechamento:data, autoFecharSuspenso:false, updatedAt:new Date().toISOString() };
  try{
    await DB.saveDoc('configuracoes',`fechamento_${key}`,novaConf,true);
    State.confFolha=State.confFolha||{};
    State.confFolha[key]=novaConf;
    toast(`Data de fechamento de ${MESES[mes]}/${ano} definida para ${new Date(data+'T12:00:00').toLocaleDateString('pt-BR')}.`);
    _updatePainelFechamento(mes,ano);
  }catch(e){ toast('Erro ao salvar data de fechamento.','error'); }
}

async function fecharPeriodo(){
  const mes=parseInt(val('payroll-mes')||currentMes());
  const ano=parseInt(val('payroll-ano')||currentAno());
  const key=_periodoKey(mes,ano);
  const qtd=State.payrolls.filter(p=>p.mes==mes&&p.ano==ano&&p.status!=='fechada').length;
  if(qtd===0){ toast(`Nenhuma folha aberta em ${MESES[mes]}/${ano}.`,'warning'); return; }
  if(!confirm(`Fechar ${qtd} folha(s) de ${MESES[mes]}/${ano}?\n\nApós o fechamento as folhas ficam bloqueadas para edição. Você poderá reabrir individualmente se necessário.`)) return;
  await _executarFechamentoPeriodo(mes,ano,key,State.confFolha?.[key]||{},false);
}

// Reabre TODAS as folhas fechadas da competência de uma vez (simétrico ao
// "Fechar Todas"). Marca o período como reaberto. Útil antes da migração
// (que aborta se houver folha fechada) e quando precisa reeditar o mês inteiro.
async function reabrirPeriodo(){
  const mes=parseInt(val('payroll-mes')||currentMes());
  const ano=parseInt(val('payroll-ano')||currentAno());
  const key=_periodoKey(mes,ano);
  const fechadas=State.payrolls.filter(p=>p.mes==mes&&p.ano==ano&&p.status==='fechada');
  if(!fechadas.length){ toast(`Nenhuma folha fechada em ${MESES[mes]}/${ano}.`,'warning'); return; }
  if(!confirm(`Reabrir ${fechadas.length} folha(s) de ${MESES[mes]}/${ano}?\n\nTodas voltam a ficar EDITÁVEIS e o período é marcado como aberto.`)) return;
  const agora=new Date().toISOString();
  try{
    await Promise.all(fechadas.map(p=>{
      const _arqC=_arquivarContestacaoFolha(p);  // preserva contestação no histórico. #contestacao-historico
      return DB.merge('payrolls',p.id,{status:'aberta',reabertoEm:agora, ...(_arqC?{contestacoesHistorico:p.contestacoesHistorico}:{})}).then(()=>{
        const s=State.payrolls.find(r=>r.id===p.id); if(s){ s.status='aberta'; s.reabertoEm=agora; if(_arqC) s.contestacoesHistorico=p.contestacoesHistorico; }
      });
    }));
    const conf=State.confFolha?.[key]||{};
    const novaConf={...conf,fechado:false,reabertoEm:agora,autoFecharSuspenso:true,updatedAt:agora};
    await DB.saveDoc('configuracoes',`fechamento_${key}`,novaConf,true);
    State.confFolha=State.confFolha||{};
    State.confFolha[key]=novaConf;
    toast(`${fechadas.length} folha(s) de ${MESES[mes]}/${ano} reabertas.`);
    try{ Auth.log('PAYROLL_PERIODO_REABERTO',null,`${MESES[mes]}/${ano} — ${fechadas.length} folhas`); }catch(_){}
    _updatePainelFechamento(mes,ano);
    _updateFolhaStatusBadge();
  }catch(e){ toast('Erro ao reabrir período.','error'); console.error(e); }
}

// ============================================
// FOLHA → CONFERÊNCIA PELO COLABORADOR (Fase 1)
// ============================================
// Após fechar a folha do mês, o master ENVIA a folha pro app do colab.
// O colab vê no inbox (banner), abre a planilha, e:
//   - Concorda: digita PIN → gera HASH SHA-256 do conteúdo+PIN+IP+UA+device
//     → folha vira 'assinada'
//   - Contesta: escreve motivo (mín. 20 chars) → master é notificado
//   - Não age em 48h → vira 'aceita_por_silencio' (job no carregamento)
// Hash = SHA-256(JSON.stringify({conteudo, pinHash, ip, ua, device, ts}))
// Validade jurídica: assinatura eletrônica simples (MP 2.200-2/2001).
// ============================================

// Prazo padrão pra conferência (decisão usuário 2026-05-30): 48 horas.
const _CONF_PRAZO_HORAS = 48;

function _statusEnvioConf(p){
  // Retorna o status atual do envio:
  //   null       → ainda não enviada
  //   'pendente' → enviada, colab não abriu
  //   'visualizada' → colab abriu, ainda não decidiu
  //   'assinada' | 'contestada' | 'aceita_por_silencio'
  return p?.envioConferencia?.status || null;
}

function _statusEnvioLabel(status){
  const map = {
    null: { txt:'Não enviada', cor:'#9E9E9E', bg:'#F5F5F5', icon:'fa-paper-plane' },
    'pendente': { txt:'Enviada — aguardando', cor:'#0288D1', bg:'#E1F5FE', icon:'fa-paper-plane' },
    'visualizada': { txt:'Visualizada', cor:'#F57F17', bg:'#FFF9C4', icon:'fa-eye' },
    'assinada': { txt:'Assinada', cor:'#2E7D32', bg:'#E8F5E9', icon:'fa-circle-check' },
    'contestada': { txt:'Contestada', cor:'#C62828', bg:'#FFEBEE', icon:'fa-circle-xmark' },
    'aceita_por_silencio': { txt:'Aceita por silêncio (48h)', cor:'#558B2F', bg:'#F1F8E9', icon:'fa-clock-rotate-left' },
  };
  return map[status] || map[null];
}

// Envia UMA folha (já fechada) para o app do colaborador conferir.
// Prazo: 48h a partir do envio. Após isso job marca aceita_por_silencio.
async function enviarFolhaParaConferencia(payrollId){
  if(Auth.currentUser?.role !== 'master' && !getUserModules(Auth.currentUser).folhaEnviar){
    toast('Sem permissão pra enviar folhas pra conferência.','error'); return;
  }
  const p = State.payrolls.find(x => x.id === payrollId);
  if(!p){ toast('Folha não encontrada.','error'); return; }
  if(p.status !== 'fechada'){ toast('Folha precisa estar FECHADA pra enviar pra conferência.','warning'); return; }
  if(!p.revisada){ toast('Marque a folha como REVISADA (tela Pagamentos) antes de enviar pra conferência.','warning'); return; }
  if(_statusEnvioConf(p) && _statusEnvioConf(p) !== 'pendente'){
    if(!confirm(`Esta folha já foi ${_statusEnvioLabel(_statusEnvioConf(p)).txt.toLowerCase()}. Reenviar mesmo assim?`)) return;
  }
  const agora = new Date();
  const prazo = new Date(agora.getTime() + _CONF_PRAZO_HORAS*60*60*1000);
  const u = Auth.currentUser || {};
  const envio = {
    enviadoEm: agora.toISOString(),
    enviadoPor: u.username || u.id || '',
    enviadoPorNome: u.username || '',
    status: 'pendente',
    prazoExpiraEm: prazo.toISOString(),
    visualizadoEm: null,
    assinadoEm: null,
    contestadoEm: null,
  };
  // Se havia contestação anterior, ARQUIVA antes de sobrescrever o envio. #contestacao-historico
  const _arqC = _arquivarContestacaoFolha(p);
  try{
    await DB.merge('payrolls', payrollId, { envioConferencia: envio, ...(_arqC?{contestacoesHistorico:p.contestacoesHistorico}:{}) });
    p.envioConferencia = envio;
    Auth.log('FOLHA_ENVIADA_CONFERENCIA', null, `${MESES[p.mes]}/${p.ano} — ${p.employeeId} (prazo ${prazo.toLocaleString('pt-BR')})`);
    toast(`Folha enviada — colab tem ${_CONF_PRAZO_HORAS}h pra conferir.`,'success');
    _updatePainelFechamento(p.mes, p.ano);
  }catch(e){ console.error(e); toast('Erro ao enviar.','error'); }
}

// Envia TODAS as folhas fechadas da competência atual pra conferência.
// Pula as que já foram enviadas (a menos que confirme reenviar).
async function enviarTodasFolhasCompetencia(){
  if(Auth.currentUser?.role !== 'master' && !getUserModules(Auth.currentUser).folhaEnviar){
    toast('Sem permissão.','error'); return;
  }
  const mes = parseInt(val('payroll-mes')||currentMes());
  const ano = parseInt(val('payroll-ano')||currentAno());
  const fechadas = State.payrolls.filter(p => p.mes==mes && p.ano==ano && p.status==='fechada');
  if(!fechadas.length){ toast(`Nenhuma folha fechada em ${MESES[mes]}/${ano}.`,'warning'); return; }
  const naoEnviadas = fechadas.filter(p => !_statusEnvioConf(p));
  const jaEnviadas  = fechadas.length - naoEnviadas.length;
  let alvos = naoEnviadas;
  if(jaEnviadas > 0){
    if(confirm(`${jaEnviadas} folha(s) JÁ enviadas. Reenviar TODAS as ${fechadas.length} folhas? Senão, mando só as ${naoEnviadas.length} ainda não enviadas.`)){
      alvos = fechadas;
    }
  }
  if(!alvos.length){ toast('Tudo já foi enviado. Nada a fazer.','info'); return; }
  // Trava de revisão: só envia folhas REVISADAS; as demais são puladas. #revisada-gate
  const semRev = alvos.filter(p=>!p.revisada);
  alvos = alvos.filter(p=>p.revisada);
  if(!alvos.length){ toast('Nenhuma folha REVISADA pra enviar. Marque como revisada na tela Pagamentos.','warning'); return; }
  const _avisoRev = semRev.length ? `\n\n⚠ ${semRev.length} folha(s) NÃO revisada(s) serão puladas.` : '';
  if(!confirm(`Enviar ${alvos.length} folha(s) de ${MESES[mes]}/${ano} pra conferência dos colaboradores?\n\nPrazo: ${_CONF_PRAZO_HORAS} horas. Após isso, sem ação, vira "aceita por silêncio".${_avisoRev}`)) return;
  const agora = new Date();
  const prazo = new Date(agora.getTime() + _CONF_PRAZO_HORAS*60*60*1000);
  const u = Auth.currentUser || {};
  let ok = 0, erros = 0;
  for(const p of alvos){
    const envio = {
      enviadoEm: agora.toISOString(),
      enviadoPor: u.username || u.id || '',
      enviadoPorNome: u.username || '',
      status: 'pendente',
      prazoExpiraEm: prazo.toISOString(),
      visualizadoEm: null,
      assinadoEm: null,
      contestadoEm: null,
    };
    try{
      await DB.merge('payrolls', p.id, { envioConferencia: envio });
      p.envioConferencia = envio;
      ok++;
    }catch(e){ console.error('envio folha', p.id, e); erros++; }
  }
  Auth.log('FOLHA_ENVIADA_CONFERENCIA_LOTE', null, `${MESES[mes]}/${ano} — ${ok} folha(s)`);
  toast(`${ok} folha(s) enviada(s) pra conferência${erros?` · ${erros} com erro`:''}${semRev.length?` · ${semRev.length} pulada(s) (não revisada)`:''}. Colab tem ${_CONF_PRAZO_HORAS}h pra responder.`,'success');
  _updatePainelFechamento(mes, ano);
  if(document.getElementById('modal-folhas-fechadas')) renderFolhasFechadasLista();
}

// ============================================================================
// TELA "FOLHAS FECHADAS" — lista enxuta das folhas fechadas da competência atual.
// Cada linha: checkbox (esquerda) · matrícula · nome (+ status do envio) ·
// ícone revisar (abre a folha) · ícone reabrir. Botões de envio em lote
// (selecionadas / todas) pra conferência. Aberta pelo botão no painel de
// fechamento. #folhas-fechadas-lista
// ============================================================================
function _folhasFechadasLista(mes, ano){
  const empById = id => State.employees.find(e=>e.id===id);
  let lista = (State.payrolls||[]).filter(p=>p.mes==mes && p.ano==ano && p.status==='fechada');
  // Respeita o escopo de postos do supervisor (master vê tudo).
  lista = lista.filter(p=>{ const e=empById(p.employeeId); return e ? _empNoEscopo(e) : true; });
  lista.sort((a,b)=>{
    const ea=empById(a.employeeId), eb=empById(b.employeeId);
    return (ea?.nome||'').localeCompare(eb?.nome||'');
  });
  return lista;
}

function openFolhasFechadas(){
  const mes=parseInt(val('payroll-mes')||currentMes());
  const ano=parseInt(val('payroll-ano')||currentAno());
  document.getElementById('modal-folhas-fechadas')?.remove();
  const html = `
    <div id="modal-folhas-fechadas" class="modal" style="display:flex;align-items:center;justify-content:center;position:fixed;inset:0;background:rgba(0,0,0,.5);z-index:9999">
      <div class="modal-content" style="background:#fff;max-width:700px;width:94%;max-height:88vh;border-radius:8px;overflow:hidden;box-shadow:0 8px 32px rgba(0,0,0,.3);display:flex;flex-direction:column">
        <div style="background:#5C6BC0;color:#fff;padding:12px 16px;display:flex;justify-content:space-between;align-items:center">
          <h3 style="margin:0;font-size:16px"><i class="fa-solid fa-lock"></i> Folhas Fechadas — ${MESES[mes]}/${ano}</h3>
          <button onclick="document.getElementById('modal-folhas-fechadas').remove()" style="background:transparent;border:none;color:#fff;font-size:20px;cursor:pointer;line-height:1">&times;</button>
        </div>
        <div style="padding:10px 16px;border-bottom:1px solid #eee;display:flex;align-items:center;gap:10px;flex-wrap:wrap">
          <label style="display:flex;align-items:center;gap:6px;font-size:13px;cursor:pointer"><input type="checkbox" id="ff-check-all" onchange="_folhasFechadasToggleAll(this)"> Marcar todos</label>
          <span style="flex:1"></span>
          <button class="btn btn-sm" id="ff-btn-enviar-sel" onclick="enviarFolhasSelecionadasConferencia()" style="background:#00897B;color:#fff;border:none;font-size:12px;white-space:nowrap"><i class="fa-solid fa-paper-plane"></i> Enviar selecionadas (0)</button>
          <button class="btn btn-sm" onclick="enviarTodasFolhasCompetencia()" style="background:#00695C;color:#fff;border:none;font-size:12px;white-space:nowrap" title="Envia todas as folhas fechadas dessa competência pra conferência"><i class="fa-solid fa-paper-plane"></i> Enviar todas</button>
        </div>
        <div style="overflow:auto;flex:1">
          <table style="width:100%;border-collapse:collapse;font-size:13px">
            <thead><tr style="position:sticky;top:0;background:#f5f6fa;z-index:1">
              <th style="width:40px;padding:8px"></th>
              <th style="width:70px;text-align:left;padding:8px 6px;color:#666;font-size:11px;text-transform:uppercase">Matr.</th>
              <th style="text-align:left;padding:8px 6px;color:#666;font-size:11px;text-transform:uppercase">Colaborador</th>
              <th style="width:100px;text-align:center;padding:8px 6px;color:#666;font-size:11px;text-transform:uppercase">Ações</th>
            </tr></thead>
            <tbody id="ff-tbody"></tbody>
          </table>
        </div>
      </div>
    </div>`;
  document.body.insertAdjacentHTML('beforeend', html);
  renderFolhasFechadasLista();
}

function renderFolhasFechadasLista(){
  const tbody=document.getElementById('ff-tbody');
  if(!tbody) return;
  const mes=parseInt(val('payroll-mes')||currentMes());
  const ano=parseInt(val('payroll-ano')||currentAno());
  const lista=_folhasFechadasLista(mes,ano);
  if(!lista.length){
    tbody.innerHTML=`<tr><td colspan="4" style="padding:26px;text-align:center;color:#888">Nenhuma folha fechada em ${MESES[mes]}/${ano}.</td></tr>`;
    _folhasFechadasUpdateSel();
    return;
  }
  tbody.innerHTML=lista.map((p,i)=>{
    const emp=State.employees.find(e=>e.id===p.employeeId);
    const nome=emp?.nome||p.employeeNome||'—';
    const reg=emp?String(emp.registro||'').padStart(4,'0'):'—';
    const st=_statusEnvioLabel(_statusEnvioConf(p));
    const chip=`<span style="display:inline-block;background:${st.bg};color:${st.cor};border-radius:10px;padding:0 7px;font-size:10px;margin-left:6px;white-space:nowrap"><i class="fa-solid ${st.icon}"></i> ${st.txt}</span>`;
    const bg=i%2?'#fafbfe':'#fff';
    return `<tr style="background:${bg};border-bottom:1px solid #eef0f5">
      <td style="text-align:center;padding:8px"><input type="checkbox" class="ff-row-check" data-id="${p.id}" onchange="_folhasFechadasUpdateSel()"></td>
      <td style="padding:8px 6px;font-family:monospace;color:#555">${reg}</td>
      <td style="padding:8px 6px"><strong>${esc(nome)}</strong>${chip}</td>
      <td style="text-align:center;padding:8px 6px;white-space:nowrap">
        <button class="btn-icon" title="Revisar folha (abre a folha de ponto)" onclick="_folhasFechadasRevisar('${p.employeeId}')"><i class="fa-solid fa-magnifying-glass" style="color:#1565C0"></i></button>
        <button class="btn-icon" title="Reabrir folha (volta a editável)" onclick="reabrirFolhaPorId('${p.id}')"><i class="fa-solid fa-lock-open" style="color:#EF6C00"></i></button>
      </td>
    </tr>`;
  }).join('');
  _folhasFechadasUpdateSel();
}

function _folhasFechadasToggleAll(master){
  document.querySelectorAll('#ff-tbody .ff-row-check').forEach(cb=>{ cb.checked=!!master.checked; });
  _folhasFechadasUpdateSel();
}

function _folhasFechadasUpdateSel(){
  const n=document.querySelectorAll('#ff-tbody .ff-row-check:checked').length;
  const btn=document.getElementById('ff-btn-enviar-sel');
  if(btn){ btn.innerHTML=`<i class="fa-solid fa-paper-plane"></i> Enviar selecionadas (${n})`; btn.disabled=n===0; btn.style.opacity=n===0?'0.55':'1'; }
}

function _folhasFechadasRevisar(empId){
  document.getElementById('modal-folhas-fechadas')?.remove();
  _abrirFolhaColaborador(empId);
}

// Reabre UMA folha pelo id (usado pela lista de Folhas Fechadas). Espelha reabrirFolha().
async function reabrirFolhaPorId(payrollId){
  if(Auth.currentUser?.role!=='master' && !getUserModules(Auth.currentUser).payroll){ toast('Sem permissão.','error'); return; }
  const p=State.payrolls.find(r=>r.id===payrollId);
  if(!p){ toast('Folha não encontrada.','error'); return; }
  const emp=State.employees.find(e=>e.id===p.employeeId);
  const nome=emp?.nome||p.employeeNome||'colaborador';
  if(!confirm(`Reabrir a folha de ${nome} — ${MESES[p.mes]}/${p.ano}?\n\nA folha voltará a ser editável.`)) return;
  try{
    const _arqC=_arquivarContestacaoFolha(p);
    await DB.merge('payrolls',p.id,{status:'aberta',reabertoEm:new Date().toISOString(), ...(_arqC?{contestacoesHistorico:p.contestacoesHistorico}:{})});
    const s=State.payrolls.find(r=>r.id===p.id); if(s){ s.status='aberta'; if(_arqC) s.contestacoesHistorico=p.contestacoesHistorico; }
    Auth.log('PAYROLL_REABERTO',null,`${nome} — ${MESES[p.mes]}/${p.ano}`);
    toast(`Folha de ${nome} reaberta para edição.`);
    _updatePainelFechamento(p.mes,p.ano);
    if(typeof _updateFolhaStatusBadge==='function') _updateFolhaStatusBadge();
    renderFolhasFechadasLista();
    if(State.currentSection==='pagamentos') renderPagamentos();
  }catch(e){ console.error(e); toast('Erro ao reabrir folha.','error'); }
}

// Fecha UMA folha pelo id (usado pela lista de Pagamentos). Apura a Boa
// Permanência por-dados via _apurarBonusFolha (mesma lógica do fechamento em
// lote) — não depende da folha estar carregada no formulário. #pagamentos-revisao
async function fecharFolhaPorId(payrollId){
  if(Auth.currentUser?.role!=='master' && !getUserModules(Auth.currentUser).payroll){ toast('Sem permissão.','error'); return; }
  const p=State.payrolls.find(r=>r.id===payrollId);
  if(!p){ toast('Folha não encontrada.','error'); return; }
  if(p.status==='fechada'){ toast('Esta folha já está fechada.','warning'); return; }
  const emp=State.employees.find(e=>e.id===p.employeeId);
  const nome=emp?.nome||p.employeeNome||'colaborador';
  if(!confirm(`Fechar a folha de ${nome} — ${MESES[p.mes]}/${p.ano}?\n\nA folha ficará bloqueada para edição. Você poderá reabrir se necessário.`)) return;
  try{
    const agora=new Date().toISOString();
    const upd={ status:'fechada', fechadoEm:agora };
    const recalc=(emp && !emp.isentoPonto) ? _apurarBonusFolha(p, emp, State.cct) : null;
    if(recalc) Object.assign(upd, recalc);
    await DB.merge('payrolls',p.id,upd);
    const s=State.payrolls.find(r=>r.id===p.id); if(s) Object.assign(s, upd);
    Auth.log('PAYROLL_FECHADO_INDIVIDUAL',null,`${nome} — ${MESES[p.mes]}/${p.ano}`);
    toast(`Folha de ${nome} fechada.`);
    _updatePainelFechamento(p.mes,p.ano);
    if(typeof _updateFolhaStatusBadge==='function') _updateFolhaStatusBadge();
    renderFolhasFechadasLista();
    if(State.currentSection==='pagamentos') renderPagamentos();
  }catch(e){ console.error(e); toast('Erro ao fechar folha.','error'); }
}

// REGRA DURA (dono 2026-07-03): informada a DATA DE DEMISSÃO, fecha AUTOMÁTICO (sem confirm) as
// folhas do colaborador — a da COMPETÊNCIA da demissão + todas as ABERTAS de meses anteriores —
// apurando e gravando as faltas (`faltasInjustificadas` via _apuracaoPontoTotais; bônus via
// _apurarBonusFolha). Ele já vira 'inativo' (some do Monitor); folha fechada some do card
// "Faltas Registradas". Reversível: reabrir a folha / apagar a demissão volta ao normal.
// #demissao-fecha-folha
async function _fecharFolhasDemissao(emp){
  if(!emp || !emp.dataDemissao) return;
  const dem=new Date((emp.dataDemissao+'').slice(0,10)+'T00:00:00');
  if(isNaN(dem.getTime())) return;
  const cDem=_competenciaDe(dem);
  const keyDem=(+cDem.ano)*12 + (+cDem.mes);
  const _key=p=>(+p.ano)*12 + (+p.mes);
  const alvo=(State.payrolls||[]).filter(p=> p && p.employeeId===emp.id && p.status!=='fechada' && _key(p)<=keyDem);
  // Garante a folha da competência da demissão (cria determinística se não existir NENHUMA — aberta ou fechada).
  const temDem=(State.payrolls||[]).some(p=> p && p.employeeId===emp.id && p.mes==cDem.mes && p.ano==cDem.ano);
  if(!temDem){
    alvo.push({ id:_payrollId(emp.id,cDem.mes,cDem.ano), employeeId:emp.id, mes:cDem.mes, ano:cDem.ano,
      pontoManualDias:[], status:'aberta', createdAt:new Date().toISOString() });
  }
  if(!alvo.length) return;
  const agora=new Date().toISOString();
  let n=0;
  for(const p of alvo){
    try{
      const faltas=(!emp.isentoPonto)?(_apuracaoPontoTotais(emp,p).faltaQtd||0):0;
      let bonus=null; try{ if(!emp.isentoPonto) bonus=_apurarBonusFolha(p,emp,State.cct); }catch(_){}
      const record={...p, faltasInjustificadas:faltas, status:'fechada', fechadoEm:agora, updatedAt:agora };
      if(bonus) Object.assign(record, bonus);
      await DB.save('payrolls', _sanitizeForFirestore(record));
      const ix=(State.payrolls||[]).findIndex(r=>r.id===record.id);
      if(ix>=0) State.payrolls[ix]=record; else (State.payrolls=State.payrolls||[]).push(record);
      n++;
    }catch(e){ console.error('fechar folha demissao', emp&&emp.nome, e); }
  }
  try{ Auth.log('DEMISSAO_FECHA_FOLHA', null, `${emp.nome} — demissão ${emp.dataDemissao} — ${n} folha(s) fechada(s)`); }catch(_){}
  if(n){
    toast(`Demissão de ${emp.nome}: ${n} folha(s) fechada(s) com as faltas apuradas.`,'success');
    try{ if(State.currentSection==='dashboard') renderDashboard(); }catch(_){}
    try{ if(State.currentSection==='monitorfaltas') renderMonitorFaltas(); }catch(_){}
    try{ renderFolhasFechadasLista(); }catch(_){}
  }
}

// Envia SÓ as folhas marcadas na lista de Folhas Fechadas pra conferência.
async function enviarFolhasSelecionadasConferencia(){
  if(Auth.currentUser?.role!=='master' && !getUserModules(Auth.currentUser).folhaEnviar){ toast('Sem permissão pra enviar folhas pra conferência.','error'); return; }
  const ids=[...document.querySelectorAll('#ff-tbody .ff-row-check:checked')].map(cb=>cb.dataset.id);
  if(!ids.length){ toast('Selecione pelo menos uma folha.','warning'); return; }
  let alvos=ids.map(id=>State.payrolls.find(p=>p.id===id)).filter(Boolean).filter(p=>p.status==='fechada');
  if(!alvos.length){ toast('Nenhuma folha fechada válida na seleção.','warning'); return; }
  // Trava de revisão: só envia folhas REVISADAS; as demais são puladas. #revisada-gate
  const semRev=alvos.filter(p=>!p.revisada);
  alvos=alvos.filter(p=>p.revisada);
  if(!alvos.length){ toast('Nenhuma folha REVISADA na seleção. Marque como revisada na tela Pagamentos.','warning'); return; }
  const jaEnviadas=alvos.filter(p=>_statusEnvioConf(p)).length;
  let msg=`Enviar ${alvos.length} folha(s) selecionada(s) pra conferência dos colaboradores?\n\nPrazo: ${_CONF_PRAZO_HORAS}h. Após isso, sem ação, vira "aceita por silêncio".`;
  if(semRev.length) msg+=`\n\n⚠ ${semRev.length} folha(s) NÃO revisada(s) serão puladas.`;
  if(jaEnviadas) msg+=`\n\n${jaEnviadas} já foram enviadas antes — serão REENVIADAS.`;
  if(!confirm(msg)) return;
  const agora=new Date();
  const prazo=new Date(agora.getTime()+_CONF_PRAZO_HORAS*60*60*1000);
  const u=Auth.currentUser||{};
  let ok=0,erros=0;
  for(const p of alvos){
    const envio={ enviadoEm:agora.toISOString(), enviadoPor:u.username||u.id||'', enviadoPorNome:u.username||'', status:'pendente', prazoExpiraEm:prazo.toISOString(), visualizadoEm:null, assinadoEm:null, contestadoEm:null };
    const _arqC=_arquivarContestacaoFolha(p);
    try{
      await DB.merge('payrolls',p.id,{ envioConferencia:envio, ...(_arqC?{contestacoesHistorico:p.contestacoesHistorico}:{}) });
      p.envioConferencia=envio; ok++;
    }catch(e){ console.error('envio folha sel',p.id,e); erros++; }
  }
  Auth.log('FOLHA_ENVIADA_CONFERENCIA_SELECAO',null,`${MESES[alvos[0].mes]}/${alvos[0].ano} — ${ok} folha(s)`);
  toast(`${ok} folha(s) enviada(s) pra conferência${erros?` · ${erros} com erro`:''}${semRev.length?` · ${semRev.length} pulada(s) (não revisada)`:''}.`,'success');
  _updatePainelFechamento(alvos[0].mes,alvos[0].ano);
  renderFolhasFechadasLista();
}

// Job "Aceito por silêncio": roda no carregamento do master. Marca como
// 'aceita_por_silencio' as folhas com status='pendente' ou 'visualizada' cujo
// prazoExpiraEm já passou.
async function _aceitarPorSilencioJob(){
  const agora = new Date();
  const candidatas = (State.payrolls||[]).filter(p => {
    const env = p.envioConferencia;
    if(!env) return false;
    if(env.status !== 'pendente' && env.status !== 'visualizada') return false;
    if(!env.prazoExpiraEm) return false;
    return new Date(env.prazoExpiraEm) <= agora;
  });
  if(!candidatas.length) return;
  for(const p of candidatas){
    const novo = { ...p.envioConferencia, status: 'aceita_por_silencio', silencioEm: agora.toISOString() };
    try{
      await DB.merge('payrolls', p.id, { envioConferencia: novo });
      p.envioConferencia = novo;
    }catch(e){ console.error('silencio', p.id, e); }
  }
  if(candidatas.length){
    Auth.log('FOLHA_SILENCIO', null, `${candidatas.length} folha(s) aceitas por silêncio`);
  }
}

// Renderiza a lista de FOLHAS ASSINADAS do colaborador no modal cadastro.
// Chamada quando o usuário clica na aba "Folhas Assinadas". Mostra cada folha
// com badge de status (assinada/silêncio/contestada), hash truncado, datas,
// e botão "Ver" que abre o HTML render numa nova janela.
// Arquiva a contestação ATUAL da folha num histórico permanente (não some quando
// a folha é reaberta/reenviada — o envioConferencia é sobrescrito). Retorna true
// se arquivou algo novo. #contestacao-historico
function _arquivarContestacaoFolha(p){
  if(!p) return false;
  const st = p.envioConferencia?.status;
  const motivo = (p.contestacao && p.contestacao.motivo) || '';
  const contestadoEm = (p.envioConferencia && p.envioConferencia.contestadoEm) || (p.contestacao && p.contestacao.contestadoEm) || '';
  if(st!=='contestada' && !motivo) return false;
  const hist = Array.isArray(p.contestacoesHistorico) ? p.contestacoesHistorico.slice() : [];
  if(contestadoEm && hist.some(h=>h.contestadoEm===contestadoEm)) return false; // já arquivada
  hist.push({
    motivo: motivo || '(sem motivo informado)',
    contestadoEm: contestadoEm || new Date().toISOString(),
    enviadoEm: (p.envioConferencia && p.envioConferencia.enviadoEm) || '',
    arquivadoEm: new Date().toISOString(),
  });
  p.contestacoesHistorico = hist;
  return true;
}

function renderFolhasAssinadasColab(){
  const empId = State.editingEmployeeId || val('emp-id');
  const container = document.getElementById('folhas-assinadas-list');
  if(!container) return;
  if(!empId){
    container.innerHTML = '<div style="font-size:12px;color:#94a3b8;padding:8px 2px">Salve o colaborador primeiro.</div>';
    return;
  }
  const folhas = (State.payrolls||[]).filter(p => {
    if(p.employeeId !== empId) return false;
    const st = p?.envioConferencia?.status;
    // Inclui também contestadas no histórico (com badge diferente)
    return st === 'assinada' || st === 'aceita_por_silencio' || st === 'contestada';
  });
  folhas.sort((a,b) => {
    if(a.ano !== b.ano) return b.ano - a.ano;
    return b.mes - a.mes;
  });
  const contestHist = (State.payrolls||[]).filter(p=>p.employeeId===empId)
    .flatMap(p=>(p.contestacoesHistorico||[]).map(c=>({...c, comp:`${MESES[p.mes]||p.mes}/${p.ano}`})))
    .sort((a,b)=>(b.contestadoEm||'').localeCompare(a.contestadoEm||''));
  if(!folhas.length && !contestHist.length){
    container.innerHTML = `<div class="empty-state small"><i class="fa-solid fa-file-signature" style="font-size:32px;color:#cbd5e0"></i><p style="font-size:13px;margin-top:8px">Nenhuma folha foi enviada/assinada ainda.</p></div>`;
    return;
  }
  let html = folhas.map(p => {
    const st = p.envioConferencia?.status;
    const stMap = {
      'assinada':            { txt:'Assinada', cor:'#2E7D32', bg:'#E8F5E9', icon:'fa-circle-check' },
      'aceita_por_silencio': { txt:'Aceita por silêncio', cor:'#558B2F', bg:'#F1F8E9', icon:'fa-clock-rotate-left' },
      'contestada':          { txt:'Contestada', cor:'#C62828', bg:'#FFEBEE', icon:'fa-circle-xmark' },
    };
    const cfg = stMap[st] || stMap['assinada'];
    const hash = p.assinatura?.hash || '';
    const hashTrunc = hash ? `${hash.substring(0,16)}…` : '—';
    const enviado = p.envioConferencia?.enviadoEm ? new Date(p.envioConferencia.enviadoEm).toLocaleString('pt-BR') : '—';
    const assinado = p.envioConferencia?.assinadoEm ? new Date(p.envioConferencia.assinadoEm).toLocaleString('pt-BR')
                   : p.envioConferencia?.silencioEm ? new Date(p.envioConferencia.silencioEm).toLocaleString('pt-BR')
                   : p.envioConferencia?.contestadoEm ? new Date(p.envioConferencia.contestadoEm).toLocaleString('pt-BR')
                   : '—';
    const motivoContest = (st === 'contestada' && p.contestacao?.motivo)
      ? `<div style="background:#FFEBEE;color:#C62828;padding:8px 10px;border-radius:5px;font-size:11px;margin-top:6px"><strong>Motivo:</strong> ${esc(p.contestacao.motivo)}</div>`
      : '';
    const btnVer = (st === 'assinada' && p.assinatura?.htmlRender)
      ? `<button class="btn btn-sm btn-outline" onclick="verFolhaAssinada('${p.id}')" style="font-size:11px"><i class="fa-solid fa-eye"></i> Ver folha + hash</button>`
      : (st === 'aceita_por_silencio')
        ? `<button class="btn btn-sm btn-outline" onclick="alert('Aceita por silêncio — sem assinatura digital, sem hash. Folha registrada como conferida automaticamente após 48h sem ação.')" style="font-size:11px;opacity:0.7"><i class="fa-solid fa-clock"></i> Sem hash (silêncio)</button>`
        : '';
    return `<div style="border:1px solid #e0e0e0;border-radius:8px;padding:12px 14px;margin-bottom:10px;background:#fafafa">
      <div style="display:flex;justify-content:space-between;align-items:center;gap:10px;flex-wrap:wrap">
        <div>
          <div style="font-weight:700;color:#1a1a2e;font-size:14px">${MESES[p.mes]} / ${p.ano}</div>
          <div style="font-size:11px;color:#888;margin-top:2px">Enviada: ${enviado} · ${cfg.txt}: ${assinado}</div>
        </div>
        <span style="background:${cfg.bg};color:${cfg.cor};padding:4px 10px;border-radius:8px;font-size:11px;font-weight:700"><i class="fa-solid ${cfg.icon}"></i> ${cfg.txt.toUpperCase()}</span>${_carimboBadgeStatus(p.carimboFolStatus)} ${_carimboAcoesHtml('folha', p.id, true)}
      </div>
      <div style="margin-top:8px;font-family:monospace;font-size:11px;color:#666"><strong>Hash:</strong> ${hashTrunc}</div>
      ${motivoContest}
      <div style="margin-top:8px">${btnVer}</div>
    </div>`;
  }).join('');
  if(contestHist.length){
    const _dt = iso => { const d=iso?new Date(iso):null; return (d&&!isNaN(d.getTime()))?d.toLocaleString('pt-BR'):''; };
    html += `<div style="margin-top:16px;padding-top:14px;border-top:1px solid #e0e0e0">
      <strong style="font-size:13px;color:#C62828"><i class="fa-solid fa-clock-rotate-left"></i> Histórico de contestações (${contestHist.length})</strong>
      <div style="font-size:11px;color:#888;margin:2px 0 8px">Contestações registradas pelo colaborador — preservadas mesmo após a folha ser reaberta/ajustada.</div>
      ${contestHist.map(c=>`<div style="background:#FFF5F5;border:1px solid #FFCDD2;border-left:3px solid #C62828;border-radius:6px;padding:8px 11px;margin-bottom:6px;font-size:12px">
        <div style="display:flex;justify-content:space-between;gap:10px;flex-wrap:wrap"><strong>${c.comp}</strong><span style="color:#888;font-size:11px">${_dt(c.contestadoEm)}</span></div>
        <div style="color:#C62828;margin-top:3px"><strong>Motivo:</strong> ${esc(c.motivo||'(sem motivo)')}</div>
      </div>`).join('')}
    </div>`;
  }
  container.innerHTML = html;
}

// Abre a folha assinada numa nova janela renderizada a partir do htmlRender
// salvo no momento da assinatura. Inclui hash + botão imprimir/PDF.
function verFolhaAssinada(payrollId){
  const p = (State.payrolls||[]).find(x => x.id === payrollId);
  if(!p || !p.assinatura?.htmlRender){
    toast('Folha sem HTML render disponível.','warning'); return;
  }
  const win = window.open('','_blank','width=900,height=900,scrollbars=yes');
  if(!win){ toast('Pop-ups bloqueados — habilite pra ver a folha.','error'); return; }
  win.document.write(p.assinatura.htmlRender);
  win.document.close();
}

// ============================================================================
// HOLERITE → CONFERÊNCIA PELO COLABORADOR (Fase 2) — espelha o fluxo da FOLHA,
// mas para o RECIBO/HOLERITE. Usa campos PRÓPRIOS no payroll
// (holeriteConferencia / holeriteAssinatura / holeriteContestacao) pra não
// colidir com a folha. O gestor grava o HTML do recibo no envio; o colaborador
// só EXIBE e ASSINA (não recalcula nada). Prazo 48h → aceito por silêncio.
// ============================================================================
function _statusEnvioHolerite(p){
  return p?.holeriteConferencia?.status || null;
}

// Envia UM holerite (de folha fechada) pro app do colaborador conferir/assinar.
async function enviarHoleriteParaConferencia(payrollId){
  if(Auth.currentUser?.role !== 'master' && !getUserModules(Auth.currentUser).folhaEnviar){
    toast('Sem permissão pra enviar holerites pra conferência.','error'); return;
  }
  const p = State.payrolls.find(x => x.id === payrollId);
  if(!p){ toast('Folha não encontrada.','error'); return; }
  if(p.status !== 'fechada'){ toast('Folha precisa estar FECHADA pra enviar o holerite.','warning'); return; }
  if(!p.revisada){ toast('Marque a folha como REVISADA (tela Pagamentos) antes de enviar o holerite pra conferência.','warning'); return; }
  const emp = State.employees.find(e => e.id === p.employeeId);
  if(!emp){ toast('Colaborador não encontrado.','error'); return; }
  if(_statusEnvioHolerite(p) && _statusEnvioHolerite(p) !== 'pendente'){
    if(!confirm(`Este holerite já foi ${_statusEnvioLabel(_statusEnvioHolerite(p)).txt.toLowerCase()}. Reenviar mesmo assim?`)) return;
  }
  const agora = new Date();
  const prazo = new Date(agora.getTime() + _CONF_PRAZO_HORAS*60*60*1000);
  const u = Auth.currentUser || {};
  const r = _reciboOficialLinhas(emp, p);
  const reciboHtml = _reciboOficialUmHTML(emp, p, p.mes, p.ano, {}); // snapshot do recibo (o colab só exibe isto)
  const envio = {
    enviadoEm: agora.toISOString(), enviadoPor: u.username||u.id||'', enviadoPorNome: u.username||'',
    status: 'pendente', prazoExpiraEm: prazo.toISOString(),
    visualizadoEm: null, assinadoEm: null, contestadoEm: null,
    reciboHtml, liquido: r.liquido,
  };
  try{
    await DB.merge('payrolls', payrollId, { holeriteConferencia: envio });
    p.holeriteConferencia = envio;
    Auth.log('HOLERITE_ENVIADO_CONFERENCIA', null, `${MESES[p.mes]}/${p.ano} — ${p.employeeId} (prazo ${prazo.toLocaleString('pt-BR')})`);
    toast(`Holerite enviado — colab tem ${_CONF_PRAZO_HORAS}h pra conferir/assinar.`,'success');
    if(typeof renderPagamentos==='function' && State.currentSection==='pagamentos') renderPagamentos();
  }catch(e){ console.error(e); toast('Erro ao enviar holerite.','error'); }
}

// Envia TODOS os holerites das folhas fechadas da competência exibida (Pagamentos).
async function enviarTodosHoleritesCompetencia(){
  if(Auth.currentUser?.role !== 'master' && !getUserModules(Auth.currentUser).folhaEnviar){
    toast('Sem permissão.','error'); return;
  }
  const mes = parseInt(val('pag-mes')||currentMes());
  const ano = parseInt(val('pag-ano')||currentAno());
  const fechadas = State.payrolls.filter(p => p.mes==mes && p.ano==ano && p.status==='fechada');
  if(!fechadas.length){ toast(`Nenhuma folha fechada em ${MESES[mes]}/${ano}.`,'warning'); return; }
  const naoEnviados = fechadas.filter(p => !_statusEnvioHolerite(p));
  const jaEnviados  = fechadas.length - naoEnviados.length;
  let alvos = naoEnviados;
  if(jaEnviados > 0){
    if(confirm(`${jaEnviados} holerite(s) JÁ enviados. Reenviar TODOS os ${fechadas.length}? Senão, mando só os ${naoEnviados.length} ainda não enviados.`)){
      alvos = fechadas;
    }
  }
  if(!alvos.length){ toast('Tudo já foi enviado. Nada a fazer.','info'); return; }
  // Trava de revisão: só envia holerites de folhas REVISADAS; as demais são puladas. #revisada-gate
  const semRev = alvos.filter(p=>!p.revisada);
  alvos = alvos.filter(p=>p.revisada);
  if(!alvos.length){ toast('Nenhuma folha REVISADA pra enviar. Marque como revisada na tela Pagamentos.','warning'); return; }
  const _avisoRev = semRev.length ? `\n\n⚠ ${semRev.length} folha(s) NÃO revisada(s) serão puladas.` : '';
  if(!confirm(`Enviar ${alvos.length} holerite(s) de ${MESES[mes]}/${ano} pra conferência dos colaboradores?\n\nPrazo: ${_CONF_PRAZO_HORAS} horas. Após isso, sem ação, vira "aceito por silêncio".${_avisoRev}`)) return;
  const agora = new Date();
  const prazo = new Date(agora.getTime() + _CONF_PRAZO_HORAS*60*60*1000);
  const u = Auth.currentUser || {};
  let ok=0, erros=0;
  for(const p of alvos){
    const emp = State.employees.find(e => e.id === p.employeeId);
    if(!emp){ erros++; continue; }
    try{
      const r = _reciboOficialLinhas(emp, p);
      const reciboHtml = _reciboOficialUmHTML(emp, p, p.mes, p.ano, {});
      const envio = {
        enviadoEm: agora.toISOString(), enviadoPor: u.username||u.id||'', enviadoPorNome: u.username||'',
        status:'pendente', prazoExpiraEm: prazo.toISOString(),
        visualizadoEm:null, assinadoEm:null, contestadoEm:null,
        reciboHtml, liquido: r.liquido,
      };
      await DB.merge('payrolls', p.id, { holeriteConferencia: envio });
      p.holeriteConferencia = envio;
      ok++;
    }catch(e){ console.error('envio holerite', p.id, e); erros++; }
  }
  Auth.log('HOLERITE_ENVIADO_CONFERENCIA_LOTE', null, `${MESES[mes]}/${ano} — ${ok} holerite(s)`);
  toast(`${ok} holerite(s) enviado(s)${erros?` · ${erros} com erro`:''}${semRev.length?` · ${semRev.length} pulado(s) (não revisada)`:''}. Colab tem ${_CONF_PRAZO_HORAS}h pra responder.`,'success');
  if(typeof renderPagamentos==='function' && State.currentSection==='pagamentos') renderPagamentos();
}

// Job "aceito por silêncio" do HOLERITE (roda no carregamento do master, junto
// com o da folha). Marca aceita_por_silencio os holerites pendentes/visualizados
// cujo prazo já passou.
async function _aceitarPorSilencioHoleriteJob(){
  const agora = new Date();
  const candidatas = (State.payrolls||[]).filter(p => {
    const env = p.holeriteConferencia;
    if(!env) return false;
    if(env.status !== 'pendente' && env.status !== 'visualizada') return false;
    if(!env.prazoExpiraEm) return false;
    return new Date(env.prazoExpiraEm) <= agora;
  });
  if(!candidatas.length) return;
  for(const p of candidatas){
    const novo = { ...p.holeriteConferencia, status:'aceita_por_silencio', silencioEm: agora.toISOString() };
    try{
      await DB.merge('payrolls', p.id, { holeriteConferencia: novo });
      p.holeriteConferencia = novo;
    }catch(e){ console.error('silencio holerite', p.id, e); }
  }
  Auth.log('HOLERITE_SILENCIO', null, `${candidatas.length} holerite(s) aceitos por silêncio`);
}

// Aba "Holerites Assinados" no cadastro do colaborador (espelha Folhas Assinadas).
function renderHoleritesAssinadosColab(){
  const empId = State.editingEmployeeId || val('emp-id');
  const container = document.getElementById('holerites-assinados-list');
  if(!container) return;
  if(!empId){ container.innerHTML = '<div style="font-size:12px;color:#94a3b8;padding:8px 2px">Salve o colaborador primeiro.</div>'; return; }
  const lista = (State.payrolls||[]).filter(p => {
    if(p.employeeId !== empId) return false;
    const st = p?.holeriteConferencia?.status;
    return st === 'assinada' || st === 'aceita_por_silencio' || st === 'contestada';
  });
  lista.sort((a,b)=> a.ano!==b.ano ? b.ano-a.ano : b.mes-a.mes);
  if(!lista.length){
    container.innerHTML = `<div class="empty-state small"><i class="fa-solid fa-file-invoice-dollar" style="font-size:32px;color:#cbd5e0"></i><p style="font-size:13px;margin-top:8px">Nenhum holerite foi enviado/assinado ainda.</p></div>`;
    return;
  }
  container.innerHTML = lista.map(p => {
    const st = p.holeriteConferencia?.status;
    const stMap = {
      'assinada':            { txt:'Assinado', cor:'#2E7D32', bg:'#E8F5E9', icon:'fa-circle-check' },
      'aceita_por_silencio': { txt:'Aceito por silêncio', cor:'#558B2F', bg:'#F1F8E9', icon:'fa-clock-rotate-left' },
      'contestada':          { txt:'Contestado', cor:'#C62828', bg:'#FFEBEE', icon:'fa-circle-xmark' },
    };
    const cfg = stMap[st] || stMap['assinada'];
    const hash = p.holeriteAssinatura?.hash || '';
    const hashTrunc = hash ? `${hash.substring(0,16)}…` : '—';
    const enviado = p.holeriteConferencia?.enviadoEm ? new Date(p.holeriteConferencia.enviadoEm).toLocaleString('pt-BR') : '—';
    const quando = p.holeriteConferencia?.assinadoEm ? new Date(p.holeriteConferencia.assinadoEm).toLocaleString('pt-BR')
                 : p.holeriteConferencia?.silencioEm ? new Date(p.holeriteConferencia.silencioEm).toLocaleString('pt-BR')
                 : p.holeriteConferencia?.contestadoEm ? new Date(p.holeriteConferencia.contestadoEm).toLocaleString('pt-BR') : '—';
    const motivo = (st==='contestada' && p.holeriteContestacao?.motivo)
      ? `<div style="background:#FFEBEE;color:#C62828;padding:8px 10px;border-radius:5px;font-size:11px;margin-top:6px"><strong>Motivo:</strong> ${esc(p.holeriteContestacao.motivo)}</div>` : '';
    const btnVer = (st==='assinada' && p.holeriteAssinatura?.htmlRender)
      ? `<button class="btn btn-sm btn-outline" onclick="verHoleriteAssinado('${p.id}')" style="font-size:11px"><i class="fa-solid fa-eye"></i> Ver holerite + hash</button>`
      : (st==='aceita_por_silencio')
        ? `<button class="btn btn-sm btn-outline" onclick="alert('Aceito por silêncio — sem assinatura digital, sem hash. Holerite registrado como conferido automaticamente após 48h sem ação.')" style="font-size:11px;opacity:0.7"><i class="fa-solid fa-clock"></i> Sem hash (silêncio)</button>` : '';
    return `<div style="border:1px solid #e0e0e0;border-radius:8px;padding:12px 14px;margin-bottom:10px;background:#fafafa">
      <div style="display:flex;justify-content:space-between;align-items:center;gap:10px;flex-wrap:wrap">
        <div>
          <div style="font-weight:700;color:#1a1a2e;font-size:14px">${MESES[p.mes]} / ${p.ano}</div>
          <div style="font-size:11px;color:#888;margin-top:2px">Enviado: ${enviado} · ${cfg.txt}: ${quando}</div>
        </div>
        <span style="background:${cfg.bg};color:${cfg.cor};padding:4px 10px;border-radius:8px;font-size:11px;font-weight:700"><i class="fa-solid ${cfg.icon}"></i> ${cfg.txt.toUpperCase()}</span>${_carimboBadgeStatus(p.carimboHolStatus)} ${_carimboAcoesHtml('holerite', p.id, true)}
      </div>
      <div style="margin-top:8px;font-family:monospace;font-size:11px;color:#666"><strong>Hash:</strong> ${hashTrunc}</div>
      ${motivo}
      <div style="margin-top:8px">${btnVer}</div>
    </div>`;
  }).join('');
}

function verHoleriteAssinado(payrollId){
  const p = (State.payrolls||[]).find(x => x.id === payrollId);
  if(!p || !p.holeriteAssinatura?.htmlRender){ toast('Holerite sem HTML render disponível.','warning'); return; }
  const win = window.open('','_blank','width=900,height=900,scrollbars=yes');
  if(!win){ toast('Pop-ups bloqueados — habilite pra ver o holerite.','error'); return; }
  win.document.write(p.holeriteAssinatura.htmlRender);
  win.document.close();
}

// ============================================================================
// RECIBO DE BENEFÍCIOS → CONFERÊNCIA PELO COLABORADOR (Fase 2). Espelha o fluxo
// do holerite, mas em coleção PRÓPRIA `beneficioRecibos` (período de benefício
// não casa 1:1 com a folha mensal). Consolida o que foi pago no período num
// recibo só → app → visualizar/assinar/contestar → aceite tácito em 24h →
// armazena na aba "Recibos de Benefício" do cadastro (download PNG/PDF). #benef-recibo
// ============================================================================
const _BENEF_RECIBO_PRAZO_HORAS = 24;

// Período corrente da tela de Benefícios (mesmo critério do registrar pagamento).
function _benefPeriodoCorrente(){
  const tab = _beneficioTabAtual || 'hoje';
  const hojeISO = new Date().toISOString().substring(0,10);
  if(tab === 'mes'){
    const d=new Date(); const cMes=d.getMonth()+1, cAno=d.getFullYear();
    const per=_compPeriodo(cMes,cAno);
    return { ini:per.deISO, fim:per.ateISO, periodoLabel:`Competência ${MESES[cMes]}/${cAno} (${_compLabel(cMes,cAno)})` };
  } else if(tab === 'custom'){
    if(!_beneficioCustomIni || !_beneficioCustomFim) return null;
    return { ini:_beneficioCustomIni, fim:_beneficioCustomFim, periodoLabel:`Personalizado ${new Date(_beneficioCustomIni+'T12:00:00').toLocaleDateString('pt-BR')}–${new Date(_beneficioCustomFim+'T12:00:00').toLocaleDateString('pt-BR')}` };
  } else if(tab === 'hoje'){
    return { ini:hojeISO, fim:hojeISO, periodoLabel:`dia ${new Date().toLocaleDateString('pt-BR')}` };
  }
  const s=_semanaDe(hojeISO);
  return { ini:s.inicio, fim:s.fim, periodoLabel:`semana ${new Date(s.inicio+'T12:00:00').toLocaleDateString('pt-BR')}–${new Date(s.fim+'T12:00:00').toLocaleDateString('pt-BR')}` };
}

// HTML do recibo de benefícios (self-contained — o colab só EXIBE/assina).
function _reciboBeneficioHTML(emp, doc){
  const linhas = (doc.itens||[]).map(i=>{
    const dt = i.data ? new Date(i.data+'T12:00:00').toLocaleDateString('pt-BR') : '—';
    const formaTxt = (i.forma==='dinheiro') ? 'Dinheiro'
      : ('Plataforma'+(i.plataforma && i.plataforma!=='Plataforma' && i.plataforma!=='Dinheiro' ? ` (${esc(i.plataforma)})` : ''));
    return `<tr><td style="padding:6px 8px;border-bottom:1px solid #ECEFF1">${esc(i.label||i.tipo)}</td><td style="text-align:center;padding:6px 8px;border-bottom:1px solid #ECEFF1">${dt}</td><td style="text-align:center;padding:6px 8px;border-bottom:1px solid #ECEFF1">${formaTxt}</td><td style="text-align:right;padding:6px 8px;border-bottom:1px solid #ECEFF1">${fmtMoney(i.valor||0)}</td></tr>`;
  }).join('');
  return `<div style="font-family:Arial,Helvetica,sans-serif;max-width:640px;margin:0 auto;color:#1a1a2e">
    <div style="display:flex;align-items:center;gap:12px;border-bottom:2px solid #0288D1;padding-bottom:10px;margin-bottom:14px">
      <div style="background:#fff;padding:4px;border-radius:6px;border:1px solid #eee"><img src="${_logoSrc()}" style="height:44px;display:block" onerror="this.style.display='none'"></div>
      <div><div style="font-weight:800;font-size:16px">${esc(_e('nomeEmpresa'))}</div>
      <div style="font-size:12px;color:#555">Recibo de Benefícios — ${esc(doc.periodoLabel||'')}</div></div>
    </div>
    <div style="font-size:13px;margin-bottom:10px"><strong>Colaborador:</strong> ${esc(emp.nome||'')}${emp.registro?` · Matrícula ${String(emp.registro).padStart(4,'0')}`:''}${emp.cpf?` · CPF ${esc(emp.cpf)}`:''}</div>
    <table style="width:100%;border-collapse:collapse;font-size:13px">
      <thead><tr style="background:#E1F5FE">
        <th style="text-align:left;padding:6px 8px;border-bottom:1px solid #B3E5FC">Benefício</th>
        <th style="text-align:center;padding:6px 8px;border-bottom:1px solid #B3E5FC">Pago em</th>
        <th style="text-align:center;padding:6px 8px;border-bottom:1px solid #B3E5FC">Forma</th>
        <th style="text-align:right;padding:6px 8px;border-bottom:1px solid #B3E5FC">Valor</th>
      </tr></thead>
      <tbody>${linhas}</tbody>
      <tfoot><tr><td colspan="3" style="text-align:right;padding:8px;font-weight:700;border-top:2px solid #0288D1">Total</td><td style="text-align:right;padding:8px;font-weight:800;border-top:2px solid #0288D1;color:#0277BD">${fmtMoney(doc.total||0)}</td></tr></tfoot>
    </table>
    <div style="font-size:11px;color:#777;margin-top:12px;line-height:1.5">Declaro o recebimento dos benefícios acima discriminados, referentes ao período indicado. Documento gerado eletronicamente pelo sistema DRG-Kronos.</div>
  </div>`;
}

// Envia recibo de benefícios (consolidado do período) p/ os colaboradores marcados.
async function enviarRecibosBeneficioSelecionados(){
  if(Auth.currentUser?.role!=='master' && !getUserModules(Auth.currentUser).folhaEnviar){ toast('Sem permissão pra enviar recibos.','error'); return; }
  const chks = [...document.querySelectorAll('.benef-chk:checked')];
  if(!chks.length){ toast('Marque ao menos um colaborador na lista.','info'); return; }
  const per = _benefPeriodoCorrente();
  if(!per){ toast('Defina o período (Personalizado) primeiro.','warning'); return; }
  const { ini, fim, periodoLabel } = per;
  if(!confirm(`Enviar recibo de benefícios de ${chks.length} colaborador(es) — ${periodoLabel}?\n\nVai pro app deles conferir/assinar. Prazo ${_BENEF_RECIBO_PRAZO_HORAS}h → depois vira aceite tácito.`)) return;
  const u = Auth.currentUser||{};
  const agora = new Date();
  const prazo = new Date(agora.getTime()+_BENEF_RECIBO_PRAZO_HORAS*60*60*1000);
  const TIPOS=[{k:'vt',lbl:'VT — Vale Transporte'},{k:'vr',lbl:'VR — Vale Refeição'},{k:'va',lbl:'VA — Vale Alimentação'}];
  let ok=0, vazios=0, erros=0;
  for(const c of chks){
    const empId=c.dataset.empId; const emp=State.employees.find(e=>e.id===empId); if(!emp){erros++;continue;}
    const itens=[];
    TIPOS.forEach(t=>{
      const sol=(State.solicitacoes||[]).find(s=>s.origem==='beneficio-manual'&&s.beneficioTipo===t.k&&s.employeeId===empId&&s.status==='pago'&&s.competencia===`BEN${t.k.toUpperCase()}_${ini}_${fim}`);
      if(sol&&(sol.valor||0)>0){ itens.push({ tipo:t.k, label:t.lbl, valor:sol.valor, data:sol.pagoEm||sol.scheduleDate||'', forma:sol.formaPagamento||((sol.plataforma==='Dinheiro')?'dinheiro':'plataforma'), plataforma:sol.plataforma||'' }); }
    });
    if(!itens.length){ vazios++; continue; }
    const total=itens.reduce((s,i)=>s+(+i.valor||0),0);
    const id=`BR_${empId}_${ini}_${fim}`.replace(/[^A-Za-z0-9_]/g,'');
    const exist=(State.beneficioRecibos||[]).find(r=>r.id===id);
    let contestHist = (exist&&exist.contestacoesHistorico)?[...exist.contestacoesHistorico]:[];
    if(exist && exist.status==='contestada' && exist.contestacao){ contestHist.push({...exist.contestacao, comp:exist.periodoLabel}); }
    const docR={
      id, employeeId:empId, employeeNome:emp.nome||'', periodoKey:`${ini}_${fim}`, periodoLabel, ini, fim,
      itens, total, status:'pendente', prazoExpiraEm:prazo.toISOString(),
      enviadoEm:agora.toISOString(), enviadoPor:u.username||u.id||'', enviadoPorNome:u.username||'',
      visualizadoEm:null, assinatura:null, contestacao:null, contestacoesHistorico:contestHist, reciboHtml:''
    };
    docR.reciboHtml=_reciboBeneficioHTML(emp, docR);
    try{ await DB.save('beneficioRecibos', docR); ok++; }catch(e){ console.error('envio recibo benef', e); erros++; }
  }
  Auth.log('BENEF_RECIBO_ENVIADO', null, `${periodoLabel} — ${ok} recibo(s)`);
  toast(`${ok} recibo(s) enviado(s)${vazios?` · ${vazios} sem pagamento no período`:''}${erros?` · ${erros} erro(s)`:''}. Prazo ${_BENEF_RECIBO_PRAZO_HORAS}h.`, erros?'warning':'success');
}

// Job aceite tácito 24h (roda no listener de beneficioRecibos).
async function _aceitarPorSilencioBeneficioJob(){
  const agora=new Date();
  const cand=(State.beneficioRecibos||[]).filter(r=>{
    if(!r) return false;
    if(r.status!=='pendente'&&r.status!=='visualizada') return false;
    if(!r.prazoExpiraEm) return false;
    return new Date(r.prazoExpiraEm)<=agora;
  });
  if(!cand.length) return;
  for(const r of cand){
    try{
      await DB.merge('beneficioRecibos', r.id, { status:'aceita_por_silencio', silencioEm:agora.toISOString() });
      const idx=(State.beneficioRecibos||[]).findIndex(x=>x.id===r.id);
      if(idx>=0) State.beneficioRecibos[idx]={...r, status:'aceita_por_silencio', silencioEm:agora.toISOString()};
    }catch(e){ console.error('silencio benef', r.id, e); }
  }
  Auth.log('BENEF_RECIBO_SILENCIO', null, `${cand.length} recibo(s) de benefício aceitos por silêncio`);
}

// Aba "Recibos de Benefício" no cadastro do colaborador.
function renderRecibosBeneficioColab(){
  const empId = State.editingEmployeeId || val('emp-id');
  const container = document.getElementById('recibos-beneficio-list');
  if(!container) return;
  if(!empId){ container.innerHTML='<div style="font-size:12px;color:#94a3b8;padding:8px 2px">Salve o colaborador primeiro.</div>'; return; }
  const lista=(State.beneficioRecibos||[]).filter(r=>r.employeeId===empId).sort((a,b)=>new Date(b.enviadoEm||0)-new Date(a.enviadoEm||0));
  if(!lista.length){ container.innerHTML=`<div class="empty-state small"><i class="fa-solid fa-receipt" style="font-size:32px;color:#cbd5e0"></i><p style="font-size:13px;margin-top:8px">Nenhum recibo de benefício enviado ainda.</p></div>`; return; }
  const stMap={ pendente:{txt:'Aguardando',cor:'#E65100',bg:'#FFF3E0',icon:'fa-clock'}, visualizada:{txt:'Visualizado',cor:'#1565C0',bg:'#E3F2FD',icon:'fa-eye'}, assinada:{txt:'Assinado',cor:'#2E7D32',bg:'#E8F5E9',icon:'fa-circle-check'}, aceita_por_silencio:{txt:'Aceito por silêncio',cor:'#558B2F',bg:'#F1F8E9',icon:'fa-clock-rotate-left'}, contestada:{txt:'Contestado',cor:'#C62828',bg:'#FFEBEE',icon:'fa-circle-xmark'} };
  container.innerHTML=lista.map(r=>{
    const cfg=stMap[r.status]||stMap.pendente;
    const hash=r.assinatura&&r.assinatura.hash||'';
    const hashTrunc=hash?`${hash.substring(0,16)}…`:'—';
    const enviado=r.enviadoEm?new Date(r.enviadoEm).toLocaleString('pt-BR'):'—';
    const motivo=(r.status==='contestada'&&r.contestacao&&r.contestacao.motivo)?`<div style="background:#FFEBEE;color:#C62828;padding:8px 10px;border-radius:5px;font-size:11px;margin-top:6px"><strong>Contestação:</strong> ${esc(r.contestacao.motivo)}</div>`:'';
    const btnResp=(r.status==='contestada')?`<button class="btn btn-sm" style="font-size:11px;background:#C62828;color:#fff;border:none" onclick="responderReabrirContestacaoBeneficio('${r.id}')"><i class="fa-solid fa-reply"></i> Responder / reenviar</button>`:'';
    return `<div style="border:1px solid #e0e0e0;border-radius:8px;padding:12px 14px;margin-bottom:10px;background:#fafafa">
      <div style="display:flex;justify-content:space-between;align-items:center;gap:10px;flex-wrap:wrap">
        <div><div style="font-weight:700;font-size:14px">${esc(r.periodoLabel||'')}</div>
        <div style="font-size:11px;color:#888;margin-top:2px">Enviado: ${enviado} · Total ${fmtMoney(r.total||0)}</div></div>
        <span style="background:${cfg.bg};color:${cfg.cor};padding:4px 10px;border-radius:8px;font-size:11px;font-weight:700"><i class="fa-solid ${cfg.icon}"></i> ${cfg.txt.toUpperCase()}</span>${_carimboBadgeStatus(r.carimboStatus)} ${_carimboAcoesHtml('beneficio', r.id, true)}
      </div>
      <div style="margin-top:6px;font-family:monospace;font-size:11px;color:#666"><strong>Hash:</strong> ${hashTrunc}</div>
      ${motivo}
      <div style="margin-top:8px;display:flex;gap:6px;flex-wrap:wrap">
        <button class="btn btn-sm btn-outline" style="font-size:11px" onclick="verReciboBeneficio('${r.id}')"><i class="fa-solid fa-eye"></i> Ver</button>
        <button class="btn btn-sm btn-outline" style="font-size:11px" onclick="_baixarReciboBeneficio('${r.id}','pdf')"><i class="fa-solid fa-file-pdf"></i> PDF</button>
        <button class="btn btn-sm btn-outline" style="font-size:11px" onclick="_baixarReciboBeneficio('${r.id}','png')"><i class="fa-solid fa-file-image"></i> PNG</button>
        ${btnResp}
      </div>
    </div>`;
  }).join('');
}

function verReciboBeneficio(reciboId){
  const r=(State.beneficioRecibos||[]).find(x=>x.id===reciboId);
  const html = (r&&r.assinatura&&r.assinatura.htmlRender) || (r&&r.reciboHtml);
  if(!html){ toast('Recibo sem HTML disponível.','warning'); return; }
  const win=window.open('','_blank','width=900,height=900,scrollbars=yes');
  if(!win){ toast('Pop-ups bloqueados — habilite pra ver o recibo.','error'); return; }
  win.document.write(`<!DOCTYPE html><html><head><meta charset="utf-8"><title>Recibo de Benefícios</title></head><body style="margin:20px;background:#fff">${html}</body></html>`);
  win.document.close();
}

// Responde à contestação e REENVIA (reinicia o prazo de 24h). #benef-recibo
async function responderReabrirContestacaoBeneficio(reciboId){
  if(Auth.currentUser?.role!=='master' && !getUserModules(Auth.currentUser).folhaEnviar){ toast('Sem permissão.','error'); return; }
  const r=(State.beneficioRecibos||[]).find(x=>x.id===reciboId);
  if(!r){ toast('Recibo não encontrado.','error'); return; }
  const resp=prompt('Resposta à contestação (fica registrada no histórico). Ao confirmar, o recibo é REENVIADO e o prazo de 24h reinicia:', '');
  if(resp===null) return;
  const emp=State.employees.find(e=>e.id===r.employeeId);
  const agora=new Date();
  const prazo=new Date(agora.getTime()+_BENEF_RECIBO_PRAZO_HORAS*60*60*1000);
  const hist=[...(r.contestacoesHistorico||[])];
  if(r.contestacao){ hist.push({...r.contestacao, comp:r.periodoLabel, respostaGestor:resp, respondidoEm:agora.toISOString(), respondidoPor:(Auth.currentUser&&Auth.currentUser.username)||''}); }
  const upd={ status:'pendente', prazoExpiraEm:prazo.toISOString(), reenviadoEm:agora.toISOString(), respostaGestor:resp, contestacao:null, visualizadoEm:null, assinatura:null, contestacoesHistorico:hist };
  if(emp) upd.reciboHtml=_reciboBeneficioHTML(emp, r);
  try{
    await DB.merge('beneficioRecibos', reciboId, upd);
    const idx=(State.beneficioRecibos||[]).findIndex(x=>x.id===reciboId);
    if(idx>=0) State.beneficioRecibos[idx]={...r, ...upd};
    Auth.log('BENEF_RECIBO_REENVIADO', null, `${r.employeeNome} — ${r.periodoLabel}`);
    toast('Resposta registrada e recibo reenviado (24h).','success');
    renderRecibosBeneficioColab();
  }catch(e){ console.error(e); toast('Erro ao reenviar.','error'); }
}

// Baixa o recibo em PNG ou PDF (html2canvas + jsPDF).
async function _baixarReciboBeneficio(reciboId, formato){
  const r=(State.beneficioRecibos||[]).find(x=>x.id===reciboId);
  const html=(r&&r.assinatura&&r.assinatura.htmlRender) || (r&&r.reciboHtml);
  if(!html){ toast('Recibo sem HTML disponível.','warning'); return; }
  if(typeof html2canvas==='undefined'){ toast('Biblioteca de imagem ainda carregando — tente de novo em instantes.','warning'); return; }
  const holder=document.createElement('div');
  holder.style.cssText='position:fixed;left:-99999px;top:0;width:680px;background:#fff;padding:20px;z-index:-1';
  holder.innerHTML=html;
  document.body.appendChild(holder);
  try{
    const canvas=await html2canvas(holder, {scale:2, backgroundColor:'#ffffff', useCORS:true});
    const nomeBase=`recibo-beneficio-${(r.employeeNome||'colab').replace(/[^A-Za-z0-9]+/g,'_')}-${r.periodoKey||''}`;
    if(formato==='png'){
      const a=document.createElement('a'); a.href=canvas.toDataURL('image/png'); a.download=`${nomeBase}.png`;
      document.body.appendChild(a); a.click(); a.remove();
    } else {
      const jsPDFctor = (window.jspdf && window.jspdf.jsPDF) || window.jsPDF;
      if(!jsPDFctor){ toast('Biblioteca de PDF ainda carregando — tente de novo.','warning'); return; }
      const pdf=new jsPDFctor('p','mm','a4');
      const pw=pdf.internal.pageSize.getWidth();
      const imgW=pw-20; const imgH=canvas.height*imgW/canvas.width;
      pdf.addImage(canvas.toDataURL('image/jpeg',0.95),'JPEG',10,10,imgW,imgH);
      pdf.save(`${nomeBase}.pdf`);
    }
  }catch(e){ console.error('download recibo', e); toast('Erro ao gerar o arquivo.','error'); }
  finally{ holder.remove(); }
}

// Apura a Boa Permanência de uma folha SALVA no fechamento (sem o formulário).
// Como a bonificação é BENEFÍCIO (pago no VR, fora do salário/impostos), só
// precisa setar o campo `bonificacao` — não mexe em totalBruto/INSS/IRRF/líquido.
// Retorna {bonificacao} a atualizar, ou null se não mudou. Usado no LOTE.
function _apurarBonusFolha(p, emp, cct){
  if(!p || !emp) return null;
  const sempreP = !!emp.bonificacaoSemprePagar;
  const faltas  = (p.faltasInjustificadas||0)+(p.faltasJustificadas||0);
  const elegivel = sempreP || faltas===0;
  if(!elegivel){
    // Tem falta → perde a BP: zera (a menos que já esteja zerada).
    return (Math.abs(p.bonificacao||0) < 0.005) ? null : { bonificacao: 0 };
  }
  // Elegível: PRESERVA um valor já lançado (>0) — pode ser ajuste manual do gestor.
  // Só preenche pela CCT quando ainda não há valor. #audit-benef-7
  if((p.bonificacao||0) > 0) return null;
  const bonusNew = (cct && cct.bonificacao) || 0;
  if(Math.abs((p.bonificacao||0) - bonusNew) < 0.005) return null;
  return { bonificacao: bonusNew };
}

async function _executarFechamentoPeriodo(mes,ano,key,conf,automatico){
  const folhasAbertas=State.payrolls.filter(p=>p.mes==mes&&p.ano==ano&&p.status!=='fechada');
  const agora=new Date().toISOString();
  try{
    // Ao fechar, apura a Boa Permanência de cada folha (recompõe bruto/encargos/
    // líquido se o bônus mudou) e marca como fechada — tudo no mesmo merge.
    await Promise.all(folhasAbertas.map(p=>{
      const emp = State.employees.find(e=>e.id===p.employeeId);
      const upd = { status:'fechada', fechadoEm:agora };
      const recalc = (emp && !emp.isentoPonto) ? _apurarBonusFolha(p, emp, State.cct) : null;
      if(recalc) Object.assign(upd, recalc);
      return DB.merge('payrolls',p.id,upd).then(()=>{
        const s=State.payrolls.find(r=>r.id===p.id); if(s) Object.assign(s, upd);
      });
    }));
    const novaConf={...conf,fechado:true,fechadoEm:agora,updatedAt:agora};
    await DB.saveDoc('configuracoes',`fechamento_${key}`,novaConf,true);
    State.confFolha=State.confFolha||{};
    State.confFolha[key]=novaConf;
    const msg=automatico
      ? `Fechamento automático: ${folhasAbertas.length} folha(s) de ${MESES[mes]}/${ano} fechadas.`
      : `${folhasAbertas.length} folha(s) de ${MESES[mes]}/${ano} fechadas com sucesso.`;
    toast(msg);
    Auth.log('PAYROLL_PERIODO_FECHADO',null,`${MESES[mes]}/${ano} — ${folhasAbertas.length} folhas`);
    _updatePainelFechamento(mes,ano);
    // Atualizar status badge da folha atual se estiver carregada
    _updateFolhaStatusBadge();
    // Atalho 'Avançar pro próximo período' — só pergunta no fechamento MANUAL
    // (automático é silencioso); só faz sentido se a competência fechada é a
    // vigente OU histórica (não pergunta pra futura — não tem sentido avançar
    // pra mais futuro ainda).
    if(!automatico){
      const st = statusCompetencia(mes, ano);
      if(st !== 'futura'){
        let novoMes = mes + 1, novoAno = ano;
        if(novoMes > 12){ novoMes = 1; novoAno++; }
        // Pergunta após 500ms pra não competir com o toast
        setTimeout(() => {
          if(confirm(`✅ ${MESES[mes]}/${ano} foi fechada com sucesso!\n\nAvançar agora para a próxima competência (${MESES[novoMes]}/${novoAno})?`)){
            setVal('payroll-mes', String(novoMes));
            setVal('payroll-ano', String(novoAno));
            onPayrollPeriodoChange();
          }
        }, 500);
      }
    }
  }catch(e){ toast('Erro ao fechar período.','error'); console.error(e); }
}

async function fecharFolhaIndividual(){
  const empId=val('payroll-employee');
  const emp=State.employees.find(e=>e.id===empId);
  const mes=parseInt(val('payroll-mes')||currentMes());
  const ano=parseInt(val('payroll-ano')||currentAno());
  if(!empId||!emp){ toast('Selecione um colaborador.','error'); return; }
  const p=State.payrolls.find(r=>r.employeeId===empId&&r.mes==mes&&r.ano==ano);
  if(!p){ toast('Salve o lançamento antes de fechar.','error'); return; }
  if(p.status==='fechada'){ toast('Esta folha já está fechada.','warning'); return; }
  if(!confirm(`Fechar a folha de ${emp.nome} — ${MESES[mes]}/${ano}?\n\nA folha ficará bloqueada para edição. Você poderá reabrir se necessário.`)) return;
  try{
    const agora=new Date().toISOString();
    // Apura a Boa Permanência NO FECHAMENTO: com o flag ligado, o recalculate
    // libera a bonificação (se sem faltas no mês) e o savePayroll persiste o
    // valor + totais. Só depois a folha é marcada como fechada.
    if(val('payroll-employee')===empId){
      _fechandoFolha = true;
      try { recalculate(); await savePayroll(); }
      finally { _fechandoFolha = false; }
    }
    await DB.merge('payrolls',p.id,{status:'fechada',fechadoEm:agora});
    const s=State.payrolls.find(r=>r.id===p.id); if(s){ s.status='fechada'; s.fechadoEm=agora; }
    Auth.log('PAYROLL_FECHADO_INDIVIDUAL',null,`${emp.nome} — ${MESES[mes]}/${ano}`);
    toast(`Folha de ${emp.nome} fechada.`);
    _updateFolhaStatusBadge();
  }catch(e){ toast('Erro ao fechar folha.','error'); console.error(e); }
}

async function reabrirFolha(){
  const empId=val('payroll-employee');
  const emp=State.employees.find(e=>e.id===empId);
  const mes=parseInt(val('payroll-mes')||currentMes());
  const ano=parseInt(val('payroll-ano')||currentAno());
  if(!empId||!emp){ toast('Selecione um colaborador.','error'); return; }
  const p=State.payrolls.find(r=>r.employeeId===empId&&r.mes==mes&&r.ano==ano);
  if(!p){ toast('Folha não encontrada.','error'); return; }
  if(!confirm(`Reabrir a folha de ${emp.nome} — ${MESES[mes]}/${ano}?\n\nA folha voltará a ser editável. O período geral continuará fechado para os demais.`)) return;
  try{
    // Antes de reabrir, ARQUIVA a contestação atual no histórico (senão some quando
    // a folha for reenviada/ajustada). #contestacao-historico
    const _arqC = _arquivarContestacaoFolha(p);
    await DB.merge('payrolls',p.id,{status:'aberta',reabertoEm:new Date().toISOString(), ...(_arqC?{contestacoesHistorico:p.contestacoesHistorico}:{})});
    const s=State.payrolls.find(r=>r.id===p.id); if(s){ s.status='aberta'; if(_arqC) s.contestacoesHistorico=p.contestacoesHistorico; }
    Auth.log('PAYROLL_REABERTO',null,`${emp.nome} — ${MESES[mes]}/${ano}`);
    toast(`Folha de ${emp.nome} reaberta para edição.`);
    _updateFolhaStatusBadge();
  }catch(e){ toast('Erro ao reabrir folha.','error'); }
}

// ============================================
// BACKFILL — preenche folhas do período com as horas previstas
// ============================================
// Ação ÚNICA usada na virada para o modelo de competência (fecha dia 25).
// Botão removido da UI em 2026-05-30 (migração já concluída). Função preservada
// caso precise restaurar o botão pra novo cliente no futuro.
async function backfillFolhasPeriodo(){
  if(Auth.currentUser?.role!=='master'){ toast('Apenas o usuário master pode rodar o preenchimento do período.','error'); return; }
  const mes=parseInt(val('payroll-mes')||currentMes());
  const ano=parseInt(val('payroll-ano')||currentAno());
  const per=_compPeriodo(mes,ano);
  const compDias=_compDias(mes,ano);
  const zp=n=>String(n).padStart(2,'0');
  const emps=_filtrarEmpsPorEscopo((State.employees||[]).filter(e=>(e.status||'ativo')==='ativo' && !e.isentoPonto));
  if(!emps.length){ toast('Nenhum colaborador ativo no escopo.','error'); return; }
  if(!confirm(`Preencher automaticamente as folhas de ${emps.length} colaborador(es) na competência ${MESES[mes]}/${ano} (${_compLabel(mes,ano)})?\n\n• Projeta as horas previstas (escala/cadastro) nos dias SEM ponto real, até a 1ª batida de cada colaborador.\n• Dias com ponto batido NÃO são tocados.\n• Recomendado: fazer backup antes.\n\nContinuar?`)) return;

  // ANTI-DUPLICIDADE: recarrega as folhas do banco AGORA, pra o "já existe folha?" deste
  // lote olhar o estado REAL (não a memória que pode estar velha — causa das folhas
  // duplicadas). Combina com o id determinístico de folha. #anti-dup-folha
  try{ State.payrolls = await DB.getAll('payrolls'); }catch(_e){}
  let nFolhas=0, nDias=0, nPulados=0;
  for(const emp of emps){
    if(_cadastroPendencias(emp).length){ nPulados++; continue; }
    const admISO=(emp.dataAdmissao||'').substring(0,10);
    if(admISO && admISO>per.ateISO){ nPulados++; continue; }          // admitido depois do período
    const effStartISO=(admISO && admISO>per.deISO) ? admISO : per.deISO;

    const reg=State.payrolls.find(p=>p.employeeId===emp.id&&p.mes==mes&&p.ano==ano);
    const dias=reg?.pontoManualDias ? [...reg.pontoManualDias] : [];

    // 1ª batida REAL (app/manual) — entradas de backfill anteriores não contam.
    let firstPunchISO=null;
    dias.forEach(d=>{
      if(!d||!d.entrada || (d.entrada_origem||'')==='backfill') return;
      const rd=_compRealDate(mes,ano,d.dia);
      const iso=`${rd.ano}-${zp(rd.mes)}-${zp(rd.dia)}`;
      if(!firstPunchISO || iso<firstPunchISO) firstPunchISO=iso;
    });

    let mudou=false;
    for(const cd of compDias){
      const iso=`${cd.ano}-${zp(cd.mes)}-${zp(cd.dia)}`;
      if(iso<effStartISO) continue;                       // antes da admissão / início do período
      if(firstPunchISO && iso>=firstPunchISO) continue;   // a partir da 1ª batida, vale o ponto real
      const ex=dias.find(x=>x.dia===cd.dia);
      if(ex && ex.entrada && (ex.entrada_origem||'')!=='backfill') continue; // não toca batida real
      const exp=_getExpectedDay(emp,cd.mes,cd.ano,cd.dia);
      if(!exp || exp.tipo==='folga' || !exp.entrada) continue;              // folga / sem expediente
      const novo={
        dia:cd.dia, diaSem:cd.diaSem,
        entrada:exp.entrada||'', saida:exp.saida||'',
        intIni:exp.intIni||'', intFim:exp.intFim||'',
        entrada_origem:'backfill', saida_origem:'backfill',
        intIni_origem:'backfill', intFim_origem:'backfill'
      };
      const ix=dias.findIndex(x=>x.dia===cd.dia);
      if(ix>=0) dias[ix]={...dias[ix], ...novo}; else dias.push(novo);
      mudou=true; nDias++;
    }
    if(!mudou) continue;

    // Recalcula totais básicos (dias/faltas/HE). Salário/benefícios são apurados
    // ao abrir/fechar a folha (recalculate) e pela tela de Benefícios a Pagar.
    const diasTrab=dias.filter(d=>d.entrada&&d.saida).length;
    const fam=escalaFamilia(emp.escala||'5x2A'); const is12=fam==='12x36';
    let faltas=0;
    for(const cd of compDias){
      const has=dias.find(x=>x.dia===cd.dia);
      if(has && has.entrada && has.saida) continue;
      const isWk=cd.diaSem===0||cd.diaSem===6;
      if(_diaEmBrancoEhFalta(emp,cd.mes,cd.ano,cd.dia,isWk,is12)) faltas++;
    }
    const heMin=_heMinFromDias(emp,mes,ano,dias);
    const base={ pontoManualDias:dias, diasTrabalhados:diasTrab,
      faltasInjustificadas:faltas, faltasJustificadas:(reg?.faltasJustificadas||0),
      horasExtrasTotal:(heMin>0?+(heMin/60).toFixed(2):0), updatedAt:new Date().toISOString() };
    const record = reg ? {...reg, ...base}
      : { id:_payrollId(emp.id,mes,ano), employeeId:emp.id, mes, ano, createdAt:new Date().toISOString(), ...base };
    try{
      await DB.save('payrolls', _sanitizeForFirestore(record));
      const ix=State.payrolls.findIndex(p=>p.id===record.id);
      if(ix>=0) State.payrolls[ix]=record; else State.payrolls.push(record);
      nFolhas++;
    }catch(e){ console.error('backfill save', emp.nome, e); }
  }
  try{ Auth.log('BACKFILL_PERIODO', null, `${MESES[mes]}/${ano} — ${nFolhas} folha(s), ${nDias} dia(s)`); }catch(_){}
  toast(`Backfill concluído: ${nFolhas} folha(s), ${nDias} dia(s) projetado(s)${nPulados?` · ${nPulados} pulado(s) (cadastro incompleto ou admissão fora do período)`:''}.`, 'success');
  if(val('payroll-employee')) onPayrollEmployeeChange();
  try{ renderDashboard(); }catch(_){}
}

// ============================================
// LIMPAR DIAS DE BACKFILL — remove só os dias projetados (origem 'backfill')
// ============================================
// Desfaz o preenchimento automático: tira das folhas da competência os dias que
// são PURAMENTE projetados (todos os campos com origem 'backfill') e NÃO têm
// nenhuma batida real (app/manual). Preserva 100% das batidas reais. Use quando
// optar por preencher o ponto manualmente. Não toca folhas FECHADAS.
async function limparBackfillPeriodo(){
  if(Auth.currentUser?.role!=='master'){ toast('Apenas o usuário master pode rodar a limpeza.','error'); return; }
  const mes=parseInt(val('payroll-mes')||currentMes());
  const ano=parseInt(val('payroll-ano')||currentAno());
  const ehBackfill=d=>{
    const og=['entrada','saida','intIni','intFim'].map(k=>d[k+'_origem']).filter(Boolean);
    const temReal=og.some(o=>o==='app'||o==='manual');
    const temBack=og.some(o=>o==='backfill');
    return temBack && !temReal;     // só dias 100% projetados, sem batida real
  };
  const afetadas=(State.payrolls||[]).filter(p=>p.mes==mes&&p.ano==ano&&Array.isArray(p.pontoManualDias)&&p.pontoManualDias.some(ehBackfill));
  if(!afetadas.length){ toast('Nenhum dia de backfill encontrado nesta competência. Nada a limpar.','info'); return; }
  const fechadas=afetadas.filter(p=>p.status==='fechada');
  if(fechadas.length){ toast(`${fechadas.length} folha(s) FECHADA(s). Reabra antes de limpar o backfill.`,'error'); return; }
  const totalDias=afetadas.reduce((s,p)=>s+p.pontoManualDias.filter(ehBackfill).length,0);
  if(!confirm(`Remover ${totalDias} dia(s) projetado(s) pelo backfill de ${afetadas.length} folha(s) — ${MESES[mes]}/${ano}?\n\n• Remove SÓ os dias 100% projetados (origem 'backfill').\n• Batidas reais (app/manual) são preservadas.\n• Depois você preenche o ponto manualmente.\n\nContinuar?`)) return;
  let nF=0, nD=0;
  for(const p of afetadas){
    const emp=State.employees.find(e=>e.id===p.employeeId);
    if(!emp) continue;
    const dias=p.pontoManualDias.filter(d=>!ehBackfill(d));
    nD += (p.pontoManualDias.length - dias.length);
    // Recalcula totais com os dias restantes
    const diasTrab=dias.filter(d=>d.entrada&&d.saida).length;
    const fam=escalaFamilia(emp.escala||'5x2A'); const is12=fam==='12x36';
    let faltas=0;
    for(const cd of _compDias(mes,ano)){
      const has=dias.find(x=>x.dia===cd.dia);
      if(has && has.entrada && has.saida) continue;
      const isWk=cd.diaSem===0||cd.diaSem===6;
      if(_diaEmBrancoEhFalta(emp,cd.mes,cd.ano,cd.dia,isWk,is12)) faltas++;
    }
    const heMin=_heMinFromDias(emp,mes,ano,dias);
    const base={ pontoManualDias:dias, diasTrabalhados:diasTrab,
      faltasInjustificadas:faltas, faltasJustificadas:(p.faltasJustificadas||0),
      horasExtrasTotal:(heMin>0?+(heMin/60).toFixed(2):0), updatedAt:new Date().toISOString() };
    const record={...p, ...base};
    try{
      await DB.save('payrolls', _sanitizeForFirestore(record));
      const ix=State.payrolls.findIndex(r=>r.id===record.id);
      if(ix>=0) State.payrolls[ix]=record;
      nF++;
    }catch(e){ console.error('limpar backfill', emp.nome, e); }
  }
  try{ Auth.log('LIMPAR_BACKFILL', null, `${MESES[mes]}/${ano} — ${nF} folha(s), ${nD} dia(s)`); }catch(_){}
  toast(`Limpeza concluída: ${nD} dia(s) de backfill removido(s) de ${nF} folha(s). Pode preencher o ponto manualmente.`, 'success');
  if(val('payroll-employee')) onPayrollEmployeeChange();
  try{ renderDashboard(); }catch(_){}
}

// ============================================
// RECALCULAR FALTAS EM MASSA — corrige faltasInjustificadas inflado pelo
// backfill (especialmente 12x36 sem âncora antes do fix de 2026-05-30).
// Recomputa `faltasInjustificadas` baseado no estado ATUAL da folha:
//   - Para cada dia previsto de trabalho (escala) sem ponto batido,
//     conta como falta SE `_diaEmBrancoEhFalta` retornar true.
// Preserva `faltasJustificadas` (lançadas manualmente pelo usuário).
// Salva mesmo em folhas FECHADAS (admin-only, master-only).
// Reset visível no BP — quem ficou em 0+0 vira elegível na próxima leitura.
// ============================================
async function recalcularFaltasCompetencia(mesArg, anoArg){
  // Feedback IMEDIATO no clique — pra confirmar que a função foi chamada.
  // (antes ficava silencioso até o confirm, dando impressão de 'não funciona')
  toast('Iniciando recalculo de faltas...','info');
  console.log('[recalcularFaltasCompetencia] iniciado', { mesArg, anoArg, user: Auth.currentUser?.username, role: Auth.currentUser?.role });
  if(Auth.currentUser?.role!=='master'){ toast('Apenas o usuário master pode rodar o recalculo.','error'); return; }
  // Aceita mes/ano via argumento OU lê dos inputs OU usa o currentMes/Ano.
  // Argumentos têm prioridade pra evitar bug quando chamado de fora da tela
  // de Folha de Ponto (Benefícios, p.ex.) onde os inputs não existem.
  let mes = parseInt(mesArg || val('payroll-mes') || currentMes());
  let ano = parseInt(anoArg || val('payroll-ano') || currentAno());
  console.log('[recalcularFaltasCompetencia] competência alvo:', mes, ano);
  const afetadas=(State.payrolls||[]).filter(p=>p.mes==mes&&p.ano==ano);
  console.log('[recalcularFaltasCompetencia] folhas encontradas:', afetadas.length);
  if(!afetadas.length){
    toast(`Nenhuma folha encontrada em ${MESES[mes]}/${ano}. Verifique se a competência tem folhas salvas.`,'warning');
    return;
  }
  if(!confirm(`Recalcular FALTAS INJUSTIFICADAS de ${afetadas.length} folha(s) da competência ${MESES[mes]}/${ano} (${_compLabel(mes,ano)})?\n\n• Recalcula com base no estado ATUAL da folha (dias batidos vs escala).\n• Preserva 'faltasJustificadas' (lançadas manualmente).\n• Roda mesmo em folhas FECHADAS.\n• Útil quando o backfill inflou as faltas (12x36 sem âncora, escala antiga errada etc.).\n\nDepois disso, quem tiver 0 falta volta a receber Boa Permanência.\n\nContinuar?`)) return;
  let nAlteradas=0, nMantidas=0, nReduziu=0;
  for(const p of afetadas){
    const emp=State.employees.find(e=>e.id===p.employeeId);
    if(!emp) continue;
    // MESMO motor da prévia/espelho: _apuracaoPontoTotais aplica _repararBatidasDia.
    // Antes este recálculo contava falta com check CRU (entrada&&saida) e DISCORDAVA da
    // folha impressa — dia com 2ª batida presa no slot de intervalo (sábado curto / FDS
    // livre) virava falta fantasma e inflava o nº salvo, deixando a pessoa "perdendo" BP
    // mesmo sem falta real (caso Carla jun/2026). Motor único. #recalc-motor-unico
    const novasFaltas = _apuracaoPontoTotais(emp, p).faltaQtd || 0;
    const antigas = p.faltasInjustificadas||0;
    if(novasFaltas === antigas){ nMantidas++; continue; }
    if(novasFaltas < antigas) nReduziu++;
    const record={...p, faltasInjustificadas:novasFaltas, updatedAt:new Date().toISOString()};
    try{
      await DB.save('payrolls', _sanitizeForFirestore(record));
      const ix=State.payrolls.findIndex(r=>r.id===record.id);
      if(ix>=0) State.payrolls[ix]=record;
      nAlteradas++;
    }catch(e){ console.error('recalc faltas', emp.nome, e); }
  }
  try{ Auth.log('RECALC_FALTAS', null, `${MESES[mes]}/${ano} — ${nAlteradas} folha(s) alterada(s), ${nReduziu} com redução, ${nMantidas} sem mudança`); }catch(_){}
  toast(`Recalculo concluído: ${nAlteradas} folha(s) alterada(s) (${nReduziu} com redução de faltas) · ${nMantidas} sem mudança. Reabra a tela de Benefícios pra ver o efeito na Boa Permanência.`, 'success');
  if(val('payroll-employee')) onPayrollEmployeeChange();
  try{ renderDashboard(); }catch(_){}
}

// ============================================
// REPROJETAR DIAS MIGRADOS (26-31) — correção em lote da virada
// ============================================
// Ação ÚNICA da virada: a migração trouxe os dias 26-31 do mês anterior com o
// horário ANTIGO (ex.: 08-17 de uma projeção antiga). Esta função REESCREVE só os
// dias 26-31 de todas as folhas da competência usando a escala ATUAL de cada
// colaborador (5x2→08-17, 12x36→07-19 etc.). Os dias 1-25 (batidas reais do mês)
// NÃO são tocados. Reversível via backup.
// ============================================
// SANEAR LIVRES DE JORNADA
// Colaborador com `isentoPonto` nao deve levar restricoes da apuracao de ponto.
// ============================================
async function sanearFolhasIsentos(mesArg, anoArg){
  if(Auth.currentUser?.role!=='master'){ toast('Apenas o usuario master pode sanear livres de jornada.','error'); return; }
  const mes=parseInt(mesArg || val('cont-mes') || val('payroll-mes') || currentMes());
  const ano=parseInt(anoArg || val('cont-ano') || val('payroll-ano') || currentAno());
  const isentos=new Set((State.employees||[]).filter(e=>e.isentoPonto).map(e=>e.id));
  const afetadas=(State.payrolls||[]).filter(p=>p.mes==mes&&p.ano==ano&&isentos.has(p.employeeId));
  if(!afetadas.length){
    toast(`Nenhuma folha de colaborador livre de jornada em ${MESES[mes]}/${ano}.`,'info');
    return;
  }
  const comRestricao=afetadas.filter(p=>
    (+p.faltas||0)>0 || (+p.faltasJustificadas||0)>0 || (+p.faltasInjustificadas||0)>0 ||
    (+p.horasExtrasTotal||0)>0 || (+p.horasExtrasValor||0)>0 ||
    (+p.heCorridoMin||0)>0 || (+p.heCorridoValor||0)>0 ||
    (+p.adNoturno||0)>0 || (+p.minutosAtraso||0)>0 || (+p.descontoAtraso||0)>0 ||
    (+p.minutosSaida||0)>0 || (+p.descontoSaida||0)>0 ||
    (+p.refNaoRendidaMin||0)>0 || (+p.refNaoRendidaValor||0)>0
  );
  if(!comRestricao.length){
    toast(`Livres de jornada ja estao sem restricoes em ${MESES[mes]}/${ano}.`,'success');
    return;
  }
  if(!confirm(`Sanear ${comRestricao.length} folha(s) de colaborador(es) livre(s) de jornada em ${MESES[mes]}/${ano}?\n\nSerao zerados: faltas, atrasos, saidas, horas extras, adicional noturno e refeicao nao rendida.\nBeneficios, emprestimos, acumulo, insalubridade e observacoes serao preservados.\n\nContinuar?`)) return;

  const patch={
    faltas:0, faltasJustificadas:0, faltasInjustificadas:0,
    horasExtrasTotal:0, horasExtrasValor:0,
    heCorridoMin:0, heCorridoDetalhe:'', heCorridoValor:0,
    adNoturno:0,
    minutosAtraso:0, descontoAtraso:0,
    minutosSaida:0, descontoSaida:0,
    refNaoRendidaMin:0, refNaoRendidaValor:0,
    updatedAt:new Date().toISOString()
  };
  let n=0;
  for(const p of comRestricao){
    const record={...p,...patch};
    try{
      await DB.save('payrolls', _sanitizeForFirestore(record));
      const ix=State.payrolls.findIndex(r=>r.id===record.id);
      if(ix>=0) State.payrolls[ix]=record;
      n++;
    }catch(e){
      const emp=State.employees.find(x=>x.id===p.employeeId);
      console.error('sanear livres de jornada', emp?.nome||p.employeeId, e);
    }
  }
  try{ Auth.log('SANEAMENTO_ISENTOS', null, `${MESES[mes]}/${ano} - ${n} folha(s) saneada(s)`); }catch(_){}
  toast(`Saneamento concluido: ${n} folha(s) livre(s) de jornada limpa(s).`,'success');
  try{ renderContabilidade(); }catch(_){}
  try{ renderPagamentos(); }catch(_){}
  if(val('payroll-employee')) onPayrollEmployeeChange();
  try{ renderDashboard(); }catch(_){}
}

async function reprojetarDiasMigrados(){
  if(Auth.currentUser?.role!=='master'){ toast('Apenas o usuário master pode rodar.','error'); return; }
  const mes=parseInt(val('payroll-mes')||currentMes());
  const ano=parseInt(val('payroll-ano')||currentAno());
  const compDias=_compDias(mes,ano);
  const emps=_filtrarEmpsPorEscopo((State.employees||[]).filter(e=>(e.status||'ativo')==='ativo' && !e.isentoPonto));
  const afetadas=(State.payrolls||[]).filter(p=>p.mes==mes&&p.ano==ano&&Array.isArray(p.pontoManualDias)&&p.pontoManualDias.some(d=>parseInt(d.dia)>=26)&&emps.some(e=>e.id===p.employeeId));
  if(!afetadas.length){ toast('Nenhuma folha com dias 26-31 nesta competência. Nada a reprojetar.','info'); return; }
  const fechadas=afetadas.filter(p=>p.status==='fechada');
  if(fechadas.length){ toast(`${fechadas.length} folha(s) FECHADA(s). Use "Reabrir Todas as Folhas" antes de reprojetar.`,'error'); return; }
  if(!confirm(`Reprojetar os dias 26-31 (vindos do mês anterior pela migração) de ${afetadas.length} folha(s) — ${MESES[mes]}/${ano}?\n\n• Esses dias serão REESCRITOS com a escala atual de cada colaborador (5x2 → 08-17, 12x36 → 07-19 etc.).\n• Os dias 1-25 (batidas reais do mês) NÃO são tocados.\n• Ação de virada (use uma vez). Faça backup antes.\n\nContinuar?`)) return;
  let nF=0, nD=0;
  for(const p of afetadas){
    const emp=emps.find(e=>e.id===p.employeeId);
    if(!emp || _cadastroPendencias(emp).length) continue;
    // Mantém dias 1-25 (batidas reais); reprojeta os dias 26-31 pela escala atual.
    const dias=p.pontoManualDias.filter(d=>parseInt(d.dia)<26);
    for(const cd of compDias){
      if(cd.dia<26) continue;
      const exp=_getExpectedDay(emp,cd.mes,cd.ano,cd.dia);
      if(!exp || exp.tipo==='folga' || !exp.entrada) continue; // folga / sem expediente
      dias.push({ dia:cd.dia, diaSem:cd.diaSem,
        entrada:exp.entrada||'', saida:exp.saida||'',
        intIni:exp.intIni||'', intFim:exp.intFim||'',
        entrada_origem:'backfill', saida_origem:'backfill',
        intIni_origem:'backfill', intFim_origem:'backfill' });
      nD++;
    }
    const diasTrab=dias.filter(d=>d.entrada&&d.saida).length;
    const fam=escalaFamilia(emp.escala||'5x2A'); const is12=fam==='12x36';
    let faltas=0;
    for(const cd of compDias){
      const has=dias.find(x=>x.dia===cd.dia);
      if(has && has.entrada && has.saida) continue;
      const isWk=cd.diaSem===0||cd.diaSem===6;
      if(_diaEmBrancoEhFalta(emp,cd.mes,cd.ano,cd.dia,isWk,is12)) faltas++;
    }
    const heMin=_heMinFromDias(emp,mes,ano,dias);
    const base={ pontoManualDias:dias, diasTrabalhados:diasTrab,
      faltasInjustificadas:faltas, faltasJustificadas:(p.faltasJustificadas||0),
      horasExtrasTotal:(heMin>0?+(heMin/60).toFixed(2):0), updatedAt:new Date().toISOString() };
    const record={...p, ...base};
    try{
      await DB.save('payrolls', _sanitizeForFirestore(record));
      const ix=State.payrolls.findIndex(r=>r.id===record.id);
      if(ix>=0) State.payrolls[ix]=record;
      nF++;
    }catch(e){ console.error('reprojetar migrados', emp.nome, e); }
  }
  try{ Auth.log('REPROJETAR_DIAS_MIGRADOS', null, `${MESES[mes]}/${ano} — ${nF} folha(s), ${nD} dia(s)`); }catch(_){}
  toast(`Reprojeção concluída: ${nF} folha(s), ${nD} dia(s) 26-31 reescritos com a escala correta. Confira alguns 12x36.`, 'success');
  if(val('payroll-employee')) onPayrollEmployeeChange();
  try{ renderDashboard(); }catch(_){}
}

// ============================================
// MIGRAÇÃO ÚNICA — calendário → competência (fecha dia 25)
// ============================================
// Antes do modelo de competência as batidas eram gravadas por MÊS DE CALENDÁRIO
// ({mes,ano}=mês do calendário, dia=dia do mês). No novo modelo {mes,ano} é o
// RÓTULO da competência e os dias 26-31 pertencem ao mês ANTERIOR. Logo os dias
// 26-31 já gravados precisam migrar para a folha da competência do mês SEGUINTE
// (ex.: maio 26-31, hoje em {mes:5}, vão para a competência junho {mes:6}).
// Roda UMA vez (marcador em configuracoes/migracao_competencia). Reversível via
// backup. NÃO altera folhas FECHADAS — aborta e pede reabertura.
async function migrarParaCompetencia(){
  if(Auth.currentUser?.role!=='master'){ toast('Apenas o usuário master pode rodar a migração.','error'); return; }
  const GKEY='migracao_competencia';
  try{
    const g=await DB.getDoc('configuracoes', GKEY);
    if(g && g.feitoEm){ toast(`Migração já realizada em ${new Date(g.feitoEm).toLocaleDateString('pt-BR')}. Não rode de novo — bagunçaria os dados.`,'warning'); return; }
  }catch(e){ console.warn('guard migração', e); }

  const zp=n=>String(n).padStart(2,'0');
  const hojeISO=new Date().toISOString().substring(0,10);
  // Snapshot imutável: clona os dias de cada folha ANTES de qualquer escrita.
  const snap=(State.payrolls||[]).filter(p=>Array.isArray(p.pontoManualDias))
    .map(p=>({employeeId:p.employeeId, mes:parseInt(p.mes), ano:parseInt(p.ano),
              dias:p.pontoManualDias.map(d=>({...d}))}));
  const snapDe=(eId,m,a)=>snap.find(s=>s.employeeId===eId&&s.mes===m&&s.ano===a);

  const comDias2631=snap.filter(s=>s.dias.some(d=>d && parseInt(d.dia)>=26));
  if(!comDias2631.length){ toast('Nenhuma folha com dias 26-31. Nada a migrar.','info'); return; }

  // Folhas que serão recompostas: as próprias fontes (perdem 26-31) + a
  // competência do mês seguinte de cada uma (recebe 26-31).
  const alvos=new Map();
  const addAlvo=(eId,m,a)=>alvos.set(`${eId}|${m}|${a}`, {employeeId:eId, mes:m, ano:a});
  for(const s of comDias2631){
    addAlvo(s.employeeId, s.mes, s.ano);
    let dm=s.mes+1, da=s.ano; if(dm>12){ dm=1; da=s.ano+1; }
    addAlvo(s.employeeId, dm, da);
  }

  // Segurança: nenhuma folha afetada pode estar FECHADA.
  const fechadas=[];
  for(const {employeeId,mes,ano} of alvos.values()){
    const d=(State.payrolls||[]).find(p=>p.employeeId===employeeId&&p.mes==mes&&p.ano==ano);
    if(d && d.status==='fechada') fechadas.push(d);
  }
  if(fechadas.length){
    const lista=fechadas.map(p=>{const e=State.employees.find(x=>x.id===p.employeeId);return `${e?e.nome:p.employeeId} ${MESES[p.mes]}/${p.ano}`;}).slice(0,8).join(', ');
    toast(`Migração abortada: ${fechadas.length} folha(s) FECHADA(s) precisariam mudar (${lista}${fechadas.length>8?'…':''}). Reabra-as antes.`,'error');
    return;
  }

  if(!confirm(`Migrar para o modelo de competência (fecha dia 25)?\n\n• ${comDias2631.length} folha(s) têm dias 26-31, que irão para a competência do mês SEGUINTE.\n• Os dias 1-25 permanecem onde estão.\n• Esta ação roda UMA única vez. Faça backup antes.\n\nContinuar?`)) return;

  // ANTI-DUPLICIDADE: recarrega as folhas do banco antes do lote (estado real, não a
  // memória velha). Combina com o id determinístico de folha. #anti-dup-folha
  try{ State.payrolls = await DB.getAll('payrolls'); }catch(_e){}
  let nFolhas=0, nMovidos=0;
  for(const {employeeId,mes,ano} of alvos.values()){
    const emp=State.employees.find(e=>e.id===employeeId);
    // Novos dias = (1-25 da própria competência) + (26-31 do mês anterior).
    let pm=mes-1, pa=ano; if(pm<1){ pm=12; pa=ano-1; }
    const own=snapDe(employeeId,mes,ano);
    const prev=snapDe(employeeId,pm,pa);
    const dias1_25=(own?.dias||[]).filter(d=>d && parseInt(d.dia)<=25);
    const dias26_31=(prev?.dias||[]).filter(d=>d && parseInt(d.dia)>=26);
    nMovidos+=dias26_31.length;
    const novosDias=[...dias1_25, ...dias26_31];

    const reg=(State.payrolls||[]).find(p=>p.employeeId===employeeId&&p.mes==mes&&p.ano==ano);

    // Recalcula totais básicos sobre a competência (faltas só até hoje, pra não
    // inflar competências ainda em andamento). Salário/benefícios são apurados
    // ao abrir/fechar a folha.
    const diasTrab=novosDias.filter(d=>d.entrada&&d.saida).length;
    let faltas=0;
    if(emp){
      const fam=escalaFamilia(emp.escala||'5x2A'); const is12=fam==='12x36';
      for(const cd of _compDias(mes,ano)){
        const isoCd=`${cd.ano}-${zp(cd.mes)}-${zp(cd.dia)}`;
        if(isoCd>hojeISO) continue;
        const has=novosDias.find(x=>x.dia===cd.dia);
        if(has && has.entrada && has.saida) continue;
        const isWk=cd.diaSem===0||cd.diaSem===6;
        if(_diaEmBrancoEhFalta(emp,cd.mes,cd.ano,cd.dia,isWk,is12)) faltas++;
      }
    }
    const heMin=emp?_heMinFromDias(emp,mes,ano,novosDias):0;
    const base={ pontoManualDias:novosDias, diasTrabalhados:diasTrab,
      faltasInjustificadas:faltas, faltasJustificadas:(reg?.faltasJustificadas||0),
      horasExtrasTotal:(heMin>0?+(heMin/60).toFixed(2):0), updatedAt:new Date().toISOString() };
    const record = reg ? {...reg, ...base}
      : { id:_payrollId(employeeId,mes,ano), employeeId, mes, ano, status:'aberta', createdAt:new Date().toISOString(), ...base };
    try{
      await DB.save('payrolls', _sanitizeForFirestore(record));
      const ix=State.payrolls.findIndex(p=>p.id===record.id);
      if(ix>=0) State.payrolls[ix]=record; else State.payrolls.push(record);
      nFolhas++;
    }catch(e){ console.error('migração save', emp?.nome, e); }
  }

  try{ await DB.saveDoc('configuracoes', GKEY, {feitoEm:new Date().toISOString(), nFolhas, nMovidos, por:Auth.currentUser?.username||'master'}, true); }catch(e){ console.warn('marcar migração', e); }
  try{ Auth.log('MIGRACAO_COMPETENCIA', null, `${nFolhas} folha(s), ${nMovidos} dia(s) 26-31 movidos`); }catch(_){}
  toast(`Migração concluída: ${nFolhas} folha(s) recompostas, ${nMovidos} dia(s) (26-31) movidos para a competência seguinte.`, 'success');
  if(val('payroll-employee')) onPayrollEmployeeChange();
  try{ renderDashboard(); }catch(_){}
}

// ============================================
// ASAAS — PAGAMENTO DE COLABORADORES VIA PIX
// ============================================

// Utilitários de chamada ao Worker
async function _asaasReq(method, path, body) {
  const headers = { 'Content-Type': 'application/json' };
  // Manda o idToken do gestor logado — o asaas-worker passa a EXIGIR (não fica mais aberto). #asaas-auth
  try {
    const fu = firebase.auth().currentUser;
    if (fu) headers['Authorization'] = 'Bearer ' + (await fu.getIdToken());
  } catch (_) { /* sem sessão → worker recusa com 401 */ }
  const opts = { method, headers };
  if (body) opts.body = JSON.stringify(body);
  const r = await fetch(ASAAS_WORKER + path, opts);
  const data = await r.json().catch(() => ({}));
  if (!r.ok) {
    const msg = data.errors?.[0]?.description || data.description || data.error || r.statusText;
    throw new Error(msg);
  }
  return data;
}
const _asaasPost = (path, body) => _asaasReq('POST', path, body);

// Detecta tipo da chave PIX automaticamente
function detectPixKeyType(key) {
  if (!key) return 'CPF';
  const s = String(key);
  if (s.includes('@')) return 'EMAIL';
  const clean = s.replace(/\D/g, '');
  if (clean.length === 14) return 'CNPJ';
  if (clean.length === 10) return 'PHONE';
  if (clean.length === 11) {
    // 11 dígitos é ambíguo (CPF ou celular). Celular BR = DDD 11-99 com
    // '9' no 1º dígito do número. Casou esse padrão → telefone; senão CPF.
    const ddd = parseInt(clean.slice(0, 2), 10);
    return (ddd >= 11 && ddd <= 99 && clean[2] === '9') ? 'PHONE' : 'CPF';
  }
  return 'EVP';
}

// Formata a chave PIX no padrão que o Asaas espera, conforme o tipo:
// CPF/CNPJ → só dígitos; Celular → +55 + DDD + número; e-mail/aleatória → como está.
function _pixKeyParaAsaas(key, tipo){
  const k = String(key || '').trim();
  if (tipo === 'CPF' || tipo === 'CNPJ') return k.replace(/\D/g, '');
  if (tipo === 'PHONE') {
    if (k.startsWith('+')) return k.replace(/[^\d+]/g, '');
    const d = k.replace(/\D/g, '');
    return (d.length === 10 || d.length === 11) ? '+55' + d : k;
  }
  return k;
}

// Auto-sugere o tipo da chave PIX no cadastro quando ainda não foi escolhido.
function onEmpPixInput(){
  const sel = document.getElementById('emp-pix-tipo');
  if (sel && !sel.value) sel.value = detectPixKeyType(val('emp-pix'));
}

// Abre modal de pagamento para o colaborador atual
function openPagarColaborador() {
  const empId = val('payroll-employee');
  const emp   = State.employees.find(e => e.id === empId);
  if (!emp) { toast('Selecione um colaborador.', 'warning'); return; }

  const mes = parseInt(val('payroll-mes') || currentMes());
  const ano = parseInt(val('payroll-ano') || currentAno());
  const p   = State.payrolls.find(r => r.employeeId === empId && r.mes == mes && r.ano == ano);

  if (!p || p.status !== 'fechada') {
    toast('Feche a folha antes de efetuar o pagamento.', 'warning');
    return;
  }

  const liquido   = p.totalLiquidoFinal || p.totalLiquido || 0;
  const adiant    = p.adiantamento || 0;
  const restante  = Math.max(0, liquido - adiant);
  const pixKey    = emp.chavePix || '';

  // Preenche info
  setEl('asaas-pagar-nome',     emp.nome);
  setEl('asaas-pagar-pix',      pixKey || '(sem chave PIX cadastrada)');
  setEl('asaas-pagar-mes',      `${String(mes).padStart(2,'0')}/${ano}`);
  setEl('asaas-pagar-liquido',  fmtMoney(liquido));
  setEl('asaas-pagar-adiant',   fmtMoney(adiant));
  setEl('asaas-pagar-restante', fmtMoney(restante));

  setVal('asaas-pagar-empid',     empId);
  setVal('asaas-pagar-payrollid', p.id || '');

  // Opções de valor
  const sel = document.getElementById('asaas-pagar-tipo');
  sel.innerHTML = '';
  if (adiant > 0 && adiant !== liquido)
    sel.innerHTML += `<option value="${adiant}">Adiantamento: ${fmtMoney(adiant)}</option>`;
  if (restante > 0)
    sel.innerHTML += `<option value="${restante}" selected>Restante a pagar: ${fmtMoney(restante)}</option>`;
  if (liquido > 0)
    sel.innerHTML += `<option value="${liquido}">Total líquido: ${fmtMoney(liquido)}</option>`;
  sel.innerHTML += `<option value="custom">Outro valor...</option>`;
  onAsaasTipoChange();

  // Data: hoje
  setVal('asaas-pagar-data', new Date().toISOString().split('T')[0]);

  // Tipo de chave
  setVal('asaas-pagar-keytype', emp.chavePixTipo || detectPixKeyType(pixKey));

  // Reset resultado
  const resEl = document.getElementById('asaas-pagar-resultado');
  resEl.innerHTML = '';
  resEl.style.display = 'none';

  const btn = document.getElementById('btn-executar-pagamento');
  btn.style.display = 'inline-flex';
  btn.disabled = !pixKey;
  if (!pixKey) toast('Colaborador sem chave PIX — cadastre em Colaboradores → Benefícios.', 'warning');

  // Já existe solicitação pendente para esta folha?
  const solPend = (State.solicitacoes || []).find(s => s.payrollId === (p.id||'') && s.status === 'pendente');
  if (solPend) {
    btn.style.display = 'none';
    resEl.style.display = 'block';
    resEl.innerHTML = `<div style="background:#FFF8E1;border:1px solid #FFE082;border-radius:8px;padding:12px;font-size:12px;color:#6D4C41">
      <i class="fa-solid fa-hourglass-half"></i> <strong>Solicitação pendente:</strong>
      ${fmtMoney(solPend.valor)} aguardando aprovação em <strong>Aprovações de Pagamentos</strong>.
    </div>`;
    document.getElementById('modal-asaas-pagar').classList.remove('hidden');
    return;
  }

  // Mostrar pagamento anterior se houver
  if (p.pagamentoAsaas) {
    const pag = p.pagamentoAsaas;
    resEl.style.display = 'block';
    resEl.innerHTML = `<div style="background:#FFF8E1;border:1px solid #FFE082;border-radius:8px;padding:12px;font-size:12px;color:#6D4C41">
      <i class="fa-solid fa-circle-info"></i> <strong>Pagamento anterior registrado:</strong>
      ${fmtMoney(pag.asaasValor)} em ${(pag.asaasData||'').split('-').reverse().join('/')} — Status: ${pag.asaasStatus} — ID: ${pag.asaasTransferId}
    </div>`;
  }

  document.getElementById('modal-asaas-pagar').classList.remove('hidden');
}

function onAsaasTipoChange() {
  const sel = document.getElementById('asaas-pagar-tipo'); if (!sel) return;
  const row = document.getElementById('asaas-pagar-custom-row');
  if (row) row.style.display = sel.value === 'custom' ? 'block' : 'none';
}

// Cria uma solicitação de pagamento (status 'pendente'). Nada vai pro Asaas
// aqui — só ao ser aprovada na tela "Aprovações de Pagamentos" (com 2FA).
async function _criarSolicitacaoPagamento(d){
  const u = Auth.currentUser || {};
  // Quem NÃO pode aprovar (operador sem 'pagamentosAprovar' e não-Master) só
  // LANÇA: a solicitação nasce marcada como "pedido de autorização ao Master".
  // O Master decide os 2 portões (inclusão + pagamento) na tela de Aprovações.
  // #autorizacao-master
  const _podeAprovar = !!(getUserModules(u).pagamentosAprovar) || u.role==='master';
  const sol = {
    id:            genId(),
    employeeId:    d.employeeId || '',
    employeeNome:  d.employeeNome || '',
    payrollId:     d.payrollId || '',
    valor:         d.valor || 0,
    pixKey:        d.pixKey || '',
    keyType:       d.keyType || 'CPF',
    descricao:     d.descricao || '',
    scheduleDate:  d.scheduleDate || '',
    competencia:   d.competencia || '',
    origem:        d.origem || 'avulso',
    status:        'pendente',
    criadoPor:     u.username || u.id || '',
    criadoPorNome: u.username || '',
    criadoEm:      new Date().toISOString(),
    aprovadoPor:'', aprovadoPorNome:'', aprovadoEm:'',
    asaasTransferId:'', asaasStatus:'', motivoRecusa:'', erro:'',
    // Fluxo de autorização do Master (só quando o criador não pode aprovar):
    autorizacaoSolicitada: !_podeAprovar,
    solicitadaPorNome:     _podeAprovar ? '' : (u.username || ''),
    solicitadaEm:          _podeAprovar ? '' : new Date().toISOString(),
    inclusaoAutorizada:    false, inclusaoAutorizadaPorNome:'', inclusaoAutorizadaEm:'',
  };
  await DB.save('solicitacoesPagamento', sol);
  if(!_podeAprovar) _agendarNotifMaster(1, sol.valor||0);   // avisa o Master (push+e-mail), agrupado
  return sol;
}

// Aviso ao Master de pedidos de autorização — agrupa vários (lote) em UM único
// disparo para não floodar push/e-mail. O card no sistema é a garantia; o
// push/e-mail é o reforço (não-crítico, falha em silêncio). #autorizacao-master
let _notifMasterTimer=null, _notifMasterAcc={count:0,total:0};
function _agendarNotifMaster(count, total){
  _notifMasterAcc.count += count; _notifMasterAcc.total += (+total||0);
  if(_notifMasterTimer) clearTimeout(_notifMasterTimer);
  _notifMasterTimer=setTimeout(()=>{
    const payload={...(_notifMasterAcc)};
    _notifMasterAcc={count:0,total:0}; _notifMasterTimer=null;
    _notificarMasterAutorizacao(payload.count, payload.total);
    try{ toast(`Pedido de autorização enviado ao Master (${payload.count} pagamento${payload.count>1?'s':''}). Ele decide a inclusão e o pagamento.`,'success'); }catch(_){}
  }, 1500);
}
async function _notificarMasterAutorizacao(count, total){
  try{
    await fetch('https://drg-monitor.zett-romao.workers.dev/notificar-autorizacao', {
      method:'POST', headers:{'Content-Type':'application/json'},
      body: JSON.stringify({
        porNome: Auth.currentUser?.username || '',
        count, total,
        tenantId: (window.DB && DB.tenantId) || ''
      })
    });
  }catch(_){ /* aviso é reforço; o card no sistema sempre aparece */ }
}

// ============================================
// PAGAMENTO AVULSO — prêmios, obrigações fora do hall legal e valores
// de rescisões feitas fora do sistema. Gera uma solicitação PIX que vai
// para Aprovações (com 2FA), origem 'avulso'. NÃO entra no cálculo da
// folha CLT — é um pagamento à parte.
// ============================================
function openPagamentoAvulsoModal(empId){
  if(!getUserModules(Auth.currentUser).pagamentosLancar){
    toast('Você não tem permissão para lançar pagamentos.','error'); return;
  }
  const m=document.getElementById('modal-pagamento-avulso'); if(!m) return;
  const sel=document.getElementById('pag-avulso-emp');
  if(sel){
    const emps=[...(State.employees||[])].sort((a,b)=>(a.nome||'').localeCompare(b.nome||'','pt-BR'));
    sel.innerHTML='<option value="">— selecione —</option>'+emps.map(e=>{
      const st=(e.status||'ativo')!=='ativo'?` (${e.status})`:'';
      return `<option value="${e.id}">${(e.nome||'—')}${st}</option>`;
    }).join('');
    sel.value=empId||'';
  }
  setVal('pag-avulso-desc','');
  setVal('pag-avulso-valor','');
  setVal('pag-avulso-data', new Date().toISOString().substring(0,10));
  onPagAvulsoEmpChange();
  m.classList.remove('hidden');
}

function onPagAvulsoEmpChange(){
  const emp=State.employees.find(e=>e.id===val('pag-avulso-emp'));
  setVal('pag-avulso-pix', emp?.chavePix||'');
  setVal('pag-avulso-pix-tipo', (emp&&emp.chavePixTipo) || detectPixKeyType(emp?.chavePix||''));
}

async function confirmarPagamentoAvulso(){
  if(!getUserModules(Auth.currentUser).pagamentosLancar){
    toast('Você não tem permissão para lançar pagamentos.','error'); return;
  }
  const emp=State.employees.find(e=>e.id===val('pag-avulso-emp'));
  if(!emp){ toast('Selecione um colaborador.','error'); return; }
  const desc=(val('pag-avulso-desc')||'').trim();
  if(!desc){ toast('Informe a descrição do pagamento (ex.: Prêmio, Saldo de rescisão).','error'); return; }
  const valor=numVal('pag-avulso-valor');
  if(!(valor>0)){ toast('Informe um valor válido.','error'); return; }
  const pixKey=(val('pag-avulso-pix')||'').trim();
  if(!pixKey){ toast('Chave PIX não informada — cadastre no colaborador ou digite aqui.','error'); return; }
  const pixTipo=val('pag-avulso-pix-tipo')||detectPixKeyType(pixKey);
  const data=val('pag-avulso-data')||new Date().toISOString().substring(0,10);
  const btn=document.getElementById('pag-avulso-confirm');
  if(btn) setBtnLoading(btn,true,'');
  try{
    const sol=await _criarSolicitacaoPagamento({
      employeeId:emp.id, employeeNome:emp.nome, payrollId:'',
      valor, pixKey:_pixKeyParaAsaas(pixKey,pixTipo), keyType:pixTipo,
      descricao:`Avulso — ${desc}`,
      scheduleDate:data, origem:'avulso',
    });
    Auth.log('PAGAMENTO_SOLICITADO', null, `Avulso | ${emp.nome} | R$ ${valor.toFixed(2)} | ${desc} | sol ${sol.id}`);
    toast('Pagamento avulso enviado para Aprovações — precisa ser aprovado com 2FA.','success');
    closeModal('modal-pagamento-avulso');
  }catch(e){
    console.error(e);
    toast('Erro ao criar a solicitação: '+(e.message||e),'error');
  }finally{
    if(btn) setBtnLoading(btn,false,'<i class="fa-solid fa-paper-plane"></i> Enviar para aprovação');
  }
}

async function executarPagamentoAsaas() {
  if (!getUserModules(Auth.currentUser).pagamentosLancar) {
    toast('Você não tem permissão para lançar pagamentos.', 'error'); return;
  }
  const empId     = val('asaas-pagar-empid');
  const payrollId = val('asaas-pagar-payrollid');
  const emp       = State.employees.find(e => e.id === empId);
  if (!emp) return;

  const sel   = document.getElementById('asaas-pagar-tipo');
  const valor = sel.value === 'custom'
    ? parseFloat((document.getElementById('asaas-pagar-custom')?.value || '0').replace(',', '.')) || 0
    : parseFloat(sel.value) || 0;

  if (valor <= 0) { toast('Valor inválido.', 'warning'); return; }

  if (payrollId && (State.solicitacoes || []).some(s => s.payrollId === payrollId && s.status === 'pendente')) {
    toast('Já existe uma solicitação pendente para esta folha.', 'warning'); return;
  }

  const keyType = emp.chavePixTipo || val('asaas-pagar-keytype') || detectPixKeyType(emp.chavePix||'');
  const pixKey  = _pixKeyParaAsaas(emp.chavePix || '', keyType);
  const data    = val('asaas-pagar-data') || new Date().toISOString().split('T')[0];
  const mes     = document.getElementById('asaas-pagar-mes')?.textContent || '';

  const btn = document.getElementById('btn-executar-pagamento');
  btn.disabled = true;
  btn.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> Lançando...';

  const resEl = document.getElementById('asaas-pagar-resultado');
  resEl.style.display = 'none';

  try {
    const sol = await _criarSolicitacaoPagamento({
      employeeId: empId, employeeNome: emp.nome, payrollId,
      valor, pixKey, keyType,
      descricao: `Salário ${mes} — ${emp.nome}`,
      scheduleDate: data, competencia: mes, origem: 'folha',
    });
    Auth.log('PAGAMENTO_SOLICITADO', null,
      `${emp.nome} | R$ ${valor.toFixed(2)} | PIX ${pixKey} | ${data} | sol ${sol.id}`);

    resEl.style.display = 'block';
    resEl.innerHTML = `
      <div style="background:#FFF8E1;border:1px solid #FFE082;border-radius:9px;padding:16px;font-size:13px;color:#6D4C41">
        <div style="font-weight:700;color:#E65100;margin-bottom:8px">
          <i class="fa-solid fa-hourglass-half"></i> Solicitação de pagamento criada!
        </div>
        <div style="margin-bottom:4px"><strong>Valor:</strong> ${fmtMoney(valor)} → <i class="fa-brands fa-pix" style="color:#00695C"></i> ${pixKey}</div>
        <div style="margin-top:6px">A transferência só será disparada após <strong>aprovação</strong> na tela <strong>Aprovações de Pagamentos</strong> (exige o código 2FA do aprovador).</div>
      </div>`;

    btn.style.display = 'none';
    toast('Solicitação criada — aguardando aprovação.', 'success');

  } catch(e) {
    resEl.style.display = 'block';
    resEl.innerHTML = `<div style="background:#fce4e4;border:1px solid #ef9a9a;border-radius:9px;padding:14px;font-size:13px;color:#c62828">
      <i class="fa-solid fa-triangle-exclamation"></i> <strong>Erro:</strong> ${e.message}
    </div>`;
    btn.disabled = false;
    btn.innerHTML = '<i class="fa-solid fa-paper-plane"></i> Tentar Novamente';
  }
}

// Helper para setar textContent com segurança
function setEl(id, txt) {
  const el = document.getElementById(id); if (el) el.textContent = txt;
}

// ============================================
// ASAAS — PAGAMENTO EM LOTE
// ============================================

// Dados do lote (preenchidos ao abrir o modal)
let _loteData = []; // [{emp, payroll, valor, pixKey, keyType, selecionado}]

function openPagarEmLote() {
  const mes = parseInt(val('pag-mes') || currentMes());
  const ano = parseInt(val('pag-ano') || currentAno());

  // Coleta colaboradores com folha FECHADA no período
  const emps = State.employees.filter(e => (e.status || 'ativo') === 'ativo');
  _loteData = [];

  emps.forEach(emp => {
    const p = State.payrolls.find(r => r.employeeId === emp.id && r.mes == mes && r.ano == ano);
    if (!p || p.status !== 'fechada') return; // só folhas fechadas

    const liquido  = p.totalLiquidoFinal || p.totalLiquido || 0;
    const adiant   = p.adiantamento || 0;
    const restante = Math.max(0, liquido - adiant);
    const pixKey   = emp.chavePix || '';
    const jaPago   = !!(p.pagamentoAsaas);
    const jaSolicitado = (State.solicitacoes || []).some(s => s.payrollId === p.id && s.status === 'pendente');

    _loteData.push({
      empId:    emp.id,
      nome:     emp.nome,
      registro: emp.registro,
      payrollId:p.id,
      liquido, adiant, restante,
      pixKey,
      keyType:  detectPixKeyType(pixKey),
      semPix:   !pixKey,
      jaPago,
      jaSolicitado,
      status:   jaPago ? 'pago' : (jaSolicitado ? 'solicitado' : (!pixKey ? 'sem-pix' : 'pendente')),
      selecionado: !jaPago && !jaSolicitado && !!pixKey, // pré-seleciona só os elegíveis
    });
  });

  if (_loteData.length === 0) {
    toast('Nenhuma folha fechada encontrada para este período. Feche as folhas antes de pagar.', 'warning');
    return;
  }

  // Data padrão: hoje
  setVal('lote-data', new Date().toISOString().split('T')[0]);
  setVal('lote-tipo-valor', 'restante');

  // Reset progresso
  document.getElementById('lote-progresso').style.display = 'none';
  document.getElementById('lote-progress-log').innerHTML  = '';
  document.getElementById('lote-progress-bar').style.width = '0%';

  const btn = document.getElementById('btn-executar-lote');
  btn.disabled = false;
  btn.onclick  = executarPagamentoLote;
  btn.innerHTML = '<i class="fa-solid fa-paper-plane"></i> Lançar Solicitações Selecionadas';

  refreshLoteTabela();
  document.getElementById('modal-pagar-lote').classList.remove('hidden');
}

function _loteValorPara(item) {
  const tipo = val('lote-tipo-valor') || 'restante';
  if (tipo === 'liquido')      return item.liquido;
  if (tipo === 'adiantamento') return item.adiant;
  return item.restante; // restante (padrão)
}

function refreshLoteTabela() {
  const tbody = document.getElementById('lote-tbody');
  if (!tbody) return;

  let totalSel = 0, totalVal = 0, semPix = 0, jaPagos = 0;

  tbody.innerHTML = _loteData.map((item, idx) => {
    const valor  = _loteValorPara(item);
    const rowBg  = idx % 2 === 0 ? '#fff' : '#f9fafb';
    const disabled = item.semPix || item.jaPago || item.jaSolicitado;

    if (item.jaPago) { jaPagos++; }
    else if (item.semPix) { semPix++; }
    else if (item.selecionado) { totalSel++; totalVal += valor; }

    // Badge de status
    let statusBadge;
    if (item.jaPago) {
      statusBadge = `<span style="background:#E0F2F1;color:#00695C;padding:2px 8px;border-radius:10px;font-size:11px;font-weight:600">✓ Pago</span>`;
    } else if (item.jaSolicitado) {
      statusBadge = `<span style="background:#FFF8E1;color:#E65100;padding:2px 8px;border-radius:10px;font-size:11px;font-weight:600">Solicitado</span>`;
    } else if (item.semPix) {
      statusBadge = `<span style="background:#FFF3E0;color:#E65100;padding:2px 8px;border-radius:10px;font-size:11px;font-weight:600">Sem PIX</span>`;
    } else {
      statusBadge = `<span style="background:#E8F5E9;color:#2e7d32;padding:2px 8px;border-radius:10px;font-size:11px;font-weight:600">Pendente</span>`;
    }

    const matr = item.registro ? String(item.registro).padStart(4,'0') : '—';
    const pixDisplay = item.pixKey
      ? `<span style="font-family:monospace;font-size:11px;color:#00695C">${item.pixKey}</span>`
      : `<span style="color:#bbb;font-size:11px">—</span>`;

    return `<tr style="background:${rowBg};opacity:${disabled ? .55 : 1}">
      <td style="padding:8px 12px;text-align:center">
        <input type="checkbox" data-idx="${idx}" ${item.selecionado ? 'checked' : ''} ${disabled ? 'disabled' : ''}
          onchange="_loteData[${idx}].selecionado=this.checked; refreshLoteResumo()">
      </td>
      <td style="padding:8px 12px"><strong>${item.nome}</strong> <span style="font-size:11px;color:#aaa">${matr}</span></td>
      <td style="padding:8px 12px;text-align:right">${fmtMoney(item.liquido)}</td>
      <td style="padding:8px 12px;text-align:right;color:#e65100">${item.adiant > 0 ? fmtMoney(item.adiant) : '—'}</td>
      <td style="padding:8px 12px;text-align:right;font-weight:700;color:#00695C">${valor > 0 ? fmtMoney(valor) : '<span style="color:#ccc">—</span>'}</td>
      <td style="padding:8px 12px">${pixDisplay}</td>
      <td style="padding:8px 12px;text-align:center">${statusBadge}</td>
    </tr>`;
  }).join('');

  refreshLoteResumo();
}

function refreshLoteResumo() {
  let totalSel = 0, totalVal = 0;
  _loteData.forEach(item => {
    if (item.selecionado && !item.semPix && !item.jaPago) {
      totalSel++;
      totalVal += _loteValorPara(item);
    }
  });

  const semPix  = _loteData.filter(i => i.semPix).length;
  const jaPagos = _loteData.filter(i => i.jaPago).length;

  document.getElementById('lote-counter').textContent =
    `${totalSel} selecionado(s) · Total: ${fmtMoney(totalVal)}`;

  let resumoHtml = `<strong>${totalSel}</strong> colaborador(es) selecionados · Total a pagar: <strong style="color:#00695C">${fmtMoney(totalVal)}</strong>`;
  if (semPix  > 0) resumoHtml += ` &nbsp;|&nbsp; <span style="color:#e65100">${semPix} sem chave PIX (não serão pagos)</span>`;
  if (jaPagos > 0) resumoHtml += ` &nbsp;|&nbsp; <span style="color:#00695C">${jaPagos} já pagos</span>`;
  document.getElementById('lote-resumo').innerHTML = resumoHtml;

  // Atualiza checkbox geral
  const elegíveis = _loteData.filter(i => !i.semPix && !i.jaPago && !i.jaSolicitado);
  const chkAll = document.getElementById('lote-chk-all');
  if (chkAll) {
    chkAll.checked       = elegíveis.length > 0 && elegíveis.every(i => i.selecionado);
    chkAll.indeterminate = elegíveis.some(i => i.selecionado) && !chkAll.checked;
  }
}

function loteSelectAll(checked) {
  _loteData.forEach(item => {
    if (!item.semPix && !item.jaPago && !item.jaSolicitado) item.selecionado = checked;
  });
  const chkAll = document.getElementById('lote-chk-all');
  if (chkAll) chkAll.checked = checked;
  refreshLoteTabela();
}

function _loteLog(msg, cor = '#81d4fa') {
  const el = document.getElementById('lote-progress-log'); if (!el) return;
  const ts = new Date().toLocaleTimeString('pt-BR');
  el.innerHTML += `<span style="color:#aaa">[${ts}]</span> <span style="color:${cor}">${msg}</span>\n`;
  el.scrollTop = el.scrollHeight;
}

async function executarPagamentoLote() {
  if (!getUserModules(Auth.currentUser).pagamentosLancar) {
    toast('Você não tem permissão para lançar pagamentos.', 'error'); return;
  }
  const selecionados = _loteData.filter(i => i.selecionado && !i.semPix && !i.jaPago && !i.jaSolicitado);

  if (selecionados.length === 0) {
    toast('Nenhum colaborador selecionado para pagamento.', 'warning');
    return;
  }

  const data      = val('lote-data') || new Date().toISOString().split('T')[0];
  const dataLabel = data.split('-').reverse().join('/');
  const mes = parseInt(val('pag-mes') || currentMes());
  const ano = parseInt(val('pag-ano') || currentAno());
  const mesLabel = `${String(mes).padStart(2,'0')}/${ano}`;
  const totalSel = selecionados.reduce((s,i) => s + _loteValorPara(i), 0);

  if (!confirm(`Lançar ${selecionados.length} solicitação(ões) de pagamento PIX (data ${dataLabel})?\n`
      + `Total: ${fmtMoney(totalSel)}\n\n`
      + `Nada será transferido agora — as solicitações vão para a tela "Aprovações de Pagamentos".`)) return;

  // UI: início
  const btn = document.getElementById('btn-executar-lote');
  btn.disabled = true;
  btn.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> Lançando...';
  document.getElementById('lote-progresso').style.display = 'block';
  document.getElementById('lote-progress-log').innerHTML  = '';
  document.getElementById('lote-progress-bar').style.width = '0%';

  _loteLog(`Criando ${selecionados.length} solicitação(ões) de pagamento...`, '#fff176');

  let ok = 0, erros = 0;

  for (let i = 0; i < selecionados.length; i++) {
    const item  = selecionados[i];
    const valor = _loteValorPara(item);

    if (valor <= 0) {
      _loteLog(`⚠ ${item.nome}: valor zero — pulado`, '#ffcc02');
      continue;
    }
    if ((State.solicitacoes || []).some(s => s.payrollId === item.payrollId && s.status === 'pendente')) {
      _loteLog(`⚠ ${item.nome}: já tem solicitação pendente — pulado`, '#ffcc02');
      continue;
    }

    try {
      const sol = await _criarSolicitacaoPagamento({
        employeeId: item.empId, employeeNome: item.nome, payrollId: item.payrollId,
        valor, pixKey: item.pixKey, keyType: item.keyType,
        descricao: `Salário ${mesLabel} — ${item.nome}`,
        scheduleDate: data, competencia: mesLabel, origem: 'lote',
      });
      item.jaSolicitado = true;
      item.selecionado  = false;

      ok++;
      _loteLog(`✓ ${item.nome}: ${fmtMoney(valor)} solicitado (sol ${sol.id})`, '#a5d6a7');
      Auth.log('PAGAMENTO_SOLICITADO', null,
        `${item.nome} | R$ ${valor.toFixed(2)} | PIX ${item.pixKey} | ${data} | sol ${sol.id}`);

    } catch(e) {
      erros++;
      _loteLog(`✗ ${item.nome}: ERRO — ${e.message}`, '#ef9a9a');
    }

    document.getElementById('lote-progress-bar').style.width =
      `${Math.round(((i + 1) / selecionados.length) * 100)}%`;
  }

  // Resultado final
  const corFinal = erros === 0 ? '#fff176' : '#ffcc02';
  _loteLog(`\nConcluído: ${ok} solicitação(ões) criada(s)${erros > 0 ? `, ${erros} com erro` : '.'}`, corFinal);

  btn.disabled = false;
  if (erros === 0) {
    btn.innerHTML = '<i class="fa-solid fa-check"></i> Concluído';
    btn.onclick = () => closeModal('modal-pagar-lote');
    toast(`${ok} solicitação(ões) criada(s) — aguardando aprovação.`, 'success');
  } else {
    btn.innerHTML = '<i class="fa-solid fa-paper-plane"></i> Tentar Novamente (com erros)';
    btn.onclick = executarPagamentoLote;
    toast(`${ok} criadas, ${erros} com erro. Verifique o log.`, 'warning');
  }

  // Atualiza tabela para refletir os solicitados
  refreshLoteTabela();
}

// ============================================
// APROVAÇÕES DE PAGAMENTOS (Etapa 4d)
// ============================================
function _aprovacaoStatusBadge(st){
  const map={
    pendente:  ['#FFF3E0','#E65100','Pendente'],
    pago:      ['#E8F5E9','#2e7d32','Pago'],
    recusado:  ['#FCE4EC','#c62828','Recusado'],
    erro:      ['#fce4e4','#c62828','Erro'],
    estornado: ['#FFF3E0','#E65100','Estornado'],
  };
  const m=map[st]||['#eee','#777',st||'—'];
  return `<span style="background:${m[0]};color:${m[1]};padding:2px 9px;border-radius:10px;font-size:11px;font-weight:600">${m[2]}</span>`;
}

// ============================================
// ADIANTAMENTOS — lista e pagamento (reaproveita o fluxo de Aprovações)
// ============================================
function _adiantMesAno(){
  const mes=parseInt(val('adiant-mes'))||(new Date().getMonth()+1);
  const ano=parseInt(val('adiant-ano'))||(new Date().getFullYear());
  return {mes,ano,comp:String(mes).padStart(2,'0')+'/'+ano};
}

// Adiantamento ATIVO numa folha: a folha já marcada OU o colaborador é OPTANTE
// (recebeAdiantamento no cadastro) e está ativo — assim o optante aparece TODO mês,
// mesmo que a folha tenha sido salva antes de marcar. #adiant-optante
// Prazo mínimo de casa p/ adiantamento (Config: empresa.adiantamentoMinDiasAdmissao). Conta
// da DATA DE ADMISSÃO até o adiantamento da competência (dia-limite do mês). Quem não cumpriu
// — e NÃO está ISENTO no contrato (emp.adiantamentoIsentoPrazo) — não é elegível. Sem regra
// (0/ausente), sem admissão cadastrada ou data inválida → não barra. #adiant-prazo-admissao
function _adiantElegivelPrazo(emp, p){
  const min = parseInt(State.empresa?.adiantamentoMinDiasAdmissao);
  if(!(min>0)) return true;                       // sem regra configurada
  if(!emp) return true;
  if(emp.adiantamentoIsentoPrazo) return true;    // válvula individual (checkbox no contrato)
  if(!emp.dataAdmissao) return true;              // sem admissão → não barra (evita bloqueio indevido)
  const adm = new Date((emp.dataAdmissao+'').slice(0,10)+'T00:00:00');
  if(isNaN(adm.getTime())) return true;
  const diaLimite = Math.min(28, Math.max(1, parseInt(State.empresa?.diaLimiteAdiantamento)||15));
  const ref = (p && p.mes && p.ano) ? new Date(p.ano, p.mes-1, diaLimite) : new Date();
  const dias = Math.floor((ref - adm)/86400000);
  return dias >= min;
}
function _adiantAtivoDe(emp, p){
  // Folha já marcada explicitamente continua valendo (regra "só novos lançamentos" — não
  // desfaz o que foi lançado quando o prazo muda). Optante só entra se cumpriu o prazo. #adiant-prazo-admissao
  if(p && p.adiantamentoAtivo) return true;
  return !!(emp && emp.recebeAdiantamento && (emp.status||'ativo')==='ativo' && _adiantElegivelPrazo(emp, p));
}
// Valor do adiantamento: o salvo na folha; senão, p/ optante, deriva do salário (% padrão 40).
function _adiantValorDe(emp, p){
  if(p && (p.adiantamentoValor||0)>0) return p.adiantamentoValor;
  if(emp && emp.recebeAdiantamento){
    const perc=parseInt((p&&p.adiantamentoPerc) || emp.adiantamentoPerc || 40)||40;
    return +(((emp.salarioBase||0)*(perc/100))).toFixed(2);
  }
  return 0;
}

function renderAdiantamentos(){
  const tbody=document.getElementById('adiant-tbody'); if(!tbody) return;
  const selAno=document.getElementById('adiant-ano');
  if(selAno && !selAno.options.length){
    const ya=new Date().getFullYear();
    for(let y=ya-1;y<=ya+1;y++){
      const o=document.createElement('option'); o.value=y; o.textContent=y;
      if(y===ya) o.selected=true;
      selAno.appendChild(o);
    }
  }
  const selMes=document.getElementById('adiant-mes');
  // <select> sempre tem .value (a primeira opção, "1" = Janeiro), então o
  // !selMes.value antigo nunca era verdadeiro e nunca corrigia para o mês
  // atual. Usa um flag de inicialização: na 1ª render aplica o mês atual,
  // depois respeita a escolha do operador.
  if(selMes && !selMes.dataset.inicializado){
    selMes.value=new Date().getMonth()+1;
    selMes.dataset.inicializado='1';
  }
  const {mes,ano,comp}=_adiantMesAno();
  // O seletor "Agendar para:" não aceita datas passadas (bloqueia no calendário). #adiant-agendar
  const _sd=document.getElementById('adiant-schedule-date'); if(_sd) _sd.min=_hojeISO();

  // Vencimento: dia limite configurado em Configurações da Empresa (default 15).
  // Passou do dia E nada foi pago (nem PIX via sistema nem registro "pago fora")
  // ⇒ status "VENCIDO". Útil para o gestor não esquecer adiantamentos atrasados.
  const diaLimite=Math.min(28,Math.max(1,parseInt(State.empresa?.diaLimiteAdiantamento)||15));
  const cutoff=new Date(ano,mes-1,diaLimite,23,59,59,999);
  const passouDoDia=new Date()>cutoff;

  const lista=(State.payrolls||[])
    .filter(p=>p.mes==mes && p.ano==ano)
    .map(p=>{
      const emp=State.employees.find(e=>e.id===p.employeeId)||{};
      if(!_adiantAtivoDe(emp,p)) return null;          // folha marcada OU optante ativo
      const valor=_adiantValorDe(emp,p);
      if(!(valor>0)) return null;
      const sol=(State.solicitacoes||[]).find(s=>s.origem==='adiantamento' && s.employeeId===p.employeeId
        && s.competencia===comp && (s.status==='pendente'||s.status==='pago'));
      const pagoExterno=p.adiantamentoPagoExterno||null;
      const naoPago=!sol && !pagoExterno;
      return {emp, valor, sol, pagoExterno, vencido:naoPago && passouDoDia};
    })
    .filter(x=>x && x.emp.id)
    .sort((a,b)=>(a.emp.nome||'').localeCompare(b.emp.nome||''));

  const cnt=document.getElementById('adiant-contador');
  if(cnt){
    const total=lista.reduce((s,x)=>s+x.valor,0);
    const aPagar  =lista.filter(x=>!x.sol && !x.pagoExterno && !x.vencido).length;
    const vencidos=lista.filter(x=>x.vencido).length;
    const pagosExt=lista.filter(x=>x.pagoExterno).length;
    const partes=[];
    if(aPagar>0)   partes.push(`<strong style="color:#1565C0">${aPagar}</strong> a pagar`);
    if(vencidos>0) partes.push(`<strong style="color:#c62828">${vencidos}</strong> vencido(s)`);
    if(pagosExt>0) partes.push(`<strong style="color:#00695C">${pagosExt}</strong> pago(s) fora`);
    cnt.innerHTML=lista.length
      ? `<strong>${lista.length}</strong> adiantamento(s) em ${comp} &middot; Total ${fmtMoney(total)}${partes.length?' &middot; '+partes.join(' &middot; '):''}`
      : `<span style="color:#999">Nenhum adiantamento lançado em ${comp}</span>`;
  }

  // Diagnóstico — colaboradores marcados como "Recebe adiantamento" no
  // cadastro mas que NÃO aparecem aqui (folha não lançada OU folha lançada
  // sem adiantamento ativo). Sem nenhum marcado, mostra uma dica leve.
  const _empsAtivos=(State.employees||[]).filter(e=>(e.status||'ativo')==='ativo');
  const _marcados=_empsAtivos.filter(e=>e.recebeAdiantamento);
  const _semFolha=[], _semAdiantNaFolha=[], _semValor=[];
  _marcados.forEach(e=>{
    const p=(State.payrolls||[]).find(pp=>pp.employeeId===e.id&&pp.mes==mes&&pp.ano==ano);
    if(!p) _semFolha.push(e);   // sem folha → não dá p/ derivar aqui; com folha já aparecem na lista (optante). #adiant-optante
  });
  const _diagEl=document.getElementById('adiant-diagnostico');
  if(_diagEl){
    if(!_marcados.length){
      _diagEl.innerHTML=`<div style="font-size:12px;color:#64748b;padding:8px 12px;background:#F8FAFC;border:1px dashed #CBD5E1;border-radius:8px">
        <i class="fa-solid fa-circle-info"></i> Para um colaborador aparecer aqui, abra a Folha de Ponto do mês, marque <strong>"Aderiu ao adiantamento? Sim"</strong> e salve.
        <br><span style="color:#94A3B8">Dica: marque <strong>"Recebe adiantamento quinzenal"</strong> no cadastro do colaborador para que a folha já venha marcada automaticamente.</span>
      </div>`;
    } else if(!_semFolha.length && !_semAdiantNaFolha.length && !_semValor.length){
      _diagEl.innerHTML='';
    } else {
      const _li=e=>`<li style="margin:3px 0"><a onclick="_abrirFolhaColaborador('${e.id}')" style="color:#1565C0;cursor:pointer;text-decoration:underline">${e.nome||'—'}</a></li>`;
      const _parts=[];
      if(_semFolha.length) _parts.push(`<div style="margin-top:6px"><strong style="color:#E65100"><i class="fa-solid fa-triangle-exclamation"></i> ${_semFolha.length} colaborador(es) marcado(s) ainda sem folha de ${comp}:</strong><ul style="margin:4px 0 0 22px;padding:0">${_semFolha.map(_li).join('')}</ul></div>`);
      if(_semAdiantNaFolha.length) _parts.push(`<div style="margin-top:8px"><strong style="color:#E65100"><i class="fa-solid fa-triangle-exclamation"></i> ${_semAdiantNaFolha.length} folha(s) de ${comp} lançada(s) sem adiantamento ativo:</strong><ul style="margin:4px 0 0 22px;padding:0">${_semAdiantNaFolha.map(_li).join('')}</ul></div>`);
      if(_semValor.length){
        const _liRecalc=e=>`<li style="margin:4px 0;display:flex;align-items:center;gap:8px;flex-wrap:wrap"><a onclick="_abrirFolhaColaborador('${e.id}')" style="color:#1565C0;cursor:pointer;text-decoration:underline">${e.nome||'—'}</a><button onclick="_recalcAdiantamento('${e.id}',${mes},${ano})" title="Atualiza o valor do adiantamento direto, sem abrir a folha" style="background:#00695C;color:#fff;border:none;border-radius:6px;padding:3px 10px;font-size:11px;font-weight:700;cursor:pointer"><i class="fa-solid fa-rotate"></i> Recalcular agora</button></li>`;
        _parts.push(`<div style="margin-top:8px"><strong style="color:#E65100"><i class="fa-solid fa-triangle-exclamation"></i> ${_semValor.length} folha(s) de ${comp} com adiantamento ativo mas valor ZERADO (salva antes da regra atual):</strong><ul style="margin:4px 0 0 22px;padding:0">${_semValor.map(_liRecalc).join('')}</ul><div style="margin-top:6px;font-size:11px;color:#7C5500">Clique em <strong>"Recalcular agora"</strong> para corrigir num clique. Ou clique no nome para abrir a folha e revisar (o valor já vem certo na tela — basta rolar até o final e clicar em <strong>"Salvar Folha"</strong>).</div></div>`);
      }
      _diagEl.innerHTML=`<div style="padding:10px 14px;background:#FFF3E0;border:1px solid #FFB74D;border-radius:8px;font-size:13px">
        <div><strong>Faltando alguém aqui?</strong> Estes colaboradores estão marcados como "Recebe adiantamento quinzenal" no cadastro, mas não aparecem na lista:</div>
        ${_parts.join('')}
        <div style="margin-top:8px;font-size:11px;color:#7C5500">Clique no nome para abrir a Folha de Ponto.</div>
      </div>`;
    }
  }

  if(!lista.length){
    tbody.innerHTML=`<tr><td colspan="6" style="padding:26px;text-align:center;color:#999">Nenhum colaborador com adiantamento lançado em ${comp}.</td></tr>`;
    return;
  }
  tbody.innerHTML=lista.map((x,idx)=>{
    let bg=idx%2?'#f9fafb':'#fff';
    let statusHtml, acao, podeSelec=false;
    const _btnPagar=`<button class="btn btn-sm" style="background:#00695C;color:#fff;border-color:#00695C;font-size:11px;padding:4px 9px" onclick="event.stopPropagation();pagarAdiantamento('${x.emp.id}')"><i class="fa-brands fa-pix"></i> Pagar</button>`;
    const _btnPagoFora=`<button class="btn btn-sm" style="background:#fff;color:#00695C;border:1px solid #00695C;font-size:11px;padding:4px 9px" onclick="event.stopPropagation();openPagoExternoModal('${x.emp.id}',${mes},${ano})" title="Marca como pago fora do sistema (você pagou via app do banco, em espécie etc.)"><i class="fa-solid fa-circle-check"></i> Pago fora</button>`;

    if(x.pagoExterno){
      const _dt=formatDateBr(x.pagoExterno.data)||'—';
      const _obs=(x.pagoExterno.obs||'').replace(/"/g,'&quot;');
      statusHtml=`<span style="background:#E0F2F1;color:#00695C;padding:3px 9px;border-radius:10px;font-size:11px;font-weight:700" title="Pago fora do sistema em ${_dt}${_obs?' — '+_obs:''}"><i class="fa-solid fa-circle-check"></i> Pago fora</span>`;
      acao=`<button class="btn btn-sm" style="background:#fff;color:#c62828;border:1px solid #c62828;font-size:11px;padding:4px 9px" onclick="event.stopPropagation();desfazerPagoExterno('${x.emp.id}',${mes},${ano})" title="Desfaz a marcação de pago externo"><i class="fa-solid fa-rotate-left"></i> Desfazer</button>`;
    } else if(x.sol?.status==='pendente'){
      statusHtml='<span style="background:#FFF3E0;color:#E65100;padding:3px 9px;border-radius:10px;font-size:11px;font-weight:700">Solicitado</span>';
      acao='<span style="font-size:11px;color:#999">aguardando aprovação</span>';
    } else if(x.sol?.status==='pago'){
      statusHtml='<span style="background:#E8F5E9;color:#2e7d32;padding:3px 9px;border-radius:10px;font-size:11px;font-weight:700">Pago</span>';
      acao=`<span style="font-size:11px;color:#00695C">ID ${x.sol.asaasTransferId||'—'}</span>`;
    } else if(x.vencido){
      bg='#FFEBEE'; // fundo vermelho claro para destacar
      statusHtml='<span style="background:#fff;color:#c62828;padding:3px 9px;border-radius:10px;font-size:11px;font-weight:700;border:1px solid #EF9A9A"><i class="fa-solid fa-triangle-exclamation"></i> VENCIDO</span>';
      acao=`<div style="display:flex;gap:6px;flex-wrap:wrap">${_btnPagar}${_btnPagoFora}</div>`;
      podeSelec=true;
    } else {
      statusHtml='<span style="background:#E3F2FD;color:#1565C0;padding:3px 9px;border-radius:10px;font-size:11px;font-weight:700">A pagar</span>';
      acao=`<div style="display:flex;gap:6px;flex-wrap:wrap">${_btnPagar}${_btnPagoFora}</div>`;
      podeSelec=true;
    }
    const semPix=!x.emp.chavePix;
    const chk=(podeSelec && !semPix)
      ? `<input type="checkbox" class="adiant-check" data-emp="${x.emp.id}" onclick="event.stopPropagation()">`
      : '';
    const pix=semPix?'<span style="color:#c62828">sem chave PIX</span>':`<span style="font-family:monospace;font-size:11px">${x.emp.chavePix}</span>`;
    return `<tr style="background:${bg};cursor:pointer" onclick="_abrirFolhaColaborador('${x.emp.id}')" title="Abrir a folha de ${(x.emp.nome||'').replace(/"/g,'')}">
      <td style="padding:9px 10px;text-align:center">${chk}</td>
      <td style="padding:9px 10px"><span style="color:#64748b;font-weight:600;margin-right:8px" title="Matrícula">${x.emp.registro?String(x.emp.registro).padStart(4,'0'):'—'}</span><strong>${x.emp.nome||'—'}</strong></td>
      <td style="padding:9px 10px;text-align:right;font-weight:700;color:#00695C">${fmtMoney(x.valor)}</td>
      <td style="padding:9px 10px">${pix}</td>
      <td style="padding:9px 10px;text-align:center">${statusHtml}</td>
      <td style="padding:9px 10px">${acao}</td>
    </tr>`;
  }).join('');
  const chkAll=document.getElementById('adiant-check-all'); if(chkAll) chkAll.checked=false;
}

function _adiantToggleAll(master){
  document.querySelectorAll('#adiant-tbody .adiant-check').forEach(c=>{ c.checked=master.checked; });
}

// ── Agendar pagamento de adiantamento para data futura. #adiant-agendar ──
// Campo "Agendar para:" no topo. Vazio = paga hoje. Com data futura, a
// solicitação leva o scheduleDate; ao APROVAR (2FA agora) o worker manda
// esse scheduleDate ao Asaas, que solta o PIX sozinho na data escolhida.
function _hojeISO(){ return new Date().toISOString().substring(0,10); }
// Lê/valida a data do campo. Retorna {date:'YYYY-MM-DD', futura:bool} ou
// null se for uma data no passado (não dá pra agendar pra trás).
function _adiantScheduleDate(){
  const hoje=_hojeISO();
  const v=(val('adiant-schedule-date')||'').trim();
  if(!v) return {date:hoje, futura:false};
  if(v<hoje) return null;
  return {date:v, futura:v>hoje};
}
function _brDate(iso){ return (iso||'').split('-').reverse().join('/'); }
function _adiantScheduleChanged(){
  const hint=document.getElementById('adiant-schedule-hint');
  const hoje=_hojeISO();
  const v=(val('adiant-schedule-date')||'').trim();
  if(!v){ if(hint) hint.textContent=''; return; }
  if(v<hoje){
    toast('Data no passado — escolha hoje ou uma data futura.','warning');
    setVal('adiant-schedule-date',''); if(hint) hint.textContent=''; return;
  }
  if(hint) hint.textContent = v>hoje
    ? `📅 Pagamentos serão AGENDADOS para ${_brDate(v)} — você aprova agora com 2FA e o banco (Asaas) solta o PIX nessa data.`
    : 'Pagamento para hoje.';
}

function _abrirFolhaColaborador(empId){
  if(!empId) return;
  showSection('payroll');
  // Garante que a opção do colaborador-alvo está no select ANTES de selecionar:
  // alinha o filtro de posto, inclui demitidos/afastados se for o caso e injeta
  // a opção se mesmo assim faltar. Sem isso, sel.value=empId falhava silenciosa
  // e a folha do colaborador não carregava (o nome era clicável mas "não ia").
  try { _ensurePayrollEmployeeOption(empId); } catch(e){ console.warn('_abrirFolhaColaborador', e); }
  const sel=document.getElementById('payroll-employee');
  if(sel){
    sel.value=empId;
    if(typeof onPayrollEmployeeChange==='function') onPayrollEmployeeChange();
  }
}

// Recalcula o valor do adiantamento de uma folha já salva (salário base ×
// percentual) e salva direto, sem precisar abrir a Folha de Ponto. Usado
// pelo botão "Recalcular agora" no diagnóstico de Adiantamentos.
async function _recalcAdiantamento(empId, mes, ano){
  const emp=State.employees.find(e=>e.id===empId);
  const p=(State.payrolls||[]).find(pp=>pp.employeeId===empId && pp.mes==mes && pp.ano==ano);
  if(!emp || !p){ toast('Folha do colaborador não encontrada.','error'); return; }
  const salBase=+emp.salarioBase||0;
  if(salBase<=0){ toast('Salário base do colaborador não está cadastrado.','error'); return; }
  const perc=parseInt(p.adiantamentoPerc||40);
  const novoValor=+(salBase*perc/100).toFixed(2);
  const updated={...p, adiantamentoValor:novoValor, updatedAt:new Date().toISOString()};
  try {
    await DB.save('payrolls', updated);
    const ix=State.payrolls.findIndex(x=>x.id===p.id);
    if(ix>=0) State.payrolls[ix]=updated;
    toast(`${emp.nome}: adiantamento recalculado para ${fmtMoney(novoValor)}.`,'success');
    renderAdiantamentos();
  } catch(e){
    console.error(e);
    toast('Erro ao salvar a folha. Tente abrir manualmente.','error');
  }
}

// "Pago fora do sistema" — registra que o adiantamento foi pago por fora
// (app do banco, espécie etc.). Tira o item da lista de pendência e marca
// como pago externo. O fluxo PIX via Aprovações continua disponível
// normalmente; isso é só para casos em que a pressa fala mais alto.
let _pagoExtCtx = null;
function openPagoExternoModal(empId, mes, ano){
  const emp=State.employees.find(e=>e.id===empId);
  const p=(State.payrolls||[]).find(pp=>pp.employeeId===empId && pp.mes==mes && pp.ano==ano);
  if(!emp || !p){ toast('Folha do colaborador não encontrada.','error'); return; }
  if((State.solicitacoes||[]).some(s=>s.origem==='adiantamento' && s.employeeId===empId
      && s.competencia===String(mes).padStart(2,'0')+'/'+ano && s.status==='pendente')){
    toast('Já existe uma solicitação PIX pendente. Cancele primeiro em Aprovações antes de marcar como pago fora.','warning');
    return;
  }
  _pagoExtCtx = {empId, mes, ano};
  setVal('pago-ext-nome', emp.nome||'—');
  setVal('pago-ext-valor', fmtMoney(p.adiantamentoValor||0));
  setVal('pago-ext-comp', String(mes).padStart(2,'0')+'/'+ano);
  setVal('pago-ext-data', new Date().toISOString().substring(0,10));
  setVal('pago-ext-obs','');
  document.getElementById('modal-pago-externo')?.classList.remove('hidden');
}

// Abre o modal de "pago fora" em modo LOTE para todos os selecionados.
async function marcarPagoExternoLote(){
  if(!getUserModules(Auth.currentUser).pagamentosLancar){
    toast('Você não tem permissão para lançar pagamentos.','error'); return;
  }
  const checks=[...document.querySelectorAll('#adiant-tbody .adiant-check:checked')];
  if(!checks.length){ toast('Selecione ao menos um colaborador (marque as caixas).','warning'); return; }
  const {mes,ano} = _adiantMesAno();
  _pagoExtCtx = { lote:true, ids: checks.map(c=>c.dataset.emp), mes, ano };
  setVal('pago-ext-data', new Date().toISOString().substring(0,10));
  setVal('pago-ext-obs','');
  document.getElementById('modal-pago-externo')?.classList.remove('hidden');
}

async function confirmarPagoExterno(){
  if(!_pagoExtCtx){ toast('Contexto perdido — reabra o modal.','error'); return; }
  const data=val('pago-ext-data')||new Date().toISOString().substring(0,10);
  const obs=(val('pago-ext-obs')||'').trim();

  // Modo LOTE — aplica a mesma data/obs a todos os colaboradores selecionados.
  if(_pagoExtCtx.lote){
    const {ids, mes:mL, ano:aL} = _pagoExtCtx;
    let ok=0, erros=0;
    for(const empId of ids){
      const p=(State.payrolls||[]).find(pp=>pp.employeeId===empId && pp.mes==mL && pp.ano==aL);
      if(!p){ erros++; continue; }
      const emp=State.employees.find(e=>e.id===empId);
      const updated={...p,
        adiantamentoPagoExterno:{
          data, obs,
          registradoEm:new Date().toISOString(),
          registradoPor:Auth.currentUser?.username || Auth.currentUser?.nome || '—'
        },
        updatedAt:new Date().toISOString()
      };
      try{
        await DB.save('payrolls', updated);
        const ix=State.payrolls.findIndex(x=>x.id===p.id);
        if(ix>=0) State.payrolls[ix]=updated;
        Auth.log('ADIANT_PAGO_EXTERNO', null, `${emp?.nome||'—'} | ${String(mL).padStart(2,'0')}/${aL} | R$ ${_adiantValorDe(emp,p).toFixed(2)}${obs?' | '+obs:''}`);
        ok++;
      }catch(e){ console.error('lote pago fora', e); erros++; }
    }
    toast(`${ok} marcado(s) como pago fora${erros?` · ${erros} erro(s)`:''}.`, erros?'warning':'success');
    closeModal('modal-pago-externo');
    _pagoExtCtx=null;
    renderAdiantamentos();
    if(typeof renderDashboard==='function' && State.currentSection==='dashboard') renderDashboard();
    return;
  }

  // Modo INDIVIDUAL (mantém o comportamento original).
  const {empId, mes, ano} = _pagoExtCtx;
  const p=(State.payrolls||[]).find(pp=>pp.employeeId===empId && pp.mes==mes && pp.ano==ano);
  if(!p){ toast('Folha não encontrada.','error'); return; }
  const emp=State.employees.find(e=>e.id===empId);
  const updated={
    ...p,
    adiantamentoPagoExterno:{
      data,
      obs,
      registradoEm:new Date().toISOString(),
      registradoPor:Auth.currentUser?.username || Auth.currentUser?.nome || '—'
    },
    updatedAt:new Date().toISOString()
  };
  try{
    await DB.save('payrolls', updated);
    const ix=State.payrolls.findIndex(x=>x.id===p.id);
    if(ix>=0) State.payrolls[ix]=updated;
    Auth.log('ADIANT_PAGO_EXTERNO', null, `${emp?.nome||'—'} | ${String(mes).padStart(2,'0')}/${ano} | R$ ${(p.adiantamentoValor||0).toFixed(2)}${obs?' | '+obs:''}`);
    toast(`${emp?.nome||'—'}: marcado como pago fora do sistema.`,'success');
    closeModal('modal-pago-externo');
    _pagoExtCtx=null;
    renderAdiantamentos();
    if(typeof renderDashboard==='function' && State.currentSection==='dashboard') renderDashboard();
  }catch(e){
    console.error(e);
    toast('Erro ao salvar.','error');
  }
}

async function desfazerPagoExterno(empId, mes, ano){
  const emp=State.employees.find(e=>e.id===empId);
  if(!confirm(`Desfazer a marcação de "pago fora" do adiantamento de ${emp?.nome||'esse colaborador'}? O item volta para a lista de pendências.`)) return;
  const p=(State.payrolls||[]).find(pp=>pp.employeeId===empId && pp.mes==mes && pp.ano==ano);
  if(!p){ toast('Folha não encontrada.','error'); return; }
  const updated={...p, updatedAt:new Date().toISOString()};
  delete updated.adiantamentoPagoExterno;
  try{
    await DB.save('payrolls', updated);
    const ix=State.payrolls.findIndex(x=>x.id===p.id);
    if(ix>=0) State.payrolls[ix]=updated;
    Auth.log('ADIANT_PAGO_EXTERNO_DESFEITO', null, `${emp?.nome||'—'} | ${String(mes).padStart(2,'0')}/${ano}`);
    toast('Marcação desfeita.','success');
    renderAdiantamentos();
    if(typeof renderDashboard==='function' && State.currentSection==='dashboard') renderDashboard();
  }catch(e){ console.error(e); toast('Erro ao salvar.','error'); }
}

// Cria a solicitação de pagamento de um adiantamento — reaproveita _criarSolicitacaoPagamento.
async function _criarSolicAdiantamento(emp, valor, comp, scheduleDate){
  if(!(valor>0)) throw new Error('valor do adiantamento inválido');
  const pixKey=emp.chavePix||'';
  if(!pixKey) throw new Error('colaborador sem chave PIX cadastrada');
  const pixTipo=emp.chavePixTipo||detectPixKeyType(pixKey);
  const jaPend=(State.solicitacoes||[]).some(s=>s.origem==='adiantamento' && s.employeeId===emp.id
    && s.competencia===comp && s.status==='pendente');
  if(jaPend) throw new Error('já existe uma solicitação pendente para este adiantamento');
  const sched=scheduleDate||_hojeISO();
  return _criarSolicitacaoPagamento({
    employeeId:emp.id, employeeNome:emp.nome, payrollId:'',
    valor, pixKey:_pixKeyParaAsaas(pixKey,pixTipo), keyType:pixTipo,
    descricao:`Adiantamento ${comp} — ${emp.nome}${sched>_hojeISO()?` (agendado p/ ${_brDate(sched)})`:''}`,
    scheduleDate:sched,
    competencia:comp, origem:'adiantamento',
  });
}

async function pagarAdiantamento(empId){
  if(!getUserModules(Auth.currentUser).pagamentosLancar){
    toast('Você não tem permissão para lançar pagamentos.','error'); return;
  }
  const {mes,ano,comp}=_adiantMesAno();
  const p=(State.payrolls||[]).find(x=>x.employeeId===empId && x.mes==mes && x.ano==ano);
  const emp=State.employees.find(e=>e.id===empId);
  if(!emp || !_adiantAtivoDe(emp,p)){ toast('Adiantamento não encontrado.','error'); return; }
  const _val=_adiantValorDe(emp,p);
  const sched=_adiantScheduleDate();
  if(!sched){ toast('A data em "Agendar para:" está no passado. Corrija (ou deixe vazia p/ hoje).','error'); return; }
  if(sched.futura && !confirm(`Agendar o adiantamento de ${emp.nome} (${fmtMoney(_val)}) para ${_brDate(sched.date)}?\n\nVai para Aprovações: você aprova AGORA com 2FA e o banco (Asaas) solta o PIX na data agendada.`)) return;
  try{
    const sol=await _criarSolicAdiantamento(emp, _val, comp, sched.date);
    Auth.log('PAGAMENTO_SOLICITADO', null, `Adiantamento ${comp} | ${emp.nome} | R$ ${_val.toFixed(2)}${sched.futura?` | agendado ${sched.date}`:''} | sol ${sol.id}`);
    toast(sched.futura
      ? `Adiantamento de ${emp.nome} agendado p/ ${_brDate(sched.date)} — aprove em Aprovações (2FA).`
      : `Adiantamento de ${emp.nome}: solicitação criada — aguardando aprovação.`,'success');
    renderAdiantamentos();
  }catch(e){
    toast('Não foi possível: '+(e.message||e),'error');
  }
}

async function pagarAdiantamentosLote(){
  if(!getUserModules(Auth.currentUser).pagamentosLancar){
    toast('Você não tem permissão para lançar pagamentos.','error'); return;
  }
  const checks=[...document.querySelectorAll('#adiant-tbody .adiant-check:checked')];
  if(!checks.length){ toast('Selecione ao menos um colaborador (marque as caixas).','warning'); return; }
  const sched=_adiantScheduleDate();
  if(!sched){ toast('A data em "Agendar para:" está no passado. Corrija (ou deixe vazia p/ hoje).','error'); return; }
  if(sched.futura && !confirm(`Agendar ${checks.length} adiantamento(s) para ${_brDate(sched.date)}?\n\nCada um vai para Aprovações: você aprova AGORA com 2FA e o banco (Asaas) solta o PIX na data agendada.`)) return;
  const {mes,ano,comp}=_adiantMesAno();
  let ok=0, erros=0;
  for(const c of checks){
    const empId=c.dataset.emp;
    const p=(State.payrolls||[]).find(x=>x.employeeId===empId && x.mes==mes && x.ano==ano);
    const emp=State.employees.find(e=>e.id===empId);
    if(!emp || !_adiantAtivoDe(emp,p)){ erros++; continue; }
    const _val=_adiantValorDe(emp,p);
    try{
      const sol=await _criarSolicAdiantamento(emp, _val, comp, sched.date);
      Auth.log('PAGAMENTO_SOLICITADO', null, `Adiantamento ${comp} | ${emp.nome} | R$ ${_val.toFixed(2)}${sched.futura?` | agendado ${sched.date}`:''} | sol ${sol.id}`);
      ok++;
    }catch(e){ erros++; }
  }
  toast(`${ok} solicitação(ões)${sched.futura?` agendada(s) p/ ${_brDate(sched.date)}`:' de adiantamento criada(s)'}${erros?` · ${erros} pulada(s)/com erro`:''}.`, erros?'warning':'success');
  renderAdiantamentos();
}

// ── Comprovante (recibo) do PIX ──────────────────────────────
// Solicitações cujo comprovante já foi buscado nesta sessão e trava de
// concorrência — para a busca automática não repetir nem rodar 2x junto.
const _comprovantesBuscados = new Set();
let   _autoComprovBusy = false;

// Abre o comprovante do PIX de uma solicitação paga. Se ainda não está
// salvo, busca a transferência no Asaas, guarda o link na solicitação e
// abre. O comprovante só existe depois que o PIX é concluído pelo banco.
async function verComprovante(solId, btnEl){
  const sol=(State.solicitacoes||[]).find(s=>s.id===solId);
  if(sol && sol.asaasComprovante){ window.open(sol.asaasComprovante,'_blank','noopener'); return; }
  if(!sol || !sol.asaasTransferId){ toast('Esta solicitação ainda não tem transferência no Asaas.','warning'); return; }
  const _html=btnEl?btnEl.innerHTML:'';
  if(btnEl){ btnEl.disabled=true; btnEl.innerHTML='<i class="fa-solid fa-spinner fa-spin"></i> Buscando...'; }
  try{
    const t=await _asaasReq('GET','/transfers/'+encodeURIComponent(sol.asaasTransferId));
    const url=(t&&t.transactionReceiptUrl)||'';
    if(url){
      sol.asaasComprovante=url; if(t.status) sol.asaasStatus=t.status;
      try{ await DB.merge('solicitacoesPagamento',solId,{asaasComprovante:url,asaasStatus:t.status||''}); }catch(_){}
      const w=window.open(url,'_blank','noopener');
      _refreshComprovanteViews();
      if(!w) toast('Comprovante pronto — clique no botão verde para abrir.','success');
    } else {
      toast('Comprovante ainda sendo gerado pelo banco. Tente de novo em instantes.','warning');
      if(btnEl){ btnEl.disabled=false; btnEl.innerHTML=_html; }
    }
  }catch(e){
    toast('Não foi possível obter o comprovante: '+(e.message||e),'error');
    if(btnEl){ btnEl.disabled=false; btnEl.innerHTML=_html; }
  }
}

// Em 2º plano, busca os comprovantes das solicitações pagas que ainda não
// têm o link salvo — assim o botão "Comprovante" já aparece pronto.
async function _autoBuscarComprovantes(){
  if(_autoComprovBusy) return;
  const pend=(State.solicitacoes||[]).filter(s=>
    s.status==='pago' && s.asaasTransferId && !s.asaasComprovante && !_comprovantesBuscados.has(s.id));
  if(!pend.length) return;
  _autoComprovBusy=true;
  let achou=false;
  try{
    for(const s of pend){
      _comprovantesBuscados.add(s.id);
      try{
        const t=await _asaasReq('GET','/transfers/'+encodeURIComponent(s.asaasTransferId));
        const url=(t&&t.transactionReceiptUrl)||'';
        if(url){
          s.asaasComprovante=url; if(t.status) s.asaasStatus=t.status;
          try{ await DB.merge('solicitacoesPagamento',s.id,{asaasComprovante:url,asaasStatus:t.status||''}); }catch(_){}
          achou=true;
        }
      }catch(_){ /* silencioso */ }
    }
  }finally{ _autoComprovBusy=false; }
  if(achou) _refreshComprovanteViews();
}

// Re-renderiza as telas que mostram comprovante: Aprovações e a aba
// Pagamentos do cadastro (se o modal do colaborador estiver aberto).
function _refreshComprovanteViews(){
  renderAprovacoes();
  const m=document.getElementById('modal-employee');
  if(m && !m.classList.contains('hidden')){
    const eid=val('emp-id'); if(eid) renderEmpPagamentos(eid);
  }
}

// Aba "Pagamentos" do cadastro — lista os pagamentos PIX feitos ao
// colaborador (coleção solicitacoesPagamento): data, descrição, valor,
// status e o link do comprovante oficial.
let _empPagFiltro  = 'pago';   // filtro de status da aba: 'pago' | 'todos'
let _empPagAtualId = null;     // colaborador exibido na aba (para re-render)

// Troca do filtro de status — re-renderiza a aba.
function _empPagSetFiltro(sel){ _empPagFiltro = sel.value; renderEmpPagamentos(_empPagAtualId); }

// Marca/desmarca todas as caixas de seleção da lista.
function _empPagToggleAll(chk){
  document.querySelectorAll('#emp-pagamentos-list .emp-pag-chk').forEach(c=>{ c.checked = chk.checked; });
}

// Abre, cada um em uma aba, os comprovantes das linhas selecionadas.
function _empPagAbrirSelecionados(){
  const chks=[...document.querySelectorAll('#emp-pagamentos-list .emp-pag-chk:checked')];
  if(!chks.length){ toast('Selecione ao menos um comprovante (caixas à esquerda).','warning'); return; }
  let n=0;
  chks.forEach(c=>{ const u=c.dataset.comp; if(u){ window.open(u,'_blank','noopener'); n++; } });
  toast(n+' comprovante(s) aberto(s) — baixe o PDF em cada aba.', n?'success':'warning');
}

function renderEmpPagamentos(empId){
  const box=document.getElementById('emp-pagamentos-list'); if(!box) return;
  _empPagAtualId = empId || null;
  const todas=(State.solicitacoes||[])
    .filter(s=>empId && s.employeeId===empId)
    .sort((a,b)=>new Date(b.criadoEm||0)-new Date(a.criadoEm||0));
  if(!todas.length){
    box.innerHTML=`<div class="empty-state small"><i class="fa-solid fa-money-bill-wave"></i><p>Nenhum pagamento registrado</p></div>`;
    return;
  }
  _autoBuscarComprovantes();   // garante os comprovantes que ainda faltam
  const lista = _empPagFiltro==='pago' ? todas.filter(s=>s.status==='pago') : todas;
  const totalPago=todas.filter(s=>s.status==='pago').reduce((t,s)=>t+(s.valor||0),0);
  const barra=`<div style="display:flex;gap:8px;align-items:center;flex-wrap:wrap;margin-bottom:10px">
    <label style="font-size:12px;color:#666">Mostrar:</label>
    <select id="emp-pag-filtro" onchange="_empPagSetFiltro(this)" style="padding:5px 9px;font-size:12px;border:1px solid var(--border);border-radius:6px">
      <option value="pago"${_empPagFiltro==='pago'?' selected':''}>Somente pagos</option>
      <option value="todos"${_empPagFiltro==='todos'?' selected':''}>Todos</option>
    </select>
    <button class="btn btn-sm btn-outline" style="color:#00695C;border-color:#00695C;font-size:12px" onclick="_empPagAbrirSelecionados()">
      <i class="fa-solid fa-up-right-from-square"></i> Abrir comprovantes selecionados
    </button>
  </div>`;
  if(!lista.length){
    box.innerHTML=barra+`<div class="empty-state small"><i class="fa-solid fa-money-bill-wave"></i><p>Nenhum pagamento com esse filtro</p></div>`;
    return;
  }
  const linhas=lista.map(s=>{
    const dt=((s.scheduleDate||s.criadoEm||'')+'').substring(0,10).split('-').reverse().join('/');
    let comp='<span style="color:#bbb">—</span>', chk='';
    if(s.status==='pago'){
      if(s.asaasComprovante){
        comp=`<a href="${s.asaasComprovante}" target="_blank" rel="noopener" style="color:#00695C;font-weight:600;text-decoration:none;white-space:nowrap"><i class="fa-solid fa-receipt"></i> Ver comprovante</a>`;
        chk=`<input type="checkbox" class="emp-pag-chk" data-comp="${s.asaasComprovante}">`;
      } else if(s.asaasTransferId){
        comp=`<button class="btn btn-sm btn-outline" style="color:#00695C;border-color:#00695C;font-size:11px;padding:3px 9px" onclick="verComprovante('${s.id}',this)"><i class="fa-solid fa-receipt"></i> Comprovante</button>`;
      } else {
        comp='<span style="font-size:11px;color:#999">pago</span>';
      }
    } else if(s.status==='recusado'){
      comp=`<span style="font-size:11px;color:#c62828">${s.motivoRecusa||'recusado'}</span>`;
    } else if(s.status==='erro'){
      comp=`<span style="font-size:11px;color:#c62828">${s.erro||'erro'}</span>`;
    } else if(s.status==='estornado'){
      comp=`<span style="font-size:11px;color:#E65100">${s.motivoEstorno||'estornado'}</span>`;
    }
    return `<tr style="border-bottom:1px solid var(--border)">
      <td style="padding:8px 6px;text-align:center;width:30px">${chk}</td>
      <td style="padding:8px 10px;font-size:12px;white-space:nowrap">${dt||'—'}</td>
      <td style="padding:8px 10px;font-size:12px">${s.descricao||s.origem||'—'}</td>
      <td style="padding:8px 10px;text-align:right;font-weight:700;color:#00695C;white-space:nowrap">${fmtMoney(s.valor||0)}</td>
      <td style="padding:8px 10px;text-align:center">${_aprovacaoStatusBadge(s.status)}</td>
      <td style="padding:8px 10px">${comp}</td>
    </tr>`;
  }).join('');
  box.innerHTML=barra+`
    <table style="width:100%;border-collapse:collapse">
      <thead><tr style="background:#f5f5f5">
        <th style="padding:7px 6px;text-align:center;width:30px"><input type="checkbox" onclick="_empPagToggleAll(this)" title="Selecionar todos"></th>
        <th style="padding:7px 10px;text-align:left;font-size:11px;color:#666">Data</th>
        <th style="padding:7px 10px;text-align:left;font-size:11px;color:#666">Descrição</th>
        <th style="padding:7px 10px;text-align:right;font-size:11px;color:#666">Valor</th>
        <th style="padding:7px 10px;text-align:center;font-size:11px;color:#666">Status</th>
        <th style="padding:7px 10px;text-align:left;font-size:11px;color:#666">Comprovante</th>
      </tr></thead>
      <tbody>${linhas}</tbody>
    </table>
    <div style="margin-top:10px;padding:8px 12px;background:#E8F5E9;border-radius:6px;font-size:13px;text-align:right">
      Total pago a este colaborador: <strong style="color:#00695C">${fmtMoney(totalPago)}</strong>
    </div>`;
}

// ============================================
// COMUNICAÇÕES — mensagens do gestor para o colaborador (Fase C)
// ============================================

// Utilitario: SHA-256 hex de um Blob/File ou string. Usa Web Crypto API
// (nativo no navegador, sem dependencia externa). Retorna sempre maiusculo.
// Usado para garantir integridade do anexo e da mensagem disciplinar —
// se o conteudo muda 1 byte, o hash muda completamente.
async function _sha256Hex(blobOrString){
  let buf;
  if(typeof blobOrString === 'string'){
    buf = new TextEncoder().encode(blobOrString);
  } else if(blobOrString instanceof Blob){
    buf = await blobOrString.arrayBuffer();
  } else {
    throw new Error('Tipo invalido para _sha256Hex');
  }
  const hash = await crypto.subtle.digest('SHA-256', buf);
  return Array.from(new Uint8Array(hash)).map(b => b.toString(16).padStart(2,'0')).join('').toUpperCase();
}

// Formata um hash hex em blocos de 4 caracteres para leitura humana
// (ex.: ABCD-1234-EF56-7890 ...) — usado nos recibos impressos.
function _formatHashLegivel(hex){
  return (hex||'').match(/.{1,4}/g)?.join('-') || hex || '';
}

let _comuDestinatarios     = [];
let _comuMensagensCache    = {};   // msgId → mensagem (para reenviar/editar)
let _comuAnexoHerdado      = null; // anexo da mensagem original (no Reenviar/Editar)
let _comuEditandoId        = null; // id da mensagem em edição (null = novo envio)

function openComunicarModal(empIdOrNull){
  const _mods=getUserModules(Auth.currentUser);
  if(!_mods.comunicacao && !_mods.employees && Auth.currentUser?.role!=='master'){
    toast('Você não tem permissão para enviar mensagens.','error'); return;
  }
  _comuDestinatarios = [];
  if(empIdOrNull){
    const emp=State.employees.find(e=>e.id===empIdOrNull);
    if(emp) _comuDestinatarios.push(emp.id);
  }
  const sel=document.getElementById('comu-add-emp');
  if(sel){
    sel.innerHTML='<option value="">— selecionar colaborador —</option>';
    State.employees
      .filter(e=>(e.status||'ativo')==='ativo')
      .sort((a,b)=>(a.nome||'').localeCompare(b.nome||'','pt-BR'))
      .forEach(e=>{
        const o=document.createElement('option');
        o.value=e.id; o.textContent=e.nome;
        sel.appendChild(o);
      });
  }
  setVal('comu-assunto','');
  _comuSetCorpo('');
  setVal('comu-tipo','normal');
  setVal('comu-disc-motivo','');
  setVal('comu-disc-dias','');
  setVal('comu-disc-artigo','');
  const fi=document.getElementById('comu-anexo'); if(fi) fi.value='';
  _comuAnexoHerdado = null;
  _comuEditandoId   = null;
  // restaura o modal para o modo "Novo envio" (caso tenha sido aberto para edição antes)
  const _tituloEl = document.querySelector('#modal-comunicar .modal-header h3');
  if(_tituloEl) _tituloEl.innerHTML = '<i class="fa-solid fa-envelope" style="color:#1976D2"></i> Comunicar Colaborador';
  const _btnEnv = document.getElementById('comu-enviar');
  if(_btnEnv) _btnEnv.innerHTML = '<i class="fa-solid fa-paper-plane"></i> Enviar';
  const _addRow = document.getElementById('comu-add-emp')?.closest('.form-row');
  if(_addRow) _addRow.style.display = '';
  _comuRenderAnexoHerdado();
  _comuRenderDest();
  _comuOnTipoChange(); // garante que o painel de disciplina esta escondido
  document.getElementById('modal-comunicar').classList.remove('hidden');
}

// Quando o tipo de mensagem muda, mostra/esconde o painel de disciplina
// (motivo + dias de suspensao + artigo CLT) e ajusta visual do modal.
function _comuOnTipoChange(){
  const tipo  = (val('comu-tipo')||'normal').toLowerCase();
  const painel = document.getElementById('comu-disciplina-painel');
  const rowDias = document.getElementById('comu-disc-dias-row');
  const hint   = document.getElementById('comu-disc-hint');
  if(painel) painel.style.display = (tipo==='advertencia'||tipo==='suspensao') ? '' : 'none';
  if(rowDias) rowDias.style.display = (tipo==='suspensao') ? '' : 'none';
  // Borda colorida no modal pra reforcar visualmente que e' um documento disciplinar
  const dlg = document.querySelector('#modal-comunicar .modal-dialog');
  if(dlg){
    dlg.style.borderTop = (tipo==='advertencia') ? '4px solid #E65100'
                        : (tipo==='suspensao')   ? '4px solid #c62828'
                        : '';
  }
  if(hint){
    if(tipo==='advertencia'){
      hint.style.display = '';
      hint.style.color = '#E65100';
      hint.innerHTML = '⚠ <strong>Advertência:</strong> o anexo é obrigatório (PDF do documento assinado ou carta). O sistema vai calcular o SHA-256 do arquivo, criar Recibo de Envio e arquivar tudo na aba <strong>Disciplina</strong> do colaborador.';
    } else if(tipo==='suspensao'){
      hint.style.display = '';
      hint.style.color = '#c62828';
      hint.innerHTML = '⛔ <strong>Suspensão:</strong> informe os dias de afastamento. O anexo é obrigatório. O sistema cria Recibo de Envio com SHA-256 e arquiva na aba <strong>Disciplina</strong>.';
    } else {
      hint.style.display = 'none';
    }
  }
}

// Editar uma mensagem ja enviada: abre o composer pre-preenchido,
// trava o destinatario no original e salva por cima (DB.merge).
function editarMensagem(msgId){
  if(!getUserModules(Auth.currentUser).employees && Auth.currentUser?.role!=='master'){
    toast('Sem permissão para editar mensagens.','error'); return;
  }
  const m = _comuMensagensCache[msgId];
  if(!m){ toast('Mensagem não encontrada — recarregue a aba.','error'); return; }
  openComunicarModal();
  _comuEditandoId   = msgId;
  _comuDestinatarios = m.employeeId ? [m.employeeId] : [];
  setVal('comu-assunto', m.assunto||'');
  _comuSetCorpo(m.corpo||'');
  if(m.anexoUrl){
    _comuAnexoHerdado = { url:m.anexoUrl, nome:m.anexoNome||'anexo', tipo:m.anexoTipo||'' };
  }
  // Trava a UI de adicionar destinatários (edição mantém o mesmo recebedor)
  const addRow = document.getElementById('comu-add-emp')?.closest('.form-row');
  if(addRow) addRow.style.display = 'none';
  // Muda titulo + botao
  const titleEl = document.querySelector('#modal-comunicar .modal-header h3');
  if(titleEl) titleEl.innerHTML = '<i class="fa-solid fa-pen" style="color:#E65100"></i> Editar Mensagem';
  const btn = document.getElementById('comu-enviar');
  if(btn) btn.innerHTML = '<i class="fa-solid fa-floppy-disk"></i> Salvar alterações';
  _comuRenderAnexoHerdado();
  _comuRenderDest();
}

// Reenviar uma mensagem já enviada: abre o composer com assunto + corpo
// já preenchidos. O usuário escolhe os novos destinatários. Se a mensagem
// tinha anexo, ele é herdado (mesmo arquivo) — pode ser substituído por
// outro upload ou removido pelo link "remover".
function reenviarMensagem(msgId){
  const m = _comuMensagensCache[msgId];
  if(!m){ toast('Mensagem não encontrada — recarregue a aba.','error'); return; }
  openComunicarModal();
  setVal('comu-assunto', m.assunto||'');
  _comuSetCorpo(m.corpo||'');
  if(m.anexoUrl){
    _comuAnexoHerdado = { url:m.anexoUrl, nome:m.anexoNome||'anexo', tipo:m.anexoTipo||'' };
  }
  _comuRenderAnexoHerdado();
}

function _comuRenderAnexoHerdado(){
  const el = document.getElementById('comu-anexo-herdado'); if(!el) return;
  if(_comuAnexoHerdado){
    el.style.display='';
    el.innerHTML = `<i class="fa-solid fa-paperclip"></i> Anexo da mensagem original: <strong>${_comuAnexoHerdado.nome}</strong> — será reaproveitado se você não enviar outro arquivo. <button type="button" onclick="_comuLimparAnexoHerdado()" style="background:none;border:none;color:#c62828;cursor:pointer;font-size:11px;margin-left:6px;text-decoration:underline">remover</button>`;
  } else {
    el.style.display='none';
    el.innerHTML='';
  }
}
function _comuLimparAnexoHerdado(){ _comuAnexoHerdado=null; _comuRenderAnexoHerdado(); }

// ===========================================================================
// DISCIPLINA — advertencias e suspensoes (com cadeia de custodia SHA-256)
// ===========================================================================

// Gera o HTML do Recibo de Envio — documento que comprova que a empresa
// enviou advertencia/suspensao com hash do anexo e timestamp do servidor.
// O HTML e' arquivado no Storage e pode ser aberto/impressovia URL.
function _gerarReciboEnvioHTML(d){
  const dtBr = new Date(d.criadoEm).toLocaleString('pt-BR');
  const tipoLabel = d.tipo==='advertencia' ? 'ADVERTÊNCIA ESCRITA'
                  : d.tipo==='suspensao'   ? 'SUSPENSÃO DISCIPLINAR'
                  : 'COMUNICADO';
  const corTipo = d.tipo==='advertencia' ? '#E65100' : '#c62828';
  const esc = s => (s||'').toString().replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
  const corpoEsc = _corpoHtml(d.corpo);
  const motivoEsc = esc(d.motivoDisc).replace(/\n/g,'<br>');
  const hashAnexoFmt = _formatHashLegivel(d.anexoHash||'');
  const hashMsgFmt   = _formatHashLegivel(d.mensagemHash||'');
  return `<!DOCTYPE html><html lang="pt-BR"><head>
<meta charset="UTF-8"><title>Recibo de Envio — ${tipoLabel} — ${esc(d.empNome)}</title>
<style>
  @page{size:A4;margin:18mm 16mm}
  *{box-sizing:border-box;margin:0;padding:0}
  body{font-family:Arial,sans-serif;font-size:11px;color:#222;line-height:1.5}
  .header{display:flex;align-items:center;gap:14px;border-bottom:3px solid ${corTipo};padding-bottom:10px;margin-bottom:18px}
  .header h1{color:${corTipo};font-size:18px;letter-spacing:.5px}
  .header .empresa{color:#666;font-size:11px;margin-top:2px}
  .header .meta{margin-left:auto;text-align:right;font-size:9px;color:#888}
  .tipo-badge{display:inline-block;background:${corTipo};color:#fff;padding:4px 12px;border-radius:4px;font-size:11px;font-weight:700;letter-spacing:.5px;margin-bottom:14px}
  h2{font-size:12px;color:${corTipo};margin:18px 0 8px;text-transform:uppercase;letter-spacing:.5px;border-bottom:1px solid #eee;padding-bottom:3px}
  table{width:100%;border-collapse:collapse;margin-bottom:12px;font-size:11px}
  td{padding:5px 8px;border-bottom:1px solid #eee;vertical-align:top}
  td.l{font-weight:700;color:#475569;width:140px;background:#f8fafc}
  .corpo-box{background:#fafafa;border-left:4px solid ${corTipo};padding:10px 14px;margin:6px 0;font-size:11px;white-space:pre-wrap;line-height:1.5}
  .hash-box{background:#fff7ed;border:1px solid #fed7aa;border-radius:4px;padding:10px 12px;margin-top:6px}
  .hash-box .lbl{font-size:10px;color:#92400e;font-weight:700;text-transform:uppercase;letter-spacing:.5px;margin-bottom:3px}
  .hash-box .val{font-family:Consolas,'Courier New',monospace;font-size:10px;color:#451a03;word-break:break-all;font-weight:600}
  .footer{margin-top:24px;padding-top:12px;border-top:2px solid ${corTipo};font-size:10px;color:#555;line-height:1.6}
  .footer .impt{font-weight:700;color:${corTipo}}
  .assinatura{margin-top:36px;display:grid;grid-template-columns:1fr 1fr;gap:30px}
  .assinatura div{border-top:1px solid #333;padding-top:6px;text-align:center;font-size:10px;color:#444}
  .badge-info{background:#e0e7ff;color:#3730a3;padding:8px 12px;border-radius:6px;font-size:10px;margin-top:14px;line-height:1.5}
</style></head>
<body>
  <div class="header">
    <div style="display:flex;align-items:center;gap:12px">
      <img src="${_logoSrc()}" alt="" style="height:46px;width:auto;max-width:80px;object-fit:contain;flex-shrink:0" onerror="this.style.display='none'">
      <div>
      <h1>RECIBO DE ENVIO</h1>
      <div class="empresa">${esc(d.empresa)}</div>
      </div>
    </div>
    <div class="meta">
      Documento ID:<br><strong>${esc(d.discId)}</strong><br>
      Emitido em ${dtBr}
    </div>
  </div>

  <div class="tipo-badge">${tipoLabel}</div>

  <h2>Identificação do Colaborador</h2>
  <table>
    <tr><td class="l">Nome</td><td><strong>${esc(d.empNome)}</strong></td></tr>
    <tr><td class="l">Matrícula</td><td>${esc(d.empMatricula)}</td></tr>
    <tr><td class="l">CPF</td><td>${esc(d.empCpf)}</td></tr>
    <tr><td class="l">Cargo</td><td>${esc(d.empCargo)}</td></tr>
    <tr><td class="l">Posto</td><td>${esc(d.empPosto)}</td></tr>
  </table>

  <h2>Dados do Ato Disciplinar</h2>
  <table>
    <tr><td class="l">Tipo</td><td><strong style="color:${corTipo}">${tipoLabel}</strong></td></tr>
    ${d.tipo==='suspensao' ? `<tr><td class="l">Dias de suspensão</td><td><strong>${esc(d.diasSusp)}</strong> dia(s)</td></tr>` : ''}
    <tr><td class="l">Motivo</td><td>${motivoEsc||'—'}</td></tr>
    ${d.artigoCLT ? `<tr><td class="l">Fundamento</td><td>${esc(d.artigoCLT)}</td></tr>` : ''}
    <tr><td class="l">Aplicado por</td><td>${esc(d.autorNome)}</td></tr>
    <tr><td class="l">Data/hora envio</td><td><strong>${dtBr}</strong></td></tr>
  </table>

  <h2>Conteúdo da Notificação</h2>
  <table>
    <tr><td class="l">Assunto</td><td><strong>${esc(d.assunto)}</strong></td></tr>
  </table>
  <div class="corpo-box">${corpoEsc}</div>

  <h2>Cadeia de Custódia — SHA-256</h2>
  <table>
    <tr><td class="l">Arquivo anexado</td><td><strong>${esc(d.anexoNome)}</strong></td></tr>
  </table>
  <div class="hash-box">
    <div class="lbl">SHA-256 do anexo</div>
    <div class="val">${hashAnexoFmt||'—'}</div>
  </div>
  ${hashMsgFmt ? `<div class="hash-box" style="margin-top:8px">
    <div class="lbl">SHA-256 da mensagem (conjunto)</div>
    <div class="val">${hashMsgFmt}</div>
  </div>` : ''}

  <div class="badge-info">
    <strong>ℹ Como verificar a integridade:</strong> baixe o anexo original e recalcule o SHA-256 (ferramentas como certutil no Windows, sha256sum no Linux/Mac).
    Se o hash bater com o registrado acima, o arquivo não foi alterado desde o envio.
    O timestamp e os identificadores são gerados pelo servidor do sistema.
  </div>

  <div class="footer">
    <p class="impt">Este recibo comprova o ENVIO do documento disciplinar pelo sistema DRG-Kronos.</p>
    <p>O documento original foi anexado e seu hash criptográfico SHA-256 está registrado acima.</p>
    <p>Um Recibo de Recebimento separado é gerado quando o colaborador visualiza a mensagem no app.</p>
    <p style="margin-top:8px">ID da comunicação: <code>${esc(d.comunicacaoId)}</code> · ID disciplina: <code>${esc(d.discId)}</code></p>
  </div>

  <div class="assinatura">
    <div>Pelo empregador<br><br><br>${esc(d.autorNome)}</div>
    <div>Pelo colaborador<br><br><br>${esc(d.empNome)}<br>Matrícula ${esc(d.empMatricula)}</div>
  </div>

</body></html>`;
}

// Modal pos-envio de disciplina — oferece abrir o e-mail (mailto) e ver o recibo
function _abrirPosEnvioDisciplina(disc){
  const e = State.employees.find(x=>x.id===disc.employeeId);
  const emailEmp = (e && e.email) || '';
  const tipoLabel = disc.tipo==='advertencia' ? 'Advertência' : 'Suspensão';
  const linhas = [
    `<strong>${tipoLabel}</strong> registrada para <strong>${(e&&e.nome)||disc.employeeNome}</strong>.`,
    `<small style="color:#666">SHA-256: <code style="font-size:11px">${(disc.anexoHash||'').substring(0,32)}...</code></small>`,
    '',
    'Próximas ações disponíveis:'
  ];
  const html = `
    <div style="padding:18px;max-width:520px">
      <div style="font-size:14px;line-height:1.6;margin-bottom:14px">${linhas.join('<br>')}</div>
      <div style="display:flex;gap:8px;flex-wrap:wrap">
        ${disc.reciboEnvioUrl ? `<a href="${disc.reciboEnvioUrl}" target="_blank" rel="noopener" class="btn btn-primary"><i class="fa-solid fa-file-pdf"></i> Ver Recibo de Envio</a>` : ''}
        <a href="${disc.anexoUrl}" target="_blank" rel="noopener" class="btn btn-outline"><i class="fa-solid fa-paperclip"></i> Abrir anexo</a>
        ${emailEmp
          ? `<button class="btn btn-outline" onclick="_abrirMailtoDisciplina('${disc.id}')"><i class="fa-solid fa-envelope"></i> Abrir e-mail para ${emailEmp}</button>`
          : `<span style="font-size:12px;color:#999;padding:6px 10px">⚠ Colaborador sem e-mail cadastrado</span>`}
      </div>
      <div style="font-size:11px;color:#888;margin-top:12px">A mensagem ja' chegou no app do colaborador. O Recibo de Recebimento sera gerado quando ele visualizar.</div>
    </div>`;
  _showFloatingModal('Ato disciplinar registrado', html);
  // guarda o recente para o mailto encontrar
  window._discRecente = disc;
}

// Abre o cliente de e-mail (Outlook/Gmail/Apple Mail) com destinatario, assunto
// e corpo ja' preenchidos. Anexos nao sao suportados via mailto:, entao
// incluimos os links do anexo e do recibo no corpo.
function _abrirMailtoDisciplina(discId){
  const disc = window._discRecente;
  if(!disc || disc.id!==discId){ toast('Dados não encontrados — feche e refaça.','error'); return; }
  const e = State.employees.find(x=>x.id===disc.employeeId);
  const emailEmp = (e && e.email) || '';
  if(!emailEmp){ toast('Colaborador sem e-mail cadastrado.','error'); return; }
  const tipoLabel = disc.tipo==='advertencia' ? 'Advertência Escrita' : 'Suspensão Disciplinar';
  const subject = `${tipoLabel} — ${(e&&e.nome)||disc.employeeNome}`;
  const lines = [
    `Prezado(a) ${(e&&e.nome)||disc.employeeNome},`,
    '',
    `Comunicamos oficialmente a aplicação de ${tipoLabel.toLowerCase()}, conforme documento em anexo.`,
    '',
    disc.tipo==='suspensao' ? `Dias de suspensão: ${disc.diasSuspensao}` : '',
    disc.motivo ? `Motivo: ${disc.motivo}` : '',
    disc.artigoCLT ? `Fundamento: ${disc.artigoCLT}` : '',
    '',
    `Documento anexado: ${disc.anexoUrl}`,
    disc.reciboEnvioUrl ? `Recibo de Envio: ${disc.reciboEnvioUrl}` : '',
    '',
    `SHA-256 do documento: ${disc.anexoHash}`,
    `Data/hora de envio: ${new Date(disc.criadoEm).toLocaleString('pt-BR')}`,
    '',
    `A mesma mensagem foi enviada para o app do colaborador.`,
    '',
    `Atenciosamente,`,
    `${disc.criadoPorNome}`,
    `${_e('nomeEmpresa')}`
  ].filter(s => s !== undefined);
  const body = lines.join('\n');
  const href = `mailto:${encodeURIComponent(emailEmp)}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
  window.location.href = href;
}

// Render do conteudo da aba Disciplina no modal do colaborador
async function renderDisciplinaTab(empId){
  const box = document.getElementById('emp-disciplina-list'); if(!box) return;
  if(!empId){
    box.innerHTML = `<div class="empty-state small"><i class="fa-solid fa-gavel"></i><p>Salve o colaborador para registrar atos disciplinares</p></div>`;
    return;
  }
  box.innerHTML = '<div style="text-align:center;padding:20px;color:#999"><i class="fa-solid fa-spinner fa-spin"></i> Carregando disciplina...</div>';
  let lista = [];
  try{
    const snap = await firebase.firestore().collection('disciplina').where('employeeId','==',empId).get();
    lista = snap.docs.map(d => ({ id:d.id, ...d.data() }));
  }catch(e){ console.error('disciplina:fetch', e); }
  lista.sort((a,b) => (b.criadoEm||'').localeCompare(a.criadoEm||''));

  // Sincroniza a visualização com a MENSAGEM ligada (comunicacaoId): se o colaborador
  // já LEU no app a mensagem da advertência/suspensão, o ato disciplinar passa a contar
  // como visualizado. Cobre atos antigos (sem disciplinaId na msg) e persiste o carimbo
  // pra não recalcular sempre. #disciplina-sync-visualizacao
  try{
    const pend = lista.filter(d => d && !d.visualizadoEm && !d.anulada && d.comunicacaoId);
    if(pend.length){
      const csnap = await firebase.firestore().collection('comunicacoes').where('employeeId','==',empId).get();
      const msgs = {}; csnap.docs.forEach(c=>{ msgs[c.id]=c.data(); });
      for(const d of pend){
        const m = msgs[d.comunicacaoId];
        if(m && m.lida){
          const quando = m.lidaEm || m.criadoEm || new Date().toISOString();
          d.visualizadoEm = quando;
          try{ await DB.merge('disciplina', d.id, { visualizadoEm: quando }); }catch(_){}
        }
      }
    }
  }catch(e){ console.warn('disciplina:sync-visualizacao', e); }
  // Anuladas nao contam nas estatisticas — sao registros historicos
  const ativas = lista.filter(x => !x.anulada);
  const totAdv = ativas.filter(x=>x.tipo==='advertencia').length;
  const totSus = ativas.filter(x=>x.tipo==='suspensao').length;
  const totAnul = lista.filter(x=>x.anulada).length;
  const fmtDt = iso => { const d=iso?new Date(iso):null; if(!d||isNaN(d.getTime())) return '—'; return d.toLocaleDateString('pt-BR') + ' ' + d.toLocaleTimeString('pt-BR',{hour:'2-digit',minute:'2-digit'}); };
  const podeAnular = !!getUserModules(Auth.currentUser).disciplinaApagar || Auth.currentUser?.role==='master';
  let html = `
    <div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px;margin-bottom:12px">
      <div>
        <strong style="font-size:13px">Atos disciplinares (${ativas.length}${totAnul?` · ${totAnul} anulado(s)`:''})</strong>
        <div style="font-size:11px;color:#888;margin-top:2px">${totAdv} advertência(s) · ${totSus} suspensão(ões) vigentes</div>
      </div>
      <button class="btn btn-sm btn-primary" onclick="_abrirNovaDisciplinaParaColaborador('${empId}')" style="font-size:12px">
        <i class="fa-solid fa-gavel"></i> Nova advertência/suspensão
      </button>
    </div>`;
  if(!lista.length){
    html += `<div class="empty-state small"><i class="fa-solid fa-folder-open"></i><p>Sem atos disciplinares registrados</p></div>`;
  } else {
    html += lista.map(d => {
      const anulada = !!d.anulada;
      const cor = anulada ? '#94a3b8'
                : d.tipo==='advertencia' ? '#E65100' : '#c62828';
      const bg  = anulada ? '#f1f5f9'
                : d.tipo==='advertencia' ? '#fff7ed' : '#fee2e2';
      const lbl = d.tipo==='advertencia' ? 'ADVERTÊNCIA' : 'SUSPENSÃO';
      const styleTexto = anulada ? 'opacity:.65' : '';
      const styleAnul  = anulada ? 'text-decoration:line-through' : '';
      const hash16 = (d.anexoHash||'').substring(0,16);
      const recb = d.visualizadoEm
        ? `<span style="color:#16a34a;font-weight:600">✓✓ Visualizada em ${fmtDt(d.visualizadoEm)}</span>`
        : `<span style="color:#94a3b8">⏳ Aguardando visualização no app</span>`;
      // Bloco de anulacao (quando aplicavel)
      const anulHtml = anulada
        ? `<div style="background:#1e293b;color:#fff;border-radius:6px;padding:10px 12px;margin:8px 0;font-size:11.5px;line-height:1.5">
            <strong style="color:#fca5a5">⊘ ANULADA</strong> em ${fmtDt(d.anuladaEm)} por <strong>${(d.anuladaPorNome||'—').replace(/</g,'&lt;')}</strong>
            <div style="margin-top:4px;color:#cbd5e1">Motivo: ${(d.motivoAnulacao||'—').replace(/</g,'&lt;')}</div>
          </div>`
        : '';
      // Botao anular — so' aparece para quem tem permissao E se ainda nao foi anulada
      const btnAnular = (podeAnular && !anulada)
        ? `<button class="btn btn-sm btn-outline" onclick="anularDisciplina('${d.id}')" style="font-size:11px;color:#c62828;border-color:#ef9a9a;margin-left:auto"><i class="fa-solid fa-ban"></i> Anular</button>`
        : '';
      return `<div style="background:${bg};border-left:4px solid ${cor};border-radius:8px;padding:12px 14px;margin-bottom:10px;${styleTexto}">
        <div style="display:flex;justify-content:space-between;align-items:flex-start;flex-wrap:wrap;gap:10px;margin-bottom:6px">
          <div style="${styleAnul}">
            <span style="background:${cor};color:#fff;padding:2px 8px;border-radius:4px;font-size:10px;font-weight:700;letter-spacing:.5px">${lbl}</span>
            ${d.tipo==='suspensao' && d.diasSuspensao ? `<span style="margin-left:6px;font-size:11px;color:${cor};font-weight:600">${d.diasSuspensao} dia(s)</span>` : ''}
          </div>
          <span style="font-size:11px;color:#666">${fmtDt(d.criadoEm)}</span>
        </div>
        ${anulHtml}
        ${d.motivo ? `<div style="font-size:12px;color:#333;margin:6px 0;line-height:1.5;${styleAnul}"><strong>Motivo:</strong> ${(d.motivo||'').replace(/</g,'&lt;')}</div>` : ''}
        ${d.artigoCLT ? `<div style="font-size:11px;color:#666;${styleAnul}"><strong>Fundamento:</strong> ${(d.artigoCLT||'').replace(/</g,'&lt;')}</div>` : ''}
        <div style="font-size:11px;color:#666;margin-top:6px">Aplicado por ${d.criadoPorNome||'—'}</div>
        <div style="margin-top:8px;padding:8px;background:rgba(255,255,255,.6);border-radius:6px;font-size:11px;font-family:Consolas,monospace;color:#555">
          🔒 SHA-256: <strong>${hash16}...${d.anexoHash?d.anexoHash.substring(d.anexoHash.length-8):''}</strong>
        </div>
        ${!anulada ? `<div style="margin-top:8px;font-size:11px">${recb}</div>` : ''}
        <div style="margin-top:10px;padding-top:8px;border-top:1px dashed rgba(0,0,0,.1);display:flex;gap:6px;flex-wrap:wrap;align-items:center">
          ${d.anexoUrl ? `<a href="${d.anexoUrl}" target="_blank" rel="noopener" class="btn btn-sm btn-outline" style="font-size:11px"><i class="fa-solid fa-paperclip"></i> ${(d.anexoNome||'anexo').substring(0,30)}</a>` : ''}
          ${d.reciboEnvioUrl ? `<a href="${d.reciboEnvioUrl}" target="_blank" rel="noopener" class="btn btn-sm btn-outline" style="font-size:11px;color:#1976D2;border-color:#1976D2"><i class="fa-solid fa-file-pdf"></i> Recibo de Envio</a>` : ''}
          ${d.reciboRecebimentoUrl ? `<a href="${d.reciboRecebimentoUrl}" target="_blank" rel="noopener" class="btn btn-sm btn-outline" style="font-size:11px;color:#16a34a;border-color:#16a34a"><i class="fa-solid fa-file-circle-check"></i> Recibo de Recebimento</a>` : ''}
          <button class="btn btn-sm btn-outline" onclick="_verHashesDisciplina('${d.id}')" style="font-size:11px;color:#7e22ce;border-color:#c084fc"><i class="fa-solid fa-fingerprint"></i> Hashes (auditoria)</button>
          ${btnAnular}
        </div>
      </div>`;
    }).join('');
  }
  box.innerHTML = html;
}

