function editarOverrideEscala(overrideId){
  const empId = _escalaEmpIdCtx();
  const emp = State.employees.find(e=>e.id===empId);
  if(!emp) return;
  const o = (emp.overridesHorario||[]).find(x => x.id===overrideId);
  if(!o){ toast('Dia avulso não encontrado.','error'); return; }
  setVal('ovr-esc-id', o.id);
  setVal('ovr-esc-data', o.data||'');
  setVal('ovr-esc-tipo', o.tipo||'diferente');
  setVal('ovr-esc-entrada', o.horarioEntrada||'');
  setVal('ovr-esc-saida', o.horarioSaida||'');
  setVal('ovr-esc-ref-ini', o.horarioRefIni||'');
  setVal('ovr-esc-ref-fim', o.horarioRefFim||'');
  setVal('ovr-esc-obs', o.observacao||'');
  const _remE = document.getElementById('ovr-esc-remunerada'); if(_remE) _remE.checked = !!o.remunerada;
  const _benE = document.getElementById('ovr-esc-paga-beneficios'); if(_benE) _benE.checked = !!o.pagaBeneficios;
  _ovrEscTipoChange();
  document.getElementById('modal-override-escala').classList.remove('hidden');
  document.getElementById('ovr-esc-tipo').onchange = _ovrEscTipoChange;
}

async function salvarOverrideEscala(){
  const empId = _escalaEmpIdCtx();
  const emp = State.employees.find(e=>e.id===empId);
  if(!emp){ toast('Colaborador não encontrado.','error'); return; }
  const data = val('ovr-esc-data');
  if(!data){ toast('Informe a data.','warning'); return; }
  const ovrId = val('ovr-esc-id') || genId();
  const ja = (emp.overridesHorario||[]).find(o => o.id===ovrId);
  // Tambem checa duplicidade de data (uma so' override por dia)
  const conflito = (emp.overridesHorario||[]).find(o => o.data===data && o.id !== ovrId);
  if(conflito){ toast('Já existe um override para esta data — edite o existente.','error'); return; }
  const quem = (Auth.currentUser && (Auth.currentUser.username||Auth.currentUser.id))||'—';
  const tipo = val('ovr-esc-tipo')||'diferente';
  const novo = {
    id: ovrId,
    data,
    tipo, // 'diferente' | 'folga'
    horarioEntrada:  tipo==='folga' ? '' : (val('ovr-esc-entrada')||''),
    horarioRefIni:   tipo==='folga' ? '' : (val('ovr-esc-ref-ini')||''),
    horarioRefFim:   tipo==='folga' ? '' : (val('ovr-esc-ref-fim')||''),
    horarioSaida:    tipo==='folga' ? '' : (val('ovr-esc-saida')||''),
    remunerada:      tipo==='folga' ? !!document.getElementById('ovr-esc-remunerada')?.checked : false,   // folga paga o dia (vs descontar). #folga-avulsa
    pagaBeneficios:  tipo==='folga' ? !!document.getElementById('ovr-esc-paga-beneficios')?.checked : false,  // VT/VR/VA do dia. #folga-avulsa
    observacao:      val('ovr-esc-obs')||'',
    criadoEm:        ja ? ja.criadoEm : new Date().toISOString(),
    criadoPorNome:   ja ? ja.criadoPorNome : quem,
    updatedAt:       new Date().toISOString(),
  };
  emp.overridesHorario = (emp.overridesHorario||[]).filter(o => o.id !== ovrId);
  emp.overridesHorario.push(novo);
  try{
    await DB.merge('employees', emp.id, { overridesHorario: emp.overridesHorario, updatedAt: new Date().toISOString() });
    try{ Auth.log(ja?'ESCALA_OVR_EDIT':'ESCALA_OVR_NEW', null, `${emp.nome} | ${data} | ${tipo}`); }catch(_){}
    closeModal('modal-override-escala');
    toast(ja?'Dia avulso atualizado.':'Dia avulso cadastrado.','success');
    renderHorariosTab(emp.id);
  }catch(e){
    toast('Erro ao salvar: '+(e.message||e),'error');
  }
}

async function removerOverrideEscala(overrideId){
  const empId = _escalaEmpIdCtx();
  const emp = State.employees.find(e=>e.id===empId);
  if(!emp) return;
  const o = (emp.overridesHorario||[]).find(x => x.id===overrideId);
  if(!o) return;
  if(!confirm(`Remover override do dia ${_fmtDtBr(o.data)}?`)) return;
  emp.overridesHorario = (emp.overridesHorario||[]).filter(x => x.id !== overrideId);
  try{
    await DB.merge('employees', emp.id, { overridesHorario: emp.overridesHorario, updatedAt: new Date().toISOString() });
    try{ Auth.log('ESCALA_OVR_DEL', null, `${emp.nome} | ${o.data}`); }catch(_){}
    toast('Dia avulso removido.','success');
    renderHorariosTab(emp.id);
  }catch(e){ toast('Erro: '+(e.message||e),'error'); }
}

// ── Troca de plantão — lança os 4 dias avulsos (folga/trabalho espelhados) ──
// Duas pessoas trocam: quem cedeu o dia FOLGA nele; quem cobriu TRABALHA nele
// (com o horário do dono original do dia). Resolve o "falta por troca" sem
// gambiarra — usa o mesmo override (prioridade máxima) já existente.
function _horarioPlantaoDia(emp, dateStr){
  // Horário esperado do DONO do dia (o plantão que será coberto). Cai no
  // contratual da lotação vigente se a projeção não devolver horário.
  const p = (dateStr||'').split('-').map(Number);
  const exp = (p.length===3) ? _getExpectedDay(emp, p[1], p[0], p[2], true) : null;
  if(exp && exp.entrada) return { entrada:exp.entrada, saida:exp.saida||'', refIni:exp.intIni||'', refFim:exp.intFim||'' };
  const lot = _lotacaoEm(emp, dateStr);
  return {
    entrada: lot.horarioEntrada||'', saida: lot.horarioSaida||'',
    refIni: lot.semRefeicao?'':(lot.horarioRefIni||''), refFim: lot.semRefeicao?'':(lot.horarioRefFim||'')
  };
}

function abrirTrocaPlantao(empIdPre){
  if(!_podeGerirFolgasEscala()){ toast('Seu perfil não tem permissão para incluir folgas / dia avulso / troca de escala.','error'); return; }
  const ativos = (State.employees||[]).filter(e=>(e.status||'ativo')==='ativo')
    .sort((a,b)=>(a.nome||'').localeCompare(b.nome||''));
  const opts = ativos.map(e=>`<option value="${e.id}">${e.nome}${e.registro?` (${String(e.registro).padStart(4,'0')})`:''}</option>`).join('');
  const selA=document.getElementById('troca-a'), selB=document.getElementById('troca-b');
  selA.innerHTML = `<option value="">— selecione —</option>`+opts;
  selB.innerHTML = `<option value="">— selecione —</option>`+opts;
  const pre = empIdPre || _escalaEmpIdCtx() || '';
  selA.value = pre || '';
  setVal('troca-b',''); setVal('troca-dia-a',''); setVal('troca-dia-b',''); setVal('troca-obs','');
  selA.onchange=_trocaPlantaoResumo; selB.onchange=_trocaPlantaoResumo;
  document.getElementById('troca-dia-a').onchange=_trocaPlantaoResumo;
  document.getElementById('troca-dia-b').onchange=_trocaPlantaoResumo;
  _trocaPlantaoResumo();
  document.getElementById('modal-troca-plantao').classList.remove('hidden');
}

function _trocaPlantaoResumo(){
  const el=document.getElementById('troca-resumo'); if(!el) return;
  const A=(State.employees||[]).find(e=>e.id===val('troca-a'));
  const B=(State.employees||[]).find(e=>e.id===val('troca-b'));
  const dA=val('troca-dia-a'), dB=val('troca-dia-b');
  if(!A||!B||!dA||!dB){
    el.innerHTML='<span style="color:#888"><i class="fa-solid fa-arrow-up"></i> Preencha os dois colaboradores e os dois dias para ver o resumo da troca.</span>';
    return;
  }
  if(A.id===B.id){ el.innerHTML='<span style="color:#C62828">Selecione colaboradores diferentes.</span>'; return; }
  const nA=(A.nome||'').split(' ')[0], nB=(B.nome||'').split(' ')[0];
  const F='<span style="color:#7e22ce;font-weight:700">FOLGA</span>', T='<span style="color:#1B5E20;font-weight:700">TRABALHA</span>';
  el.innerHTML =
    `<div><i class="fa-solid fa-user" style="color:#6D28D9"></i> <strong>${nA}</strong>: ${F} em ${_fmtDtBr(dA)} &middot; ${T} em ${_fmtDtBr(dB)}</div>`+
    `<div><i class="fa-solid fa-user" style="color:#6D28D9"></i> <strong>${nB}</strong>: ${T} em ${_fmtDtBr(dA)} &middot; ${F} em ${_fmtDtBr(dB)}</div>`;
}

async function salvarTrocaPlantao(){
  const A=(State.employees||[]).find(e=>e.id===val('troca-a'));
  const B=(State.employees||[]).find(e=>e.id===val('troca-b'));
  const dA=val('troca-dia-a'), dB=val('troca-dia-b');
  const obs=(val('troca-obs')||'').trim();
  if(!A||!B){ toast('Selecione os dois colaboradores.','warning'); return; }
  if(A.id===B.id){ toast('Selecione colaboradores diferentes.','warning'); return; }
  if(!dA||!dB){ toast('Informe os dois dias da troca.','warning'); return; }
  if(dA===dB){ toast('Os dois dias da troca devem ser diferentes.','warning'); return; }
  const quem=(Auth.currentUser&&(Auth.currentUser.username||Auth.currentUser.id))||'—';
  const nowISO=new Date().toISOString();
  const obsBase = obs || `Troca de plantão: ${(A.nome||'').split(' ')[0]} ↔ ${(B.nome||'').split(' ')[0]}`;
  // Horário do dono original de cada dia (o plantão que está sendo coberto).
  const hDiaA=_horarioPlantaoDia(A, dA);  // dia dA é da A → quem cobre usa o horário de A
  const hDiaB=_horarioPlantaoDia(B, dB);  // dia dB é da B → quem cobre usa o horário de B
  // 4 lançamentos: A folga em dA / trabalha em dB ; B trabalha em dA / folga em dB.
  const lancamentos=[
    { emp:A, data:dA, tipo:'folga',     hor:null  },
    { emp:A, data:dB, tipo:'diferente', hor:hDiaB },
    { emp:B, data:dA, tipo:'diferente', hor:hDiaA },
    { emp:B, data:dB, tipo:'folga',     hor:null  },
  ];
  const conflitos=[];
  for(const l of lancamentos){
    const ja=(l.emp.overridesHorario||[]).find(o=>o.data===l.data);
    if(ja) conflitos.push(`${l.emp.nome} em ${_fmtDtBr(l.data)}`);
  }
  if(conflitos.length && !confirm(`Já existe dia avulso em:\n• ${conflitos.join('\n• ')}\n\nSubstituir pelos lançamentos da troca?`)) return;
  for(const l of lancamentos){
    const novo={
      id: genId(), data:l.data, tipo:l.tipo,
      horarioEntrada: l.hor?l.hor.entrada:'', horarioSaida: l.hor?l.hor.saida:'',
      horarioRefIni:  l.hor?l.hor.refIni:'',  horarioRefFim: l.hor?l.hor.refFim:'',
      observacao: obsBase, criadoEm: nowISO, criadoPorNome: quem, updatedAt: nowISO,
      trocaPlantao: true,
    };
    l.emp.overridesHorario=(l.emp.overridesHorario||[]).filter(o=>o.data!==l.data);
    l.emp.overridesHorario.push(novo);
  }
  try{
    await DB.merge('employees', A.id, { overridesHorario:A.overridesHorario, updatedAt:nowISO });
    await DB.merge('employees', B.id, { overridesHorario:B.overridesHorario, updatedAt:nowISO });
    try{ Auth.log('TROCA_PLANTAO', null, `${A.nome} ${dA} ↔ ${dB} ${B.nome}`); }catch(_){}
    closeModal('modal-troca-plantao');
    toast('Troca registrada — 4 dias avulsos lançados. Rode "Recalcular faltas" da competência p/ atualizar.','success');
    const cur=_escalaEmpIdCtx();
    if(cur===A.id||cur===B.id) renderHorariosTab(cur);
    // Espelha no Ponto Manual se o colaborador em foco lá é um dos envolvidos.
    const _pm=document.getElementById('modal-ponto-manual');
    if(_pm && !_pm.classList.contains('hidden')){ const pe=val('payroll-employee'); if(pe===A.id||pe===B.id) _renderAjustesEscalaPonto(pe); }
  }catch(e){ toast('Erro ao salvar a troca: '+(e.message||e),'error'); }
}

// Mini-modal flutuante reutilizavel (igual ao de stats)
function _showFloatingModal(titulo, htmlConteudo){
  const old = document.getElementById('modal-floating-disc');
  if(old) old.remove();
  const div = document.createElement('div');
  div.id = 'modal-floating-disc';
  div.className = 'modal-overlay';
  div.style.zIndex = '11000';
  div.onclick = (ev) => { if(ev.target===div) div.remove(); };
  div.innerHTML = `
    <div class="modal-dialog" style="max-width:680px;width:95%">
      <div class="modal-header">
        <h3>${titulo}</h3>
        <button class="modal-close" onclick="document.getElementById('modal-floating-disc').remove()"><i class="fa-solid fa-xmark"></i></button>
      </div>
      <div class="modal-body" style="padding:0">${htmlConteudo}</div>
    </div>`;
  document.body.appendChild(div);
}

// Anula um ato disciplinar — SOFT DELETE, nao apaga. O registro permanece
// arquivado com marca de "ANULADA", motivo, quem e quando. A mensagem
// correspondente em "comunicacoes" e' apagada (some do app do colaborador)
// mas o snapshot em "auditoria_disciplina" fica intacto (write-once).
// Isso preserva a trilha jurídica — voce sempre consegue provar que
// existiu o ato, quem o anulou, quando e por que.
async function anularDisciplina(discId){
  const mods = getUserModules(Auth.currentUser);
  if(!mods.disciplinaApagar && Auth.currentUser?.role!=='master'){
    toast('Sem permissão para anular atos disciplinares.','error'); return;
  }
  let snap;
  try{ snap = await firebase.firestore().collection('disciplina').doc(discId).get(); }
  catch(e){ toast('Erro ao buscar registro: '+(e.message||e),'error'); return; }
  if(!snap.exists){ toast('Registro nao encontrado.','error'); return; }
  const d = snap.data();
  if(d.anulada){ toast('Este ato ja foi anulado.','warning'); return; }
  const tipoLabel = d.tipo==='advertencia' ? 'advertência' : 'suspensão';
  if(!confirm(`Anular esta ${tipoLabel}?\n\nColaborador: ${d.employeeNome||'—'}\nMotivo original: ${d.motivo||'—'}\n\nA medida vai aparecer como ANULADA na aba Disciplina (registro mantido para auditoria). A mensagem some do app do colaborador.`)) return;
  const motivoAnul = (prompt('Motivo da anulação (obrigatorio — sera arquivado para auditoria):')||'').trim();
  if(!motivoAnul){ toast('Anulação cancelada — o motivo é obrigatório.','warning'); return; }
  const agora = new Date().toISOString();
  const quem  = (Auth.currentUser && (Auth.currentUser.username||Auth.currentUser.id))||'—';
  const quemId= (Auth.currentUser && Auth.currentUser.id)||'';
  try{
    // 1. Marca como anulada (soft delete) — mantem o registro
    await DB.merge('disciplina', discId, {
      anulada: true,
      anuladaEm: agora,
      anuladaPorId: quemId,
      anuladaPorNome: quem,
      motivoAnulacao: motivoAnul,
      updatedAt: agora,
    });
    // 2. Apaga a mensagem do app do colaborador (some da aba Avisos dele)
    if(d.comunicacaoId){
      try{ await DB.remove('comunicacoes', d.comunicacaoId); }catch(_){}
    }
    // 3. Snapshot do evento na auditoria imutavel
    try{
      await DB.save('auditoria_disciplina', _sanitizeForFirestore({
        id: genId(),
        disciplinaId: discId,
        employeeId: d.employeeId,
        tipo: d.tipo,
        evento: 'ANULACAO',
        motivoAnulacao: motivoAnul,
        anuladaEm: agora,
        anuladaPorId: quemId,
        anuladaPorNome: quem,
        snapshotOriginal: d,
        criadoEm: agora,
      }));
    }catch(_){}
    try{ Auth.log('DISCIPLINA_ANULADA', null, `${d.tipo.toUpperCase()} — ${d.employeeNome||''} — Motivo: ${motivoAnul}`); }catch(_){}
    toast(`${tipoLabel.charAt(0).toUpperCase()+tipoLabel.slice(1)} anulada. Registro mantido para auditoria.`,'success');
    renderDisciplinaTab(d.employeeId);
  }catch(e){
    toast('Erro ao anular: '+(e.message||e),'error');
  }
}

// Apaga uma mensagem da coleção comunicacoes. Sumirá do app do colaborador
// na próxima vez que ele abrir a aba Avisos (cache é invalidado por navTo).
async function apagarComunicacao(msgId){
  if(!getUserModules(Auth.currentUser).comunicacoesApagar && Auth.currentUser?.role!=='master'){
    toast('Sem permissão para apagar mensagens.','error'); return;
  }
  const m = _comuMensagensCache[msgId];
  const assuntoTxt = (m && m.assunto) || msgId;
  if(!confirm(`Apagar a mensagem "${assuntoTxt}"?\n\nEla também sumirá do app do colaborador.`)) return;
  try{
    await DB.remove('comunicacoes', msgId);
    try{ Auth.log('COMUNICACAO_APAGADA', null, `${(m&&m.employeeNome)||''} — ${assuntoTxt}`); }catch(_){}
    delete _comuMensagensCache[msgId];
    toast('Mensagem apagada.','success');
    const eid = val('emp-id');
    if(eid) renderComunicacoesTab(eid);
  }catch(e){
    toast('Erro ao apagar: '+(e.message||e),'error');
  }
}

function _comuRenderDest(){
  const box=document.getElementById('comu-dest-list');
  const cnt=document.getElementById('comu-dest-count');
  if(cnt) cnt.textContent=_comuDestinatarios.length;
  if(!box) return;
  if(!_comuDestinatarios.length){
    box.innerHTML='<span style="font-size:12px;color:#999;padding:4px 0">Nenhum destinatário</span>';
    return;
  }
  box.innerHTML=_comuDestinatarios.map(id=>{
    const e=State.employees.find(x=>x.id===id);
    const nome=(e&&e.nome)||id;
    // Em modo edição, nao mostra o "×" para nao deixar o usuario trocar de destinatario.
    const closeBtn = _comuEditandoId ? '' : `<button type="button" onclick="_comuRemoveDest('${id}')" title="Remover" style="background:none;border:none;color:#c62828;cursor:pointer;font-size:13px;line-height:1;padding:0">×</button>`;
    return `<span style="background:#fff;border:1px solid var(--border);border-radius:14px;padding:4px 10px;font-size:12px;display:inline-flex;align-items:center;gap:6px">
      ${nome}
      ${closeBtn}
    </span>`;
  }).join('');
}

function _comuAddDest(){
  const sel=document.getElementById('comu-add-emp'); if(!sel) return;
  const id=sel.value; if(!id) return;
  if(!_comuDestinatarios.includes(id)) _comuDestinatarios.push(id);
  sel.value='';
  _comuRenderDest();
}
function _comuRemoveDest(id){
  _comuDestinatarios=_comuDestinatarios.filter(x=>x!==id);
  _comuRenderDest();
}
function _comuAddTodos(){
  (State.employees||[]).filter(e=>(e.status||'ativo')==='ativo').forEach(e=>{
    if(!_comuDestinatarios.includes(e.id)) _comuDestinatarios.push(e.id);
  });
  _comuRenderDest();
}
function _comuLimparDest(){ _comuDestinatarios=[]; _comuRenderDest(); }

// ── Selecao em massa por filtro (posto, setor, escala) ─────────────────────
// Pega valores unicos do campo escolhido entre os ativos, abre um prompt
// para escolher (lista numerada) e adiciona todos do(s) selecionado(s).
// Modal visual de selecao multipla — substitui o prompt() horroroso.
// Recebe titulo, lista de {value, label} e callback com os values escolhidos.
function _abrirSelecaoMultipla(titulo, opcoes, onConfirm){
  const old = document.getElementById('modal-sel-mult');
  if(old) old.remove();
  if(!opcoes || !opcoes.length){
    toast('Nenhuma opção disponível.','warning');
    return;
  }
  const m = document.createElement('div');
  m.id = 'modal-sel-mult';
  m.className = 'modal-overlay';
  m.style.zIndex = '10500';
  m.onclick = ev => { if(ev.target===m) m.remove(); };
  const linhas = opcoes.map((o,i) => `
    <label style="display:flex;align-items:center;gap:10px;padding:10px 14px;cursor:pointer;border-bottom:1px solid #f1f5f9;transition:background .12s"
           onmouseover="this.style.background='#f8fafc'" onmouseout="this.style.background=''">
      <input type="checkbox" class="sel-mult-opt" value="${o.value.replace(/"/g,'&quot;')}" data-idx="${i}" style="width:18px;height:18px;cursor:pointer;flex-shrink:0">
      <span style="font-size:14px;color:#1e293b;flex:1">${o.label.replace(/</g,'&lt;')}</span>
    </label>`).join('');
  m.innerHTML = `
    <div class="modal-dialog" style="max-width:520px;width:95%;display:flex;flex-direction:column;max-height:85vh">
      <div class="modal-header">
        <h3 style="font-size:16px;color:#1e293b"><i class="fa-solid fa-list-check" style="color:#1976D2"></i> ${titulo}</h3>
        <button class="modal-close" onclick="document.getElementById('modal-sel-mult').remove()"><i class="fa-solid fa-xmark"></i></button>
      </div>
      <div style="padding:10px 14px;border-bottom:1px solid #e2e8f0;display:flex;gap:8px;align-items:center;flex-wrap:wrap">
        <button type="button" class="btn btn-sm btn-outline" onclick="_selMultMarcarTodos(true)" style="font-size:12px">
          <i class="fa-regular fa-square-check"></i> Marcar todos
        </button>
        <button type="button" class="btn btn-sm btn-outline" onclick="_selMultMarcarTodos(false)" style="font-size:12px">
          <i class="fa-regular fa-square"></i> Desmarcar todos
        </button>
        <span id="sel-mult-cnt" style="margin-left:auto;font-size:12px;color:#666">0 / ${opcoes.length} selecionado(s)</span>
      </div>
      <div id="sel-mult-list" style="overflow-y:auto;flex:1;min-height:120px">${linhas}</div>
      <div class="modal-footer" style="border-top:1px solid #e2e8f0;padding:12px 14px;display:flex;gap:8px;justify-content:flex-end">
        <button type="button" class="btn btn-outline" onclick="document.getElementById('modal-sel-mult').remove()">Cancelar</button>
        <button type="button" class="btn btn-primary" id="sel-mult-ok"><i class="fa-solid fa-check"></i> Confirmar</button>
      </div>
    </div>`;
  document.body.appendChild(m);
  // Atualiza contador conforme marca/desmarca
  const atualizarCnt = () => {
    const n = m.querySelectorAll('.sel-mult-opt:checked').length;
    document.getElementById('sel-mult-cnt').textContent = `${n} / ${opcoes.length} selecionado(s)`;
  };
  m.querySelectorAll('.sel-mult-opt').forEach(cb => cb.addEventListener('change', atualizarCnt));
  document.getElementById('sel-mult-ok').addEventListener('click', () => {
    const escolhidos = [...m.querySelectorAll('.sel-mult-opt:checked')].map(cb => cb.value);
    if(!escolhidos.length){ toast('Marque pelo menos uma opção.','warning'); return; }
    m.remove();
    onConfirm(escolhidos);
  });
}
function _selMultMarcarTodos(marcar){
  document.querySelectorAll('#modal-sel-mult .sel-mult-opt').forEach(cb => cb.checked = !!marcar);
  const n = document.querySelectorAll('#modal-sel-mult .sel-mult-opt:checked').length;
  const tot = document.querySelectorAll('#modal-sel-mult .sel-mult-opt').length;
  document.getElementById('sel-mult-cnt').textContent = `${n} / ${tot} selecionado(s)`;
}

// Adicionar destinatarios filtrando por um campo do cadastro (posto, setor).
function _comuAddPorCampo(campo, rotulo){
  const ativos = (State.employees||[]).filter(e=>(e.status||'ativo')==='ativo');
  const valores = [...new Set(ativos.map(e => (e[campo]||'').toString().trim()).filter(Boolean))]
    .sort((a,b)=>a.localeCompare(b,'pt-BR'));
  if(!valores.length){
    toast(`Nenhum colaborador ativo com ${rotulo} informado.`,'warning');
    return;
  }
  const opcoes = valores.map(v => ({ value:v, label:v }));
  _abrirSelecaoMultipla(`Selecionar por ${rotulo}`, opcoes, (escolhidos) => {
    let n = 0;
    ativos.forEach(e=>{
      if(escolhidos.includes((e[campo]||'').toString().trim())){
        if(!_comuDestinatarios.includes(e.id)){ _comuDestinatarios.push(e.id); n++; }
      }
    });
    _comuRenderDest();
    toast(`${n} colaborador(es) adicionado(s) (${rotulo}: ${escolhidos.join(', ')}).`,'success');
  });
}
function _comuAddPorPosto() { _comuAddPorCampo('posto', 'Posto de trabalho'); }
function _comuAddPorSetor() { _comuAddPorCampo('setor', 'Setor'); }
function _comuAddPorEscala(){
  const ativos = (State.employees||[]).filter(e=>(e.status||'ativo')==='ativo');
  const codigos = [...new Set(ativos.map(e => (e.escala||'').toString().trim()).filter(Boolean))]
    .sort((a,b)=>a.localeCompare(b));
  if(!codigos.length){ toast('Nenhum colaborador ativo com escala informada.','warning'); return; }
  const opcoes = codigos.map(c => ({ value:c, label: `${escalaLabel(c)} (${c})` }));
  _abrirSelecaoMultipla('Selecionar por Escala', opcoes, (escolhidos) => {
    let n = 0;
    ativos.forEach(e=>{
      if(escolhidos.includes((e.escala||'').toString().trim())){
        if(!_comuDestinatarios.includes(e.id)){ _comuDestinatarios.push(e.id); n++; }
      }
    });
    _comuRenderDest();
    toast(`${n} colaborador(es) adicionado(s).`,'success');
  });
}

// Classifica o turno do colaborador conforme o horario de entrada cadastrado:
//   Madrugada: entrada 00:00-05:59
//   Manha:     entrada 06:00-11:59
//   Tarde:     entrada 12:00-17:59
//   Noite:     entrada 18:00-23:59 ou turnoNoturno=true
//   Indefinido: sem horario cadastrado
function _classificarTurno(emp){
  if(!emp) return 'Indefinido';
  if(emp.turnoNoturno) return 'Noite';
  const ent = (emp.horarioEntrada||'').toString().trim();
  if(!ent || !ent.includes(':')) return 'Indefinido';
  const h = parseInt(ent.split(':')[0], 10);
  if(isNaN(h)) return 'Indefinido';
  if(h >= 0  && h <  6) return 'Madrugada';
  if(h >= 6  && h < 12) return 'Manhã';
  if(h >= 12 && h < 18) return 'Tarde';
  return 'Noite';
}
const _TURNO_ICON = { 'Madrugada':'🌙', 'Manhã':'🌅', 'Tarde':'☀️', 'Noite':'🌃', 'Indefinido':'❓' };

function _comuAddPorTurno(){
  const ativos = (State.employees||[]).filter(e=>(e.status||'ativo')==='ativo');
  // Conta quantos cada turno tem (so' mostra turnos que ja existem)
  const map = {};
  ativos.forEach(e => {
    const t = _classificarTurno(e);
    map[t] = (map[t]||0) + 1;
  });
  const ordem = ['Madrugada','Manhã','Tarde','Noite','Indefinido'];
  const opcoes = ordem.filter(t => map[t]).map(t => ({
    value: t,
    label: `${_TURNO_ICON[t]||''} ${t}  (${map[t]} colaborador${map[t]!==1?'es':''})`
  }));
  if(!opcoes.length){ toast('Nenhum colaborador ativo encontrado.','warning'); return; }
  _abrirSelecaoMultipla('Selecionar por Turno', opcoes, (escolhidos) => {
    let n = 0;
    ativos.forEach(e=>{
      if(escolhidos.includes(_classificarTurno(e))){
        if(!_comuDestinatarios.includes(e.id)){ _comuDestinatarios.push(e.id); n++; }
      }
    });
    _comuRenderDest();
    toast(`${n} colaborador(es) adicionado(s) (turno: ${escolhidos.join(', ')}).`,'success');
  });
}

// ── FILTRO AVANCADO — combina varias dimensoes em UM unico envio ─────────
// AND entre dimensoes, OR dentro de cada dimensao. Exemplo:
//   Turno: [Noite] + Escala: [12x36, 6x1A] + Posto: [todos]
//   = quem trabalha a noite E (esta em 12x36 OU 6x1A) E em qualquer posto.
// Dimensao sem nada marcado = "qualquer" (nao restringe).
function _comuAddFiltroAvancado(){
  const ativos = (State.employees||[]).filter(e=>(e.status||'ativo')==='ativo');
  if(!ativos.length){ toast('Sem colaboradores ativos.','warning'); return; }
  // Calcula opcoes para cada dimensao
  const turnos = [...new Set(ativos.map(e=>_classificarTurno(e)))]
    .sort((a,b)=>['Madrugada','Manhã','Tarde','Noite','Indefinido'].indexOf(a) - ['Madrugada','Manhã','Tarde','Noite','Indefinido'].indexOf(b));
  const escalas = [...new Set(ativos.map(e=>(e.escala||'').trim()).filter(Boolean))].sort();
  const postos = [...new Set(ativos.map(e=>(e.posto||'').trim()).filter(Boolean))].sort((a,b)=>a.localeCompare(b,'pt-BR'));
  const setores= [...new Set(ativos.map(e=>(e.setor||'').trim()).filter(Boolean))].sort((a,b)=>a.localeCompare(b,'pt-BR'));
  const old = document.getElementById('modal-filtro-av');
  if(old) old.remove();
  const m = document.createElement('div');
  m.id = 'modal-filtro-av';
  m.className = 'modal-overlay';
  m.style.zIndex = '10500';
  m.onclick = ev => { if(ev.target===m) m.remove(); };
  const secao = (titulo, icone, key, opts) => `
    <div style="margin-bottom:12px">
      <div style="font-size:12px;font-weight:700;color:#475569;margin-bottom:6px;text-transform:uppercase;letter-spacing:.4px">${icone} ${titulo}</div>
      <div style="background:#f8fafc;border:1px solid #e2e8f0;border-radius:8px;max-height:160px;overflow-y:auto">
        ${opts.length === 0
          ? `<div style="padding:10px;font-size:12px;color:#94a3b8;text-align:center">Nenhum valor</div>`
          : opts.map(o => `
            <label style="display:flex;align-items:center;gap:8px;padding:7px 10px;cursor:pointer;border-bottom:1px solid #f1f5f9;font-size:13px"
                   onmouseover="this.style.background='#fff'" onmouseout="this.style.background=''">
              <input type="checkbox" class="fav-${key}" value="${o.replace(/"/g,'&quot;')}" style="width:16px;height:16px;cursor:pointer">
              <span>${o.replace(/</g,'&lt;')}${key==='escala' ? ` <span style="color:#94a3b8;font-size:11px">(${escalaLabel(o)})</span>`:''}</span>
            </label>`).join('')}
      </div>
    </div>`;
  m.innerHTML = `
    <div class="modal-dialog" style="max-width:640px;width:95%;display:flex;flex-direction:column;max-height:90vh">
      <div class="modal-header">
        <h3 style="font-size:16px;color:#1e293b"><i class="fa-solid fa-filter" style="color:#7c3aed"></i> Filtro avançado — combinar critérios</h3>
        <button class="modal-close" onclick="document.getElementById('modal-filtro-av').remove()"><i class="fa-solid fa-xmark"></i></button>
      </div>
      <div style="padding:12px 16px;background:#faf5ff;border-bottom:1px solid #e9d5ff;font-size:12px;color:#6b21a8;line-height:1.5">
        <strong>Como funciona:</strong> dentro de uma seção, marca o que quer incluir (OR).
        Entre seções, o sistema cruza tudo (AND). Seção sem nada marcado = qualquer valor (não restringe).
      </div>
      <div style="padding:14px 16px;overflow-y:auto;flex:1">
        ${secao('Turno (baseado no horário de entrada)', '⏰', 'turno',  turnos.map(t=>`${_TURNO_ICON[t]||''} ${t}`))}
        ${secao('Escala', '📅', 'escala', escalas)}
        ${secao('Posto de trabalho', '🏢', 'posto',  postos)}
        ${secao('Setor', '🌐', 'setor',  setores)}
      </div>
      <div class="modal-footer" style="border-top:1px solid #e2e8f0;padding:12px 16px;display:flex;gap:8px;justify-content:space-between;align-items:center;flex-wrap:wrap">
        <div id="fav-preview" style="font-size:12px;color:#666;flex:1;min-width:160px">Selecione critérios para ver a prévia</div>
        <div style="display:flex;gap:8px">
          <button type="button" class="btn btn-outline" onclick="document.getElementById('modal-filtro-av').remove()">Cancelar</button>
          <button type="button" class="btn btn-primary" id="fav-aplicar"><i class="fa-solid fa-check"></i> Aplicar filtro</button>
        </div>
      </div>
    </div>`;
  document.body.appendChild(m);
  // Calcula prevista de quem cai no filtro a cada mudanca
  const calcular = () => {
    const sel = {
      turno:  [...m.querySelectorAll('.fav-turno:checked')].map(cb => cb.value.replace(/^[^a-zA-ZÀ-ÿ]+/, '').trim()),
      escala: [...m.querySelectorAll('.fav-escala:checked')].map(cb => cb.value),
      posto:  [...m.querySelectorAll('.fav-posto:checked')].map(cb => cb.value),
      setor:  [...m.querySelectorAll('.fav-setor:checked')].map(cb => cb.value),
    };
    const algumMarcado = sel.turno.length+sel.escala.length+sel.posto.length+sel.setor.length > 0;
    const matches = ativos.filter(e => {
      if(sel.turno.length  && !sel.turno.includes(_classificarTurno(e))) return false;
      if(sel.escala.length && !sel.escala.includes((e.escala||'').trim())) return false;
      if(sel.posto.length  && !sel.posto.includes((e.posto||'').trim())) return false;
      if(sel.setor.length  && !sel.setor.includes((e.setor||'').trim())) return false;
      return true;
    });
    const prevEl = document.getElementById('fav-preview');
    if(!algumMarcado){
      prevEl.innerHTML = `<span style="color:#94a3b8">Selecione critérios para ver a prévia</span>`;
    } else {
      prevEl.innerHTML = `<i class="fa-solid fa-users" style="color:#7c3aed"></i> <strong>${matches.length}</strong> colaborador${matches.length!==1?'es':''} atende${matches.length===1?'':'m'} o filtro`;
    }
    return matches;
  };
  m.querySelectorAll('input[type=checkbox]').forEach(cb => cb.addEventListener('change', calcular));
  document.getElementById('fav-aplicar').addEventListener('click', () => {
    const matches = calcular();
    const sel = {
      turno:  [...m.querySelectorAll('.fav-turno:checked')].length,
      escala: [...m.querySelectorAll('.fav-escala:checked')].length,
      posto:  [...m.querySelectorAll('.fav-posto:checked')].length,
      setor:  [...m.querySelectorAll('.fav-setor:checked')].length,
    };
    const algumMarcado = sel.turno+sel.escala+sel.posto+sel.setor > 0;
    if(!algumMarcado){ toast('Marque ao menos um critério.','warning'); return; }
    if(!matches.length){ toast('Nenhum colaborador atende a esse filtro.','warning'); return; }
    let n = 0;
    matches.forEach(e => {
      if(!_comuDestinatarios.includes(e.id)){ _comuDestinatarios.push(e.id); n++; }
    });
    m.remove();
    _comuRenderDest();
    toast(`${n} colaborador(es) adicionado(s) pelo filtro avançado.`,'success');
  });
}

// ── Editor rico da Comunicação (negrito/itálico/sublinhado/alinhamento/fonte) ──
function _rtbCmd(cmd, valArg){
  const ed=document.getElementById('comu-corpo'); if(!ed) return;
  ed.focus();
  try{ document.execCommand(cmd, false, valArg!=null?valArg:undefined); }catch(_){}
}
// Sanitiza o HTML da mensagem: mantém só formatação segura, remove script/eventos/etc.
function _sanitizeMsgHtml(html){
  if(!html) return '';
  const tpl=document.createElement('template'); tpl.innerHTML=String(html);
  const OK=new Set(['B','STRONG','I','EM','U','BR','P','DIV','SPAN','UL','OL','LI','FONT']);
  const STYLE_OK=/^(text-align|font-weight|font-style|text-decoration|font-size)\s*:/i;
  const walk=(node)=>{
    [...node.childNodes].forEach(ch=>{
      if(ch.nodeType===1){
        if(!OK.has(ch.tagName)){ while(ch.firstChild) node.insertBefore(ch.firstChild, ch); node.removeChild(ch); return; }
        [...ch.attributes].forEach(a=>{
          const n=a.name.toLowerCase();
          if(n==='style'){
            const safe=(a.value||'').split(';').map(s=>s.trim()).filter(s=>STYLE_OK.test(s)).join('; ');
            if(safe) ch.setAttribute('style', safe); else ch.removeAttribute('style');
          } else if(n==='size' && ch.tagName==='FONT'){ /* mantém o size do <font> */ }
          else ch.removeAttribute(a.name);
        });
        walk(ch);
      } else if(ch.nodeType===8){ node.removeChild(ch); }
    });
  };
  walk(tpl.content);
  return tpl.innerHTML;
}
// HTML pronto pra EXIBIR o corpo: sanitiza; texto antigo (sem tags) vira nl2br.
function _corpoHtml(corpo){
  const s=_sanitizeMsgHtml(corpo||'');
  if(!/[<]/.test(String(corpo||''))) return s.replace(/\n/g,'<br>');
  return s;
}
// Texto puro do corpo (p/ prévia de notificação e busca).
function _corpoTexto(corpo){ return String(corpo||'').replace(/<br\s*\/?>(?=)/gi,' ').replace(/<[^>]+>/g,' ').replace(/&nbsp;/g,' ').replace(/\s+/g,' ').trim(); }
function _comuSetCorpo(html){ const ed=document.getElementById('comu-corpo'); if(ed) ed.innerHTML=_corpoHtml(html); }
function _comuGetCorpo(){ const ed=document.getElementById('comu-corpo'); return ed?_sanitizeMsgHtml(ed.innerHTML):''; }
function _comuCorpoVazio(){ const ed=document.getElementById('comu-corpo'); return !ed || !(ed.textContent||'').replace(/ /g,'').trim(); }

async function enviarComunicacao(){
  const ids=[..._comuDestinatarios];
  if(!ids.length){ toast('Adicione ao menos um destinatário.','warning'); return; }
  const assunto=(val('comu-assunto')||'').trim();
  if(!assunto){ toast('Informe o assunto.','warning'); return; }
  if(_comuCorpoVazio()){ toast('Escreva a mensagem.','warning'); return; }
  const corpo=_comuGetCorpo();
  const tipo=(val('comu-tipo')||'normal').toLowerCase();
  const ehDisciplina = (tipo==='advertencia' || tipo==='suspensao');
  const fi=document.getElementById('comu-anexo');
  const file=fi && fi.files && fi.files[0] ? fi.files[0] : null;
  if(file && file.size > 10*1024*1024){ toast('Anexo grande demais (máx. 10 MB).','error'); return; }
  // Disciplina exige anexo (nao reaproveita herdado para nao bagunçar cadeia)
  if(ehDisciplina && !file){
    toast('Para advertência/suspensão é obrigatório anexar o documento.','error'); return;
  }
  // Disciplina nao deve ser enviada em massa (uma por colaborador, com ato proprio)
  if(ehDisciplina && ids.length > 1){
    toast('Advertência/suspensão deve ser enviada individualmente (1 colaborador por envio).','error'); return;
  }
  const motivoDisc = ehDisciplina ? (val('comu-disc-motivo')||'').trim() : '';
  if(ehDisciplina && !motivoDisc){ toast('Informe o motivo da medida disciplinar.','error'); return; }
  const diasSusp = (tipo==='suspensao') ? parseInt(val('comu-disc-dias')||'0',10) : 0;
  if(tipo==='suspensao' && (!diasSusp || diasSusp<1)){ toast('Informe os dias de suspensão (1 ou mais).','error'); return; }
  const artigoCLT = ehDisciplina ? (val('comu-disc-artigo')||'').trim() : '';

  const btn=document.getElementById('comu-enviar');
  setBtnLoading(btn,true,'');
  try{
    let anexoUrl='', anexoNome='', anexoTipo='', anexoHash='';
    if(file){
      // Calcula SHA-256 ANTES do upload — assim o hash representa exatamente
      // o que o gestor anexou (cadeia de custodia comeca aqui).
      if(ehDisciplina){
        try{ anexoHash = await _sha256Hex(file); }
        catch(e){ console.error('sha256', e); toast('Erro ao calcular hash do anexo.','error'); setBtnLoading(btn,false,''); return; }
      }
      const ext=(file.name.split('.').pop()||'bin').toLowerCase();
      const refId=Date.now().toString(36)+Math.random().toString(36).slice(2,8);
      const ref=DB.storageRef(`comunicacoes/${refId}.${ext}`);
      await ref.put(file);
      anexoUrl=await ref.getDownloadURL();
      anexoNome=file.name;
      anexoTipo=file.type||'';
    } else if(_comuAnexoHerdado){
      // reenviar: reaproveita o anexo da mensagem original (sem novo upload)
      anexoUrl  = _comuAnexoHerdado.url;
      anexoNome = _comuAnexoHerdado.nome;
      anexoTipo = _comuAnexoHerdado.tipo;
    }
    const quem=(Auth.currentUser && (Auth.currentUser.username||Auth.currentUser.id))||'—';
    const quemId=(Auth.currentUser && Auth.currentUser.id)||'';
    const agora=new Date().toISOString();

    // MODO EDIÇÃO — atualiza a mensagem original (mantém destinatário, reações e datas).
    // Reseta o "lida" para que a versão editada seja sinalizada como nao-vista
    // ate o colaborador abrir a aba Avisos de novo.
    if(_comuEditandoId){
      const changes = {
        assunto, corpo,
        anexoUrl, anexoNome, anexoTipo,
        editadoEm: agora,
        editadoPorNome: quem,
        lida: false,
        lidaEm: '',
        updatedAt: agora,
      };
      try{
        await DB.merge('comunicacoes', _comuEditandoId, changes);
        try{ Auth.log('COMUNICACAO_EDITADA', null, `${assunto}`); }catch(_){}
        toast('Mensagem atualizada.','success');
        closeModal('modal-comunicar');
        const m=document.getElementById('modal-employee');
        if(m && !m.classList.contains('hidden')){
          const eid=val('emp-id');
          if(eid) renderComunicacoesTab(eid);
        }
      }catch(e){
        toast('Erro ao atualizar: '+(e.message||e),'error');
      }finally{
        setBtnLoading(btn,false,'');
      }
      return;
    }

    let ok=0;
    // Quando for disciplina, ja' sabemos que ids tem exatamente 1 elemento.
    let disciplinaCriada = null;
    for(const empId of ids){
      const e=State.employees.find(x=>x.id===empId);
      const msgId = genId();
      const discId = ehDisciplina ? genId() : '';   // ligação reversa msg→ato p/ sincronizar visualização. #disciplina-sync-visualizacao
      // Hash da mensagem disciplinar (assunto + corpo + hash do anexo +
      // timestamp + autor + colaborador) — preserva a integridade do conjunto.
      let mensagemHash = '';
      if(ehDisciplina){
        const payloadParaHash = JSON.stringify({
          tipo, assunto, corpo, motivoDisc, diasSusp, artigoCLT,
          anexoHash, anexoNome,
          employeeId: empId,
          employeeNome: (e&&e.nome)||'',
          origemUserId: quemId,
          origemUserNome: quem,
          criadoEm: agora,
        });
        try{ mensagemHash = await _sha256Hex(payloadParaHash); }catch(_){}
      }
      const msg={
        id: msgId,
        employeeId: empId,
        employeeNome: (e&&e.nome)||'',
        assunto, corpo,
        tipo,
        anexoUrl, anexoNome, anexoTipo,
        origemUserId: quemId,
        origemUserNome: quem,
        criadoEm: agora,
        lida: false,
      };
      if(ehDisciplina){
        msg.anexoHash = anexoHash;
        msg.mensagemHash = mensagemHash;
        msg.motivoDisciplina = motivoDisc;
        msg.diasSuspensao = diasSusp;
        msg.artigoCLT = artigoCLT;
        msg.disciplinaId = discId;   // ← ao ler esta msg no app, o ato disciplinar é marcado visualizado
      }
      try{ await DB.save('comunicacoes', _sanitizeForFirestore(msg)); ok++; }
      catch(err){ console.error('Erro ao salvar comunicacao', err); continue; }

      // Para disciplina: criar registro em "disciplina" + snapshot em
      // "auditoria_disciplina" + recibo de envio em HTML/PDF.
      if(ehDisciplina){
        const reciboHtml = _gerarReciboEnvioHTML({
          discId,
          tipo,
          empNome: (e&&e.nome)||'',
          empMatricula: (e&&e.registro) ? String(e.registro).padStart(4,'0') : '—',
          empCpf: (e&&e.cpf)||'—',
          empCargo: (e&&e.cargo)||'—',
          empPosto: (e&&e.posto)||'—',
          assunto, corpo, motivoDisc, diasSusp, artigoCLT,
          anexoNome, anexoHash, anexoUrl,
          mensagemHash,
          autorNome: quem,
          empresa: _e('nomeEmpresa'),
          criadoEm: agora,
          comunicacaoId: msgId,
        });
        let reciboUrl = '';
        try{
          const blob = new Blob([reciboHtml], { type:'text/html;charset=utf-8' });
          const refR = DB.storageRef(`disciplina/recibos/envio-${discId}.html`);
          await refR.put(blob);
          reciboUrl = await refR.getDownloadURL();
        }catch(err){ console.error('Falha ao subir recibo de envio', err); }
        const disc = {
          id: discId,
          employeeId: empId,
          employeeNome: (e&&e.nome)||'',
          tipo,
          motivo: motivoDisc,
          diasSuspensao: diasSusp,
          artigoCLT,
          anexoUrl, anexoNome, anexoTipo, anexoHash,
          mensagemHash,
          comunicacaoId: msgId,
          reciboEnvioUrl: reciboUrl,
          reciboRecebimentoUrl: '',
          criadoEm: agora,
          criadoPorId: quemId,
          criadoPorNome: quem,
          visualizadoEm: '',
        };
        try{ await DB.save('disciplina', _sanitizeForFirestore(disc)); disciplinaCriada = disc; }
        catch(err){ console.error('Erro ao salvar disciplina', err); }
        // Snapshot imutavel — coleção write-once via Rules (a ser configurado)
        try{
          await DB.save('auditoria_disciplina', _sanitizeForFirestore({
            id: genId(),
            disciplinaId: discId,
            employeeId: empId,
            tipo,
            snapshot: disc,
            anexoHash,
            mensagemHash,
            criadoEm: agora,
            criadoPorId: quemId,
            criadoPorNome: quem,
            evento: 'ENVIO',
          }));
        }catch(err){ console.error('Erro ao salvar auditoria', err); }
        try{ Auth.log('DISCIPLINA_ENVIADA', null, `${tipo.toUpperCase()} — ${(e&&e.nome)||''} — Hash: ${(anexoHash||'').substring(0,16)}...`); }catch(_){}
      }
    }
    try{ Auth.log('COMUNICACAO_ENVIADA', null, `${ok} destinatario(s) — ${assunto}`); }catch(_){}
    if(ok===0){
      toast('Nenhuma mensagem foi salva — abra o console do navegador (F12) para o erro.','error');
      return;
    }
    if(ehDisciplina && disciplinaCriada){
      toast(`${tipo==='advertencia'?'Advertência':'Suspensão'} registrada e enviada. Hash arquivado.`, 'success');
      closeModal('modal-comunicar');
      // Pos-envio: oferece abrir e-mail (mailto) + ver recibo de envio
      _abrirPosEnvioDisciplina(disciplinaCriada);
    } else {
      toast(`Mensagem enviada para ${ok} colaborador(es).`, 'success');
      closeModal('modal-comunicar');
    }
    const m=document.getElementById('modal-employee');
    if(m && !m.classList.contains('hidden')){
      const eid=val('emp-id');
      if(eid && ids.includes(eid)){
        renderComunicacoesTab(eid);
        if(ehDisciplina) renderDisciplinaTab(eid);
      }
    }
  }catch(e){
    toast('Erro ao enviar: '+(e.message||e),'error');
  }finally{
    setBtnLoading(btn,false,'');
  }
}

// Aba "Comunicações" no cadastro — log de mensagens manuais + snapshot
// dos avisos automáticos correntes do colaborador.
async function renderComunicacoesTab(empId){
  const box=document.getElementById('emp-comunicacoes-list'); if(!box) return;
  if(!empId){
    box.innerHTML=`<div class="empty-state small"><i class="fa-solid fa-envelope"></i><p>Salve o colaborador para registrar comunicações</p></div>`;
    return;
  }
  box.innerHTML='<div style="text-align:center;padding:20px;color:#999"><i class="fa-solid fa-spinner fa-spin"></i> Carregando comunicações...</div>';
  let lista=[];
  try{
    const snap=await firebase.firestore().collection('comunicacoes').where('employeeId','==',empId).get();
    lista=snap.docs.map(d=>({id:d.id,...d.data()}));
  }catch(e){ console.error('comunicacoes:fetch',e); }
  lista.sort((a,b)=>(b.criadoEm||'').localeCompare(a.criadoEm||''));
  // cache das mensagens para o botão "Reenviar"
  _comuMensagensCache = {};
  lista.forEach(m => { _comuMensagensCache[m.id] = m; });
  const podeApagar = !!getUserModules(Auth.currentUser).comunicacoesApagar || Auth.currentUser?.role==='master';
  const emp=State.employees.find(e=>e.id===empId);
  const autos = emp ? _computeAvisosAutomaticos(emp) : [];
  const docsEnv = _docsEnviadosColab(empId);
  let html='';
  html+=`<div style="margin-bottom:12px;display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px">
    <strong style="font-size:13px">Mensagens enviadas (${lista.length})</strong>
    <button class="btn btn-sm btn-primary" onclick="openComunicarModal('${empId}')" style="font-size:12px">
      <i class="fa-solid fa-paper-plane"></i> Nova mensagem
    </button>
  </div>`;
  if(!lista.length){
    html+=`<div class="empty-state small" style="margin-bottom:14px"><i class="fa-solid fa-envelope-open"></i><p>Nenhuma mensagem enviada ainda</p></div>`;
  } else {
    // Helpers de formatacao em horario local (criadoEm/lidaEm sao ISO em UTC;
    // o usuario esta em America/Sao_Paulo — converter pelo Date do navegador).
    const _fmtDt = iso => { const d=iso?new Date(iso):null; return (d && !isNaN(d.getTime())) ? d.toLocaleDateString('pt-BR') : ''; };
    const _fmtHr = iso => { const d=iso?new Date(iso):null; return (d && !isNaN(d.getTime())) ? d.toLocaleTimeString('pt-BR',{hour:'2-digit',minute:'2-digit'}) : ''; };
    html+=lista.map(m=>{
      const dt=_fmtDt(m.criadoEm);
      const hr=_fmtHr(m.criadoEm);
      const anexo=m.anexoUrl?`<div style="margin-top:6px;font-size:12px"><a href="${m.anexoUrl}" target="_blank" rel="noopener" style="color:var(--primary)"><i class="fa-solid fa-paperclip"></i> ${m.anexoNome||'anexo'}</a></div>`:'';
      // Reações do colaborador (emojis) — mostra o que ele já reagiu
      const reacEntries = Object.entries(m.reacoes||{}).filter(([_,ids])=>(ids||[]).length>0);
      const reacHtml = reacEntries.length
        ? `<div style="margin-top:6px;font-size:12px;color:#475569"><span style="color:#94a3b8">Reagiu:</span> ${reacEntries.map(([emo])=>`<span style="font-size:14px;margin-right:2px">${emo}</span>`).join('')}</div>`
        : '';
      // Confirmação de leitura — ✓✓ verde se visualizada
      const lidaHtml = m.lida
        ? `<span style="color:#16a34a;font-weight:600" title="Visualizada">✓✓ visualizada${m.lidaEm?` em ${_fmtDt(m.lidaEm)} ${_fmtHr(m.lidaEm)}`:''}</span>`
        : `<span style="color:#94a3b8" title="Ainda não visualizada">✓ enviada · não visualizada</span>`;
      return `<div style="background:#fff;border:1px solid var(--border);border-radius:8px;padding:10px 12px;margin-bottom:8px">
        <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:10px">
          <strong style="font-size:13px;color:var(--text)">${m.assunto||'(sem assunto)'}</strong>
          <span style="font-size:11px;color:#999;white-space:nowrap">${dt}${hr?' '+hr:''}</span>
        </div>
        <div style="font-size:12px;color:#555;margin-top:4px;line-height:1.5">${_corpoHtml(m.corpo)}</div>
        ${anexo}
        ${reacHtml}
        <div style="margin-top:6px;font-size:11px">${lidaHtml}</div>
        <div style="margin-top:8px;padding-top:7px;border-top:1px dashed var(--border);display:flex;justify-content:space-between;align-items:center;gap:8px;flex-wrap:wrap">
          <span style="font-size:11px;color:#888">Enviado por ${m.origemUserNome||'—'}${m.editadoEm?` · <em>editado ${_fmtDt(m.editadoEm)}</em>`:''}</span>
          <div style="display:flex;gap:6px;flex-wrap:wrap">
            <button type="button" onclick="editarMensagem('${m.id}')" class="btn btn-sm btn-outline" style="font-size:11px;padding:3px 10px;color:#E65100;border-color:#FFCC80"><i class="fa-solid fa-pen"></i> Editar</button>
            <button type="button" onclick="reenviarMensagem('${m.id}')" class="btn btn-sm btn-outline" style="font-size:11px;padding:3px 10px;color:#1976D2;border-color:#1976D2"><i class="fa-solid fa-rotate-right"></i> Reenviar</button>
            ${podeApagar?`<button type="button" onclick="apagarComunicacao('${m.id}')" class="btn btn-sm btn-outline" style="font-size:11px;padding:3px 10px;color:#c62828;border-color:#ef9a9a"><i class="fa-solid fa-trash"></i> Apagar</button>`:''}
          </div>
        </div>
      </div>`;
    }).join('');
  }
  if(autos.length){
    html+=`<div style="margin-top:18px;padding-top:14px;border-top:1px solid var(--border)">
      <strong style="font-size:13px">Avisos automáticos do sistema (${autos.length})</strong>
      <div style="font-size:11px;color:#888;margin-bottom:8px">O que o colaborador vê no app dele agora.</div>
      ${autos.map(a=>`<div style="background:#fafafa;border-left:3px solid #999;padding:7px 10px;margin-bottom:6px;border-radius:4px;font-size:12px"><strong>${a.icone} ${a.titulo}</strong><br><span style="color:#555">${a.msg}</span></div>`).join('')}
    </div>`;
  }
  if(docsEnv.length){
    const _fdt = iso => { const d=iso?new Date(iso):null; return (d&&!isNaN(d.getTime()))?(d.toLocaleDateString('pt-BR')+' '+d.toLocaleTimeString('pt-BR',{hour:'2-digit',minute:'2-digit'})):''; };
    html+=`<div style="margin-top:18px;padding-top:14px;border-top:1px solid var(--border)">
      <strong style="font-size:13px"><i class="fa-solid fa-file-arrow-up" style="color:#1a3a6b"></i> Documentos enviados — folha & holerite (${docsEnv.length})</strong>
      <div style="font-size:11px;color:#888;margin-bottom:8px">Registro de cada folha de ponto e holerite enviado ao colaborador para conferência/assinatura.</div>
      ${docsEnv.map(d=>`<div style="background:#fff;border:1px solid var(--border);border-left:3px solid #1a3a6b;border-radius:6px;padding:8px 11px;margin-bottom:6px;font-size:12px">
        <div style="display:flex;justify-content:space-between;gap:10px;flex-wrap:wrap"><strong>${d.icone} ${d.tipo} — ${d.comp}</strong><span style="color:#475569">${_docEnvStatusLabel(d.status)}</span></div>
        <div style="color:#888;font-size:11px;margin-top:2px">Enviado em ${_fdt(d.enviadoEm)} por ${d.por}</div>
      </div>`).join('')}
    </div>`;
  }
  // Ação no fim da aba: gerar relatório PDF SO deste colaborador — usado em
  // auditorias / pastas individuais. Abre o modal universal de relatorios
  // em modo dedicado (sem grid de tipos e sem filtros).
  html+=`<div style="margin-top:20px;padding-top:14px;border-top:1px dashed var(--border);display:flex;justify-content:flex-end;flex-wrap:wrap;gap:8px">
    <button type="button" class="btn btn-outline btn-sm" onclick="gerarRelatorioComunicacoesIndividual('${empId}')" style="font-size:12px;color:#1a3a6b;border-color:#1a3a6b">
      <i class="fa-solid fa-file-pdf"></i> Gerar relatório PDF deste colaborador
    </button>
  </div>`;
  box.innerHTML=html;
}

// Computa os avisos automáticos correntes do colaborador (snapshot do que
// o app dele mostra agora) — usado no log da aba "Comunicações".
function _computeAvisosAutomaticos(emp){
  if(!emp) return [];
  const hoje=new Date(); hoje.setHours(0,0,0,0);
  const D=86400000;
  const out=[];
  if(emp.exameVencimento){
    const venc=new Date(emp.exameVencimento+'T00:00:00');
    const diff=Math.round((venc-hoje)/D);
    if(diff<0) out.push({icone:'🩺',titulo:'Exame médico VENCIDO',msg:`Venceu há ${Math.abs(diff)} dia(s).`});
    else if(diff<=10) out.push({icone:'🩺',titulo:'Exame médico vencendo',msg:`Vence em ${diff} dia(s).`});
  }
  (emp.ferias||[]).forEach(f=>{
    if(!f.inicio||!f.fim) return;
    const ini=new Date(f.inicio+'T00:00:00');
    const fim=new Date(f.fim+'T00:00:00');
    if(ini>hoje){
      const dd=Math.round((ini-hoje)/D);
      if(dd<=30) out.push({icone:'🏖️',titulo:'Férias programadas',msg:`Começa em ${dd} dia(s).`});
    } else if(ini<=hoje&&fim>=hoje){
      const r=Math.round((fim-hoje)/D);
      out.push({icone:'🏖️',titulo:'Em férias agora',msg:`Retorno em ${r} dia(s).`});
    }
  });
  if(emp.tipoContrato==='experiencia' && emp.expDecisao1==='renovado' && emp.expDecisao1Data){
    const dd=Math.round((hoje-new Date(emp.expDecisao1Data+'T00:00:00'))/D);
    if(dd>=0 && dd<=14) out.push({icone:'⏳',titulo:'Renovado p/ 2º período',msg:`Em ${emp.expDecisao1Data.split('-').reverse().join('/')}.`});
  }
  if(emp.efetivadoEm){
    const dd=Math.round((hoje-new Date(emp.efetivadoEm+'T00:00:00'))/D);
    if(dd>=0 && dd<=30) out.push({icone:'🤝',titulo:'Contrato efetivado',msg:`Em ${emp.efetivadoEm.split('-').reverse().join('/')}.`});
  }
  return out;
}

// Log de DOCUMENTOS enviados ao colaborador (folha de ponto / holerite p/
// conferência) — derivado das folhas em State.payrolls (folha → envioConferencia;
// holerite → holeriteConferencia). Registro persistente na aba Comunicações
// (pedido do usuário 2026-05-31). #docs-enviados
function _docsEnviadosColab(empId){
  const out=[];
  (State.payrolls||[]).filter(p=>p && p.employeeId===empId).forEach(p=>{
    const comp = `${MESES[p.mes]||p.mes}/${p.ano}`;
    if(p.envioConferencia && p.envioConferencia.enviadoEm){
      const e=p.envioConferencia;
      out.push({ tipo:'Folha de Ponto', icone:'🕐', comp, enviadoEm:e.enviadoEm, por:e.enviadoPorNome||e.enviadoPor||'—', status:e.status||'pendente' });
    }
    if(p.holeriteConferencia && p.holeriteConferencia.enviadoEm){
      const e=p.holeriteConferencia;
      out.push({ tipo:'Holerite', icone:'🧾', comp, enviadoEm:e.enviadoEm, por:e.enviadoPorNome||e.enviadoPor||'—', status:e.status||'pendente' });
    }
  });
  out.sort((a,b)=>(b.enviadoEm||'').localeCompare(a.enviadoEm||''));
  return out;
}
function _docEnvStatusLabel(s){
  const m={ pendente:'⏳ Aguardando conferência', assinada:'✅ Assinada', assinado:'✅ Assinado',
    aceita:'✅ Aceita', aceita_por_silencio:'✅ Aceita (decurso de prazo)',
    contestada:'⚠️ Contestada', contestado:'⚠️ Contestado', recusada:'⚠️ Contestada' };
  return m[s]||s||'—';
}

function renderAprovacoes(){
  const tbody=document.getElementById('aprovacoes-tbody'); if(!tbody) return;
  const filtro=val('aprovacoes-filtro')||'pendente';
  const mods=getUserModules(Auth.currentUser);
  const podeAprovar=!!mods.pagamentosAprovar;
  _autoBuscarComprovantes();   // puxa em 2o plano os comprovantes que faltam

  let lista=[...(State.solicitacoes||[])];
  if(filtro!=='todos') lista=lista.filter(s=>s.status===filtro);
  // Busca por nome do colaborador (caixa de busca da seção). #busca-aprovacoes
  const _busca=(val('aprovacoes-busca')||'').trim().toLowerCase();
  if(_busca) lista=lista.filter(s=>(s.employeeNome||'').toLowerCase().includes(_busca));
  lista.sort((a,b)=>new Date(b.criadoEm||0)-new Date(a.criadoEm||0));

  const pend=(State.solicitacoes||[]).filter(s=>s.status==='pendente');
  const cnt=document.getElementById('aprovacoes-contador');
  if(cnt){
    const totalP=pend.reduce((s,x)=>s+(x.valor||0),0);
    cnt.innerHTML = pend.length
      ? `<strong style="color:#E65100">${pend.length}</strong> pendente(s) · Total ${fmtMoney(totalP)}`
      : '<span style="color:#2e7d32">Nenhuma pendência</span>';
  }
  const aviso=document.getElementById('aprovacoes-sem-perm');
  if(aviso) aviso.style.display = podeAprovar ? 'none' : '';

  if(lista.length===0){
    tbody.innerHTML=`<tr><td colspan="9" style="padding:26px;text-align:center;color:#999">Nenhuma solicitação${filtro!=='todos'?' ('+filtro+')':''}.</td></tr>`;
    _aprAtualizarLoteBar();
    return;
  }
  tbody.innerHTML=lista.map((s,idx)=>{
    const bg=idx%2?'#f9fafb':'#fff';
    // Selecionável p/ lote: só pendente/erro e só quem pode aprovar. #lote-aprovacoes
    const selecionavel = podeAprovar && (s.status==='pendente' || s.status==='erro');
    const dt=(s.criadoEm||'').substring(0,10).split('-').reverse().join('/');
    const sched=(s.scheduleDate||'').split('-').reverse().join('/');
    // Nome do colaborador clicavel → abre o cadastro (se o colaborador existe)
    const _empCad=State.employees.find(e=>e.id===s.employeeId);
    const nomeCell=_empCad
      ? `<strong style="color:var(--primary);cursor:pointer;text-decoration:underline;text-decoration-style:dotted;text-underline-offset:2px" onclick="openEmployeeModal('${s.employeeId}')" title="Abrir cadastro de ${(s.employeeNome||'').replace(/"/g,'&quot;')}">${s.employeeNome||'—'}</strong>`
      : `<strong>${s.employeeNome||'—'}</strong>`;
    let acoes='—';
    if(s.status==='pendente'){
      acoes = podeAprovar
        ? `<button class="btn btn-sm" style="background:#2e7d32;color:#fff;border-color:#2e7d32;margin-right:4px" onclick="openAprovarPagamento('${s.id}')"><i class="fa-solid fa-check"></i> Aprovar</button>`
          + `<button class="btn btn-sm btn-outline" style="color:#c62828;border-color:#ef9a9a" onclick="recusarSolicitacao('${s.id}')"><i class="fa-solid fa-ban"></i> Recusar</button>`
        : `<span style="font-size:11px;color:#999">aguardando aprovador</span>`;
    } else if(s.status==='pago'){
      const idTxt=s.asaasTransferId?`<div style="font-size:10px;color:#aaa;margin-top:3px">ID: ${s.asaasTransferId}</div>`:'';
      // "Estornar" so' aparece quando NAO existe comprovante oficial da Asaas
      // ainda. Comprovante presente = PIX confirmado pelo banco — nao da' pra
      // estornar so' no sistema sem o dinheiro voltar de fato. Nesses casos,
      // se houver problema, abre disputa direto na Asaas (fora do app).
      const podeEstornar = podeAprovar && !s.asaasComprovante;
      const estornarBtn = podeEstornar
        ? `<div style="margin-top:5px"><button class="btn btn-sm btn-outline" style="color:#E65100;border-color:#FFCC80;font-size:11px;padding:3px 9px" onclick="estornarPagamento('${s.id}')" title="Marcar como estornado — use quando o PIX nao foi concluido no banco"><i class="fa-solid fa-rotate-left"></i> Estornar</button></div>`
        : '';
      if(s.asaasComprovante){
        acoes=`<a href="${s.asaasComprovante}" target="_blank" rel="noopener" class="btn btn-sm" style="background:#00695C;color:#fff;border-color:#00695C;text-decoration:none"><i class="fa-solid fa-receipt"></i> Comprovante</a>${idTxt}`;
      } else if(s.asaasTransferId){
        acoes=`<button class="btn btn-sm btn-outline" style="color:#00695C;border-color:#00695C" onclick="verComprovante('${s.id}',this)"><i class="fa-solid fa-receipt"></i> Comprovante</button>${idTxt}${estornarBtn}`;
      } else {
        acoes=`<span style="font-size:11px;color:#00695C">pago</span>${estornarBtn}`;
      }
    } else if(s.status==='estornado'){
      const refazBtn = mods.pagamentosLancar
        ? `<div style="margin-top:5px"><button class="btn btn-sm btn-outline" style="color:#1565C0;border-color:#90CAF9;font-size:11px;padding:3px 9px" onclick="refazerSolicitacao('${s.id}')" title="Cria uma NOVA solicitação pendente com os mesmos dados"><i class="fa-solid fa-arrows-rotate"></i> Refazer lançamento</button></div>`
        : '';
      acoes=`<span style="font-size:11px;color:#E65100" title="${(s.motivoEstorno||'').replace(/"/g,'&quot;')}"><i class="fa-solid fa-rotate-left"></i> ${s.motivoEstorno||'estornado'}</span>`
        + (s.estornadoEm?`<div style="font-size:10px;color:#aaa;margin-top:2px">por ${s.estornadoPorNome||'—'} · ${(s.estornadoEm||'').substring(0,10).split('-').reverse().join('/')}</div>`:'')
        + refazBtn;
    } else if(s.status==='recusado'){
      const refazBtn = mods.pagamentosLancar
        ? `<div style="margin-top:5px"><button class="btn btn-sm btn-outline" style="color:#1565C0;border-color:#90CAF9;font-size:11px;padding:3px 9px" onclick="refazerSolicitacao('${s.id}')" title="Cria uma NOVA solicitação pendente com os mesmos dados"><i class="fa-solid fa-arrows-rotate"></i> Refazer lançamento</button></div>`
        : '';
      acoes=`<span style="font-size:11px;color:#c62828">${(s.motivoRecusa||'recusado')}</span>` + refazBtn;
    } else if(s.status==='erro'){
      const refazBtn = mods.pagamentosLancar
        ? `<button class="btn btn-sm btn-outline" style="color:#1565C0;border-color:#90CAF9;font-size:11px;padding:3px 9px;margin-left:4px" onclick="refazerSolicitacao('${s.id}')" title="Cria uma NOVA solicitação pendente (em vez de retentar a mesma)"><i class="fa-solid fa-arrows-rotate"></i> Refazer</button>`
        : '';
      acoes = podeAprovar
        ? `<button class="btn btn-sm" style="background:#e65100;color:#fff;border-color:#e65100;margin-right:4px" onclick="openAprovarPagamento('${s.id}')" title="${(s.erro||'').replace(/"/g,'')}"><i class="fa-solid fa-rotate-right"></i> Tentar de novo</button>`
          + `<button class="btn btn-sm btn-outline" style="color:#c62828;border-color:#ef9a9a" onclick="recusarSolicitacao('${s.id}')" title="${(s.erro||'').replace(/"/g,'')}"><i class="fa-solid fa-ban"></i> Recusar</button>`
          + refazBtn
        : `<span style="font-size:11px;color:#c62828">${s.erro||'erro'}</span>`;
    }
    return `<tr style="background:${bg}">
      <td style="padding:9px 6px;text-align:center">${selecionavel?`<input type="checkbox" class="apr-row-check" data-id="${s.id}" ${_aprSelecionados.has(s.id)?'checked':''} onclick="_aprToggleSel('${s.id}',this.checked)">`:''}</td>
      <td style="padding:9px 10px">${nomeCell}${s.origem==='lote'?' <span style="font-size:10px;color:#aaa">(lote)</span>':''}</td>
      <td style="padding:9px 10px;text-align:right;font-weight:700;color:#00695C">${fmtMoney(s.valor||0)}</td>
      <td style="padding:9px 10px;font-family:monospace;font-size:11px">${s.pixKey||'—'}</td>
      <td style="padding:9px 10px;font-size:12px">${sched||'—'}</td>
      <td style="padding:9px 10px;font-size:12px">${s.criadoPorNome||'—'}<br><span style="color:#aaa;font-size:10px">${dt}</span></td>
      <td style="padding:9px 10px;text-align:center">${_aprovacaoStatusBadge(s.status)}</td>
      <td style="padding:9px 10px;font-size:12px">${s.aprovadoPorNome||'—'}</td>
      <td style="padding:9px 10px">${acoes}</td>
    </tr>`;
  }).join('');
  _aprAtualizarLoteBar();
}

// ── Aprovação/Recusa EM LOTE (checkboxes) ──────────────────────────────────
// Seleciona vários pendentes e aprova com UM 2FA (ou recusa com um motivo).
// O backend valida o TOTP por chamada, mas o mesmo código vale dentro da janela
// de tempo → um código autoriza o lote. Cada PIX mantém a trava atômica
// anti-duplo-pagamento no worker. #lote-aprovacoes #autorizacao-master
let _aprSelecionados = new Set();
function _aprListaSelecionavel(){
  if(!getUserModules(Auth.currentUser).pagamentosAprovar) return [];
  return (State.solicitacoes||[]).filter(s=> s.status==='pendente' || s.status==='erro');
}
function _aprSelecionadas(){
  return (State.solicitacoes||[]).filter(s=>_aprSelecionados.has(s.id) && (s.status==='pendente'||s.status==='erro'));
}
function _aprToggleSel(id, checked){
  if(checked) _aprSelecionados.add(id); else _aprSelecionados.delete(id);
  _aprAtualizarLoteBar();
}
function _aprToggleAll(checked){
  document.querySelectorAll('.apr-row-check').forEach(cb=>{
    cb.checked=checked;
    const id=cb.getAttribute('data-id');
    if(checked) _aprSelecionados.add(id); else _aprSelecionados.delete(id);
  });
  _aprAtualizarLoteBar();
}
function _aprAtualizarLoteBar(){
  const bar=document.getElementById('aprovacoes-lote-bar'); if(!bar) return;
  const mods=getUserModules(Auth.currentUser);
  // mantém no set só os ids ainda selecionáveis (status mudou / sumiu)
  const validos=new Set(_aprListaSelecionavel().map(s=>s.id));
  Array.from(_aprSelecionados).forEach(id=>{ if(!validos.has(id)) _aprSelecionados.delete(id); });
  const sel=_aprSelecionadas();
  const n=sel.length, total=sel.reduce((a,s)=>a+(s.valor||0),0);
  bar.style.display = (mods.pagamentosAprovar && n>0) ? 'flex' : 'none';
  const cEl=document.getElementById('apr-lote-count'); if(cEl) cEl.textContent=n;
  const tEl=document.getElementById('apr-lote-total'); if(tEl) tEl.textContent=fmtMoney(total);
  const all=document.getElementById('apr-check-all');
  if(all){
    const checks=document.querySelectorAll('.apr-row-check');
    const marc=document.querySelectorAll('.apr-row-check:checked');
    all.checked = checks.length>0 && marc.length===checks.length;
    all.indeterminate = marc.length>0 && marc.length<checks.length;
  }
}
function abrirAprovarLote(){
  if(!getUserModules(Auth.currentUser).pagamentosAprovar){ toast('Sem permissão para aprovar pagamentos.','error'); return; }
  const sel=_aprSelecionadas();
  if(!sel.length){ toast('Selecione ao menos um pagamento pendente.','warning'); return; }
  const total=sel.reduce((a,s)=>a+(s.valor||0),0);
  document.getElementById('aprovar-lote-info').innerHTML=
    `<div style="font-weight:700;color:#00695C;font-size:15px">${sel.length} pagamento(s) selecionado(s)</div>
     <div style="font-size:14px;margin-top:6px">Total: <strong>${fmtMoney(total)}</strong></div>
     <div style="font-size:11px;color:#999;margin-top:6px">${sel.slice(0,6).map(s=>esc(s.employeeNome||'—')+' · '+fmtMoney(s.valor||0)).join('<br>')}${sel.length>6?`<br>… e mais ${sel.length-6}`:''}</div>`;
  setVal('aprovar-lote-code','');
  const prog=document.getElementById('aprovar-lote-progresso'); prog.style.display='none'; prog.innerHTML='';
  const btn=document.getElementById('btn-confirmar-aprovar-lote'); btn.disabled=false; btn.style.display=''; btn.innerHTML='<i class="fa-solid fa-lock"></i> Aprovar e Pagar todos';
  document.getElementById('modal-aprovar-lote').classList.remove('hidden');
  setTimeout(()=>document.getElementById('aprovar-lote-code')?.focus(),150);
}
async function confirmarAprovarLote(){
  const code=(val('aprovar-lote-code')||'').replace(/\D/g,'');
  if(code.length!==6){ toast('Digite o código de 6 dígitos do app autenticador.','warning'); return; }
  const sel=_aprSelecionadas();
  if(!sel.length){ toast('Nada selecionado.','warning'); return; }
  const btn=document.getElementById('btn-confirmar-aprovar-lote');
  btn.disabled=true; btn.innerHTML='<i class="fa-solid fa-spinner fa-spin"></i> Processando...';
  const prog=document.getElementById('aprovar-lote-progresso'); prog.style.display='block';
  let ok=0, fail=0; const erros=[]; let expirou=false;
  for(let i=0;i<sel.length;i++){
    const s=sel[i];
    prog.innerHTML=`<div style="background:#E3F2FD;border:1px solid #90CAF9;border-radius:9px;padding:12px;font-size:13px;color:#0D47A1"><i class="fa-solid fa-spinner fa-spin"></i> Processando ${i+1}/${sel.length}: <strong>${esc(s.employeeNome||'—')}</strong> (${fmtMoney(s.valor||0)})…<br>✅ ${ok} · ❌ ${fail}</div>`;
    try{
      const r=await _aprovacaoReq('/aprovar-pagamento',{code,solicitacaoId:s.id});
      if(r.ok){
        ok++;
        const st=State.solicitacoes.find(x=>x.id===s.id);
        if(st){
          st.status='pago'; st.asaasTransferId=r.asaasTransferId||st.asaasTransferId; st.asaasStatus=r.status||st.asaasStatus;
          st.aprovadoPorNome=Auth.currentUser?.username||st.aprovadoPorNome;
          if(st.autorizacaoSolicitada && !st.inclusaoAutorizada){
            try{ await DB.merge('solicitacoesPagamento', st.id, { inclusaoAutorizada:true, inclusaoAutorizadaPorNome:(Auth.currentUser?.username||''), inclusaoAutorizadaEm:new Date().toISOString() }); st.inclusaoAutorizada=true; }catch(_){}
          }
        }
        _aprSelecionados.delete(s.id);
        try{ Auth.log('PAGAMENTO_APROVADO',null,`${s.employeeNome||s.id} | R$ ${(s.valor||0).toFixed(2)} | lote | ID Asaas ${r.asaasTransferId||'—'}`); }catch(_){}
      } else {
        fail++; erros.push(`${s.employeeNome||s.id}: ${r.erro||'falhou'}`);
        // 2FA recusado no meio → código provavelmente expirou: para e pede novo. Os já pagos ficam.
        if(/2fa|c[oó]digo/i.test(r.erro||'')){ expirou=true; break; }
      }
    }catch(e){ fail++; erros.push(`${s.employeeNome||s.id}: ${e.message||e}`); }
  }
  if(expirou) erros.push('⚠️ O código 2FA pode ter expirado no meio do lote. Os já pagos estão concluídos — gere um código novo e aprove os restantes.');
  const cor = fail? (ok?'#E65100':'#c62828') : '#2e7d32';
  const bgC = fail? (ok?'#FFF3E0':'#FCE4E4') : '#E8F5E9';
  const brC = fail? (ok?'#FFCC80':'#EF9A9A') : '#A5D6A7';
  prog.innerHTML=`<div style="background:${bgC};border:1px solid ${brC};border-radius:9px;padding:14px;font-size:13px;color:${cor}">
    <strong>${ok} aprovado(s) e pago(s)${fail?` · ${fail} não concluído(s)`:''}.</strong>
    ${erros.length?`<div style="margin-top:8px;font-size:12px">${erros.map(esc).join('<br>')}</div>`:''}</div>`;
  btn.style.display='none';
  const cBtn=document.getElementById('btn-aprovar-lote-cancelar'); if(cBtn) cBtn.innerHTML='Fechar';
  if(ok) toast(`${ok} pagamento(s) aprovado(s) em lote!`,'success');
  if(State.currentSection==='aprovacoes') renderAprovacoes();
}
async function recusarLote(){
  if(!getUserModules(Auth.currentUser).pagamentosAprovar){ toast('Sem permissão para recusar pagamentos.','error'); return; }
  const sel=_aprSelecionadas();
  if(!sel.length){ toast('Selecione ao menos um pagamento.','warning'); return; }
  const total=sel.reduce((a,s)=>a+(s.valor||0),0);
  const motivo=prompt(`Recusar ${sel.length} pagamento(s) selecionado(s) — total ${fmtMoney(total)}?\n\nInforme o motivo (vale para TODOS):`);
  if(motivo===null) return;
  if(!motivo.trim()){ toast('O motivo da recusa é obrigatório.','warning'); return; }
  const u=Auth.currentUser||{}; const agora=new Date().toISOString();
  let ok=0, fail=0;
  for(const s of sel){
    try{
      await DB.merge('solicitacoesPagamento', s.id, { status:'recusado', motivoRecusa:motivo.trim(), aprovadoPor:u.username||u.id||'', aprovadoPorNome:u.username||'', aprovadoEm:agora });
      const st=State.solicitacoes.find(x=>x.id===s.id); if(st){ st.status='recusado'; st.motivoRecusa=motivo.trim(); st.aprovadoPorNome=u.username||''; }
      _aprSelecionados.delete(s.id); ok++;
      try{ Auth.log('PAGAMENTO_RECUSADO',null,`${s.employeeNome||s.id} | R$ ${(s.valor||0).toFixed(2)} | lote | ${motivo.trim()}`); }catch(_){}
    }catch(e){ fail++; }
  }
  toast(`${ok} recusado(s)${fail?` · ${fail} falhou`:''}.`, fail?'warning':'success');
  if(State.currentSection==='aprovacoes') renderAprovacoes();
}

let _aprovacaoAtualId=null;
function openAprovarPagamento(id){
  if(!getUserModules(Auth.currentUser).pagamentosAprovar){ toast('Sem permissão para aprovar pagamentos.','error'); return; }
  const s=(State.solicitacoes||[]).find(x=>x.id===id);
  if(!s){ toast('Solicitação não encontrada.','error'); return; }
  _aprovacaoAtualId=id;
  const _pedido = !!s.autorizacaoSolicitada;
  document.getElementById('aprovar-pag-info').innerHTML=`
    <div style="font-weight:700;color:#00695C;font-size:15px">${s.employeeNome}</div>
    <div style="font-size:14px;margin-top:6px"><strong>${fmtMoney(s.valor)}</strong> &rarr; <i class="fa-brands fa-pix" style="color:#00695C"></i> <code style="background:#fff;padding:2px 6px;border-radius:4px">${s.pixKey}</code></div>
    <div style="font-size:12px;color:#666;margin-top:6px">${s.descricao||''}${s.scheduleDate?' · data '+s.scheduleDate.split('-').reverse().join('/'):''}</div>
    <div style="font-size:11px;color:#999;margin-top:4px">Lançado por ${s.criadoPorNome||'—'}${_pedido?` · <span style="color:#E65100;font-weight:700">pedido de autorização de ${esc(s.solicitadaPorNome||s.criadoPorNome||'operador')}</span>`:''}${s.inclusaoAutorizada?' · <span style="color:#1565C0;font-weight:700">inclusão já autorizada</span>':''}</div>`;
  setVal('aprovar-pag-code','');
  const resEl=document.getElementById('aprovar-pag-resultado');
  resEl.style.display='none'; resEl.innerHTML='';
  const btn=document.getElementById('btn-confirmar-aprovacao');
  btn.disabled=false; btn.innerHTML='<i class="fa-solid fa-lock"></i> Aprovar e Pagar';
  _aprConfigModal(s);   // mostra/esconde os 2 portões conforme for pedido de autorização
  document.getElementById('modal-aprovar-pagamento').classList.remove('hidden');
}

// ── Os 2 portões do Master ────────────────────────────────────────────────
// Pedido de autorização do operador → o Master responde: (1) autoriza a
// INCLUSÃO? (2) autoriza o PAGAMENTO? Só com os dois "Sim" aparece o 2FA e o
// botão "Aprovar e Pagar" (que dispara a ordem ao banco). #autorizacao-master
let _aprGate1=null, _aprGate2=null;
function _aprConfigModal(s){
  _aprGate1=null; _aprGate2=null;
  const gatesEl=document.getElementById('aprovar-pag-gates');
  const precisa = !!(s && s.autorizacaoSolicitada);
  if(!precisa){
    // Pagamento lançado por quem já pode aprovar (ou Master) → fluxo direto de sempre.
    if(gatesEl) gatesEl.style.display='none';
    _aprToggle('aprovar-pag-2fa', true);
    _aprToggle('btn-confirmar-aprovacao', true);
    _aprToggle('btn-recusar-inclusao', false);
    _aprToggle('btn-salvar-inclusao', false);
    setTimeout(()=>document.getElementById('aprovar-pag-code')?.focus(),150);
    return;
  }
  if(gatesEl) gatesEl.style.display='';
  if(s.inclusaoAutorizada) _aprGate1=true;   // inclusão já autorizada antes → vai direto pro portão 2
  _aprApplyGateState();
}
function _aprToggle(id, show){ const e=document.getElementById(id); if(e) e.style.display = show ? '' : 'none'; }
function _aprGate(n, val){
  if(n===1){ _aprGate1=val; if(!val) _aprGate2=null; }
  else { _aprGate2=val; }
  _aprApplyGateState();
}
function _aprApplyGateState(){
  const mark=(id,on,cor)=>{ const b=document.getElementById(id); if(b){ b.style.outline = on?('2px solid '+cor):'none'; b.style.fontWeight = on?'800':'600'; } };
  mark('apr-g1-sim', _aprGate1===true,  '#2e7d32'); mark('apr-g1-nao', _aprGate1===false, '#c62828');
  mark('apr-g2-sim', _aprGate2===true,  '#2e7d32'); mark('apr-g2-nao', _aprGate2===false, '#c62828');
  _aprToggle('apr-g2-wrap', _aprGate1===true);
  const bothYes = _aprGate1===true && _aprGate2===true;
  const incOnly = _aprGate1===true && _aprGate2===false;
  const reject  = _aprGate1===false;
  _aprToggle('aprovar-pag-2fa', bothYes);
  _aprToggle('btn-confirmar-aprovacao', bothYes);
  _aprToggle('btn-recusar-inclusao', reject);
  _aprToggle('btn-salvar-inclusao', incOnly);
  if(bothYes) setTimeout(()=>document.getElementById('aprovar-pag-code')?.focus(),60);
}
// Portão 1 = Não → recusa o pedido (reaproveita o fluxo de recusa existente).
function _aprRecusarInclusao(){
  const id=_aprovacaoAtualId; if(!id) return;
  closeModal('modal-aprovar-pagamento');
  recusarSolicitacao(id);
}
// Portão 1 = Sim, Portão 2 = Não → autoriza só a INCLUSÃO; fica pendente p/ pagar depois.
async function _aprSalvarInclusao(){
  const id=_aprovacaoAtualId; if(!id) return;
  const u=Auth.currentUser||{};
  try{
    await DB.merge('solicitacoesPagamento', id, {
      inclusaoAutorizada:true, inclusaoAutorizadaPorNome:u.username||'',
      inclusaoAutorizadaEm:new Date().toISOString()
    });
    const s=(State.solicitacoes||[]).find(x=>x.id===id); if(s) s.inclusaoAutorizada=true;
    Auth.log && Auth.log('PAGAMENTO_INCLUSAO_AUTORIZADA', null, `${s?.employeeNome||id} | R$ ${(s?.valor||0).toFixed(2)}`);
    toast('Inclusão autorizada. O pagamento fica pendente — você envia ao banco quando quiser.','success');
    closeModal('modal-aprovar-pagamento');
    if(State.currentSection==='aprovacoes') renderAprovacoes();
  }catch(e){ toast('Erro ao salvar a autorização: '+(e.message||e),'error'); }
}

async function confirmarAprovacaoPagamento(){
  const id=_aprovacaoAtualId; if(!id) return;
  const code=(val('aprovar-pag-code')||'').replace(/\D/g,'');
  if(code.length!==6){ toast('Digite o código de 6 dígitos do app autenticador.','warning'); return; }

  const btn=document.getElementById('btn-confirmar-aprovacao');
  btn.disabled=true; btn.innerHTML='<i class="fa-solid fa-spinner fa-spin"></i> Processando...';
  const resEl=document.getElementById('aprovar-pag-resultado'); resEl.style.display='none';

  try{
    const r=await _aprovacaoReq('/aprovar-pagamento',{code,solicitacaoId:id});
    if(r.ok){
      const s=(State.solicitacoes||[]).find(x=>x.id===id);
      // Pagou ⇒ a inclusão também fica registrada como autorizada (auditoria do fluxo do Master).
      if(s && s.autorizacaoSolicitada && !s.inclusaoAutorizada){
        try{ await DB.merge('solicitacoesPagamento', id, { inclusaoAutorizada:true, inclusaoAutorizadaPorNome:(Auth.currentUser?.username||''), inclusaoAutorizadaEm:new Date().toISOString() }); s.inclusaoAutorizada=true; }catch(_){}
      }
      Auth.log('PAGAMENTO_APROVADO',null,
        `${s?.employeeNome||id} | R$ ${(s?.valor||0).toFixed(2)} | ID Asaas ${r.asaasTransferId||'—'}`);
      resEl.style.display='block';
      resEl.innerHTML=`<div style="background:#e8f5e9;border:1px solid #a5d6a7;border-radius:9px;padding:14px;font-size:13px;color:#2e7d32">
        <i class="fa-solid fa-circle-check"></i> <strong>${r.jaPago?'Esta solicitação já estava paga.':'Pagamento aprovado e enviado ao Asaas!'}</strong><br>
        ID Asaas: <code>${r.asaasTransferId||'—'}</code> · Status: ${r.status||'—'}</div>`;
      btn.style.display='none';
      toast('Pagamento aprovado!','success');
      setTimeout(()=>{ closeModal('modal-aprovar-pagamento'); if(State.currentSection==='aprovacoes') renderAprovacoes(); },2000);
    } else {
      resEl.style.display='block';
      resEl.innerHTML=`<div style="background:#fce4e4;border:1px solid #ef9a9a;border-radius:9px;padding:14px;font-size:13px;color:#c62828">
        <i class="fa-solid fa-triangle-exclamation"></i> ${r.erro||'Não foi possível aprovar.'}</div>`;
      btn.disabled=false; btn.innerHTML='<i class="fa-solid fa-lock"></i> Aprovar e Pagar';
    }
  }catch(e){
    resEl.style.display='block';
    resEl.innerHTML=`<div style="background:#fce4e4;border:1px solid #ef9a9a;border-radius:9px;padding:14px;font-size:13px;color:#c62828">
      <i class="fa-solid fa-triangle-exclamation"></i> ${e.message}</div>`;
    btn.disabled=false; btn.innerHTML='<i class="fa-solid fa-lock"></i> Aprovar e Pagar';
  }
}

// Estorna um pagamento marcado como "pago" — usar quando o PIX nao foi
// concluido no banco (devolvido / falhou apos a aprovacao). A linha sai
// da lista "Pagos" e aparece no filtro "Estornados". Mantem o registro
// para auditoria (motivo, quem estornou, quando).
async function estornarPagamento(id){
  const mods = getUserModules(Auth.currentUser);
  if(!mods.pagamentosAprovar && Auth.currentUser?.role!=='master'){
    toast('Sem permissão para estornar pagamentos.','error'); return;
  }
  const s = (State.solicitacoes||[]).find(x=>x.id===id);
  if(!s){ toast('Solicitação não encontrada.','error'); return; }
  if(s.status!=='pago'){ toast('Só dá pra estornar uma solicitação com status "Pago".','warning'); return; }
  // Blindagem: comprovante oficial = PIX confirmado pelo banco. Estornar so'
  // no sistema cria divergencia (dinheiro saiu mas o registro diz que nao).
  // Se mesmo assim houver problema, abra disputa direto na Asaas.
  if(s.asaasComprovante){
    toast('Este pagamento ja tem comprovante oficial da Asaas — nao pode ser estornado pelo sistema. Para contestar, abra disputa direto na Asaas.','error');
    return;
  }
  if(!confirm(`Estornar este pagamento?\n\n${s.employeeNome||''} — ${fmtMoney(s.valor||0)}\nID Asaas: ${s.asaasTransferId||'—'}\n\nUse quando o PIX nao chegou no banco (devolvido / falhou). A linha sai da lista "Pagos" e fica em "Estornados".`)) return;
  const motivo = (prompt('Motivo do estorno (obrigatorio):')||'').trim();
  if(!motivo){ toast('Estorno cancelado — o motivo é obrigatório.','warning'); return; }
  const agora = new Date().toISOString();
  const quem = (Auth.currentUser && (Auth.currentUser.username||Auth.currentUser.id))||'—';
  try{
    await DB.merge('solicitacoesPagamento', id, {
      status: 'estornado',
      motivoEstorno: motivo,
      estornadoEm: agora,
      estornadoPorNome: quem,
      updatedAt: agora,
    });
    Object.assign(s, { status:'estornado', motivoEstorno:motivo, estornadoEm:agora, estornadoPorNome:quem });
    try{ Auth.log('PAGAMENTO_ESTORNADO', null, `${s.employeeNome||''} — ${fmtMoney(s.valor||0)} — ${motivo}`); }catch(_){}
    toast('Pagamento estornado. Saiu da lista de "Pagos".','success');
    renderAprovacoes();
  }catch(e){
    toast('Erro ao estornar: '+(e.message||e),'error');
  }
}

async function recusarSolicitacao(id){
  if(!getUserModules(Auth.currentUser).pagamentosAprovar){ toast('Sem permissão para recusar pagamentos.','error'); return; }
  const s=(State.solicitacoes||[]).find(x=>x.id===id);
  if(!s) return;
  const motivo=prompt(`Recusar o pagamento de ${s.employeeNome} (${fmtMoney(s.valor)})?\n\nInforme o motivo da recusa:`);
  if(motivo===null) return;
  if(!motivo.trim()){ toast('O motivo da recusa é obrigatório.','warning'); return; }
  try{
    const u=Auth.currentUser||{};
    await DB.merge('solicitacoesPagamento',id,{
      status:'recusado', motivoRecusa:motivo.trim(),
      aprovadoPor:u.username||u.id||'', aprovadoPorNome:u.username||'',
      aprovadoEm:new Date().toISOString(),
    });
    Auth.log('PAGAMENTO_RECUSADO',null,`${s.employeeNome} | R$ ${(s.valor||0).toFixed(2)} | ${motivo.trim()}`);
    toast('Solicitação recusada.','success');
  }catch(e){ toast('Erro ao recusar: '+e.message,'error'); }
}

// Cria uma NOVA solicitação pendente a partir de uma estornada/recusada/erro —
// pra refazer o lançamento sem ter que voltar pra tela de origem (Benefícios,
// Folha…). A original fica preservada (histórico). Bloqueia se já existir outra
// solicitação pendente do mesmo colaborador no mesmo período.
async function refazerSolicitacao(id){
  if(!getUserModules(Auth.currentUser).pagamentosLancar){
    toast('Você não tem permissão para lançar pagamentos.','error'); return;
  }
  const orig=(State.solicitacoes||[]).find(s=>s.id===id);
  if(!orig){ toast('Solicitação não encontrada.','error'); return; }
  if(!orig.pixKey || (orig.valor||0)<=0){ toast('Solicitação original sem chave PIX ou valor — não dá pra refazer.','error'); return; }
  const jaPend=(State.solicitacoes||[]).some(s=>s.employeeId===orig.employeeId && s.competencia===orig.competencia && s.status==='pendente' && s.id!==orig.id);
  if(jaPend){ toast(`Já existe uma solicitação PENDENTE para ${orig.employeeNome} neste período — aprove/recuse a existente antes.`,'warning'); return; }
  const motivoOrig = orig.status==='estornado' ? (orig.motivoEstorno||'estornado')
                    : orig.status==='recusado' ? (orig.motivoRecusa||'recusado')
                    : (orig.erro||orig.status||'');
  if(!confirm(`Refazer o lançamento de ${orig.employeeNome} — ${fmtMoney(orig.valor||0)}?\n\nOriginal: ${orig.status.toUpperCase()} (${motivoOrig})\n\nCria uma NOVA solicitação PENDENTE com os mesmos dados (mesma chave PIX). Vai pra "Aprovações" e o aprovador faz o 2FA.`)) return;
  try{
    const dtOrig=(orig.criadoEm||'').substring(0,10).split('-').reverse().join('/');
    const novo=await _criarSolicitacaoPagamento({
      employeeId:    orig.employeeId,
      employeeNome:  orig.employeeNome,
      payrollId:     orig.payrollId||'',
      valor:         orig.valor||0,
      pixKey:        orig.pixKey,
      keyType:       orig.keyType||'',
      descricao:     `[RE-LANÇAMENTO de ${dtOrig} — ${orig.status}] ${orig.descricao||''}`.slice(0,500),
      scheduleDate:  new Date().toISOString().substring(0,10),
      competencia:   orig.competencia||'',
      origem:        orig.origem||'avulso',
    });
    Auth.log('PAGAMENTO_SOLICITADO',null,`RE-LANÇAMENTO ${orig.employeeNome} | R$ ${(orig.valor||0).toFixed(2)} | nova ${novo.id} (original ${orig.id} / ${orig.status})`);
    toast(`Lançamento refeito — nova solicitação pendente criada. Vá em Aprovações p/ aprovar.`,'success');
    renderAprovacoes();
  }catch(e){ toast('Erro ao refazer: '+(e.message||e),'error'); }
}

// ============================================
// DOCUMENTOS ENVIADOS PELO COLABORADOR (via app de ponto)
// ============================================
// Espelho gestor da feature do ponto.html: o colaborador envia documento
// pelo app -> coleção `documentos` com status 'pendente' -> aqui o gestor
// aprova ou reprova. Atestados NÃO entram aqui (continuam na Folha de Ponto).
const DOC_TIPOS_META = {
  declaracao:        { ico:'📜', nome:'Declaração' },
  comprovante:       { ico:'📄', nome:'Comprovante' },
  documento_pessoal: { ico:'🪪', nome:'Documento pessoal' },
  outros:            { ico:'📁', nome:'Outro documento' }
};

function _docStatusBadge(status){
  if(status==='aprovado')  return '<span style="background:#E8F5E9;color:#1B5E20;padding:3px 9px;border-radius:9px;font-size:11px;font-weight:600">aprovado</span>';
  if(status==='reprovado') return '<span style="background:#FFEBEE;color:#c62828;padding:3px 9px;border-radius:9px;font-size:11px;font-weight:600">reprovado</span>';
  return '<span style="background:#FFF3E0;color:#E65100;padding:3px 9px;border-radius:9px;font-size:11px;font-weight:600">pendente</span>';
}

function renderDocumentosPendentes(){
  const tbody=document.getElementById('documentos-tbody'); if(!tbody) return;
  const filtro=val('documentos-filtro')||'pendente';

  let lista=[...(State.documentos||[])];
  if(filtro!=='todos') lista=lista.filter(d=>d.status===filtro);
  lista.sort((a,b)=>new Date(b.createdAt||0)-new Date(a.createdAt||0));

  const pend=(State.documentos||[]).filter(d=>d.status==='pendente');
  const cnt=document.getElementById('documentos-contador');
  if(cnt){
    cnt.innerHTML = pend.length
      ? `<strong style="color:#E65100">${pend.length}</strong> documento(s) aguardando aprovação`
      : '<span style="color:#2e7d32">Nenhuma pendência</span>';
  }

  if(lista.length===0){
    tbody.innerHTML=`<tr><td colspan="7" style="padding:26px;text-align:center;color:#999">Nenhum documento${filtro!=='todos'?' ('+filtro+')':''}.</td></tr>`;
    return;
  }

  tbody.innerHTML=lista.map((d,idx)=>{
    const bg=idx%2?'#f9fafb':'#fff';
    const emp=State.employees.find(e=>e.id===d.employeeId);
    const nomeEmp=emp?emp.nome:(d.employeeId||'—');
    const nomeCell=emp
      ? `<strong style="color:var(--primary);cursor:pointer;text-decoration:underline;text-decoration-style:dotted;text-underline-offset:2px" onclick="openEmployeeModal('${d.employeeId}')" title="Abrir cadastro de ${nomeEmp.replace(/"/g,'&quot;')}">${nomeEmp}</strong>`
      : `<strong>${nomeEmp}</strong>`;
    const meta=DOC_TIPOS_META[d.tipo]||{ico:'📄',nome:d.tipoLabel||d.tipo||'Documento'};
    const dt=(d.createdAt||'').substring(0,10).split('-').reverse().join('/');
    const arquivoCell = d.arquivoUrl
      ? `<a href="${d.arquivoUrl}" target="_blank" rel="noopener" class="btn btn-sm btn-outline" style="font-size:11px;padding:3px 9px"><i class="fa-solid fa-paperclip"></i> Abrir</a>`
      : '—';

    let acoes='—';
    if(d.status==='pendente'){
      acoes = `<button class="btn btn-sm" style="background:#2e7d32;color:#fff;border-color:#2e7d32;margin-right:4px" onclick="aprovarDocumento('${d.id}')"><i class="fa-solid fa-check"></i> Aprovar</button>`
            + `<button class="btn btn-sm btn-outline" style="color:#c62828;border-color:#ef9a9a" onclick="reprovarDocumento('${d.id}')"><i class="fa-solid fa-ban"></i> Reprovar</button>`;
    } else if(d.status==='aprovado'){
      const quando=(d.aprovadoEm||'').substring(0,10).split('-').reverse().join('/');
      acoes=`<span style="font-size:11px;color:#1B5E20">por ${d.aprovadoPorNome||'—'}${quando?' · '+quando:''}</span>`;
    } else if(d.status==='reprovado'){
      acoes=`<span style="font-size:11px;color:#c62828" title="${(d.motivoReprovacao||'').replace(/"/g,'&quot;')}">${d.motivoReprovacao||'reprovado'}</span>`;
    }

    return `<tr style="background:${bg}">
      <td style="padding:9px 10px">${nomeCell}</td>
      <td style="padding:9px 10px"><span style="font-size:16px">${meta.ico}</span> ${meta.nome}</td>
      <td style="padding:9px 10px;font-size:12px;color:#475569">${(d.descricao||'').replace(/</g,'&lt;')||'<span style="color:#aaa">—</span>'}</td>
      <td style="padding:9px 10px;font-size:12px">${dt}</td>
      <td style="padding:9px 10px;text-align:center">${arquivoCell}</td>
      <td style="padding:9px 10px;text-align:center">${_docStatusBadge(d.status)}</td>
      <td style="padding:9px 10px">${acoes}</td>
    </tr>`;
  }).join('');
}

async function aprovarDocumento(id){
  if(!getUserModules(Auth.currentUser).employees){ toast('Sem permissão para aprovar documentos.','error'); return; }
  const d=(State.documentos||[]).find(x=>x.id===id);
  if(!d){ toast('Documento não encontrado.','error'); return; }
  if(d.status!=='pendente'){ toast('Este documento já foi processado.','warning'); return; }
  try{
    const u=Auth.currentUser||{};
    await DB.merge('documentos',id,{
      status:'aprovado',
      aprovadoPor:u.username||u.id||'',
      aprovadoPorNome:u.username||'',
      aprovadoEm:new Date().toISOString(),
      updatedAt:new Date().toISOString()
    });
    const emp=State.employees.find(e=>e.id===d.employeeId);
    Auth.log('DOCUMENTO_APROVADO',null,`${emp?.nome||d.employeeId} | ${d.tipoLabel||d.tipo} | ${(d.descricao||'').substring(0,80)}`);
    toast('Documento aprovado.','success');
  }catch(e){ toast('Erro ao aprovar: '+e.message,'error'); }
}

async function reprovarDocumento(id){
  if(!getUserModules(Auth.currentUser).employees){ toast('Sem permissão para reprovar documentos.','error'); return; }
  const d=(State.documentos||[]).find(x=>x.id===id);
  if(!d){ toast('Documento não encontrado.','error'); return; }
  if(d.status!=='pendente'){ toast('Este documento já foi processado.','warning'); return; }
  const emp=State.employees.find(e=>e.id===d.employeeId);
  const motivo=prompt(`Reprovar o ${(d.tipoLabel||d.tipo||'documento').toLowerCase()} de ${emp?.nome||d.employeeId}?\n\nInforme o motivo (o colaborador não recebe notificação automática — combine pessoalmente):`);
  if(motivo===null) return;
  if(!motivo.trim()){ toast('O motivo da reprovação é obrigatório.','warning'); return; }
  try{
    const u=Auth.currentUser||{};
    await DB.merge('documentos',id,{
      status:'reprovado',
      motivoReprovacao:motivo.trim(),
      aprovadoPor:u.username||u.id||'',
      aprovadoPorNome:u.username||'',
      aprovadoEm:new Date().toISOString(),
      updatedAt:new Date().toISOString()
    });
    Auth.log('DOCUMENTO_REPROVADO',null,`${emp?.nome||d.employeeId} | ${d.tipoLabel||d.tipo} | ${motivo.trim()}`);
    toast('Documento reprovado.','success');
  }catch(e){ toast('Erro ao reprovar: '+e.message,'error'); }
}

// Renderiza, no topo da aba "Documentos" da ficha, os documentos APROVADOS
// que vieram do app do colaborador. Pendentes ficam na tela de Aprovação;
// reprovados ficam ocultos da ficha (auditoria via tela de Documentos).
function renderDocumentosAprovadosNaFicha(empId){
  const box=document.getElementById('doc-app-list'); if(!box) return;
  const docs=(State.documentos||[])
    .filter(d=>d.employeeId===empId && d.status==='aprovado')
    .sort((a,b)=>new Date(b.createdAt||0)-new Date(a.createdAt||0));
  if(docs.length===0){
    box.innerHTML='<div style="font-size:12px;color:#94a3b8;padding:8px 2px">Nenhum documento enviado pelo app ainda.</div>';
    return;
  }
  _docFichaAppItems=docs;   // guarda p/ o botão "Baixar". #docs-ver-baixar
  box.innerHTML = docs.map((d,i)=>{
    const meta=DOC_TIPOS_META[d.tipo]||{ico:'📄',nome:d.tipoLabel||d.tipo||'Documento'};
    const dt=(d.createdAt||'').substring(0,10).split('-').reverse().join('/');
    return `<div class="doc-item">
      <div class="doc-icon" style="font-size:22px">${meta.ico}</div>
      <div class="doc-info">
        <div class="doc-name">${meta.nome}${d.descricao?` <span style="color:#64748b;font-weight:400">— ${d.descricao.replace(/</g,'&lt;')}</span>`:''}</div>
        <div class="doc-meta">Enviado em ${dt} · aprovado por ${d.aprovadoPorNome||'—'}</div>
      </div>
      <div class="doc-actions">
        <a href="${d.arquivoUrl}" target="_blank" rel="noopener" class="btn-icon btn-outline" title="Visualizar"><i class="fa-solid fa-eye"></i></a>
        <button class="btn-icon btn-primary-icon" onclick="_baixarDocApp(${i})" title="Baixar"><i class="fa-solid fa-download"></i></button>
      </div>
    </div>`;
  }).join('');
}
let _docFichaAppItems=[];
function _baixarDocApp(i){ const d=(_docFichaAppItems||[])[i]; if(!d) return; const meta=DOC_TIPOS_META[d.tipo]||{}; _baixarArquivoUrl(d.arquivoUrl, d.arquivoNome||meta.nome||'documento'); }

function _lockPayrollForm(isLocked){
  const form=document.querySelector('#section-payroll .payroll-form-col');
  if(!form) return;
  // Inputs e selects (exceto colaborador, mês, ano, período)
  const editIds=['payroll-dias','payroll-faltas-justificadas','payroll-faltas-injustificadas',
    'payroll-remuneracao','payroll-vt-dia','payroll-vt-total','payroll-vr-dia','payroll-vr-total',
    'payroll-va-total','payroll-va-liquido','payroll-bonus','payroll-noturno','payroll-acumulo',
    'payroll-insalubridade','payroll-atraso-min','payroll-desconto-atraso',
    'payroll-atraso-tipo','payroll-atraso-justificativa','payroll-atraso-abonado','payroll-adiantamento-ativo',
    'payroll-adiantamento-perc','payroll-adiantamento-valor','payroll-entrada','payroll-saida',
    'payroll-intervalo-inicio','payroll-intervalo-fim','payroll-he-total','payroll-he-perc',
    'payroll-he-valor','payroll-observacao-folha','pdf-input'];
  editIds.forEach(id=>{ const el=document.getElementById(id); if(el) el.disabled=isLocked; });
  // Botões
  const saveBtn=document.querySelector('#section-payroll .btn-primary');
  if(saveBtn) saveBtn.disabled=isLocked;
  const recalcBtn=document.querySelector('#section-payroll [onclick*="recalculate"]');
  if(recalcBtn) recalcBtn.disabled=isLocked;
  // PDF upload area
  const pdfArea=document.getElementById('pdf-upload-area');
  if(pdfArea) pdfArea.style.pointerEvents=isLocked?'none':'auto';
  // Botão Reabrir
  const btnReabrir=document.getElementById('btn-reabrir-folha');
  if(btnReabrir) btnReabrir.style.display=isLocked?'inline-flex':'none';
  // Overlay visual
  const formCard=document.querySelector('#section-payroll .payroll-form-col .card-body');
  if(formCard) formCard.style.opacity=isLocked?'0.75':'1';
}

function _updateFolhaStatusBadge(){
  const empId=val('payroll-employee');
  const mes=parseInt(val('payroll-mes')||currentMes());
  const ano=parseInt(val('payroll-ano')||currentAno());
  const badge=document.getElementById('payroll-status-badge');
  if(!badge) return;
  const p=State.payrolls.find(r=>r.employeeId===empId&&r.mes==mes&&r.ano==ano);
  const fechada=p?.status==='fechada';
  const temFolha=!!p;
  badge.innerHTML=fechada
    ? `<span style="background:#E8EAF6;color:#5C6BC0;padding:3px 10px;border-radius:10px;font-size:12px;font-weight:700;white-space:nowrap"><i class="fa-solid fa-lock"></i> Folha Fechada</span>`
    : (temFolha?`<span style="background:#E8F5E9;color:#2E7D32;padding:3px 10px;border-radius:10px;font-size:12px;font-weight:700;white-space:nowrap"><i class="fa-solid fa-lock-open"></i> Folha Aberta</span>`:'');
  // Botão "Recalcular faltas (master)" — mesmo motor do botão em Benefícios.
  // Recalcula a competência selecionada aqui; como tudo lê do mesmo motor, atualizar
  // por aqui reflete em folha/contabilidade/holerite/recibo/Benefícios. #recalc-faltas-folha
  const _btnRecalcF=document.getElementById('btn-payroll-recalc-faltas');
  if(_btnRecalcF) _btnRecalcF.style.display=(Auth.currentUser?.role==='master')?'inline-flex':'none';
  // Botão "Fechar esta Folha" — visível só quando tem folha salva e está aberta
  const btnFecharInd=document.getElementById('btn-fechar-folha-individual');
  if(btnFecharInd) btnFecharInd.style.display=(temFolha&&!fechada)?'inline-flex':'none';
  // Botão "Reabrir esta Folha" — visível só quando fechada
  const btnReabrir=document.getElementById('btn-reabrir-folha');
  if(btnReabrir) btnReabrir.style.display=fechada?'inline-flex':'none';
  // Botão "Pagar via PIX" — visível quando fechada + colaborador tem chave PIX + sem pagamento anterior
  const btnPix=document.getElementById('btn-pagar-asaas');
  const pixBadge=document.getElementById('asaas-pago-badge');
  if(btnPix||pixBadge){
    const emp=State.employees.find(e=>e.id===empId);
    const temPix=!!(emp?.chavePix);
    const jaPago=!!(p?.pagamentoAsaas);
    if(btnPix) btnPix.style.display=(fechada&&temPix&&!jaPago)?'inline-flex':'none';
    if(pixBadge){
      if(fechada&&jaPago){
        const pg=p.pagamentoAsaas;
        pixBadge.style.display='inline-flex';
        pixBadge.innerHTML=`<span style="background:#E0F2F1;color:#00695C;padding:3px 10px;border-radius:10px;font-size:12px;font-weight:700;white-space:nowrap;cursor:pointer" onclick="openPagarColaborador()" title="Ver pagamento Asaas"><i class="fa-brands fa-pix"></i> ${fmtMoney(pg.asaasValor)} pago</span>`;
      } else {
        pixBadge.style.display='none';
        pixBadge.innerHTML='';
      }
    }
  }
  _lockPayrollForm(fechada);
}

