function maskCnpj(input){
  let v=input.value.replace(/\D/g,'').slice(0,14);
  if(v.length>12) v=v.replace(/^(\d{2})(\d{3})(\d{3})(\d{4})(\d{0,2}).*/,'$1.$2.$3/$4-$5');
  else if(v.length>8) v=v.replace(/^(\d{2})(\d{3})(\d{3})(\d{0,4}).*/,'$1.$2.$3/$4');
  else if(v.length>5) v=v.replace(/^(\d{2})(\d{3})(\d{0,3}).*/,'$1.$2.$3');
  else if(v.length>2) v=v.replace(/^(\d{2})(\d{0,3}).*/,'$1.$2');
  input.value=v;
}

// Consulta dados de um CNPJ na Receita Federal. Tenta a BrasilAPI e, se ela
// falhar (instabilidade / limite de consultas), cai para a minhareceita.org
// — mesma fonte de dados, mesmo formato de resposta. 2 tentativas em cada.
// Lança Error com `.tipo` = 'naoexiste' | 'ocupado' | 'indisponivel'.
async function _lookupCnpjData(cnpj){
  const fontes=[
    `https://brasilapi.com.br/api/cnpj/v1/${cnpj}`,
    `https://minhareceita.org/${cnpj}`,
  ];
  const pausa=ms=>new Promise(r=>setTimeout(r,ms));
  let ultimoErro='indisponivel';
  for(const url of fontes){
    for(let tent=0;tent<2;tent++){
      try{
        const res=await fetch(url);
        if(res.status===404){ ultimoErro='naoexiste'; break; }   // não tem nessa fonte → tenta a próxima
        if(res.status===429){ ultimoErro='ocupado'; await pausa(1500); continue; }
        if(!res.ok){ ultimoErro='indisponivel'; await pausa(900); continue; }
        const d=await res.json();
        if(d && (d.razao_social||d.cnpj)) return d;
        ultimoErro='naoexiste'; break;
      }catch(e){ ultimoErro='indisponivel'; await pausa(900); }
    }
  }
  const err=new Error(ultimoErro); err.tipo=ultimoErro; throw err;
}
// Mensagem amigável para o status box, conforme o tipo de falha.
function _cnpjErroMsg(tipo){
  if(tipo==='naoexiste') return 'CNPJ não encontrado na base da Receita. Confira o número digitado.';
  if(tipo==='ocupado')   return 'Serviço da Receita ocupado (muitas consultas no momento). Aguarde alguns segundos e tente de novo.';
  return 'Serviço da Receita instável agora. Tente novamente em instantes — ou preencha os campos manualmente.';
}
// HTML do status box de erro: mensagem + botão "Preencher manualmente".
// `tentarFn` = nome da função de lookup p/ tentar de novo; `focusId` = campo a focar.
function _cnpjErroHtml(tipo, tentarFn, focusId){
  return '<i class="fa-solid fa-triangle-exclamation"></i> ' + _cnpjErroMsg(tipo)
    + '<div style="margin-top:8px;display:flex;gap:8px;flex-wrap:wrap">'
    + `<button type="button" class="btn btn-sm" style="background:#fff;border:1px solid #FFCDD2;color:#B71C1C" onclick="${tentarFn}()"><i class="fa-solid fa-rotate-right"></i> Tentar de novo</button>`
    + `<button type="button" class="btn btn-sm" style="background:#fff;border:1px solid #cfd8dc;color:#37474F" onclick="preencherCnpjManual('${focusId}')"><i class="fa-solid fa-pen"></i> Preencher manualmente</button>`
    + '</div>';
}
// Dispensa o aviso de erro e leva o foco para o 1º campo, para o gestor digitar.
function preencherCnpjManual(focusId){
  ['cnpj-lookup-status','contrato-cnpj-status'].forEach(id=>{
    const s=document.getElementById(id); if(s) s.style.display='none';
  });
  const f=document.getElementById(focusId); if(f) f.focus();
  toast('Pode preencher os campos manualmente — o CNPJ é opcional.');
}

async function lookupCnpjPosto(){
  const cnpj=(val('posto-cnpj')||'').replace(/\D/g,'');
  if(cnpj.length!==14) return;
  const spinner=document.getElementById('cnpj-lookup-spinner');
  const statusEl=document.getElementById('cnpj-lookup-status');
  // Mostrar spinner
  if(spinner) spinner.style.display='inline';
  if(statusEl){ statusEl.style.display='none'; statusEl.textContent=''; }
  try {
    const d=await _lookupCnpjData(cnpj);
    // Preencher campos
    if(d.razao_social)  setVal('posto-razao',    toTitleCase(d.razao_social));
    if(d.nome_fantasia) setVal('posto-fantasia',  toTitleCase(d.nome_fantasia));
    if(d.email)         setVal('posto-email',     d.email.toLowerCase());
    if(d.ddd_telefone_1){
      const tel=(d.ddd_telefone_1||'').replace(/\D/g,'');
      const fmtTel=tel.length>=10?tel.replace(/^(\d{2})(\d{4,5})(\d{4})$/,'($1) $2-$3'):tel;
      setVal('posto-telefone', fmtTel);
    }
    if(d.cep){
      const cepFmt=d.cep.replace(/\D/g,'').replace(/^(\d{5})(\d{3})$/,'$1-$2');
      setVal('posto-cep', cepFmt);
    }
    if(d.logradouro)    setVal('posto-endereco',  toTitleCase(d.logradouro));
    if(d.numero)        setVal('posto-numero',    d.numero);
    if(d.complemento)   setVal('posto-complemento', toTitleCase(d.complemento));
    if(d.bairro)        setVal('posto-bairro',    toTitleCase(d.bairro));
    if(d.municipio)     setVal('posto-cidade',    toTitleCase(d.municipio));
    if(d.uf)            setVal('posto-estado',    d.uf);
    // Status da empresa
    const sit=(d.situacao_cadastral||'').toUpperCase();
    const isAtiva=sit==='ATIVA';
    const sitIcon=isAtiva?'circle-check':'circle-exclamation';
    const sitColor=isAtiva?'#1B5E20':'#E65100';
    const sitBg=isAtiva?'#F1F8E9':'#FFF3E0';
    const sitBorder=isAtiva?'#A5D6A7':'#FFCC80';
    if(statusEl){
      statusEl.style.display='block';
      statusEl.style.background=sitBg;
      statusEl.style.border=`1px solid ${sitBorder}`;
      statusEl.style.color=sitColor;
      statusEl.innerHTML=`<i class="fa-solid fa-${sitIcon}"></i> <strong>${toTitleCase(d.razao_social)}</strong> &nbsp;|&nbsp; Situação: <strong>${sit}</strong>${d.data_inicio_atividade?' &nbsp;|&nbsp; Fundação: '+d.data_inicio_atividade.split('-').reverse().join('/'):''}`;
    }
    toast('Dados preenchidos automaticamente pela Receita Federal ✓');
  } catch(e){
    if(statusEl){
      statusEl.style.display='block';
      statusEl.style.background='#FFF3F3';
      statusEl.style.border='1px solid #FFCDD2';
      statusEl.style.color='#B71C1C';
      statusEl.innerHTML=_cnpjErroHtml(e&&e.tipo,'lookupCnpjPosto','posto-razao');
    }
  } finally {
    if(spinner) spinner.style.display='none';
  }
}

async function lookupCnpjContrato(){
  const cnpj=(val('contrato-cnpj')||'').replace(/\D/g,'');
  if(cnpj.length!==14) return;
  const spinner=document.getElementById('contrato-cnpj-spinner');
  const statusEl=document.getElementById('contrato-cnpj-status');
  if(spinner) spinner.style.display='inline';
  if(statusEl){ statusEl.style.display='none'; statusEl.textContent=''; }
  try {
    const d=await _lookupCnpjData(cnpj);
    if(d.razao_social) setVal('contrato-razao', toTitleCase(d.razao_social));
    if(d.email)        setVal('contrato-email',  d.email.toLowerCase());
    // Montar endereço completo numa linha
    const partes=[
      d.logradouro?toTitleCase(d.logradouro):'',
      d.numero||'',
      d.complemento?toTitleCase(d.complemento):'',
      d.bairro?toTitleCase(d.bairro):'',
      d.municipio?toTitleCase(d.municipio):'',
      d.uf||''
    ].filter(Boolean);
    if(partes.length) setVal('contrato-endereco', partes.join(', '));
    const sit=(d.situacao_cadastral||'').toUpperCase();
    const isAtiva=sit==='ATIVA';
    if(statusEl){
      statusEl.style.display='block';
      statusEl.style.background=isAtiva?'#F1F8E9':'#FFF3E0';
      statusEl.style.border=`1px solid ${isAtiva?'#A5D6A7':'#FFCC80'}`;
      statusEl.style.color=isAtiva?'#1B5E20':'#E65100';
      statusEl.innerHTML=`<i class="fa-solid fa-${isAtiva?'circle-check':'circle-exclamation'}"></i> <strong>${toTitleCase(d.razao_social)}</strong> &nbsp;|&nbsp; Situação: <strong>${sit}</strong>${d.data_inicio_atividade?' &nbsp;|&nbsp; Fundação: '+d.data_inicio_atividade.split('-').reverse().join('/'):''}`;
    }
    toast('Dados do cliente preenchidos pela Receita Federal ✓');
  } catch(e){
    if(statusEl){
      statusEl.style.display='block';
      statusEl.style.background='#FFF3F3';
      statusEl.style.border='1px solid #FFCDD2';
      statusEl.style.color='#B71C1C';
      statusEl.innerHTML=_cnpjErroHtml(e&&e.tipo,'lookupCnpjContrato','contrato-razao');
    }
  } finally {
    if(spinner) spinner.style.display='none';
  }
}

function onContratoPostoChange(){
  const postoId=val('contrato-posto');
  if(!postoId) return;
  const p=State.postos.find(x=>x.id===postoId);
  if(!p) return;
  // Preencher dados do cliente a partir do posto cadastrado
  if(p.cnpj)     setVal('contrato-cnpj',     p.cnpj);
  if(p.razaoSocial) setVal('contrato-razao', p.razaoSocial);
  if(p.email)    setVal('contrato-email',    p.email);
  if(p.telefone) setVal('contrato-telefone', p.telefone);
  // Montar endereço a partir dos campos do posto
  const partes=[p.endereco, p.numero, p.complemento, p.bairro, p.cidade, p.estado].filter(Boolean);
  if(partes.length) setVal('contrato-endereco', partes.join(', '));
  // Limpar status do CNPJ anterior
  const statusEl=document.getElementById('contrato-cnpj-status');
  if(statusEl) statusEl.style.display='none';
}

function toTitleCase(str){
  if(!str) return '';
  const minusculas=['de','da','do','das','dos','e','em','a','o','as','os','com','para','por','no','na','nos','nas'];
  return str.toLowerCase().split(' ').map((w,i)=>
    (!i||!minusculas.includes(w))?w.charAt(0).toUpperCase()+w.slice(1):w
  ).join(' ');
}

function maskTelefone(input){
  let v=input.value.replace(/\D/g,'').slice(0,11);
  if(v.length>10) v=v.replace(/^(\d{2})(\d{5})(\d{4})$/,'($1) $2-$3');
  else if(v.length>6) v=v.replace(/^(\d{2})(\d{4,5})(\d{0,4}).*/,'($1) $2-$3');
  else if(v.length>2) v=v.replace(/^(\d{2})(\d{0,5}).*/,'($1) $2');
  input.value=v;
}

async function fetchCepPosto(){
  const cep=(val('posto-cep')||'').replace(/\D/g,'');
  if(cep.length!==8) return;
  try {
    const r=await fetch(`https://viacep.com.br/ws/${cep}/json/`);
    const d=await r.json();
    if(!d.erro){
      setVal('posto-endereco',d.logradouro||'');
      setVal('posto-bairro',d.bairro||'');
      setVal('posto-cidade',d.localidade||'');
      setVal('posto-estado',d.uf||'');
    }
  } catch(e){}
}

function renderPostosTable(){
  const q=(val('postos-search')||'').toLowerCase();
  const tbody=document.getElementById('postos-tbody'); if(!tbody) return;
  const lista=State.postos.filter(p=>
    !q ||
    (p.razaoSocial||'').toLowerCase().includes(q) ||
    (p.cnpj||'').includes(q) ||
    (p.cidade||'').toLowerCase().includes(q)
  );
  if(lista.length===0){
    tbody.innerHTML=`<tr><td colspan="6" class="empty-row"><i class="fa-solid fa-building"></i> Nenhum posto cadastrado</td></tr>`;
    return;
  }
  tbody.innerHTML=lista.map(p=>{
    const colaboradores=State.employees.filter(e=>e.posto===p.razaoSocial && (e.status||'ativo')==='ativo').length;
    const nomeExibir=p.nomeFantasia
      ?`<strong>${p.nomeFantasia}</strong><br><span style="font-size:11px;color:var(--text-muted)">${p.razaoSocial}</span>`
      :`<strong>${p.razaoSocial}</strong>`;
    return `<tr>
      <td>${nomeExibir}</td>
      <td style="font-size:12px">${p.cnpj||'—'}</td>
      <td style="font-size:12px">${p.cidade?(p.cidade+(p.estado?' / '+p.estado:'')):'—'}</td>
      <td style="font-size:12px">${p.telefone||'—'}</td>
      <td style="font-size:12px">${p.email?`<a href="mailto:${p.email}" style="color:var(--primary)">${p.email}</a>`:'—'}</td>
      <td><span class="badge-count">${colaboradores}</span></td>
      <td>
        <button class="btn-action btn-edit" onclick="openPostoModal('${p.id}')" title="Editar"><i class="fa-solid fa-pen"></i></button>
        <button class="btn-action btn-danger" onclick="confirmDeletePosto('${p.id}')" title="Excluir"><i class="fa-solid fa-trash"></i></button>
      </td>
    </tr>`;
  }).join('');
}

function populatePostoSelect(){
  const sel=document.getElementById('emp-posto');
  if(!sel) return;
  const current=sel.value;
  sel.innerHTML='<option value="">— Selecione o posto —</option>';
  State.postos.sort((a,b)=>(a.razaoSocial||'').localeCompare(b.razaoSocial||'')).forEach(p=>{
    const opt=document.createElement('option');
    opt.value=p.razaoSocial;
    opt.textContent=p.razaoSocial+(p.cidade?' — '+p.cidade:'');
    sel.appendChild(opt);
  });
  if(current) sel.value=current;
}

function openPostoModal(id=null){
  document.getElementById('modal-posto').classList.remove('hidden');
  const titleEl=document.getElementById('modal-posto-title');
  if(id){
    const p=State.postos.find(x=>x.id===id); if(!p) return;
    titleEl.innerHTML='<i class="fa-solid fa-building"></i> Editar Posto';
    setVal('posto-id',p.id);
    setVal('posto-razao',p.razaoSocial||'');
    setVal('posto-fantasia',p.nomeFantasia||'');
    setVal('posto-cnpj',p.cnpj||'');
    setVal('posto-telefone',p.telefone||'');
    setVal('posto-email',p.email||'');
    setVal('posto-cep',p.cep||'');
    setVal('posto-endereco',p.endereco||'');
    setVal('posto-numero',p.numero||'');
    setVal('posto-complemento',p.complemento||'');
    setVal('posto-bairro',p.bairro||'');
    setVal('posto-cidade',p.cidade||'');
    setVal('posto-estado',p.estado||'');
    const statusEl=document.getElementById('cnpj-lookup-status');
    if(statusEl) statusEl.style.display='none';
  } else {
    titleEl.innerHTML='<i class="fa-solid fa-building"></i> Novo Posto';
    ['posto-id','posto-razao','posto-fantasia','posto-cnpj','posto-telefone','posto-email','posto-cep',
     'posto-endereco','posto-numero','posto-complemento','posto-bairro','posto-cidade','posto-estado']
      .forEach(id=>setVal(id,''));
    const statusEl=document.getElementById('cnpj-lookup-status');
    if(statusEl) statusEl.style.display='none';
  }
}

async function savePosto(){
  const razao=val('posto-razao').trim();
  if(!razao){ toast('Informe a Razão Social.','error'); return; }
  const existingPostoId=val('posto-id');
  const id=existingPostoId||genId();
  const record={
    id, razaoSocial:razao,
    nomeFantasia:val('posto-fantasia').trim(),
    cnpj:val('posto-cnpj').trim(),
    telefone:val('posto-telefone').trim(),
    email:val('posto-email').trim(),
    cep:val('posto-cep').trim(),
    endereco:val('posto-endereco').trim(),
    numero:val('posto-numero').trim(),
    complemento:val('posto-complemento').trim(),
    bairro:val('posto-bairro').trim(),
    cidade:val('posto-cidade').trim(),
    estado:val('posto-estado').trim(),
    updatedAt:new Date().toISOString()
  };
  try {
    await DB.save('postos',record);
    Auth.log(existingPostoId?'POSTO_UPDATED':'POSTO_CREATED', null, `${razao}${record.cidade?' — '+record.cidade:''}`);
    toast(existingPostoId?'Posto atualizado!':'Posto cadastrado!');
    closeModal('modal-posto');
  } catch(e){ toast('Erro ao salvar posto.','error'); }
}

// ── RUBRICAS — catálogo de proventos/descontos (Fase 1) ──────────────
const RUBRICAS_SEED = [
  { codigo:'224', descricao:'Seguro de Vida',             tipo:'D', calculo:'fixo', fixaTodos:true, valorPadrao:2.40 },
  { codigo:'212', descricao:'Pensão Alimentícia',          tipo:'D', calculo:'fixo' },
  { codigo:'218', descricao:'Desconto Empréstimo',         tipo:'D', calculo:'fixo' },
  { codigo:'235', descricao:'Empréstimo Consignado',       tipo:'D', calculo:'fixo' },
  { codigo:'239', descricao:'Desconto Pagamento Indevido', tipo:'D', calculo:'fixo' },
  { codigo:'207', descricao:'Reembolso Desconto Indevido', tipo:'P', calculo:'fixo' },
  { codigo:'19',  descricao:'Diferença de Salários',       tipo:'P', calculo:'fixo' },
];
let _rubricasSeedTentado = false;
async function _seedRubricasSeNecessario(){
  if(_rubricasSeedTentado) return;
  if(!Auth.currentUser || Auth.currentUser.role!=='master') return;  // só master semeia
  if((State.rubricas||[]).length > 0) return;
  _rubricasSeedTentado = true;
  for(const r of RUBRICAS_SEED){
    try{ await DB.save('rubricas', { id:genId(), base:'salarioBase', incideINSS:false, incideFGTS:false, incideIRRF:false, ativa:true, sistema:true, valorPadrao:0, fixaTodos:false, ...r, updatedAt:new Date().toISOString() }); }
    catch(e){ console.error('seed rubrica', e); }
  }
}
function _rubricaCalcLabel(c){ return c==='percentual' ? '% do salário' : c==='quantidade' ? 'Qtde × valor' : 'Valor fixo'; }
function renderRubricas(){
  const tbody=document.getElementById('rubricas-tbody'); if(!tbody) return;
  const lista=(State.rubricas||[]).slice().sort((a,b)=>(a.descricao||'').localeCompare(b.descricao||''));
  if(!lista.length){
    tbody.innerHTML=`<tr><td colspan="6" class="empty-row"><i class="fa-solid fa-list-check"></i> Nenhuma rubrica — clique "Nova rubrica" (as padrões são semeadas no 1º acesso do master)</td></tr>`;
    return;
  }
  tbody.innerHTML=lista.map(r=>{
    const tipoBadge = r.tipo==='P'
      ? '<span class="badge" style="background:#E8F5E9;color:#1B5E20">Provento</span>'
      : '<span class="badge" style="background:#FFEBEE;color:#C62828">Desconto</span>';
    const fixa = r.fixaTodos ? ` <span class="badge" style="background:#F3E5F5;color:#7B1FA2" title="Aplica automaticamente a todos os ativos">Fixa p/ todos · ${fmtMoney(r.valorPadrao||0)}</span>` : '';
    const inc = [r.incideINSS?'INSS':'',r.incideFGTS?'FGTS':'',r.incideIRRF?'IRRF':''].filter(Boolean).join(' · ')||'—';
    return `<tr>
      <td style="font-size:12px">${esc(r.codigo||'—')}</td>
      <td><strong>${esc(r.descricao||'—')}</strong>${fixa}</td>
      <td>${tipoBadge}</td>
      <td style="font-size:12px">${_rubricaCalcLabel(r.calculo)}</td>
      <td style="font-size:11px;color:#888">${inc}</td>
      <td>
        <button class="btn-action btn-edit" onclick="openRubricaModal('${r.id}')" title="Editar"><i class="fa-solid fa-pen"></i></button>
        <button class="btn-action btn-danger" onclick="confirmDeleteRubrica('${r.id}')" title="Excluir"><i class="fa-solid fa-trash"></i></button>
      </td>
    </tr>`;
  }).join('');
}
function _rubricaFixaToggle(){
  const row=document.getElementById('rubrica-row-valorpadrao');
  if(row) row.style.display = document.getElementById('rubrica-fixatodos')?.checked ? '' : 'none';
}
function openRubricaModal(id=null){
  document.getElementById('modal-rubrica').classList.remove('hidden');
  const r = id ? (State.rubricas||[]).find(x=>x.id===id) : null;
  setVal('rubrica-id', r?r.id:'');
  setVal('rubrica-codigo', r?(r.codigo||''):'');
  setVal('rubrica-descricao', r?(r.descricao||''):'');
  setVal('rubrica-tipo', r?(r.tipo||'D'):'D');
  setVal('rubrica-calculo', r?(r.calculo||'fixo'):'fixo');
  const fx=document.getElementById('rubrica-fixatodos'); if(fx) fx.checked=!!(r&&r.fixaTodos);
  setVal('rubrica-valorpadrao', (r&&r.valorPadrao)?r.valorPadrao:'');
  const ii=document.getElementById('rubrica-inss'); if(ii) ii.checked=!!(r&&r.incideINSS);
  const ig=document.getElementById('rubrica-fgts'); if(ig) ig.checked=!!(r&&r.incideFGTS);
  const ir=document.getElementById('rubrica-irrf'); if(ir) ir.checked=!!(r&&r.incideIRRF);
  document.getElementById('modal-rubrica-title').innerHTML = id?'<i class="fa-solid fa-pen"></i> Editar Rubrica':'<i class="fa-solid fa-plus"></i> Nova Rubrica';
  _rubricaFixaToggle();
}
async function salvarRubrica(){
  const desc=val('rubrica-descricao').trim();
  if(!desc){ toast('Informe a descrição da rubrica.','error'); return; }
  const id=val('rubrica-id')||genId();
  const record={
    id, codigo:val('rubrica-codigo').trim(), descricao:desc,
    tipo: val('rubrica-tipo')||'D',
    calculo: val('rubrica-calculo')||'fixo',
    fixaTodos: !!document.getElementById('rubrica-fixatodos')?.checked,
    valorPadrao: parseFloat(val('rubrica-valorpadrao'))||0,
    base:'salarioBase',
    incideINSS: !!document.getElementById('rubrica-inss')?.checked,
    incideFGTS: !!document.getElementById('rubrica-fgts')?.checked,
    incideIRRF: !!document.getElementById('rubrica-irrf')?.checked,
    ativa:true, sistema:false, updatedAt:new Date().toISOString()
  };
  try{ await DB.save('rubricas', record); toast('Rubrica salva!'); closeModal('modal-rubrica'); }
  catch(e){ toast('Erro ao salvar rubrica.','error'); }
}
async function confirmDeleteRubrica(id){
  const r=(State.rubricas||[]).find(x=>x.id===id); if(!r) return;
  if(!confirm(`Excluir a rubrica "${r.descricao}"? Lançamentos já feitos nas folhas não são afetados.`)) return;
  try{ await DB.remove('rubricas', id); toast('Rubrica excluída.'); }catch(e){ toast('Erro ao excluir.','error'); }
}

// ---- Histórico de Postos ----

// Timeline de lotação (posto/turno/escala/função/salário por vigência) — pra
// conferência. Cada período aplica suas regras no cálculo da folha por data.
function renderHistoricoLotacao(emp){
  const el=document.getElementById('historico-lotacao-list'); if(!el) return;
  const hist=(emp?.historicoLotacao||[]).slice().sort((a,b)=>(b.dataInicio||'').localeCompare(a.dataInicio||''));
  if(!hist.length){ el.innerHTML=''; return; }
  // Mostra a regra COMPLETA de cada período — tudo que incide a partir da data:
  // posto/função/escala/turno/salário + adicionais + BENEFÍCIOS (VT/VR/VA). Assim o
  // contrato é a fonte única visível: trabalhista E benefícios, segmentados por data.
  const _bn=v=>(v!=null && v!=='' && !isNaN(parseFloat(v))) ? fmtMoney(v) : '—';
  // Projeção dos benefícios do PRÓXIMO mês — o cruzamento da escala do contrato com
  // os dias do mês de uso (o que será pago, antes de descontos por falta). Mostra
  // no contrato que o benefício sai da escala, não da folha de ponto. #benef-segmentado
  let _projHtml='';
  try{
    const _hm=new Date().getMonth()+1, _ha=new Date().getFullYear();
    let _mu=_hm+1, _au=_ha; if(_mu>12){_mu=1;_au++;}
    const _b=_calcBeneficiosColabPrevisto(emp, _mu, _au, _hm, _ha);
    const _tot=(_b.vtCheio||0)+(_b.vrCheio||0)+(_b.vaCheio||0);
    _projHtml=`<div style="background:#E1F5FE;border-left:4px solid #0277BD;border-radius:6px;padding:8px 12px;font-size:12px;color:#01579B;margin-bottom:10px">
      <i class="fa-solid fa-arrow-trend-up"></i> <strong>Benefícios do próximo mês (projetados pela escala do contrato):</strong>
      ${_b.diasVt||0} dia(s) previsto(s) · VT ${fmtMoney(_b.vtCheio||0)} · VR ${fmtMoney(_b.vrCheio||0)} · VA ${fmtMoney(_b.vaCheio||0)} = <strong>${fmtMoney(_tot)}</strong>
      <span style="font-size:11px;color:#0277BD">(antes de descontos por falta · BP à parte)</span>
    </div>`;
  }catch(_){}
  el.innerHTML=_projHtml+`<div style="font-size:12px;color:var(--text-muted);margin:0 0 4px"><i class="fa-solid fa-timeline"></i> Linha do tempo de lotação — cada regra vale <strong>a partir da data</strong> (aplicada no cálculo trabalhista <strong>e</strong> nos benefícios):</div>
    <div style="overflow-x:auto"><table class="report-table" style="font-size:12px;margin-bottom:10px;min-width:920px">
      <thead><tr>
        <th style="background:#5C6BC0">A partir de</th>
        <th style="background:#5C6BC0">Posto</th>
        <th style="background:#5C6BC0">Função</th>
        <th style="background:#5C6BC0">Escala</th>
        <th style="background:#5C6BC0">Turno</th>
        <th style="background:#5C6BC0">Horário</th>
        <th style="background:#5C6BC0">Salário</th>
        <th style="background:#5C6BC0">Adicionais</th>
        <th style="background:#5C6BC0">Benefícios <small style="font-weight:400">(VT/dia · VR/dia · VA/mês)</small></th>
        <th style="background:#5C6BC0"></th>
      </tr></thead>
      <tbody>
      ${hist.map(h=>{
        const adic=[h.insalubridade?`Insal. ${h.insalubridade}%`:'', h.acumuloFuncao?'Acúmulo +20%':''].filter(Boolean).join(' · ')||'—';
        const benef=`VT ${_bn(h.valorDiarioVt)} · VR ${_bn(h.valorDiarioVr)} · VA ${_bn(h.valorMensalVa)}`;
        return `<tr>
          <td><strong>${formatDateBr(h.dataInicio)}</strong></td>
          <td>${h.posto||'—'}</td>
          <td>${h.cargo||'—'}</td>
          <td>${h.escala||'—'}</td>
          <td>${h.turnoNoturno?'<span style="color:#5C6BC0;font-weight:600">Noturno</span>':'Diurno'}</td>
          <td style="white-space:nowrap;font-variant-numeric:tabular-nums">${h.horarioEntrada||'—'}–${h.horarioSaida||'—'}${h.semRefeicao?' <small style="color:#C62828">(s/ ref.)</small>':((h.horarioRefIni||h.horarioRefFim)?` <small style="color:#888">int ${h.horarioRefIni||'—'}–${h.horarioRefFim||'—'}</small>`:'')}</td>
          <td>${fmtMoney(h.salarioBase||0)}</td>
          <td style="font-size:11px">${adic}</td>
          <td style="font-size:11px;white-space:nowrap">${benef}</td>
          <td style="white-space:nowrap">
            <button class="btn-icon" title="Editar este período" onclick="editarPeriodoLotacao('${h.id}')"><i class="fa-solid fa-pen" style="color:#1565C0"></i></button>
            <button class="btn-icon btn-danger-icon" title="Remover este período" onclick="removeHistoricoLotacao('${h.id}')"><i class="fa-solid fa-trash"></i></button>
          </td>
        </tr>`;
      }).join('')}
      </tbody>
    </table></div>`;
}

async function removeHistoricoLotacao(id){
  const empId=State.editingEmployeeId;
  const emp=State.employees.find(e=>e.id===empId); if(!emp) return;
  if(!confirm('Remover este período de lotação? O cálculo dos dias afetados volta a usar o período anterior.')) return;
  let lotHist=(emp.historicoLotacao||[]).filter(h=>h.id!==id).sort((a,b)=>a.dataInicio.localeCompare(b.dataInicio));
  const ultimo=lotHist[lotHist.length-1];
  const updated={ ...emp, historicoLotacao:lotHist, updatedAt:new Date().toISOString() };
  if(ultimo){ Object.assign(updated, {
    posto:ultimo.posto, turnoNoturno:ultimo.turnoNoturno, escala:ultimo.escala,
    ciclo12x36Inicio: (escalaFamilia(ultimo.escala||'')==='12x36') ? (ultimo.ciclo12x36Inicio||emp.ciclo12x36Inicio||'') : (emp.ciclo12x36Inicio||''),
    horarioEntrada:ultimo.horarioEntrada, horarioSaida:ultimo.horarioSaida,
    horarioRefIni:ultimo.horarioRefIni, horarioRefFim:ultimo.horarioRefFim,
    cargo:ultimo.cargo, salarioBase:ultimo.salarioBase,
    insalubridade:ultimo.insalubridade, acumuloFuncao:ultimo.acumuloFuncao
  }); }
  try{
    await DB.save('employees', _sanitizeForFirestore(updated));
    Object.assign(emp, updated);
    renderHistoricoLotacao(updated);
    if(val('payroll-employee')===empId){ try{ onPayrollEmployeeChange(); }catch(_){} }
    toast('Período de lotação removido.','success');
  }catch(e){ console.error('removeHistoricoLotacao',e); toast('Erro ao remover.','error'); }
}

function renderHistoricoPostos(emp){
  renderHistoricoLotacao(emp);
  const el=document.getElementById('historico-postos-list'); if(!el) return;
  const hist=(emp?.historicoPostos||[]).slice().sort((a,b)=>new Date(b.dataInicio)-new Date(a.dataInicio));
  if(hist.length===0){
    el.innerHTML=`<div class="empty-state small" style="padding:12px">
      <i class="fa-solid fa-building"></i>
      <p style="font-size:13px">Nenhuma transferência registrada</p>
    </div>`;
    return;
  }
  el.innerHTML=`<div class="posto-hist-table">
    <table class="report-table" style="font-size:13px">
      <thead><tr>
        <th style="background:var(--primary)">Posto</th>
        <th style="background:var(--primary)">Entrada</th>
        <th style="background:var(--primary)">Saída</th>
        <th style="background:var(--primary)">Observação</th>
        <th style="background:var(--primary)"></th>
      </tr></thead>
      <tbody>
      ${hist.map((h,i)=>`<tr>
        <td><strong>${h.postoNome}</strong></td>
        <td>${formatDateBr(h.dataInicio)}</td>
        <td>${h.dataFim?formatDateBr(h.dataFim):'<span class="badge-atual">Atual</span>'}</td>
        <td style="color:var(--text-muted);font-size:12px">${h.obs||'—'}</td>
        <td><button class="btn-icon btn-danger-icon" title="Remover"
          onclick="removeHistoricoPosto(${i})"><i class="fa-solid fa-trash"></i></button></td>
      </tr>`).join('')}
      </tbody>
    </table>
  </div>`;
}

// ISO menos N dias.
function _isoMinusDays(iso, n){
  const d=new Date(iso+'T12:00:00'); d.setDate(d.getDate()-n);
  return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
}
// Remove as escalas SALVAS do colaborador a partir do mês da vigência (inclusive),
// para que _getExpectedDay reprojete por lotação (split por data) nesses meses.
async function _limparEscalasSalvasDesde(empId, vigISO){
  const [vy,vm]=vigISO.split('-').map(Number);
  const afetadas=(State.escalas||[]).filter(es=>es.employeeId===empId && (es.ano>vy || (es.ano===vy && es.mes>=vm)));
  for(const es of afetadas){ try{ await DB.remove('escalas', es.id); }catch(_){} }
  if(afetadas.length) State.escalas=(State.escalas||[]).filter(es=>!afetadas.includes(es));
}

// Mostra o campo "início do ciclo 12x36" no modal de transferência só quando a
// escala selecionada é 12x36 (a paridade trabalho/folga depende da âncora). #troca-escala-12x36
function _transfToggleCiclo12x36(){
  const row=document.getElementById('transf-row-ciclo12x36');
  if(!row) return;
  row.style.display = (escalaFamilia(val('transf-escala')||'')==='12x36') ? '' : 'none';
}

function openTransferenciaModal(){
  const empId=State.editingEmployeeId;
  const emp=State.employees.find(e=>e.id===empId);
  if(!empId||!emp){ toast('Salve o colaborador antes de registrar mudanças de lotação.','warning'); return; }
  const hojeISO=new Date().toISOString().slice(0,10);
  const lot=_lotacaoEm(emp, hojeISO);
  document.getElementById('transferencia-posto-atual-texto').textContent =
    `Lotação atual: ${lot.posto||'—'} · ${lot.cargo||emp.setor||'—'} · ${lot.escala||'—'}${lot.turnoNoturno?' (noturno)':''} · ${fmtMoney(lot.salarioBase||0)}`;
  // Novo posto (todos; "" = manter o atual)
  const sel=document.getElementById('transf-novo-posto');
  sel.innerHTML='<option value="">— Manter posto atual —</option>';
  State.postos.slice().sort((a,b)=>(a.razaoSocial||'').localeCompare(b.razaoSocial||'')).forEach(p=>{
    const opt=document.createElement('option');
    opt.value=p.razaoSocial;
    opt.textContent=p.razaoSocial+(p.cidade?' — '+p.cidade:'');
    sel.appendChild(opt);
  });
  // Escala — clona as opções do cadastro (inclui as personalizadas)
  const escSel=document.getElementById('transf-escala'), empEsc=document.getElementById('emp-escala');
  if(escSel && empEsc) escSel.innerHTML=empEsc.innerHTML;
  if(escSel) escSel.value=emp.escala||'5x2A';
  // Âncora do ciclo 12x36 (paridade) — só aparece p/ escala 12x36. Vazio = usa a vigência.
  if(escSel) escSel.onchange=_transfToggleCiclo12x36;
  setVal('transf-ciclo-12x36', emp.ciclo12x36Inicio||'');
  _transfToggleCiclo12x36();
  // Pré-preenche com a lotação atual (muda só o que trocou)
  setVal('transf-data-entrada',hojeISO);
  setVal('transf-cargo',emp.cargo||'');
  setVal('transf-salario',emp.salarioBase||'');
  const tn=document.getElementById('transf-turno-noturno'); if(tn) tn.checked=!!emp.turnoNoturno;
  setVal('transf-h-entrada',emp.horarioEntrada||'');
  setVal('transf-h-saida',emp.horarioSaida||'');
  setVal('transf-h-ref-ini',emp.horarioRefIni||'');
  setVal('transf-h-ref-fim',emp.horarioRefFim||'');
  setVal('transf-insalubridade',String(emp.insalubridade||0));
  const ac=document.getElementById('transf-acumulo'); if(ac) ac.checked=!!emp.acumuloFuncao;
  // Benefícios — pré-preenche com os valores atuais (muda só o que o novo posto altera)
  setVal('transf-vt-valor', emp.valorDiarioVt||'');
  setVal('transf-vt-freq', emp.vtFreq||'diario');
  setVal('transf-vr-valor', emp.valorDiarioVr||'');
  setVal('transf-vr-freq', emp.vrFreq||'diario');
  setVal('transf-va-valor', emp.valorMensalVa||'');
  setVal('transf-obs','');
  document.getElementById('modal-transferencia').classList.remove('hidden');
}

// Editar um período EXISTENTE da linha do tempo: abre o modal pré-preenchido com os
// dados do período (inclusive a DATA). Salvar com a mesma data SUBSTITUI o período
// (saveTransferencia filtra por dataInicio). #editar-periodo-lotacao
function editarPeriodoLotacao(id){
  const empId=State.editingEmployeeId;
  const emp=State.employees.find(e=>e.id===empId); if(!emp) return;
  const p=(emp.historicoLotacao||[]).find(h=>h.id===id);
  if(!p){ toast('Período não encontrado.','error'); return; }
  openTransferenciaModal();                       // monta postos/escala/etc.
  setVal('transf-data-entrada', p.dataInicio||'');
  const escSel=document.getElementById('transf-escala');
  if(escSel){ escSel.value=p.escala||emp.escala||'5x2A'; if(typeof escSel.onchange==='function') escSel.onchange(); }
  const selP=document.getElementById('transf-novo-posto'); if(selP) selP.value=p.posto||'';
  setVal('transf-ciclo-12x36', p.ciclo12x36Inicio||'');
  setVal('transf-cargo', p.cargo||'');
  setVal('transf-salario', p.salarioBase||'');
  const tn=document.getElementById('transf-turno-noturno'); if(tn) tn.checked=!!p.turnoNoturno;
  setVal('transf-h-entrada', p.horarioEntrada||'');
  setVal('transf-h-saida', p.horarioSaida||'');
  setVal('transf-h-ref-ini', p.horarioRefIni||'');
  setVal('transf-h-ref-fim', p.horarioRefFim||'');
  setVal('transf-insalubridade', String(p.insalubridade||0));
  const ac=document.getElementById('transf-acumulo'); if(ac) ac.checked=!!p.acumuloFuncao;
  setVal('transf-vt-valor', p.valorDiarioVt||'');
  setVal('transf-vt-freq', p.vtFreq||'diario');
  setVal('transf-vr-valor', p.valorDiarioVr||'');
  setVal('transf-vr-freq', p.vrFreq||'diario');
  setVal('transf-va-valor', p.valorMensalVa||'');
  setVal('transf-obs', p.obs||'');
  toast(`Editando o período de ${formatDateBr(p.dataInicio)} — salvar substitui esse período (mantém a data).`,'info');
}

async function saveTransferencia(){
  const empId=State.editingEmployeeId;
  const emp=State.employees.find(e=>e.id===empId); if(!emp) return;
  const vig=val('transf-data-entrada');
  if(!vig){ toast('Informe a data de vigência (a partir de quando vale).','error'); return; }
  const novoPosto=val('transf-novo-posto')||emp.posto||'';
  const obs=val('transf-obs').trim();
  const snapNovo={
    id:genId(), dataInicio:vig,
    posto:novoPosto,
    turnoNoturno:!!(document.getElementById('transf-turno-noturno')||{}).checked,
    escala:val('transf-escala')||emp.escala||'5x2A',
    // Âncora do ciclo 12x36 da NOVA fase (paridade trabalho/folga). Só p/ 12x36;
    // vazio → a folha usa a dataInicio (vigência) como âncora. #troca-escala-12x36
    ciclo12x36Inicio: (escalaFamilia(val('transf-escala')||emp.escala||'5x2A')==='12x36') ? (val('transf-ciclo-12x36')||'') : '',
    horarioEntrada:val('transf-h-entrada')||'',
    horarioSaida:val('transf-h-saida')||'',
    horarioRefIni:val('transf-h-ref-ini')||'',
    horarioRefFim:val('transf-h-ref-fim')||'',
    semRefeicao:!!emp.semRefeicao,
    cargo:val('transf-cargo')||'',
    salarioBase:parseFloat(val('transf-salario'))||emp.salarioBase||0,
    insalubridade:parseInt(val('transf-insalubridade'))||0,
    acumuloFuncao:!!(document.getElementById('transf-acumulo')||{}).checked,
    // Benefícios do período (incidem a partir de dataInicio) — #benef-segmentado
    valorDiarioVt:parseFloat(val('transf-vt-valor'))||0,
    vtFreq:val('transf-vt-freq')||'diario',
    valorDiarioVr:parseFloat(val('transf-vr-valor'))||0,
    vrFreq:val('transf-vr-freq')||'diario',
    valorMensalVa:parseFloat(val('transf-va-valor'))||0,
    obs
  };
  // historicoLotacao — semeia o estado atual como 1º período (admissão) se vazio
  let lotHist=[...(emp.historicoLotacao||[])];
  if(!lotHist.length){
    lotHist.push({
      id:genId(), dataInicio:(emp.dataAdmissao||vig),
      posto:emp.posto||'', turnoNoturno:!!emp.turnoNoturno, escala:emp.escala||'5x2A',
      horarioEntrada:emp.horarioEntrada||'', horarioSaida:emp.horarioSaida||'',
      horarioRefIni:emp.horarioRefIni||'', horarioRefFim:emp.horarioRefFim||'',
      semRefeicao:!!emp.semRefeicao, cargo:emp.cargo||'', salarioBase:emp.salarioBase||0,
      insalubridade:emp.insalubridade||0, acumuloFuncao:!!emp.acumuloFuncao,
      valorDiarioVt:emp.valorDiarioVt||0, vtFreq:emp.vtFreq||'diario',
      valorDiarioVr:emp.valorDiarioVr||0, vrFreq:emp.vrFreq||'diario',
      valorMensalVa:emp.valorMensalVa||0,
      obs:'Lotação inicial (admissão)'
    });
  }
  lotHist=lotHist.filter(h=>h.dataInicio!==vig);   // re-edição da mesma data substitui
  // Backfill: períodos antigos (criados antes do benefício segmentado) não tinham
  // valores de benefício. Carimba os ATUAIS do colaborador — que representam o
  // estado "antes" desta transferência — pra a segmentação histórica ficar correta
  // (senão os dias anteriores usariam o valor NOVO). #benef-segmentado
  lotHist.forEach(h=>{
    if(h.valorDiarioVt==null) h.valorDiarioVt = emp.valorDiarioVt||0;
    if(!h.vtFreq)             h.vtFreq        = emp.vtFreq||'diario';
    if(h.valorDiarioVr==null) h.valorDiarioVr = emp.valorDiarioVr||0;
    if(!h.vrFreq)             h.vrFreq        = emp.vrFreq||'diario';
    if(h.valorMensalVa==null) h.valorMensalVa = emp.valorMensalVa||0;
  });
  lotHist.push(snapNovo);
  lotHist.sort((a,b)=>a.dataInicio.localeCompare(b.dataInicio));
  const ultimo=lotHist[lotHist.length-1];          // estado "atual" = último período

  // historicoPostos (log existente) — fecha o atual e abre o novo se o posto mudou
  let postoHist=[...(emp.historicoPostos||[])];
  if(novoPosto && novoPosto!==emp.posto){
    const diaAntes=_isoMinusDays(vig,1);
    const aberto=postoHist.find(h=>!h.dataFim && h.postoNome===emp.posto);
    if(aberto) aberto.dataFim=diaAntes;
    else if(emp.posto) postoHist.push({id:genId(),postoNome:emp.posto,dataInicio:emp.dataAdmissao||vig,dataFim:diaAntes,obs:''});
    postoHist.push({id:genId(),postoNome:novoPosto,dataInicio:vig,dataFim:null,obs});
  }

  const updated={ ...emp,
    historicoLotacao:lotHist, historicoPostos:postoHist,
    // espelha os campos do ÚLTIMO período no estado atual do colaborador
    posto:ultimo.posto, turnoNoturno:ultimo.turnoNoturno, escala:ultimo.escala,
    // Âncora 12x36 do último período espelha no cadastro (mantém a atual se o seg. não trouxe). #troca-escala-12x36
    ciclo12x36Inicio: (escalaFamilia(ultimo.escala||'')==='12x36') ? (ultimo.ciclo12x36Inicio||emp.ciclo12x36Inicio||'') : (emp.ciclo12x36Inicio||''),
    horarioEntrada:ultimo.horarioEntrada, horarioSaida:ultimo.horarioSaida,
    horarioRefIni:ultimo.horarioRefIni, horarioRefFim:ultimo.horarioRefFim,
    cargo:ultimo.cargo, salarioBase:ultimo.salarioBase,
    insalubridade:ultimo.insalubridade, acumuloFuncao:ultimo.acumuloFuncao,
    // Benefícios — espelha o último período (se o snapshot trouxe; senão mantém o atual)
    valorDiarioVt:(ultimo.valorDiarioVt!=null?ultimo.valorDiarioVt:emp.valorDiarioVt),
    vtFreq:(ultimo.vtFreq||emp.vtFreq),
    valorDiarioVr:(ultimo.valorDiarioVr!=null?ultimo.valorDiarioVr:emp.valorDiarioVr),
    vrFreq:(ultimo.vrFreq||emp.vrFreq),
    valorMensalVa:(ultimo.valorMensalVa!=null?ultimo.valorMensalVa:emp.valorMensalVa),
    updatedAt:new Date().toISOString()
  };
  try{
    await DB.save('employees', _sanitizeForFirestore(updated));
    Object.assign(emp, updated);
    await _limparEscalasSalvasDesde(empId, vig);   // reprojeta por lotação nos meses afetados
    // Reflete no formulário do cadastro aberto
    populatePostoSelect();
    const selP=document.getElementById('emp-posto'); if(selP) selP.value=updated.posto;
    setVal('emp-cargo',updated.cargo||'');
    setVal('emp-escala',updated.escala||'5x2A');
    setVal('emp-salario-base',updated.salarioBase||'');
    const tnE=document.getElementById('emp-turno-noturno'); if(tnE) tnE.checked=!!updated.turnoNoturno;
    const acE=document.getElementById('emp-acumulo-funcao'); if(acE) acE.checked=!!updated.acumuloFuncao;
    setVal('emp-insalubridade',String(updated.insalubridade||0));
    setVal('emp-horario-entrada',updated.horarioEntrada||'');
    setVal('emp-horario-saida',updated.horarioSaida||'');
    renderHistoricoPostos(updated);
    closeModal('modal-transferencia');
    try{ Auth.log('LOTACAO_MUDANCA', null, `${emp.nome} → ${updated.posto} · ${updated.escala}${updated.turnoNoturno?' noturno':''} · vig ${vig}`); }catch(_){}
    toast('Mudança de lotação registrada. Reabra/recalcule as folhas dos meses afetados pra atualizar os valores.','success');
    if(val('payroll-employee')===empId){ try{ onPayrollEmployeeChange(); }catch(_){} }
  }catch(e){ console.error('saveTransferencia',e); toast('Erro ao registrar a mudança de lotação.','error'); }
}

async function removeHistoricoPosto(index){
  const empId=State.editingEmployeeId;
  const emp=State.employees.find(e=>e.id===empId); if(!emp) return;
  const hist=[...(emp.historicoPostos||[])].sort((a,b)=>new Date(b.dataInicio)-new Date(a.dataInicio));
  hist.splice(index,1);
  const updated={ ...emp, historicoPostos:hist, updatedAt:new Date().toISOString() };
  await DB.save('employees', updated);
  renderHistoricoPostos(updated);
  toast('Registro removido.','warning');
}

function confirmDeletePosto(id){
  const p=State.postos.find(x=>x.id===id); if(!p) return;
  const emUso=State.employees.some(e=>e.posto===p.razaoSocial);
  if(emUso){
    toast(`Posto em uso por colaboradores ativos — remova o vínculo antes de excluir.`,'error');
    return;
  }
  document.getElementById('confirm-message').textContent=`Excluir o posto "${p.razaoSocial}"?`;
  const btn=document.getElementById('confirm-ok-btn');
  btn.innerHTML='<i class="fa-solid fa-trash"></i> Excluir';
  btn.onclick=async()=>{
    await DB.remove('postos',id);
    Auth.log('POSTO_DELETED', null, p.razaoSocial);
    closeModal('modal-confirm');
    toast('Posto excluído.','warning');
  };
  document.getElementById('modal-confirm').classList.remove('hidden');
}

// ============================================
// ESCALAS — Projeção mensal por colaborador
// ============================================
// Defaults de horários por escala (usado quando emp não tem horarioEntrada/Saida)
const ESCALA_HORARIOS_DEFAULT = {
  '5x2A':  { entrada:'08:00', saida:'18:00' }, // Sex 08-16
  '5x2B':  { entrada:'07:00', saida:'17:00' }, // Sex 07-16
  '6x1A':  { entrada:'07:00', saida:'16:00' }, // Sáb 07-11
  '6x1B':  { entrada:'08:00', saida:'16:20' },
  '6x1C':  { entrada:'08:00', saida:'17:00' }, // Sáb 08-12
  '12x36': { entrada:'07:00', saida:'19:00' },
  // Variantes 12x36 com horário FIXO (escalas do sistema). As noturnas (19-07,
  // 18-06) cruzam a meia-noite — _escala12x36Noturna() liga o adicional noturno.
  '12x36-07-19': { entrada:'07:00', saida:'19:00' },
  '12x36-06-18': { entrada:'06:00', saida:'18:00' },
  '12x36-19-07': { entrada:'19:00', saida:'07:00' },
  '12x36-18-06': { entrada:'18:00', saida:'06:00' },
  // 6x1 Alternado fixo: seg-sex + 1 dia do fim de semana (revezando sáb/dom),
  // almoço 12:00-13:00. Variantes por horário.
  '6x1ALT-0900-1720': { entrada:'09:00', saida:'17:20', intIni:'12:00', intFim:'13:00' },
  '6x1ALT-0800-1620': { entrada:'08:00', saida:'16:20', intIni:'12:00', intFim:'13:00' },
  // Seg-Sex 08:00-17:00; sáb/dom (o que trabalha, revezando) sai 16:00. Almoço 12-13.
  '6x1ALT-0800-1700-S16': { entrada:'08:00', saida:'17:00', intIni:'12:00', intFim:'13:00' },
  // Seg-Sex 07:00-16:00 (almoço 12-13); sáb/dom trabalhado 07:00-11:00 (4h, sem almoço).
  '6x1ALT-0700-1600-S11': { entrada:'07:00', saida:'16:00', intIni:'12:00', intFim:'13:00' },
  // 6x1 FIM DE SEMANA LIVRE: mesmos horários das variantes acima, mas o dia de
  // folga do fds NÃO é fixo/alternado — ela trabalha sáb OU dom (qualquer um vale).
  '6x1LIV-0800-1700-S16': { entrada:'08:00', saida:'17:00', intIni:'12:00', intFim:'13:00' },
  // Seg-Sex 08:00-17:00 (almoço 12-13); sáb OU dom trabalhado 08:00-12:00 (4h, sem almoço).
  '6x1LIV-0800-1700-S12': { entrada:'08:00', saida:'17:00', intIni:'12:00', intFim:'13:00' },
  '6x1LIV-0700-1600-S11': { entrada:'07:00', saida:'16:00', intIni:'12:00', intFim:'13:00' },
  // FDS livre 09:00-17:20 (fim de semana com o MESMO horário do dia útil, sem encurtar).
  '6x1LIV-0900-1720': { entrada:'09:00', saida:'17:20', intIni:'12:00', intFim:'13:00' },
  // 5x2 FDS OPCIONAL: Seg-Sex 07:30-16:30 (almoço 12-13); fim de semana trabalhado
  // 07:00-15:00 (almoço 12-13). O dia de fds é voluntário (nunca falta). #fds-opcional
  '5x2LIV-0730-1630-S15': { entrada:'07:30', saida:'16:30', intIni:'12:00', intFim:'13:00' }
};

// Retorna horários default para um colaborador num dia da semana específico
function _escalaHorariosDia(emp, diaSem, lot){
  // L = lotação vigente na data (quando passada) ou o estado atual do colaborador.
  const L = lot || emp;
  const escala = L.escala || '5x2A';
  const _mod=_escalaModelo(escala);
  if(_mod){
    const md = _mod.tipo==='ciclo'
      ? ((_mod.dias||[]).find(d=>d.tipo==='trabalho'||d.tipo==='corrido')||{})
      : (_mod.dias[diaSem]||{});
    return { entrada:md.entrada||'', intIni:md.intIni||'', intFim:md.intFim||'', saida:md.saida||'' };
  }
  const noturno = !!L.turnoNoturno || _escala12x36Noturna(escala);
  const def = ESCALA_HORARIOS_DEFAULT[escala] || ESCALA_HORARIOS_DEFAULT['5x2A'];
  // Escalas do sistema com horário fixo IGNORAM o horário do cadastro — a escala
  // define a jornada. As demais usam o horário do colaborador.
  const escalaFixa = _escalaFixa(escala);
  let entrada = escalaFixa ? def.entrada : (L.horarioEntrada || def.entrada);
  let saida   = escalaFixa ? def.saida   : (L.horarioSaida   || def.saida);
  // Refeição: respeita flag "semRefeicao" e diferencia noturno/diurno no default
  let intIni, intFim;
  if(L.semRefeicao){
    intIni = ''; intFim = '';
  } else if(L.horarioRefIni && L.horarioRefFim){
    // Cadastro/lotação do colaborador tem refeição definida — usa a dele
    intIni = L.horarioRefIni;
    intFim = L.horarioRefFim;
  } else if(escalaFixa){
    // Escala do sistema com horário fixo: a refeição também é cravada pela
    // escala (def.intIni/intFim). As 12x36 não têm refeição (plantão); a 6x1
    // alternada tem 12:00-13:00. Mantém coerência entre projetado e batido.
    intIni = def.intIni || ''; intFim = def.intFim || '';
  } else {
    // Sem cadastro: default sensato — noturno janta após meia-noite, diurno almoça
    if(noturno){
      intIni = '00:00'; intFim = '01:00';
    } else {
      intIni = '12:00'; intFim = '13:00';
    }
  }
  // Para 12x36 noturno, se não tem horário cadastrado, ajusta default
  if(escala==='12x36' && noturno && !L.horarioEntrada){
    entrada = '19:00'; saida = '07:00';
  }
  // Variantes com horário diferenciado em sex/sáb — faz parte da DEFINIÇÃO
  // da escala, então aplica mesmo que o colaborador tenha horário próprio
  // cadastrado (o horário do cadastro vale para os dias normais de semana).
  if(diaSem===5 && (escala==='5x2A' || escala==='5x2B')){
    saida = '16:00';
  }
  if(diaSem===6 && escala==='6x1A'){
    saida = '11:00'; intIni = ''; intFim = ''; // sábado 07h–11h (4h) — sem refeição
  }
  if(diaSem===6 && escala==='6x1C'){
    saida = '12:00'; intIni = ''; intFim = ''; // sábado 08h–12h (4h) — sem refeição
  }
  // 6x1 Alternado 08-17 com fim de semana mais curto: o dia de sáb/dom trabalhado
  // sai às 16:00 (mantém o almoço 12-13). Seg-Sex segue 08-17.
  if((diaSem===0 || diaSem===6) && (escala==='6x1ALT-0800-1700-S16' || escala==='6x1LIV-0800-1700-S16')){
    saida = '16:00';
  }
  // 6x1 FDS Livre 08-17 com fim de semana curto: sáb/dom trabalhado sai 12:00
  // (4h, sem refeição). Seg-Sex segue 08-17 com almoço 12-13.
  if((diaSem===0 || diaSem===6) && escala==='6x1LIV-0800-1700-S12'){
    saida = '12:00'; intIni = ''; intFim = '';
  }
  // 5x2 FDS Opcional 07:30-16:30: o dia de fim de semana trabalhado é 07:00–15:00
  // (com almoço 12-13). Seg-Sex segue 07:30-16:30. #fds-opcional
  if((diaSem===0 || diaSem===6) && escala==='5x2LIV-0730-1630-S15'){
    entrada = '07:00'; saida = '15:00'; intIni = '12:00'; intFim = '13:00';
  }
  // 6x1 Alternado 07-16 com fim de semana curto: sáb/dom trabalhado sai 11:00
  // (4h, sem refeição). Seg-Sex segue 07-16 com almoço 12-13.
  if((diaSem===0 || diaSem===6) && (escala==='6x1ALT-0700-1600-S11' || escala==='6x1LIV-0700-1600-S11')){
    saida = '11:00'; intIni = ''; intFim = '';
  }
  return { entrada, intIni, intFim, saida };
}

// Busca dados do mês anterior (escala salva ou pontoManualDias) para projeção 12x36/6x1B
function _getPrevMonthDias(empId, mes, ano){
  let pMes = mes - 1, pAno = ano;
  if(pMes < 1){ pMes = 12; pAno = ano - 1; }
  // 1) Tenta coleção `escalas` salva
  const savedEsc = (State.escalas||[]).find(e => e.employeeId===empId && e.mes==pMes && e.ano==pAno);
  if(savedEsc?.dias?.length) return savedEsc.dias;
  // 2) Fallback: pontoManualDias da folha de ponto fechada
  const pay = (State.payrolls||[]).find(p => p.employeeId===empId && p.mes==pMes && p.ano==pAno);
  if(pay?.pontoManualDias?.length){
    return pay.pontoManualDias.map(d => ({
      dia:d.dia, diaSem:d.diaSem,
      tipo:(d.entrada && d.saida) ? 'trabalho' : 'folga',
      entrada:d.entrada, intIni:d.intIni, intFim:d.intFim, saida:d.saida
    }));
  }
  return null;
}

// Projeta a escala completa de um colaborador para a COMPETÊNCIA (26→25)
// Projeta a escala de um modelo customizado (padrão semanal)
function _projectEscalaModelo(emp, mes, ano, modelo){
  const dias=[];
  // Itera pela competência: dias 26-fimMesAnterior + dias 1-25 do mes/ano.
  for(const cd of _compDias(mes, ano)){
    const dObj=new Date(cd.ano, cd.mes-1, cd.dia);
    const ds=cd.diaSem;
    const md=_modeloDiaTemplate(modelo, dObj);
    const tipo=md.tipo||'folga';
    const h=(tipo!=='folga')
      ? {entrada:md.entrada||'', intIni:md.intIni||'', intFim:md.intFim||'', saida:md.saida||''}
      : {entrada:'',intIni:'',intFim:'',saida:''};
    dias.push({dia:cd.dia, diaSem:ds, tipo, ...h});
  }
  return dias;
}

function _projectEscala(emp, mes, ano, prevDias){
  const _mod=_escalaModelo(emp.escala);
  if(_mod) return _projectEscalaModelo(emp, mes, ano, _mod);
  const fam = escalaFamilia(emp.escala || '5x2A');
  if(fam==='5x2')   return _projectEscala5x2(emp, mes, ano);
  if(fam==='6x1'){
    if(emp.escala && emp.escala.startsWith('6x1ALT')) return _projectEscala6x1ALT(emp, mes, ano);
    if(emp.escala==='6x1B')   return _projectEscala6x1B(emp, mes, ano, prevDias);
    return _projectEscala6x1AC(emp, mes, ano);
  }
  if(fam==='12x36') return _projectEscala12x36(emp, mes, ano, prevDias);
  return _projectEscala5x2(emp, mes, ano);
}

function _projectEscala5x2(emp, mes, ano){
  const dias = [];
  // Itera competência (26→25), não mês de calendário
  for(const cd of _compDias(mes, ano)){
    const ds = cd.diaSem;
    const isWknd = ds===0 || ds===6;
    const tipo = isWknd ? 'folga' : 'trabalho';
    const h = (tipo==='trabalho') ? _escalaHorariosDia(emp, ds) : {entrada:'',intIni:'',intFim:'',saida:''};
    dias.push({ dia:cd.dia, diaSem:ds, tipo, ...h });
  }
  return dias;
}

function _projectEscala6x1AC(emp, mes, ano){
  const dias = [];
  for(const cd of _compDias(mes, ano)){
    const ds = cd.diaSem;
    const tipo = (ds===0) ? 'folga' : 'trabalho';
    const h = (tipo==='trabalho') ? _escalaHorariosDia(emp, ds) : {entrada:'',intIni:'',intFim:'',saida:''};
    dias.push({ dia:cd.dia, diaSem:ds, tipo, ...h });
  }
  return dias;
}

// 6x1 Alternado: a folga alterna sáb↔dom a cada semana, a partir da admissão.
// A primeira folga (sáb ou dom) é definida em emp.alternadaPrimeiraFolga.
function _6x1ALTEhFolga(emp, ano, mes, dia){
  const date = new Date(ano, mes-1, dia);
  const diaSem = date.getDay();          // 0=Dom, 6=Sáb
  if(diaSem >= 1 && diaSem <= 5) return false;  // Seg–Sex sempre trabalho
  if(!emp.dataAdmissao) return diaSem===0;       // sem âncora → fallback: domingo folga
  const admissao = new Date(emp.dataAdmissao+'T00:00:00');
  if(isNaN(admissao.getTime())) return diaSem===0;
  // Normaliza para o domingo (início) da semana
  const startOfWeek = (d) => {
    const r = new Date(d.getFullYear(), d.getMonth(), d.getDate());
    r.setDate(r.getDate() - r.getDay());
    return r;
  };
  const weeks = Math.round((startOfWeek(date) - startOfWeek(admissao)) / (7*86400000));
  const par   = ((weeks % 2) + 2) % 2;   // 0 = mesma paridade da semana de admissão
  const primeiraIsSab = (emp.alternadaPrimeiraFolga || 'dom') === 'sab';
  const sabFolgaNestaSemana = (par === 0) ? primeiraIsSab : !primeiraIsSab;
  return sabFolgaNestaSemana ? (diaSem === 6) : (diaSem === 0);
}

// Âncora do ciclo 6x1 = uma FOLGA conhecida do colaborador (define a "fase" do
// ciclo de 7 dias). Deriva automaticamente: campo explícito > última folga de
// escala salva (mais recente) > data de admissão. Retorna um Date ou null.
function _anchor6x1Folga(emp){
  if(!emp) return null;
  if(emp.folga6x1Ref){ const d=new Date(emp.folga6x1Ref+'T00:00:00'); if(!isNaN(d.getTime())) return d; }
  const escs=(State.escalas||[]).filter(e=>e && e.employeeId===emp.id && Array.isArray(e.dias))
    .sort((a,b)=>(b.ano-a.ano)||(b.mes-a.mes));
  for(const e of escs){
    let ultima=null; // dias em ordem cronológica da competência (26..31,1..25): pega a ÚLTIMA folga
    // Só conta como folga o tipo EXPLÍCITO 'folga'. Um dia 'trabalho'/'corrido' salvo
    // sem horário NÃO é folga (o _getExpectedDay usa horário contratual) — senão a
    // âncora cairia num dia de trabalho e deslocaria todo o ciclo. #audit-hoje-6
    for(const d of e.dias){ if(d && (d.tipo==='folga' || (d.tipo!=='trabalho' && d.tipo!=='corrido' && !d.entrada && !d.saida))) ultima=d; }
    if(ultima){
      const real=_compRealDate(e.mes, e.ano, ultima.dia);
      const d=new Date(real.ano, real.mes-1, real.dia);
      if(!isNaN(d.getTime())) return d;
    }
  }
  if(emp.dataAdmissao){ const d=new Date(emp.dataAdmissao+'T00:00:00'); if(!isNaN(d.getTime())) return d; }
  return null;
}

// Ciclo 6x1 DESLIZANTE: 6 dias de trabalho + 1 de folga, repetindo a cada 7 dias
// a partir da âncora (uma folga conhecida). Garante SEMPRE no máximo 6 dias
// seguidos de trabalho (definição legal do 6x1). Unifica 6x1 Alternado e 6x1B
// rotativo num só motor. Sem âncora → cai no comportamento antigo (segurança).
function _ehFolga6x1Ciclo(emp, ano, mes, dia){
  const anchor=_anchor6x1Folga(emp);
  if(!anchor){
    return (emp.escala||'').startsWith('6x1ALT')
      ? _6x1ALTEhFolga(emp, ano, mes, dia)
      : (new Date(ano, mes-1, dia).getDay()===0);
  }
  const diff=Math.round((new Date(ano, mes-1, dia) - anchor)/86400000);
  return ((((diff % 7) + 7) % 7) === 0);
}

function _projectEscala6x1ALT(emp, mes, ano){
  const dias = [];
  for(const cd of _compDias(mes, ano)){
    const ds = cd.diaSem;
    // Usa o MESMO motor do _getExpectedDay (ciclo deslizante 6+1 a partir da âncora),
    // garantindo no máx. 6 dias seguidos de trabalho. Antes a projeção usava
    // _6x1ALTEhFolga (paridade sáb↔dom), que ao migrar a folga de domingo→sábado
    // entre semanas gerava até 12 dias seguidos na tela — divergindo da folha (que
    // já calcula pelo ciclo deslizante). #fix-6x1alt-12dias
    const tipo = _ehFolga6x1Ciclo(emp, cd.ano, cd.mes, cd.dia) ? 'folga' : 'trabalho';
    const h = (tipo==='trabalho') ? _escalaHorariosDia(emp, ds) : {entrada:'',intIni:'',intFim:'',saida:''};
    dias.push({ dia:cd.dia, diaSem:ds, tipo, ...h });
  }
  return dias;
}

// 6x1B: folga rotativa (1 dia folga a cada 7). Detecta âncora pela última
// folga do bloco anterior (competência anterior). Usa datas REAIS pra alinhar
// o ciclo de 7 dias com a competência (26→25).
function _projectEscala6x1B(emp, mes, ano, prevDias){
  const dias = [];
  // Acha a última folga em prevDias e converte pra data real (data anchor).
  let anchorDate = null;
  if(prevDias && prevDias.length){
    const sorted = [...prevDias].sort((a,b)=>b.dia-a.dia);
    const lastFolga = sorted.find(d => d.tipo==='folga' || (!d.entrada && !d.saida));
    if(lastFolga){
      // prevDias é da competência mes-1/ano. Resolve a data real do dia.
      let pMes = mes - 1, pAno = ano; if(pMes < 1){ pMes = 12; pAno = ano - 1; }
      const real = _compRealDate(pMes, pAno, lastFolga.dia);
      anchorDate = new Date(real.ano, real.mes-1, real.dia);
    }
  }
  const folgaTimestamps = new Set();
  if(anchorDate){
    // Marca as próximas folgas (a cada 7 dias) até o fim da competência.
    const fimComp = _compDias(mes, ano);
    const fimReal = fimComp.length ? new Date(fimComp[fimComp.length-1].ano, fimComp[fimComp.length-1].mes-1, fimComp[fimComp.length-1].dia) : null;
    const cur = new Date(anchorDate);
    cur.setDate(cur.getDate() + 7);
    while(fimReal && cur <= fimReal){
      folgaTimestamps.add(cur.getTime());
      cur.setDate(cur.getDate() + 7);
    }
  }
  for(const cd of _compDias(mes, ano)){
    const ds = cd.diaSem;
    const realT = new Date(cd.ano, cd.mes-1, cd.dia).getTime();
    const tipo = folgaTimestamps.has(realT) ? 'folga' : 'trabalho';
    const h = (tipo==='trabalho') ? _escalaHorariosDia(emp, ds) : {entrada:'',intIni:'',intFim:'',saida:''};
    const obj = { dia:cd.dia, diaSem:ds, tipo, ...h };
    if(!anchorDate) obj.revisao = true; // marcar para revisão manual
    dias.push(obj);
  }
  return dias;
}

// 12x36: alternância 1 dia trabalho / 1 dia folga.
// Prioridade da âncora: override explícito (modal) > âncora do cadastro
// (ciclo12x36Inicio) > detecção pelo mês anterior > dia 1.
function _projectEscala12x36(emp, mes, ano, prevDias, anchorOverride){
  const dias = [];
  const temAncoraCad = !anchorOverride && !!(emp && emp.ciclo12x36Inicio);
  // anchorDate = data REAL de início do ciclo (paridade trabalho).
  // Prioridade: override > emp.ciclo12x36Inicio > último trabalho do bloco
  // anterior > dataAdmissao > primeira data da competência.
  let anchorDate = null;
  let noPrev = false;
  if(anchorOverride){
    // anchorOverride é um dia-da-competência (1..25 ou 26..31). Resolve real.
    const real = _compRealDate(mes, ano, anchorOverride);
    anchorDate = new Date(real.ano, real.mes-1, real.dia);
  } else if(temAncoraCad){
    const d = new Date(emp.ciclo12x36Inicio + 'T00:00:00');
    if(!isNaN(d.getTime())) anchorDate = d;
  }
  if(!anchorDate && prevDias && prevDias.length){
    const sorted = [...prevDias].sort((a,b)=>b.dia-a.dia);
    const lw = sorted.find(d => d.tipo==='trabalho' || (d.entrada && d.saida));
    if(lw){
      let pMes = mes - 1, pAno = ano; if(pMes < 1){ pMes = 12; pAno = ano - 1; }
      const real = _compRealDate(pMes, pAno, lw.dia);
      anchorDate = new Date(real.ano, real.mes-1, real.dia);
    }
  }
  if(!anchorDate){
    // Sem nenhuma referência: usa dataAdmissao OU 1º dia da competência.
    const _adm = emp && emp.dataAdmissao ? new Date(emp.dataAdmissao+'T00:00:00') : null;
    if(_adm && !isNaN(_adm.getTime())){
      anchorDate = _adm;
    } else {
      const compDs = _compDias(mes, ano);
      if(compDs.length){
        const c0 = compDs[0];
        anchorDate = new Date(c0.ano, c0.mes-1, c0.dia);
      }
      noPrev = true;
    }
  }
  for(const cd of _compDias(mes, ano)){
    const ds = cd.diaSem;
    let tipo;
    if(temAncoraCad){
      const ehCad = _ciclo12x36EhTrabalho(emp, cd.ano, cd.mes, cd.dia);
      if(ehCad === null){
        // Dia anterior ao início do ciclo cadastrado: colab ainda não estava
        // na escala → folga (não pode virar HE).
        tipo = 'folga';
      } else {
        tipo = ehCad ? 'trabalho' : 'folga';
      }
    } else if(anchorDate){
      const realDate = new Date(cd.ano, cd.mes-1, cd.dia);
      const diff = Math.round((realDate - anchorDate) / 86400000);
      const ehTrab = ((((diff % 2) + 2) % 2) === 0);
      tipo = ehTrab ? 'trabalho' : 'folga';
    } else {
      tipo = 'folga';
    }
    const h = (tipo==='trabalho') ? _escalaHorariosDia(emp, ds) : {entrada:'',intIni:'',intFim:'',saida:''};
    const obj = { dia:cd.dia, diaSem:ds, tipo, ...h };
    if(noPrev) obj.revisao = true;
    dias.push(obj);
  }
  return dias;
}

// ============================================
// ESCALAS — Render & UI
// ============================================
// ============================================
// MODELOS DE ESCALA (escalas customizadas)
// ============================================
const _DIAS_SEMANA=['Domingo','Segunda','Terça','Quarta','Quinta','Sexta','Sábado'];

// Injeta os modelos personalizados num <optgroup> "★ Criadas por você",
// separado das escalas do sistema. Compartilhado pelo cadastro e pelo Ajustar.
function _injetarModelosNoSelect(sel){
  if(!sel) return;
  const old=sel.querySelector('optgroup[data-custom-group]'); if(old) old.remove();
  // compat: remove options custom soltas de versões anteriores
  Array.from(sel.querySelectorAll('option[data-custom]')).forEach(o=>o.remove());
  const mods=(State.escalasModelos||[]).slice().sort((a,b)=>(a.nome||'').localeCompare(b.nome||''));
  if(!mods.length) return;
  const og=document.createElement('optgroup');
  og.label='★ Criadas por você';
  og.setAttribute('data-custom-group','1');
  mods.forEach(m=>{
    const o=document.createElement('option');
    o.value='m_'+m.id; o.textContent=m.nome; o.setAttribute('data-custom','1');
    og.appendChild(o);
  });
  sel.appendChild(og);
}

function populateEscalaSelect(){
  const sel=document.getElementById('emp-escala'); if(!sel) return;
  const atual=sel.value;
  _injetarModelosNoSelect(sel);
  if(atual) sel.value=atual;
}

function openEscalaModelos(){
  document.getElementById('modal-escala-modelos').classList.remove('hidden');
  _escModMostrarLista();
}
function _escModMostrarLista(){
  document.getElementById('esc-mod-form-panel').style.display='none';
  document.getElementById('esc-mod-lista-panel').style.display='';
  document.getElementById('esc-mod-btn-voltar').style.display='none';
  document.getElementById('esc-mod-btn-salvar').style.display='none';
  const btnNovo=document.getElementById('btn-novo-escala-modelo');
  if(btnNovo) btnNovo.style.display=_podeCriarEscalas()?'':'none';
  renderEscalaModelosList();
}
function _escModMostrarForm(){
  document.getElementById('esc-mod-lista-panel').style.display='none';
  document.getElementById('esc-mod-form-panel').style.display='';
  document.getElementById('esc-mod-btn-voltar').style.display='';
  document.getElementById('esc-mod-btn-salvar').style.display='';
}
function renderEscalaModelosList(){
  const c=document.getElementById('esc-mod-lista'); if(!c) return;
  const arr=(State.escalasModelos||[]).slice().sort((a,b)=>(a.nome||'').localeCompare(b.nome||''));
  if(!arr.length){
    c.innerHTML='<div class="empty-state small"><i class="fa-solid fa-calendar-days"></i><p>Nenhum modelo de escala criado</p></div>';
    return;
  }
  const pode=_podeCriarEscalas();
  c.innerHTML=arr.map(m=>{
    const trab=(m.dias||[]).filter(d=>d.tipo==='trabalho'||d.tipo==='corrido').length;
    // Selo "FDS Livre": modelo com EXATAMENTE um dia de fim de semana marcado = trabalha
    // sáb OU dom (livre, resolve pela batida). #escala-custom-fdslivre
    const fdsLivre=!!_modeloFdsLivre('m_'+m.id);
    const selo=fdsLivre?` <span style="font-size:10px;font-weight:600;color:#1565C0;background:#E3F2FD;border:1px solid #90CAF9;border-radius:6px;padding:1px 6px" title="Trabalha sábado OU domingo, sem ordem fixa — resolve pelo dia batido; não falta se trabalhou um deles">⇄ FDS Livre</span>`:'';
    const acoes=pode?`
      <button class="btn-icon" onclick="editEscalaModelo('${m.id}')" title="Editar"><i class="fa-solid fa-pen" style="color:#1565C0"></i></button>
      <button class="btn-icon" onclick="confirmDeleteEscalaModelo('${m.id}')" title="Excluir"><i class="fa-solid fa-trash" style="color:#C62828"></i></button>`:'';
    return `<div style="display:flex;align-items:center;gap:8px;padding:8px 10px;border:1px solid var(--border);border-radius:8px;margin-bottom:6px">
      <i class="fa-solid fa-calendar-days" style="color:var(--primary)"></i>
      <span style="flex:1"><strong>${esc(m.nome||'—')}</strong>${selo} <span style="font-size:11px;color:var(--text-muted)">— ${trab} dia(s) de trabalho por semana</span></span>
      ${acoes}
    </div>`;
  }).join('');
}
function _renderEscalaModeloDias(tipo, dias){
  const tb=document.getElementById('esc-mod-dias'); if(!tb) return;
  const n = tipo==='ciclo' ? ((dias&&dias.length)||0) : 7;
  let html='';
  for(let i=0;i<n;i++){
    const d=(dias&&dias[i])||{tipo:'folga'};
    // Auto-corrige inconsistência: se tem entrada+saída mas tá marcado como folga,
    // assume trabalho (o usuário preencheu horários, claramente não é folga).
    let t = d.tipo || 'folga';
    if (t === 'folga' && (d.entrada || d.saida)) t = 'trabalho';
    const nome = tipo==='ciclo' ? ('Dia '+(i+1)) : _DIAS_SEMANA[i];
    const disabled = t === 'folga' ? 'disabled' : '';
    const opacity  = t === 'folga' ? 'opacity:.4' : '';
    html+=`<tr>
      <td style="font-weight:600;font-size:12px">${nome}</td>
      <td><select class="em-tipo" onchange="_escModOnTipoChange(this)"><option value="folga"${t==='folga'?' selected':''}>Folga</option><option value="trabalho"${t==='trabalho'?' selected':''}>Trabalho</option><option value="corrido"${t==='corrido'?' selected':''}>Hora corrida</option></select></td>
      <td><input type="time" class="em-entrada" value="${d.entrada||''}" ${disabled} style="${opacity}" oninput="_escModOnHorarioInput(this)"></td>
      <td><input type="time" class="em-intIni" value="${d.intIni||''}" ${disabled} style="${opacity}" oninput="_escModOnHorarioInput(this)"></td>
      <td><input type="time" class="em-intFim" value="${d.intFim||''}" ${disabled} style="${opacity}" oninput="_escModOnHorarioInput(this)"></td>
      <td><input type="time" class="em-saida" value="${d.saida||''}" ${disabled} style="${opacity}" oninput="_escModOnHorarioInput(this)"></td>
    </tr>`;
  }
  tb.innerHTML=html;
}
// UX do editor de modelos — coerência entre "Situação" e horários.
// Folga + horário digitado virou ambiguidade na produção (usuario via
// Folga e esperava 4h trabalho). Agora o editor força consistência.
function _escModOnTipoChange(sel){
  const tr = sel.closest('tr'); if(!tr) return;
  const folga = sel.value === 'folga';
  const inputs = tr.querySelectorAll('input[type="time"]');
  inputs.forEach(inp => {
    inp.disabled = folga;
    inp.style.opacity = folga ? '.4' : '';
    if (folga) inp.value = '';  // muda pra Folga → limpa horários
  });
}
function _escModOnHorarioInput(inp){
  const tr = inp.closest('tr'); if(!tr) return;
  const sel = tr.querySelector('.em-tipo');
  // Digitou um horário numa linha de Folga → assume Trabalho automaticamente
  if (sel && sel.value === 'folga' && inp.value) {
    sel.value = 'trabalho';
    tr.querySelectorAll('input[type="time"]').forEach(i => {
      i.disabled = false; i.style.opacity = '';
    });
  }
}
function _escModColetarDias(){
  const arr=[];
  document.querySelectorAll('#esc-mod-dias tr').forEach(tr=>{
    arr.push({
      tipo:tr.querySelector('.em-tipo').value,
      entrada:tr.querySelector('.em-entrada').value||'',
      intIni:tr.querySelector('.em-intIni').value||'',
      intFim:tr.querySelector('.em-intFim').value||'',
      saida:tr.querySelector('.em-saida').value||''
    });
  });
  return arr;
}
function _escModDefSemanal(){
  const def=[];
  for(let i=0;i<7;i++) def.push((i>=1&&i<=5)
    ? {tipo:'trabalho',entrada:'08:00',intIni:'12:00',intFim:'13:00',saida:'17:00'}
    : {tipo:'folga'});
  return def;
}
function onEscModTipoChange(){
  const ciclo=val('esc-mod-tipo')==='ciclo';
  document.querySelectorAll('.esc-mod-ciclo-cfg').forEach(el=>el.style.display=ciclo?'':'none');
  const flw=document.getElementById('esc-mod-fds-livre-wrap'); if(flw) flw.style.display=ciclo?'none':'';   // FDS livre só p/ semanal
  if(ciclo) _escModRegenCiclo(true);
  else _renderEscalaModeloDias('semanal', _escModDefSemanal());
}
function _escModRegenCiclo(novo){
  const n=Math.max(2,Math.min(60,parseInt(val('esc-mod-ciclo-n'))||6));
  setVal('esc-mod-ciclo-n',n);
  const atual=novo?[]:_escModColetarDias();
  const dias=[];
  for(let i=0;i<n;i++) dias.push(atual[i]||{tipo:'trabalho',entrada:'07:00',intIni:'',intFim:'',saida:'19:00'});
  _renderEscalaModeloDias('ciclo',dias);
}
// Permissão para criar/editar/excluir modelos de escala. Master sempre pode;
// os demais perfis dependem do módulo `criarEscalas` (default bloqueado).
function _podeCriarEscalas(){
  return Auth.currentUser?.role==='master' || !!getUserModules(Auth.currentUser).criarEscalas;
}
function novoEscalaModelo(){
  if(!_podeCriarEscalas()){ toast('Seu perfil não tem permissão para criar escalas.','error'); return; }
  setVal('esc-mod-id','');
  setVal('esc-mod-nome','');
  setVal('esc-mod-tipo','semanal');
  setVal('esc-mod-ciclo-n',6);
  setVal('esc-mod-ciclo-inicio','');
  document.querySelectorAll('.esc-mod-ciclo-cfg').forEach(el=>el.style.display='none');
  _renderEscalaModeloDias('semanal', _escModDefSemanal());
  { const fl=document.getElementById('esc-mod-fds-livre'); if(fl) fl.checked=false;
    const flw=document.getElementById('esc-mod-fds-livre-wrap'); if(flw) flw.style.display=''; }
  setVal('esc-mod-fds-duracao-horas','');
  document.getElementById('esc-mod-form-titulo').textContent='Novo modelo de escala';
  _escModMostrarForm();
}
function editEscalaModelo(id){
  if(!_podeCriarEscalas()){ toast('Seu perfil não tem permissão para editar escalas.','error'); return; }
  const m=(State.escalasModelos||[]).find(x=>x.id===id); if(!m) return;
  const tipo=m.tipo||'semanal';
  setVal('esc-mod-id',m.id);
  setVal('esc-mod-nome',m.nome||'');
  setVal('esc-mod-tipo',tipo);
  setVal('esc-mod-ciclo-n', tipo==='ciclo'?((m.dias&&m.dias.length)||6):6);
  setVal('esc-mod-ciclo-inicio',m.dataInicio||'');
  document.querySelectorAll('.esc-mod-ciclo-cfg').forEach(el=>el.style.display=tipo==='ciclo'?'':'none');
  _renderEscalaModeloDias(tipo, m.dias||[]);
  // Reflete o estado REAL: flag explícita OU detecção automática (1 dia de fds marcado). #escala-custom-fdslivre
  { const fl=document.getElementById('esc-mod-fds-livre'); if(fl) fl.checked=(!!m.fdsLivre || !!_modeloFdsLivre('m_'+m.id));
    const flw=document.getElementById('esc-mod-fds-livre-wrap'); if(flw) flw.style.display=(tipo==='ciclo')?'none':''; }
  setVal('esc-mod-fds-duracao-horas', (+m.fdsDuracaoMin>0)?(m.fdsDuracaoMin/60):'');
  document.getElementById('esc-mod-form-titulo').textContent='Editar modelo de escala';
  _escModMostrarForm();
}
async function saveEscalaModelo(){
  if(!_podeCriarEscalas()){ toast('Seu perfil não tem permissão para criar escalas.','error'); return; }
  const nome=val('esc-mod-nome').trim();
  if(!nome){ toast('Dê um nome ao modelo de escala.','error'); return; }
  const tipo=val('esc-mod-tipo')||'semanal';
  const dias=_escModColetarDias();
  if(!dias.some(d=>d.tipo==='trabalho'||d.tipo==='corrido')){
    toast('O modelo precisa ter ao menos um dia de trabalho.','error'); return;
  }
  let dataInicio='';
  if(tipo==='ciclo'){
    dataInicio=val('esc-mod-ciclo-inicio');
    if(!dataInicio){ toast('Informe a data de início do ciclo (a âncora do plantão).','error'); return; }
  }
  // FDS LIVRE (só semanal): trabalha sáb OU dom (livre). Precisa de horário num dos dois. #escala-custom-fdslivre
  const fdsLivre = tipo==='semanal' && !!document.getElementById('esc-mod-fds-livre')?.checked;
  // Fim de semana por DURAÇÃO (horário livre): X horas em qualquer horário no sáb OU dom. #fds-duracao
  const fdsDuracaoMin = fdsLivre ? Math.round((parseFloat(val('esc-mod-fds-duracao-horas'))||0)*60) : 0;
  if(fdsLivre){
    // Por duração: basta marcar "Trabalho" em sáb e/ou dom (horário opcional). Por horário fixo: precisa do horário.
    const _t=d=>!!(d && (d.tipo==='trabalho'||d.tipo==='corrido') && (fdsDuracaoMin>0 || d.entrada));
    if(!_t(dias[6]) && !_t(dias[0])){ toast(fdsDuracaoMin>0?'Fim de semana livre: marque "Trabalho" em Sábado e/ou Domingo (basta um).':'Fim de semana livre: marque "Trabalho" e o horário em Sábado e/ou Domingo (basta um).','error'); return; }
  }
  const id=val('esc-mod-id');
  const existente=id?(State.escalasModelos||[]).find(x=>x.id===id):null;
  const doc={
    id:id||genId(), nome, tipo, dias, dataInicio, fdsLivre, fdsDuracaoMin,
    createdAt:existente?.createdAt||new Date().toISOString(),
    updatedAt:new Date().toISOString()
  };
  const btn=document.getElementById('esc-mod-btn-salvar');
  setBtnLoading(btn,true,'');
  try {
    await DB.save('escalasModelos', doc);
    Auth.log(existente?'ESCALA_MODELO_UPDATED':'ESCALA_MODELO_CREATED', null, nome);
    toast('Modelo de escala salvo!');
    _escModMostrarLista();
  } catch(e){ toast('Erro ao salvar modelo.','error'); }
  finally { setBtnLoading(btn,false,'<i class="fa-solid fa-floppy-disk"></i> Salvar Modelo'); }
}
function confirmDeleteEscalaModelo(id){
  if(!_podeCriarEscalas()){ toast('Seu perfil não tem permissão para excluir escalas.','error'); return; }
  const m=(State.escalasModelos||[]).find(x=>x.id===id); if(!m) return;
  document.getElementById('confirm-message').innerHTML=`Excluir o modelo de escala <strong>${m.nome}</strong>?<br><br>Colaboradores que usam este modelo ficarão sem escala definida — reatribua a escala deles depois.`;
  const btn=document.getElementById('confirm-ok-btn');
  btn.innerHTML='<i class="fa-solid fa-trash"></i> Excluir';
  btn.onclick=async()=>{
    try { await DB.remove('escalasModelos', id); } catch(e){}
    closeModal('modal-confirm');
    renderEscalaModelosList();
    toast('Modelo excluído.','warning');
  };
  document.getElementById('modal-confirm').classList.remove('hidden');
}

function renderEscalas(){
  // Inicializa selects de mês/ano
  const yearSel = document.getElementById('escala-ano');
  if(yearSel && !yearSel.options.length){
    const cur = currentAno();
    let opts = '';
    for(let y=cur-1; y<=cur+2; y++) opts += `<option value="${y}">${y}</option>`;
    yearSel.innerHTML = opts;
    yearSel.value = cur;
    document.getElementById('escala-mes').value = currentMes();
  }
  // Popula filtros postos / setores
  const postoSel = document.getElementById('escala-filter-posto');
  if(postoSel){
    const sel = postoSel.value;
    let opts = '<option value="">Todos</option>';
    // emp.posto guarda o nome do posto (razaoSocial) — o filtro precisa casar com isso
    (State.postos||[]).forEach(p => { opts += `<option value="${p.razaoSocial||''}">${p.razaoSocial||p.nome||'—'}</option>`; });
    postoSel.innerHTML = opts;
    postoSel.value = sel;
  }
  const setorSel = document.getElementById('escala-filter-setor');
  if(setorSel){
    const sel = setorSel.value;
    const setores = [...new Set((State.employees||[]).map(e=>e.setor).filter(Boolean))].sort();
    let opts = '<option value="">Todos</option>';
    setores.forEach(s => { opts += `<option value="${s}">${s}</option>`; });
    setorSel.innerHTML = opts;
    setorSel.value = sel;
  }
  _renderEscalasCards();
}

function onEscalaMesChange(){ _renderEscalasCards(); }
function onEscalaFilterChange(){ _renderEscalasCards(); }

function changeEscalaMes(delta){
  const mesSel = document.getElementById('escala-mes');
  const anoSel = document.getElementById('escala-ano');
  let m = parseInt(mesSel.value) + delta;
  let a = parseInt(anoSel.value);
  if(m < 1){ m = 12; a -= 1; }
  if(m > 12){ m = 1; a += 1; }
  mesSel.value = m;
  if(!Array.from(anoSel.options).some(o=>o.value==a)){
    const opt = document.createElement('option');
    opt.value = a; opt.textContent = a;
    anoSel.appendChild(opt);
  }
  anoSel.value = a;
  _renderEscalasCards();
}

function _renderEscalasCards(){
  const mes = parseInt(document.getElementById('escala-mes').value || currentMes());
  const ano = parseInt(document.getElementById('escala-ano').value || currentAno());
  const fNome   = (document.getElementById('escala-filter-nome').value||'').toLowerCase().trim();
  const fPosto  = document.getElementById('escala-filter-posto').value||'';
  const fSetor  = document.getElementById('escala-filter-setor').value||'';
  const fEscala = document.getElementById('escala-filter-escala').value||'';
  const fTurno  = document.getElementById('escala-filter-turno').value||'';

  const ativos = (State.employees||[]).filter(e => (e.status||'ativo')==='ativo');
  const filtered = ativos.filter(e => {
    if(fNome && !(e.nome||'').toLowerCase().includes(fNome)) return false;
    if(fPosto && e.posto !== fPosto) return false;
    if(fSetor && e.setor !== fSetor) return false;
    if(fEscala && e.escala !== fEscala) return false;
    if(fTurno){
      const isNot = !!e.turnoNoturno;
      if(fTurno==='noturno' && !isNot) return false;
      if(fTurno==='diurno'  &&  isNot) return false;
    }
    return true;
  }).sort((a,b)=>(a.nome||'').localeCompare(b.nome||''));

  const _bannerInfo = `<div style="background:#E1F5FE;border:1px solid #B3E5FC;border-left:4px solid #0277BD;border-radius:8px;padding:12px 16px;margin-bottom:14px;font-size:13px;color:#01579B;line-height:1.5">
    <i class="fa-solid fa-circle-info"></i> <strong>Tela informativa.</strong> Em competência <strong>aberta</strong>, mostra a escala <strong>efetiva do contrato</strong> (cadastro + transferências). Quando a competência está <strong>fechada</strong>, a tela se atualiza sozinha e passa a mostrar a escala <strong>realizada</strong> — montada pelas <strong>batidas reais do ponto</strong> (dia previsto sem batida aparece como <strong>"s/ registro"</strong>). É apenas para o supervisor consultar — <strong>não orienta nenhuma outra tela do sistema</strong>. Para <strong>mudar a escala</strong> use <strong>Ajustar escala</strong> (ou Transferência no cadastro); exceção de um dia, use o <strong>override de dia avulso</strong> na Folha de Ponto.
  </div>`;
  const container = document.getElementById('escalas-container');
  if(!container) return;
  if(!filtered.length){
    container.innerHTML = _bannerInfo + '<div class="empty-state"><i class="fa-solid fa-filter-circle-xmark"></i><p>Nenhum colaborador encontrado com os filtros atuais</p></div>';
    return;
  }
  container.innerHTML = _bannerInfo + filtered.map(emp => _renderEscalaCard(emp, mes, ano)).join('');
}

// Escala REALIZADA (consulta): quando a competência está FECHADA, esta tela informativa
// se atualiza sozinha pelas BATIDAS reais do ponto. NÃO orienta nenhuma outra tela/seção
// (não toca State.escalas/motor/apuração — leitura pura). Dia sem batida que era trabalho
// → "s/ registro" (pedido do dono 2026-06-28). #escala-realizada
function _realizedEscalaDias(emp, mes, ano, payroll){
  const diasPonto = Array.isArray(payroll?.pontoManualDias) ? payroll.pontoManualDias : [];
  const dias = [];
  for(const cd of _compDias(mes, ano)){
    const ds = cd.diaSem;
    const ymd = `${cd.ano}-${String(cd.mes).padStart(2,'0')}-${String(cd.dia).padStart(2,'0')}`;
    const pd = diasPonto.find(x=>x.dia===cd.dia) || {};
    const exp = _getExpectedDay(emp, cd.mes, cd.ano, cd.dia);
    const _bat = _repararBatidasDia(pd, exp);
    const temBatida = !!(_bat.entrada && _bat.saida);
    const expFolga = !exp || exp.tipo==='folga' || !exp.entrada;
    let tipo = 'folga';
    let h = {entrada:'',intIni:'',intFim:'',saida:''};
    if(temBatida){
      tipo = 'trabalho';
      h = {entrada:_bat.entrada||'', intIni:_bat.intIni||'', intFim:_bat.intFim||'', saida:_bat.saida||''};
    } else if(_emFeriasNoDia(emp, ymd)){
      tipo = 'ferias';
    } else {
      const atst = _atestadoDoDia(emp.id, ymd);
      if(atst){ tipo = atst.categoria==='cobertura' ? 'cobertura' : (atst.categoria==='abono' ? 'abono' : 'atestado'); }
      else if(expFolga){ tipo = 'folga'; }
      else { tipo = 'semreg'; }   // previsto trabalho, sem batida → "s/ registro"
    }
    dias.push({ dia:cd.dia, diaSem:ds, tipo, ...h });
  }
  return dias;
}

// Override MANUAL de consulta (escala realizada editada à mão). Vive em configuracoes/
// escalaConsulta (chave empId|mes|ano), lido SÓ por esta tela. NÃO toca ponto/folha/motor.
let _escalaEditing=null;   // chave do card em edição
function _escalaConsultaOverride(empId, mes, ano){
  const v = (State.escalaConsulta||{})[`${empId}|${mes}|${ano}`];
  return Array.isArray(v) && v.length ? v : null;
}
// Fonte única das linhas da escala (tela E exportação): fechada → realizada das batidas
// (ou ajuste manual de consulta); aberta → salva/projeção do contrato. #escala-realizada
function _escalaDiasFor(emp, mes, ano){
  const payroll = (State.payrolls||[]).find(p => p.employeeId===emp.id && p.mes==mes && p.ano==ano);
  if(payroll?.status === 'fechada'){
    const ov = _escalaConsultaOverride(emp.id, mes, ano);
    if(ov) return { dias: ov, fonte:'ajustada' };
    return { dias: _realizedEscalaDias(emp, mes, ano, payroll), fonte:'realizada' };
  }
  const saved = (State.escalas||[]).find(e => e.employeeId===emp.id && e.mes==mes && e.ano==ano);
  if(saved?.dias?.length) return { dias: saved.dias, fonte:'salva' };
  const prevDias = _getPrevMonthDias(emp.id, mes, ano);
  return { dias: _projectEscala(emp, mes, ano, prevDias), fonte:'projetada' };
}
// Linha EDITÁVEL do modo de ajuste de consulta.
function _renderEscalaRowEdit(d, mes, ano){
  const sem=['Dom','Seg','Ter','Qua','Qui','Sex','Sáb'][d.diaSem];
  let labelDia=String(d.dia).padStart(2,'0');
  if(mes!=null&&ano!=null){ const r=_compRealDate(mes,ano,d.dia); labelDia=`${String(r.dia).padStart(2,'0')}/${String(r.mes).padStart(2,'0')}`; }
  const opts=[['trabalho','Trabalho'],['folga','Folga'],['semreg','s/ registro'],['atestado','Atestado'],['abono','Abono'],['cobertura','Cobertura'],['ferias','Férias']]
    .map(([v,l])=>`<option value="${v}" ${d.tipo===v?'selected':''}>${l}</option>`).join('');
  const ti=(cls,val)=>`<input type="time" class="esc-ed-${cls}" value="${val||''}" style="padding:3px 5px;border:1px solid var(--border);border-radius:5px;font-size:11px;width:96px">`;
  return `<tr data-dia="${d.dia}" style="background:#FFFDE7">
    <td style="padding:4px 6px;text-align:center;border:1px solid var(--border);font-weight:700;font-size:11px">${labelDia}</td>
    <td style="padding:4px 6px;text-align:center;border:1px solid var(--border);font-size:11px">${sem}</td>
    <td style="padding:4px 6px;text-align:center;border:1px solid var(--border)"><select class="esc-ed-tipo" style="padding:3px 5px;border:1px solid var(--border);border-radius:5px;font-size:11px">${opts}</select></td>
    <td style="padding:4px 6px;text-align:center;border:1px solid var(--border)">${ti('entrada',d.entrada)}</td>
    <td style="padding:4px 6px;text-align:center;border:1px solid var(--border)">${ti('intini',d.intIni)}</td>
    <td style="padding:4px 6px;text-align:center;border:1px solid var(--border)">${ti('intfim',d.intFim)}</td>
    <td style="padding:4px 6px;text-align:center;border:1px solid var(--border)">${ti('saida',d.saida)}</td>
  </tr>`;
}
function _escalaCollectEditDias(card){
  const mes=parseInt(card.dataset.mes), ano=parseInt(card.dataset.ano);
  const out=[];
  card.querySelectorAll('tbody tr[data-dia]').forEach(row=>{
    const dia=parseInt(row.dataset.dia);
    const r=_compRealDate(mes,ano,dia); const ds=new Date(r.ano,r.mes-1,r.dia).getDay();
    const tipo=row.querySelector('.esc-ed-tipo')?.value||'folga';
    const g=cls=>row.querySelector('.esc-ed-'+cls)?.value||'';
    out.push({dia,diaSem:ds,tipo,entrada:g('entrada'),intIni:g('intini'),intFim:g('intfim'),saida:g('saida')});
  });
  return out;
}
function _escalaEditMode(empId,mes,ano){ _escalaEditing=`${empId}|${mes}|${ano}`; _renderEscalasCards(); }
function _escalaCancelEdit(){ _escalaEditing=null; _renderEscalasCards(); }
async function _escalaSalvarAjuste(empId,mes,ano){
  const card=document.querySelector(`.escala-card[data-emp-id="${empId}"]`); if(!card) return;
  const dias=_escalaCollectEditDias(card);
  State.escalaConsulta=State.escalaConsulta||{};
  State.escalaConsulta[`${empId}|${mes}|${ano}`]=dias;
  _escalaEditing=null;
  try{ await DB.saveDoc('configuracoes','escalaConsulta',State.escalaConsulta,false); toast('Ajuste de consulta salvo — não altera ponto, folha nem nenhuma outra tela.'); }
  catch(e){ toast('Erro ao salvar o ajuste.','error'); }
  _renderEscalasCards();
}
async function _escalaRecompor(empId,mes,ano){
  State.escalaConsulta=State.escalaConsulta||{};
  delete State.escalaConsulta[`${empId}|${mes}|${ano}`];
  _escalaEditing=null;
  try{ await DB.saveDoc('configuracoes','escalaConsulta',State.escalaConsulta,false); toast('Escala recomposta pelas batidas do ponto.'); }
  catch(e){ toast('Erro ao recompor.','error'); }
  _renderEscalasCards();
}

function _renderEscalaCard(emp, mes, ano){
  const { dias, fonte } = _escalaDiasFor(emp, mes, ano);   // #escala-realizada
  const editing = _escalaEditing===`${emp.id}|${mes}|${ano}`;
  const fam = escalaFamilia(emp.escala || '5x2A');
  const posto = (emp.posto || '—');
  const setor = emp.setor || '—';
  const noturnoBadge = emp.turnoNoturno
    ? '<span style="background:#E8EAF6;color:#3F51B5;padding:2px 8px;border-radius:4px;font-size:11px;font-weight:600;margin-left:6px"><i class="fa-solid fa-moon"></i> Noturno</span>'
    : '';
  const semRefBadge = emp.semRefeicao
    ? '<span style="background:#FFEBEE;color:#C62828;padding:2px 8px;border-radius:4px;font-size:11px;font-weight:600;margin-left:6px" title="Trabalha sozinho — sem horário de refeição"><i class="fa-solid fa-ban"></i> Sem refeição</span>'
    : '';
  const projBadge = editing
    ? '<span style="background:#FFF8E1;color:#E65100;padding:2px 8px;border-radius:4px;font-size:11px;font-weight:600;margin-left:6px"><i class="fa-solid fa-pen"></i> Editando consulta…</span>'
    : fonte==='realizada'
    ? '<span style="background:#E8F5E9;color:#2E7D32;padding:2px 8px;border-radius:4px;font-size:11px;font-weight:600;margin-left:6px" title="Competência fechada — escala atualizada pelas batidas reais do ponto (apenas consulta; não orienta outras telas)"><i class="fa-solid fa-clipboard-check"></i> Realizada (do ponto)</span>'
    : fonte==='ajustada'
    ? '<span style="background:#EDE7F6;color:#5E35B1;padding:2px 8px;border-radius:4px;font-size:11px;font-weight:600;margin-left:6px" title="Escala realizada ajustada manualmente para consulta (não altera nada no sistema)"><i class="fa-solid fa-user-pen"></i> Ajustada (consulta)</span>'
    : fonte==='projetada'
    ? '<span style="background:#E1F5FE;color:#0277BD;padding:2px 8px;border-radius:4px;font-size:11px;font-weight:600;margin-left:6px" title="Escala efetiva derivada do contrato (cadastro + transferências)"><i class="fa-solid fa-file-contract"></i> Do contrato</span>'
    : '<span style="background:#ECEFF1;color:#546E7A;padding:2px 8px;border-radius:4px;font-size:11px;font-weight:600;margin-left:6px" title="Escala que foi salva manualmente nesta competência (histórico)"><i class="fa-solid fa-clock-rotate-left"></i> Salva (histórico)</span>';
  const rowsHtml = editing
    ? dias.map(d => _renderEscalaRowEdit(d, mes, ano)).join('')
    : dias.map(d => _renderEscalaRow(d, fam, mes, ano)).join('');
  const btns = editing
    ? `<button class="btn btn-success" onclick="_escalaSalvarAjuste('${emp.id}',${mes},${ano})"><i class="fa-solid fa-floppy-disk"></i> Salvar ajustes</button>
       <button class="btn btn-outline" onclick="_escalaCancelEdit()">Cancelar</button>`
    : `<button class="btn btn-secondary" onclick="openAjustarEscala('${emp.id}')" title="Trocar a escala contratual do colaborador (5x2, 6x1, 12x36...)"><i class="fa-solid fa-gear" style="color:var(--primary)"></i> Ajustar escala</button>
       ${(fonte==='realizada'||fonte==='ajustada') ? `<button class="btn btn-secondary" onclick="_escalaEditMode('${emp.id}',${mes},${ano})" title="Ajustar manualmente esta escala de consulta — não altera nada no sistema"><i class="fa-solid fa-pen" style="color:var(--primary)"></i> Editar consulta</button>` : ''}
       ${fonte==='ajustada' ? `<button class="btn btn-secondary" onclick="_escalaRecompor('${emp.id}',${mes},${ano})" title="Descartar os ajustes e refazer pelas batidas do ponto"><i class="fa-solid fa-rotate-left" style="color:#E65100"></i> Recompor do ponto</button>` : ''}`;
  return `<div class="card escala-card" data-emp-id="${emp.id}" data-fam="${fam}" data-mes="${mes}" data-ano="${ano}" style="margin-bottom:16px">
    <div class="card-body" style="padding:14px 18px">
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px;flex-wrap:wrap;gap:8px">
        <div>
          <div style="font-size:15px;font-weight:700;color:var(--primary)">${emp.nome}${noturnoBadge}${semRefBadge}${projBadge}</div>
          <div style="font-size:12px;color:var(--text-muted);margin-top:2px"><i class="fa-solid fa-building"></i> ${posto} &middot; <i class="fa-solid fa-sitemap"></i> ${setor} &middot; <strong>${escalaLabel(emp.escala||'5x2A')}</strong></div>
        </div>
        <div style="display:flex;gap:6px;flex-wrap:wrap">${btns}</div>
      </div>
      ${editing ? '<div style="font-size:11px;color:#E65100;margin-bottom:8px;background:#FFF8E1;border:1px solid #FFE082;border-radius:6px;padding:6px 10px"><i class="fa-solid fa-circle-info"></i> Ajuste apenas de <strong>consulta</strong> — não altera ponto, folha, apuração nem nenhuma outra tela do sistema.</div>' : ''}
      <div style="overflow-x:auto">
        <table class="escala-table" style="width:100%;border-collapse:collapse;font-size:12px;min-width:680px">
          <thead>
            <tr style="background:#F5F7FB">
              <th style="padding:6px 8px;text-align:center;border:1px solid var(--border);width:54px">Dia</th>
              <th style="padding:6px 8px;text-align:center;border:1px solid var(--border);width:46px">Sem.</th>
              <th style="padding:6px 8px;text-align:center;border:1px solid var(--border);width:88px">Status</th>
              <th style="padding:6px 8px;text-align:center;border:1px solid var(--border)">Entrada</th>
              <th style="padding:6px 8px;text-align:center;border:1px solid var(--border)">Início Refeição</th>
              <th style="padding:6px 8px;text-align:center;border:1px solid var(--border)">Retorno Refeição</th>
              <th style="padding:6px 8px;text-align:center;border:1px solid var(--border)">Saída</th>
            </tr>
          </thead>
          <tbody>${rowsHtml}</tbody>
        </table>
      </div>
    </div>
  </div>`;
}

function _escalaTipoBadge(tipo, perc){
  if(tipo === 'corrido'){
    const pct = perc ? ` <small style="background:#F3E5F5;padding:0 4px;border-radius:3px">+${perc}%</small>` : '';
    return `<span style="color:#7B1FA2;font-weight:600;font-size:11px"><i class="fa-solid fa-person-running"></i> Corrido${pct}</span>`;
  }
  if(tipo === 'folga')    return '<span style="color:#E65100;font-weight:600;font-size:11px"><i class="fa-solid fa-umbrella-beach"></i> Folga</span>';
  // Status da escala REALIZADA (competência fechada, derivado das batidas). #escala-realizada
  if(tipo === 'semreg')   return '<span style="color:#90A4AE;font-weight:600;font-size:11px"><i class="fa-regular fa-circle-question"></i> s/ registro</span>';
  if(tipo === 'ferias')   return '<span style="color:#00838F;font-weight:600;font-size:11px"><i class="fa-solid fa-plane-departure"></i> Férias</span>';
  if(tipo === 'cobertura')return '<span style="color:#5E35B1;font-weight:600;font-size:11px"><i class="fa-solid fa-people-arrows"></i> Cobertura</span>';
  if(tipo === 'abono')    return '<span style="color:#1565C0;font-weight:600;font-size:11px"><i class="fa-solid fa-clipboard-check"></i> Abono</span>';
  if(tipo === 'atestado') return '<span style="color:#C62828;font-weight:600;font-size:11px"><i class="fa-solid fa-notes-medical"></i> Atestado</span>';
  return                          '<span style="color:#1B5E20;font-weight:600;font-size:11px"><i class="fa-solid fa-briefcase"></i> Trabalho</span>';
}

// ============================================
// ESCALAS — Modal de % HE para Corrido
// ============================================
let _pendingCorridoRow = null;
let _previousTipoBeforeCorrido = null;

function _openCorridoPercModal(row, prevTipo){
  _pendingCorridoRow = row;
  _previousTipoBeforeCorrido = prevTipo || 'trabalho';
  setVal('corrido-perc-custom', '');
  document.getElementById('modal-corrido-perc').classList.remove('hidden');
}

function setCorridoPerc(perc){
  const row = _pendingCorridoRow;
  if(!row){ closeModal('modal-corrido-perc'); return; }
  const validPerc = Math.max(0, Math.min(200, parseInt(perc)||50));
  row.dataset.hePerc = validPerc;
  const cell = row.querySelector('.esc-tipo-cell');
  if(cell) cell.innerHTML = _escalaTipoBadge('corrido', validPerc);
  const card = row.closest('.escala-card');
  if(card) card.dataset.dirty = '1';
  closeModal('modal-corrido-perc');
  _pendingCorridoRow = null;
  _previousTipoBeforeCorrido = null;
}

function cancelCorridoPerc(){
  // Reverte o status para o anterior (trabalho ou folga)
  const row = _pendingCorridoRow;
  if(row){
    const prev = _previousTipoBeforeCorrido || 'trabalho';
    row.dataset.tipo = prev;
    delete row.dataset.hePerc;
    const cell = row.querySelector('.esc-tipo-cell');
    if(cell) cell.innerHTML = _escalaTipoBadge(prev);
    // Restaura inputs conforme tipo anterior
    const ent = row.querySelector('.esc-entrada');
    const ini = row.querySelector('.esc-int-ini');
    const fim = row.querySelector('.esc-int-fim');
    const sai = row.querySelector('.esc-saida');
    if(prev === 'trabalho'){
      [ent, ini, fim, sai].forEach(i => { if(i) i.style.opacity='1'; });
      // Recompõe defaults se vazios
      const card = row.closest('.escala-card');
      const empId = card?.dataset.empId;
      const emp = (State.employees||[]).find(e=>e.id===empId);
      if(emp){
        const dia = parseInt(row.dataset.dia);
        const mes = parseInt(document.getElementById('escala-mes').value);
        const ano = parseInt(document.getElementById('escala-ano').value);
        const realDs = new Date(ano, mes-1, dia).getDay();
        const h = _escalaHorariosDia(emp, realDs);
        if(ent && !ent.value) ent.value = h.entrada;
        if(ini && !ini.value) ini.value = h.intIni;
        if(fim && !fim.value) fim.value = h.intFim;
        if(sai && !sai.value) sai.value = h.saida;
      }
    } else {
      // folga
      [ent, ini, fim, sai].forEach(i => { if(i){ i.value=''; i.style.opacity='.55'; } });
    }
  }
  closeModal('modal-corrido-perc');
  _pendingCorridoRow = null;
  _previousTipoBeforeCorrido = null;
}

function _renderEscalaRow(d, fam, compMes, compAno){
  // SOMENTE LEITURA (Fase 1 — tela informativa): mostra a escala EFETIVA, sem
  // edição. Mudança de escala = Transferência no contrato; exceção de 1 dia =
  // override de dia avulso na Folha de Ponto.
  const sem = ['Dom','Seg','Ter','Qua','Qui','Sex','Sáb'][d.diaSem];
  let bg = '#fff';
  if(fam==='12x36'){
    bg = (d.tipo==='trabalho' || d.tipo==='corrido') ? '#E3F2FD' : '#FFF8E1';
  } else {
    if(d.diaSem===0)      bg = '#FFEBEE';
    else if(d.diaSem===6) bg = '#FFF9C4';
  }
  const semHorario = d.tipo!=='trabalho' && d.tipo!=='corrido';   // folga/semreg/atestado/abono/cobertura/ferias
  const op = semHorario ? 'opacity:.5' : (d.tipo==='corrido' ? 'opacity:.7' : '');
  let labelDia = String(d.dia).padStart(2,'0');
  if(compMes != null && compAno != null){
    const r = _compRealDate(compMes, compAno, d.dia);
    labelDia = `${String(r.dia).padStart(2,'0')}/${String(r.mes).padStart(2,'0')}`;
  }
  const cel = v => `<td style="padding:4px 6px;text-align:center;border:1px solid var(--border);font-size:11px;${op}">${v || '—'}</td>`;
  return `<tr style="background:${bg}">
    <td style="padding:4px 6px;text-align:center;border:1px solid var(--border);font-weight:700;font-size:11px">${labelDia}</td>
    <td style="padding:4px 6px;text-align:center;border:1px solid var(--border);font-size:11px">${sem}</td>
    <td style="padding:4px 6px;text-align:center;border:1px solid var(--border)">${_escalaTipoBadge(d.tipo, d.hePercDia)}</td>
    ${cel(semHorario?'':d.entrada)}
    ${cel(semHorario?'':d.intIni)}
    ${cel(semHorario?'':d.intFim)}
    ${cel(semHorario?'':d.saida)}
  </tr>`;
}

function onEscalaCellEdit(input){
  const row = input.closest('tr');
  const card = input.closest('.escala-card');
  if(card) card.dataset.dirty = '1';
  if(!row) return;
  const cur = row.dataset.tipo || 'trabalho';
  const isMealField = input.classList.contains('esc-int-ini') || input.classList.contains('esc-int-fim');

  // Helper para resolver defaults do colaborador
  const getDefaults = () => {
    const empId = card?.dataset.empId;
    const emp = (State.employees||[]).find(e=>e.id===empId);
    if(!emp) return null;
    const dia = parseInt(row.dataset.dia);
    const mes = parseInt(document.getElementById('escala-mes').value);
    const ano = parseInt(document.getElementById('escala-ano').value);
    const realDs = new Date(ano, mes-1, dia).getDay();
    return _escalaHorariosDia(emp, realDs);
  };
  const setBadge = (tipo) => {
    const cell = row.querySelector('.esc-tipo-cell');
    if(cell) cell.innerHTML = _escalaTipoBadge(tipo);
  };
  const setOpacity = (tipo) => {
    const ent = row.querySelector('.esc-entrada');
    const ini = row.querySelector('.esc-int-ini');
    const fim = row.querySelector('.esc-int-fim');
    const sai = row.querySelector('.esc-saida');
    if(tipo === 'trabalho'){
      [ent,ini,fim,sai].forEach(i => { if(i) i.style.opacity = '1'; });
    } else if(tipo === 'corrido'){
      if(ent) ent.style.opacity = '1';
      if(sai) sai.style.opacity = '1';
      if(ini) ini.style.opacity = '.4';
      if(fim) fim.style.opacity = '.4';
    } else {
      [ent,ini,fim,sai].forEach(i => { if(i) i.style.opacity = '.55'; });
    }
  };

  // 1) Folga + qualquer input preenchido → Trabalho com defaults completados
  if(cur === 'folga' && input.value){
    row.dataset.tipo = 'trabalho';
    setBadge('trabalho');
    setOpacity('trabalho');
    const h = getDefaults();
    if(h){
      const ent = row.querySelector('.esc-entrada');
      const ini = row.querySelector('.esc-int-ini');
      const fim = row.querySelector('.esc-int-fim');
      const sai = row.querySelector('.esc-saida');
      if(ent && !ent.value) ent.value = h.entrada;
      if(ini && !ini.value) ini.value = h.intIni;
      if(fim && !fim.value) fim.value = h.intFim;
      if(sai && !sai.value) sai.value = h.saida;
    }
    return;
  }
  // 2) Corrido + campo de refeição preenchido → volta para Trabalho normal
  if(cur === 'corrido' && isMealField && input.value){
    row.dataset.tipo = 'trabalho';
    setBadge('trabalho');
    setOpacity('trabalho');
    const ini = row.querySelector('.esc-int-ini');
    const fim = row.querySelector('.esc-int-fim');
    const h = getDefaults();
    if(h){
      if(ini && !ini.value) ini.value = h.intIni;
      if(fim && !fim.value) fim.value = h.intFim;
    }
  }
}

// Ciclo de status: Trabalho → Corrido → Folga → Trabalho ...
function toggleEscalaTipo(span){
  const row = span.closest('tr');
  if(!row) return;
  const card = span.closest('.escala-card');
  const cur = row.dataset.tipo || 'trabalho';
  let novo;
  if(cur === 'trabalho')      novo = 'corrido';
  else if(cur === 'corrido')  novo = 'folga';
  else                        novo = 'trabalho';
  row.dataset.tipo = novo;
  // Limpa hePerc ao sair de corrido
  if(novo !== 'corrido') delete row.dataset.hePerc;
  const perc = parseInt(row.dataset.hePerc) || (novo==='corrido' ? 50 : null);
  span.innerHTML = _escalaTipoBadge(novo, perc);

  const ent = row.querySelector('.esc-entrada');
  const ini = row.querySelector('.esc-int-ini');
  const fim = row.querySelector('.esc-int-fim');
  const sai = row.querySelector('.esc-saida');

  // Defaults do colaborador (para preencher entrada/saída em corrido e tudo em trabalho)
  let h = null;
  if(card){
    const empId = card.dataset.empId;
    const emp = (State.employees||[]).find(e=>e.id===empId);
    if(emp){
      const dia = parseInt(row.dataset.dia);
      const mes = parseInt(document.getElementById('escala-mes').value);
      const ano = parseInt(document.getElementById('escala-ano').value);
      const realDs = new Date(ano, mes-1, dia).getDay();
      h = _escalaHorariosDia(emp, realDs);
    }
  }

  if(novo === 'folga'){
    [ent, ini, fim, sai].forEach(inp => { if(inp){ inp.value=''; inp.style.opacity='.55'; } });
  } else if(novo === 'corrido'){
    // Mantém entrada/saída (preenche se vazio); zera refeição e esmaece
    if(ent){ ent.style.opacity='1'; if(!ent.value && h) ent.value = h.entrada; }
    if(sai){ sai.style.opacity='1'; if(!sai.value && h) sai.value = h.saida; }
    if(ini){ ini.value=''; ini.style.opacity='.4'; }
    if(fim){ fim.value=''; fim.style.opacity='.4'; }
    // Define default 50% e abre modal pra escolher %
    row.dataset.hePerc = '50';
    _openCorridoPercModal(row, cur);
  } else {
    // Trabalho: pré-preenche todos vazios
    [ent, ini, fim, sai].forEach(inp => { if(inp) inp.style.opacity='1'; });
    if(h){
      if(ent && !ent.value) ent.value = h.entrada;
      if(ini && !ini.value) ini.value = h.intIni;
      if(fim && !fim.value) fim.value = h.intFim;
      if(sai && !sai.value) sai.value = h.saida;
    }
  }
  if(card) card.dataset.dirty = '1';
}

// Aplica um tipo (trabalho/folga) a uma linha da escala — usado pela
// reprojeção do ciclo 12x36 (clique no número do dia). Preserva os
// horários já preenchidos em dias que continuam sendo de trabalho.
function _setEscalaRowTipo(row, novo, emp, mes, ano){
  row.dataset.tipo = novo;
  delete row.dataset.hePerc;
  const cell = row.querySelector('.esc-tipo-cell');
  if(cell) cell.innerHTML = _escalaTipoBadge(novo);
  const ent = row.querySelector('.esc-entrada');
  const ini = row.querySelector('.esc-int-ini');
  const fim = row.querySelector('.esc-int-fim');
  const sai = row.querySelector('.esc-saida');
  if(novo === 'folga'){
    [ent,ini,fim,sai].forEach(i=>{ if(i){ i.value=''; i.style.opacity='.55'; } });
    return;
  }
  [ent,ini,fim,sai].forEach(i=>{ if(i) i.style.opacity='1'; });
  let h = null;
  if(emp){
    const dia = parseInt(row.dataset.dia);
    h = _escalaHorariosDia(emp, new Date(ano, mes-1, dia).getDay());
  }
  if(h){
    if(ent && !ent.value) ent.value = h.entrada;
    if(ini && !ini.value) ini.value = h.intIni;
    if(fim && !fim.value) fim.value = h.intFim;
    if(sai && !sai.value) sai.value = h.saida;
  }
}

// Dias da escala que NÃO devem ser reprojetados: APENAS os já trabalhados,
// com ponto real batido na folha (entrada + saída). Dia que só está "no
// passado" do calendário, mas sem ponto, é apenas projeção — pode e deve
// ser corrigido quando o gestor ajusta a escala.
function _diasProtegidosEscala(empId, mes, ano){
  const set = new Set();
  const pay = (State.payrolls||[]).find(p=>p.employeeId===empId&&p.mes==mes&&p.ano==ano);
  if(pay && Array.isArray(pay.pontoManualDias)){
    pay.pontoManualDias.forEach(d=>{ if(d&&d.entrada&&d.saida) set.add(d.dia); });
  }
  return set;
}

// Clique no número do dia (escala 12x36): define esse dia como início do
// ciclo de trabalho, recalcula a alternância trabalho/folga e salva — sem
// mexer nos dias já trabalhados/passados.
async function _escala12x36Anchor(cell){
  const card = cell.closest('.escala-card');
  const row0 = cell.closest('tr');
  if(!card || !row0) return;
  if(card.dataset.fam !== '12x36') return;
  const anchorDia = parseInt(row0.dataset.dia);
  const empId = card.dataset.empId;
  const emp = (State.employees||[]).find(e=>e.id===empId);
  const mes = parseInt(document.getElementById('escala-mes').value);
  const ano = parseInt(document.getElementById('escala-ano').value);
  const protegidos = _diasProtegidosEscala(empId, mes, ano);
  let bloqueados = 0;
  card.querySelectorAll('tbody tr[data-dia]').forEach(row=>{
    const dia = parseInt(row.dataset.dia);
    if(protegidos.has(dia)){ bloqueados++; return; } // dia trabalhado/passado: preserva
    const tipo = (((dia - anchorDia) % 2) === 0) ? 'trabalho' : 'folga';
    _setEscalaRowTipo(row, tipo, emp, mes, ano);
  });
  // Re-ancora o ciclo no cadastro (a escala reprojetada vira a referência;
  // desvinculada do 1º dia de trabalho — pode mudar no meio do contrato).
  if(emp){
    const _zpA = n=>String(n).padStart(2,'0');
    emp.ciclo12x36Inicio = `${ano}-${_zpA(mes)}-${_zpA(anchorDia)}`;
    emp.updatedAt = new Date().toISOString();
    try { await DB.save('employees', emp); } catch(e){ console.error('âncora 12x36', e); }
  }
  await saveEscala(empId, true);
  toast(`Ciclo 12x36 re-ancorado no dia ${String(anchorDia).padStart(2,'0')} (trabalho) — escala e cadastro salvos.${bloqueados?` ${bloqueados} dia(s) já trabalhado(s)/passado(s) preservado(s).`:''}`, 'success');
}

// ── Ajustar / trocar escala de um colaborador (modal) ──────────────────
let _ajustarEscalaEmpId = null;

function openAjustarEscala(empId){
  const emp = (State.employees||[]).find(e=>e.id===empId);
  if(!emp){ toast('Colaborador não encontrado.','error'); return; }
  _ajustarEscalaEmpId = empId;
  const mes = parseInt(document.getElementById('escala-mes').value);
  const ano = parseInt(document.getElementById('escala-ano').value);
  const sel = document.getElementById('ajustar-escala-tipo');
  // Re-injeta os modelos de escala customizados (optgroup "★ Criadas por você")
  _injetarModelosNoSelect(sel);
  sel.value = emp.escala || '5x2A';
  const diaEl = document.getElementById('ajustar-escala-dia');
  diaEl.max = new Date(ano, mes, 0).getDate();
  diaEl.value = 1; // 12x36: âncora no dia 1 · 5x2/6x1: mês inteiro
  document.getElementById('ajustar-escala-update-cadastro').checked = false;
  document.getElementById('ajustar-escala-info').innerHTML =
    `<strong>${emp.nome}</strong> &middot; ${MESES[mes]}/${ano} &middot; escala no cadastro: <strong>${escalaLabel(emp.escala||'5x2A')}</strong>`;
  document.getElementById('modal-ajustar-escala').classList.remove('hidden');
}

async function aplicarAjusteEscala(){
  const empId = _ajustarEscalaEmpId;
  const emp = (State.employees||[]).find(e=>e.id===empId);
  if(!emp){ toast('Colaborador não encontrado.','error'); return; }
  // (não depende mais da grade do card — opera só sobre emp.escala + DB. #audit-hoje-8)
  const mes = parseInt(document.getElementById('escala-mes').value);
  const ano = parseInt(document.getElementById('escala-ano').value);
  const novaEscala = document.getElementById('ajustar-escala-tipo').value;
  const dpm  = new Date(ano, mes, 0).getDate();
  const diaX = Math.min(dpm, Math.max(1, parseInt(document.getElementById('ajustar-escala-dia').value)||1));
  const updateCad = document.getElementById('ajustar-escala-update-cadastro').checked;
  // Quando o usuário marca "troca definitiva", força os horários default da
  // nova escala — senão `_escalaHorariosDia` continua usando `emp.horarioEntrada`
  // (que sobrou da escala anterior) e a projeção sai com os horários antigos.
  // Se o gestor quer manter horário customizado, desmarca o checkbox.
  const def = ESCALA_HORARIOS_DEFAULT[novaEscala] || ESCALA_HORARIOS_DEFAULT['5x2A'];
  const fam = escalaFamilia(novaEscala);
  // MODELO INFORMATIVO (Fase 1): "Ajustar escala" muda a escala CONTRATUAL do
  // colaborador (fonte única) — NÃO grava mais uma grade por competência. A
  // projeção passa a refletir a nova escala automaticamente. Mudança a partir do
  // meio do mês → use Transferência de escala no cadastro; 12x36 grava a âncora.
  emp.escala = novaEscala;
  if(fam === '12x36'){
    const _zpA = n=>String(n).padStart(2,'0');
    // diaX é dia da COMPETÊNCIA (26-31 = mês anterior); a âncora é DATA REAL de
    // calendário. Converte antes, senão dias 26-31 ancoram o ciclo ~1 mês à frente
    // e invertem trabalho/folga o mês todo. #audit-hoje-3
    const _r = _compRealDate(mes, ano, diaX);
    emp.ciclo12x36Inicio = `${_r.ano}-${_zpA(_r.mes)}-${_zpA(_r.dia)}`;
    if(novaEscala.startsWith('12x36-')) emp.turnoNoturno = _escala12x36Noturna(novaEscala);
  }
  if(updateCad){
    // "Trocar horários para o padrão da nova escala" (senão mantém os do cadastro).
    emp.horarioEntrada = def.entrada;
    emp.horarioSaida   = def.saida;
    // A refeição é do CONTRATO: só sobrescreve se a nova escala TEM refeição padrão;
    // senão MANTÉM a do colaborador (não zera). #jornada-segue-contrato
    emp.horarioRefIni  = (def && def.intIni) ? def.intIni : (emp.horarioRefIni||'');
    emp.horarioRefFim  = (def && def.intFim) ? def.intFim : (emp.horarioRefFim||'');
  }
  emp.updatedAt = new Date().toISOString();
  try {
    await DB.save('employees', emp);
  } catch (e) {
    console.error('Erro ao salvar cadastro:', e);
    toast('Falhou ao salvar a escala no cadastro: ' + (e.message || e), 'error'); return;
  }
  // Remove a escala SALVA desta competência (se houver) — sem isso ela venceria a
  // projeção e o "Ajustar" não surtiria efeito aqui. Só esta competência; as
  // batidas reais ficam na folha (não se perdem).
  const _savedEsc = (State.escalas||[]).find(e=>e && e.employeeId===empId && e.mes==mes && e.ano==ano);
  if(_savedEsc){
    try { await DB.remove('escalas', _savedEsc.id); State.escalas=(State.escalas||[]).filter(e=>e.id!==_savedEsc.id); }
    catch(e){ console.error('remover escala salva (ajuste):', e); }
  }
  closeModal('modal-ajustar-escala');
  _renderEscalasCards(); // re-renderiza a tela já com a nova projeção (do contrato)
  const partes = [`Escala alterada para ${escalaLabel(novaEscala)} no cadastro`];
  if(fam==='12x36') partes.push(`ciclo ancorado em ${String(diaX).padStart(2,'0')}/${String(mes).padStart(2,'0')}`);
  if(updateCad)     partes.push(`horários: entrada ${def.entrada} / saída ${def.saida}`);
  toast(partes.join(' · ') + '.', 'success');
}

function _collectEscalaDias(empId){
  const card = document.querySelector(`.escala-card[data-emp-id="${empId}"]`);
  if(!card) return null;
  const mes = parseInt(document.getElementById('escala-mes').value);
  const ano = parseInt(document.getElementById('escala-ano').value);
  const rows = card.querySelectorAll('tbody tr[data-dia]');
  const dias = [];
  rows.forEach(row => {
    const dia = parseInt(row.dataset.dia);
    // diaSem usa a DATA REAL da competência (dia 26-31 = mês anterior).
    // Antes usava new Date(ano, mes-1, dia) que dava errado pra dias 26-31.
    const r = _compRealDate(mes, ano, dia);
    const ds = new Date(r.ano, r.mes-1, r.dia).getDay();
    const tipo = row.dataset.tipo || 'trabalho';
    const obj = {
      dia, diaSem:ds, tipo,
      entrada: row.querySelector('.esc-entrada').value,
      intIni:  row.querySelector('.esc-int-ini').value,
      intFim:  row.querySelector('.esc-int-fim').value,
      saida:   row.querySelector('.esc-saida').value
    };
    if(tipo === 'corrido'){
      obj.hePercDia = parseInt(row.dataset.hePerc) || 50;
    }
    dias.push(obj);
  });
  return dias;
}

async function saveEscala(empId, silent){
  const mes = parseInt(document.getElementById('escala-mes').value);
  const ano = parseInt(document.getElementById('escala-ano').value);
  const dias = _collectEscalaDias(empId);
  if(!dias){ toast('Erro: card não encontrado','error'); return; }
  const existing = (State.escalas||[]).find(e => e.employeeId===empId && e.mes==mes && e.ano==ano);
  const record = {
    id:        existing?.id || genId(),
    employeeId:empId, mes, ano, dias,
    updatedAt: new Date().toISOString(),
    createdAt: existing?.createdAt || new Date().toISOString()
  };
  const card = document.querySelector(`.escala-card[data-emp-id="${empId}"]`);
  const btn = card?.querySelector('.btn-primary');
  if(btn) setBtnLoading(btn, true, '');
  try {
    await DB.save('escalas', record);
    if(!silent) toast('Escala salva!');
    if(card) delete card.dataset.dirty;
  } catch(e){
    console.error(e);
    toast('Erro ao salvar escala','error');
  } finally {
    if(btn) setBtnLoading(btn, false, '<i class="fa-solid fa-floppy-disk"></i> Salvar');
  }
}

function resetEscala(empId){
  const mes = parseInt(document.getElementById('escala-mes').value);
  const ano = parseInt(document.getElementById('escala-ano').value);
  const emp = (State.employees||[]).find(e=>e.id===empId);
  if(!emp) return;
  // Substitui card sem usar a versão salva
  const oldEscalas = State.escalas;
  State.escalas = (oldEscalas||[]).filter(e => !(e.employeeId===empId && e.mes==mes && e.ano==ano));
  const card = document.querySelector(`.escala-card[data-emp-id="${empId}"]`);
  if(card) card.outerHTML = _renderEscalaCard(emp, mes, ano);
  State.escalas = oldEscalas;
  toast('Escala reprojetada (não salva)');
}

// ============================================
// ESCALAS — Refeição em massa (cascata)
// ============================================
let _bulkRefeicaoEmpId = null;

function openBulkRefeicao(empId){
  const emp = (State.employees||[]).find(e=>e.id===empId);
  if(!emp){ toast('Colaborador não encontrado','error'); return; }
  if(emp.semRefeicao){ toast('Este colaborador trabalha sozinho — sem horário de refeição.','error'); return; }
  _bulkRefeicaoEmpId = empId;
  const mes = parseInt(document.getElementById('escala-mes').value);
  const ano = parseInt(document.getElementById('escala-ano').value);
  const today = new Date();
  const isCurMes = (mes==today.getMonth()+1 && ano==today.getFullYear());
  const startDia = isCurMes ? today.getDate() : 1;
  // Pré-preenche com horários atuais do colaborador
  setVal('bulk-ref-ini', emp.horarioRefIni || '12:00');
  setVal('bulk-ref-fim', emp.horarioRefFim || '13:00');
  setVal('bulk-ref-dia', startDia);
  document.getElementById('bulk-ref-update-cadastro').checked = true;
  document.getElementById('bulk-ref-future-months').checked = true;
  document.getElementById('bulk-refeicao-info').innerHTML =
    `<strong>${emp.nome}</strong> &middot; ${escalaLabel(emp.escala||'5x2A')}${emp.turnoNoturno?' (Noturno)':''}<br>
     <span style="color:var(--text-muted);font-size:12px">Mês visível: ${MESES[mes]}/${ano}</span>`;
  document.getElementById('modal-bulk-refeicao').classList.remove('hidden');
}

async function applyBulkRefeicao(){
  const empId = _bulkRefeicaoEmpId;
  if(!empId){ closeModal('modal-bulk-refeicao'); return; }
  const emp = (State.employees||[]).find(e=>e.id===empId);
  if(!emp){ toast('Colaborador não encontrado','error'); return; }
  const newIni = val('bulk-ref-ini');
  const newFim = val('bulk-ref-fim');
  if(!newIni || !newFim){ toast('Preencha os dois horários.','error'); return; }
  const startDia = parseInt(val('bulk-ref-dia')||'1');
  const updateCadastro = document.getElementById('bulk-ref-update-cadastro').checked;
  const futureMonths = document.getElementById('bulk-ref-future-months').checked;
  const mes = parseInt(document.getElementById('escala-mes').value);
  const ano = parseInt(document.getElementById('escala-ano').value);
  const btn = document.querySelector('#modal-bulk-refeicao .btn-primary');
  if(btn) setBtnLoading(btn, true, '');
  try {
    // 1) Atualiza DOM do card atual (apenas dias >= startDia, somente trabalho)
    const card = document.querySelector(`.escala-card[data-emp-id="${empId}"]`);
    let domCount = 0;
    if(card){
      card.querySelectorAll('tbody tr[data-dia]').forEach(row => {
        const d = parseInt(row.dataset.dia);
        if(d < startDia) return;
        if(row.dataset.tipo !== 'trabalho') return;
        const ini = row.querySelector('.esc-int-ini');
        const fim = row.querySelector('.esc-int-fim');
        if(ini){ ini.value = newIni; }
        if(fim){ fim.value = newFim; }
        domCount++;
      });
      card.dataset.dirty = '1';
    }
    // 2) Atualiza cadastro se solicitado
    if(updateCadastro){
      emp.horarioRefIni = newIni;
      emp.horarioRefFim = newFim;
      emp.updatedAt = new Date().toISOString();
      await DB.save('employees', emp);
    }
    // 3) Atualiza meses futuros já salvos (se solicitado)
    let futCount = 0;
    if(futureMonths){
      const futuras = (State.escalas||[]).filter(e => e.employeeId===empId &&
        ((e.ano > ano) || (e.ano==ano && e.mes > mes))
      );
      for(const fut of futuras){
        const novoDias = (fut.dias||[]).map(d => {
          if(d.tipo === 'trabalho'){
            return { ...d, intIni: newIni, intFim: newFim };
          }
          return d;
        });
        const novo = { ...fut, dias: novoDias, updatedAt: new Date().toISOString() };
        await DB.save('escalas', novo);
        futCount++;
      }
    }
    closeModal('modal-bulk-refeicao');
    toast(`Aplicado: ${domCount} dia(s) no mês atual + ${futCount} mês(es) futuro(s). Clique em Salvar no card pra confirmar o mês atual.`);
  } catch(e){
    console.error(e);
    toast('Erro ao aplicar refeição em massa','error');
  } finally {
    if(btn) setBtnLoading(btn, false, '<i class="fa-solid fa-check"></i> Aplicar');
  }
}

// ============================================
// ESCALAS — Exports (Print/Excel/Word)
// ============================================
function exportEscalas(format){
  const mes = parseInt(document.getElementById('escala-mes').value);
  const ano = parseInt(document.getElementById('escala-ano').value);
  const cards = document.querySelectorAll('.escala-card');
  if(!cards.length){ toast('Nenhuma escala visível para exportar','error'); return; }
  let bodyHtml = '';
  cards.forEach(card => {
    const empId = card.dataset.empId;
    const emp = State.employees.find(e=>e.id===empId);
    if(!emp) return;
    const posto = (emp.posto || '—');
    const dias = _escalaDiasFor(emp, mes, ano).dias;   // mesma fonte da tela (realizada/ajustada/contrato). #escala-realizada
    const _statusLabel = {trabalho:'Trabalho',corrido:'Corrido',folga:'Folga',semreg:'s/ registro',atestado:'Atestado',abono:'Abono',cobertura:'Cobertura',ferias:'Férias'};
    const fam = escalaFamilia(emp.escala||'5x2A');
    bodyHtml += `<h2 style="color:#1a3a6b;font-size:14px;margin:14px 0 4px;page-break-after:avoid">${emp.nome}</h2>
      <p style="font-size:11px;color:#444;margin:0 0 6px"><strong>Posto:</strong> ${posto} &nbsp;|&nbsp; <strong>Setor:</strong> ${emp.setor||'—'} &nbsp;|&nbsp; <strong>Escala:</strong> ${escalaLabel(emp.escala||'5x2A')}${emp.turnoNoturno?' (Noturno)':''}</p>
      <table border="1" cellpadding="4" cellspacing="0" style="border-collapse:collapse;width:100%;font-size:11px;margin-bottom:14px;page-break-inside:auto">
        <thead style="background:#1a3a6b;color:#fff"><tr>
          <th>Dia</th><th>Sem.</th><th>Status</th><th>Entrada</th><th>Início Ref.</th><th>Retorno Ref.</th><th>Saída</th>
        </tr></thead><tbody>`;
    dias.forEach(d => {
      const sem = ['Dom','Seg','Ter','Qua','Qui','Sex','Sáb'][d.diaSem];
      let bg = '#fff';
      if(fam==='12x36') bg = d.tipo==='trabalho' ? '#E3F2FD' : '#FFF8E1';
      else if(d.diaSem===0) bg = '#FFEBEE';
      else if(d.diaSem===6) bg = '#FFF9C4';
      const _rd=_compRealDate(mes,ano,d.dia);
      bodyHtml += `<tr style="background:${bg}">
        <td style="text-align:center"><strong>${String(_rd.dia).padStart(2,'0')}/${String(_rd.mes).padStart(2,'0')}</strong></td>
        <td style="text-align:center">${sem}</td>
        <td style="text-align:center">${_statusLabel[d.tipo]||'Trabalho'}</td>
        <td style="text-align:center">${d.entrada||'—'}</td>
        <td style="text-align:center">${d.intIni||'—'}</td>
        <td style="text-align:center">${d.intFim||'—'}</td>
        <td style="text-align:center">${d.saida||'—'}</td>
      </tr>`;
    });
    bodyHtml += `</tbody></table>`;
  });
  const titulo = `Escalas — ${MESES[mes]}/${ano}`;
  const html = `<!DOCTYPE html><html><head><meta charset="UTF-8"><title>${titulo}</title>
<style>body{font-family:Arial,sans-serif;padding:14px;color:#212529}h1{color:#1a3a6b;font-size:18px;margin-bottom:6px}h2{page-break-after:avoid}table{font-size:11px}@media print{h1{font-size:14px}h2{font-size:12px}table{page-break-inside:avoid}}</style>
</head><body>
<h1>${_e('nomeEmpresa')} — ${titulo}</h1>
${bodyHtml}
<p style="margin-top:18px;font-size:9px;color:#888;text-align:center">Gerado em ${new Date().toLocaleString('pt-BR')} — ${cards.length} colaborador(es)</p>
</body></html>`;
  if(format==='print'){
    const win = window.open('','_blank','width=900,height=700');
    if(!win){ toast('Permita pop-ups para imprimir','error'); return; }
    win.document.write(html + '<scr'+'ipt>window.onload=function(){window.print();}<\/scr'+'ipt>');
    win.document.close();
  } else if(format==='excel'){
    const blob = new Blob(['﻿' + html], {type:'application/vnd.ms-excel;charset=utf-8'});
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = `Escalas_${MESES[mes]}_${ano}.xls`;
    a.click();
    URL.revokeObjectURL(a.href);
    toast('Excel gerado!');
  } else if(format==='word'){
    const blob = new Blob(['﻿' + html], {type:'application/msword;charset=utf-8'});
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = `Escalas_${MESES[mes]}_${ano}.doc`;
    a.click();
    URL.revokeObjectURL(a.href);
    toast('Word gerado!');
  }
}

