// Retorna os módulos permitidos para o usuário
function getUserModules(user){
  if(!user) return {};
  if(user.role==='master')  return {dashboard:true,employees:true,payroll:true,escalas:true,criarEscalas:true,aprovaHE:true,aprovaHESupervisor:true,reports:true,pagamentos:true,pagamentosLancar:true,pagamentosAprovar:true,decimoterceiro:true,ferias:true,rescisao:true,contabilidade:true,postos:true,contratos:true,users:true,log:true,comunicacao:true,comunicacoesApagar:true,disciplinaApagar:true,autorizarPonto:true,monitorarFaltas:true,revisarContrato:true,gerirFolgasEscala:true,estoque:true,lgpd:true,configuracoes:true};
  // PERMISSÕES POR USUÁRIO (fonte principal; substitui perfis). Vive em
  // configuracoes/permissoesUsuarios por username. Fallback p/ perfil/role se o
  // usuário ainda NÃO tem lista própria — assim ninguém perde acesso. #perm-por-usuario
  const _pu=(State.permissoesUsuarios||{})[user.username];
  if(_pu && _pu.modules && typeof _pu.modules==='object'){
    return {dashboard:true, ..._pu.modules, log:!!(_pu.modules.log||user.showLog)};
  }
  if(user.role==='operador') return {dashboard:true,employees:false,payroll:true,escalas:true,criarEscalas:false,aprovaHE:false,reports:true,pagamentos:true,pagamentosLancar:false,pagamentosAprovar:false,decimoterceiro:true,ferias:true,rescisao:false,contabilidade:true,postos:false,contratos:false,users:false,log:!!user.showLog};
  if(user.role&&user.role.startsWith('p_')){
    const perfilId=user.role.replace('p_','');
    const perfil=(State.perfis||[]).find(p=>p.id===perfilId);
    if(perfil) return {dashboard:true,...(perfil.modules||{}),log:!!(perfil.modules?.log||user.showLog)};
  }
  return {dashboard:true,payroll:true,escalas:true,reports:true};
}

// Módulos com cadastro/edição onde o nível "editar vs só visualizar" faz sentido.
// (aprovaHE, reports e log ficam de fora — são ação ou somente leitura.)
const CRUD_MODULES=['employees','payroll','escalas','pagamentos','decimoterceiro','ferias','rescisao','contabilidade','postos','contratos','users'];

// Nível de permissão por módulo: 'edit' | 'view'. Master e operador = edit em tudo.
// Perfis antigos sem `modulesPerm` assumem 'edit' nos módulos acessíveis
// (retrocompatível — comportamento idêntico ao anterior à feature).
function getUserPerms(user){
  const perms={};
  if(!user) return perms;
  if(user.role==='master'){ CRUD_MODULES.forEach(m=>perms[m]='edit'); return perms; }
  // Nível por USUÁRIO (fonte principal); fallback p/ perfil/role. #perm-por-usuario
  const _pu=(State.permissoesUsuarios||{})[user.username];
  if(_pu && _pu.modulesPerm){ CRUD_MODULES.forEach(m=>{ perms[m]=(_pu.modulesPerm[m]==='view')?'view':'edit'; }); return perms; }
  if(user.role==='operador'){ CRUD_MODULES.forEach(m=>perms[m]='edit'); return perms; }
  if(user.role&&user.role.startsWith('p_')){
    const perfil=(State.perfis||[]).find(p=>p.id===user.role.replace('p_',''));
    const mp=(perfil&&perfil.modulesPerm)||{};
    CRUD_MODULES.forEach(m=>{ perms[m]=(mp[m]==='view')?'view':'edit'; });
    return perms;
  }
  CRUD_MODULES.forEach(m=>perms[m]='edit');
  return perms;
}

// true se o usuário atual pode EDITAR o módulo. Módulos fora de CRUD_MODULES
// (aprovaHE/reports/log/dashboard) não têm restrição de nível.
function canEditModule(mod){
  const u=Auth.currentUser;
  if(!u) return false;
  if(u.role==='master') return true;
  if(!CRUD_MODULES.includes(mod)) return true;
  return getUserPerms(u)[mod]!=='view';
}

// true se o usuário pode incluir FOLGAS, dia avulso (override) e troca/mudança de
// escala no cadastro. Permissão dedicada `gerirFolgasEscala` (master sempre pode). #folga-avulsa
function _podeGerirFolgasEscala(){
  const u=Auth.currentUser;
  if(!u) return false;
  if(u.role==='master') return true;
  const mods=getUserModules(u);
  // Perfis LEGADOS (chave ausente, anteriores à feature) HERDAM de quem já gere Escalas
  // ou Folha — senão supervisores/gestores antigos perderam folga/compensação/troca sem o
  // master saber (os botões eram livres antes da permissão). Se o master marcar/desmarcar
  // explicitamente no editor, vale o valor explícito (true/false). #folga-avulsa
  if(typeof mods.gerirFolgasEscala==='undefined') return !!(mods.escalas || mods.payroll);
  return !!mods.gerirFolgasEscala;
}

// true se o usuário pode gerir perfis de acesso: master, ou perfil com o módulo
// "Usuários & Acessos" no nível Editar (ex.: o perfil "Gestor Senior").
function canManagePerfis(){
  const u=Auth.currentUser; if(!u) return false;
  if(u.role==='master') return true;
  return !!(getUserModules(u).users && canEditModule('users'));
}

// ── Escopo por postos (supervisor responsável por N postos) ──
// Retorna a lista de postos (razaoSocial) que o usuário enxerga, OU null se ele
// não tem restrição (master, ou usuário sem `postosResponsavel` definido).
// `emp.posto` guarda a razaoSocial do posto (ver entrada do CLAUDE.md de
// 2026-05-17 sobre padronização do campo `posto`).
function _postosDoUsuario(user){
  if(!user) return null;
  if(user.role==='master') return null;
  const lista=user.postosResponsavel;
  if(!Array.isArray(lista) || lista.length===0) return null;
  return lista;
}
// true se o colaborador está no escopo do usuário atual. Sem restrição → tudo true.
function _empNoEscopo(emp){
  const escopo=_postosDoUsuario(Auth.currentUser);
  if(!escopo) return true;
  return escopo.includes(emp&&emp.posto);
}
// Filtra um array de colaboradores pelo escopo do usuário atual.
function _filtrarEmpsPorEscopo(emps){
  const escopo=_postosDoUsuario(Auth.currentUser);
  if(!escopo) return emps;
  return (emps||[]).filter(e=>escopo.includes(e&&e.posto));
}

// ── Bloqueio central de gravação para perfis "somente visualizar" ──
// Mapeia coleção do Firestore → módulo. Coleções fora do mapa não têm restrição
// (ex.: accessLog, configuracoes — sempre liberadas).
const COLL_MODULE={employees:'employees',payrolls:'payroll',escalas:'escalas',rescisoes:'rescisao',decimoTerceiro:'decimoterceiro',ferias:'ferias',postos:'postos',contratos:'contratos',bancoHoras:'payroll'};
// Lança erro (e avisa o usuário) se o perfil atual não pode gravar na coleção.
// Chamado dentro dos métodos de escrita do DB — rede de segurança do "só visualizar".
function _dbAssertWrite(col){
  const mod=COLL_MODULE[col];
  if(!mod || !Auth.currentUser || canEditModule(mod)) return;
  toast('Seu perfil é somente de visualização — esta alteração não é permitida.','error');
  const err=new Error('view-only'); err._viewOnly=true; throw err;
}

function openPerfilModal(id=null){
  if(!canManagePerfis()) return;
  document.getElementById('modal-perfil').classList.remove('hidden');
  const titleEl=document.getElementById('modal-perfil-title');
  // Aplica o nível de um módulo ao controle correspondente (select de 3 níveis ou checkbox)
  const setMod=(mod,modules,perm)=>{
    const chk=document.querySelector(`#perfil-modulos input[value="${mod}"]`);
    if(chk){
      // gerirFolgasEscala legado (chave ausente) mostra o estado EFETIVO (herda de
      // Escalas/Folha, igual _podeGerirFolgasEscala) — assim o master vê marcado e pode
      // salvar (vira explícito) ou desmarcar (revoga). #folga-avulsa
      chk.checked = (mod==='gerirFolgasEscala' && typeof modules[mod]==='undefined')
        ? !!(modules.escalas || modules.payroll)
        : !!modules[mod];
    }
    const ed=document.querySelector(`#perfil-modulos input[data-edit="${mod}"]`);
    if(ed) ed.checked = !!modules[mod] && perm[mod]!=='view';
  };
  if(id){
    const p=State.perfis.find(p=>p.id===id); if(!p) return;
    titleEl.innerHTML='<i class="fa-solid fa-shield-halved"></i> Editar Perfil';
    setVal('perfil-id',p.id); setVal('perfil-nome',p.nome);
    const modules=p.modules||{}, perm=p.modulesPerm||{};
    Object.keys(MODULOS_LABELS).forEach(mod=>setMod(mod,modules,perm));
  } else {
    titleEl.innerHTML='<i class="fa-solid fa-shield-halved"></i> Novo Perfil';
    setVal('perfil-id',''); setVal('perfil-nome','');
    // Novo perfil: acesso de edição a tudo, exceto Usuários & Acessos
    const defModules={}, defPerm={};
    Object.keys(MODULOS_LABELS).forEach(m=>{ defModules[m]=(m!=='users' && m!=='criarEscalas'); defPerm[m]='edit'; });
    Object.keys(MODULOS_LABELS).forEach(mod=>setMod(mod,defModules,defPerm));
  }
}

async function savePerfil(){
  if(!canManagePerfis()) return;
  const nome=val('perfil-nome').trim();
  if(!nome){ toast('Nome do perfil obrigatório.','error'); return; }
  const modules={dashboard:true}, modulesPerm={};
  Object.keys(MODULOS_LABELS).forEach(mod=>{
    const chk=document.querySelector(`#perfil-modulos input[value="${mod}"]`);
    modules[mod]=chk?chk.checked:false;
    const ed=document.querySelector(`#perfil-modulos input[data-edit="${mod}"]`);
    if(ed && modules[mod]) modulesPerm[mod]= ed.checked ? 'edit' : 'view';
  });
  const id=val('perfil-id')||genId();
  const perfil={id,nome,modules,modulesPerm,updatedAt:new Date().toISOString()};
  const btn=document.querySelector('#modal-perfil .btn-primary');
  setBtnLoading(btn,true,'');
  try {
    await DB.save('perfis',perfil);
    closeModal('modal-perfil');
    toast(`Perfil "${nome}" salvo!`);
    Auth.log('USER_UPDATED',Auth.currentUser.username,`Perfil salvo: ${nome}`);
  } catch(e){ toast('Erro ao salvar perfil.','error'); }
  finally { setBtnLoading(btn,false,'<i class="fa-solid fa-floppy-disk"></i> Salvar Perfil'); }
}

// Card de Perfis fica OCULTO por padrão (permissões agora são por usuário). Pode ser
// reativado pelo botão "Perfis (avançado)" — preferência guardada no aparelho. #perm-por-usuario
function _aplicarVisibilidadePerfis(){
  const card=document.getElementById('perfis-card'); if(!card) return;
  const mostrar = localStorage.getItem('drg_mostrarPerfis')==='1';
  card.style.display = mostrar ? '' : 'none';
}
function _togglePerfisCard(){
  const mostrar = localStorage.getItem('drg_mostrarPerfis')==='1';
  localStorage.setItem('drg_mostrarPerfis', mostrar ? '0' : '1');
  _aplicarVisibilidadePerfis();
  if(!mostrar){ renderPerfisTable(); toast('Perfis exibidos (recurso opcional).'); }
  else toast('Perfis ocultados.');
}
function renderPerfisTable(){
  _aplicarVisibilidadePerfis();
  const tbody=document.getElementById('perfis-tbody'); if(!tbody) return;
  const systemPerfis=[
    {nome:'Master',desc:'Acesso total ao sistema',tipo:'Sistema'},
    {nome:'Operador',desc:'Folha de Ponto + Relatórios',tipo:'Sistema'}
  ];
  let rows=systemPerfis.map(p=>`<tr>
    <td><strong>${p.nome}</strong></td>
    <td style="font-size:12px;color:var(--text-muted)">${p.desc}</td>
    <td><span class="badge badge-muted">Sistema</span></td>
    <td>—</td>
  </tr>`).join('');
  if(State.perfis.length>0){
    rows+=State.perfis.map(p=>{
      const modList=Object.entries(p.modules||{}).filter(([k,v])=>v&&k!=='dashboard').map(([k])=>{
        const lbl=MODULOS_LABELS[k]||k;
        return (p.modulesPerm&&p.modulesPerm[k]==='view')?lbl+' <span style="color:#90A4AE">(ver)</span>':lbl;
      }).join(', ')||'—';
      return `<tr>
        <td><strong>${p.nome}</strong></td>
        <td style="font-size:12px;color:var(--text-muted)">${modList}</td>
        <td><span class="badge badge-gestor">Customizado</span></td>
        <td><div class="actions-cell">
          <button class="btn-icon btn-warning-icon" onclick="openPerfilModal('${p.id}')" title="Editar"><i class="fa-solid fa-pencil"></i></button>
          <button class="btn-icon btn-danger-icon" onclick="confirmDeletePerfil('${p.id}')" title="Excluir"><i class="fa-solid fa-trash"></i></button>
        </div></td>
      </tr>`;
    }).join('');
  }
  tbody.innerHTML=rows;
}

function confirmDeletePerfil(id){
  if(!canManagePerfis()) return;
  const p=State.perfis.find(p=>p.id===id); if(!p) return;
  document.getElementById('confirm-message').textContent=`Excluir o perfil "${p.nome}"? Usuários com este perfil passarão a ser Operadores.`;
  const btn=document.getElementById('confirm-ok-btn');
  btn.innerHTML='<i class="fa-solid fa-trash"></i> Excluir';
  btn.onclick=async()=>{
    await DB.remove('perfis',id);
    closeModal('modal-confirm');
    Auth.log('USER_DELETED',Auth.currentUser.username,`Perfil excluído: ${p.nome}`);
    toast(`Perfil "${p.nome}" excluído.`,'warning');
  };
  document.getElementById('modal-confirm').classList.remove('hidden');
}

// ============================================
// LOG EXPANDIDO — TOGGLE POR USUÁRIO
// ============================================
async function toggleShowLog(userId){
  if(Auth.currentUser?.role!=='master') return;
  const u=Auth.users.find(u=>u.id===userId); if(!u) return;
  const novo=!u.showLog;
  try {
    const r=await _aprovacaoReq('/usuarios/salvar',{
      user:{ id:u.id, username:u.username, email:u.email, role:u.role, active:u.active, showLog:novo },
    });
    if(!r || r.ok!==true){ toast((r&&r.erro)||'Não foi possível atualizar.','error'); return; }
    Auth.log('USER_UPDATED',Auth.currentUser.username,`Log ${novo?'liberado':'bloqueado'} para: ${u.username}`);
    toast(`Log ${novo?'liberado':'bloqueado'} para ${u.username}.`);
    await loadUsersFromWorker();
    if(State.currentSection==='users') renderUsersTable();
  } catch(e){
    toast((e&&e.message)||'Erro ao atualizar.','error');
  }
}

// ============================================
// MÓDULO DE LICENÇA / LOCAÇÃO
// ============================================
async function checkLicenca(){
  if(!DB.fs) return true;
  try {
    // Modo multi-tenant: lê metadata do tenant no painel operador
    if(DB.tenantId){
      const tenantRef = DB.tenantDoc();
      if(!tenantRef) return true;
      const doc = await tenantRef.get();
      if(!doc.exists) return true; // tenant ainda não registrado no operador = livre
      const t = doc.data();
      State.tenantMeta = t; // guarda p/ a trava de funcionários por plano #planos-trava
      const hoje = new Date().toISOString().split('T')[0];
      // Bloqueado pelo operador
      if(t.status==='bloqueado'){
        showLicencaLock(t.msgBloqueio||'Sistema bloqueado. Entre em contato com o suporte.');
        return false;
      }
      // Arquivado
      if(t.status==='arquivado'){
        showLicencaLock('Este tenant foi arquivado. Entre em contato com o suporte.');
        return false;
      }
      // Trava por INADIMPLÊNCIA: pagamento em atraso confirmado pelo Asaas (webhook PAYMENT_OVERDUE
      // marca inadimplente:true e grava bloqueioEm = vencimento + tolerância). PAYMENT_CONFIRMED/
      // RECEIVED zera e estende a validade. Some sozinha quando paga. Isenção: t.isentoInadimplencia.
      // Sem bloqueioEm (flag antiga / webhook não republicado) = bloqueia direto. #planos-precos
      if(t.inadimplente === true && !t.isentoInadimplencia){
        if(!t.bloqueioEm || hoje >= t.bloqueioEm){
          showLicencaLock('Pagamento da assinatura em atraso. Regularize para reativar o acesso — assim que o Asaas confirmar o pagamento, o sistema libera automaticamente.');
          return false;
        }
        // Dentro da tolerância: deixa entrar, mas avisa até quando.
        setTimeout(()=>toast(`⚠ Pagamento em atraso. Regularize até ${formatDateBr(t.bloqueioEm)} para não perder o acesso.`,'warning'),2500);
      }
      // Trial ou ativo com validade expirada
      if(t.validade && hoje > t.validade){
        const planoLabel = t.plano==='trial' ? 'Trial' : 'Licença';
        showLicencaLock(`${planoLabel} expirado em ${formatDateBr(t.validade)}. Entre em contato para renovar.`);
        return false;
      }
      // Aviso de vencimento próximo (7 dias)
      if(t.validade){
        const diasRestantes=Math.floor((new Date(t.validade)-new Date())/86400000);
        if(diasRestantes<=7){
          const planoLabel = t.plano==='trial' ? 'Trial' : 'Licença';
          setTimeout(()=>toast(`⚠ ${planoLabel} vence em ${diasRestantes} dia(s)! Contate o suporte.`,'warning'),3000);
        }
      }
      return true;
    }
    // Modo legado: lê de config/licenca (coleção raiz)
    const doc = await DB.fs.collection('config').doc('licenca').get();
    if(!doc.exists) return true;
    const lic=doc.data();
    if(!lic.ativa){
      showLicencaLock('Sistema bloqueado pelo administrador. Entre em contato com o suporte.');
      return false;
    }
    if(lic.validade){
      const hoje=new Date().toISOString().split('T')[0];
      if(hoje>lic.validade){
        showLicencaLock(`Licença expirada em ${formatDateBr(lic.validade)}. Renove para continuar usando o sistema.`);
        return false;
      }
      const diasRestantes=Math.floor((new Date(lic.validade)-new Date())/86400000);
      if(diasRestantes<=7){
        setTimeout(()=>toast(`⚠ Licença vence em ${diasRestantes} dia(s)! Renove para não perder o acesso.`,'warning'),3000);
      }
    }
    return true;
  } catch(e){
    console.warn('Licença: erro ao verificar (continuando normalmente):',e);
    return true;
  }
}

async function showTrialBanner(){
  if(!DB.fs || !DB.tenantId) return;
  try {
    const tenantRef = DB.tenantDoc(); if(!tenantRef) return;
    const doc = await tenantRef.get(); if(!doc.exists) return;
    const t = doc.data();
    if(!t.validade) return;
    const hoje = new Date().toISOString().split('T')[0];
    if(hoje > t.validade) return; // já bloqueado pelo checkLicenca
    const dias = Math.floor((new Date(t.validade) - new Date()) / 86400000);
    // Período grátis de 6 meses: só avisa nos últimos 30 dias, pra não "cobrar" o cliente o tempo todo.
    if(t.status === 'trial' && dias <= 30){
      const banner = document.getElementById('trial-banner');
      const msg = document.getElementById('trial-banner-msg');
      if(banner && msg){
        msg.textContent = `Período grátis: ${dias} dia(s) restante(s) — entre em contato para contratar um plano e continuar usando o sistema.`;
        banner.classList.remove('hidden');
        banner.style.background = dias <= 3 ? '#c62828' : '#e65100';
      }
    }
  } catch(e){ /* silencioso */ }
}

function showLicencaLock(msg){
  hideLoading();
  const lock=document.getElementById('licenca-lock');
  if(lock){
    const msgEl=document.getElementById('licenca-msg');
    if(msgEl) msgEl.textContent=msg;
    lock.classList.remove('hidden');
  }
}

// ============================================
// INICIALIZAÇÃO
// ============================================
// ── Carregamento de dados PÓS-LOGIN ──────────────────────────
// Esta função reúne tudo que precisa de acesso autenticado ao Firestore:
// verifica licença, baixa coleções iniciais, migra localStorage legado,
// anexa todos os listeners em tempo real e prepara a UI. É chamada por:
//   - `init()`        quando a sessão do usuário é restaurada de uma execução anterior
//   - `doLogin()`     logo após o `signInWithCustomToken` ter sucesso
// É idempotente: a flag `_dadosCarregados` impede recarga e duplicação dos
// listeners caso a função seja chamada mais de uma vez no mesmo ciclo de página.
let _dadosCarregados = false;
async function _carregarDadosPosLogin(){
  if (_dadosCarregados) return true;

  showLoading('Carregando dados...');

  // Verifica licença ANTES de qualquer carga (pode bloquear o app inteiro)
  const licencaOk = await checkLicenca();
  if(!licencaOk){ hideLoading(); return false; }
  showTrialBanner(); // assíncrono, não bloqueia

  // Config da empresa + parâmetros legais — paralelo, não bloqueia
  loadEmpresaConfig().catch(()=>{});
  loadParametrosLegais().catch(()=>{});

  // Carregar dados iniciais em paralelo
  try {
    const [employees, payrolls, logs, cctDocs, perfisDocs] = await Promise.all([
      DB.getAll('employees'),
      DB.getAll('payrolls'),
      DB.col('accessLog')
        .where('timestamp','>=', new Date(Date.now()-186*86400000).toISOString())   // retenção ~6 meses. #lgpd
        .orderBy('timestamp','desc').limit(5000).get()
        .then(s=>s.docs.map(d=>d.data()))
        .catch(()=>DB.col('accessLog').orderBy('timestamp','desc').limit(2000).get().then(s=>s.docs.map(d=>d.data()))),
      DB.col('cct').get().then(s=>s.docs.map(d=>d.data())),
      DB.getAll('perfis')
    ]);
    State.employees = employees;
    State.payrolls  = payrolls;
    Auth.accessLog  = logs;
    State.cct = cctDocs.find(c=>c.id==='current')||null;
    State.perfis = perfisDocs;
    try{ State.feriadosConfig = (await DB.getDoc('configuracoes','feriados')) || {trabalha:[],extras:[]}; }  // #feriados
    catch(_){ State.feriadosConfig = {trabalha:[],extras:[]}; }
    try{ State.acessoUsuarios = (await DB.getDoc('configuracoes','acessoUsuarios')) || {}; }   // trava de horário de acesso. #acesso-horario
    catch(_){ State.acessoUsuarios = {}; }
    try{ State.escalaConsulta = (await DB.getDoc('configuracoes','escalaConsulta')) || {}; }   // ajuste manual da escala realizada (consulta). #escala-realizada
    catch(_){ State.escalaConsulta = {}; }
    try{ State.permissoesUsuarios = (await DB.getDoc('configuracoes','permissoesUsuarios')) || {}; }   // permissões por usuário (substitui perfis). #perm-por-usuario
    catch(_){ State.permissoesUsuarios = {}; }
    try{ State.lgpdConfig = (await DB.getDoc('configuracoes','lgpdConfig')) || {}; }   // encarregado/DPO. #lgpd
    catch(_){ State.lgpdConfig = {}; }
    try{ State.termosLgpd = await DB.getAll('termosLgpd'); }   // termos de consentimento. #lgpd-termo
    catch(_){ State.termosLgpd = []; }
    try{ State.termosFerias = await DB.getAll('termosFerias'); }   // termos de férias assinados. #ferias-sign
    catch(_){ State.termosFerias = []; }
    try{ State.pedidosTitular = await DB.getAll('pedidosTitular'); }   // direitos do titular (LGPD Fase 3). #lgpd-titular
    catch(_){ State.pedidosTitular = []; }
  } catch(e){
    console.error('Erro ao carregar dados:', e);
    const msg = e && e.message ? e.message : String(e);
    document.getElementById('loading-msg').innerHTML =
      '<span style="color:#ef9a9a">⚠ Erro ao conectar ao Firebase</span><br>'
      + '<span style="font-size:13px;opacity:.85">' + msg + '</span><br>'
      + '<span style="font-size:11px;opacity:.65;margin-top:6px;display:block">Verifique firebase-config.js e as regras do Firestore.</span>';
    return false;
  }

  // Migração de localStorage (legado, raramente dispara)
  const hasMigrationData =
    (localStorage.getItem('drg_employees') && JSON.parse(localStorage.getItem('drg_employees')||'[]').length > 0) ||
    (localStorage.getItem('drg_payrolls')  && JSON.parse(localStorage.getItem('drg_payrolls') ||'[]').length > 0);
  if(hasMigrationData && State.employees.length === 0){
    showLoading('Migrando dados locais para o Firebase...');
    const ok = await DB.migrateFromLocalStorage();
    if(ok){
      const [emp,pay] = await Promise.all([DB.getAll('employees'),DB.getAll('payrolls')]);
      State.employees = emp; State.payrolls = pay;
      toast('Dados migrados do armazenamento local para o Firebase!','success');
    }
  }

  // Iniciar listeners em tempo real (anexa uma única vez via _dadosCarregados)
  DB.listen('employees', data => {
    State.employees = data;
    if(State.currentSection==='employees') renderEmployeeTable();
    if(State.currentSection==='dashboard') renderDashboard();
    updateDbInfo();
  });
  DB.listen('payrolls', data => {
    State.payrolls = data;
    _resetPrimTrab12x36Cache();   // ponto mudou → recalcula a âncora 12x36 (1º dia batido)
    if(State.currentSection==='payroll') renderPayrollHistory(val('payroll-employee'));
    if(State.currentSection==='dashboard') renderDashboard();
    // Batida do app sincronizou → Monitor de Faltas atualiza AO VIVO (senão fica mostrando
    // "falta" até o tick de 5min/Atualizar, e o operador lança manual à toa). #monitor-faltas-sync
    if(State.currentSection==='monitorfaltas' && typeof renderMonitorFaltas==='function') renderMonitorFaltas();
    if(State.currentSection==='contabilidade' && typeof renderContabilidade==='function') renderContabilidade();   // #contab-retorno-competencia
    if(State.currentSection==='recibos') renderRecibosEnviados(); // assinatura no app reflete na tela Recibos
    if(document.getElementById('modal-folhas-fechadas')) renderFolhasFechadasLista(); // status na lista de folhas fechadas
    updateDbInfo();
    // Job 'Aceito por silêncio': roda toda vez que payrolls são atualizados.
    // Marca como 'aceita_por_silencio' folhas cujo prazo de 48h passou.
    // Só master/usuário com permissão pode atualizar; outros leem só.
    if(Auth.currentUser?.role==='master' || getUserModules(Auth.currentUser).folhaEnviar){
      _aceitarPorSilencioJob().catch(e => console.error('silêncio job:', e));
      _aceitarPorSilencioHoleriteJob().catch(e => console.error('silêncio holerite job:', e));
    }
  });
  // `users` NÃO tem listener — é coleção só-servidor; a lista vem do Worker
  // (loadUsersFromWorker) sob demanda ao abrir a tela de Usuários.
  DB.listen('accessLog', data => {
    Auth.accessLog = data.sort((a,b)=>new Date(b.timestamp)-new Date(a.timestamp));
    if(State.currentSection==='users') renderLogTable();
  }, 'timestamp', 200);
  DB.listen('cct', data => {
    State.cct = data.find(c=>c.id==='current')||null;
    if(State.currentSection==='dashboard') renderDashboard();
  });
  DB.listen('rubricas', data => {
    State.rubricas = data || [];
    _seedRubricasSeNecessario();
    if(State.currentSection==='rubricas') renderRubricas();
  });
  DB.listen('perfis', data => {
    State.perfis = data;
    if(State.currentSection==='users') renderPerfisTable();
  });
  DB.listen('postos', data => {
    State.postos = data;
    if(State.currentSection==='postos') renderPostosTable();
    populatePostoSelect();
  });
  DB.listen('contratos', data => {
    State.contratos = data;
    if(State.currentSection==='contratos') renderContratosTable();
    if(State.currentSection==='dashboard') renderAlerts();
  });
  DB.listen('estoqueItens', data => {
    State.estoqueItens = data;
    if(State.currentSection==='estoque') renderEstoque();
  });
  DB.listen('estoqueMov', data => {
    State.estoqueMov = data;
    if(State.currentSection==='estoque') renderEstoque();
  });
  DB.listen('notasFiscais', data => {
    State.notasFiscais = data;
    const _nfModal=document.getElementById('modal-notas-fiscais');
    if(_nfModal && !_nfModal.classList.contains('hidden')) renderNotasFiscais();
  });
  DB.listen('decimoTerceiro', data => {
    State.decimoTerceiro = data;
    if(State.currentSection==='decimoterceiro') renderDecimoTerceiro();
  });
  DB.listen('ferias', data => {
    State.ferias = data;
    if(State.currentSection==='ferias') renderFeriasModulo();
  });
  DB.listen('escalas', data => {
    State.escalas = data;
    if(State.currentSection==='escalas') renderEscalas();
    if(State.currentSection==='dashboard') renderDashboard();
  });
  DB.listen('bancoHoras', data => {
    State.bancoHoras = data;
    if(State.currentSection==='dashboard') renderDashboard();
    const bhModal=document.getElementById('modal-banco-horas');
    if(bhModal && !bhModal.classList.contains('hidden')) renderBancoHoras();
  });
  DB.listen('atestados', data => {
    State.atestados = data;
    if(State.currentSection==='payroll'){ renderAtestadosFolha(); recalculate(); }
  });
  DB.listen('documentos', data => {
    State.documentos = data;
    // Re-renderiza a sub-secao "Enviados pelo colaborador" se a aba Documentos
    // da ficha estiver visivel (tab-documentos com classe active).
    const fichaModal = document.getElementById('modal-employee');
    if (fichaModal && !fichaModal.classList.contains('hidden')) {
      const aba = document.getElementById('tab-documentos');
      if (aba && aba.classList.contains('active')) {
        const empId = val('emp-id');
        if (empId) renderDocumentosAprovadosNaFicha(empId);
      }
    }
    // Re-renderiza a tela de aprovacoes se estiver aberta
    if (State.currentSection === 'documentos') renderDocumentosPendentes();
    // Atualiza card no dashboard
    if (State.currentSection === 'dashboard') renderDashboard();
  });
  DB.listen('saidas', data => {
    State.saidas = data;
    if(State.currentSection==='payroll'){ renderSaidasFolha(); recalculate(); }
  });
  DB.listen('documentosEmpresa', data => {   // documentos globais da empresa. #docs-empresa
    State.docsEmpresa = data;
    if(State.currentSection==='docsempresa') renderDocsEmpresa();
  });
  DB.listen('holeritesImportados', data => {   // holerites da contabilidade externa. #importar-holerite
    State.holeritesImportados = data;
    if(State.currentSection==='importaholerite') renderImportaHolerite();
  });
  DB.listen('atrasos', data => {
    State.atrasos = data;
    if(State.currentSection==='payroll'){ renderAtrasosFolha(); recalculate(); }
  });
  DB.listen('holeritesEnviados', data => {
    State.holeritesEnviados = data;
    if(State.currentSection==='pagamentos') renderPagamentos();
    if(State.currentSection==='recibos') renderRecibosEnviados();
  });
  DB.listen('escalasModelos', data => {
    State.escalasModelos = data;
    const m=document.getElementById('modal-escala-modelos');
    if(m && !m.classList.contains('hidden')) renderEscalaModelosList();
    if(State.currentSection==='escalas') renderEscalas();
    populateEscalaSelect();
  });
  DB.listen('rescisoes', data => {
    State.rescisoes = data;
    if(State.currentSection==='rescisao') renderRescisoes();
    if(State.currentSection==='dashboard') renderDashboard();
  });
  DB.listen('solicitacoesPagamento', data => {
    State.solicitacoes = data;
    if(State.currentSection==='aprovacoes') renderAprovacoes();
    if(State.currentSection==='adiantamentos') renderAdiantamentos();
    if(State.currentSection==='dashboard') renderDashboard();
  });
  DB.listen('termosFerias', data => {   // termos de férias — atualiza status/carimbo ao vivo. #ferias-sign
    State.termosFerias = data;
    const fichaModal = document.getElementById('modal-employee');
    if(fichaModal && !fichaModal.classList.contains('hidden')){
      const aba = document.getElementById('tab-ferias');
      if(aba && aba.classList.contains('active')){
        const emp = State.employees.find(e=>e.id===(State.editingEmployeeId||val('emp-id')));
        if(emp) renderFeriasList(emp.ferias||[]);
      }
    }
  });
  DB.listen('beneficioRecibos', data => {
    State.beneficioRecibos = data;
    // Atualiza a aba "Recibos de Benefício" da ficha se estiver aberta
    const fichaModal = document.getElementById('modal-employee');
    if(fichaModal && !fichaModal.classList.contains('hidden')){
      const aba = document.getElementById('tab-recibos-beneficio');
      if(aba && aba.classList.contains('active')) renderRecibosBeneficioColab();
    }
    if(State.currentSection==='beneficios' && typeof renderBeneficiosLista==='function') renderBeneficiosLista();
    if(State.currentSection==='dashboard') renderDashboard();
    // Job aceite tácito 24h (só quem pode enviar/gerir). #benef-recibo
    if(Auth.currentUser?.role==='master' || getUserModules(Auth.currentUser).folhaEnviar){
      _aceitarPorSilencioBeneficioJob().catch(e=>console.error('silencio benef job:', e));
    }
  });

  // Configurar datas na UI
  document.getElementById('topbar-date').textContent =
    new Date().toLocaleDateString('pt-BR',{weekday:'long',year:'numeric',month:'long',day:'numeric'});
  document.getElementById('payroll-mes').value            = currentMes();
  document.getElementById('payroll-ano').value            = currentAno();
  document.getElementById('report-mes').value             = currentMes();
  document.getElementById('report-ano').value             = currentAno();
  const _rbMes=document.getElementById('report-benef-mes'); if(_rbMes) _rbMes.value=currentMes();
  const _rbAno=document.getElementById('report-benef-ano'); if(_rbAno) _rbAno.value=currentAno();
  const rIndAno=document.getElementById('report-individual-ano');
  if(rIndAno) rIndAno.value=currentAno();
  const decAno=document.getElementById('dec-ano');
  if(decAno) decAno.value=currentAno();
  const ferModAno=document.getElementById('fer-mod-ano');
  if(ferModAno) ferModAno.value=currentAno();

  hideLoading();
  _dadosCarregados = true;
  _refreshPushSubFaltas();   // mantém a janela do push de faltas em dia. #janela-notif
  return true;
}

async function init(){
  // Injeta versão nos elementos HTML
  ['login-version','sidebar-version'].forEach(id => {
    const el = document.getElementById(id);
    if(el) el.textContent = APP_VERSION;
  });

  showLoading('Verificando configuração...');

  // 1. Verificar se Firebase está configurado
  if(!DB.isConfigured()){ showSetup(); return; }

  // 1b. Resolver tenantId: URL ?tenant= → localStorage → null (modo legado)
  const _urlParams = new URLSearchParams(window.location.search);
  const _tenantFromUrl = _urlParams.get('tenant');
  if(_tenantFromUrl){
    DB.tenantId = _tenantFromUrl;
    localStorage.setItem('drg_tenant', _tenantFromUrl);
  } else {
    DB.tenantId = localStorage.getItem('drg_tenant') || null;
  }
  if(DB.tenantId) console.info(`[DRG] Tenant ativo: ${DB.tenantId}`);

  showLoading('Conectando ao Firebase...');

  // 2. Inicializar Firebase
  if(!DB.init()){ showSetup(); return; }

  // 2a. Espera o Firebase Auth estabilizar SEM forçar sessão anônima.
  // A sessão real do gestor (Custom Token via Worker) é criada em `doLogin`.
  // Em recargas da página o Firebase Auth restaura a sessão automaticamente
  // (persistência local) — não precisamos forçar nada aqui.
  await new Promise(resolve => {
    const unsub = firebase.auth().onAuthStateChanged(u => { unsub(); resolve(u); });
  });

  // 2b. Rota pública do recibo (#/recibo/TOKEN) — bypass do login do gestor.
  // Se detectar, renderiza o recibo no body e encerra o init aqui.
  if(await _entrarRotaPublicaSeAplicavel()) return;

  // 3. Listeners de UI permanentes (não dependem de login)
  // (férias: início/fim/dias usam onchange/oninput inline → _feriasSync). #ferias-sign
  document.addEventListener('keydown', e => {
    if(e.key==='Escape'){
      ['modal-employee','modal-pdf','modal-confirm','modal-user','modal-change-pass','modal-cct',
       'modal-ponto-manual','modal-relatorio-individual','modal-perfil']
        .forEach(id => document.getElementById(id)?.classList.add('hidden'));
    }
  });

  // 4. Tenta restaurar uma sessão deixada por execução anterior.
  // Só entra direto se TUDO bater: sessão local salva (sessionStorage) +
  // sessão Firebase Auth real (não-anônima). Qualquer cenário "meia sessão"
  // → limpa o sessionStorage e mostra a tela de login.
  const sessionUser = Auth.loadSession();
  const fbUser = firebase.auth().currentUser;

  if(sessionUser && fbUser && !fbUser.isAnonymous){
    Auth.currentUser = sessionUser;
    document.getElementById('login-screen').classList.add('hidden');
    await _aplicarTenantDoToken();   // MT-2: no reload, tenant vem do token (não da URL/localStorage). #multitenant
    const ok = await _carregarDadosPosLogin();
    if(!ok) return; // licença bloqueou ou erro de Firestore — mensagem já exibida
    applyUserSession(sessionUser);
    AutoBackup.tryRestore();
  } else {
    if(sessionUser) Auth.clearSession();
    hideLoading();
    // Tela de login já está visível por padrão; nada de dados ainda.
  }
}

document.addEventListener('DOMContentLoaded', init);
